-- ----------------------------
-- Table structure for checksums
-- ----------------------------
DROP TABLE IF EXISTS `checksums`;
CREATE TABLE `checksums` (
  `db` char(64) CHARACTER SET utf8 NOT NULL,
  `tbl` char(64) CHARACTER SET utf8 NOT NULL,
  `chunk` int(11) NOT NULL,
  `chunk_time` float DEFAULT NULL,
  `chunk_index` varchar(200) CHARACTER SET utf8 DEFAULT NULL,
  `lower_boundary` text CHARACTER SET utf8,
  `upper_boundary` text CHARACTER SET utf8,
  `this_crc` char(40) CHARACTER SET utf8 NOT NULL,
  `this_cnt` int(11) NOT NULL,
  `master_crc` char(40) CHARACTER SET utf8 DEFAULT NULL,
  `master_cnt` int(11) DEFAULT NULL,
  `ts` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`db`,`tbl`,`chunk`),
  KEY `ts_db_tbl` (`ts`,`db`,`tbl`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

