-- Table structure for lb_account_approval_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_approval_record`;
CREATE TABLE `lb_account_approval_record` (
  `account_approval_record_id` varchar(32) NOT NULL DEFAULT '',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `account_id` varchar(64) DEFAULT '' COMMENT '账号唯一标识',
  `username` varchar(32) DEFAULT '' COMMENT '登录账号',
  `display_name` varchar(64) DEFAULT '' COMMENT '使用姓名',
  `role_id` varchar(64) DEFAULT '' COMMENT '角色唯一标识',
  `region_id` varchar(64) DEFAULT '' COMMENT '区域唯一标识',
  `csr_num` int(11) DEFAULT '0' COMMENT '员工号',
  `center_id` varchar(32) DEFAULT '' COMMENT '守护中心唯一标识',
  `is_select_all` tinyint(1) DEFAULT '0' COMMENT '客服行政区域是否全选，1全选，0部分选中',
  `apply_account_id` varchar(64) DEFAULT '' COMMENT '申请人账号id',
  `apply_name` varchar(32) DEFAULT NULL COMMENT '申请人姓名',
  `approve_account_id` varchar(64) DEFAULT '' COMMENT '审批人账号id',
  `type` tinyint(4) DEFAULT '2' COMMENT '2默认添加账号 3修改账号角色',
  `result` tinyint(1) DEFAULT '0' COMMENT '0 审批中、1通过、2驳回',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否 删除 0 否 1 是',
  `approval_time` bigint(20) DEFAULT '0' COMMENT '审批时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_approval_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户审计记录表';

-- ----------------------------
-- Table structure for lb_account_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_balance`;
CREATE TABLE `lb_account_balance` (
  `account_balance_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `username` varchar(32) DEFAULT '' COMMENT '用户',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `amount` double DEFAULT '0' COMMENT '余额',
  `pay_time` bigint(20) DEFAULT '0' COMMENT '最新付款时间',
  `user_type` char(1) DEFAULT '1' COMMENT '1.app用户 2.交互终端',
  `expire_time` bigint(20) DEFAULT '0' COMMENT '到期时间',
  `last_order_id` varchar(64) DEFAULT '' COMMENT '上次订单id',
  `last_description` varchar(32) DEFAULT '' COMMENT '上次订单叙述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构组织id',
  `trial_user` char(1) DEFAULT '0' COMMENT '0:试用用户 1:vip用户',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_balance_id`),
  KEY `account_id` (`account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_account_card_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_card_config`;
CREATE TABLE `lb_account_card_config` (
  `config_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `card_name` varchar(16) NOT NULL DEFAULT '' COMMENT '页卡名称',
  `card_type` smallint(6) NOT NULL DEFAULT '0' COMMENT '页卡类型',
  `card_photo` varchar(128) NOT NULL DEFAULT '' COMMENT '页卡图标地址',
  `serial_num` smallint(6) NOT NULL DEFAULT '0' COMMENT '页卡序号',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联账号id',
  `is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示 0不显示 1显示',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_editable` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否可编辑，0否,1可编辑',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `platform_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '健康卡片平台类型（1-馨刻平台卡片（设备种类-迭代号-长者id） 2-其他平台卡片（账号id-长者id））',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='账号健康卡片配置表';

-- ----------------------------
-- Table structure for lb_account_center_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_center_relation`;
CREATE TABLE `lb_account_center_relation` (
  `account_center_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联关系主键',
  `account_id` varchar(32) DEFAULT '' COMMENT '用户主键',
  `center_id` varchar(32) DEFAULT '' COMMENT '守护中心主键',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_center_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户守护中心关联表';

-- ----------------------------
-- Table structure for lb_account_composite_view_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_composite_view_config`;
CREATE TABLE `lb_account_composite_view_config` (
  `id` varchar(32) NOT NULL COMMENT '记录主键',
  `account_id` varchar(32) DEFAULT NULL COMMENT '账号ＩＤ',
  `view_style` int(11) DEFAULT '0' COMMENT '显示模板风格',
  `type` int(11) DEFAULT NULL COMMENT '设置项目类别　１长者信息－２长者指标－３可配置项－４可显示项',
  `item` varchar(32) DEFAULT NULL COMMENT '配置项目',
  `item_name` varchar(32) DEFAULT NULL COMMENT '项目名称',
  `item_setting` text COMMENT '项目设置　Ｙ启用　Ｎ不启用　设置内容　',
  `order_num` int(11) DEFAULT NULL COMMENT '排序字段',
  `view_model` int(11) DEFAULT '0' COMMENT '显示模板',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `meal` varchar(32) NOT NULL DEFAULT '1,2,4' COMMENT '餐次类别',
  `page_turning_time` bigint(20) NOT NULL DEFAULT '15' COMMENT '翻页时间（秒级） 0 不翻页',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='综合一览表账户显示配置';

-- ----------------------------
-- Table structure for lb_account_csr
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_csr`;
CREATE TABLE `lb_account_csr` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `account_id` varchar(64) DEFAULT NULL COMMENT '用户id',
  `guardianship_center_id` varchar(32) DEFAULT NULL COMMENT '守护中心主键',
  `csr_num` varchar(32) DEFAULT '0' COMMENT '工号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_select_all` tinyint(4) DEFAULT '0' COMMENT '客服行政区域是否全选，1全选，0部分选中',
  `extend_staff_id` varchar(32) DEFAULT '' COMMENT '电信云呼叫账号',
  `call_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '通话模式： 0可呼入呼出（默认） 1仅呼出 2仅呼入',
  `cloud_call_account` varchar(32) NOT NULL DEFAULT '' COMMENT '云呼账号',
  `cloud_call_password` varchar(64) NOT NULL DEFAULT '' COMMENT '云呼密码',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `account_id` (`account_id`)
) ENGINE=InnoDB AUTO_INCREMENT=19056 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='坐席用户属性表';

-- ----------------------------
-- Table structure for lb_account_csr_organization
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_csr_organization`;
CREATE TABLE `lb_account_csr_organization` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '账户id',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=23036 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='坐席用户管理报警关联表';

-- ----------------------------
-- Table structure for lb_account_csr_region
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_csr_region`;
CREATE TABLE `lb_account_csr_region` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '账户id',
  `region_id` varchar(64) DEFAULT '' COMMENT '区域id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `region_level` tinyint(1) NOT NULL DEFAULT '0' COMMENT '区域层级',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `region_id` (`region_id`) USING BTREE,
  KEY `account_id` (`account_id`,`region_level`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=184486 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='坐席用户管理区域关联表';

-- ----------------------------
-- Table structure for lb_account_family_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_family_relation`;
CREATE TABLE `lb_account_family_relation` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `family_id` varchar(64) NOT NULL DEFAULT '' COMMENT '家庭id',
  `account_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '账号类型，参见字典表',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='家庭-账号关联表';

-- ----------------------------
-- Table structure for lb_account_login_organization
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_login_organization`;
CREATE TABLE `lb_account_login_organization` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '账户id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=53540 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='子平台账号免登录管理';

-- ----------------------------
-- Table structure for lb_account_org_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_org_relation`;
CREATE TABLE `lb_account_org_relation` (
  `account_org_re_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_admin` tinyint(1) DEFAULT '2' COMMENT '1 管理员，2 非管理员',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_org_re_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='用户项目关联表';

-- ----------------------------
-- Table structure for lb_account_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_relation`;
CREATE TABLE `lb_account_relation` (
  `id` varchar(32) NOT NULL COMMENT 'id',
  `account_id` varchar(32) NOT NULL COMMENT '账号id',
  `user_key` varchar(32) NOT NULL COMMENT '关联唯一标识，长者主键',
  `user_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '账号所属主体类型，1长者',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0-未删除 1-已删除）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  PRIMARY KEY (`id`),
  KEY `account_id_index` (`account_id`) USING BTREE COMMENT '账号id索引',
  KEY `user_key_index` (`user_key`) USING BTREE COMMENT '唯一标识索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='账号实体关联表';

-- ----------------------------
-- Table structure for lb_account_relation_third
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_relation_third`;
CREATE TABLE `lb_account_relation_third` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `account_id` varchar(32) NOT NULL,
  `third_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '三方平台类型(1:微信)',
  `info` text NOT NULL COMMENT '三方平台用户信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='账号与三方平台关系表';

-- ----------------------------
-- Table structure for lb_account_role
-- ----------------------------
DROP TABLE IF EXISTS `lb_account_role`;
CREATE TABLE `lb_account_role` (
  `account_role_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `role_id` varchar(64) DEFAULT '' COMMENT '角色id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_role_id`),
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_activity_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_activity_record`;
CREATE TABLE `lb_activity_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) DEFAULT NULL COMMENT '看护对象',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '看护对象名字',
  `activity_type` tinyint(4) DEFAULT NULL COMMENT '活动类型，参见字典表',
  `start_time` bigint(20) DEFAULT NULL COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT NULL COMMENT '结束时间',
  `duration` bigint(20) DEFAULT '0' COMMENT '持续时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `show_type` tinyint(1) DEFAULT '1' COMMENT '显示类型，1开始结束都正常，2开始正常，结束异常，3开始异常，结束正常',
  `device_type` int(2) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '电信平台设备Id',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `activity_type` (`activity_type`),
  KEY `org_id` (`org_id`,`iot_device_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`,`activity_type`) USING BTREE,
  KEY `lb_activity_record_create_time_IDX` (`create_time`) USING BTREE,
  KEY `activity_record_device_unique_id` (`device_unique_id`),
  KEY `activity_record_care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='活动记录';

-- ----------------------------
-- Table structure for lb_aep_ota_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_aep_ota_task`;
CREATE TABLE `lb_aep_ota_task` (
  `id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备id',
  `device_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `device_iteration_number` int(3) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `task_id` varchar(64) NOT NULL DEFAULT '' COMMENT '升级任务id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0否 1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='AEP平台设备远程升级记录';

-- ----------------------------
-- Table structure for lb_alarm_action
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_action`;
CREATE TABLE `lb_alarm_action` (
  `alarm_action_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_action_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警处理行为表';

-- ----------------------------
-- Table structure for lb_alarm_action_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_action_relation`;
CREATE TABLE `lb_alarm_action_relation` (
  `relation_id` varchar(32) NOT NULL COMMENT '主键',
  `alarm_action_id` varchar(32) DEFAULT '' COMMENT '行为',
  `alarm_type` tinyint(4) DEFAULT '1' COMMENT '报警类型',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警和处理行为绑定关系表';

-- ----------------------------
-- Table structure for lb_alarm_additional_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_additional_info`;
CREATE TABLE `lb_alarm_additional_info` (
  `alarm_id` varchar(32) NOT NULL COMMENT '报警标识',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构标识',
  `last_track_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '前次位置时间',
  `last_lng` varchar(32) NOT NULL DEFAULT '' COMMENT '前次位置经度',
  `last_lat` varchar(32) NOT NULL DEFAULT '' COMMENT '前次位置纬度',
  `last_coordsys` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '前次位置坐标系（0-WGS-84，1-百度，2-高德）',
  `last_position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '前次位置描述',
  `last_gps_is_detail` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '前次位置GPS定位类型，参见GPS定位类型枚举',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `receive_alarm_time` int(11) NOT NULL DEFAULT '0' COMMENT '接警时间',
  `is_automatic_dispose` tinyint(1) NOT NULL DEFAULT '0' COMMENT '自动处理标识（0-主动处理，1-自动处理，2-不参与处理， 3-守护中心不参与）',
  `alarm_set` text COMMENT '处警设置',
  `is_receive_alarm` int(11) NOT NULL DEFAULT '0' COMMENT '接警标识（二进制位运算）',
  `receive_alarm_delay_time` int(11) NOT NULL DEFAULT '0' COMMENT '接警最大延时时间(秒)',
  `is_extension` tinyint(1) NOT NULL DEFAULT '0' COMMENT '延迟处理标识（0-不延迟，1-延迟）',
  `delay_times` tinyint(1) NOT NULL DEFAULT '0' COMMENT '延迟次数',
  `is_sign` tinyint(1) NOT NULL DEFAULT '0' COMMENT '特殊标记（居所无生命活动：0-否，1-是）',
  `not_dispose_account` text COMMENT '不处理此报警用户',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `call_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '云呼处警状态（0-不处警，1-待处警，3-处警中，4-处警完成）',
  `session_id` varchar(128) NOT NULL DEFAULT '' COMMENT '会话标识（第三方事件有效）',
  `event_code` int(11) NOT NULL DEFAULT '0' COMMENT '事件编码（详见lb_event_code_system）',
  `code_system` tinyint(1) NOT NULL DEFAULT '0' COMMENT '编码系统（详见编码系统枚举）',
  `additional_content` text COMMENT '附加内容',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_id`),
  KEY `is_sign` (`is_sign`) USING BTREE,
  KEY `is_receive_alarm` (`is_receive_alarm`) USING BTREE,
  KEY `is_automatic_dispose` (`is_automatic_dispose`) USING BTREE,
  KEY `idx_lb_alarm_additional_info` (`alarm_id`,`is_automatic_dispose`,`is_receive_alarm`,`is_extension`),
  KEY `is_extension_IDX` (`is_extension`) USING BTREE,
  KEY `idx_session_id` (`session_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警附加信息表';

-- ----------------------------
-- Table structure for lb_alarm_btn
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_btn`;
CREATE TABLE `lb_alarm_btn` (
  `alarm_btn_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位',
  `device_type` smallint(3) DEFAULT '40' COMMENT '40:洗手间按钮 41:床头按钮 42:公共区域按钮',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `position_desc` varchar(32) DEFAULT '' COMMENT '位置描述(按钮)',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `serial_num` int(11) DEFAULT '1' COMMENT '序号',
  `expire_time` bigint(20) DEFAULT '0' COMMENT 'nb卡套餐可用时间',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` int(3) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `nb_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `version` smallint(1) DEFAULT '1' COMMENT '下发信息版本号',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备软件版本号',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '按钮的主要使用长者',
  `rand_num` int(11) DEFAULT '0' COMMENT '心跳随机数',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '所属地图区域id',
  `startup_time` varchar(16) DEFAULT NULL COMMENT '开机时间',
  `master_control_box_id` varchar(64) DEFAULT '' COMMENT '主控盒唯一标识',
  `heart_time` int(11) DEFAULT '0' COMMENT '每小时上报心跳的时间（秒）',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `power_report_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量上报次数',
  `position_priority` tinyint(1) DEFAULT '0' COMMENT '定位优先级，从高到低，0无优先级',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `platform_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '平台类型',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_product_test` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为生产测试设备:0否 1是',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的上报时间',
  `receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `bed_people_num` int(3) NOT NULL DEFAULT '0' COMMENT '在床人数',
  `room_people_num` int(3) NOT NULL DEFAULT '0' COMMENT '在房人数',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `command_version_info` varchar(128) NOT NULL DEFAULT '' COMMENT '各协议命令版本号信息',
  PRIMARY KEY (`alarm_btn_id`),
  KEY `mac` (`mac`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `device_type` (`device_type`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `imei` (`imei`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警按钮';

-- ----------------------------
-- Table structure for lb_alarm_call_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_call_record`;
CREATE TABLE `lb_alarm_call_record` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构标识',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警标识',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者标识',
  `call_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '云呼类型（1-云呼告警，2-云呼处警）',
  `call_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '云呼状态（1-待云呼，2-已取消，3-云呼中，4-云呼完成）',
  `call_contacts` text NOT NULL COMMENT '云呼联系人',
  `call_order_id` varchar(64) NOT NULL DEFAULT '' COMMENT '云呼工单号',
  `call_result` text NOT NULL COMMENT '云呼结果',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `import_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '导入云呼平台时间',
  `call_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '呼出时间',
  `care_object_name` varchar(128) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_alarm_care_object_call_type` (`alarm_id`,`care_object_id`,`call_type`) USING BTREE,
  KEY `call_order_id` (`call_order_id`) USING BTREE,
  KEY `import_time` (`import_time`) USING BTREE,
  KEY `call_type` (`call_type`,`call_status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警云呼记录表';

-- ----------------------------
-- Table structure for lb_alarm_count_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_count_record`;
CREATE TABLE `lb_alarm_count_record` (
  `alarm_count_id` varchar(32) NOT NULL COMMENT '主键',
  `alarm_count` int(11) NOT NULL DEFAULT '0' COMMENT '报警数量',
  `alarm_type` int(11) NOT NULL DEFAULT '0' COMMENT '报警类型',
  `device_type` int(11) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `region` varchar(100) DEFAULT NULL COMMENT '地市',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `is_automatic` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否自动 1 是 0 否',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_count_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='报警数量统计记录表';

-- ----------------------------
-- Table structure for lb_alarm_dispose_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_dispose_account`;
CREATE TABLE `lb_alarm_dispose_account` (
  `alarm_dispose_account_id` varchar(32) NOT NULL COMMENT '主键',
  `alarm_id` varchar(32) DEFAULT '' COMMENT '报警记录id',
  `dispose_account_id` varchar(32) DEFAULT '' COMMENT '处理人主键',
  `dispose_account_name` varchar(128) DEFAULT '' COMMENT '处理人名字',
  `dispose_account_type` tinyint(1) DEFAULT '1' COMMENT '处理人类型（1app用户，2主机，3客服，4守护中心）',
  `dispose_start_time` bigint(20) DEFAULT '0' COMMENT '开始处理时间',
  `dispose_end_time` bigint(20) DEFAULT '0' COMMENT '结束处理时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_dispose_account_id`),
  KEY `alarm_id` (`alarm_id`) USING BTREE,
  KEY `dispose_account_id` (`dispose_account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警处理人;';

-- ----------------------------
-- Table structure for lb_alarm_dispose_org
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_dispose_org`;
CREATE TABLE `lb_alarm_dispose_org` (
  `alarm_dispose_org_id` varchar(64) NOT NULL COMMENT '主键',
  `alarm_id` varchar(64) DEFAULT '' COMMENT '报警编号',
  `dispose_time` bigint(20) DEFAULT '0' COMMENT '处理时间',
  `dispose_desc` varchar(128) DEFAULT '' COMMENT '叙述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_dispose_org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_alarm_dispose_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_dispose_record`;
CREATE TABLE `lb_alarm_dispose_record` (
  `alarm_dispose_record_id` varchar(64) NOT NULL COMMENT '报警处理记录id',
  `alarm_dispose_account_id` varchar(64) DEFAULT NULL COMMENT '报警处理人id',
  `dispose_type` tinyint(4) DEFAULT NULL COMMENT '处理方式 0预处理（系统默认生成）,1打电话（老人，亲属，紧急联系人，终端），2发信息给终端，3发信息给子女app,4,确认处理，5老人自己确认无恙',
  `dispose_time` bigint(20) DEFAULT NULL COMMENT '处理时间',
  `called_phone_num` varchar(32) DEFAULT NULL COMMENT '拨打的电话号码',
  `called_contact_name` varchar(32) DEFAULT NULL COMMENT '电话号码人名',
  `push_type` tinyint(4) DEFAULT NULL COMMENT '推送类型，1文件，2网址',
  `push_file_type` tinyint(4) DEFAULT NULL COMMENT '推送的文件类型，1图片，2音频',
  `push_file_url` varchar(255) DEFAULT NULL COMMENT '推送的文件地址',
  `push_web_url` varchar(32) DEFAULT NULL COMMENT '推送的网址',
  `send_app_msg` mediumtext COMMENT '发送给子女app的消息',
  `status` tinyint(1) DEFAULT '0' COMMENT '记录状态，0正常，1撤回',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `alarm_dispose` text COMMENT '处理内容',
  `alarm_dispose_duration` int(11) DEFAULT '0' COMMENT '音频、视频的时长，单位秒',
  `alarm_dispose_type` tinyint(4) DEFAULT '0' COMMENT '0 文本 1 音频 2 图片 3 视频',
  `read_account` text COMMENT '已读子女app账号',
  `photo_width` int(9) DEFAULT '0' COMMENT '图片宽度(px)',
  `photo_height` int(9) DEFAULT '0' COMMENT '图片高度(px)',
  `dispose_account_id` varchar(64) DEFAULT '' COMMENT '处理人主键',
  `alarm_id` varchar(32) DEFAULT '' COMMENT '报警记录主键',
  `content_type` tinyint(1) DEFAULT NULL COMMENT '处理结果类型 0 为追加处理结果',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_dispose_record_id`),
  KEY `alarm_dispose_account_id` (`alarm_dispose_account_id`) USING BTREE,
  KEY `dispose_account_id` (`dispose_account_id`) USING BTREE,
  KEY `alarm_id` (`alarm_id`) USING BTREE,
  KEY `dispose_time` (`dispose_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警处理记录';

-- ----------------------------
-- Table structure for lb_alarm_dispose_result_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_dispose_result_record`;
CREATE TABLE `lb_alarm_dispose_result_record` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构标识',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警记录主键',
  `dispose_account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '处理人主键',
  `dispose_account_type` tinyint(1) NOT NULL COMMENT '处理人类型，参见处理人类型枚举',
  `dispose_account_name` varchar(128) NOT NULL DEFAULT '' COMMENT '处理人姓名',
  `dispose_method` tinyint(1) NOT NULL DEFAULT '0' COMMENT '处理方式（0-常规处理，1-追加处理）',
  `dispose_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处理时间',
  `dispose_type` tinyint(1) NOT NULL COMMENT '处理方式，参见处理方式枚举',
  `dispose_content` text NOT NULL COMMENT '处理内容',
  `dispose_content_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '处理内容类型（0-文本，1-音频，2-图片，3-视频）',
  `photo_width` int(11) NOT NULL DEFAULT '0' COMMENT '图片宽度(px)',
  `photo_height` int(11) NOT NULL DEFAULT '0' COMMENT '图片高度(px)',
  `dispose_content_duration` int(11) NOT NULL DEFAULT '0' COMMENT '处理内容时长(秒)，音频/视频有效',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态(0-正常，1-撤回)',
  `read_account` text NOT NULL COMMENT '已读用户',
  `click_account` text NOT NULL COMMENT '已点击用户（语音消息有效）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `alarm_id` (`alarm_id`) USING BTREE,
  KEY `org_id_create_time` (`org_id`,`create_time`) USING BTREE,
  KEY `dispose_account_id` (`dispose_account_id`,`dispose_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警处理结果记录表';

-- ----------------------------
-- Table structure for lb_alarm_elder
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_elder`;
CREATE TABLE `lb_alarm_elder` (
  `alarm_elder_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `master_num` varchar(32) DEFAULT NULL COMMENT '主机号',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `elder_code` varchar(32) NOT NULL COMMENT '长者code',
  `is_time_alarm` tinyint(1) NOT NULL COMMENT '是否是时间段报警',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '最后更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_elder_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='离院报警老人关系';

-- ----------------------------
-- Table structure for lb_alarm_event_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_event_record`;
CREATE TABLE `lb_alarm_event_record` (
  `alarm_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `org_type` tinyint(1) DEFAULT NULL COMMENT '项目类型，参见项目类型枚举',
  `system_type` tinyint(1) DEFAULT NULL COMMENT '项目系统类型，参见项目系统类型枚举',
  `track_id` varchar(64) NOT NULL DEFAULT '' COMMENT '轨迹标识',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者标识',
  `care_object_name` varchar(128) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域标识',
  `bed_id` varchar(32) NOT NULL DEFAULT '' COMMENT '床位标识',
  `alarm_type` smallint(6) NOT NULL COMMENT '报警类型，参见报警类型枚举',
  `alarm_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '报警类型描述',
  `is_automatic` tinyint(1) NOT NULL DEFAULT '0' COMMENT '自动标识（0-手动，1-自动）',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '监测开始时间（持续性报警有效）',
  `alarm_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '报警时间',
  `dispose_result_id` varchar(64) NOT NULL DEFAULT '' COMMENT '首条处理结果标识',
  `dispose_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处警开始时间',
  `dispose_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处警结束时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '报警状态，参见报警状态枚举',
  `device_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac',
  `device_imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备imei',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '注册平台设备标识',
  `device_type` smallint(6) DEFAULT NULL COMMENT '设备类型，参见设备类型枚举',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_type_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `device_category` smallint(6) DEFAULT NULL COMMENT '设备种类，参见设备种类枚举',
  `position_type` tinyint(1) DEFAULT NULL COMMENT '安装位置类型，参见安装位置类型枚举',
  `report_device_type` tinyint(1) DEFAULT NULL COMMENT '上报设备类型',
  `mainframe_num` text NOT NULL COMMENT '接警主机号',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1-报警，2-事件，3-第三方事件）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `device_position` varchar(64) NOT NULL DEFAULT '' COMMENT '设备安装位置',
  `care_object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '长者类型（0：无效值，其他参见长者类型枚举）',
  `device_unique_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `guardian_center_service_status` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '守护中心服务状态（0：服务到期，1：守护服务，2：救护服务）',
  `helper_iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '协助设备注册平台设备标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_id`),
  KEY `track_id` (`track_id`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `org_type` (`org_type`,`status`) USING BTREE,
  KEY `org_id` (`org_id`,`alarm_type`,`status`) USING BTREE,
  KEY `care_object_id` (`care_object_id`,`alarm_type`,`status`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`,`alarm_type`,`status`) USING BTREE,
  KEY `org_id_status_IDX` (`org_id`,`status`) USING BTREE,
  KEY `idx_org_id_alarm_time` (`org_id`,`alarm_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警&事件记录表';

-- ----------------------------
-- Table structure for lb_alarm_mode
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_mode`;
CREATE TABLE `lb_alarm_mode` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `alarm_type` tinyint(4) NOT NULL COMMENT '报警类型（1-心率异常报警，2-不动类报警，3-呼吸异常报警）',
  `alarm_mode` tinyint(4) NOT NULL DEFAULT '1' COMMENT '报警模式（1-提醒，2-报警）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `family_id` varchar(32) NOT NULL DEFAULT '' COMMENT '家庭主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id` (`care_object_id`,`alarm_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警模式设置表';

-- ----------------------------
-- Table structure for lb_alarm_push_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_push_record`;
CREATE TABLE `lb_alarm_push_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `content` mediumtext COMMENT '报警内容 jsonString',
  `is_receive` tinyint(1) DEFAULT '0' COMMENT '是否已经收到，1是 0否',
  `push_times` tinyint(4) DEFAULT '1' COMMENT '已推送次数',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `alarm_id` varchar(64) DEFAULT '' COMMENT '报警主键',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '报警所属NB设备iotid',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `msg_type` tinyint(1) DEFAULT '2' COMMENT '消息类型，2新报警，3报警处理',
  `org_type` tinyint(1) DEFAULT '1' COMMENT '机构类型',
  `region_id` varchar(64) DEFAULT '' COMMENT '区域id',
  `client_type` tinyint(1) DEFAULT '4' COMMENT '客户端类型',
  `is_receive_alarm` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接警标识（0-未接警，1-已接警）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `record_id` (`record_id`) USING BTREE,
  KEY `alarm_id` (`alarm_id`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `region_id` (`region_id`) USING BTREE,
  KEY `is_receive` (`is_receive`,`push_times`) USING BTREE,
  KEY `org_receive_client_time` (`org_id`,`is_receive`,`client_type`,`update_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_alarm_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_record`;
CREATE TABLE `lb_alarm_record` (
  `alarm_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `alarm_type` int(11) DEFAULT '0' COMMENT '报警类型，参见字典表',
  `alarm_desc` varchar(32) DEFAULT '' COMMENT '报警叙述',
  `care_object_name` varchar(128) DEFAULT '' COMMENT '看护对象名字',
  `lgt` varchar(32) DEFAULT '' COMMENT '经度',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `alarm_time` bigint(20) DEFAULT '0' COMMENT '报警时间',
  `receive_alarm_time` bigint(20) DEFAULT '0' COMMENT '接警时间',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '1室外，0室内',
  `position_desc` varchar(128) DEFAULT '' COMMENT '位置描述',
  `status` tinyint(1) DEFAULT '1' COMMENT '报警状态，1未处理，3正在处理，4处理完成',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `area_id` varchar(64) DEFAULT '' COMMENT '房间id',
  `is_receive` tinyint(1) DEFAULT '0' COMMENT '是否已接收，0否1是（已无效）',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` int(11) DEFAULT '42' COMMENT '设备类型，参见字典表',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'GPS是粗定位/实时位置',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '经度 原',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '纬度 原',
  `device_status` int(1) DEFAULT '0' COMMENT '报警时的设备状态（仅对手表有效）0不显示状态，1佩戴中，2未佩戴，3充电中',
  `device_type_desc` varchar(32) DEFAULT '' COMMENT '设备类型描述',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '报警时心率。手表报警有效',
  `track_id` varchar(255) DEFAULT '' COMMENT '轨迹id',
  `last_track_id` varchar(64) DEFAULT '' COMMENT '报警时上一次位置信息',
  `phone_num` varchar(32) DEFAULT NULL COMMENT '老人手机号码',
  `is_automatic` tinyint(1) DEFAULT '0' COMMENT '是否为自动报警，１是，０否',
  `alarm_set` text COMMENT '处警设置',
  `not_dispose_account` text COMMENT '不处理报警账号',
  `is_automatic_dispose` tinyint(1) DEFAULT '0' COMMENT '是否自动处理（0 主动处理，1 自动处理，2 不参与处理）',
  `mainframe_num` varchar(32) DEFAULT '' COMMENT '主机号',
  `dispose_mainframe_num` varchar(32) DEFAULT '' COMMENT '处理主机号',
  `call_order_id` varchar(64) DEFAULT '' COMMENT '云呼处警工单号',
  `call_status` tinyint(1) DEFAULT '0' COMMENT '云呼处警状态（0-不处警，1-待处警，3-处警中，4-处警完成）',
  `call_result` text COMMENT '云呼结果',
  `device_iteration_number` int(11) DEFAULT '0' COMMENT '设备迭代版本号',
  `is_sign` tinyint(1) DEFAULT '0' COMMENT '是否标记（0-否，1-是）',
  `call_contacts` text COMMENT '云呼处警联系人',
  `is_extension` tinyint(1) NOT NULL DEFAULT '0' COMMENT '报警是否延迟处理 0 不延迟 1 延迟',
  `delay_times` tinyint(1) NOT NULL DEFAULT '0' COMMENT '延期次数',
  `device_mac` varchar(32) DEFAULT '' COMMENT '设备mac',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位标识',
  `is_receive_alarm` int(11) NOT NULL DEFAULT '0' COMMENT '接警标识（二进制位运算）',
  `receive_alarm_delay_time` int(11) NOT NULL DEFAULT '0' COMMENT '接警最大延时时间（秒级）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_id`),
  KEY `alarm_time` (`alarm_time`) USING BTREE,
  KEY `alarm_type` (`alarm_type`) USING BTREE,
  KEY `track_id` (`track_id`(191)) USING BTREE,
  KEY `org_id` (`org_id`,`status`,`alarm_type`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`,`alarm_type`,`status`) USING BTREE,
  KEY `care_object_id` (`care_object_id`,`alarm_type`,`status`) USING BTREE,
  KEY `status` (`status`,`is_automatic_dispose`,`call_status`) USING BTREE,
  KEY `is_receive_alarm` (`is_receive_alarm`),
  KEY `call_order_id` (`call_order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警记录';

-- ----------------------------
-- Table structure for lb_alarm_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_set`;
CREATE TABLE `lb_alarm_set` (
  `alarm_set_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `alarm_mode` tinyint(1) DEFAULT '0' COMMENT '处警模式，0不更改，1不处理所有报警，2不处理自动报警 3.心率异常报警 4.参与处理手动SOS 5.长时间不动报警 6.在床不动报警 7.洗手间不动报警 8.居所内无生命活动报警 9.洗手间滞留报警',
  `set_time` int(11) DEFAULT '1' COMMENT '处警修改持续时间 0为永久',
  `alarm_set_name` varchar(255) DEFAULT '' COMMENT '处警设置人姓名（处警设置人类型为客服时，为要求人姓名）',
  `alarm_set_type` tinyint(1) DEFAULT '1' COMMENT '处警设置人类型 1子女app用户 3客服',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系描述',
  `csr_id` varchar(64) DEFAULT '' COMMENT '客服Id（处警设置人类型为客服时存在）',
  `is_use` tinyint(1) DEFAULT '0' COMMENT '设置是否过期  0已过期 1未过期',
  `recovery_time` bigint(20) DEFAULT '1' COMMENT '处警修改恢复时间,持续时间为永久时该字段为处警设置时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_open` tinyint(1) DEFAULT '1' COMMENT '是否开启 0 关闭 1开启',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `org_type` tinyint(4) DEFAULT '1' COMMENT '项目类型',
  `area_id` varchar(32) DEFAULT '' COMMENT '区域id',
  `time_type` int(3) DEFAULT '1' COMMENT '时间段设置: 1 全天 2 白天 3 晚上',
  `start_time` varchar(32) DEFAULT '00:00' COMMENT '处警设置开始时间',
  `end_time` varchar(32) DEFAULT '00:00' COMMENT '处警设置结束时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_set_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `alarm_mode` (`alarm_mode`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者处警设置表';

-- ----------------------------
-- Table structure for lb_alarm_switch_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_switch_config`;
CREATE TABLE `lb_alarm_switch_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置对象标识',
  `report_device_type` tinyint(1) NOT NULL COMMENT 'NB上报设备类型',
  `device_iteration_number` tinyint(1) DEFAULT NULL COMMENT '设备迭代版本号',
  `device_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `alarm_type` tinyint(1) NOT NULL COMMENT '报警类型',
  `alarm_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '报警类型描述',
  `switch_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '开关状态（0-屏蔽，1-启用）',
  `config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '配置类型',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `object_id` (`object_id`,`alarm_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警开关配置表';

-- ----------------------------
-- Table structure for lb_alarm_time
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_time`;
CREATE TABLE `lb_alarm_time` (
  `alarm_time_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `start_time` varchar(32) NOT NULL COMMENT '报警时间段开始',
  `end_time` varchar(32) NOT NULL COMMENT '报警时间段结束',
  `is_next_day` tinyint(1) NOT NULL COMMENT '结束时间点是否次日',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '最后更新时间',
  `master_num` int(11) NOT NULL DEFAULT '0' COMMENT '主机号',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_time_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='离院报警时间段';

-- ----------------------------
-- Table structure for lb_alarm_track_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_track_record`;
CREATE TABLE `lb_alarm_track_record` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构标识',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '注册平台设备标识',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域标识',
  `map_area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域地图标识',
  `record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录时间',
  `lng_primitive` varchar(32) NOT NULL DEFAULT '' COMMENT '原始经度（WGS-84）',
  `lat_primitive` varchar(32) NOT NULL DEFAULT '' COMMENT '原始纬度（WGS-84）',
  `lng` varchar(32) NOT NULL DEFAULT '' COMMENT '经度',
  `lat` varchar(32) NOT NULL DEFAULT '' COMMENT '纬度',
  `coordsys` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '坐标系（0-WGS-84，1-百度，2-高德）',
  `position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '位置描述',
  `gps_is_detail` tinyint(1) NOT NULL DEFAULT '-1' COMMENT 'GPS定位类型，参见GPS定位类型枚举',
  `position_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '定位设备mac',
  `heart_rate` int(11) NOT NULL DEFAULT '-1' COMMENT '心率',
  `heart_rate_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '心率数据显示标识（0-不显示，1-显示）',
  `systolic_pressure` int(11) NOT NULL DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(11) NOT NULL DEFAULT '-1' COMMENT '舒张压',
  `sphygmomanometer_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血压计状态（0-未绑定，1-已校准，2-短时间未校准，3-长时间未校准，4-未绑定正常显示，5-未绑定长时间未校准）',
  `uncalibrated_day_num` int(11) NOT NULL DEFAULT '-1' COMMENT '血压计未校准天数',
  `blood_pressure_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血压数据显示标识（0-不显示， 1-显示）',
  `blood_oxygen` int(11) NOT NULL DEFAULT '-1' COMMENT '血氧',
  `is_applets_measure` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血氧小程序测量标识（0-否，1-是）',
  `blood_oxygen_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血氧数据显示标识（0-不显示， 1-显示）',
  `body_temperature` decimal(3,1) NOT NULL DEFAULT '-1.0' COMMENT '体温',
  `body_temperature_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '体温数据显示标识（0-不显示， 1-显示）',
  `breath` int(11) NOT NULL DEFAULT '-1' COMMENT '呼吸',
  `breath_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼吸数据显示标识（0-不显示， 1-显示）',
  `is_exercise_measure` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '健康数据测量时运动状态（0-静止测，1运动测）',
  `power` int(11) NOT NULL DEFAULT '-1' COMMENT '设备电量',
  `device_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备状态（0-不显示，1-佩戴中，2-未佩戴，3-充电中）',
  `device_status_duration` bigint(20) NOT NULL DEFAULT '0' COMMENT '设备状态持续时长(秒)',
  `device_status_is_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备状态显示标识（0-不显示， 1-显示）',
  `position_status` text NOT NULL COMMENT '位置状态',
  `is_health_intact` tinyint(1) NOT NULL DEFAULT '0' COMMENT '健康数据完整标识（0-不完整，1-完整）',
  `is_position_intact` tinyint(1) NOT NULL DEFAULT '0' COMMENT '位置信息完整标识（0-不完整，1-完整）',
  `is_intact` tinyint(1) NOT NULL DEFAULT '0' COMMENT '数据完整标识（0-不完整，1-完整）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者标识',
  `device_type` smallint(6) DEFAULT NULL COMMENT '设备类型，参见设备类型枚举',
  `device_category` smallint(6) DEFAULT NULL COMMENT '设备种类，参见设备种类枚举',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `position_is_show` tinyint(1) NOT NULL DEFAULT '1' COMMENT '位置信息显示标识（0：不显示， 1：显示）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `is_intact` (`is_intact`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警轨迹记录表';

-- ----------------------------
-- Table structure for lb_alarm_type_enum
-- ----------------------------
DROP TABLE IF EXISTS `lb_alarm_type_enum`;
CREATE TABLE `lb_alarm_type_enum` (
  `alarm_type` smallint(6) NOT NULL COMMENT '报警类型',
  `alarm_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '报警类型描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_send` tinyint(1) NOT NULL DEFAULT '0' COMMENT '下发标识（0-不下发，1-下发），用于护工手表',
  `is_support_hospital` tinyint(1) NOT NULL DEFAULT '0' COMMENT '医院场景支持标识（0-不支持，1-支持）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_type`),
  KEY `idx_alarm_type_desc` (`alarm_type_desc`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='报警类型枚举表';

-- ----------------------------
-- Table structure for lb_ali_csr
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_csr`;
CREATE TABLE `lb_ali_csr` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) DEFAULT NULL COMMENT '来邦客服用户id',
  `ali_account` varchar(50) NOT NULL COMMENT '阿里云呼帐号',
  `ali_pwd` varchar(50) NOT NULL COMMENT '阿里云呼密码',
  `access_token` varchar(100) DEFAULT NULL COMMENT '阿里云呼accessToken',
  `refresh_token` varchar(100) DEFAULT NULL COMMENT '阿里云呼refreshToken',
  `ali_ramid` varchar(50) NOT NULL COMMENT '阿里云呼帐号ramid',
  `ali_userid` varchar(50) NOT NULL COMMENT '阿里云呼帐号userid',
  `ali_email` varchar(50) NOT NULL COMMENT '阿里云呼帐号邮箱',
  `ali_displayname` varchar(30) DEFAULT NULL COMMENT '阿里云呼帐号姓名',
  `access_token_update_time` bigint(20) DEFAULT NULL COMMENT '阿里云呼accessToken更新时间',
  `refresh_token_update_time` bigint(20) DEFAULT NULL COMMENT '阿里云呼refreshToken更新时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '记录创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '记录更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='阿里云呼座席信息表';

-- ----------------------------
-- Table structure for lb_ali_csr_dispose_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_csr_dispose_record`;
CREATE TABLE `lb_ali_csr_dispose_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `alarm_id` varchar(64) NOT NULL COMMENT '报警id',
  `phone_list` text COMMENT '待拨打的电话列表',
  `status` tinyint(4) DEFAULT NULL COMMENT '处理状态，0正在处理，1处理结束',
  `current_phone_order` int(11) DEFAULT NULL COMMENT '当前拨打的电话序号',
  `task_id` varchar(64) DEFAULT NULL COMMENT '阿里的拨号任务id',
  `alarm_content` text COMMENT '报警内容',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `ivr_id` varchar(64) DEFAULT NULL COMMENT '处理的智能客服id',
  `current_phone` varchar(20) DEFAULT NULL COMMENT '当前拨打的电话号码',
  `current_contacts` varchar(64) DEFAULT NULL COMMENT '当前被拨打的联系人信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `status` (`status`) USING BTREE,
  KEY `ivr_id` (`ivr_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_ali_ivr
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_ivr`;
CREATE TABLE `lb_ali_ivr` (
  `ivr_id` varchar(64) NOT NULL COMMENT '主键',
  `status` tinyint(4) DEFAULT NULL COMMENT '状态，1工作，0不工作',
  `phone_num` varchar(20) DEFAULT NULL COMMENT '电话号码',
  `max_dispose_count` int(11) DEFAULT NULL COMMENT '最大同时处理量',
  `contract_flow_id` varchar(64) DEFAULT NULL COMMENT '联系流id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`ivr_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_ali_sign
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_sign`;
CREATE TABLE `lb_ali_sign` (
  `sign_code` varchar(16) NOT NULL DEFAULT '' COMMENT '签名cod (signXX)',
  `sign_name` varchar(32) NOT NULL DEFAULT '' COMMENT '签名名称',
  `org_id` varchar(32) NOT NULL DEFAULT 'lonbon',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sign_code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='阿里签名信息';

-- ----------------------------
-- Table structure for lb_ali_sign_template_org_relation_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_sign_template_org_relation_v2`;
CREATE TABLE `lb_ali_sign_template_org_relation_v2` (
  `id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '',
  `sign_code` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '签名code(ali_sign)',
  `code_num` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '模板代号(ali_template)',
  `org_id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启(0:否  1:是)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin COMMENT='机构-模板-签名信息';

-- ----------------------------
-- Table structure for lb_ali_sign_template_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_sign_template_relation`;
CREATE TABLE `lb_ali_sign_template_relation` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `sign_code` varchar(16) NOT NULL DEFAULT '' COMMENT '签名code (signXX)',
  `code_value` varchar(16) NOT NULL DEFAULT '' COMMENT '模板CODE',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_ali_sign_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_sign_v2`;
CREATE TABLE `lb_ali_sign_v2` (
  `sign_code` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '签名code (signXX)',
  `sign_name` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '签名名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sign_code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin COMMENT='阿里签名信息';

-- ----------------------------
-- Table structure for lb_ali_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_template`;
CREATE TABLE `lb_ali_template` (
  `id` varchar(32) NOT NULL COMMENT 'template_type',
  `type` tinyint(1) NOT NULL COMMENT '模板类型 0欠费/1退住/2用药不足/3预缴',
  `context` text NOT NULL,
  `code_num` int(10) NOT NULL DEFAULT '0' COMMENT '代号',
  `code_value` varchar(16) NOT NULL DEFAULT '' COMMENT 'ali 模板CODE',
  `open_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '开启状态(0:禁用  1:开启)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `code_num` (`code_num`),
  UNIQUE KEY `code_value` (`code_value`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='阿里短信模板信息';

-- ----------------------------
-- Table structure for lb_ali_template_param_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_template_param_v2`;
CREATE TABLE `lb_ali_template_param_v2` (
  `id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '',
  `key_id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT 'code_num/sms_template_id',
  `param_name` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '',
  `param_value` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '',
  `is_modify` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可修改(0: 否 1:是)',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin COMMENT='模板占位参数值信息';

-- ----------------------------
-- Table structure for lb_ali_template_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_ali_template_v2`;
CREATE TABLE `lb_ali_template_v2` (
  `code_num` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '模板代号',
  `code_value` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '阿里模板code',
  `context` text COLLATE utf8_bin NOT NULL COMMENT '模板信息',
  `param` varchar(64) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '参数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`code_num`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin COMMENT='阿里模板信息';

-- ----------------------------
-- Table structure for lb_alipay_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_alipay_order`;
CREATE TABLE `lb_alipay_order` (
  `order_id` varchar(64) NOT NULL COMMENT '主键',
  `order_num` varchar(64) DEFAULT '' COMMENT '支付订单号',
  `trade_num` varchar(64) DEFAULT '' COMMENT '交易号',
  `goods_title` varchar(32) DEFAULT '' COMMENT '商品',
  `receipt_amount` varchar(32) DEFAULT '' COMMENT '收款金额',
  `order_status` tinyint(1) DEFAULT '1' COMMENT '1.等待付款  2.已付款',
  `gmt_create` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `gmt_payment` bigint(20) DEFAULT '0' COMMENT '支付时间',
  `fund_bill_list` mediumtext COMMENT '付款账单列表',
  `seller_id` varchar(32) DEFAULT '' COMMENT '卖方ID',
  `seller_account` varchar(32) DEFAULT '' COMMENT '卖方账户',
  `buyer_id` varchar(32) DEFAULT '' COMMENT '买方ID',
  `buyer_account` mediumtext COMMENT '买方账户',
  `refund_status` tinyint(1) DEFAULT '0' COMMENT '退款状态',
  `refund_fee` varchar(32) DEFAULT '' COMMENT '退款金额',
  `gmt_refund` bigint(20) DEFAULT '0' COMMENT '退款时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `buyer_pay_amount` varchar(32) DEFAULT NULL,
  `goods_detail` varchar(255) DEFAULT '' COMMENT '商品叙述',
  `goods_amount` varchar(32) DEFAULT '' COMMENT '商品金额',
  `business_type` tinyint(1) DEFAULT '0' COMMENT '业务类型,默认0,注释:0:子女appV.1.0，1:子女appV.2.0，2:商城',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_annual_fee
-- ----------------------------
DROP TABLE IF EXISTS `lb_annual_fee`;
CREATE TABLE `lb_annual_fee` (
  `annual_fee_id` varchar(32) NOT NULL COMMENT '主键',
  `type` tinyint(1) DEFAULT '0' COMMENT '类型',
  `description` varchar(32) DEFAULT '' COMMENT '叙述',
  `discount` double DEFAULT '0' COMMENT '折扣',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`annual_fee_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_anti_lost_host
-- ----------------------------
DROP TABLE IF EXISTS `lb_anti_lost_host`;
CREATE TABLE `lb_anti_lost_host` (
  `id` varchar(32) NOT NULL,
  `device_type` int(3) NOT NULL DEFAULT '117' COMMENT '设备类型',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '设备sn号',
  `ip` varchar(32) NOT NULL DEFAULT '' COMMENT 'ip',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '在线状态 0离线 1在线',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '安装位置',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `antenna` text NOT NULL COMMENT '主机天线信息',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1是0否',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_sn` (`sn`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='防走失主机表';

-- ----------------------------
-- Table structure for lb_anti_lost_tag
-- ----------------------------
DROP TABLE IF EXISTS `lb_anti_lost_tag`;
CREATE TABLE `lb_anti_lost_tag` (
  `id` varchar(32) NOT NULL,
  `device_type` int(3) NOT NULL DEFAULT '118' COMMENT '设备类型',
  `tag_num` varchar(32) NOT NULL DEFAULT '' COMMENT '标签号',
  `tag_remark` varchar(255) NOT NULL DEFAULT '' COMMENT '标签备注',
  `tag_group` varchar(32) NOT NULL DEFAULT '' COMMENT '标签分组',
  `leave_alarm_switch` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否开启离院报警 1开0关',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1是0否',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_tag_num` (`tag_num`),
  KEY `idx_tag_group` (`tag_group`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='防走失标签表';

-- ----------------------------
-- Table structure for lb_approval_process
-- ----------------------------
DROP TABLE IF EXISTS `lb_approval_process`;
CREATE TABLE `lb_approval_process` (
  `process_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `approval_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批记录id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `level` tinyint(1) NOT NULL COMMENT '审批等级 1-5 最多5级 0 抄送',
  `approval_staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人或抄送id（员工id）',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '流程审批状态 1 待审核 2 审核通过 3 审核驳回',
  `approval_opinion` varchar(255) NOT NULL DEFAULT '' COMMENT '审批意见',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `approval_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `is_read` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已读 0 否 1 是',
  `approval_department_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审核人所在部门名称',
  `approval_staff_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审核员工姓名',
  `staff_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '员工类型 1 审批人 2 抄送人',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `approval_staff_office` varchar(32) NOT NULL DEFAULT '' COMMENT '审核员工职务',
  `approval_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人或抄送人所在机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`process_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `approval_record_id_IDX` (`approval_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='审批流程表';

-- ----------------------------
-- Table structure for lb_approval_process_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_approval_process_setting`;
CREATE TABLE `lb_approval_process_setting` (
  `setting_id` varchar(32) NOT NULL COMMENT '主键',
  `group_id` varchar(32) NOT NULL DEFAULT '' COMMENT '分组id（区分流程设置）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '流程所在机构id',
  `applicant_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设置人所在机构id',
  `approval_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审批类型 1 入住审批 2 退住审批 3 评估审批 4 通用审批',
  `applicant_department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '申请人部门id  “0” 为全部部门',
  `approval_staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人或抄送人（员工id）',
  `staff_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '员工类型 1 审批类型 2 推送人',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `level` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审批级别 0 抄送人 1-5 ，最高五级',
  `approval_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人或抄送人所在机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `department_id_IDX` (`applicant_department_id`) USING BTREE,
  KEY `applicant_org_id_IDX` (`applicant_org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='审批流程设置表';

-- ----------------------------
-- Table structure for lb_approval_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_approval_record`;
CREATE TABLE `lb_approval_record` (
  `approval_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `approval_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审批类型 1 入住审批 2 退住审批 3 评估审批 4 通用审批',
  `business_id` text COMMENT '业务id（入住退住为长者id，评估为评估记录id，批量退住用逗号隔开）',
  `title` varchar(255) NOT NULL DEFAULT '' COMMENT '标题',
  `approval_details` text COMMENT '审批详情（内容）',
  `annex_url` text COMMENT '附件',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1 审核中 2 已撤回 3 审核通过 4 审核不通过 5 已作废',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `finish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批完成时间',
  `applicant_staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批发起人id(员工id)',
  `applicant_staff_name` varchar(32) NOT NULL DEFAULT '' COMMENT '申请人姓名（员工姓名）',
  `approval_number` varchar(32) NOT NULL DEFAULT '' COMMENT '审批编号',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `approval_content` mediumtext COMMENT '审批内容（用于存储入住账单等信息）',
  `now_process_id` text NOT NULL COMMENT '当前审批处于的流程id',
  `is_read` tinyint(1) NOT NULL DEFAULT '0' COMMENT '审批记录申请人是否已读 0 未读 1 已读',
  `is_reapply` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已重新申请审批记录，0 否 1 是',
  `cancel_staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '作废人员工id',
  `cancel_staff_name` varchar(32) NOT NULL DEFAULT '' COMMENT '作废人姓名',
  `cancel_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '作废时间',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`approval_record_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `create_time_index` (`create_time`),
  KEY `business_id_index` (`business_id`(64))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='审批记录表';

-- ----------------------------
-- Table structure for lb_approval_type_enum
-- ----------------------------
DROP TABLE IF EXISTS `lb_approval_type_enum`;
CREATE TABLE `lb_approval_type_enum` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `approval_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审批类型 1 入住审批 2 退住审批 3 评估审批 4 通用审批 5 物业保修审批',
  `approval_type_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审批类型名称',
  `system_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '系统类型，与机构表中system_type一致，如未设置某个类型平台，查 -1（-1表示默认）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COMMENT='审批类型枚举表';

-- ----------------------------
-- Table structure for lb_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_area`;
CREATE TABLE `lb_area` (
  `area_id` varchar(32) NOT NULL COMMENT '主键',
  `building_id` varchar(32) DEFAULT '' COMMENT '所属楼层',
  `area_name` varchar(32) DEFAULT '' COMMENT '房间名称',
  `position_desc` varchar(200) DEFAULT '' COMMENT '楼栋楼层/详细地址 描述',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `area_type` tinyint(1) DEFAULT '1' COMMENT '1:机构公共区域 2:机构房间 3:散户区域',
  `unit_num` varchar(32) DEFAULT NULL COMMENT '单元（弃用）',
  `is_use` tinyint(1) DEFAULT '2' COMMENT '1使用 2未使用',
  `temperature` tinyint(3) DEFAULT '-1' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `floor_id` varchar(32) DEFAULT '' COMMENT '楼层id',
  `mainframe_id` varchar(32) DEFAULT '' COMMENT '主机id',
  `direction` tinyint(1) DEFAULT '0' COMMENT '朝向0:东1:南2:西3:北',
  `area_num_role` tinyint(1) DEFAULT '1' COMMENT '房间号是否带楼栋编号0:否1:是',
  `bed_num_role` tinyint(1) DEFAULT '0' COMMENT '床位编号方式  1:按房间计数2:按楼层计数',
  `building_floor_connector` varchar(16) DEFAULT '' COMMENT '楼栋楼层连接符',
  `floor_area_connector` varchar(16) DEFAULT '' COMMENT '楼层房间连接符',
  `area_bed_connector` varchar(16) DEFAULT '' COMMENT '房间床位连接符',
  `area_map_content` text COMMENT '房间地图附加信息',
  `region_id` int(10) DEFAULT NULL COMMENT '区域id',
  `nurse_id` varchar(32) DEFAULT '' COMMENT '护工小组人员id',
  `area_map` varchar(125) DEFAULT '' COMMENT '区域地图',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `map_floor_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属地图楼层id(area_type=5时有效)',
  `householder_info` varchar(128) NOT NULL DEFAULT '' COMMENT '户主信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `building_id_IDX` (`building_id`) USING BTREE,
  KEY `area_type` (`area_type`),
  KEY `idx_floor_id` (`floor_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='房间';

-- ----------------------------
-- Table structure for lb_area_alarm_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_area_alarm_set`;
CREATE TABLE `lb_area_alarm_set` (
  `alarm_set_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) DEFAULT '' COMMENT '区域id',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `alarm_mode` tinyint(1) DEFAULT '0' COMMENT '处警模式，0不更改，1不处理所有报警，2不处理自动报警 3.心率异常报警 4.参与处理手动SOS 5.长时间不动报警 6.在床不动报警 7.洗手间不动报警 8.居所内无生命活动报警 9.洗手间滞留报警',
  `set_time` int(11) DEFAULT '1' COMMENT '处警修改持续时间 0为永久',
  `alarm_set_name` varchar(32) DEFAULT '' COMMENT '处警设置人姓名（处警设置人类型为客服时，为要求人姓名）',
  `alarm_set_type` tinyint(1) DEFAULT '1' COMMENT '处警设置人类型 1子女app用户 3客服',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系描述',
  `csr_id` varchar(64) DEFAULT '' COMMENT '客服Id（处警设置人类型为客服时存在）',
  `is_use` tinyint(1) DEFAULT '0' COMMENT '设置是否过期  0已过期 1未过期',
  `recovery_time` bigint(20) DEFAULT '1' COMMENT '处警修改恢复时间,持续时间为永久时该字段为处警设置时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_open` tinyint(1) DEFAULT '1' COMMENT '是否开启 0 关闭 1开启',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_set_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='区域处警设置表';

-- ----------------------------
-- Table structure for lb_area_bed
-- ----------------------------
DROP TABLE IF EXISTS `lb_area_bed`;
CREATE TABLE `lb_area_bed` (
  `area_bed_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间',
  `bed_name` varchar(32) DEFAULT '' COMMENT '床位',
  `position_desc` varchar(32) DEFAULT '' COMMENT '位置',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `is_use` tinyint(1) DEFAULT '2' COMMENT '1使用 2未使用',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `area_bed_num` varchar(125) DEFAULT '' COMMENT '床位号',
  `area_bed_name` varchar(125) DEFAULT '' COMMENT '名字',
  `area_name` varchar(125) DEFAULT '' COMMENT '房间名',
  `floor_id` varchar(32) DEFAULT '0' COMMENT '楼层id',
  `floor_name` varchar(125) DEFAULT '' COMMENT '楼层名',
  `building_id` varchar(32) DEFAULT '' COMMENT '楼栋id',
  `building_name` varchar(125) DEFAULT '' COMMENT '楼栋名',
  `community_id` varchar(32) DEFAULT '' COMMENT '小区id',
  `community_name` varchar(125) DEFAULT '' COMMENT '小区名',
  `direction` tinyint(1) DEFAULT '0' COMMENT '朝向0:东1:南2:西3:北',
  `bed_type_id` varchar(64) DEFAULT '' COMMENT '床位类型',
  `care_level_id` varchar(32) DEFAULT '' COMMENT '护理标识',
  `nurse_team_id` varchar(32) NOT NULL DEFAULT '' COMMENT '护工小组id',
  `nurse_id` varchar(32) NOT NULL DEFAULT '' COMMENT '护工小组人员id',
  `doctor_team_id` varchar(32) NOT NULL DEFAULT '' COMMENT '医生小组id',
  `doctor_id` varchar(32) NOT NULL DEFAULT '' COMMENT '医生id',
  `butler_id` varchar(32) NOT NULL DEFAULT '' COMMENT '管家id',
  `butler_team_id` varchar(32) NOT NULL DEFAULT '' COMMENT '管家小组id',
  `mainframe_id` varchar(32) DEFAULT '' COMMENT '主机id',
  `is_occupy` tinyint(1) DEFAULT '0' COMMENT '是否有长者入住 0:否 1:是 2被预约 3 试住',
  `private_room` tinyint(1) DEFAULT '0' COMMENT '是否包房（0否，1是）',
  `building_serial_number` varchar(125) DEFAULT '' COMMENT '楼栋编号',
  `bed_nature` int(11) NOT NULL DEFAULT '0' COMMENT '床位性质',
  `bed_code_url` varchar(128) NOT NULL DEFAULT '' COMMENT '床位码地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_bed_id`),
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `lb_area_bed_floor_id_idx` (`floor_id`) USING BTREE,
  KEY `lb_area_bed_building_id_IDX` (`building_id`) USING BTREE,
  KEY `lb_area_bed_community_id_IDX` (`community_id`) USING BTREE,
  KEY `lb_area_bed_org_id_IDX` (`org_id`) USING BTREE,
  KEY `is_delete` (`is_delete`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_area_map
-- ----------------------------
DROP TABLE IF EXISTS `lb_area_map`;
CREATE TABLE `lb_area_map` (
  `area_map_id` varchar(32) NOT NULL COMMENT '主键',
  `area_map_name` varchar(32) NOT NULL DEFAULT '' COMMENT '地图名称',
  `area_map_image_path` varchar(64) NOT NULL DEFAULT '' COMMENT '地图图片路径',
  `area_map_content` text COMMENT '地图附加信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '归属区域id(类型为楼层地图时该字段有有效值)',
  `area_map_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '地图类型：1、室外地图  2、楼层地图 3、总览地图 4、户型图',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为默认地图模板：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_map_id`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='区域地图';

-- ----------------------------
-- Table structure for lb_area_map_area_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_area_map_area_relation`;
CREATE TABLE `lb_area_map_area_relation` (
  `area_map_area_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(64) NOT NULL DEFAULT '' COMMENT '区域id',
  `area_map_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域地图id',
  `area_map_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '地图类型：1、室外地图  2、楼层地图 3、总览地图4、户型图',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_map_area_relation_id`) USING BTREE,
  UNIQUE KEY `uni_area_id_area_map_type` (`area_id`,`area_map_type`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='区域地图关联区域信息表';

-- ----------------------------
-- Table structure for lb_area_map_poi
-- ----------------------------
DROP TABLE IF EXISTS `lb_area_map_poi`;
CREATE TABLE `lb_area_map_poi` (
  `area_map_poi_id` varchar(32) NOT NULL COMMENT '主键',
  `area_map_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属区域地图id',
  `poi_target_id` varchar(64) NOT NULL DEFAULT '' COMMENT '兴趣点目标主键',
  `poi_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '兴趣点类型 见类型枚举',
  `poi_map_position` text COMMENT '兴趣点地图位置信息',
  `poi_image_id` varchar(64) NOT NULL DEFAULT '' COMMENT '兴趣点图片主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `poi_desc` text COMMENT '兴趣点描述',
  `poi_name` varchar(32) NOT NULL DEFAULT '' COMMENT '兴趣点名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_map_poi_id`) USING BTREE,
  KEY `area_map_id` (`area_map_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='区域地图兴趣点表';

-- ----------------------------
-- Table structure for lb_assessment_transaction
-- ----------------------------
DROP TABLE IF EXISTS `lb_assessment_transaction`;
CREATE TABLE `lb_assessment_transaction` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `assessment_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录主键',
  `agency_social_code` varchar(128) NOT NULL DEFAULT '' COMMENT '评估机构统一社会信用代码',
  `agency_name` varchar(128) NOT NULL DEFAULT '' COMMENT '评估机构名称',
  `lead_assessor_name` varchar(128) NOT NULL DEFAULT '' COMMENT '主评估员姓名',
  `lead_assessor_number` varchar(128) NOT NULL DEFAULT '' COMMENT '主评估员证件号码',
  `deputy_assessor_name` varchar(128) NOT NULL DEFAULT '' COMMENT '副评估员姓名',
  `deputy_assessor_number` varchar(128) NOT NULL DEFAULT '' COMMENT '副评估员证件号码',
  `data_source` varchar(16) NOT NULL DEFAULT '' COMMENT '数据来源，01民政 02机构',
  `identification_civil_name` varchar(128) NOT NULL DEFAULT '' COMMENT '认定的民政机构',
  `assessment_location` varchar(256) NOT NULL DEFAULT '' COMMENT '评估工作执行的详细地点',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  PRIMARY KEY (`id`),
  KEY `org_id_index` (`org_id`),
  KEY `assessment_id_index` (`assessment_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='评估事务信息表';

-- ----------------------------
-- Table structure for lb_async_export_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_async_export_task`;
CREATE TABLE `lb_async_export_task` (
  `task_id` varchar(32) NOT NULL COMMENT '任务id',
  `task_name` varchar(64) NOT NULL DEFAULT '' COMMENT '任务名称',
  `task_code` varchar(32) NOT NULL DEFAULT '' COMMENT '任务编码',
  `task_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务类型 (1:导出 2:导入)',
  `task_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务状态1: 待处理2: 导出中3: 已完成4: 导出异常',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '组织id',
  `user_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `priority` tinyint(3) DEFAULT '0' COMMENT '优先级(预留)',
  `task_param` mediumtext COMMENT '任务参数',
  `path_key` varchar(64) DEFAULT '' COMMENT '文件存储key',
  `path` varchar(255) DEFAULT '' COMMENT '文件路径',
  `file_expiry_date` int(11) NOT NULL DEFAULT '30' COMMENT '文件有效期 单位（天）',
  `result` mediumtext COMMENT '处理结果',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `deal_time` bigint(20) DEFAULT '0' COMMENT '处理时间',
  `finish_time` bigint(20) DEFAULT '0' COMMENT '完成时间',
  `parent_task_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '父任务id,0为无父任务',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务是否删除 0未删除 1已删除',
  `file_is_delete` tinyint(1) DEFAULT '0' COMMENT '文件是否删除 0未删除 1已删除',
  `total` int(11) NOT NULL DEFAULT '0' COMMENT '文件总数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='异步导出任务表';

-- ----------------------------
-- Table structure for lb_atest
-- ----------------------------
DROP TABLE IF EXISTS `lb_atest`;
CREATE TABLE `lb_atest` (
  `id` int(11) NOT NULL,
  `create_time` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `update_time` timestamp NULL DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_auth_refresh_token
-- ----------------------------
DROP TABLE IF EXISTS `lb_auth_refresh_token`;
CREATE TABLE `lb_auth_refresh_token` (
  `refresh_token_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `token_id` varchar(32) NOT NULL DEFAULT '' COMMENT '表auth_access_token对应的主键',
  `refresh_token` text NOT NULL COMMENT 'Refresh Token',
  `expire_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '过期时间戳',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`refresh_token_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='Refresh Token信息表';

-- ----------------------------
-- Table structure for lb_authorized_application_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_authorized_application_info`;
CREATE TABLE `lb_authorized_application_info` (
  `app_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `app_name` varchar(32) NOT NULL DEFAULT '' COMMENT '应用名称',
  `client_id` varchar(64) NOT NULL DEFAULT '' COMMENT '应用key',
  `client_secret` varchar(64) NOT NULL DEFAULT '' COMMENT '应用密钥',
  `scope` varchar(255) NOT NULL DEFAULT '' COMMENT 'oauth权限范围',
  `authorized_grant_types` varchar(255) NOT NULL DEFAULT '' COMMENT '支持的授权类型',
  `redirect_uri` varchar(255) NOT NULL DEFAULT '' COMMENT '重定向uri',
  `access_token_validity` bigint(20) NOT NULL DEFAULT '0' COMMENT 'access_token有效时间',
  `refresh_token_validity` bigint(20) NOT NULL DEFAULT '0' COMMENT 'refresh_token有效时间',
  `additional_information` varchar(255) NOT NULL DEFAULT '' COMMENT '客户端的其他信息',
  `trusted` int(11) NOT NULL DEFAULT '1' COMMENT '是否是信任的,0:不受信任，1：信任的',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0未删除；1已删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`app_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='第三方客户端信息表';

-- ----------------------------
-- Table structure for lb_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_balance`;
CREATE TABLE `lb_balance` (
  `balance_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `account_preparatory_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '账户预存款余额',
  `one_card_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '一卡通余额',
  `total_deposit_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '总押金余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '入住状态（0 已入住，1 退住结算中，2 已退住）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`balance_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='余额表';

-- ----------------------------
-- Table structure for lb_band
-- ----------------------------
DROP TABLE IF EXISTS `lb_band`;
CREATE TABLE `lb_band` (
  `band_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置描述(按钮)',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id（电信云平台注册返回）',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT NULL COMMENT '是否加密',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `version` smallint(1) DEFAULT '1' COMMENT '下发信息版本号',
  `serial_num` int(11) NOT NULL DEFAULT '0' COMMENT '序号',
  `expire_time` bigint(20) DEFAULT '0' COMMENT '过期时间（弃用）',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` int(3) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量,2充电中)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `nb_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `real_time_track_status` tinyint(1) DEFAULT '0' COMMENT '实时轨迹功能状态，0关闭，1开启中',
  `real_time_track_last_time` bigint(20) DEFAULT '0' COMMENT '上一次开启实时轨迹的开始时间',
  `heart_time` int(3) DEFAULT '0' COMMENT '手表每小时上报心跳的时间分钟数（秒）',
  `heart_period` int(3) DEFAULT '7200' COMMENT '心跳周期，单位秒',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备软件版本号',
  `electricity_mode` tinyint(1) DEFAULT '2' COMMENT '应用的电量模式,0:eDRX,1:DRX,2:PSM',
  `electricity_mode_code` varchar(32) DEFAULT '' COMMENT '手表电量模式信息',
  `is_restore` tinyint(1) DEFAULT '0' COMMENT '是否需要恢复出厂设置',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型:0',
  `device_iteration_number` int(3) DEFAULT '-1' COMMENT '设备迭代版本号',
  `is_mode_change` tinyint(1) DEFAULT '1' COMMENT '设备模式是否切换完成 0 切换中 1切换完成',
  `last_change_time` bigint(20) DEFAULT '0' COMMENT '设备上次切换时间',
  `power_consumption_mode` tinyint(1) DEFAULT '1' COMMENT '功耗模式 0 超低功耗 1 正常功耗',
  `rand_num` int(11) DEFAULT '0' COMMENT '手表心跳随机数',
  `fault` varchar(16) DEFAULT NULL COMMENT '故障信息（1 心率故障，2 六轴故障，3 WIFI芯片故障，4 生命探头故障）',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `band_name` varchar(32) DEFAULT '' COMMENT ' 手表名称(医院手表)',
  `mainframe_num` varchar(32) DEFAULT '' COMMENT ' 主机号(医院手表)',
  `slave_name` varchar(32) DEFAULT '' COMMENT '分机号(医院手表)',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识(医院手表)',
  `wear_status` tinyint(1) DEFAULT NULL COMMENT '佩戴状态（0 未佩戴， 1 佩戴中）',
  `motion_status` tinyint(1) DEFAULT NULL COMMENT '运动状态（0 静止， 1 活动，2 行走）',
  `config_send_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `send_num` tinyint(3) DEFAULT '1' COMMENT '更新次数',
  `is_product_test` tinyint(1) DEFAULT '0' COMMENT '是否为生产测试设备:0否 1是',
  `energy_monitor_status` tinyint(1) DEFAULT '0' COMMENT '电量监控状态 0未监控,1监测中,2正常,3异常',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警标识（护工手表），已无效',
  `receive_alarm_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接警条数',
  `platform_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '平台类型',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的上报时间',
  `receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `command_version_info` varchar(128) NOT NULL DEFAULT '' COMMENT '各协议命令版本号信息',
  PRIMARY KEY (`band_id`),
  KEY `mac` (`mac`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `imei` (`imei`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `alarm_id` (`alarm_id`) USING BTREE,
  KEY `device_type` (`device_type`) USING BTREE,
  KEY `mainframe_num` (`mainframe_num`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='手环';

-- ----------------------------
-- Table structure for lb_band_position_status_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_band_position_status_record`;
CREATE TABLE `lb_band_position_status_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `band_id` varchar(64) DEFAULT '' COMMENT '手表id',
  `position_status` int(4) DEFAULT '0' COMMENT '位置状态',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `duration` bigint(20) DEFAULT NULL COMMENT '持续时长（单位秒）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='位置状态记录';

-- ----------------------------
-- Table structure for lb_band_power_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_band_power_record`;
CREATE TABLE `lb_band_power_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `band_id` varchar(32) DEFAULT '' COMMENT '手表id',
  `power` int(4) DEFAULT '0' COMMENT '电量',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='电量记录';

-- ----------------------------
-- Table structure for lb_band_wear_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_band_wear_record`;
CREATE TABLE `lb_band_wear_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `band_id` varchar(32) DEFAULT '' COMMENT '手表id',
  `wear_status` int(4) DEFAULT '0' COMMENT '0不显示状态，1佩戴中，2未佩戴，3充电中',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='佩带记录';

-- ----------------------------
-- Table structure for lb_beacon
-- ----------------------------
DROP TABLE IF EXISTS `lb_beacon`;
CREATE TABLE `lb_beacon` (
  `beacon_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位',
  `rail_id` varchar(32) DEFAULT '' COMMENT '围栏',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_type` smallint(3) DEFAULT '20' COMMENT '20:出入口内 21:出入口外 22:危险位置 23:门口 24:客厅 26:公共区域 60:红外探头（床顶） 61:红外探头（活动探测器） 80:门口门灯 ',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `position_re_id` varchar(32) DEFAULT '' COMMENT '位置id',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检测时间',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `building_id` varchar(32) DEFAULT '' COMMENT '楼栋',
  `floor_id` varchar(32) DEFAULT '' COMMENT '楼层',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '所属地图区域id',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id(电信云平台注册返回)',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称(注册时使用)',
  `iot_is_encode` char(1) DEFAULT '' COMMENT '是否加密',
  `iot_psk` char(1) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` char(1) DEFAULT '' COMMENT '安全设备',
  `activated` char(1) DEFAULT '' COMMENT '激活',
  `expire_time` bigint(20) DEFAULT '0' COMMENT 'nb卡套餐可用时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `nb_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备软件版本号',
  `version` smallint(1) NOT NULL DEFAULT '1' COMMENT '下发信息版本号',
  `startup_time` varchar(16) DEFAULT '' COMMENT '开机时间',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '按钮使用长者',
  `rand_num` int(11) DEFAULT '0' COMMENT '心跳随机数',
  `power_report_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量上报次数',
  `position_priority` tinyint(1) DEFAULT '0' COMMENT '定位优先级，从高到低，0无优先级',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `platform_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '平台类型',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的上报时间',
  `receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_bind` tinyint(1) NOT NULL DEFAULT '0' COMMENT '绑定标识（0：未绑定，1：已绑定）',
  `command_version_info` varchar(128) NOT NULL DEFAULT '' COMMENT '各协议命令版本号信息',
  PRIMARY KEY (`beacon_id`),
  KEY `areaId` (`area_id`) USING BTREE,
  KEY `mac` (`mac`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `device_type` (`device_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='信标';

-- ----------------------------
-- Table structure for lb_beacon_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_beacon_area`;
CREATE TABLE `lb_beacon_area` (
  `beacon_area_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间id',
  `beacon_id` varchar(32) NOT NULL DEFAULT '' COMMENT '信标id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`beacon_area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='楼栋楼层设备与房间对应关系表';

-- ----------------------------
-- Table structure for lb_beacon_position_re
-- ----------------------------
DROP TABLE IF EXISTS `lb_beacon_position_re`;
CREATE TABLE `lb_beacon_position_re` (
  `position_re_id` varchar(32) NOT NULL COMMENT '主键',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置叙述',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`position_re_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_big_toilet_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_big_toilet_report`;
CREATE TABLE `lb_big_toilet_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '大解次数',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '大解时长',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='大解报表';

-- ----------------------------
-- Table structure for lb_blood_band_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_blood_band_device`;
CREATE TABLE `lb_blood_band_device` (
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `company_name` varchar(32) NOT NULL DEFAULT '' COMMENT '厂商名称',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `acc_num` varchar(64) NOT NULL DEFAULT '' COMMENT '设备号码',
  `import_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '录入时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`),
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='血压手表表';

-- ----------------------------
-- Table structure for lb_blood_glucose_meter
-- ----------------------------
DROP TABLE IF EXISTS `lb_blood_glucose_meter`;
CREATE TABLE `lb_blood_glucose_meter` (
  `blood_glucose_meter_id` varchar(32) NOT NULL COMMENT '主键',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_type` tinyint(1) NOT NULL DEFAULT '14' COMMENT '设备类型',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '设备序列号',
  `iccid` varchar(64) NOT NULL DEFAULT '' COMMENT '卡号',
  `unit` int(11) NOT NULL DEFAULT '-1' COMMENT '单位',
  `voice_switch` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `power` int(11) NOT NULL DEFAULT '-1' COMMENT '设备电量',
  `signal_strength` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `protocol_ver` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `online_status` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构标识',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `assist_device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '协助设备种类(0:监护手表 4:求救定位器 5:定位手环)',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`blood_glucose_meter_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='血糖仪表';

-- ----------------------------
-- Table structure for lb_blood_glucose_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_blood_glucose_record_statistics`;
CREATE TABLE `lb_blood_glucose_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录结束时间',
  `content` text COMMENT '血糖数据',
  `record_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '记录类型（1 日常，2 轨迹，3 血糖仪测量, 4 实时守护, 5 报警测量, 6 主动测量）',
  `record_time_date` datetime NOT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `lb_blood_glucose_record_statistics_update_time_IDX` (`update_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='血糖记录统计表';

-- ----------------------------
