-- ----------------------------
-- Table structure for lb_call_alert_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_call_alert_set`;
CREATE TABLE `lb_call_alert_set` (
  `call_alert_set_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者Id',
  `alert_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '告警类型（0 云呼，1 短信）',
  `alert_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '告警状态（0 关闭，1 开启）',
  `start_time` varchar(8) NOT NULL DEFAULT '' COMMENT '开始时间',
  `end_time` varchar(8) NOT NULL DEFAULT '' COMMENT '结束时间',
  `set_name` varchar(128) DEFAULT '' COMMENT '设置人姓名（处警设置人类型为客服时，为要求人姓名）',
  `set_type` tinyint(1) NOT NULL COMMENT '设置人类型（ 1 子女app用户，2 系统， 3 客服）',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系描述',
  `csr_id` varchar(64) DEFAULT '' COMMENT '客服Id（设置人类型为客服时存在）',
  `is_valid` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否有效  0 有效，1 失效',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `alert_care_object_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '告警长者类型（详见枚举文档）',
  `alert_contact_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '告警联系人类型（详见枚举文档）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_alert_set_id`),
  KEY `care_object_id` (`care_object_id`,`alert_type`,`is_valid`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='云呼告警时间段设置表';

