DROP TABLE IF EXISTS `lb_call_device_relation`;
CREATE TABLE `lb_call_device_relation` (
  `call_device_relation_id` varchar(32) NOT NULL COMMENT '主键id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `device_called_id` varchar(32) NOT NULL DEFAULT '' COMMENT '可通话设备id',
  `device_un_called_id` varchar(32) NOT NULL DEFAULT '' COMMENT '非通话设备id',
  `device_called_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '可通话设备类型',
  `device_un_called_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '非通话设备类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_device_relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通话设备联动信息表';

-- ----------------------------
-- Table structure for lb_call_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_call_record`;
CREATE TABLE `lb_call_record` (
  `call_record_id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `manager_id` varchar(64) DEFAULT '' COMMENT '管理服务器记录的主键,去重',
  `device_type` varchar(255) DEFAULT NULL COMMENT '设备类型',
  `device_num` varchar(100) DEFAULT NULL COMMENT '设备号',
  `area_name` varchar(100) DEFAULT NULL COMMENT '居住房号',
  `describe` varchar(255) DEFAULT NULL COMMENT '描述',
  `elder_name` varchar(100) DEFAULT NULL COMMENT '长者名称',
  `accept_status` tinyint(1) DEFAULT NULL COMMENT '受理状态',
  `event_type` tinyint(1) DEFAULT NULL COMMENT '事件类型',
  `file_type` tinyint(1) DEFAULT NULL COMMENT '文件类型',
  `event_time` bigint(20) DEFAULT NULL COMMENT '事件时间秒',
  `call_time` bigint(20) DEFAULT NULL COMMENT '呼叫时间秒',
  `communicate_time` bigint(20) DEFAULT NULL COMMENT '通话时长秒',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `master_num` varchar(100) DEFAULT NULL COMMENT '主机号',
  `accept_master_num` varchar(100) DEFAULT NULL COMMENT '接听主机号',
  `upload_master_num` varchar(32) DEFAULT NULL COMMENT '上传记录主机号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_record_id`) USING BTREE,
  KEY `org_manager_event` (`org_id`,`manager_id`,`event_time`),
  KEY `create_time_index` (`create_time`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='通话记录';

-- ----------------------------
-- Table structure for lb_care_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_config`;
CREATE TABLE `lb_care_config` (
  `care_config_id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置对象标识',
  `report_device_type` tinyint(1) DEFAULT NULL COMMENT 'NB上报设备类型',
  `device_iteration_number` tinyint(1) DEFAULT NULL COMMENT '设备迭代版本号',
  `care_config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '监护配置类型（0-协议配置，其他参见监护配置类型枚举）',
  `protocol_config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '协议配置类型（0-非协议配置，其他参见`LB_NB协议`）',
  `param` text NOT NULL COMMENT '参数',
  `param_length` tinyint(1) NOT NULL DEFAULT '1' COMMENT '参数长度（非通讯协议配置无效）',
  `param_order` tinyint(1) NOT NULL DEFAULT '1' COMMENT '参数顺序',
  `param_desc` varchar(256) NOT NULL DEFAULT '' COMMENT '参数描述',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '开放标识（0-禁止配置，1-开放配置）',
  `show_type` int(3) NOT NULL DEFAULT '0' COMMENT '显示类型（0-不显示，其他参见`监护设置显示类型枚举`）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '默认标识（0-自定义，1-默认）',
  `carry_type` tinyint(1) NOT NULL DEFAULT '10' COMMENT '进位类型',
  `carry_digit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '进位数位（十进制无效）',
  `set_item` varchar(64) NOT NULL DEFAULT '' COMMENT '设置项标识',
  `show_page_type` varchar(256) NOT NULL DEFAULT '0' COMMENT '可配置showType页面类型(位:2 <-> 16)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_config_id`),
  KEY `object_id` (`object_id`) USING BTREE,
  KEY `device_type` (`report_device_type`,`device_iteration_number`) USING BTREE,
  KEY `care_config_type` (`care_config_type`) USING BTREE,
  KEY `protocol_config_type` (`protocol_config_type`) USING BTREE,
  KEY `lb_care_config_org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='监护配置表';

-- ----------------------------
-- Table structure for lb_care_config_page
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_config_page`;
CREATE TABLE `lb_care_config_page` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `page_type` int(11) NOT NULL DEFAULT '0' COMMENT '页面类型枚举',
  `system_type` tinyint(4) NOT NULL DEFAULT '0',
  `report_device_type` tinyint(4) DEFAULT NULL COMMENT 'NB设备上报类型',
  `device_iteration_number` tinyint(4) DEFAULT NULL COMMENT '迭代号',
  `show_type` int(11) NOT NULL DEFAULT '0' COMMENT '显示类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `lb_care_config_page_page_type_index` (`page_type`),
  KEY `lb_care_config_page_show_type_index` (`show_type`),
  KEY `lb_care_config_page_system_type_index` (`system_type`)
) ENGINE=InnoDB AUTO_INCREMENT=61258 DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object`;
CREATE TABLE `lb_care_object` (
  `care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭组',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `name` varchar(128) DEFAULT NULL COMMENT '长者姓名',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `birthday_type` tinyint(1) DEFAULT '0' COMMENT '生日类型 0 阳历 1 阴历',
  `description` varchar(32) DEFAULT '' COMMENT '描述信息',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `phone_num` varchar(12) DEFAULT '' COMMENT '电话号码',
  `telephone` varchar(32) DEFAULT '' COMMENT '台机号码',
  `photo` varchar(128) DEFAULT '' COMMENT '头像地址',
  `age` int(11) DEFAULT '0' COMMENT '入住时年龄',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `is_valid` tinyint(1) DEFAULT '1' COMMENT '是否有效，1有效，0失效（机构退住）',
  `nation` varchar(32) DEFAULT '' COMMENT '民族',
  `marital_status` int(11) DEFAULT NULL COMMENT '婚姻状况',
  `political_status` varchar(32) DEFAULT '' COMMENT '政治面貌',
  `faith` varchar(32) DEFAULT '' COMMENT '宗教信仰',
  `hobby` varchar(32) DEFAULT '' COMMENT '兴趣爱好',
  `educational_level` int(4) DEFAULT NULL COMMENT '文化程度 9文盲 8半文盲 7小学 6初中 5高中 4中专 3本科 2大专 1研究生 0博士',
  `retired_occupation` varchar(32) DEFAULT '' COMMENT '退休职业',
  `disease_status` text COMMENT '病情状态描述',
  `at_home` tinyint(1) DEFAULT NULL COMMENT '长者是否在家（0否，1是）',
  `out_home_time` bigint(20) DEFAULT '0' COMMENT '离/回家时间',
  `bed_btn_id` varchar(32) DEFAULT NULL COMMENT '主要使用按钮（床头）',
  `toilet_btn_id` varchar(32) DEFAULT NULL COMMENT '主要使用按钮（洗手间）',
  `is_settle` tinyint(1) DEFAULT '0' COMMENT '是否已退住结算（0 否，1 是）',
  `archives_id` varchar(32) DEFAULT '' COMMENT '档案号',
  `sign_time` bigint(20) DEFAULT '0' COMMENT '签订合同日期',
  `sign_number` varchar(125) NOT NULL DEFAULT '' COMMENT '签订合同编号',
  `try_start_time` bigint(20) DEFAULT '0' COMMENT '试住开始时间',
  `try_end_time` bigint(20) DEFAULT '0' COMMENT '试住结束时间',
  `last_region_id` varchar(32) DEFAULT NULL COMMENT '最后一级区域id',
  `receiver_id` varchar(128) DEFAULT '' COMMENT '接待人id',
  `receiver_name` varchar(32) DEFAULT '' COMMENT '接待人name',
  `receiver_phone` varchar(20) DEFAULT NULL COMMENT '接待人手机号',
  `is_try` tinyint(1) DEFAULT '0' COMMENT '是否试住，0入住；1试住',
  `charging_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '试住收费模式',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '入住床位id,废弃',
  `birthday_date` date DEFAULT NULL COMMENT '出生日期date类型冗余,方便统计生日',
  `is_pay_cost` tinyint(1) DEFAULT '0' COMMENT '是否已入院缴费,0未,1已',
  `pay_cost_time` bigint(20) DEFAULT '0' COMMENT '入住缴费时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `last_position` varchar(32) DEFAULT '' COMMENT '前次位置（区/县）',
  `care_object_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1护理楼长者 2 公寓楼长者 3 社区居家长者',
  `sign_expire` bigint(20) DEFAULT NULL COMMENT '到期时间',
  `is_deathbed` tinyint(1) DEFAULT '0' COMMENT '是否是关怀对象：1是，0否，2死亡',
  `registrant` varchar(128) DEFAULT NULL COMMENT '姓名',
  `identity_type` int(11) DEFAULT '0' COMMENT '身份证类型;0:中国居民身份证,1:香港身份证,2:澳门身份证,3:台湾身份证',
  `last_synch_time` bigint(20) DEFAULT '0' COMMENT '长者信息同步到芜湖智慧养老 上次同步时间',
  `is_upload_today` tinyint(1) DEFAULT '0' COMMENT '南陵今日是否上传',
  `house_type` tinyint(1) DEFAULT NULL COMMENT '户籍类别 0:农村 1:城市',
  `group_tags` varchar(128) DEFAULT NULL COMMENT '分组标记',
  `migrate_count` tinyint(1) DEFAULT '0' COMMENT '长者迁移次数',
  `funding_type` varchar(128) NOT NULL DEFAULT '' COMMENT '资助类型',
  `funding_status` varchar(128) NOT NULL DEFAULT '' COMMENT '资助状态',
  `org_sign_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目标识',
  `pay_identity_way` varchar(64) NOT NULL DEFAULT '0' COMMENT '0全部，1 人脸识别，2 刷卡识别 ，3 扫长者助餐二维码识别,多个用逗号隔开',
  `emergency_door_method` varchar(255) NOT NULL DEFAULT '' COMMENT '紧急情况下开启门禁的具体方式描述',
  `archive_num` varchar(32) NOT NULL DEFAULT '' COMMENT '档案号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `is_delete` (`is_delete`),
  KEY `update_time` (`update_time`),
  KEY `lb_care_object_identity_IDX` (`identity`) USING BTREE,
  KEY `care_object_type` (`care_object_type`),
  KEY `idx_phone_num` (`phone_num`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='看护对象';

-- ----------------------------
-- Table structure for lb_care_object_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_area`;
CREATE TABLE `lb_care_object_area` (
  `elder_area_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `area` varchar(32) DEFAULT '' COMMENT '房间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `building` varchar(11) DEFAULT '' COMMENT '楼栋',
  `bed` varchar(11) DEFAULT '' COMMENT '床位',
  `unit` varchar(255) DEFAULT '' COMMENT '单元（弃用）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='看护对象绑定房间表';

-- ----------------------------
-- Table structure for lb_care_object_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_balance`;
CREATE TABLE `lb_care_object_balance` (
  `care_object_balance_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '长者id',
  `amount` double DEFAULT '0' COMMENT '余额',
  `pay_time` bigint(20) DEFAULT '0' COMMENT '最新付款时间',
  `user_type` char(1) DEFAULT '1' COMMENT '1.app用户',
  `expire_time` bigint(20) DEFAULT '0' COMMENT '到期时间',
  `last_order_id` varchar(64) DEFAULT '' COMMENT '上次订单id',
  `last_description` varchar(32) DEFAULT '' COMMENT '上次订单叙述',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构组织id',
  `trial_user` char(1) DEFAULT '0' COMMENT '0:试用用户 1:vip用户',
  `identity` varchar(32) DEFAULT '' COMMENT '注释身份证',
  `band_imei` varchar(32) DEFAULT '' COMMENT '手表imei号',
  `is_give` char(1) DEFAULT '0' COMMENT '默认0 注释0未赠送 1已经赠送',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `notice_record_time` bigint(20) DEFAULT '0' COMMENT '上次即将到期提醒时间',
  `expire_record_time` bigint(20) DEFAULT '0' COMMENT '上次到期记录时间',
  `device_type` tinyint(3) DEFAULT '0' COMMENT '设备类型:0手表 1求救定位器',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_balance_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_band_imei` (`band_imei`) USING BTREE,
  KEY `idx_identity` (`identity`),
  KEY `idx_org_id_identity` (`identity`,`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者余额表';

-- ----------------------------
-- Table structure for lb_care_object_careinfo
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_careinfo`;
CREATE TABLE `lb_care_object_careinfo` (
  `careinfo_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT 'care_object_id',
  `care_level_id` varchar(32) DEFAULT '' COMMENT '看护等级',
  `check_in_num` varchar(32) DEFAULT '' COMMENT '入住编号',
  `check_in_time` bigint(20) DEFAULT '0' COMMENT '入住时间',
  `check_in_pay_time` bigint(20) DEFAULT '0' COMMENT '入住缴费时间',
  `check_out_time` bigint(20) DEFAULT '0' COMMENT '退住时间',
  `care_instruction_one` varchar(255) DEFAULT '' COMMENT '注意事项一',
  `care_instruction_two` varchar(255) DEFAULT '' COMMENT '注意事项二',
  `care_instruction_three` varchar(255) DEFAULT '' COMMENT '注意事项三',
  `care_instruction_four` varchar(255) DEFAULT '' COMMENT '注意事项四',
  `medical_history` text COMMENT '病史',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `address` varchar(255) DEFAULT NULL COMMENT 'address',
  `region` varchar(255) DEFAULT '' COMMENT '区域',
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `diet_type` varchar(255) DEFAULT '' COMMENT '饮食类型',
  `medicare_type` varchar(255) DEFAULT '' COMMENT '医保类型',
  `critical_type` varchar(255) DEFAULT '' COMMENT '危重类型',
  `disability_type` varchar(32) DEFAULT NULL COMMENT '残疾类型',
  `elderly_type` varchar(255) DEFAULT '' COMMENT '长者类别',
  `risk_tips` varchar(255) DEFAULT '' COMMENT '风险提示',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `blood_type` varchar(32) DEFAULT NULL COMMENT '血型',
  `is_local` tinyint(1) DEFAULT NULL COMMENT '是否本市户籍,0不是本地；1是本地',
  `src_live` varchar(128) DEFAULT '' COMMENT '原居住情况',
  `is_nonlocal` tinyint(1) DEFAULT NULL COMMENT '是否外地迁入,0不是外地迁入;1是',
  `family_number` varchar(32) DEFAULT NULL COMMENT '家庭人口',
  `census_register` varchar(255) DEFAULT NULL COMMENT '户籍地址',
  `census_register_region` varchar(255) DEFAULT NULL COMMENT '户籍地址regionid',
  `home_address` varchar(255) DEFAULT NULL COMMENT '家庭住址',
  `disposition` varchar(32) DEFAULT NULL COMMENT '性格',
  `economic_sources` varchar(128) DEFAULT '' COMMENT '经济来源',
  `diet` varchar(32) DEFAULT NULL COMMENT '饮食特点',
  `labor_power` varchar(32) DEFAULT NULL COMMENT '劳动能力',
  `medical_number` varchar(50) DEFAULT NULL COMMENT '医保卡号',
  `vision` varchar(32) DEFAULT NULL COMMENT '视力',
  `hearing` varchar(32) DEFAULT NULL COMMENT '听力',
  `hospital` varchar(32) DEFAULT NULL COMMENT '主治医院',
  `hospital_doctor` varchar(128) DEFAULT NULL COMMENT '姓名',
  `hospital_phone` varchar(32) DEFAULT NULL COMMENT '医院电话',
  `drug_allergy` varchar(255) DEFAULT NULL COMMENT '过敏药物',
  `major_diseases` varchar(32) DEFAULT NULL COMMENT '主要疾病',
  `oneself_situation` varchar(32) DEFAULT NULL COMMENT '自理情况',
  `assessment_result` varchar(100) DEFAULT NULL COMMENT '健康评估结果',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '登记人姓名',
  `wechat_num` varchar(32) DEFAULT '' COMMENT '微信号',
  `tiktok_num` varchar(32) DEFAULT '' COMMENT '抖音号',
  `retired_unit` varchar(255) DEFAULT NULL COMMENT '退休单位',
  `smoke` tinyint(1) DEFAULT NULL COMMENT '是否吸烟 0否 1是',
  `drink` tinyint(1) DEFAULT NULL COMMENT '是否饮酒 0否 1是',
  `food_allergy_history` varchar(255) DEFAULT NULL COMMENT '食物过敏史',
  `monthly_pay` varchar(1) DEFAULT NULL COMMENT '月收入1：0-3000，2：3000-5000,3:5000-8000,4:8000-10000,5：10000以上',
  `live` varchar(10) DEFAULT NULL COMMENT '居住情况',
  `intention_care_way` varchar(10) DEFAULT NULL COMMENT '意向养老方式1：机构养老,2:社区养老,3:居家养老,4：老年大学，5：旅居养老',
  `pain_point_problem` varchar(255) DEFAULT NULL COMMENT '痛点问题',
  `other_care_way` varchar(30) DEFAULT NULL COMMENT '其他养老方式',
  `admit_name` varchar(128) DEFAULT NULL COMMENT '接待人员',
  `stay_back_reason` varchar(1) DEFAULT '0' COMMENT '退住原因 0：其它，1：已过世，2：已取消补贴',
  `lat` varchar(32) DEFAULT NULL COMMENT '经度',
  `lng` varchar(32) DEFAULT NULL COMMENT '纬度',
  `location` varchar(100) DEFAULT NULL COMMENT '具体位置',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `house_area` decimal(8,2) DEFAULT NULL COMMENT '房屋面积',
  `income_month` decimal(8,2) DEFAULT NULL COMMENT '平均月收入',
  `bank_name` varchar(64) DEFAULT NULL COMMENT '开户行',
  `bank_account` varchar(32) DEFAULT NULL COMMENT '银行账号',
  `bank_user` varchar(32) DEFAULT NULL COMMENT '开户人',
  `bank_phone_num` varchar(32) DEFAULT NULL COMMENT '开户人联系电话',
  `ward_rounds_time` bigint(20) DEFAULT NULL,
  `pay_type` varchar(125) DEFAULT NULL COMMENT '医疗费用支付方式',
  `is_enjoy_serve` tinyint(1) DEFAULT '1' COMMENT '0:享受 1:不享受',
  `intention_serve` varchar(255) NOT NULL DEFAULT '' COMMENT '意向服务id',
  `enjoy_serve_times` int(11) NOT NULL DEFAULT '0' COMMENT '享受服务次数',
  `door_photo` varchar(64) NOT NULL DEFAULT '' COMMENT '长者入户门照片',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `check_in_level_id` varchar(32) NOT NULL DEFAULT '' COMMENT '入住等级id',
  PRIMARY KEY (`careinfo_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `care_level_id` (`care_level_id`),
  KEY `region` (`region`(191))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='看护对象在机构的看护信息;';

-- ----------------------------
-- Table structure for lb_care_object_careinfo_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_careinfo_contacts`;
CREATE TABLE `lb_care_object_careinfo_contacts` (
  `contacts_id` varchar(64) NOT NULL COMMENT '主键',
  `name` varchar(128) DEFAULT NULL,
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `relation` varchar(32) DEFAULT '' COMMENT '关系',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '老人id',
  `is_guardian` tinyint(1) DEFAULT '2' COMMENT '是否是监护人,1 是，2 否',
  `guardian_first` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否第一监护人',
  `identity` varchar(32) DEFAULT NULL COMMENT '身份证',
  `gender` varchar(32) DEFAULT '' COMMENT '性别 1 男 2 女',
  `birthday` varchar(32) DEFAULT NULL COMMENT '生日,计算年龄',
  `is_local` tinyint(1) DEFAULT '2' COMMENT '是否本地户籍 1 是 2 否',
  `address` varchar(32) DEFAULT '' COMMENT '联系住址',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `region` varchar(255) DEFAULT NULL COMMENT '省市区',
  `telephone` varchar(30) DEFAULT NULL COMMENT '固定电话',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contacts_id`),
  KEY `lb_care_object_careinfo_contacts_care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `delete_time` (`is_delete`,`update_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='看护对象亲属表';

-- ----------------------------
-- Table structure for lb_care_object_careinfo_trace_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_careinfo_trace_record`;
CREATE TABLE `lb_care_object_careinfo_trace_record` (
  `trace_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT 'care_object_id,长者id',
  `trace_record_info` varchar(1000) DEFAULT '' COMMENT '跟踪记录信息',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0：未删除，1：删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `record_name` varchar(32) DEFAULT '' COMMENT '记录人',
  `record_account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '跟踪记录人id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`trace_record_id`),
  KEY `lb_care_object_careinfo_trace_record_care_object_id_IDX` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='居家长者跟踪记录表';

-- ----------------------------
-- Table structure for lb_care_object_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_device`;
CREATE TABLE `lb_care_object_device` (
  `care_object_device_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `device_id` varchar(32) DEFAULT '' COMMENT '设备',
  `device_type` smallint(4) NOT NULL DEFAULT '0' COMMENT '设备类型 0 手环 100交互终端',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` int(11) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_device_id`),
  KEY `care_object_id` (`care_object_id`,`device_id`) USING BTREE,
  KEY `device_id` (`device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='看护对象与设备绑定';

-- ----------------------------
-- Table structure for lb_care_object_expense
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_expense`;
CREATE TABLE `lb_care_object_expense` (
  `care_object_expense_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `expense_id` varchar(32) NOT NULL DEFAULT '' COMMENT '费用主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_expense_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `expense_id` (`expense_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='长者费用表';

-- ----------------------------
-- Table structure for lb_care_object_family
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_family`;
CREATE TABLE `lb_care_object_family` (
  `care_object_family_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `family_id` varchar(32) NOT NULL DEFAULT '' COMMENT '家庭id',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `org_type` tinyint(4) DEFAULT '2' COMMENT '机构类型 字典表organization_type',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_valid` tinyint(1) NOT NULL DEFAULT '1',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_family_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_org_type_is_valid` (`org_type`,`is_valid`,`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='老人家庭表';

-- ----------------------------
-- Table structure for lb_care_object_health_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_health_device`;
CREATE TABLE `lb_care_object_health_device` (
  `care_object_health_device_id` varchar(32) NOT NULL COMMENT '主键',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_type` tinyint(1) NOT NULL DEFAULT '14' COMMENT '设备类型',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac地址',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '设备序列号',
  `iccid` varchar(64) NOT NULL DEFAULT '' COMMENT '卡号',
  `unit` int(11) NOT NULL DEFAULT '-1' COMMENT '单位',
  `voice_switch` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `signal_strength` int(11) NOT NULL DEFAULT '-1' COMMENT '信号强度',
  `protocol_ver` varchar(32) NOT NULL DEFAULT '1.0.0' COMMENT '版本号',
  `online_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1:在线 0:离线',
  `power` int(11) NOT NULL DEFAULT '-1' COMMENT '设备电量',
  `online_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '在线时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构标识',
  `energy_check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '电量检查时间',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_health_device_id`),
  KEY `device_type_device_iteration_number_index` (`device_type`,`device_iteration_number`),
  KEY `lb_care_object_health_device_org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='长者健康设备表';

-- ----------------------------
-- Table structure for lb_care_object_health_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_health_record`;
CREATE TABLE `lb_care_object_health_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `content` mediumtext NOT NULL COMMENT '记录内容',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `record_type` tinyint(4) DEFAULT '0' COMMENT '体征数据类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='体征记录表';

-- ----------------------------
-- Table structure for lb_care_object_insurance
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_insurance`;
CREATE TABLE `lb_care_object_insurance` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `care_object_id` varchar(32) NOT NULL DEFAULT '',
  `balance` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '余额',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '状态(0:正常 1:已注销)',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `register_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_account_name` varchar(16) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id_index` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者-长期护理保险账户表';

-- ----------------------------
-- Table structure for lb_care_object_insurance_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_insurance_detail`;
CREATE TABLE `lb_care_object_insurance_detail` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `insurance_id` varchar(32) NOT NULL DEFAULT '',
  `type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '类型(0:充值 1:消费)',
  `type_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '类型描述',
  `amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '变动金额',
  `after_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '变更后金额',
  `change_month` bigint(20) NOT NULL DEFAULT '0' COMMENT '变更月份(月份1号0点0分，秒级时间戳)',
  `change_time` int(11) NOT NULL DEFAULT '0' COMMENT '变更时间(秒级时间戳)',
  `remark` text NOT NULL COMMENT '备注',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '变更人id',
  `account_name` varchar(16) NOT NULL DEFAULT '' COMMENT '变更人名称',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `insurance_id_index` (`insurance_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_care_object_jpush_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_jpush_record`;
CREATE TABLE `lb_care_object_jpush_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '老人id',
  `record_type` int(11) DEFAULT '0' COMMENT '报警类型',
  `content` text COMMENT '内容',
  `record_time` bigint(20) DEFAULT '0' COMMENT '报警时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `family_id` varchar(64) DEFAULT '' COMMENT '家庭id',
  `receive_account` varchar(64) DEFAULT '' COMMENT '接受账户',
  `alarm_id` varchar(64) DEFAULT '' COMMENT '报警账户',
  `read_account` text COMMENT '已读的账号',
  `call_order_id` varchar(64) DEFAULT '' COMMENT '云呼工单号（云呼告警）',
  `call_result` text COMMENT '云呼结果（云呼告警）',
  `is_receive_alarm` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接警标识（0-未接警，1-已接警）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `alarm_id` (`alarm_id`) USING HASH,
  KEY `family_id` (`family_id`) USING BTREE,
  KEY `receive_account` (`receive_account`) USING HASH,
  KEY `create_time` (`create_time`),
  KEY `record_time` (`record_time`),
  KEY `care_object_id` (`care_object_id`,`record_type`) USING BTREE,
  KEY `record_type` (`record_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_care_object_last_track
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_last_track`;
CREATE TABLE `lb_care_object_last_track` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '0信标位置,1非信标位置(粗定位,gps,wifi)',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` smallint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '原始纬度',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '原始经度',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '心率值',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `blood_oxygen` int(3) DEFAULT '-1' COMMENT '血氧值',
  `device_status` tinyint(1) DEFAULT '1' COMMENT '手表佩带情况，0不显示佩带情况，1佩戴中，2未佩戴，3充电中',
  `device_status_duration` bigint(20) DEFAULT '0' COMMENT '佩带状态持续时长',
  `systolic_pressure` int(3) DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT '-1' COMMENT '舒张压',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `temperature` tinyint(3) DEFAULT '-10' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_humiture_sensor` tinyint(3) DEFAULT '0' COMMENT '是否有温湿度传感器 0:没有 1:有',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '老人id',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_status` text COMMENT '位置状态记录',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`),
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE,
  KEY `care_object_id` (`care_object_id`,`record_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者轨迹最新记录信息';

-- ----------------------------
-- Table structure for lb_care_object_location_adjust
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_location_adjust`;
CREATE TABLE `lb_care_object_location_adjust` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `distance` int(3) NOT NULL DEFAULT '10000' COMMENT '校准距离',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='长者定位校准表';

-- ----------------------------
-- Table structure for lb_care_object_org
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_org`;
CREATE TABLE `lb_care_object_org` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `family_id` varchar(32) NOT NULL DEFAULT '' COMMENT '家庭id',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `belong_org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '归属机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `belong_org_id` (`belong_org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者归属项目关联信息表';

-- ----------------------------
-- Table structure for lb_care_object_password
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_password`;
CREATE TABLE `lb_care_object_password` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `care_object_id` varchar(32) NOT NULL DEFAULT '',
  `password_type` int(11) NOT NULL DEFAULT '0' COMMENT '密码类型(1:钥匙盒密码)',
  `password` varchar(16) NOT NULL DEFAULT '' COMMENT '密码',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `last_password` varchar(32) NOT NULL DEFAULT '' COMMENT '上一次密码数据',
  `authorize` tinyint(4) NOT NULL DEFAULT '0' COMMENT '授权状态(0:未授权, 1:已授权)',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者密码信息';

-- ----------------------------
-- Table structure for lb_care_object_reported
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_reported`;
CREATE TABLE `lb_care_object_reported` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `reported_type` varchar(32) DEFAULT '' COMMENT '上报消息类型',
  `reported_time` bigint(20) DEFAULT '0' COMMENT '上报时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='手表上报时间表';

-- ----------------------------
-- Table structure for lb_care_object_terminal
-- ----------------------------
DROP TABLE IF EXISTS `lb_care_object_terminal`;
CREATE TABLE `lb_care_object_terminal` (
  `care_object_terminal_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人ID',
  `account_id` varchar(32) DEFAULT '' COMMENT '账号',
  `action` varchar(32) DEFAULT NULL COMMENT 'iemi',
  `inter_cmd` varchar(32) DEFAULT NULL COMMENT 'mac',
  `ip` varchar(32) DEFAULT NULL COMMENT 'ip',
  `port` varchar(32) DEFAULT NULL COMMENT '端口',
  `address_ip` varchar(32) DEFAULT NULL COMMENT '地址ip',
  `display_num` varchar(32) DEFAULT NULL COMMENT 'display_num',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `terminal_id` varchar(32) DEFAULT NULL COMMENT '终端主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_terminal_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='老人与智能终端绑定关系表';

-- ----------------------------
-- Table structure for lb_careinfo_building
-- ----------------------------
DROP TABLE IF EXISTS `lb_careinfo_building`;
CREATE TABLE `lb_careinfo_building` (
  `careinfo_building_id` varchar(32) NOT NULL COMMENT '主键',
  `careinfo_id` varchar(32) DEFAULT '' COMMENT '看护对象ID',
  `building_id` varchar(32) DEFAULT '' COMMENT '楼栋ID',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间ID',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位ID',
  `private_room` tinyint(1) DEFAULT '0' COMMENT '是否包房（0否，1是）',
  `unit` varchar(32) DEFAULT '' COMMENT '单元',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `community_id` varchar(32) DEFAULT '' COMMENT '小区',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`careinfo_building_id`),
  KEY `building_id` (`building_id`) USING BTREE,
  KEY `bed_id` (`bed_id`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `careinfo_id` (`careinfo_id`) USING BTREE,
  KEY `community_id` (`community_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='老人机构房间绑定关系表;';

-- ----------------------------
-- Table structure for lb_check_out_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_check_out_care_object`;
CREATE TABLE `lb_check_out_care_object` (
  `care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭组',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `description` varchar(32) DEFAULT '' COMMENT '描述信息',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `telephone` varchar(12) DEFAULT '' COMMENT '台机号码',
  `photo` varchar(128) DEFAULT '' COMMENT '头像地址',
  `age` tinyint(3) DEFAULT '0' COMMENT '年龄',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `is_valid` tinyint(1) DEFAULT '1' COMMENT '是否有效，1有效，0失效（机构退住）',
  `nation` varchar(32) DEFAULT '' COMMENT '民族',
  `marital_status` tinyint(1) DEFAULT NULL COMMENT '婚姻状况  1已婚 3未婚 2离异 4丧偶',
  `political_status` varchar(32) DEFAULT '' COMMENT '政治面貌',
  `faith` varchar(32) DEFAULT '' COMMENT '宗教信仰',
  `hobby` varchar(32) DEFAULT '' COMMENT '兴趣爱好',
  `educational_level` tinyint(1) DEFAULT NULL COMMENT '文化程度 9文盲 8半文盲 7小学 6初中 5高中 4中专 3本科 2大专 1研究生 0博士',
  `retired_occupation` varchar(32) DEFAULT '' COMMENT '退休职业',
  `disease_status` text COMMENT '病情状态描述',
  `at_home` tinyint(1) DEFAULT NULL COMMENT '长者是否在家（0否，1是）',
  `out_home_time` bigint(20) DEFAULT '0' COMMENT '离/回家时间',
  `bed_btn_id` varchar(32) DEFAULT NULL COMMENT '主要使用按钮（床头）',
  `toilet_btn_id` varchar(32) DEFAULT NULL COMMENT '主要使用按钮（洗手间）',
  `is_settle` tinyint(1) DEFAULT '0' COMMENT '是否已退住结算（0 否，1 是）',
  `archives_id` varchar(32) DEFAULT '' COMMENT '档案号',
  `sign_time` bigint(20) DEFAULT '0' COMMENT '签订合同日期',
  `try_start_time` bigint(20) DEFAULT '0' COMMENT '试住开始时间',
  `try_end_time` bigint(20) DEFAULT '0' COMMENT '试住结束时间',
  `receiver_id` varchar(32) DEFAULT '' COMMENT '接待人id',
  `receiver_name` varchar(32) DEFAULT '' COMMENT '接待人name',
  `receiver_phone` varchar(20) DEFAULT NULL COMMENT '接待人手机号',
  `is_try` tinyint(1) DEFAULT NULL COMMENT '是否试住，0入住；1试住',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '入住床位id',
  `birthday_date` date DEFAULT NULL COMMENT '出生日期date类型冗余,方便统计生日',
  `is_pay_cost` tinyint(1) DEFAULT '0' COMMENT '是否已入院缴费,0未,1已',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `last_position` varchar(32) DEFAULT '' COMMENT '前次位置（区/县）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='退住看护对象';

-- ----------------------------
-- Table structure for lb_check_out_care_object_careinfo
-- ----------------------------
DROP TABLE IF EXISTS `lb_check_out_care_object_careinfo`;
CREATE TABLE `lb_check_out_care_object_careinfo` (
  `careinfo_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT 'care_object_id',
  `care_level_id` varchar(32) DEFAULT '' COMMENT '看护等级',
  `check_in_num` varchar(32) DEFAULT '' COMMENT '入住编号',
  `check_in_time` bigint(20) DEFAULT '0' COMMENT '入住时间',
  `check_out_time` bigint(20) DEFAULT '0' COMMENT '退住时间',
  `care_instruction_one` varchar(255) DEFAULT '' COMMENT '注意事项一',
  `care_instruction_two` varchar(255) DEFAULT '' COMMENT '注意事项二',
  `care_instruction_three` varchar(255) DEFAULT '' COMMENT '注意事项三',
  `care_instruction_four` varchar(255) DEFAULT '' COMMENT '注意事项四',
  `medical_history` varchar(255) DEFAULT '' COMMENT '病史',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `address` varchar(255) DEFAULT '' COMMENT 'address',
  `region` varchar(255) DEFAULT '' COMMENT '区域',
  `diet_type` varchar(255) DEFAULT '' COMMENT '饮食类型',
  `medicare_type` varchar(255) DEFAULT '' COMMENT '医保类型',
  `critical_type` varchar(255) DEFAULT '' COMMENT '危重类型',
  `elderly_type` varchar(255) DEFAULT '' COMMENT '长者类别',
  `risk_tips` varchar(255) DEFAULT '' COMMENT '风险提示',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `blood_type` varchar(32) DEFAULT NULL COMMENT '血型',
  `is_local` tinyint(1) DEFAULT NULL COMMENT '是否本市户籍,0不是本地；1是本地',
  `src_live` varchar(32) DEFAULT NULL COMMENT '原居住情况',
  `is_nonlocal` tinyint(1) DEFAULT NULL COMMENT '是否外地迁入,0不是外地迁入;1是',
  `family_number` varchar(32) DEFAULT NULL COMMENT '家庭人口',
  `census_register` varchar(255) DEFAULT NULL COMMENT '户籍地址',
  `census_register_region` varchar(255) DEFAULT NULL COMMENT '户籍地址regionid',
  `home_address` varchar(255) DEFAULT NULL COMMENT '家庭住址',
  `disposition` varchar(32) DEFAULT NULL COMMENT '性格',
  `economic_sources` varchar(32) DEFAULT NULL COMMENT '经济来源',
  `diet` varchar(32) DEFAULT NULL COMMENT '饮食特点',
  `labor_power` varchar(32) DEFAULT NULL COMMENT '劳动能力',
  `medical_number` varchar(32) DEFAULT NULL COMMENT '医保卡号',
  `vision` varchar(32) DEFAULT NULL COMMENT '视力',
  `hearing` varchar(32) DEFAULT NULL COMMENT '听力',
  `hospital` varchar(32) DEFAULT NULL COMMENT '主治医院',
  `hospital_doctor` varchar(32) DEFAULT NULL COMMENT '主治医生',
  `hospital_phone` varchar(32) DEFAULT NULL COMMENT '医院电话',
  `drug_allergy` varchar(32) DEFAULT NULL COMMENT '过敏药物',
  `major_diseases` varchar(32) DEFAULT NULL COMMENT '主要疾病',
  `oneself_situation` varchar(32) DEFAULT NULL COMMENT '自理情况',
  `assessment_result` varchar(100) DEFAULT NULL COMMENT '健康评估结果',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_name` varchar(32) DEFAULT NULL COMMENT '登记人姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`careinfo_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='看护对象在机构的看护信息';

-- ----------------------------
-- Table structure for lb_check_out_care_object_careinfo_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_check_out_care_object_careinfo_contacts`;
CREATE TABLE `lb_check_out_care_object_careinfo_contacts` (
  `contacts_id` varchar(64) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT '' COMMENT '姓名',
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `relation` varchar(32) DEFAULT '' COMMENT '关系',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '老人id',
  `is_guardian` tinyint(1) DEFAULT NULL COMMENT '是否是监护人,0不是，1是',
  `identity` varchar(32) DEFAULT NULL COMMENT '身份证',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` varchar(32) DEFAULT NULL COMMENT '生日,计算年龄',
  `is_local` tinyint(1) DEFAULT NULL COMMENT '是否本地户籍',
  `address` varchar(32) DEFAULT '' COMMENT '联系住址',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `region` varchar(255) DEFAULT NULL COMMENT '省市区',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contacts_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='退住长者亲属信息';

-- ----------------------------
-- Table structure for lb_check_out_emergency_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_check_out_emergency_contacts`;
CREATE TABLE `lb_check_out_emergency_contacts` (
