-- ----------------------------
-- Table structure for lb_cms_abandon_serve
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_abandon_serve`;
CREATE TABLE `lb_cms_abandon_serve` (
  `abandon_serve_id` varchar(32) NOT NULL COMMENT '放弃服务id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `abandon_reason` varchar(100) NOT NULL COMMENT '放弃原因',
  `is_abandon` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否放弃服务 1 放弃服务 0 不放弃',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '修改人',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `abandon_type` int(11) NOT NULL DEFAULT '0' COMMENT '放弃服务类型，详细见字典项',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`abandon_serve_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='放弃服务长者表';

-- ----------------------------
-- Table structure for lb_cms_account_composite_view_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_account_composite_view_config`;
CREATE TABLE `lb_cms_account_composite_view_config` (
  `id` varchar(32) NOT NULL COMMENT '记录主键',
  `account_id` varchar(32) DEFAULT NULL COMMENT '账号ＩＤ',
  `view_style` int(11) DEFAULT '0' COMMENT '显示模板风格',
  `type` int(11) DEFAULT NULL COMMENT '设置项目类别　１长者信息－２长者指标－３可配置项－４可显示项——5位置信息',
  `item` varchar(32) DEFAULT NULL COMMENT '配置项目',
  `item_name` varchar(32) DEFAULT NULL COMMENT '项目名称',
  `item_setting` varchar(200) DEFAULT NULL COMMENT '项目设置　Ｙ启用　Ｎ不启用　设置内容　',
  `order_num` int(11) DEFAULT NULL COMMENT '排序字段',
  `view_model` int(11) DEFAULT '0' COMMENT '显示模板',
  `data_source` tinyint(1) DEFAULT '1' COMMENT '数据源 1：床垫 2：平台',
  `elder_type` tinyint(1) DEFAULT '1' COMMENT '长者类型： 1：居家长者 2：机构长者',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 ：0非删除 1：删除',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `field_type` tinyint(1) DEFAULT NULL COMMENT '字段属性：1：社区 2.机构 3.共有字段',
  `bed_data` tinyint(1) DEFAULT '0' COMMENT '1:在床数据 0:全部数据',
  `view_title` varchar(255) DEFAULT NULL COMMENT '健康数据一览表标题',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区综合一览表账户显示配置';

-- ----------------------------
-- Table structure for lb_cms_account_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_account_relation`;
CREATE TABLE `lb_cms_account_relation` (
  `account_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `account_type` tinyint(4) DEFAULT '29' COMMENT '账号类型，参见字典表,默认社区长者app',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '实体唯一标识',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除(0未删除,1删除)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_relation_id`),
  UNIQUE KEY `object_id_idx` (`care_object_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='用户关联信息表';

-- ----------------------------
-- Table structure for lb_cms_account_show
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_account_show`;
CREATE TABLE `lb_cms_account_show` (
  `account_show_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) DEFAULT NULL COMMENT '登录用户id',
  `is_show_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否是演示模式 0:否 1:是',
  `menu_router` varchar(255) DEFAULT NULL COMMENT '菜单路由',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:否，1：是',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `org_id` varchar(20) DEFAULT NULL COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_show_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区信息一览表演示模式配置';

-- ----------------------------
-- Table structure for lb_cms_advert
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_advert`;
CREATE TABLE `lb_cms_advert` (
  `advert_id` varchar(32) NOT NULL COMMENT '主键',
  `photo` varchar(1000) DEFAULT NULL COMMENT '图片链接',
  `advert_details` longtext COMMENT '广告详情',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`advert_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='小程序广告表';

-- ----------------------------
-- Table structure for lb_cms_advice
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_advice`;
CREATE TABLE `lb_cms_advice` (
  `advice_id` varchar(32) NOT NULL COMMENT '主键',
  `source_id` varchar(32) DEFAULT NULL COMMENT '咨询来源主键',
  `content` varchar(2048) DEFAULT NULL COMMENT '建议内容',
  `type` int(8) DEFAULT '21' COMMENT '类型：1 电话咨询 21 助老APP 25 社区管理APP',
  `org_id` varchar(32) DEFAULT NULL,
  `picture_url` varchar(512) DEFAULT NULL COMMENT '图片地址 逗号分割',
  `status` tinyint(4) DEFAULT '0' COMMENT '状态 0 未解决 1 已解决',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`advice_id`) USING BTREE,
  UNIQUE KEY `uk_index` (`source_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区意见反馈表';

-- ----------------------------
-- Table structure for lb_cms_age_subsidy_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_age_subsidy_config`;
CREATE TABLE `lb_cms_age_subsidy_config` (
  `subsidy_config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `age_level_one` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '60~69周岁的补贴金额',
  `age_level_two` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '70～79周岁的补贴金额',
  `age_level_three` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '80～89周岁的补贴金额',
  `age_level_four` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '90 ~ 99周岁的补贴金额',
  `age_level_five` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '100周岁以上的补贴金额',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`subsidy_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府平台高龄补贴配置表';

-- ----------------------------
-- Table structure for lb_cms_alarm_docking_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_alarm_docking_info`;
CREATE TABLE `lb_cms_alarm_docking_info` (
  `docking_info_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `alarm_id` varchar(128) NOT NULL DEFAULT '' COMMENT '报警id',
  `third_alarm_id` varchar(128) NOT NULL DEFAULT '' COMMENT '三方平台报警id',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0：失败 1：成功',
  `result` text NOT NULL COMMENT '数据结果信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_info_id`),
  KEY `alarm_id_index` (`alarm_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者报警记录对接详情表';

-- ----------------------------
-- Table structure for lb_cms_all_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_all_order`;
CREATE TABLE `lb_cms_all_order` (
  `order_id` varchar(32) NOT NULL COMMENT '订单id',
  `order_type` tinyint(2) NOT NULL COMMENT '订单类型',
  `order_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '订单状态',
  `order_details` text NOT NULL COMMENT '订单详情',
  `order_price` decimal(10,2) DEFAULT NULL COMMENT '订单价格',
  `pay_type` tinyint(1) DEFAULT NULL COMMENT '支付方式',
  `create_time` bigint(20) NOT NULL COMMENT '订单时间',
  `update_time` bigint(20) NOT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 已删除',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `cancel_reason` varchar(500) DEFAULT NULL COMMENT '取消原因',
  `cancel_by` varchar(32) DEFAULT NULL COMMENT '取消人',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `work_order_id` varchar(32) DEFAULT NULL COMMENT '与配送服务关联的工单id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单表';

-- ----------------------------
-- Table structure for lb_cms_archives_disease_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_archives_disease_contacts`;
CREATE TABLE `lb_cms_archives_disease_contacts` (
  `contacts_id` varchar(32) NOT NULL COMMENT '主键',
  `archives_record_id` varchar(32) DEFAULT NULL COMMENT '档案记录id',
  `show_msg` varchar(64) DEFAULT NULL COMMENT '展示信息',
  `show_time` bigint(20) DEFAULT NULL COMMENT '展示时间',
  `operate_type` tinyint(1) DEFAULT NULL COMMENT '操作类型：0：手术；1：外伤；2：献血',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contacts_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康管理档案记录和既往病史关系对照表';

-- ----------------------------
-- Table structure for lb_cms_archives_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_archives_record`;
CREATE TABLE `lb_cms_archives_record` (
  `archives_record_id` varchar(32) NOT NULL COMMENT '档案记录id主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '看护对象id',
  `payment_type` int(11) DEFAULT NULL COMMENT '费用支付方式',
  `work_units` varchar(128) DEFAULT NULL COMMENT '工作单位',
  `drug_allergy_type` varchar(64) DEFAULT NULL COMMENT '药物过敏类别（1：青霉素，2：磺胺，3：链霉菌）',
  `drug_allergy_describe` varchar(128) DEFAULT NULL COMMENT '药物过敏类别其他具体描述信息',
  `exposed_environment_type` varchar(64) DEFAULT NULL COMMENT '暴露环境类别（1：化学品，2：毒物，3：射线）',
  `exposed_environment_describe` varchar(128) DEFAULT NULL COMMENT '暴露环境其他具体描述信息',
  `disease_type` varchar(64) DEFAULT NULL COMMENT '疾病类别：（1：高血压，2：糖尿病，3：冠心病 ）',
  `disease_describe` varchar(128) DEFAULT NULL COMMENT '疾病类别其他具体信息',
  `is_surgery_exp` tinyint(1) DEFAULT NULL COMMENT '手术经历(0：无,1：有)',
  `is_trauma_exp` tinyint(1) DEFAULT NULL COMMENT '外伤经历(0:无,1：有)',
  `is_Blood_donation_exp` tinyint(1) DEFAULT NULL COMMENT '献血经历(0:无,1：有)',
  `is_genetic` tinyint(1) DEFAULT NULL COMMENT '遗传病史(0:无,1：有)',
  `disease_name` varchar(32) DEFAULT NULL COMMENT '遗传病史名称',
  `equipment_type` int(11) DEFAULT NULL COMMENT '厨房排风设备(1. 无  2 油烟机   3 换气扇    4 烟囱）',
  `fuel_type` int(11) DEFAULT NULL COMMENT '燃料',
  `water_type` int(11) DEFAULT NULL COMMENT '水类型',
  `toilet_type` int(11) DEFAULT NULL COMMENT '厕所',
  `livestock_type` int(11) DEFAULT NULL COMMENT '生活设施',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `father_disease_history` int(11) DEFAULT NULL COMMENT '父亲疾病史(1 无    2 高血压  3 糖尿病  4 冠心病  5 慢性阻塞性肺疾病   6 恶性肿瘤   7 脑卒中 8 重型精神疾病  9 结核病   10 肝炎   11 先天畸形 )',
  `mother_disease_history` int(11) DEFAULT NULL COMMENT '母亲疾病史(1 无    2 高血压  3 糖尿病  4 冠心病  5 慢性阻塞性肺疾病   6 恶性肿瘤   7 脑卒中 8 重型精神疾病  9 结核病   10 肝炎   11 先天畸形 )',
  `children_disease_history` int(11) DEFAULT NULL COMMENT '子女疾病史(1 无    2 高血压  3 糖尿病  4 冠心病  5 慢性阻塞性肺疾病   6 恶性肿瘤   7 脑卒中 8 重型精神疾病  9 结核病   10 肝炎   11 先天畸形 )',
  `relatives_disease_history` int(11) DEFAULT NULL COMMENT '亲属疾病史(1 无    2 高血压  3 糖尿病  4 冠心病  5 慢性阻塞性肺疾病   6 恶性肿瘤   7 脑卒中 8 重型精神疾病  9 结核病   10 肝炎   11 先天畸形 )',
  `name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `gender` varchar(32) DEFAULT NULL COMMENT '性别',
  `birthday` bigint(20) DEFAULT NULL COMMENT '生日',
  `identity` varchar(32) DEFAULT NULL COMMENT '身份证号',
  `phone_num` varchar(11) DEFAULT NULL COMMENT '手机号码',
  `nation` varchar(32) DEFAULT NULL COMMENT '民族',
  `contacts_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `contacts_phone` varchar(11) DEFAULT NULL COMMENT '联系人电话',
  `blood_type` varchar(32) DEFAULT NULL COMMENT '血型',
  `retired_occupation` varchar(32) DEFAULT NULL COMMENT '职业',
  `educational_level` varchar(10) DEFAULT NULL COMMENT '文化程度',
  `hobby` varchar(32) DEFAULT NULL COMMENT '兴趣爱好',
  `marital_status` int(11) DEFAULT NULL COMMENT '婚姻状况',
  `disability_type` varchar(32) DEFAULT NULL COMMENT '残疾类型',
  `address` varchar(128) DEFAULT NULL COMMENT '居住地址',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `disability_type_str` varchar(32) DEFAULT NULL COMMENT '残疾类型具体名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`archives_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康管理档案记录表';

-- ----------------------------
-- Table structure for lb_cms_assess_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assess_item`;
CREATE TABLE `lb_cms_assess_item` (
  `assess_item_id` varchar(32) NOT NULL COMMENT '主键',
  `serial_number` int(32) NOT NULL COMMENT '问题序号',
  `item_content` varchar(512) DEFAULT NULL COMMENT '问题描述',
  `first_score` tinyint(1) DEFAULT NULL COMMENT '第一项分值',
  `second_score` tinyint(1) DEFAULT NULL COMMENT '第二项分值',
  `three_score` tinyint(1) DEFAULT NULL COMMENT '第三项分值',
  `four_score` tinyint(1) DEFAULT NULL COMMENT '第四项分值',
  `five_score` tinyint(1) DEFAULT NULL COMMENT '第五项分值',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `type` varchar(128) DEFAULT NULL COMMENT '评估问卷类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assess_item_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='体质类型评估-评估项字典表';

-- ----------------------------
-- Table structure for lb_cms_assess_result
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assess_result`;
CREATE TABLE `lb_cms_assess_result` (
  `assess_result_id` varchar(32) NOT NULL COMMENT '主键',
  `body_type_key` varchar(32) DEFAULT NULL COMMENT '体质类型key值',
  `body_type_value` varchar(512) DEFAULT NULL COMMENT '体质类型名称',
  `index_list` varchar(32) DEFAULT NULL COMMENT '体质类型对应的条目集合',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `result_type` varchar(128) DEFAULT NULL COMMENT '评估结果类型',
  `order_number` int(11) NOT NULL COMMENT '排序字段',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assess_result_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='体质类型评估-评估结果字典表';

-- ----------------------------
-- Table structure for lb_cms_assess_score
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assess_score`;
CREATE TABLE `lb_cms_assess_score` (
  `assess_score_id` varchar(32) NOT NULL COMMENT '评估结果得分id（主键）',
  `body_type_assessment_id` varchar(32) DEFAULT NULL COMMENT '自理评估主表id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `assess_body_key` varchar(32) DEFAULT NULL COMMENT '评估结果字典表key',
  `assess_score` tinyint(1) DEFAULT NULL COMMENT '评估得分',
  `judge_result` varchar(32) DEFAULT NULL COMMENT '判定结果',
  `tcm_guide` varchar(64) DEFAULT NULL COMMENT '中医保健指导类型',
  `tcm_guide_name` varchar(32) DEFAULT NULL COMMENT '中医保健指导类型名称',
  `tcm_guide_other` varchar(255) DEFAULT NULL COMMENT '中医保健指导其他描述',
  `assess_body_value` varchar(255) DEFAULT NULL COMMENT '评估结果字典表value',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assess_score_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='体质类型评估-选择评估项表';

-- ----------------------------
-- Table structure for lb_cms_assess_sign_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assess_sign_record`;
CREATE TABLE `lb_cms_assess_sign_record` (
  `sign_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联记录主键',
  `sign_type` varchar(32) NOT NULL DEFAULT '' COMMENT '签字类型',
  `sign_url` varchar(125) NOT NULL DEFAULT '' COMMENT '签字图片地址',
  `sign_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '签字时间',
  `sign_reason` varchar(32) NOT NULL DEFAULT '' COMMENT '签字原因',
  `sign_person_type_name` varchar(128) NOT NULL DEFAULT '' COMMENT '签字人名称',
  `sign_person_type` varchar(32) NOT NULL DEFAULT '' COMMENT '签字人类型',
  `org_id` varchar(32) NOT NULL DEFAULT ' ' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sign_record_id`),
  KEY `idx_org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='签字记录表';

-- ----------------------------
-- Table structure for lb_cms_assessment_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assessment_record`;
CREATE TABLE `lb_cms_assessment_record` (
  `assessment_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `height` varchar(32) NOT NULL DEFAULT '' COMMENT '身高',
  `weight` varchar(32) NOT NULL DEFAULT '' COMMENT '体重',
  `assessment_standard` tinyint(1) NOT NULL DEFAULT '1' COMMENT '评估标准： 1-2013评估标准 2-2022评估标准',
  `assessment_number` varchar(32) NOT NULL COMMENT '评估编号',
  `assessment_class` varchar(32) NOT NULL DEFAULT '' COMMENT '评估分类',
  `assessment_reason` varchar(255) NOT NULL DEFAULT '' COMMENT '评估原因',
  `assessment_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '评估时间',
  `assessment_grade` varchar(512) NOT NULL DEFAULT '' COMMENT '评估得分,每项得分拼接',
  `social_security_card` varchar(32) NOT NULL DEFAULT '' COMMENT '社保卡号',
  `pay_type` varchar(125) NOT NULL DEFAULT '' COMMENT '医疗费用支付方式',
  `provide_name` varchar(128) NOT NULL DEFAULT '' COMMENT '姓名',
  `provide_relation` varchar(32) NOT NULL DEFAULT '' COMMENT '信息提供者与长者关系',
  `provide_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '信息提供者手机号',
  `assessment_result` text COMMENT '评估结果',
  `assessment_type` varchar(32) NOT NULL DEFAULT '' COMMENT '评估类型 1能力评估 2健康评估 3心理 4社会角色 5主观健康 6 其他 7风险 8失智 9压疮 10跌倒 11自定义评估',
  `assessment_person` varchar(32) NOT NULL DEFAULT '' COMMENT '评估人',
  `assessment_person_two` varchar(32) NOT NULL DEFAULT '' COMMENT '评估人员2',
  `assessment_address` varchar(32) NOT NULL DEFAULT '' COMMENT '评估地点',
  `assessment_file_url` text COMMENT '附件,多个拼接使用',
  `assessment_file_name` text COMMENT '附件名称,多个拼接使用',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_first` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为试(入)住登记录入',
  `registration_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `registration_name` varchar(128) NOT NULL DEFAULT '' COMMENT '姓名',
  `assessment_level` varchar(100) NOT NULL DEFAULT '' COMMENT '评估后的等级',
  `assessment_care_level_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估对应的护理等级',
  `choose_answer` json DEFAULT NULL COMMENT '评估题目的选择答案',
  `topic_answer` text COMMENT '评估时题目,选项等信息',
  `again_assessment_result` varchar(200) NOT NULL DEFAULT '' COMMENT '再次评估结果',
  `again_assessment_grade` varchar(512) NOT NULL DEFAULT '' COMMENT '再次评估得分',
  `again_assessment_person` varchar(32) NOT NULL DEFAULT '' COMMENT '再次评估人',
  `again_provide_name` varchar(32) NOT NULL DEFAULT '' COMMENT '再次评估信息提供着姓名',
  `again_provide_relation` varchar(32) NOT NULL DEFAULT '' COMMENT '再次评估信息提供者与长者关系',
  `again_assessment_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '评估时间',
  `sign_url` varchar(128) NOT NULL DEFAULT '' COMMENT '签字地址',
  `sign_url_again` varchar(128) NOT NULL DEFAULT '' COMMENT '再次签字',
  `remark` text COMMENT '备注',
  `assessment_report_url` varchar(255) NOT NULL DEFAULT '' COMMENT '第三方评估报告链接',
  `assessment_report_file_name` varchar(100) NOT NULL DEFAULT '' COMMENT '第三方评估报告文件名称',
  `assessment_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '评估是否有效 0 作废 1 有效',
  `tumble_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '跌倒风险',
  `lost_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '走失风险',
  `dysphoria_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '噎食风险',
  `suicide_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '自杀、自伤风险',
  `other_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '其他风险',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_record_id`) USING BTREE,
  KEY `lb_assessment_record_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='评估记录表';

-- ----------------------------
-- Table structure for lb_cms_assessment_topic
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assessment_topic`;
CREATE TABLE `lb_cms_assessment_topic` (
  `assessment_topic_id` varchar(64) NOT NULL COMMENT '自然主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `topic_type_id` varchar(64) NOT NULL COMMENT '类型主键',
  `topic_name` varchar(255) NOT NULL COMMENT '题目名称',
  `description` varchar(255) NOT NULL DEFAULT '' COMMENT '情况描述',
  `component_type` varchar(32) NOT NULL DEFAULT '' COMMENT '分项类型',
  `order_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '预留排序字段',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_topic_id`) USING BTREE,
  KEY `lb_cms_assessment_topic_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康评估题目';

-- ----------------------------
-- Table structure for lb_cms_assessment_topic_option
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_assessment_topic_option`;
CREATE TABLE `lb_cms_assessment_topic_option` (
  `assessment_topic_option_id` varchar(64) NOT NULL COMMENT '自然主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `topic_id` varchar(64) NOT NULL DEFAULT '' COMMENT '题目主键',
  `option_name` varchar(255) NOT NULL DEFAULT '' COMMENT '选项名称',
  `option_number` int(10) NOT NULL DEFAULT '0' COMMENT '选项分值',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_topic_option_id`) USING BTREE,
  KEY `lb_cms_assessment_topic_option_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康评估题目选项及分值';

-- ----------------------------
-- Table structure for lb_cms_auxiliary_equipment_lease_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_auxiliary_equipment_lease_record`;
CREATE TABLE `lb_cms_auxiliary_equipment_lease_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `tenant_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '电话号码',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `age` tinyint(3) DEFAULT '0' COMMENT '年龄',
  `region_id` varchar(32) DEFAULT '' COMMENT '居住地址id',
  `region_desc` varchar(500) DEFAULT '' COMMENT '居住地址',
  `detail_address` varchar(500) DEFAULT '' COMMENT '详细地址',
  `supplies_id` varchar(32) NOT NULL DEFAULT '' COMMENT '辅具设备标识',
  `start_time` bigint(20) DEFAULT '0' COMMENT '租赁开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '租赁结束时间',
  `lease_type` tinyint(3) DEFAULT '1' COMMENT '租赁方式 1:按日, 2:按月',
  `lease_time` int(11) DEFAULT '0' COMMENT '租赁时长',
  `rent` decimal(10,2) DEFAULT '0.00' COMMENT '租金',
  `total_rent` decimal(10,2) DEFAULT '0.00' COMMENT '总租金',
  `lease_status` tinyint(3) DEFAULT '1' COMMENT '租赁状态 1:进行中,2:已完成',
  `deposit` decimal(10,2) DEFAULT NULL COMMENT '押金',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人id',
  `check_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `check_account_phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '登记人电话号码',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `return_time` bigint(20) DEFAULT '0' COMMENT '退租时间',
  `group_id` varchar(32) DEFAULT '' COMMENT '续租分组标识',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `pay_way` tinyint(2) DEFAULT '1' COMMENT '支付方式(1 一卡通余额 2 账户余额)',
  `tenant_id` varchar(32) NOT NULL COMMENT '租赁人标识',
  `device_num` int(11) NOT NULL COMMENT '设备数量',
  `total_cost` int(11) NOT NULL COMMENT '总金额',
  `settle_method` varchar(32) NOT NULL DEFAULT '' COMMENT '支付方式（组合支付逗号分隔）',
  `scale_set` int(11) NOT NULL DEFAULT '0' COMMENT '当前订单国家补贴比例',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='辅具租赁记录';

-- ----------------------------
-- Table structure for lb_cms_auxiliary_equipment_month_check
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_auxiliary_equipment_month_check`;
CREATE TABLE `lb_cms_auxiliary_equipment_month_check` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_name` varchar(64) DEFAULT '' COMMENT '类别名称',
  `supplies_in_number` int(10) DEFAULT '0' COMMENT '入库数量',
  `supplies_leasing_number` int(10) DEFAULT '0' COMMENT '租赁数量',
  `supplies_scrapped_number` int(10) DEFAULT '0' COMMENT '报废数量',
  `final_number` int(10) DEFAULT '0' COMMENT '库存数量',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='辅助库存统计表';

-- ----------------------------
-- Table structure for lb_cms_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_balance`;
CREATE TABLE `lb_cms_balance` (
  `balance_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `account_preparatory_balance` decimal(32,1) NOT NULL DEFAULT '0.0' COMMENT '账户预存款余额',
  `one_card_balance` decimal(32,1) DEFAULT '0.0' COMMENT '一卡通余额',
  `total_deposit_balance` decimal(32,1) NOT NULL DEFAULT '0.0' COMMENT '总押金余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '账户状态（0 正常，1 冻结（退住结算中），2 注销（已结算退住））',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `version` int(32) NOT NULL DEFAULT '1' COMMENT '版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`balance_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='余额表';

-- ----------------------------
-- Table structure for lb_cms_body_type_assess
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_body_type_assess`;
CREATE TABLE `lb_cms_body_type_assess` (
  `body_type_assessment_id` varchar(32) NOT NULL COMMENT '主键（自理评估id）',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `assessment_number` varchar(32) DEFAULT NULL COMMENT '评估编号',
  `assessment_reason` varchar(32) DEFAULT NULL COMMENT '评估原因',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估基准日期',
  `social_security_card` varchar(32) DEFAULT NULL COMMENT '社保卡号',
  `pay_type` varchar(32) DEFAULT NULL COMMENT '医疗费用支付方式',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `select_result` varchar(255) DEFAULT NULL COMMENT '选择的结果',
  `assess_guide_other` varchar(255) DEFAULT NULL COMMENT '中医指导的选择结果',
  `assess_body_type` varchar(255) DEFAULT NULL COMMENT '评估体质的结果',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`body_type_assessment_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='体质类型评估-信息登记表';

-- ----------------------------
-- Table structure for lb_cms_booking_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_booking_order`;
CREATE TABLE `lb_cms_booking_order` (
  `booking_id` varchar(32) NOT NULL COMMENT '主键',
  `booking_type` tinyint(1) NOT NULL COMMENT '预约类型 1 按服务人员类型 2 按长者预约',
  `care_object_id` text NOT NULL COMMENT '长者id',
  `loop_model` tinyint(1) NOT NULL COMMENT '循环模式 1 单次 2 每天 3 每周 4 每月',
  `loop_date` text COMMENT '循环的日期',
  `serve_staff_ids` text NOT NULL COMMENT '服务人员id',
  `serve_item_ids` text NOT NULL COMMENT '服务项目',
  `order_handle_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '工单处理类型',
  `booking_start_time` bigint(20) DEFAULT NULL COMMENT '预约开始时间',
  `booking_end_time` bigint(20) DEFAULT NULL COMMENT '预约结束时间',
  `effective_time_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '有效时间 1 当天有效 2 一直有效',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `send_msg_phone_nums` varchar(255) DEFAULT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除，1 删除',
  `book_order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '预约时间段 1 上午 2 下午',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `provider_type` tinyint(1) NOT NULL COMMENT '用户类型 1:服务商 2:应急人员 3:志愿者 4:个体服务人员 5:服务团体',
  `work_order_remarks` varchar(128) NOT NULL DEFAULT '' COMMENT '工单备注',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`booking_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='定时工单';

-- ----------------------------
-- Table structure for lb_cms_call_center_guard
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_call_center_guard`;
CREATE TABLE `lb_cms_call_center_guard` (
  `call_center_guard` varchar(30) NOT NULL COMMENT '主键',
  `guard_time` tinyint(1) DEFAULT NULL COMMENT '守护时长(小时)',
  `num` tinyint(1) DEFAULT NULL COMMENT '人数',
  `year_cost` decimal(10,2) DEFAULT NULL COMMENT '年费用',
  `month_cost` decimal(10,2) DEFAULT NULL COMMENT '月费用',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_center_guard`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='呼叫中心资费详情';

-- ----------------------------
-- Table structure for lb_cms_care_object_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_care_object_balance`;
CREATE TABLE `lb_cms_care_object_balance` (
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `cash_balance` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '现金余额 ',
  `cash_coupon_balance` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '代金券余额 ',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '入住状态（0 已入住，1 退住结算中，2 已退住）',
  `version` int(10) NOT NULL DEFAULT '0' COMMENT '版本号',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `vip_card_balance` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '会员卡余额',
  `vip_card_credits` bigint(20) NOT NULL DEFAULT '0' COMMENT '积分余额',
  `one_card_balance` decimal(32,1) NOT NULL DEFAULT '0.0' COMMENT '一卡通余额',
  `subsidy_balance` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '长者国家补贴余额',
  `freeze_cash_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '冻结现金额度',
  `freeze_coupon_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '冻结代金券额度',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`) USING BTREE,
  UNIQUE KEY `pk_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区长者余额表';

-- ----------------------------
-- Table structure for lb_cms_care_object_settle
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_care_object_settle`;
CREATE TABLE `lb_cms_care_object_settle` (
  `care_object_settle_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '长者扣费记录主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `work_order_id` varchar(32) NOT NULL COMMENT '工单主键',
  `order_cash` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '现金扣费',
  `order_total_price` decimal(8,2) DEFAULT NULL COMMENT '订单总额',
  `order_coupon` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '代金券扣费',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_settle_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=756 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区长者订单信息表';

-- ----------------------------
-- Table structure for lb_cms_care_object_treatment_evaluation
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_care_object_treatment_evaluation`;
CREATE TABLE `lb_cms_care_object_treatment_evaluation` (
  `evaluation_id` varchar(32) NOT NULL COMMENT '评价id',
  `record_id` varchar(32) DEFAULT NULL COMMENT '治疗记录id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `servicer_id` varchar(255) DEFAULT NULL COMMENT '服务人员id',
  `service_rating` tinyint(1) DEFAULT NULL COMMENT '服务评级',
  `evaluation_content` varchar(255) DEFAULT NULL COMMENT '评价内容',
  `evaluation_time` bigint(20) DEFAULT NULL COMMENT '评价时间',
  `servicer_name` varchar(255) DEFAULT NULL COMMENT '服务人员姓名',
  `servicer_ids` varchar(1280) DEFAULT NULL COMMENT '服务人员id集合',
  `servicer_names` varchar(255) DEFAULT NULL COMMENT '服务人员姓名集合',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`evaluation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='服务人员评价表';

-- ----------------------------
-- Table structure for lb_cms_care_object_treatment_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_care_object_treatment_item`;
CREATE TABLE `lb_cms_care_object_treatment_item` (
  `relation_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `record_id` varchar(32) DEFAULT '' COMMENT '治疗处理记录id',
  `item_type` tinyint(1) DEFAULT '0' COMMENT '项目类别',
  `item_name` text COMMENT '项目名称',
  `treatment_cost` decimal(10,2) DEFAULT NULL COMMENT '治疗费用',
  `treatment_time` varchar(32) DEFAULT '' COMMENT '治疗时长',
  `treatment_type` tinyint(1) DEFAULT '0' COMMENT '治疗周期类型',
  `treatment_cycle` bigint(20) DEFAULT '0' COMMENT '治疗周期(按次数则为总次数,按时间则为到期时间戳)',
  `rest_cycle` int(10) DEFAULT '0' COMMENT '剩余治疗次数',
  `is_item_use_again` tinyint(1) DEFAULT '0' COMMENT '项目是否可再次使用 0:不可用 1:可用',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `item_id` varchar(32) DEFAULT '' COMMENT '治疗项目id',
  `is_purchase` tinyint(1) DEFAULT '1' COMMENT '当次是否购买 0 非购买 1 购买',
  `item_end_time` bigint(20) DEFAULT '0' COMMENT '截止日期',
  `servicer_ids` varchar(1024) DEFAULT NULL COMMENT '服务人员id集合',
  `servicer_names` varchar(255) DEFAULT NULL COMMENT '服务人员姓名集合',
  `servicer_id` varchar(255) DEFAULT NULL COMMENT '服务人员id',
  `service_rating` tinyint(1) DEFAULT NULL COMMENT '服务评级',
  `evaluation_content` varchar(255) DEFAULT NULL COMMENT '评价内容',
  `evaluation_time` bigint(20) DEFAULT NULL COMMENT '评价时间',
  `servicer_name` varchar(255) DEFAULT NULL COMMENT '服务人员姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='长者已购治疗项目表';

-- ----------------------------
-- Table structure for lb_cms_care_object_treatment_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_care_object_treatment_record`;
CREATE TABLE `lb_cms_care_object_treatment_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `age` tinyint(3) DEFAULT NULL COMMENT '年龄',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `address` varchar(500) DEFAULT '' COMMENT '居住地址',
  `servicer` varchar(128) DEFAULT NULL COMMENT '姓名',
  `height` varchar(16) DEFAULT '' COMMENT '身高',
  `weight` varchar(16) DEFAULT '' COMMENT '体重',
  `systolic_pressure` int(3) DEFAULT NULL COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT NULL COMMENT '舒张压',
  `temperature` varchar(16) DEFAULT '' COMMENT '体温',
  `respiratory_rate` int(3) DEFAULT NULL COMMENT '呼吸频率',
  `pulse` int(3) DEFAULT NULL COMMENT '脉搏',
  `blood_oxygen` int(3) DEFAULT NULL COMMENT '血氧值',
  `cholesterol` varchar(32) DEFAULT '' COMMENT '总胆固醇',
  `HDL` varchar(32) DEFAULT '' COMMENT '高密度脂蛋白',
  `triglycerides` varchar(32) DEFAULT '' COMMENT '甘油三酯',
  `LDL` varchar(32) DEFAULT '' COMMENT '低密度脂蛋白',
  `ua` varchar(32) DEFAULT '' COMMENT '尿酸',
  `circulatory_system_status` varchar(64) DEFAULT NULL COMMENT '循环系统状态',
  `respiratory_endocrine_system_status` varchar(64) DEFAULT NULL COMMENT '呼吸内分泌系统状态',
  `constitution_differentiate_status` varchar(64) DEFAULT NULL COMMENT '体质辨析',
  `specialized_subject_diagnosis_status` varchar(64) DEFAULT NULL COMMENT '专科诊断',
  `treatment_recommendations_status` varchar(64) DEFAULT NULL COMMENT '治疗建议',
  `treatment_cost` decimal(10,2) DEFAULT NULL COMMENT '治疗金额',
  `treatment_result` varchar(128) DEFAULT '' COMMENT '治疗结果',
  `service_rating` tinyint(1) DEFAULT NULL COMMENT '服务评级',
  `evaluation_content` varchar(128) DEFAULT NULL COMMENT '评价内容',
  `evaluation_time` bigint(20) DEFAULT NULL COMMENT '评价时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `treatment_status` tinyint(1) DEFAULT '0' COMMENT '治疗状态 0未完成 1 进行中 2 已完成',
  `item_name` varchar(255) DEFAULT '' COMMENT '治疗项目名称',
  `sap_system_status` varchar(64) DEFAULT NULL COMMENT '消化/泌尿/血液系统',
  `item_ids` text COMMENT '治疗项目id',
  `service_time` bigint(20) DEFAULT NULL COMMENT '服务时间',
  `service_ids` varchar(1024) DEFAULT NULL COMMENT '治疗记录的服务人员集合',
  `service_names` varchar(255) DEFAULT NULL COMMENT '治疗记录的服务人员姓名集合',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='治疗处理记录表';

-- ----------------------------
-- Table structure for lb_cms_cash_extract
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_cash_extract`;
CREATE TABLE `lb_cms_cash_extract` (
  `cash_extract_id` varchar(32) NOT NULL COMMENT '提现主键id',
  `account_id` varchar(32) DEFAULT NULL COMMENT '提现人 主键',
  `staff_type` tinyint(4) DEFAULT NULL COMMENT '提现人类型 0 服务商 1 服务人员 2 应急人员 3 志愿者 4 机构 ',
  `username` varchar(32) DEFAULT NULL COMMENT '提现人真实姓名：支付宝提现用到',
  `phone_num` char(64) DEFAULT NULL COMMENT '提现手机号：支付宝提现 用到',
  `extract_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '提现类型 1 微信 2 支付宝',
  `extract_amount` decimal(12,2) DEFAULT NULL COMMENT '提现金额',
  `remain_amount` decimal(12,2) DEFAULT NULL COMMENT '剩余金额',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '提现状态 1申请提现 2提现成功 3 提现失败',
  `partner_trade_no` varchar(64) NOT NULL COMMENT '提现单号',
  `remake` varchar(255) DEFAULT NULL COMMENT '备注',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_by` varchar(32) NOT NULL COMMENT '更新人',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`cash_extract_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='提现审核记录表';

-- ----------------------------
-- Table structure for lb_cms_catering_assistance_service
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_catering_assistance_service`;
CREATE TABLE `lb_cms_catering_assistance_service` (
  `service_id` varchar(32) NOT NULL COMMENT '主键',
  `month` varchar(32) NOT NULL DEFAULT '' COMMENT '月份',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `canteen_region` varchar(255) NOT NULL DEFAULT '' COMMENT '饭堂区域',
  `canteen_name` varchar(128) NOT NULL DEFAULT '' COMMENT '饭堂名称',
  `operating_org_name` varchar(128) NOT NULL DEFAULT '' COMMENT '运营机构名称',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `city_meal_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '市就餐补贴次数',
  `city_meal_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市就餐补贴金额',
  `city_meal_delivery_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '市送餐补贴次数',
  `city_meal_delivery_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市送餐补贴金额',
  `city_meal_operate_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '市运营补贴次数',
  `city_meal_operate_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市运营补贴金额',
  `area_meal_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '区餐补次数',
  `area_meal_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '区餐补金额',
  `area_charitable_meal_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '区慈善餐补次数',
  `area_charitable_meal_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '区慈善补贴金额',
  `street_meal_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '街道餐补次数',
  `street_meal_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '街道餐补金额',
  `street_charitable_meal_subsidy_times` int(11) NOT NULL DEFAULT '0' COMMENT '街道慈善餐补次数',
  `street_charitable_meal_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '街道慈善补贴金额',
  `city_meal_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市就餐补贴总金额',
  `city_meal_delivery_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市送餐补贴总金额',
  `city_meal_operate_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '市运营补贴总金额',
  `area_meal_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '区餐补总金额',
  `area_charitable_meal_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '区慈善补贴总金额',
  `street_meal_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '街道餐补总金额',
  `street_charitable_meal_subsidy_all_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '街道慈善补贴总金额',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`service_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='助餐配餐服务';

-- ----------------------------
-- Table structure for lb_cms_check_out_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_check_out_record`;
CREATE TABLE `lb_cms_check_out_record` (
  `check_out_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `org_id` varchar(32) DEFAULT NULL COMMENT '当前平台的id',
  `elder_org_id` varchar(32) DEFAULT NULL COMMENT '长者所在的机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:否 1:是',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `check_out_type` tinyint(1) DEFAULT NULL COMMENT '退住类型',
  `check_out_time` bigint(20) DEFAULT NULL COMMENT '退住时间',
  `check_out_reason` varchar(255) DEFAULT NULL COMMENT '退住原因',
  `cash_balance` decimal(12,2) DEFAULT '0.00' COMMENT '退住时现金余额',
  `cash_coupon_balance` decimal(12,2) DEFAULT '0.00' COMMENT '退住时代金劵余额',
  `one_card_balance` decimal(12,2) DEFAULT '0.00' COMMENT '退住时一卡通余额',
  `vip_card_balance` decimal(12,2) DEFAULT '0.00' COMMENT '退住时会员卡余额',
  `vip_card_credits` bigint(20) DEFAULT '0' COMMENT '退住时会员卡积分',
  `account_id` varchar(32) DEFAULT NULL COMMENT '操作人id',
  `account_name` varchar(255) DEFAULT NULL COMMENT '操作人名称',
  `is_latest` tinyint(1) DEFAULT '1' COMMENT '是否是最新的一条',
  `check_in_time` bigint(20) DEFAULT NULL COMMENT '原有平台登记入住时间',
  `elder_region` varchar(255) DEFAULT NULL COMMENT '长者原居住区域',
  `elder_address` varchar(255) DEFAULT NULL COMMENT '长者原居住地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`check_out_record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者退住记录表';

-- ----------------------------
-- Table structure for lb_cms_consult_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_consult_record`;
CREATE TABLE `lb_cms_consult_record` (
  `consult_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构',
  `elder_name` varchar(128) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `identity` varchar(32) NOT NULL DEFAULT '' COMMENT '长者身份证',
  `gender` varchar(32) NOT NULL DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) NOT NULL DEFAULT '0' COMMENT '生日',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '长者手机号',
  `region` varchar(128) NOT NULL DEFAULT '' COMMENT '户籍地址region',
  `region_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '户籍地址region描述',
  `address` varchar(255) NOT NULL DEFAULT '' COMMENT '家庭住址',
  `consult_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '意向登记时间',
  `remark` varchar(64) NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `enrolled_source` tinyint(1) NOT NULL DEFAULT '1' COMMENT '登记来源  1:通过平台登记 2:通过二维码登记',
  `mini_username` varchar(128) NOT NULL DEFAULT '' COMMENT '小程序登录账号',
  `mini_password` varchar(128) NOT NULL DEFAULT '' COMMENT '小程序登录密码',
  `check_in_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '意向入住状态 0：未入住 1:已入住',
  `mini_password_encrypt` varchar(128) NOT NULL DEFAULT '' COMMENT '小程序密码密文',
  `min_password_weak` varchar(128) NOT NULL DEFAULT '' COMMENT '小程序弱密码密文',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consult_record_id`) USING BTREE,
  KEY `org_id_index` (`org_id`) USING BTREE COMMENT 'org_id索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区意向登记记录表';

-- ----------------------------
-- Table structure for lb_cms_consumption_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_consumption_record`;
CREATE TABLE `lb_cms_consumption_record` (
  `consumption_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_id` varchar(32) DEFAULT '' COMMENT '消费详情记录主键',
  `consumption_type` tinyint(1) NOT NULL COMMENT '消费类型（0 账户充值，1 一卡通充值，2 押金充值， 3 账户余额消费，4 一卡通余额消费，5  入住缴费）',
  `consumer` varchar(128) DEFAULT NULL COMMENT '姓名',
  `consumption_pattern` int(11) NOT NULL COMMENT '消费方式（0 账户现金，1 一卡通余额，2 微信，3 支付宝，4 银行卡，5 现金 ，6 代金劵 7，会员卡 ）',
  `consumption_amount` decimal(32,2) DEFAULT NULL COMMENT '消费金额',
  `start_time` bigint(20) DEFAULT '0' COMMENT '消费开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '消费结束时间',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '收费人',
  `registrant_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `consumption_remark` text COMMENT '消费备注',
  `expense_name` varchar(32) DEFAULT '' COMMENT '费用名称,(记录为入院总缴费时,0:首月减免,1每月减免,2老数据总费用减免)',
  `expense_amount` varchar(32) DEFAULT '' COMMENT '费用金额',
  `expense_type` tinyint(1) DEFAULT NULL COMMENT '费用类型',
  `expense_nature` tinyint(1) DEFAULT NULL COMMENT '费用性质 0-日常费用 1-月收费用 2-年收费用 3-特殊费用 4-押金 5-阶段性费用 6-床位费 7-餐饮费 8-护理费 9-定制护理费 10-水费 11-电费 12-医嘱取药 13-检查化验 14-自主点餐 99-入住总缴费',
  `expense_remark` text COMMENT '费用备注',
  `account_preparatory_balance` decimal(32,1) NOT NULL DEFAULT '0.0' COMMENT '账户预存款余额',
  `one_card_balance` decimal(32,1) NOT NULL DEFAULT '0.0' COMMENT '一卡通余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费状态（0 正常，1 作废，2 退费 ,3入院缴费退住结算）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `discount_rate` decimal(10,2) DEFAULT '1.00' COMMENT '折扣比率',
  `discount_amount` decimal(10,2) DEFAULT '0.00' COMMENT '折扣金额',
  `expense_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_estonian_ci DEFAULT NULL COMMENT '费用主键，暂为入院缴费使用',
  `derate_after` decimal(10,2) DEFAULT NULL COMMENT '减免后应收费',
  `consumption_protype` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费大类（1：充值，2:消费）',
  `vip_card_balance` decimal(10,2) DEFAULT '0.00' COMMENT '会员卡余额',
  `cash_coupon_balance` decimal(10,2) DEFAULT '0.00' COMMENT '代金劵余额',
  `source_shop_id` varchar(128) NOT NULL DEFAULT '' COMMENT '店铺来源id',
  `subsidy_type_setting_id` varchar(128) NOT NULL DEFAULT '' COMMENT '补贴设置id',
  `subsidy_name` varchar(128) NOT NULL DEFAULT '' COMMENT '补贴设置名称',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '支付设备id',
  `device_pay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备支付方式 0 其他 1 刷卡 2 刷脸 3 二维码',
  `before_vipdiscount_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '会员卡折扣前的订单金额',
  `freeze_cash_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '冻结现金额度',
  `freeze_coupon_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '冻结代金券额度',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_record_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `record_id` (`record_id`),
  KEY `registrant` (`registrant`),
  KEY `consumption_protype` (`consumption_protype`),
  KEY `start_time` (`start_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消费记录表';

-- ----------------------------
-- Table structure for lb_cms_consumption_record_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_consumption_record_stat`;
CREATE TABLE `lb_cms_consumption_record_stat` (
  `consumption_record_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `stat_year` varchar(16) DEFAULT NULL COMMENT '统计年份',
  `consumption_way` tinyint(1) DEFAULT NULL COMMENT '消费方式',
  `stat_month` varchar(16) DEFAULT NULL COMMENT '统计月份',
  `total_price` decimal(10,2) DEFAULT NULL COMMENT '消费总金额',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `expense_nature` tinyint(1) DEFAULT NULL COMMENT '账单类型',
  `expense_name` varchar(16) DEFAULT NULL COMMENT '账单名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_record_stat_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消费记录统计报表';

-- ----------------------------
-- Table structure for lb_cms_coupon_consumption_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_coupon_consumption_record`;
CREATE TABLE `lb_cms_coupon_consumption_record` (
  `coupon_consumption_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `work_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '工单id',
  `recharge_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '代金券充值记录id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `consumption_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '消费金额',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `status` tinyint(1) NOT NULL DEFAULT '2' COMMENT '消费金额状态 1 冻结 2 消费完成',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '金额类型，0 现金 1 代金券',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`coupon_consumption_record_id`),
  KEY `work_order_id_IDX` (`work_order_id`) USING BTREE,
  KEY `recharge_record_id_IDX` (`recharge_record_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单代金券结算消费记录';

-- ----------------------------
-- Table structure for lb_cms_crutch
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_crutch`;
CREATE TABLE `lb_cms_crutch` (
  `crutch_id` varchar(32) NOT NULL COMMENT '主键',
  `mac` varchar(32) DEFAULT NULL COMMENT 'mac地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `device_type` tinyint(1) NOT NULL DEFAULT '104' COMMENT '设备类型',
  `phone_num` varchar(32) NOT NULL COMMENT '电话号码',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`crutch_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='拐杖表';

-- ----------------------------
-- Table structure for lb_cms_data_docking_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_data_docking_record`;
CREATE TABLE `lb_cms_data_docking_record` (
  `record_id` varchar(32) NOT NULL COMMENT '记录id',
  `docking_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '同步时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT ' 1：已完成 0：失败',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `docking_result` text NOT NULL COMMENT '同步结果信息',
  `docking_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '同步类型 0:长者相关数据  1：记录信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0：否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区数据增量同步记录表';

-- ----------------------------
-- Table structure for lb_cms_day_care_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_day_care_record`;
CREATE TABLE `lb_cms_day_care_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `serve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '服务时间',
  `serve_item` varchar(128) NOT NULL DEFAULT '' COMMENT '服务项目',
  `serve_times` int(10) NOT NULL DEFAULT '0' COMMENT '服务次数',
  `serve_hours` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '服务时长',
  `serve_type` varchar(128) NOT NULL DEFAULT '' COMMENT '服务类别',
  `serve_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '金额（元）',
  `type` varchar(32) NOT NULL COMMENT '类型',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0:否 1:是)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id_idx` (`care_object_id`) USING BTREE COMMENT '長者id',
  KEY `org_id_idx` (`org_id`) USING BTREE COMMENT '机构id'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='日间照料托管服务';

-- ----------------------------
-- Table structure for lb_cms_dementia_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_dementia_config`;
