  `org_id` varchar(32) DEFAULT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `tag` int(11) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`dementia_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='失智评估标准配置';

-- ----------------------------
-- Table structure for lb_cms_device_docking_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_device_docking_info`;
CREATE TABLE `lb_cms_device_docking_info` (
  `docking_info_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `device_id` varchar(128) NOT NULL DEFAULT '' COMMENT '设备id',
  `device_name` varchar(255) NOT NULL DEFAULT '' COMMENT '三方设备名称',
  `position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '位置信息',
  `type_id` varchar(128) NOT NULL DEFAULT '' COMMENT '三方设备类型',
  `big_device_type` varchar(128) NOT NULL DEFAULT '' COMMENT '三方设备大类',
  `device_serial` varchar(128) NOT NULL DEFAULT '' COMMENT '传给三方的设备号',
  `device_model` varchar(32) NOT NULL DEFAULT '' COMMENT '设备型号',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0：失败 1：成功',
  `result` text NOT NULL COMMENT '数据结果信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_info_id`),
  KEY `device_id_index` (`device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备数据对接详情表';

-- ----------------------------
-- Table structure for lb_cms_device_grant_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_device_grant_record`;
CREATE TABLE `lb_cms_device_grant_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `device_name` varchar(64) NOT NULL DEFAULT '' COMMENT '设备名称',
  `device_mode` varchar(32) NOT NULL DEFAULT '' COMMENT '设备型号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_position` varchar(125) NOT NULL DEFAULT '' COMMENT '设备位置',
  `care_object_name` varchar(32) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '电话号码',
  `grant_account_name` varchar(32) NOT NULL DEFAULT '' COMMENT '发放人员名称',
  `grant_man_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '发放人员手机号',
  `check_account_id` varchar(64) DEFAULT '' COMMENT '登记人id',
  `grant_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '发放时间',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `remark` text COMMENT '备注',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `check_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
