  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备发放记录表';

-- ----------------------------
-- Table structure for lb_cms_device_install_docking_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_device_install_docking_info`;
CREATE TABLE `lb_cms_device_install_docking_info` (
  `docking_info_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `record_id` text NOT NULL COMMENT '安装记录id',
  `record_total` int(10) NOT NULL DEFAULT '0' COMMENT '安装记录id数量',
  `third_record_id` varchar(128) NOT NULL DEFAULT '' COMMENT '三方接口返回安装记录id',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0：失败 1：成功',
  `result` text NOT NULL COMMENT '数据结果信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_info_id`),
  KEY `care_object_id_index` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造对接详情表';

-- ----------------------------
-- Table structure for lb_cms_device_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_device_type`;
CREATE TABLE `lb_cms_device_type` (
  `device_type_id` varchar(32) NOT NULL COMMENT '主键',
  `device_name` varchar(32) DEFAULT '' COMMENT '设备名称',
  `device_mode` varchar(32) DEFAULT '' COMMENT '设备型号',
  `device_product_factory` varchar(64) DEFAULT '' COMMENT '设备厂家',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备型号表';

-- ----------------------------
-- Table structure for lb_cms_docking_platform
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_docking_platform`;
CREATE TABLE `lb_cms_docking_platform` (
  `docking_platform_id` varchar(32) NOT NULL COMMENT '主键',
  `docking_manufacturers_name` varchar(64) NOT NULL COMMENT '对接厂商',
  `docking_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '对接厂商类型 1 大华 2 萤石',
  `platform_name` varchar(64) NOT NULL COMMENT '平台名称',
  `platform_website` varchar(255) NOT NULL COMMENT '平台网址',
  `app_id` varchar(64) NOT NULL COMMENT '对接账号',
  `app_secret` varchar(100) NOT NULL COMMENT '账号密码',
  `synchronization_cycle` int(11) NOT NULL COMMENT '同步周期(分钟)',
  `is_connect` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否连接 0 未连接 1 已连接',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `token` varchar(100) DEFAULT NULL COMMENT '管理员token',
  `token_time` bigint(20) DEFAULT '0' COMMENT 'token更新时间',
  `is_synchro` bigint(1) NOT NULL DEFAULT '0' COMMENT '是否启用连接 0 未启用 1 启用',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_platform_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管对接平台表';

-- ----------------------------
-- Table structure for lb_cms_docking_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_docking_setting`;
CREATE TABLE `lb_cms_docking_setting` (
  `docking_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_docking` tinyint(1) NOT NULL COMMENT '是否开启对接设置 0 关闭 1 开启',
  `url` text COMMENT '第三方对接设置地址',
  `app_key` varchar(100) NOT NULL COMMENT '登录账号',
  `app_secret` varchar(100) NOT NULL COMMENT '账号密码',
  `synch_period` int(11) NOT NULL COMMENT '同步周期 默认24小时',
  `is_connect` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否连接 0 未连接 1 连接',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '修改人',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 ',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='南陵特困平台对接设置';

-- ----------------------------
-- Table structure for lb_cms_elder_ability_estimate_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_ability_estimate_object`;
CREATE TABLE `lb_cms_elder_ability_estimate_object` (
  `estimate_object_id` varchar(32) NOT NULL COMMENT '主键',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录主键',
  `height` varchar(32) NOT NULL DEFAULT '' COMMENT '身高',
  `identity` varchar(32) NOT NULL DEFAULT '' COMMENT '能力评估-身份证',
  `weight` varchar(32) NOT NULL DEFAULT '' COMMENT '体重',
  `nation` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:汉族 1:其他',
  `nation_other` varchar(128) NOT NULL DEFAULT '' COMMENT '其他的民族',
  `belief` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:有 1:无',
  `belief_name` varchar(128) NOT NULL DEFAULT '' COMMENT '信仰名称',
  `education` tinyint(1) NOT NULL DEFAULT '0' COMMENT '文化程度',
  `residency` varchar(128) NOT NULL DEFAULT '' COMMENT '居住情况(多选)',
  `marital` tinyint(1) NOT NULL DEFAULT '0' COMMENT '婚姻状况',
  `pay_methods` varchar(128) NOT NULL DEFAULT '' COMMENT '医疗费用支付方式(多选)',
  `economic_sources` varchar(128) NOT NULL DEFAULT '' COMMENT '经济来源',
  `care_risk_event` longtext COMMENT '近30天照顾风险事件(json)',
  `info_provider` varchar(128) NOT NULL DEFAULT '' COMMENT '信息提供者姓名',
  `info_provider_relate` varchar(128) NOT NULL DEFAULT '' COMMENT '信息提供者与老人的关系',
  `concat_name` varchar(128) NOT NULL DEFAULT '' COMMENT '联系人姓名',
  `concat_phone` varchar(128) NOT NULL DEFAULT '' COMMENT '联系人电话',
  `info_provider_name` varchar(128) NOT NULL DEFAULT '' COMMENT '信息提供者与老人的关系(其他)',
  `disease_diagnose_other` varchar(255) NOT NULL DEFAULT '' COMMENT '疾病诊断(其他)',
  `disease_diagnose` varchar(128) NOT NULL DEFAULT '' COMMENT '疾病诊断(多选)',
  `medications` text COMMENT '用药情况',
  `pressure_injury` varchar(128) NOT NULL DEFAULT '' COMMENT '压力性损伤',
  `joint_active` tinyint(1) NOT NULL DEFAULT '0' COMMENT '关节活动度',
  `joint_active_name` varchar(128) NOT NULL DEFAULT '' COMMENT '关节活动度名称',
  `wound_condition` varchar(128) NOT NULL DEFAULT '' COMMENT '伤口情况',
  `special_care` varchar(128) NOT NULL DEFAULT '' COMMENT '特殊护理情况',
  `pain_sensing` varchar(128) NOT NULL DEFAULT '' COMMENT '疼痛感',
  `miss_teeth` text COMMENT '牙齿缺失情况(JSON)',
  `denture_wear` varchar(128) NOT NULL DEFAULT '' COMMENT '义齿佩戴情况',
  `swallow_conditions` varchar(128) NOT NULL DEFAULT '' COMMENT '吞咽情况',
  `malnutrition` tinyint(1) NOT NULL DEFAULT '0' COMMENT '营养不良',
  `airway_clear` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼吸道清理是否有效',
  `is_coma` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否昏迷',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`estimate_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='适老监管评估对象基本信息';

-- ----------------------------
-- Table structure for lb_cms_elder_ability_estimate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_ability_estimate_record`;
CREATE TABLE `lb_cms_elder_ability_estimate_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `elder_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `estimate_standard` int(11) NOT NULL DEFAULT '0' COMMENT '评估标准',
  `estimate_number` varchar(32) NOT NULL DEFAULT '' COMMENT '评估编号',
  `estimate_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '评估时间',
  `estimate_reason` int(11) NOT NULL DEFAULT '0' COMMENT '评估原因(0:首次评估 ,1:常规评估,2.及时评估,3,因对评估结果有疑问进行的复评 4.其他)',
  `estimate_other` varchar(255) NOT NULL DEFAULT '' COMMENT '其他',
  `self_care_info` text COMMENT '自理能力记录',
  `self_care_score` int(1) NOT NULL DEFAULT '0' COMMENT '自理能力得分',
  `athletics_info` text COMMENT '基础运动能力记录',
  `athletics_score` int(1) NOT NULL DEFAULT '0' COMMENT '基础运动能力得分',
  `feeling_social_info` text COMMENT '感知觉与社会参与记录',
  `feeling_social_score` int(1) NOT NULL DEFAULT '0' COMMENT '感知觉与社会参与得分',
  `mentality_info` text COMMENT '精神状态记录',
  `mentality_score` int(1) NOT NULL DEFAULT '0' COMMENT '精神状态得分',
  `ability_start_grade` int(11) NOT NULL DEFAULT '99' COMMENT '老人能力初步等级',
  `ability_grade_basis` int(11) NOT NULL DEFAULT '0' COMMENT '能力登记变更依据',
  `ability_final_grade` int(11) NOT NULL DEFAULT '99' COMMENT '老人能力最终等级',
  `estimate_address` varchar(255) NOT NULL DEFAULT '' COMMENT '评估地点',
  `estimateer_photo` varchar(255) NOT NULL DEFAULT '' COMMENT '评估人员签名',
  `message_offer_photo` varchar(255) NOT NULL DEFAULT '' COMMENT '信息提供者签名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '评估状态',
  `packet_id` varchar(255) NOT NULL DEFAULT '' COMMENT '分包id',
  `check_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `check_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记日期',
  `approve_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审批人姓名',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `approve_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人id',
  `approve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '能力评估-长者姓名',
  `gender` int(11) NOT NULL DEFAULT '0' COMMENT '能力评估-长者性别',
  `birthday` bigint(20) NOT NULL DEFAULT '0' COMMENT '能力评估-出生日期',
  `registration_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '信息登记记录id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='长者能力评估记录表';

-- ----------------------------
-- Table structure for lb_cms_elder_base_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_base_info`;
CREATE TABLE `lb_cms_elder_base_info` (
  `elder_id` varchar(32) NOT NULL COMMENT '长者id',
  `name` varchar(128) DEFAULT NULL COMMENT '长者姓名',
  `identity` varchar(32) NOT NULL DEFAULT '' COMMENT '长者身份证',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '长者电话号码',
  `elder_region` varchar(128) NOT NULL DEFAULT '' COMMENT '长者所属区域',
  `region` varchar(128) NOT NULL DEFAULT '' COMMENT '居住地址',
  `address` varchar(128) NOT NULL DEFAULT '' COMMENT '居住详细信息',
  `location` varchar(255) NOT NULL DEFAULT '' COMMENT '详细地址 gps获取的地址',
  `lat` varchar(128) NOT NULL DEFAULT '' COMMENT '经度',
  `lng` varchar(128) NOT NULL DEFAULT '' COMMENT '纬度',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0:否 1:是)',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `coordsys` tinyint(1) NOT NULL DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `photo` varchar(128) NOT NULL DEFAULT '' COMMENT '长者头像url',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者所在的项目id(非包id)',
  `gender` tinyint(1) NOT NULL DEFAULT '0' COMMENT '性别: 0 未知 1:男 2:女',
  `birthday` bigint(20) NOT NULL DEFAULT '0' COMMENT '生日',
  `elder_source` tinyint(1) NOT NULL DEFAULT '0' COMMENT '长者信息数据来源 0 未知 1:平台申请 2:个人申请',
  `migrate_count` int(11) NOT NULL DEFAULT '0' COMMENT '迁移次数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老监管长者基本信息表';

-- ----------------------------
-- Table structure for lb_cms_elder_base_registration_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_base_registration_record`;
CREATE TABLE `lb_cms_elder_base_registration_record` (
  `registration_record_id` varchar(32) NOT NULL COMMENT '主键',
  `elder_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '记录状态',
  `check_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `check_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记日期',
  `approve_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审批人姓名',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `approve_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人id',
  `approve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:否 1:是',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `packet_id` varchar(32) NOT NULL DEFAULT '' COMMENT '分包id',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`registration_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者登记记录信息';

-- ----------------------------
-- Table structure for lb_cms_elder_care
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_care`;
CREATE TABLE `lb_cms_elder_care` (
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `care_way` tinyint(4) NOT NULL DEFAULT '1' COMMENT '关怀方式 1 电话关怀 2 上门关怀',
  `care_frequency` tinyint(4) NOT NULL DEFAULT '1' COMMENT '关怀频次 1 一周一次 2 一月一次',
  `last_care_record_id` varchar(32) DEFAULT NULL COMMENT '上次关怀记录主键',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启关怀 0 否 1 是',
  `org_id` varchar(32) NOT NULL COMMENT '社区id',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `update_by` varchar(32) NOT NULL COMMENT '更新人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`),
  UNIQUE KEY `pk_index` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者关怀表';

-- ----------------------------
-- Table structure for lb_cms_elder_care_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_care_record`;
CREATE TABLE `lb_cms_elder_care_record` (
  `elder_care_record_id` varchar(32) NOT NULL COMMENT '关怀记录主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `care_name` varchar(32) DEFAULT NULL COMMENT '关怀人员姓名',
  `care_way` tinyint(4) NOT NULL COMMENT '关怀方式 1 电话关怀 2 上门关怀',
  `care_frequency` tinyint(4) NOT NULL COMMENT '关怀频次 1 一周一次 2 一月一次',
  `is_need_serve` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否需要上门服务 0 否 1 是',
  `is_care` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否关怀完成 0 否 1 是',
  `work_order_id` varchar(32) DEFAULT NULL COMMENT '关联工单编号',
  `care_feedback` varchar(255) DEFAULT NULL COMMENT '关怀反馈',
  `last_care_time` bigint(20) DEFAULT NULL COMMENT '上次关怀时间',
  `next_care_time` bigint(20) DEFAULT NULL COMMENT '下次关怀时间',
  `call_id` varchar(32) DEFAULT NULL COMMENT '通话记录id',
  `org_id` varchar(32) NOT NULL COMMENT '社区id',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_by` varchar(32) NOT NULL COMMENT '更新人',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_care_record_id`),
  UNIQUE KEY `uk_work_order_id` (`work_order_id`) USING BTREE,
  KEY `nk_org_id` (`org_id`) USING BTREE,
  KEY `index_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_elder_care_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_care_stat`;
CREATE TABLE `lb_cms_elder_care_stat` (
  `elder_care_stat_id` varchar(32) NOT NULL,
  `stat_year` varchar(16) NOT NULL COMMENT '统计年份',
  `stat_month` varchar(32) NOT NULL COMMENT '统计月份 格式2021-12',
  `province_id` int(10) NOT NULL COMMENT '省级id',
  `city_id` int(10) DEFAULT NULL COMMENT '市级id',
  `area_id` int(10) DEFAULT NULL COMMENT '区级id',
  `street_id` int(10) DEFAULT NULL COMMENT '街道id',
  `elder_count` int(10) DEFAULT NULL COMMENT '长者总数',
  `care_elder_count` int(10) DEFAULT NULL COMMENT '已关怀长者人数',
  `uncare_elder_count` int(10) DEFAULT NULL COMMENT '未关怀长者人数',
  `phone_care_count` int(10) DEFAULT NULL COMMENT '电话关怀次数',
  `scene_care_count` int(10) DEFAULT NULL COMMENT '上门关怀次数',
  `org_id` varchar(32) NOT NULL,
  `create_time` bigint(20) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_care_stat_id`),
  UNIQUE KEY `stat_org_street_idx` (`stat_month`,`street_id`,`org_id`) USING BTREE,
  KEY `org_idx` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_elder_count_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_count_stat`;
CREATE TABLE `lb_cms_elder_count_stat` (
  `elder_count_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `elder_count` int(10) DEFAULT NULL COMMENT '平台下长者总数',
  `elder_man` int(10) DEFAULT '0' COMMENT '男性总数',
  `age_six_upper` int(10) DEFAULT NULL COMMENT '60岁以下长者',
  `age_six_seven` int(10) DEFAULT NULL COMMENT '60岁到69岁',
  `age_seven_eight` int(10) DEFAULT NULL COMMENT '70岁到79岁',
  `age_eight_nine` int(10) DEFAULT NULL COMMENT '80岁到89岁',
  `age_nine_ten` int(10) DEFAULT NULL COMMENT '90岁到99岁',
  `age_ten_up` int(10) DEFAULT NULL COMMENT '100岁以上',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `elder_woman` varchar(255) DEFAULT NULL COMMENT '女性总数',
  `region` varchar(255) DEFAULT NULL COMMENT '长者所在区域信息',
  `care_object_type` tinyint(1) DEFAULT '0' COMMENT '长者类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_count_stat_id`),
  KEY `index_org` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府监管平台一览表长者年龄段数据分布展示';

-- ----------------------------
-- Table structure for lb_cms_elder_docking_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_docking_info`;
CREATE TABLE `lb_cms_elder_docking_info` (
  `docking_info_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `elder_id` varchar(128) NOT NULL DEFAULT '' COMMENT '三方平台长者id',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '0：失败 1：成功',
  `result` text NOT NULL COMMENT '数据结果信息',
  `is_valid` tinyint(1) NOT NULL DEFAULT '1' COMMENT '入住状态 0：退住 1：入住',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_info_id`),
  KEY `care_object_id_index` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者数据对接详情表';

-- ----------------------------
-- Table structure for lb_cms_elder_gov_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_gov_stat`;
CREATE TABLE `lb_cms_elder_gov_stat` (
  `elder_gov_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `stat_year` varchar(16) NOT NULL COMMENT '统计年份 格式2022',
  `stat_month` varchar(32) NOT NULL COMMENT '统计月份 格式2022-12',
  `elder_count` int(10) DEFAULT NULL COMMENT '平台下长者总数',
  `elder_count_in` int(10) DEFAULT NULL COMMENT '入住长者总数',
  `elder_count_out` int(10) DEFAULT NULL COMMENT '退住长者总数',
  `org_id` varchar(32) NOT NULL,
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `region` varchar(255) DEFAULT NULL COMMENT '长者所在地信息',
  `elder_in_man` int(10) DEFAULT '0' COMMENT '长者入住男性',
  `elder_in_woman` int(10) DEFAULT '0' COMMENT '长者入住女性',
  `elder_out_man` int(10) DEFAULT '0' COMMENT '长者退住男性',
  `elder_out_woman` int(10) DEFAULT '0' COMMENT '长者退住女性',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_gov_stat_id`),
  KEY `index_org` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府监管平台一览表退住入住数据展示';

-- ----------------------------
-- Table structure for lb_cms_elder_migrate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_migrate_record`;
CREATE TABLE `lb_cms_elder_migrate_record` (
  `migrate_record_id` varchar(32) NOT NULL COMMENT '长者机构迁移主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `old_org_id` varchar(32) DEFAULT NULL COMMENT '机构id(源头)',
  `new_org_id` varchar(32) DEFAULT NULL COMMENT '机构id(终点)',
  `org_id` varchar(32) DEFAULT NULL COMMENT '当前机构id',
  `is_delete` tinyint(1) unsigned DEFAULT '0' COMMENT '是否删除0否1:是',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `migrate_type` tinyint(1) DEFAULT '0' COMMENT '0:社区-社区',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`migrate_record_id`),
  KEY `care_object_id_index` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区平台长者迁移记录';

-- ----------------------------
-- Table structure for lb_cms_elder_modification_evaluation_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_modification_evaluation_record`;
CREATE TABLE `lb_cms_elder_modification_evaluation_record` (
  `modification_evaluation_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `status` tinyint(1) NOT NULL DEFAULT '2' COMMENT '状态',
  `package_id` varchar(32) NOT NULL DEFAULT '' COMMENT '分包id',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `approve_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人id',
  `approve_account_name` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人姓名',
  `approve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `self_care_score` tinyint(1) NOT NULL DEFAULT '0' COMMENT '自理能力得分',
  `athletics_score` tinyint(1) NOT NULL DEFAULT '0' COMMENT '基础运动能力得分',
  `feeling_social_score` tinyint(1) NOT NULL DEFAULT '0' COMMENT '感知觉与社会参与得分',
  `mentality_score` tinyint(1) NOT NULL DEFAULT '0' COMMENT '精神状态得分',
  `total_score` tinyint(1) NOT NULL DEFAULT '0' COMMENT '总得分',
  `ability_final_grade` tinyint(1) NOT NULL DEFAULT '0' COMMENT '长者能力等级',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `ability_estimate_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '能力评估记录id',
  `ability_grade_basis` tinyint(1) NOT NULL DEFAULT '0' COMMENT '能力等级变更依据',
  `registration_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '信息登记记录id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`modification_evaluation_record_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `package_id_IDX` (`package_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造长者改造评定';

-- ----------------------------
-- Table structure for lb_cms_elder_msg
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_msg`;
CREATE TABLE `lb_cms_elder_msg` (
  `msg_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL COMMENT '长者ID',
  `action_type` tinyint(1) DEFAULT '0' COMMENT '行动类型 0-发起 1-取消',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态 :0-正常 1-废弃（取消）',
  `source_id` varchar(32) DEFAULT NULL COMMENT '来源ID（比如服务消息为工单ID）',
  `content` text COMMENT '消息内容',
  `extra_content` text COMMENT '额外信息',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '删除标识:0-未删除，1-删除',
  `is_read` tinyint(1) DEFAULT '0' COMMENT '是否已读:0-未读，1-已读',
  `msg_type` tinyint(1) NOT NULL COMMENT '消息类型 0-服务消息 1-活动消息 2-点餐消息 3-购物消息 4-健康消息',
  `amount` decimal(10,2) DEFAULT '0.00' COMMENT '金额',
  `msg_dt` bigint(20) DEFAULT NULL COMMENT '消息日期（活动日期、服务上门日期等）',
  `msg_time_descr` varchar(300) DEFAULT NULL COMMENT '消息时间描述',
  `shop_id` varchar(32) NOT NULL COMMENT '店铺id',
  `shop_name` varchar(100) NOT NULL DEFAULT '' COMMENT '店铺名称',
  `commodity_name` text COMMENT '活动以及购买商品名称',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`msg_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者消息表';

-- ----------------------------
-- Table structure for lb_cms_elder_packet_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_packet_info`;
CREATE TABLE `lb_cms_elder_packet_info` (
  `packet_info_id` varchar(32) NOT NULL COMMENT '主键',
  `elder_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `packet_id` varchar(32) NOT NULL DEFAULT '' COMMENT '包id',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `flow_type` varchar(32) NOT NULL DEFAULT '0' COMMENT '流程类型总和',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:否1:是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`packet_info_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者所在包的关系表';

-- ----------------------------
-- Table structure for lb_cms_elder_renovation_check_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_renovation_check_record`;
CREATE TABLE `lb_cms_elder_renovation_check_record` (
  `record_id` varchar(64) NOT NULL COMMENT '记录主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录状态',
  `device_number` int(11) NOT NULL DEFAULT '0' COMMENT '建设设备数量',
  `construct_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '建设设备价格',
  `approve_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审批人姓名',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `approve_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人id',
  `approve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属项目id',
  `package_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属分包id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `self_care_score` int(11) NOT NULL DEFAULT '0' COMMENT '自理能力得分',
  `athletics_score` int(11) NOT NULL DEFAULT '0' COMMENT '基础运动能力得分',
  `feeling_social_score` int(11) NOT NULL DEFAULT '0' COMMENT '感知觉与社会参与得分',
  `mentality_score` int(11) NOT NULL DEFAULT '0' COMMENT '精神状态得分',
  `ability_final_grade` int(11) NOT NULL DEFAULT '0' COMMENT '能力最终等级',
  `estimate_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录id',
  `construct_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '建设记录id',
  `ability_estimate_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '能力评估记录id',
  `estimate_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '改造评估价格',
  `estimate_number` int(11) NOT NULL DEFAULT '0' COMMENT '改造评估设备数据',
  `check_account_name` varchar(32) NOT NULL DEFAULT '' COMMENT '建设人员姓名',
  `registration_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '信息登记id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者改造验收记录表';

-- ----------------------------
-- Table structure for lb_cms_elder_renovation_construct_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_renovation_construct_record`;
CREATE TABLE `lb_cms_elder_renovation_construct_record` (
  `record_id` varchar(64) NOT NULL COMMENT '记录主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
