  `estimate_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `estimate_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `estimate_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记日期',
  `approve_account_name` varchar(64) NOT NULL DEFAULT '' COMMENT '审批人姓名',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `approve_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审批人id',
  `work_order_photo` text NOT NULL COMMENT '施工单、验收单照片',
  `house_photo` text NOT NULL COMMENT '屋内照片',
  `group_photo` text NOT NULL COMMENT '合影照',
  `annex` text NOT NULL COMMENT '附件',
  `signature` varchar(128) NOT NULL DEFAULT '' COMMENT '长者签字',
  `approve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `project_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属项目id',
  `package_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属分包id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `estimate_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录id',
  `assessment_photo` text NOT NULL COMMENT '需求评估照片',
  `check_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '改造验收记录id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者改造建设记录表';

-- ----------------------------
-- Table structure for lb_cms_elder_renovation_device_message
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_renovation_device_message`;
CREATE TABLE `lb_cms_elder_renovation_device_message` (
  `device_id` varchar(64) NOT NULL COMMENT '设备主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `binding_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '绑定状态 1未安装 2已安装未绑定 3已安装已绑定',
  `device_name` varchar(64) NOT NULL DEFAULT '' COMMENT '设备名称',
  `device_photo` varchar(128) NOT NULL DEFAULT '' COMMENT '设备图片',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '设备价格',
  `serial_num` int(11) NOT NULL DEFAULT '1' COMMENT '设备序号',
  `is_outsourcing` int(11) NOT NULL DEFAULT '1' COMMENT '是否是来邦设备 0 否 1 是',
  `device_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac地址',
  `iot_product_id` varchar(32) NOT NULL DEFAULT '' COMMENT '产品id',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信id（电信云平台注册返回）',
  `iot_card_num` varchar(64) NOT NULL DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台所属应用id',
  `online_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '在线时间',
  `status` int(3) NOT NULL DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) NOT NULL DEFAULT '0' COMMENT '电量',
  `hardware_version` varchar(32) NOT NULL DEFAULT '' COMMENT '硬件版本号',
  `nb_version` varchar(32) NOT NULL DEFAULT '' COMMENT '版本号',
  `version` smallint(1) NOT NULL DEFAULT '1' COMMENT '下发信息版本号',
  `notes` varchar(128) NOT NULL DEFAULT '' COMMENT '备注',
  `install_before_url` text NOT NULL COMMENT '设备安装前的照片',
  `install_after_url` text NOT NULL COMMENT '设备安装后的照片',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `renovation_inventory_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备改造清单id',
  `position_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备安装位置id',
  `device_model` varchar(64) NOT NULL DEFAULT '' COMMENT '设备型号 ，来邦设备，设备型号必填',
  `position_message` varchar(255) NOT NULL DEFAULT '' COMMENT '位置信息',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属记录id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者改造建设设备表';

-- ----------------------------
-- Table structure for lb_cms_elder_renovation_estimate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_renovation_estimate_record`;
CREATE TABLE `lb_cms_elder_renovation_estimate_record` (
  `record_id` varchar(64) NOT NULL COMMENT '记录主键',
