-- ----------------------------
-- Table structure for lb_cms_elder_renovation_position_list
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_renovation_position_list`;
CREATE TABLE `lb_cms_elder_renovation_position_list` (
  `position_id` varchar(64) NOT NULL COMMENT '位置主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `position_photo` varchar(128) NOT NULL DEFAULT '' COMMENT '安装位置图片',
  `position_abbreviation_photo` varchar(128) NOT NULL DEFAULT '' COMMENT '安装位置缩略图',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `position_name` varchar(32) NOT NULL DEFAULT '' COMMENT '安装位置名称',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属记录id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`position_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者改造建设设备安装位置记录表';

-- ----------------------------
-- Table structure for lb_cms_elder_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_stat`;
CREATE TABLE `lb_cms_elder_stat` (
  `elder_stat_id` varchar(32) NOT NULL,
  `stat_year` varchar(16) NOT NULL COMMENT '统计年份',
  `stat_month` varchar(32) NOT NULL COMMENT '统计月份 格式2021-12',
  `province_id` int(10) DEFAULT NULL COMMENT '省级id',
  `city_id` int(10) DEFAULT NULL COMMENT '市级id',
  `area_id` int(10) DEFAULT NULL COMMENT '区级id',
  `street_id` int(10) DEFAULT NULL COMMENT '街道id',
  `elder_count` int(10) DEFAULT NULL COMMENT '长者总数',
  `serve_elder_count` int(10) DEFAULT NULL COMMENT '已服务长者人数',
  `serve_man_count` int(10) DEFAULT NULL COMMENT '已服务男性总数',
  `serve_woman_count` int(10) DEFAULT NULL COMMENT '已服务女性总数',
  `serve_two_count` int(10) DEFAULT NULL COMMENT '服务两次及以下长者数',
  `serve_three_count` int(10) DEFAULT NULL COMMENT '服务三次及以下长者数',
  `serve_four_count` int(10) DEFAULT NULL COMMENT '服务四次及以下长者数',
  `serve_five_count` int(10) DEFAULT NULL COMMENT '服务五次及以下长者数',
  `serve_six_count` int(10) DEFAULT NULL COMMENT '服务六次及以下长者数',
  `serve_much_count` int(10) DEFAULT NULL COMMENT '服务六次及以上长者数',
  `order_count` int(10) DEFAULT NULL COMMENT '服务工单数',
  `order_amount` decimal(10,2) DEFAULT NULL COMMENT '服务总金额',
  `org_id` varchar(32) NOT NULL,
  `create_time` bigint(20) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `eval_level_no` int(10) DEFAULT '0' COMMENT '未评价',
  `eval_level_five` int(10) DEFAULT '0' COMMENT '满意度:非常满意',
  `eval_level_four` int(10) DEFAULT '0' COMMENT '满意度:满意',
  `eval_level_three` int(10) DEFAULT '0' COMMENT '满意度:一般',
  `eval_level_two` int(10) DEFAULT '0' COMMENT '满意度:不满意',
  `eval_level_one` int(10) DEFAULT '0' COMMENT '满意度:非常不满意',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_stat_id`) USING BTREE,
  UNIQUE KEY `stat_org_street_idx` (`stat_month`,`street_id`,`org_id`) USING BTREE,
  KEY `org_idx` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_cms_elder_subsidy_archives
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elder_subsidy_archives`;
CREATE TABLE `lb_cms_elder_subsidy_archives` (
  `archives_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `subsidy_name` varchar(128) NOT NULL DEFAULT '' COMMENT '补贴名称',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `registrant` varchar(128) NOT NULL DEFAULT '' COMMENT '登记人',
  `registrant_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `is_cancel` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否退档 1:是 0：否 默认 0',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0：未删除 1:删除 默认 0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`archives_id`),
  KEY `care_object_id_index` (`care_object_id`) USING BTREE COMMENT '账户id索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区长者国家补贴档案表';

-- ----------------------------
-- Table structure for lb_cms_elderinfo_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_elderinfo_contacts`;
CREATE TABLE `lb_cms_elderinfo_contacts` (
  `contacts_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(128) DEFAULT NULL COMMENT '联系人姓名',
  `relation` varchar(16) NOT NULL DEFAULT '' COMMENT '联系人与长者的关系',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '电话号码',
  `relation_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '关系类型(0:亲属关系1:紧急联系人 )',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 (0:否 1:是)',
  `elder_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contacts_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者亲属关系表';

-- ----------------------------
-- Table structure for lb_cms_estimate_commdict
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_estimate_commdict`;
CREATE TABLE `lb_cms_estimate_commdict` (
  `commdict_id` int(10) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `type_order` int(4) NOT NULL DEFAULT '0' COMMENT '类型排序',
  `type` varchar(128) NOT NULL DEFAULT '' COMMENT '类型',
  `type_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '字典数据类型描述',
  `key` varchar(128) NOT NULL DEFAULT '' COMMENT '键',
  `value` varchar(128) NOT NULL DEFAULT '' COMMENT '值',
  `is_open` tinyint(4) NOT NULL DEFAULT '1' COMMENT '1开放查询 2不开放查询',
  `is_editable` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否可编辑，0否,1可编辑',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `topic_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主题id',
  `type_child` varchar(128) NOT NULL DEFAULT '' COMMENT '类型补充标识',
  `type_child_desc` varchar(128) NOT NULL COMMENT '类型补充标识描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `order_num` int(4) NOT NULL DEFAULT '0' COMMENT '排序字段',
  `is_delete` int(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`commdict_id`)
) ENGINE=InnoDB AUTO_INCREMENT=270 DEFAULT CHARSET=utf8mb4 COMMENT='适老监管能力评估字典表';

-- ----------------------------
-- Table structure for lb_cms_food
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food`;
CREATE TABLE `lb_cms_food` (
  `food_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `food_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食物类别主键',
  `food_name` varchar(32) NOT NULL DEFAULT '' COMMENT '食物名称',
  `spice` varchar(32) NOT NULL DEFAULT '' COMMENT '辣味',
  `texture` varchar(32) NOT NULL DEFAULT '' COMMENT '口感',
  `taste` varchar(32) NOT NULL DEFAULT '' COMMENT '口味',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '价格',
  `is_order` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可点（0 不可点，1 可点）',
  `term` tinyint(1) DEFAULT NULL COMMENT '长短期（0 短期，1 长期）',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `food_desc` text COMMENT '食材说明',
  `taboo` text COMMENT '禁忌项',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '食物图片地址',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `food_type` varchar(32) NOT NULL DEFAULT '' COMMENT '菜品类型',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `meal` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次类别',
  `vip_price` decimal(10,2) DEFAULT NULL COMMENT '价格',
  `food_number` int(10) NOT NULL DEFAULT '0' COMMENT '食物库存量',
  `food_num_id` int(11) NOT NULL DEFAULT '1' COMMENT '菜品id(点餐机对接需要传数字id)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_sort_id` (`food_sort_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食物表';

-- ----------------------------
-- Table structure for lb_cms_food_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_order`;
CREATE TABLE `lb_cms_food_order` (
  `food_order_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `orderer` varchar(128) DEFAULT NULL COMMENT '姓名',
  `meal` tinyint(1) NOT NULL COMMENT '餐次（0 早茶，1 早餐，2 午餐，3 下午茶，4 晚餐，5 宵夜）',
  `order_content` text NOT NULL COMMENT '点餐内容',
  `order_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '点餐总价',
  `delivery_address` text COMMENT '送餐地址信息',
  `meal_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '就餐时间',
  `order_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '下单时间',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订餐状态（0 待送餐/出餐，1 已送餐/出餐，2 已取消，3 已超时，4 送餐中，5 预约待确认）',
  `deliverer` varchar(32) NOT NULL DEFAULT '' COMMENT '送餐人',
  `delivery_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '送餐时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `deliverer_id` varchar(64) NOT NULL DEFAULT '' COMMENT '送餐人主键',
  `orderer_id` varchar(64) NOT NULL DEFAULT '' COMMENT '下单人主键',
  `settle_method` varchar(64) NOT NULL DEFAULT '0' COMMENT '结算方式（0-账户余额，1-一卡通余额， 2-现金支付）',
  `order_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '点餐类型（0 食谱点餐，1 平台在线点餐，2 护工APP点餐，3 长者APP点餐）',
  `cancel_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '取消类型（0 未取消，1 系统取消，2 人为取消）',
  `refund_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退款状态（0 未退款，1 待退款，2 已退款）',
  `timeout_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '超时时间',
  `meal_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '就餐方式（0-店内就餐， 1-送餐上门， 2-打包带走 ）',
  `diners_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '就餐人类型（0 长者，1 员工，2 其他，参照lb_ims_ic_card表account_type字段）',
  `delivery_expense` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '送餐费用',
  `remark` text COMMENT '备注',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `serial_num` smallint(6) NOT NULL DEFAULT '0' COMMENT '流水号',
  `take_num` varchar(3) NOT NULL DEFAULT '' COMMENT '取餐号',
  `actual_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '实收金额（现金支付有效）',
  `order_vip_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '点餐会员总价',
  `vip_order` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为VIP订单 0 否 1 是',
  `meal_way_mode` tinyint(4) DEFAULT NULL COMMENT '线上订单细节 1:自提 2:配送',
  `pay_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单支付状态 0:未支付 1:已支付（默认 0）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_order_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `orderer_id` (`orderer_id`) USING BTREE,
  KEY `status` (`status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='订餐记录表';

-- ----------------------------
-- Table structure for lb_cms_food_order_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_order_detail`;
CREATE TABLE `lb_cms_food_order_detail` (
  `food_order_detail_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `food_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '点餐订单主键',
  `food_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食物类别主键',
  `food_id` varchar(32) DEFAULT '' COMMENT '食物主键',
  `food_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '食物类型（0-食谱，1-食物）',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '食物名称',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '食物图片',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '食物价格',
  `food_content` text COMMENT '食物内容',
  `num` int(11) NOT NULL DEFAULT '1' COMMENT '点餐数量',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `vip_price` decimal(10,2) DEFAULT NULL COMMENT '会员价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_order_detail_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `food_order_id` (`food_order_id`) USING BTREE,
  KEY `food_sort_id` (`food_sort_id`) USING BTREE,
  KEY `food_id` (`food_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='订餐明细表';

-- ----------------------------
-- Table structure for lb_cms_food_purchase
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_purchase`;
CREATE TABLE `lb_cms_food_purchase` (
  `food_purchase_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `purchase_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '采购日期',
  `purchase_detail` text NOT NULL COMMENT '采购食材明细',
  `purchase_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '采购总金额',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant` varchar(128) DEFAULT NULL COMMENT '姓名',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `remark` varchar(200) DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_purchase_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食材采购记录表';

-- ----------------------------
-- Table structure for lb_cms_food_shop
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_shop`;
CREATE TABLE `lb_cms_food_shop` (
  `food_shop_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `shop_name` varchar(32) NOT NULL DEFAULT '' COMMENT '店铺名称',
  `shop_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '店铺类型（0-食堂， 1-餐饮店）',
  `shop_address` varchar(256) NOT NULL DEFAULT '' COMMENT '店铺地址',
  `contact_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '联系人手机号',
  `remark` varchar(256) DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `shop_photo` varchar(64) NOT NULL DEFAULT '' COMMENT '店铺图片地址',
  `lng` varchar(32) NOT NULL DEFAULT '' COMMENT '经度',
  `lat` varchar(32) NOT NULL DEFAULT '' COMMENT '纬度',
  `position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '位置叙述',
  `is_default` tinyint(1) DEFAULT '0' COMMENT '是否默认 是1 否 0',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_meal_assistance` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否是助餐 0 否 1 是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_shop_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='餐饮店铺表';

-- ----------------------------
-- Table structure for lb_cms_food_shop_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_shop_account`;
CREATE TABLE `lb_cms_food_shop_account` (
  `food_shop_account_id` varchar(32) NOT NULL COMMENT '主键',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_shop_account_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='餐饮店铺用户关联表';

-- ----------------------------
-- Table structure for lb_cms_food_sort
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_food_sort`;
CREATE TABLE `lb_cms_food_sort` (
  `food_sort_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `sort_name` varchar(32) NOT NULL DEFAULT '' COMMENT '类别名称',
  `sort_desc` varchar(255) DEFAULT '' COMMENT '类别说明',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `category_id` int(11) NOT NULL DEFAULT '1' COMMENT '分类id（对接点餐机，要求分类id传数字）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_sort_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食物类别表';

-- ----------------------------
-- Table structure for lb_cms_gift
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_gift`;
CREATE TABLE `lb_cms_gift` (
  `gift_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) NOT NULL COMMENT '类型',
  `type` varchar(32) NOT NULL COMMENT '类型',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态 0-下架 1-上架',
  `unit` varchar(32) NOT NULL COMMENT '单位',
  `price` decimal(10,2) NOT NULL COMMENT '价格',
  `points` int(9) NOT NULL COMMENT '所需积分',
  `img` varchar(255) NOT NULL COMMENT '所需积分',
  `register_name` varchar(32) NOT NULL COMMENT '登记人',
  `register_time` varchar(32) NOT NULL COMMENT '登记时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`gift_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='礼品表';

-- ----------------------------
-- Table structure for lb_cms_gift_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_gift_type`;
CREATE TABLE `lb_cms_gift_type` (
