) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='礼品单位表';

-- ----------------------------
-- Table structure for lb_cms_goods
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods`;
CREATE TABLE `lb_cms_goods` (
  `goods_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_name` varchar(64) DEFAULT '' COMMENT '商品名称',
  `goods_detail` text COMMENT '卖点描述',
  `vip_price` decimal(10,2) DEFAULT NULL COMMENT '会员价',
  `selling_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品售价',
  `status` tinyint(4) DEFAULT '1' COMMENT '销售状态(1:销售,2:已下架)',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '商品类型',
  `goods_photo` varchar(128) DEFAULT '' COMMENT '商品图片',
  `goods_detail_photo` text COMMENT '商品详情图片',
  `specification` varchar(32) DEFAULT '' COMMENT '商品规格(套,只,个,台)',
  `goods_packing` varchar(32) DEFAULT '' COMMENT '商品包装',
  `recommend_level` tinyint(4) DEFAULT '0' COMMENT '推荐级别',
  `pull_time` bigint(20) DEFAULT NULL COMMENT '下架时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `barcode` varchar(32) NOT NULL DEFAULT '' COMMENT '条码',
  `inventory` int(11) DEFAULT '0' COMMENT '库存',
  `warning_inventory` int(11) DEFAULT '0' COMMENT '预警库存',
  `cost_price` decimal(10,2) DEFAULT NULL COMMENT '商品成本价',
  `create_by` varchar(32) DEFAULT NULL COMMENT '生成人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_id`),
  KEY `org_index` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `barcode` (`barcode`) USING BTREE,
  KEY `goods_type_id` (`goods_type_id`) USING BTREE,
  KEY `is_delete` (`is_delete`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='商品表';

-- ----------------------------
-- Table structure for lb_cms_goods_inventory_change
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_inventory_change`;
CREATE TABLE `lb_cms_goods_inventory_change` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `batch` varchar(32) DEFAULT NULL COMMENT '批次',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `goods_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品主键',
  `goods_name` varchar(64) NOT NULL DEFAULT '' COMMENT '商品名称',
  `barcode` varchar(32) NOT NULL DEFAULT '' COMMENT '商品条码',
  `specification` varchar(32) DEFAULT '' COMMENT '商品规格',
  `inventory_num` int(11) NOT NULL DEFAULT '0' COMMENT '库存数量',
  `change_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '变动类型（1-入库，2-出库，3-报废）',
  `change_num` int(11) NOT NULL DEFAULT '0' COMMENT '变动数量',
  `remark` varchar(100) DEFAULT '' COMMENT '备注',
  `operator_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人主键',
  `operator` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `operate_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '操作时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0-未删除，1-删除）',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品类别主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='商品库存变动记录表';

-- ----------------------------
-- Table structure for lb_cms_goods_inventory_check
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_inventory_check`;
CREATE TABLE `lb_cms_goods_inventory_check` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `goods_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品主键',
  `goods_name` varchar(64) NOT NULL DEFAULT '' COMMENT '商品名称',
  `barcode` varchar(32) NOT NULL DEFAULT '' COMMENT '商品条码',
  `selling_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品售价',
  `in_num` int(11) NOT NULL DEFAULT '0' COMMENT '入库数量',
  `out_num` int(11) NOT NULL DEFAULT '0' COMMENT '出库数量',
  `sell_num` int(11) NOT NULL DEFAULT '0' COMMENT '售出数量',
  `inventory_num` int(11) NOT NULL DEFAULT '0' COMMENT '库存数量',
  `inventory_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '盘点时间',
  `scrap_num` int(11) NOT NULL DEFAULT '0' COMMENT '报废数量',
  `vip_price` decimal(10,2) DEFAULT NULL COMMENT '会员价',
  `total_prices` decimal(20,2) DEFAULT '0.00' COMMENT '商品总值',
  `warning_inventory` int(11) DEFAULT '0' COMMENT '预警库存',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0-未删除，1-删除）',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品类别主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='商品库存盘点记录表';

-- ----------------------------
-- Table structure for lb_cms_goods_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_order`;
CREATE TABLE `lb_cms_goods_order` (
  `goods_order_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `goods_total_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '商品总价',
  `discounts_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '优惠金额',
  `order_total_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '订单总价',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '订单状态(（0 待送货，1 已送达，2 已取消，3 已超时，4 送货中，5 预约待确认）)',
  `refund_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '退款状态 （0 未退款 1 已退款）',
  `buy_way` tinyint(4) NOT NULL DEFAULT '1' COMMENT '购买方式(1:平台商城下单，2:长者APP下单)',
  `pay_way` tinyint(2) DEFAULT '1' COMMENT '支付方式(1 一卡通余额 2 账户余额)',
  `pay_time` bigint(20) DEFAULT NULL COMMENT '付款时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `actual_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '实收金额（现金支付有效）',
  `total_cost` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总成本',
  `serial_num` smallint(6) NOT NULL DEFAULT '0' COMMENT '流水号',
  `delivery_address` text COMMENT '送货地址',
  `delivery_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '送货时间',
  `order_content` text NOT NULL COMMENT '订单内容',
  `order_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '下单时间',
  `order_content_desc` text NOT NULL COMMENT '订单内容描述',
  `create_by` varchar(128) DEFAULT NULL COMMENT '姓名',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `buy_way_mode` tinyint(4) DEFAULT NULL COMMENT '线上订单细节 1:自提 2:配送',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_order_id`),
  KEY `care_object_index` (`care_object_id`) USING BTREE,
  KEY `org_index` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='购物订单表';

-- ----------------------------
-- Table structure for lb_cms_goods_order_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_order_detail`;
CREATE TABLE `lb_cms_goods_order_detail` (
  `goods_order_detail_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_order_id` varchar(32) NOT NULL COMMENT '订单号',
  `goods_id` varchar(20) NOT NULL COMMENT '商品id',
  `goods_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品支付的时单价',
  `goods_num` int(10) NOT NULL COMMENT '商品的数量',
  `order_amount` decimal(10,2) DEFAULT NULL COMMENT '订单金额',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `cost_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品成本价',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品类别主键',
  `order_cost` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '订单成本',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '购物店铺主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '商品名称',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '商品图片',
  `vip_price` decimal(10,2) DEFAULT NULL COMMENT '会员价',
  `goods_content` text COMMENT '商品内容',
  `create_by` varchar(32) DEFAULT NULL COMMENT '生成人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_order_detail_id`) USING BTREE,
  KEY `goods_order_index` (`goods_order_id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单详细表';

-- ----------------------------
-- Table structure for lb_cms_goods_shop
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_shop`;
CREATE TABLE `lb_cms_goods_shop` (
  `goods_shop_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `shop_name` varchar(32) NOT NULL DEFAULT '' COMMENT '店铺名称',
  `shop_address` varchar(255) NOT NULL DEFAULT '' COMMENT '店铺地址',
  `shop_photo` varchar(64) NOT NULL DEFAULT '' COMMENT '店铺图片地址',
  `business` varchar(255) DEFAULT '' COMMENT '主营业务',
  `contact_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '负责人手机号',
  `lng` varchar(32) NOT NULL DEFAULT '' COMMENT '经度',
  `lat` varchar(32) NOT NULL DEFAULT '' COMMENT '纬度',
  `position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '位置叙述',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) DEFAULT '0' COMMENT '是否默认 是1 否 0',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_shop_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='商家店铺表';

-- ----------------------------
-- Table structure for lb_cms_goods_shop_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_shop_account`;
CREATE TABLE `lb_cms_goods_shop_account` (
  `goods_shop_account_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_shop_account_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='商家店铺用户关联表';

-- ----------------------------
-- Table structure for lb_cms_goods_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_goods_type`;
CREATE TABLE `lb_cms_goods_type` (
  `goods_type_id` varchar(32) NOT NULL COMMENT '商品类型主键',
  `name` varchar(32) NOT NULL COMMENT '类别名称',
  `icon_path` varchar(64) DEFAULT NULL COMMENT '图标',
  `org_id` varchar(32) NOT NULL,
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_type_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品类型表';

-- ----------------------------
-- Table structure for lb_cms_gov_region_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_gov_region_config`;
CREATE TABLE `lb_cms_gov_region_config` (
  `gov_region_config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL,
  `province_id` varchar(32) DEFAULT NULL COMMENT '省级区域id',
  `city_id` varchar(32) DEFAULT NULL COMMENT '市级区域id',
  `area_id` varchar(32) DEFAULT NULL COMMENT '区级区域id',
  `street_id` varchar(32) DEFAULT NULL COMMENT '街道区域id',
  `address_info` varchar(255) DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `create_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `update_by` varchar(32) DEFAULT NULL,
  `title_set` varchar(32) DEFAULT NULL COMMENT '标题设置',
  `ad_msg_id` varchar(32) DEFAULT NULL COMMENT '关联广告信息id',
  `charge_type` tinyint(1) DEFAULT NULL COMMENT '菜单类型：1：平台数据总览 2：长者信息总览 3：机构养老数据 4：社区养老数据 5：居家养老数据',
  `is_carousel` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启轮播 0:关闭 1:开启',
  `view_style` tinyint(1) DEFAULT '0',
  `zoom` double(8,2) DEFAULT NULL,
  `center` varchar(255) DEFAULT NULL,
  `work_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '工作模式 0:工作模式 1:演示模式',
  `show_digital_human` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示数字人 0:不显示 1:显示',
  `broadcast_content` text COMMENT '数字人播报内容',
  `template_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '模版类型 1:模版一 2:模版二',
  `org_info_show` varchar(255) NOT NULL DEFAULT '' COMMENT '平台数据显示',
  `inner_page_show` tinyint(1) NOT NULL DEFAULT '0' COMMENT '内页机构列表展示 0:不展示 1:展示 默认 0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`gov_region_config_id`),
  KEY `org_index` (`org_id`) USING BTREE COMMENT '机构索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府监管平台统计区域配置表';

-- ----------------------------
-- Table structure for lb_cms_health_index
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_health_index`;
CREATE TABLE `lb_cms_health_index` (
  `health_index_id` int(10) NOT NULL DEFAULT '0' COMMENT '主键',
  `index_type` varchar(32) NOT NULL COMMENT '指标类型',
  `index_name` varchar(32) NOT NULL COMMENT '指标名称',
  `index_min` decimal(10,4) DEFAULT NULL COMMENT '取值范围下界限',
  `index_max` decimal(10,4) DEFAULT NULL COMMENT '取值范围上界限',
  `unit` varchar(32) DEFAULT '' COMMENT '单位',
  `index_describe` varchar(32) NOT NULL COMMENT '描述',
  `color` varchar(32) DEFAULT NULL COMMENT '颜色',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `gender` int(2) DEFAULT NULL,
  `normal` int(2) DEFAULT '0',
  `index_symbol` varchar(32) DEFAULT NULL COMMENT '符号描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_index_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_health_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_health_record`;
CREATE TABLE `lb_cms_health_record` (
  `health_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `care_object_name` varchar(32) DEFAULT NULL COMMENT '老人姓名',
  `index` varchar(32) DEFAULT NULL COMMENT '指标类型',
  `number` varchar(750) DEFAULT NULL COMMENT '指标',
  `data_src` varchar(32) DEFAULT NULL COMMENT '数据来源,0手动录入 1设备上报 2 健康一体机',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `medical_time` bigint(20) DEFAULT NULL COMMENT '体检时间',
  `device_number` varchar(100) DEFAULT NULL COMMENT '设备型号',
  `device_vendor` varchar(100) DEFAULT NULL COMMENT '设备厂商',
  `medical_record_id` varchar(32) DEFAULT NULL COMMENT '体检记录主键',
  `remark` varchar(255) DEFAULT NULL COMMENT '助老app端录入备注',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `work_order_id` varchar(32) DEFAULT NULL COMMENT '工单id',
  `data_src_detail` tinyint(10) DEFAULT '0' COMMENT '数据具体来源 0:未知 1:助老app 2:小程序',
  `machine_record_no` varchar(128) DEFAULT '' COMMENT '三方对接接口上传健康数据唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_record_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_health_report_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_health_report_record`;
CREATE TABLE `lb_cms_health_report_record` (
  `report_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `index` varchar(32) NOT NULL DEFAULT '' COMMENT '指标类型',
  `number` varchar(255) NOT NULL DEFAULT '' COMMENT '指标数值',
  `number_state_source` tinyint(1) NOT NULL DEFAULT '0' COMMENT '指标数值标准来源值',
  `number_state` tinyint(1) NOT NULL DEFAULT '0' COMMENT '指标数值标准（1=偏高 2=偏低 3=正常）',
  `data_src` tinyint(1) NOT NULL DEFAULT '0' COMMENT '数据来源:0:未知 2:健康一体机',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `report_id` varchar(128) NOT NULL DEFAULT '' COMMENT '健康一体机上传健康数据唯一标识(报告id)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`report_record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `report_id_index` (`report_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康一体机健康报告记录表';

-- ----------------------------
-- Table structure for lb_cms_health_station
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_health_station`;
CREATE TABLE `lb_cms_health_station` (
  `health_station_id` varchar(32) NOT NULL COMMENT '主键',
  `station_name` varchar(32) DEFAULT NULL COMMENT '服务站名称',
  `station_address` varchar(255) DEFAULT NULL COMMENT '服务站地址',
  `station_localtion` varchar(255) DEFAULT NULL COMMENT '服务站位置',
  `lat` varchar(255) DEFAULT NULL COMMENT '经度',
  `lng` varchar(255) DEFAULT NULL COMMENT '纬度',
  `station_server` varchar(255) DEFAULT NULL COMMENT '主营业务',
  `station_account_name` varchar(255) DEFAULT NULL COMMENT '负责人姓名',
  `station_account_phone` varchar(255) DEFAULT NULL COMMENT '负责人电话号码',
  `station_account_id` varchar(255) DEFAULT NULL COMMENT '负责人id(有则记录)',
  `station_photo` varchar(255) DEFAULT NULL COMMENT '服务站照片',
  `is_default` tinyint(1) DEFAULT '0' COMMENT '是否默认(0:否 1:是)',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除(0:否 1:是)',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_station_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区卫生服务站';

-- ----------------------------
-- Table structure for lb_cms_health_warning
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_health_warning`;
CREATE TABLE `lb_cms_health_warning` (
  `health_warning_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `warning_info` text NOT NULL COMMENT '预警信息',
  `handle_person` varchar(128) DEFAULT NULL COMMENT '姓名',
  `handle_time` varchar(32) DEFAULT NULL COMMENT '处理时间',
  `handle_info` varchar(200) DEFAULT NULL COMMENT '处理描述',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_warning_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_holiday
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_holiday`;
CREATE TABLE `lb_cms_holiday` (
  `holiday_id` varchar(32) NOT NULL COMMENT '主键',
  `holiday_str` varchar(255) DEFAULT NULL COMMENT '节假日字符串，‘,’分割',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`holiday_id`) USING BTREE,
  UNIQUE KEY `pk_holiday_id` (`holiday_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_cms_home_bed_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_home_bed_record`;
CREATE TABLE `lb_cms_home_bed_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `bed_num` varchar(32) NOT NULL DEFAULT '' COMMENT '床位号',
  `bed_type` varchar(32) NOT NULL DEFAULT '' COMMENT '床位类型',
  `bed_area` varchar(32) NOT NULL DEFAULT '' COMMENT '床位所在区',
  `bed_street` varchar(32) NOT NULL DEFAULT '' COMMENT '床位所在街道',
  `care_for_level` varchar(32) NOT NULL DEFAULT '' COMMENT '申请时照顾需求等级',
  `nurse_for_level` varchar(32) NOT NULL DEFAULT '' COMMENT '申请时照护需求等级',
  `service_org_area` varchar(32) NOT NULL DEFAULT '' COMMENT '机构所在区',
  `service_org_street` varchar(32) NOT NULL DEFAULT '' COMMENT '机构所在街道',
  `service_org_name` varchar(128) NOT NULL DEFAULT '' COMMENT '服务机构名称',
  `enter_real_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '实际系统录入时间',
  `bed_identity` varchar(32) NOT NULL DEFAULT '' COMMENT '床位标识',
  `is_finish` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否完成改造',
  `is_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否验收合格',
  `is_use` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否投入使用',
  `is_sign_protocol` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否签订协议',
  `protocol_time` varchar(128) NOT NULL DEFAULT '' COMMENT '协议期限',
  `serve_item` varchar(128) NOT NULL DEFAULT '' COMMENT '服务项目',
  `serve_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '每月服务收费（元）',
  `serve_month` varchar(32) NOT NULL DEFAULT '' COMMENT '累计服务月数',
  `serve_time` varchar(32) NOT NULL DEFAULT '' COMMENT '累计服务数时',
  `bed_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '试点床位建床补贴（元）',
  `bed_quality_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '试点床位质保期满资助补贴（元）',
  `bed_nurse_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '试点床位护理补贴（元）',
  `bed_build_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '扩面床位建床补贴（元）',
  `bed_center_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '扩面床位中央财政专项资助补贴（元）',
  `bed_increase_subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '扩面床位护理补贴（元）',
  `is_upload_serve_data` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否上传服务数据',
  `is_upload_device_data` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否上传设备数据',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `subsidy_type` varchar(32) NOT NULL DEFAULT '' COMMENT '补助对象类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `service_org_region` varchar(255) NOT NULL DEFAULT '' COMMENT '机构所在区域信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='家庭养老床位工作记录';

-- ----------------------------
-- Table structure for lb_cms_home_care_service
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_home_care_service`;
CREATE TABLE `lb_cms_home_care_service` (
  `home_care_service_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `big_funding_category` varchar(128) NOT NULL DEFAULT '' COMMENT '资助类别（大类）',
  `small_funding_category` varchar(128) NOT NULL DEFAULT '' COMMENT '资助类别（小类）',
  `funding_start_time` varchar(64) NOT NULL DEFAULT '' COMMENT '资助开始时间',
  `funding_end_time` varchar(64) NOT NULL DEFAULT '' COMMENT '资助结束时间',
  `funding_year_month` varchar(32) NOT NULL DEFAULT '' COMMENT '资助年月',
  `funding_standards` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '资助标准（元/月）',
  `annual_funding_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '全年资助金额',
  `annual_service_frequency` int(11) NOT NULL DEFAULT '0' COMMENT '全年服务次数',
  `monthly_subsidy_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '月资助金额',
  `monthly_service_frequency` int(11) NOT NULL DEFAULT '0' COMMENT '月服务次数',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `subsidy_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '补助类型 1 特困补助 2 居家补助',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`home_care_service_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='上门照料服务';

