-- ----------------------------
-- Table structure for lb_cms_ic_card
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_ic_card`;
CREATE TABLE `lb_cms_ic_card` (
  `card_id` varchar(32) NOT NULL COMMENT '卡id',
  `card_num` varchar(128) NOT NULL COMMENT '卡号',
  `account_id` varchar(32) NOT NULL COMMENT '使用者id',
  `account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `type_desc` varchar(32) DEFAULT NULL COMMENT '其他人员类型',
  `phone_num` varchar(32) DEFAULT NULL COMMENT '手机号码',
  `account_type` tinyint(1) DEFAULT NULL COMMENT '使用者类型:0长者，1员工， 2其他',
  `open_time` bigint(20) DEFAULT '0' COMMENT '开通时间',
  `balance` decimal(10,2) DEFAULT '0.00' COMMENT '余额',
  `total_expend` decimal(10,2) DEFAULT '0.00' COMMENT '累计花费',
  `last_expend_time` bigint(20) DEFAULT '0' COMMENT '上一次消费时间',
  `status` tinyint(1) DEFAULT NULL COMMENT '状态：0已激活，1已冻结，2已注销',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`card_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='IC卡信息表';

-- ----------------------------
-- Table structure for lb_cms_ic_operate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_ic_operate_record`;
CREATE TABLE `lb_cms_ic_operate_record` (
  `operate_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `operate_type` tinyint(1) DEFAULT NULL COMMENT '操作类型：0激活，1冻结，2注销',
  `operator` varchar(128) DEFAULT NULL COMMENT '姓名',
  `card_id` varchar(32) NOT NULL COMMENT '卡id',
  `card_num` varchar(128) NOT NULL COMMENT '卡号',
  `account_id` varchar(32) NOT NULL COMMENT '使用者id',
  `account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `account_type` tinyint(1) DEFAULT NULL COMMENT '使用者类型:0长者，1员工',
  `record_time` bigint(20) DEFAULT '0' COMMENT '操作时间',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`operate_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='卡操作记录';

-- ----------------------------
-- Table structure for lb_cms_ic_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_ic_setting`;
CREATE TABLE `lb_cms_ic_setting` (
  `setting_id` varchar(32) NOT NULL COMMENT '设置id',
  `meal_name` varchar(32) DEFAULT NULL COMMENT '餐次名称',
  `start_time` bigint(20) DEFAULT NULL COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT NULL COMMENT '结束时间',
  `max_amount` decimal(32,2) DEFAULT NULL COMMENT '单次最大金额',
  `max_times` int(10) DEFAULT NULL COMMENT '餐次内最大次数',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `meal` tinyint(1) DEFAULT NULL COMMENT '餐次（0 早茶，1 早餐，2 午餐，3 下午茶，4 晚餐，5 宵夜）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_cms_import_export_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_import_export_task`;
CREATE TABLE `lb_cms_import_export_task` (
  `task_id` varchar(32) NOT NULL COMMENT '任务id',
  `task_name` varchar(64) NOT NULL DEFAULT '' COMMENT '任务名称',
  `task_code` varchar(32) NOT NULL DEFAULT '' COMMENT '任务编码',
  `task_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务类型 ',
  `task_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务状态1: 待处理2: 导出中3: 已完成4: 导出异常',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '组织id',
  `user_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `priority` int(11) NOT NULL DEFAULT '0' COMMENT '优先级(预留)',
  `task_param` text COMMENT '任务参数',
  `path_key` varchar(64) NOT NULL DEFAULT '' COMMENT '文件存储key',
  `path` text COMMENT '文件路径',
  `file_expiry_date` int(11) NOT NULL DEFAULT '30' COMMENT '文件有效期 单位（天）',
  `result` text COMMENT '处理结果',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `deal_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处理时间',
  `finish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '完成时间',
  `parent_task_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '父任务id,0为无父任务',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务是否删除 0未删除 1已删除',
  `file_is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '文件是否删除 0未删除 1已删除',
  `total` int(11) NOT NULL DEFAULT '0' COMMENT '文件总数',
  `execute_count` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务执行次数',
  `sub_task_count` int(11) NOT NULL DEFAULT '0' COMMENT '子任务数量',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='异步导入导出任务表';

-- ----------------------------
-- Table structure for lb_cms_level_subsidy_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_level_subsidy_config`;
CREATE TABLE `lb_cms_level_subsidy_config` (
  `subsidy_config_id` varchar(128) NOT NULL DEFAULT '' COMMENT '主键',
  `ability_good` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '能力完好补贴金额',
  `ability_mild` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '轻度失能补贴金额',
  `ability_moderate` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '中度失能补贴金额',
  `ability_severe` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '重度失能补贴金额',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0：否 1：是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`subsidy_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府平台能力补贴配置表';

-- ----------------------------
-- Table structure for lb_cms_literary_education_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_literary_education_record`;
CREATE TABLE `lb_cms_literary_education_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `serve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '服务时间',
  `serve_item` varchar(128) NOT NULL DEFAULT '' COMMENT '服务项目',
  `serve_times` int(10) NOT NULL DEFAULT '0' COMMENT '服务次数',
  `serve_hours` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '服务时长',
  `serve_type` varchar(128) NOT NULL DEFAULT '' COMMENT '服务类别',
  `serve_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '金额（元）',
  `type` varchar(128) NOT NULL DEFAULT '' COMMENT '类型',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0:否 1:是)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id_idx` (`care_object_id`) USING BTREE COMMENT '長者id',
  KEY `org_id_idx` (`org_id`) USING BTREE COMMENT '机构id'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='文体教育康乐服务明细';

-- ----------------------------
-- Table structure for lb_cms_maintenance_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_maintenance_record`;
CREATE TABLE `lb_cms_maintenance_record` (
  `maintenance_record_id` varchar(32) NOT NULL COMMENT '主键',
  `device_name` varchar(64) DEFAULT '' COMMENT '设备名称',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `device_position` varchar(125) DEFAULT '' COMMENT '设备位置',
  `device_product_factory` varchar(64) DEFAULT '' COMMENT '设备厂家',
  `fault_type` int(11) DEFAULT '0' COMMENT '故障类别',
  `repair_man_name` varchar(32) DEFAULT '' COMMENT '维修人员名称',
  `repair_man_phone` varchar(32) DEFAULT '' COMMENT '维修人员手机号',
  `is_repair` tinyint(1) DEFAULT '0' COMMENT '是否维修完成 0未完成 1维修完成',
  `fault_reason` varchar(255) DEFAULT '' COMMENT '故障原因',
  `check_account_id` varchar(64) DEFAULT '' COMMENT '登记人id',
  `repair_start_time` bigint(20) DEFAULT '0' COMMENT '维修开始时间',
  `repair_end_time` bigint(20) DEFAULT '0' COMMENT '维修结束时间',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `remark` text COMMENT '备注',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `check_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
  `position_type` tinyint(3) DEFAULT '1' COMMENT '位置类型  1 其他位置 2 房间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`maintenance_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='维修记录表';

-- ----------------------------
-- Table structure for lb_cms_medical_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_medical_record`;
CREATE TABLE `lb_cms_medical_record` (
  `medical_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `medical_hospital` varchar(32) DEFAULT NULL COMMENT '体检医院',
  `medical_time` bigint(20) DEFAULT NULL COMMENT '体检时间',
  `medical_result` varchar(1024) DEFAULT NULL COMMENT '体检结果',
  `medical_img` varchar(1024) DEFAULT NULL COMMENT '体检图片,多张隔开url',
  `height` varchar(32) DEFAULT NULL COMMENT '身高',
  `weight` varchar(32) DEFAULT NULL COMMENT '体重',
  `temperature` varchar(32) DEFAULT NULL COMMENT '体温',
  `blood_pressure` varchar(32) DEFAULT NULL COMMENT '血压',
  `low_pressure` varchar(32) DEFAULT NULL COMMENT '低压',
  `pulse` varchar(32) DEFAULT NULL COMMENT '脉搏',
  `blood_oxygen` varchar(32) DEFAULT NULL COMMENT '血氧',
  `fbg` varchar(32) DEFAULT NULL COMMENT '空腹血糖',
  `pbg` varchar(32) DEFAULT NULL COMMENT '餐后血糖',
  `cholesterol` varchar(32) DEFAULT NULL COMMENT '总胆固醇',
  `hdl_cholesterol` varchar(32) DEFAULT NULL COMMENT '高密度脂蛋白胆固醇',
  `triglycerides` varchar(32) DEFAULT NULL COMMENT '甘油三脂',
  `ldl_cholesterol` varchar(32) DEFAULT NULL COMMENT '低密度脂蛋白胆固醇',
  `ua` varchar(32) DEFAULT NULL COMMENT '尿酸',
  `qrs` varchar(32) DEFAULT NULL COMMENT 'qrs',
  `notation` varchar(1024) DEFAULT NULL COMMENT '全科医生批注',
  `rr` varchar(32) DEFAULT NULL COMMENT 'rr',
  `doctor_analysis` varchar(1024) DEFAULT NULL COMMENT '医生分析',
  `heart_rate` varchar(32) DEFAULT NULL COMMENT '心率',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_first` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否第一次入院录入',
  `disease` varchar(255) DEFAULT NULL COMMENT '疾病字典值，隔开',
  `breathe` varchar(32) DEFAULT NULL COMMENT '呼吸',
  `registration_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`medical_record_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_medical_recovery_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_medical_recovery_record`;
CREATE TABLE `lb_cms_medical_recovery_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `serve_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '服务时间',
  `serve_item` varchar(128) NOT NULL DEFAULT '' COMMENT '服务项目',
  `serve_times` int(10) NOT NULL DEFAULT '0' COMMENT '服务次数',
  `serve_hours` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '服务时长',
  `serve_type` varchar(128) NOT NULL DEFAULT '' COMMENT '服务类别',
  `serve_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '金额（元）',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `type` varchar(32) NOT NULL DEFAULT '' COMMENT '类别',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0:否 1:是)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id_idx` (`care_object_id`) USING BTREE COMMENT '長者id',
  KEY `org_id_idx` (`org_id`) USING BTREE COMMENT '机构id'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='医疗康复护理服务';

-- ----------------------------
-- Table structure for lb_cms_meds_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_meds_item`;
CREATE TABLE `lb_cms_meds_item` (
  `meds_item_id` varchar(32) NOT NULL COMMENT '服药药品项目表',
  `meds_msg_id` varchar(32) NOT NULL COMMENT '闹钟id',
  `alarm_number` tinyint(1) NOT NULL COMMENT '闹钟编号',
  `pill_name` varchar(100) NOT NULL COMMENT '药品名称',
  `pill_num` tinyint(1) NOT NULL COMMENT '吃药数量',
  `pill_photo` text COMMENT '药品照片',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` tinyint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` tinyint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meds_item_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='服药药品详情表';

-- ----------------------------
-- Table structure for lb_cms_meds_msg
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_meds_msg`;
CREATE TABLE `lb_cms_meds_msg` (
  `meds_msg_id` varchar(32) NOT NULL COMMENT '服药计划闹钟id',
  `meds_plan_id` varchar(32) NOT NULL COMMENT '服药计划id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `alarm_number` tinyint(1) NOT NULL COMMENT '闹钟编号(1--6)',
  `alarm_time` varchar(32) DEFAULT NULL COMMENT '闹钟报警时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除 ',
  `remak_msg` text COMMENT '闹钟备注信息',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '闹钟是否开启 0 关闭  1 开启',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meds_msg_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='服药计划闹钟信息表';

-- ----------------------------
-- Table structure for lb_cms_meds_plan
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_meds_plan`;
CREATE TABLE `lb_cms_meds_plan` (
  `meds_plan_id` varchar(32) NOT NULL COMMENT '服药计划id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '床位id',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `plaid_number` tinyint(2) NOT NULL COMMENT '锁装盒子编号',
  `alarm_work` tinyint(1) NOT NULL DEFAULT '1' COMMENT '闹钟有效期 1 始终有效 0 自定义闹钟',
  `alarm_start_time` bigint(20) DEFAULT NULL COMMENT '自定义闹钟结束时间',
  `alarm_end_time` bigint(20) DEFAULT NULL COMMENT '自定义闹钟结束时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `device_number` varchar(32) NOT NULL COMMENT '设备编号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meds_plan_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='服药计划表';

-- ----------------------------
-- Table structure for lb_cms_meds_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_meds_record`;
CREATE TABLE `lb_cms_meds_record` (
  `med_record_id` varchar(32) NOT NULL COMMENT '记录信息id',
  `device_number` varchar(32) DEFAULT NULL COMMENT '设备编号',
  `record_time` bigint(20) DEFAULT NULL COMMENT '取用药品时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0：未删除，1：已删除）',
  `take_status` tinyint(255) DEFAULT NULL COMMENT '0:等待取药 1：按时取药成功 2：等待取药超时 3：超时取药成功  4：漏取药  5：提前取药成功',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `alarm_time` bigint(20) DEFAULT NULL COMMENT '闹钟时间',
  `pill_tag` tinyint(1) DEFAULT NULL COMMENT '取药触发标识',
  `pill_record` text COMMENT '服用药品名称',
  `pill_msg` text COMMENT '服用药品详细记录（json格式）',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`med_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能药盒服药记录表';

-- ----------------------------
-- Table structure for lb_cms_message_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_message_record`;
CREATE TABLE `lb_cms_message_record` (
  `message_record_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '短信记录主键',
  `work_order_id` varchar(32) DEFAULT NULL COMMENT '关联工单Id',
  `type` tinyint(4) DEFAULT '1' COMMENT '推送类型：1 工单推送 2 充值推送 ',
  `relation` varchar(32) DEFAULT NULL COMMENT '与长者的关系',
  `receive_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `receive_id` varchar(32) NOT NULL COMMENT '收件人',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '状态 0 发送失败 1 发送成功',
  `content` varchar(255) DEFAULT NULL COMMENT '内容',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构Id',
  `is_delete` tinyint(4) DEFAULT '0' COMMENT '是否删除 0 否 1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`message_record_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=482 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_cms_msg_issue
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_msg_issue`;
CREATE TABLE `lb_cms_msg_issue` (
  `msg_issue_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `title` varchar(128) DEFAULT NULL COMMENT '标题',
  `content` text COMMENT '发布内容',
  `issue_obj` text COMMENT '发布对象',
  `issue_obj_name` text COMMENT '发布对象名称',
  `issue_time` bigint(20) DEFAULT '0' COMMENT '发布时间',
  `issue_staff` varchar(255) DEFAULT NULL COMMENT '发布人员姓名（创建公告的人）',
  `issue_staff_id` varchar(255) DEFAULT NULL COMMENT '发布人员id（创建公告的id）',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `attachment_msg` text COMMENT '附件信息',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0：不删除 1：删除',
  `msg_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1:信息发布 2：居家养老信息简介 3：机构养老信息简介 4：社区养老信息简介',
  `att_name` text COMMENT '文件名称',
  `is_release` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0：未发布 1：已发布 （只有1：信息发布有发布状态）',
  `releaser_id` varchar(255) DEFAULT NULL COMMENT '具体发布人员',
  `releaser_name` varchar(255) DEFAULT NULL COMMENT '具体发布人员姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`msg_issue_id`) USING BTREE,
  KEY `org_index` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='政府监管平台信息发布';

-- ----------------------------
-- Table structure for lb_cms_notification_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_notification_record`;
CREATE TABLE `lb_cms_notification_record` (
  `notification_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `source_id` varchar(32) DEFAULT NULL COMMENT '消息公告来源id',
  `account_id` varchar(32) DEFAULT NULL COMMENT '用户id',
  `record_type` varchar(11) DEFAULT NULL COMMENT '1：护工APP公告,2医生app公告，3网页端公告，多客户端通知类型之间用逗号拼接',
  `account_type` tinyint(3) DEFAULT NULL COMMENT '用户类型',
  `content` text COMMENT '内容(政府监管和社区居家包括附件信息)',
  `record_time` bigint(20) DEFAULT '0',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除标识0否1是',
  `org_id` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT '0',
  `update_time` bigint(20) DEFAULT '0',
  `title` varchar(128) DEFAULT NULL COMMENT '通知标题',
  `read_account` text,
  `publish_status` tinyint(3) DEFAULT '0' COMMENT '发布状态，0未发布，１已发布',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`notification_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='社区居家通知发布记录表';

-- ----------------------------
-- Table structure for lb_cms_one_touch_dial
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_one_touch_dial`;
CREATE TABLE `lb_cms_one_touch_dial` (
  `one_touch_dial_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL COMMENT '长者ID',
  `contacts` varchar(32) DEFAULT NULL COMMENT '拨打对象',
  `phone_num` varchar(11) DEFAULT NULL COMMENT '手机号码',
  `enabled` tinyint(1) DEFAULT '1' COMMENT '状态 0:禁用 1:启用',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '删除标识:0-默认，1-删除',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`one_touch_dial_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区长者一键拨打设置表';

-- ----------------------------
-- Table structure for lb_cms_order_add_deal
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_add_deal`;
CREATE TABLE `lb_cms_order_add_deal` (
  `deal_id` varchar(32) NOT NULL COMMENT '主键',
  `work_order_id` varchar(32) NOT NULL COMMENT '工单id',
  `url` text COMMENT '视频，录音，图片链接',
  `remark` varchar(100) DEFAULT NULL COMMENT '备注信息',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `update_by` varchar(30) NOT NULL COMMENT '修改人',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`deal_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单维护处理表';

-- ----------------------------
-- Table structure for lb_cms_order_buyer
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_buyer`;
CREATE TABLE `lb_cms_order_buyer` (
  `order_buyer_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `provider_id` varchar(32) DEFAULT NULL,
  `care_object_id` varchar(32) NOT NULL,
  `serve_staff_id` varchar(32) NOT NULL,
  `is_settle` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否结算',
  `json_data` json NOT NULL COMMENT 'json格式的订单',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_buyer_id`) USING BTREE,
  KEY `idx_provider_id` (`provider_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_service_staff_id` (`serve_staff_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区已完成订单表';

-- ----------------------------
-- Table structure for lb_cms_order_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_config`;
CREATE TABLE `lb_cms_order_config` (
  `order_config_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL,
  `serve_amount` decimal(10,2) DEFAULT NULL COMMENT '上门服务费用',
  `rescue_amount` decimal(10,2) DEFAULT NULL COMMENT '上门救助费用',
  `serve_rate` decimal(8,2) DEFAULT NULL COMMENT '上门服务费率',
  `rescue_rate` decimal(8,2) DEFAULT NULL COMMENT '上门救助费率',
  `use_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '付费方式 1 按单费用 2 按单费率',
  `create_time` bigint(20) DEFAULT NULL,
  `create_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `update_by` bigint(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_config_id`) USING BTREE,
  UNIQUE KEY `org_index` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务费用配置表';

-- ----------------------------
-- Table structure for lb_cms_order_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_detail`;
CREATE TABLE `lb_cms_order_detail` (
  `order_detail_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `order_id` varchar(32) NOT NULL COMMENT '订单编号',
  `sys_dict_id` int(10) DEFAULT NULL COMMENT '服务类别id',
  `serve_item_id` varchar(32) NOT NULL COMMENT '服务项目Id',
  `serve_name` varchar(32) NOT NULL COMMENT '服务名称',
  `item_detail` varchar(255) DEFAULT NULL COMMENT '套餐详情',
  `item_type` tinyint(4) DEFAULT '1' COMMENT '1 单个项目 2 套餐',
  `price` decimal(8,2) DEFAULT '0.00' COMMENT '收费单价',
  `charge_mode` tinyint(4) DEFAULT '0' COMMENT '收费方式 0 按次 1 按小时',
  `serve_num` decimal(8,1) DEFAULT '1.0' COMMENT '服务次数',
  `credits` int(10) DEFAULT NULL COMMENT '获得积分',
  `status` tinyint(4) DEFAULT '0' COMMENT '状态 0:未完成 1:已完成 2:已取消',
  `type` tinyint(4) DEFAULT '0' COMMENT '下单类型 0:原始需求 1:新增需求',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `discounted_price` decimal(8,2) DEFAULT NULL COMMENT '折后价格',
  `pay_image_path` text COMMENT '缴费截图，多个用逗号隔开',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `finish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '项目完成时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_detail_id`) USING BTREE,
  UNIQUE KEY `pk_order_detail_id` (`order_detail_id`) USING BTREE,
  KEY `idx_order_id` (`order_id`) USING BTREE,
  KEY `orgid_index` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区订单详情表';

-- ----------------------------
-- Table structure for lb_cms_order_export_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_export_record`;
CREATE TABLE `lb_cms_order_export_record` (
  `order_export_record_id` varchar(32) NOT NULL COMMENT '主键',
  `export_month` varchar(32) NOT NULL COMMENT '导出月份',
  `export_size` int(10) DEFAULT '0' COMMENT '导出条数',
  `org_id` varchar(32) NOT NULL COMMENT '社区id',
  `export_name` varchar(32) NOT NULL COMMENT '导出姓名',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `update_by` varchar(32) NOT NULL COMMENT '更新人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_export_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单导出记录表';

-- ----------------------------
-- Table structure for lb_cms_order_news
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_news`;
CREATE TABLE `lb_cms_order_news` (
  `order_news_id` varchar(32) NOT NULL DEFAULT '',
  `work_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '工单id',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '消息接收人id',
  `news_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '消息类型:默认1 待接工单提醒 2 预约服务工单提醒',
  `is_read` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已读(0 未读，1 已读)',
  `news_content` text COMMENT '消息内容',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否 删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_news_id`),
  KEY `idx_work_order_id` (`work_order_id`) USING BTREE,
  KEY `idx_account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单消息表';

-- ----------------------------
-- Table structure for lb_cms_order_process
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_process`;
CREATE TABLE `lb_cms_order_process` (
  `order_process_id` varchar(32) NOT NULL COMMENT '主键',
  `work_order_id` varchar(32) NOT NULL,
  `type` tinyint(4) DEFAULT '1' COMMENT '类型： 1 追加处理 2 工单关闭 3咨询来邦 4 服务点评',
  `content` varchar(255) DEFAULT NULL COMMENT '处理内容',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_process_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区订单处理信息记录表';

-- ----------------------------
-- Table structure for lb_cms_order_update_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_order_update_record`;
CREATE TABLE `lb_cms_order_update_record` (
  `order_update_record_id` varchar(32) NOT NULL COMMENT '主键',
  `work_order_id` varchar(32) NOT NULL COMMENT '工单id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `update_content` text COMMENT '修改内容',
  `update_reason` varchar(300) DEFAULT NULL COMMENT '修改原因',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '修改人',
  `amount_change` text COMMENT '长者消费金额以及服务人员佣金发生变化记录',
  `account_name` varchar(100) NOT NULL COMMENT '管理员姓名',
  `csr_num` varchar(30) DEFAULT NULL COMMENT '客服工号',
  `account_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '修改人员类型 1 编辑客服人员 2 待审核处客服人员 3 APP服务人员 4 管理员工单作废操作',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_update_record_id`),
  KEY `lb_cms_order_update_record_work_order_id_IDX` (`work_order_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单修改记录';

-- ----------------------------
-- Table structure for lb_cms_org_config_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_org_config_set`;
CREATE TABLE `lb_cms_org_config_set` (
  `config_set_id` varchar(32) NOT NULL COMMENT '主键',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '辅具租用是否开启 0：关闭 1：开启',
  `scale_set` tinyint(1) NOT NULL DEFAULT '0' COMMENT '辅具租用设置比例',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:否，1：是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_set_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区国家补贴规则配置表';

-- ----------------------------
-- Table structure for lb_cms_org_invited
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_org_invited`;
CREATE TABLE `lb_cms_org_invited` (
  `org_invited_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL COMMENT '邀请入驻的机构Id',
  `serve_provider_id` varchar(32) NOT NULL COMMENT '服务提供商Id或其他人员id',
  `provider_type` tinyint(4) DEFAULT '1' COMMENT '服务提供者类型：1服务提供商，2应急人员，3志愿者',
  `content` varchar(255) DEFAULT NULL COMMENT '邀请入住通知',
  `status` tinyint(4) DEFAULT '0' COMMENT '入住邀请状态 0 已邀请 1 已同意 2 已拒绝',
  `is_delete` tinyint(1) DEFAULT '0',
  `create_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_invited_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区入驻邀请记录表';

-- ----------------------------
-- Table structure for lb_cms_org_provider
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_org_provider`;
CREATE TABLE `lb_cms_org_provider` (
  `org_provider_id` varchar(32) NOT NULL,
  `serve_provider_id` varchar(32) NOT NULL COMMENT '服务提供者Id：通过类型判断',
  `provider_type` tinyint(4) DEFAULT '0' COMMENT '服务提供者类型：1服务提供商，2应急人员，3志愿者',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_origin` tinyint(1) DEFAULT '0' COMMENT '是否是自身机构 0 否 1 是',
  `org_id` varchar(32) NOT NULL,
  `create_time` bigint(20) DEFAULT NULL,
  `create_by` varchar(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_provider_id`) USING BTREE,
  KEY `serve_provider_id_IDX` (`serve_provider_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务人员及服务商关联表';

-- ----------------------------
-- Table structure for lb_cms_org_region_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_org_region_config`;
CREATE TABLE `lb_cms_org_region_config` (
  `org_region_config_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL,
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `address_info` varchar(255) DEFAULT NULL,
  `address` varchar(255) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT NULL,
  `create_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `update_by` bigint(32) DEFAULT NULL,
  `care_object_type` tinyint(1) DEFAULT NULL COMMENT '长者类型 1：机构长者 2：居家长者',
  `view_style` tinyint(1) DEFAULT '0' COMMENT '展示风格 0:静谧蓝 1:清爽白 2:亮彩白',
  `view_title` varchar(32) DEFAULT NULL COMMENT '地图一览表标题',
  `center` varchar(255) DEFAULT NULL COMMENT '位置',
  `zoom` double(8,2) DEFAULT NULL,
  `view_title_one` varchar(255) DEFAULT NULL COMMENT '信息一览表1标题',
  `view_title_two` varchar(255) DEFAULT NULL COMMENT '信息一览表2标题',
  `to_do_item_settings` varchar(255) NOT NULL DEFAULT '' COMMENT '待办事项设置',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_region_config_id`) USING BTREE,
  UNIQUE KEY `org_index` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区统计区域配置表';

-- ----------------------------
-- Table structure for lb_cms_photo_album
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_photo_album`;
CREATE TABLE `lb_cms_photo_album` (
  `photo_album_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `name` varchar(255) NOT NULL COMMENT '相册名称',
  `url` text COMMENT '相片url',
  `parent_id` varchar(32) DEFAULT NULL COMMENT '父相册id，空为相册，不空为照片',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`photo_album_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='相册管理表';

-- ----------------------------
-- Table structure for lb_cms_point_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_point_setting`;
CREATE TABLE `lb_cms_point_setting` (
  `setting_id` varchar(32) NOT NULL COMMENT '主键',
  `is_vip` tinyint(1) NOT NULL COMMENT '是否会员',
  `types` tinyint(1) NOT NULL COMMENT '类型：0-充值, 1-消费, 2-签到',
  `points` int(3) NOT NULL DEFAULT '0' COMMENT '获得积分',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='积分设置表';

-- ----------------------------
-- Table structure for lb_cms_privacy_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_privacy_set`;
CREATE TABLE `lb_cms_privacy_set` (
  `privacy_set_id` varchar(32) NOT NULL COMMENT '主键',
  `is_privacy_phone` tinyint(1) NOT NULL DEFAULT '0' COMMENT '手机号码、固话隐私开关 0:已开启 1：未开启',
  `is_privacy_identity` tinyint(1) NOT NULL DEFAULT '0' COMMENT '手机号码、固话隐私开关  0:已开启 1：未开启',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '0:否，1：是',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `org_id` varchar(20) DEFAULT NULL COMMENT '机构id',
  `account_id` varchar(32) DEFAULT NULL COMMENT '账户id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`privacy_set_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='隐私设置表';

-- ----------------------------
-- Table structure for lb_cms_public_activity
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_public_activity`;
CREATE TABLE `lb_cms_public_activity` (
  `activity_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT NULL COMMENT '活动名称',
  `synopsis` varchar(128) DEFAULT NULL COMMENT '活动简介',
  `photo` text COMMENT '活动图片',
  `date_type` tinyint(1) DEFAULT '1' COMMENT '活动日期类型 1.指定日期 2.长期活动',
  `start_date` bigint(20) DEFAULT '0' COMMENT '活动开始日期',
  `end_date` bigint(20) DEFAULT '0' COMMENT '活动结束日期',
  `start_time` int(11) DEFAULT '0' COMMENT '活动开始时间',
  `end_time` int(11) DEFAULT '0' COMMENT '活动结束时间',
  `enroll_type` tinyint(1) DEFAULT '1' COMMENT '报名模式   1.审批模式  2.人数模式',
  `field_type` tinyint(1) DEFAULT '1' COMMENT '场地限制   0 不指定场地  1 指定场地',
  `field_name` varchar(32) DEFAULT NULL COMMENT '场地名称',
  `capacity` int(11) DEFAULT NULL COMMENT '每日人数上限',
  `enroll_cost` decimal(10,2) DEFAULT NULL COMMENT '报名费用',
  `apply_time` varchar(32) DEFAULT NULL COMMENT '发布时间',
  `apply_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `apply_account_id` varchar(64) DEFAULT NULL COMMENT '发布人id',
  `activity_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '活动类型（1 公共活动  2 公共课程)',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `status` tinyint(1) DEFAULT '1' COMMENT '活动状态 1 待审核 2已通过 3已驳回 4 进行中 5 已结束',
  `field_id` varchar(32) DEFAULT NULL COMMENT '场地id',
  `is_summary` tinyint(1) NOT NULL DEFAULT '1' COMMENT '报告是否总结（1：未总结 2：已总结）',
  `enroll_count` tinyint(1) DEFAULT NULL COMMENT '活动实际参加人数',
  `activity_cost` decimal(10,2) DEFAULT NULL COMMENT '活动实际花费',
  `activity_summary` varchar(255) DEFAULT NULL COMMENT '活动小结',
  `exist_question` varchar(255) DEFAULT NULL COMMENT '活动存在问题',
  `improve_way` varchar(255) DEFAULT NULL COMMENT '活动的改进措施',
  `activity_organizer_id` varchar(32) DEFAULT NULL COMMENT '活动组织者id',
  `activity_organizer` varchar(128) DEFAULT NULL COMMENT '姓名',
  `activity_organizer_phone` varchar(11) DEFAULT NULL COMMENT '活动组织者电话号码',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`activity_id`),
  KEY `applyAccountId` (`apply_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='公共活动表';

-- ----------------------------
-- Table structure for lb_cms_public_activity_care_object_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_public_activity_care_object_record`;
CREATE TABLE `lb_cms_public_activity_care_object_record` (
  `record_id` varchar(32) NOT NULL COMMENT '报名记录id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `phone` varchar(11) DEFAULT NULL COMMENT '电话号码',
  `address` varchar(255) DEFAULT NULL COMMENT '地址',
  `age` int(4) DEFAULT '0' COMMENT '年龄',
  `gender` varchar(32) DEFAULT NULL COMMENT '性别',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `activity_id` varchar(32) DEFAULT NULL COMMENT '活动id',
  `status` tinyint(1) DEFAULT '0' COMMENT '报名状态 0未审批,1已审批 2 被驳回',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `enroll_date` bigint(20) DEFAULT '0' COMMENT '参加日期',
  `is_evaluate` tinyint(1) DEFAULT '0' COMMENT '是否已评价  0未评价, 1 已评价',
  `is_enroll` tinyint(1) DEFAULT '0' COMMENT '是否已参加，0未参加，1已参加',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='公共活动报名记录表';

-- ----------------------------
-- Table structure for lb_cms_public_activity_evaluate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_public_activity_evaluate_record`;
CREATE TABLE `lb_cms_public_activity_evaluate_record` (
  `evaluate_id` varchar(32) NOT NULL COMMENT '评价记录id',
  `activity_id` varchar(32) NOT NULL COMMENT '报名记录id',
  `evaluate_message` varchar(255) DEFAULT NULL COMMENT '评价内容',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `evaluate_level` tinyint(1) DEFAULT NULL COMMENT '评价等级',
  `record_id` varchar(32) DEFAULT NULL COMMENT '报名记录id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `care_object_name` varchar(64) DEFAULT NULL COMMENT '长者姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`evaluate_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='公共活动评价表';

-- ----------------------------
-- Table structure for lb_cms_public_activity_field
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_public_activity_field`;
CREATE TABLE `lb_cms_public_activity_field` (
  `field_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT NULL COMMENT '场地名称',
  `capacity` int(11) DEFAULT NULL COMMENT '场地容量',
  `charge_account_id` varchar(64) DEFAULT NULL COMMENT '负责人id',
  `charge_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `phone` varchar(32) DEFAULT NULL COMMENT '负责人手机号',
  `field_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '场地类型（1 公共活动场地  2 公共课程场地',
  `remarks` text COMMENT '备注',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`field_id`),
  KEY `chargeAccountId` (`charge_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='公共活动场地表';

-- ----------------------------
-- Table structure for lb_cms_receiver_address
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_receiver_address`;
CREATE TABLE `lb_cms_receiver_address` (
  `receiver_address_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL COMMENT '长者ID',
  `receiver_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `receiver_address` varchar(255) NOT NULL COMMENT '收货人详细地址',
  `receiver_region` varchar(150) NOT NULL COMMENT '收货人地区（完整描述）',
  `phone_num` varchar(11) NOT NULL COMMENT '手机号码',
  `province` int(9) NOT NULL DEFAULT '0' COMMENT '省份',
  `city` int(9) DEFAULT '0' COMMENT '城市',
  `prefecture` int(9) DEFAULT '0' COMMENT '区、县',
  `town` int(9) DEFAULT '0' COMMENT '城镇',
  `default_address` tinyint(1) NOT NULL DEFAULT '0' COMMENT '默认地址(0:否,1:是)',
  `longitude` varchar(32) DEFAULT NULL COMMENT '经度',
  `latitude` varchar(32) DEFAULT NULL COMMENT '纬度',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '删除标识:0-默认，1-删除',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `coordsys` tinyint(1) DEFAULT '2' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`receiver_address_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区长者收货地址表';

-- ----------------------------
-- Table structure for lb_cms_recharge_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_recharge_record`;
CREATE TABLE `lb_cms_recharge_record` (
  `recharge_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `recharge_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '充值方式（0 现金，1　代金券）',
  `recharge_amount` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '充值金额',
  `consumption_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '消费金额',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '有效期开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '有效期结束时间',
  `recharge_source` varchar(128) NOT NULL DEFAULT '' COMMENT '充值来源',
  `recharge_remark` varchar(128) DEFAULT NULL COMMENT '充值备注',
  `is_expire` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否过期 0 否 1 是',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `rechange_way` char(1) DEFAULT NULL COMMENT '1-现场充值 2-线上充值',
  `work_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '工单id（该充值记录只能用于当前工单的结算）',
  `is_cancel` tinyint(1) DEFAULT '0' COMMENT '是否作废 0:否 1:是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recharge_record_id`) USING BTREE,
  UNIQUE KEY `pk_recharge_record_id` (`recharge_record_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区长者充值记录表';

-- ----------------------------
-- Table structure for lb_cms_recharge_record_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_recharge_record_stat`;
CREATE TABLE `lb_cms_recharge_record_stat` (
  `recharge_record_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `stat_year` varchar(16) DEFAULT NULL COMMENT '统计年份',
  `recharge_way` tinyint(1) DEFAULT NULL COMMENT '充值方式',
  `stat_month` varchar(16) DEFAULT NULL COMMENT '统计月份',
  `total_price` decimal(10,2) DEFAULT NULL COMMENT '充值总金额',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recharge_record_stat_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='充值记录统计报表';

-- ----------------------------
-- Table structure for lb_cms_renewal_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_renewal_record`;
CREATE TABLE `lb_cms_renewal_record` (
  `renewal_record_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `amount` decimal(8,2) NOT NULL COMMENT '续费金额',
  `expire_time` bigint(20) DEFAULT NULL COMMENT '续费后过期时间',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '支付类型：1 支付宝 2 微信',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '续费订单状态：1 未支付 2 支付成功 3 支付失败 4 退款',
  `old_expire_time` bigint(20) DEFAULT NULL COMMENT '续费前过期时间',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `update_by` varchar(32) NOT NULL COMMENT '更新人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`renewal_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区加盟续费记录表';

-- ----------------------------
-- Table structure for lb_cms_self_care_ability
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_self_care_ability`;
CREATE TABLE `lb_cms_self_care_ability` (
  `self_assessment_record_id` varchar(32) NOT NULL COMMENT '自理能力评估id主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `assessment_number` varchar(32) DEFAULT NULL COMMENT '评估编号',
  `assessment_reason` varchar(32) DEFAULT NULL COMMENT '评估原因',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估基准时间',
  `social_security_card` varchar(32) DEFAULT NULL COMMENT '社保卡号',
  `pay_type` varchar(32) DEFAULT NULL COMMENT '医疗费用支付方式',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `eating_ability_type` tinyint(1) DEFAULT NULL COMMENT '能力评估（进餐）',
  `wash_ability_type` tinyint(1) DEFAULT NULL COMMENT '能力评估（梳洗）',
  `dress_ability_type` tinyint(1) DEFAULT NULL COMMENT '能力评估（穿衣）',
  `toilet_ability_type` tinyint(1) DEFAULT NULL COMMENT '能力评估（如厕）',
  `activity_ability_type` tinyint(1) DEFAULT NULL COMMENT '能力评估（活动）',
  `assessment_score` tinyint(1) DEFAULT NULL COMMENT '最终评分',
  `assessment_level` varchar(32) DEFAULT NULL COMMENT '评估等级',
  `create_time` bigint(20) DEFAULT NULL COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`self_assessment_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='自理能力评估表';

-- ----------------------------
-- Table structure for lb_cms_send_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_send_order`;
CREATE TABLE `lb_cms_send_order` (
  `send_order_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `order_id` varchar(32) NOT NULL COMMENT '工单编号',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `provider_type` tinyint(4) DEFAULT NULL COMMENT '服务提供者类型：1服务提供商，2应急人员，3志愿者',
  `serve_provider_id` varchar(32) NOT NULL COMMENT '派单对象Id:有可能是服务提供商Id，也有可能是其他人员id',
  `book_order_time` bigint(20) DEFAULT NULL COMMENT '预约时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '订单状态 0:等待接单 1:已关闭 2 已接单',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`send_order_id`) USING BTREE,
  UNIQUE KEY `pk_send_order_id` (`send_order_id`) USING BTREE,
  KEY `idx_send_user_id` (`serve_provider_id`) USING BTREE,
  KEY `idx_order_id` (`order_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1574138 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区派单表';

-- ----------------------------
-- Table structure for lb_cms_serve_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_area`;
CREATE TABLE `lb_cms_serve_area` (
  `serve_area_id` varchar(32) NOT NULL COMMENT '服务区域主键',
  `region_id` varchar(255) NOT NULL COMMENT '区域id',
  `region` varchar(255) NOT NULL COMMENT '区域地址',
  `province_id` int(10) DEFAULT NULL COMMENT '省级id',
  `city_id` int(10) DEFAULT NULL COMMENT '市级id',
  `area_id` int(10) DEFAULT NULL COMMENT '区级id',
  `street_id` int(10) DEFAULT NULL COMMENT '街道id',
  `address_detail` varchar(255) DEFAULT NULL COMMENT '详细地址',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL,
  `create_by` varchar(32) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `update_by` varchar(32) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `serve_team_id` varchar(32) DEFAULT NULL COMMENT '服务商id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区服务区域表';

-- ----------------------------
-- Table structure for lb_cms_serve_category_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_category_stat`;
CREATE TABLE `lb_cms_serve_category_stat` (
  `serve_category_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `stat_year` varchar(16) NOT NULL COMMENT '统计年份',
  `stat_month` varchar(16) NOT NULL COMMENT '统计月份',
  `sys_dict_id` int(10) NOT NULL COMMENT '服务类别id',
  `total_price` decimal(12,2) NOT NULL COMMENT '服务总金额',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_category_stat_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_cms_serve_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_item`;
CREATE TABLE `lb_cms_serve_item` (
  `serve_item_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '项目类型：1 单个项目 2 套餐',
  `serve_name` varchar(32) NOT NULL COMMENT '服务名称',
  `item_detail` varchar(255) DEFAULT NULL COMMENT '套餐详情',
  `item_ids` varchar(1024) DEFAULT NULL COMMENT '服务项目内容  '',''分割',
  `sys_dict_id` int(10) NOT NULL COMMENT '服务类别 字典表中的KEY',
  `price` decimal(8,2) DEFAULT '0.00' COMMENT '收费单价',
  `charge_mode` tinyint(4) DEFAULT '0' COMMENT '计费方式 0:按次 1 按小时',
  `serve_credits` int(10) DEFAULT '0' COMMENT '服务积分',
  `is_volunteer` tinyint(1) DEFAULT '0' COMMENT '志愿者是否扣费',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_by` varchar(32) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `update_by` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `object_content` varchar(500) DEFAULT NULL COMMENT '服务内容及标准',
  `discounted_price` decimal(8,2) DEFAULT NULL COMMENT '折后价格',
  `is_charge` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否扣除长者费用 0 否， 1 是',
  `is_delivery` tinyint(1) DEFAULT NULL COMMENT '平台配送服务标记位',
  `root_serve_item_id` varchar(32) DEFAULT NULL COMMENT '父类服务项目id',
  `use_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '付费方式 1 按单费用 2 按单费率',
  `serve_amount` decimal(8,2) DEFAULT NULL COMMENT '上门服务费用',
  `serve_rate` decimal(8,2) DEFAULT NULL COMMENT '上门服务费率',
  `is_visit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否需要回访 0 不用 1 需要回访',
  `order_num` int(10) NOT NULL DEFAULT '0' COMMENT '排列序号',
  `serve_icon` varchar(300) DEFAULT NULL COMMENT '服务图标',
  `is_check` tinyint(1) DEFAULT '0' COMMENT '是否查看长者用药禁忌 0 否 1 是',
  `is_grounding` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否上架 0 下架 1 上架',
  `serve_overview` text COMMENT '服务概述',
  `serve_details_path` text COMMENT '服务详情图片 最多9个',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_item_id`) USING BTREE,
  UNIQUE KEY `pk_serve_item_id` (`serve_item_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务项目表';

-- ----------------------------
-- Table structure for lb_cms_serve_item_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_item_stat`;
CREATE TABLE `lb_cms_serve_item_stat` (
  `serve_item_stat_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `stat_year` varchar(16) NOT NULL COMMENT '统计年份',
  `stat_month` varchar(16) NOT NULL COMMENT '统计月份',
  `serve_item_id` varchar(32) NOT NULL COMMENT '服务项目id',
  `serve_count` int(10) NOT NULL COMMENT '服务次数',
  `total_price` decimal(12,2) NOT NULL COMMENT '服务总金额',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_item_stat_id`),
  KEY `serve_item_id_index` (`serve_item_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区扩展服务项目统计表';

-- ----------------------------
-- Table structure for lb_cms_serve_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_object`;
CREATE TABLE `lb_cms_serve_object` (
  `serve_object_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `serve_staff_id` varchar(32) NOT NULL COMMENT '用户id',
  `care_object_id` varchar(32) NOT NULL COMMENT '看护对象Id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_object_id`) USING BTREE,
  UNIQUE KEY `uk_union_index` (`care_object_id`,`serve_staff_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_serve_staff_id` (`serve_staff_id`) USING BTREE,
  KEY `orgid_index` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务长者关联表';

-- ----------------------------
-- Table structure for lb_cms_serve_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_order`;
CREATE TABLE `lb_cms_serve_order` (
  `order_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `description` varchar(2048) DEFAULT '' COMMENT '描述',
  `serve_type` tinyint(4) DEFAULT '0' COMMENT '订单类型 1:上门救助 2:上门服务 3:上门关怀',
  `provider_type` tinyint(4) DEFAULT '0' COMMENT '服务者类型 1:家政公司 2:应急人员 3:志愿者',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '订单长者Id',
  `work_order_id` varchar(32) NOT NULL COMMENT '订单的工单Id',
  `serve_team_id` varchar(32) DEFAULT NULL COMMENT '服务商id',
  `serve_staff_id` varchar(32) DEFAULT NULL COMMENT '接单人id',
  `audio_url` varchar(2048) DEFAULT NULL COMMENT '录音记录',
  `start_picture_url` text COMMENT '服务开始前图片',
  `picture_url` text COMMENT '拍照记录',
  `is_charge` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否扣费 0 否 1 是',
  `close_reason` varchar(255) DEFAULT NULL COMMENT '订单关闭原因',
  `close_note` varchar(255) DEFAULT NULL COMMENT '订单关闭备注',
  `evaluation` varchar(255) DEFAULT NULL COMMENT '服务评价',
  `evaluate_time` bigint(20) DEFAULT NULL COMMENT '服务评价时间',
  `service_eval` tinyint(4) DEFAULT '0' COMMENT '综合评分 1-5',
  `consume_result` varchar(255) DEFAULT NULL COMMENT '扣费情况',
  `order_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '订单状态 1:已下单未接单 2:已接单未完成 3:已完成 4:取消单 5:异常单（待补充）',
  `org_order_voucher` decimal(8,2) DEFAULT '0.00' COMMENT '机构代金券所得',
  `org_order_cash` decimal(8,2) DEFAULT '0.00' COMMENT '机构现金所得',
  `org_order_vip_card` decimal(8,2) DEFAULT '0.00' COMMENT '机构会员卡金额所得',
  `org_order_one_card` decimal(8,2) DEFAULT '0.00' COMMENT '机构一卡通金额所得',
  `pro_order_voucher` decimal(8,2) DEFAULT '0.00' COMMENT '服务商代金券所得',
  `pro_order_cash` decimal(8,2) DEFAULT '0.00' COMMENT '服务商现金所得',
  `pro_order_vip_card` decimal(8,2) DEFAULT '0.00' COMMENT '服务商会员卡金额所得',
  `pro_order_one_card` decimal(8,2) DEFAULT '0.00' COMMENT '服务商一卡通金额所得',
  `order_cash` decimal(8,2) DEFAULT '0.00' COMMENT '现金所得',
  `order_credits` int(10) DEFAULT '0' COMMENT '积分所得',
  `order_voucher` decimal(8,2) DEFAULT '0.00' COMMENT '代金券所得',
  `order_vip_card` decimal(8,2) DEFAULT '0.00' COMMENT '会员卡金额所得',
  `order_settle_price` decimal(8,2) DEFAULT '0.00' COMMENT '订单实际完成总金额',
  `order_one_card` decimal(8,2) DEFAULT '0.00' COMMENT '一卡通金额所得',
  `settle_voucher` decimal(8,2) DEFAULT '0.00' COMMENT '订单老人实际扣除的代金券',
  `settle_cash` decimal(8,2) DEFAULT '0.00' COMMENT '订单老人实际扣除的现金',
  `settle_vip_card` decimal(8,2) DEFAULT '0.00' COMMENT '订单老人实际扣除的会员卡金额',
  `settle_one_card` decimal(8,2) DEFAULT '0.00' COMMENT '订单老人实际扣除的一卡通金额',
  `settle_time` bigint(20) DEFAULT NULL COMMENT '扣费时间',
  `handle_type` tinyint(4) DEFAULT '0' COMMENT '结算类型： 0 助老APP结算 1 代理服务扣费',
  `settle_status` tinyint(4) DEFAULT '0' COMMENT '扣费情况：0 未扣费 1 正常扣费 2 余额不足',
  `serve_plan_time` bigint(20) DEFAULT NULL COMMENT '服务安排时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `cancel_reservation_reason` varchar(300) DEFAULT NULL COMMENT '取消预约原因',
  `before_shoot` tinyint(1) DEFAULT NULL COMMENT '服务前拍摄的是图片还是视频',
  `before_first_photo` text COMMENT '服务前视频第一帧图片',
  `before_shoot_url` text COMMENT '服务前图片或者视频链接',
  `after_shoot` tinyint(1) DEFAULT NULL COMMENT '服务后拍摄的是图片还是视频',
  `after_first_photo` text COMMENT '服务后视频第一帧图片',
  `after_shoot_url` text COMMENT '服务后图片或者视频链接',
  `pay_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单支付方式：见枚举类 EConsumptionPatternEnum',
  `serve_item_price` decimal(8,2) DEFAULT NULL COMMENT '工单结算实际应该结算的金额',
  `customize_serve_content` text COMMENT '服务工单自定义服务内容',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`) USING BTREE,
  UNIQUE KEY `pk_order_id` (`order_id`) USING BTREE,
  UNIQUE KEY `uk_work_index` (`work_order_id`) USING BTREE,
  KEY `idx_provider_id` (`serve_team_id`) USING BTREE,
  KEY `order_status_index` (`order_status`) USING BTREE,
  KEY `idx_serve_staff_id` (`serve_staff_id`) USING BTREE,
  KEY `id_care_object_id` (`care_object_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区订单表';

-- ----------------------------
-- Table structure for lb_cms_serve_plan
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_plan`;
CREATE TABLE `lb_cms_serve_plan` (
  `serve_plan_id` varchar(32) NOT NULL COMMENT '日程计划主键',
  `work_order_id` varchar(32) NOT NULL COMMENT '工单id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `serve_staff_id` varchar(32) NOT NULL COMMENT '服务人员id',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '订单状态 0:等待接单 1 已接单',
  `serve_time` bigint(20) NOT NULL COMMENT '上门服务时间',
  `serve_time_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '上门服务时间段 1 上午 2 下午',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `serve_time_str` varchar(32) NOT NULL COMMENT '上门服务时间字符格式',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_plan_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='服务人员日程计划表';

-- ----------------------------
-- Table structure for lb_cms_serve_staff
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_staff`;
CREATE TABLE `lb_cms_serve_staff` (
  `serve_staff_id` varchar(32) NOT NULL COMMENT '主键',
  `serve_team_id` varchar(32) DEFAULT NULL COMMENT '服务团队Id，服务人员关联',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `identity` varchar(32) NOT NULL COMMENT '身份证号码',
  `name` varchar(128) DEFAULT NULL,
  `gender` tinyint(1) DEFAULT '0' COMMENT '性别：1 男，2 女',
  `age` tinyint(4) DEFAULT '0' COMMENT '年龄',
  `serve_area_id` varchar(32) DEFAULT NULL COMMENT '服务区域id',
  `profile_photo` varchar(255) DEFAULT '' COMMENT '用户头像',
  `phone_num` char(11) DEFAULT '' COMMENT '手机号',
  `present_address_id` varchar(255) DEFAULT NULL COMMENT '居住地址id',
  `present_address` varchar(255) DEFAULT NULL COMMENT '居住地址',
  `address_detail` varchar(255) DEFAULT NULL COMMENT '详细地址',
  `staff_type` tinyint(4) DEFAULT '1' COMMENT '用户类型 1:服务人员 2:应急人员 3:志愿者 4:个体服务人员',
  `commission_rate` decimal(5,2) DEFAULT '0.00' COMMENT '佣金比例:针对服务人员',
  `serve_expire_time` bigint(20) DEFAULT NULL COMMENT '服务到期时间',
  `serve_address_id` varchar(255) DEFAULT NULL COMMENT '服务地址Id:针对服务人员',
  `serve_address` varchar(255) DEFAULT NULL COMMENT '服务地址:针对服务人员',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `is_dimission` tinyint(1) DEFAULT NULL COMMENT '服务人员离职状态：0 在职，1 离职',
  `last_synch_time` bigint(20) DEFAULT '0' COMMENT '服务人员同步到芜湖智慧养老 上次同步时间',
  `is_upload_today` tinyint(1) DEFAULT '0' COMMENT '南陵今日是否上传',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_staff_id`) USING BTREE,
  UNIQUE KEY `pk_serve_user_id` (`serve_staff_id`) USING BTREE,
  KEY `staff_type_index` (`staff_type`) USING BTREE,
  KEY `org_id_index` (`org_id`),
  KEY `serve_team_id_IDX` (`serve_team_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务人员表';

-- ----------------------------
-- Table structure for lb_cms_serve_team
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_serve_team`;
CREATE TABLE `lb_cms_serve_team` (
  `serve_team_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `provider_attr` tinyint(4) DEFAULT '0' COMMENT '商家性质：0 国有，1 私有',
  `principal` varchar(16) DEFAULT '' COMMENT '主要负责人',
  `principal_phone` char(11) DEFAULT '' COMMENT '负责人手机号',
  `address_id` varchar(128) DEFAULT NULL COMMENT '商家地址id',
  `address` varchar(128) DEFAULT NULL COMMENT '商家地址',
  `address_detail` varchar(100) DEFAULT NULL COMMENT '详细地址',
  `status` tinyint(1) DEFAULT '0' COMMENT '服务状态：0 正常 ，1 停止',
  `start_datetime` varchar(32) DEFAULT NULL COMMENT '服务开始时间',
  `end_datetime` varchar(32) DEFAULT NULL COMMENT '服务结束时间',
  `is_week` tinyint(1) DEFAULT '0' COMMENT '周末是否提供服务 0:否 1:是',
  `is_holiday` tinyint(1) DEFAULT '0' COMMENT '节假日是否提供服务 0:否 1:是',
  `serve_area_id` varchar(128) DEFAULT NULL COMMENT '服务区域id',
  `serve_area` varchar(128) DEFAULT '' COMMENT '服务区域',
  `serve_type` varchar(32) DEFAULT '0' COMMENT '服务范围 1:服务类 2:商品类 3:餐饮',
  `lng` varchar(32) DEFAULT NULL COMMENT '纬度',
  `lat` varchar(32) DEFAULT NULL COMMENT '经度',
  `serve_phone` char(18) DEFAULT '' COMMENT '商家联系电话',
  `is_certification` tinyint(1) DEFAULT '0' COMMENT '是否认证 0:未认证 1:已认证',
  `serve_level` tinyint(4) DEFAULT '0' COMMENT '服务评级',
  `business_license` char(32) DEFAULT '' COMMENT '营业执照',
  `picture_url` varchar(2048) DEFAULT '' COMMENT '商家图片',
  `description` varchar(100) DEFAULT '' COMMENT '商家描述',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `team_kind` tinyint(1) NOT NULL DEFAULT '0',
  `location` varchar(300) DEFAULT NULL COMMENT '所在位置',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `last_synch_time` bigint(20) DEFAULT '0' COMMENT '服务商同步到芜湖智慧养老 上次同步时间',
  `is_upload_today` tinyint(1) DEFAULT '0' COMMENT '南陵今日是否上传',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_team_id`) USING BTREE,
  UNIQUE KEY `pk_service_provider_id` (`serve_team_id`) USING BTREE,
  KEY `uk_principal_phone` (`principal_phone`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='服务提供商表';

-- ----------------------------
-- Table structure for lb_cms_service_evaluation
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_service_evaluation`;
CREATE TABLE `lb_cms_service_evaluation` (
  `evaluation_id` varchar(30) NOT NULL COMMENT '主键',
  `service_eval` tinyint(1) NOT NULL COMMENT '服务评分 1-5',
  `evaluation` varchar(255) NOT NULL COMMENT '服务评价',
  `org_id` varchar(30) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '服务评价时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新时间',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '评价人类型 1 客服评价，2 长者评价',
  `order_id` varchar(32) NOT NULL COMMENT '服务工单id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`evaluation_id`),
  KEY `lb_cms_service_evaluation_org_id_IDX` (`org_id`) USING BTREE,
  KEY `lb_cms_service_evaluation_order_id_IDX` (`order_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单服务评价表';

-- ----------------------------
-- Table structure for lb_cms_settlement_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_settlement_record`;
CREATE TABLE `lb_cms_settlement_record` (
  `settlement_record_id` varchar(32) NOT NULL COMMENT '主键',
  `settlement_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '结算对象主键',
  `settlement_object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '结算对象类型 1:服务商 2:应急人员 3:志愿者',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `settlement_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '结算类型 0  代金券 1 现金 2 混合结算',
  `settlement_time` varchar(32) NOT NULL DEFAULT '0' COMMENT '结算月份',
  `total_serve_credits` int(10) NOT NULL DEFAULT '0' COMMENT '服务总积分',
  `surplus_serve_credits` int(10) NOT NULL DEFAULT '0' COMMENT '剩余服务积分',
  `for_settlement_serve_credits` int(10) NOT NULL DEFAULT '0' COMMENT '未结算服务积分',
  `settlement_serve_credits` int(10) NOT NULL DEFAULT '0' COMMENT '已结算服务积分',
  `this_settlement_serve_credits` int(10) NOT NULL DEFAULT '0' COMMENT '本次结算服务积分',
  `serve_order` int(10) NOT NULL DEFAULT '0' COMMENT '服务工单数',
  `total_cash_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '现金总金额',
  `total_cash_coupon_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '代金券总金额',
  `settlement_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已结算金额',
  `surplus_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '剩余结算金额',
  `this_settlement_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '本次结算金额',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`settlement_record_id`) USING BTREE,
  UNIQUE KEY `pk_settlement_record_id` (`settlement_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区费用结算记录表';

-- ----------------------------
-- Table structure for lb_cms_shopping_cart
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_shopping_cart`;
CREATE TABLE `lb_cms_shopping_cart` (
  `shopping_cart_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '店铺主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `goods_id` varchar(32) DEFAULT '' COMMENT '商品主键',
  `cart_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '购物车类型（1-点餐购物车，2-超市购物车）',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '商品名称',
  `num` int(11) NOT NULL DEFAULT '1' COMMENT '购买数量',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`shopping_cart_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `shop_id` (`shop_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='购物车列表';

-- ----------------------------
-- Table structure for lb_cms_sign
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_sign`;
CREATE TABLE `lb_cms_sign` (
  `sigin_id` varchar(32) NOT NULL COMMENT '签字表主键',
  `apply_id` varchar(32) NOT NULL DEFAULT '' COMMENT '申请主键',
  `pic_url` text COMMENT '签字图片地址',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sigin_id`),
  KEY `sigin_id` (`sigin_id`),
  KEY `apply_id` (`apply_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='二维码签字';

-- ----------------------------
-- Table structure for lb_cms_sign_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_sign_record`;
CREATE TABLE `lb_cms_sign_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(64) DEFAULT '' COMMENT '人员姓名',
  `account_id` varchar(64) DEFAULT '' COMMENT '签到人id',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除(0未删除,1删除)',
  `sign_time` bigint(20) DEFAULT '0' COMMENT '签到时间',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='签到记录表';

-- ----------------------------
-- Table structure for lb_cms_sms_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_sms_config`;
CREATE TABLE `lb_cms_sms_config` (
  `sms_config_id` varchar(32) NOT NULL COMMENT '主键',
  `region` varchar(128) DEFAULT NULL COMMENT '区域id',
  `access_key_id` varchar(255) NOT NULL COMMENT '验签id',
  `access_key_secret` varchar(255) NOT NULL COMMENT '验签秘钥',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `org_id` varchar(20) DEFAULT NULL COMMENT '机构id',
  `sign_name` varchar(255) NOT NULL COMMENT '签名',
  `template_code` varchar(32) NOT NULL COMMENT '模板code',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1:删除 0:不删除',
  `sms_type` tinyint(1) DEFAULT NULL COMMENT '1:验证码,2:充值短信',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sms_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区私有化短信配置';

-- ----------------------------
-- Table structure for lb_cms_staff_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_staff_balance`;
CREATE TABLE `lb_cms_staff_balance` (
  `serve_staff_id` varchar(32) NOT NULL COMMENT '用户Id，服务商id',
  `staff_type` tinyint(4) DEFAULT '0' COMMENT '0 服务提供商 1 服务人员 2 应急人员 3 志愿者',
  `staff_cash_balance` decimal(12,2) DEFAULT '0.00' COMMENT '用户现金余额',
  `staff_credits_balance` int(10) DEFAULT '0' COMMENT '用户积分余额',
  `staff_coupon_balance` decimal(12,2) DEFAULT '0.00' COMMENT '代金券余额',
  `last_trade_time` datetime DEFAULT NULL COMMENT '最后交易时间',
  `last_order_id` varchar(32) DEFAULT NULL COMMENT '最后一笔订单id',
  `serve_total_cash` decimal(12,2) DEFAULT '0.00' COMMENT '累计服务总金额',
  `serve_total_time` bigint(20) DEFAULT '0' COMMENT '累计服务总时间',
  `order_cash_total` decimal(12,2) DEFAULT '0.00' COMMENT '用户现金总收入',
  `order_credits_total` int(10) DEFAULT '0' COMMENT '用户积分总额',
  `order_voucher_total` decimal(12,2) DEFAULT '0.00' COMMENT '用户代金券总收入',
  `version` int(10) DEFAULT '0' COMMENT '版本号（乐观锁配置字段）',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构Id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`serve_staff_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务人员余额表';

-- ----------------------------
-- Table structure for lb_cms_stat_change_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_stat_change_log`;
CREATE TABLE `lb_cms_stat_change_log` (
  `stat_change_id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `change_date` varchar(32) DEFAULT NULL COMMENT '修改的年月份(2023-05)',
  `change_source` tinyint(1) DEFAULT '0' COMMENT '修改的原因来源(0:未知 1:工单结算修改)',
  `exec_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '执行状态(0 :未执行 1:已执行)',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0否 1:是)',
  `exec_table_name` varchar(255) DEFAULT NULL COMMENT '需要更新的表名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`stat_change_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=694 DEFAULT CHARSET=utf8mb4 COMMENT='报表修改记录日志';

-- ----------------------------
-- Table structure for lb_cms_subsidy_consumption_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_subsidy_consumption_record`;
CREATE TABLE `lb_cms_subsidy_consumption_record` (
  `consumption_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `consumption_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费类型 0：国家补贴消费',
  `source_id` varchar(32) NOT NULL DEFAULT '' COMMENT '消费详情记录主键',
  `amount_discount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '折扣比例',
  `consumption_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '实际消费金额',
  `consumption_before_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '消费前金额',
  `consumption_after_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '消费后金额',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '消费备注',
  `consumption_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_record_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区长者国家补贴消费记录表';

-- ----------------------------
-- Table structure for lb_cms_subsidy_recharge_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_subsidy_recharge_record`;
CREATE TABLE `lb_cms_subsidy_recharge_record` (
  `recharge_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `recharge_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '充值时间',
  `recharge_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '充值金额',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_cancel` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否作废 0:否 1:是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recharge_record_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区长者国家补贴充值记录表';

-- ----------------------------
-- Table structure for lb_cms_suit_elder_migrate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_suit_elder_migrate_record`;
CREATE TABLE `lb_cms_suit_elder_migrate_record` (
  `migrate_record_id` varchar(32) NOT NULL COMMENT '长者机构绑定主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `suit_elder_id` varchar(32) NOT NULL DEFAULT '' COMMENT '适老监管长者id',
  `new_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id(终点)',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '当前机构id',
  `is_delete` tinyint(1) unsigned NOT NULL DEFAULT '0' COMMENT '是否删除0否1:是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`migrate_record_id`) USING BTREE,
  KEY `care_object_id_index` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造长者绑定记录';

-- ----------------------------
-- Table structure for lb_cms_supplier
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_supplier`;
CREATE TABLE `lb_cms_supplier` (
  `supplier_id` varchar(32) NOT NULL COMMENT '主键',
  `supplier_name` varchar(64) DEFAULT '' COMMENT '供应商名称',
  `supplier_type` tinyint(2) DEFAULT NULL COMMENT '供应商性质 1-制造商、2-代理商、3-批发商、4-零售商',
  `supplier_principal` varchar(128) DEFAULT NULL COMMENT '姓名',
  `supplier_phone` varchar(32) DEFAULT '' COMMENT '联系电话',
  `supplier_position` varchar(64) DEFAULT '0' COMMENT '联系地址',
  `supplier_region` varchar(255) DEFAULT NULL COMMENT '地址所在区域',
  `supplier_status` tinyint(1) DEFAULT '0' COMMENT '供应状态 0-正常供应 1-非正常供应',
  `supplier_level` tinyint(2) DEFAULT NULL COMMENT '供应商等级 1-A级、2-B级、3-C级、4-D级',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人',
  `check_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `type` tinyint(1) DEFAULT '0' COMMENT '0:库存供应商,1:药品供应商,2:辅具供应商',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplier_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='供应商表';

-- ----------------------------
-- Table structure for lb_cms_supplies
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_supplies`;
CREATE TABLE `lb_cms_supplies` (
  `supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_name` varchar(64) DEFAULT '' COMMENT '物资名称',
  `supplies_category_id` varchar(32) DEFAULT '' COMMENT '所属类别id',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `supplier_id` varchar(32) DEFAULT '' COMMENT '供应商id',
  `max_warning_value` int(3) DEFAULT '0' COMMENT '上限预警值',
  `min_warning_value` int(3) DEFAULT '0' COMMENT '下限预警值',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '是否可用0不可用1可用',
  `supplies_description` varchar(255) DEFAULT '' COMMENT '物资描述',
  `price` decimal(10,2) DEFAULT '0.00' COMMENT '单价',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `day_rent` decimal(10,2) DEFAULT NULL COMMENT '日租金',
  `month_rent` decimal(10,2) DEFAULT NULL COMMENT '月租金',
  `deposit` decimal(10,2) DEFAULT NULL COMMENT '押金',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='物资表';

-- ----------------------------
-- Table structure for lb_cms_supplies_category
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_supplies_category`;
CREATE TABLE `lb_cms_supplies_category` (
  `supplies_category_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_category_name` varchar(64) DEFAULT '' COMMENT '类别名称',
  `parent_id` varchar(32) DEFAULT '' COMMENT '所属类别id',
  `supplies_category_description` varchar(100) DEFAULT '' COMMENT '类别描述',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplies_category_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='物资类别表';

-- ----------------------------
-- Table structure for lb_cms_supplies_month_check
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_supplies_month_check`;
CREATE TABLE `lb_cms_supplies_month_check` (
  `month_check_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_category_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_category_name` varchar(64) DEFAULT '' COMMENT '类别名称',
  `supplies_in_number` int(10) DEFAULT '0' COMMENT '入库数量',
  `supplies_out_number` int(10) DEFAULT '0' COMMENT '出库数量',
  `supplies_scrapped_number` int(10) DEFAULT '0' COMMENT '报废数量',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `final_number` int(10) DEFAULT '0' COMMENT '库存数量',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`month_check_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='库存统计表';

-- ----------------------------
-- Table structure for lb_cms_sys_dict
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_sys_dict`;
CREATE TABLE `lb_cms_sys_dict` (
  `sys_dict_id` int(10) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `data_type` varchar(32) DEFAULT '0' COMMENT '类型',
  `data_key` varchar(32) NOT NULL COMMENT '字典表中的key',
  `data_value` varchar(32) NOT NULL COMMENT '字典表中的value',
  `data_html` text COMMENT '静态页面',
  `order_num` int(10) NOT NULL DEFAULT '0' COMMENT '排序字段',
  `is_allow_delete` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否允许删除 0 否 1 是',
  `org_id` varchar(32) DEFAULT NULL,
  `is_delete` tinyint(1) DEFAULT '0',
  `create_time` bigint(20) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `create_by` varchar(32) DEFAULT NULL,
  `update_by` varchar(32) DEFAULT NULL,
  `root_sys_dict_id` int(10) DEFAULT NULL COMMENT '父类服务类别id',
  `oneself_situation` varchar(100) NOT NULL DEFAULT 'all' COMMENT '关联自理情况',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sys_dict_id`) USING BTREE,
  UNIQUE KEY `pk_index` (`sys_dict_id`) USING BTREE COMMENT '主键索引'
) ENGINE=InnoDB AUTO_INCREMENT=28430 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='服务类别表';

-- ----------------------------
-- Table structure for lb_cms_system_news
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_system_news`;
CREATE TABLE `lb_cms_system_news` (
  `system_news_id` varchar(32) NOT NULL,
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者唯一标识',
  `system_type` tinyint(1) DEFAULT '0' COMMENT '系统类型:默认0长者app',
  `news_type` tinyint(1) DEFAULT '0' COMMENT '消息类型:默认0在线点餐 1活动报名 2课程报名 3在线商城',
  `news_content` text COMMENT '消息内容',
  `org_id` varchar(64) DEFAULT NULL COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否 删除 0 否 1 是',
  `record_id` varchar(32) DEFAULT NULL COMMENT '记录唯一标识',
  `is_read` tinyint(1) DEFAULT '0' COMMENT '是否已读(0 未读，1 已读)',
  `news_status` tinyint(1) DEFAULT '1' COMMENT '1:确认/进行中 2:已确认 3:已完成 4:已取消/停止',
  `news_time` bigint(20) DEFAULT '0' COMMENT '下单/报名/消息时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`system_news_id`),
  KEY `idx_care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='系统消息表';

-- ----------------------------
-- Table structure for lb_cms_treatment_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_treatment_item`;
CREATE TABLE `lb_cms_treatment_item` (
  `item_id` varchar(32) NOT NULL COMMENT '主键',
  `item_type` tinyint(1) DEFAULT '0' COMMENT '项目类型 1 基础服务 2 服务包',
  `item_name` varchar(64) DEFAULT '' COMMENT '项目名称',
  `treatment_cost` decimal(10,2) DEFAULT NULL COMMENT '治疗费用',
  `treatment_time` varchar(32) DEFAULT '' COMMENT '治疗时长',
  `treatment_type` tinyint(1) DEFAULT '0' COMMENT '治疗周期类型 1 按次数 2 按时间',
  `treatment_cycle` int(10) DEFAULT '0' COMMENT '治疗周期(按次数时为总次数, 按时间时为天数)',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '是否使用 0:未使用1:使用',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`item_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='治疗项目表';

-- ----------------------------
-- Table structure for lb_cms_video_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_video_area`;
CREATE TABLE `lb_cms_video_area` (
  `area_id` varchar(32) NOT NULL COMMENT '主键',
  `area_name` varchar(100) NOT NULL COMMENT '区域名称',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管区域';

-- ----------------------------
-- Table structure for lb_cms_video_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_video_config`;
CREATE TABLE `lb_cms_video_config` (
  `video_config_id` varchar(32) NOT NULL COMMENT '主键',
  `title` varchar(100) NOT NULL COMMENT '标题设置',
  `screen_display` int(11) NOT NULL COMMENT '画面显示',
  `polling_interval` int(11) NOT NULL COMMENT '轮询间隔',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`video_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监控配置';

-- ----------------------------
-- Table structure for lb_cms_video_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_video_device`;
CREATE TABLE `lb_cms_video_device` (
  `video_device_id` varchar(32) NOT NULL COMMENT '主键',
  `device_id` varchar(32) NOT NULL COMMENT '设备序列号，主键',
  `device_name` varchar(32) NOT NULL COMMENT '设备名称',
  `device_model` varchar(100) NOT NULL COMMENT '设备型号',
  `device_status` varchar(32) NOT NULL COMMENT '设备状态',
  `source` varchar(32) DEFAULT NULL COMMENT '权限类型',
  `channel_num` int(11) DEFAULT NULL COMMENT '设备最大支持接入的通道数',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `docking_platform_id` varchar(32) NOT NULL COMMENT '所属厂商',
  `area_id` varchar(32) DEFAULT NULL COMMENT '所属区域id',
  `is_show_device_name` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示摄像机名称 0 不显示 1 显示',
  `upgradeInfo` text COMMENT '属性',
  `accessType` varchar(32) DEFAULT NULL COMMENT '设备接入类型，PaaS-表示Paas程序接入、Lechange-表示乐橙非PaaS设备、Easy4IP表示Easy4IP程序设备、P2P表示P2P程序设备',
  `deviceVersion` varchar(32) DEFAULT NULL COMMENT '设备版本号',
  `playToken` text COMMENT '设备播放码，opensdk使用',
  `brand` varchar(32) DEFAULT NULL COMMENT '设备品牌信息：lechange-乐橙设备，general-通用设备',
  `encryptMode` varchar(32) DEFAULT NULL COMMENT '设备加密模式：0-设备默认加密 1-用户自定义加密',
  `lastOffLineTime` varchar(100) DEFAULT NULL COMMENT '设备最后离线时间',
  `catalog` varchar(32) DEFAULT NULL COMMENT '设备大类【NVR/DVR/HCVR/IPC/SD/IHG/ARC】',
  `deviceAbility` text COMMENT '设备能力集，逗号隔开',
  `channels` text COMMENT '通道信息',
  `deviceInfo` text COMMENT '设备信息',
  `is_monitor` bigint(1) NOT NULL DEFAULT '0' COMMENT '是否监控 0 否 1 是',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '绑定的长者id',
  `bind_time` bigint(20) DEFAULT '0' COMMENT '长者绑定时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`video_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管设备';

-- ----------------------------
-- Table structure for lb_cms_vip_card
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_vip_card`;
CREATE TABLE `lb_cms_vip_card` (
  `vip_card_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL COMMENT '长者ID',
  `vip_card_num` varchar(32) NOT NULL COMMENT '会员卡号',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态 0-正常，1-挂失，2-注销，3-弃用（被替换卡，默认不展示）',
  `vip_level` varchar(32) DEFAULT NULL COMMENT '关联等级表id',
  `vip_point` bigint(20) DEFAULT '0' COMMENT '会员积分',
  `amount` decimal(10,2) DEFAULT '0.00' COMMENT '余额',
  `register_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记日期',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `vip_point_saved` bigint(20) DEFAULT '0' COMMENT '累计积分',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除(换卡之后)',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `bestow_amount` decimal(10,2) DEFAULT NULL COMMENT '赠送金额',
  `member_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '会员类型 1 普通会员 2 助餐会员',
  `member_face_id` int(11) NOT NULL COMMENT '会员面部id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`vip_card_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员卡表';

-- ----------------------------
-- Table structure for lb_cms_vip_card_face
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_vip_card_face`;
CREATE TABLE `lb_cms_vip_card_face` (
  `face_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `vip_card_id` varchar(32) NOT NULL DEFAULT '' COMMENT '会员卡id',
  `face_url` varchar(255) NOT NULL DEFAULT '' COMMENT '面部图片地址',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `is_delete` varchar(32) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` varchar(32) NOT NULL COMMENT '更新时间',
  `is_effective` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否有效 1 有效 0 无效',
  `face_feature` text COMMENT 'Base64处理后的人脸特征值',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`face_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `vip_card_id_IDX` (`vip_card_id`) USING BTREE,
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员卡面部图片表';

-- ----------------------------
-- Table structure for lb_cms_vip_card_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_vip_card_log`;
CREATE TABLE `lb_cms_vip_card_log` (
  `vip_card_log_id` varchar(32) NOT NULL COMMENT '主键',
  `vip_card_id` varchar(64) DEFAULT NULL COMMENT '会员卡ID',
  `old_vip_card_id` varchar(64) DEFAULT NULL COMMENT '旧会员卡ID',
  `vip_card_num` varchar(32) DEFAULT NULL COMMENT '会员卡号',
  `old_vip_card_num` varchar(32) DEFAULT NULL COMMENT '旧会员卡号',
  `care_object_id` varchar(64) NOT NULL COMMENT '长者ID',
  `operation_type` tinyint(1) DEFAULT '0' COMMENT '操作类型 0-充值，1-挂失，2-注销，3-换卡，4-恢复使用 5-第一次办卡 6-消费 7-签到 8-兑换 9-退费 10-一卡通充值 11-账户现金余额充值 12-代金券充值',
  `consumption_type` tinyint(1) DEFAULT '0' COMMENT '消费类型 0-服务工单 1-购物消费 2-点餐消费',
  `consumption_source_id` varchar(32) DEFAULT NULL COMMENT '消费来源ID（例如服务工单消费则为工单ID）',
  `shop_name` varchar(32) DEFAULT NULL COMMENT '商家名称',
  `shop_id` varchar(32) DEFAULT NULL COMMENT '商家ID',
  `gift_id` varchar(32) DEFAULT NULL COMMENT '礼品ID',
  `gift_name` varchar(32) DEFAULT NULL COMMENT '礼品名称',
  `gift_unit` varchar(32) DEFAULT NULL COMMENT '礼品单位',
  `gift_price` decimal(10,2) DEFAULT NULL COMMENT '礼品价格',
  `gift_img` varchar(255) DEFAULT NULL COMMENT '礼品图片',
  `gift_register_name` varchar(32) DEFAULT NULL COMMENT '登记人',
  `gift_count` int(3) DEFAULT NULL COMMENT '礼品个数',
  `amount_before` decimal(10,2) DEFAULT '0.00' COMMENT '操作前余额',
  `amount_after` decimal(10,2) DEFAULT '0.00' COMMENT '操作后余额',
  `point_before` int(11) DEFAULT '0' COMMENT '操作前积分',
  `point_after` int(11) DEFAULT '0' COMMENT '操作后积分',
  `point_saved_before` int(11) DEFAULT '0' COMMENT '操作前累计积分',
  `point_saved_after` int(11) DEFAULT '0' COMMENT '操作后累计积分',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除(换卡之后)',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `bestow_amount` decimal(10,2) DEFAULT '0.00' COMMENT '赠送金额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '充值状态(0:正常,1 作废)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`vip_card_log_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员卡日志表';

-- ----------------------------
-- Table structure for lb_cms_vip_face_upload_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_vip_face_upload_record`;
CREATE TABLE `lb_cms_vip_face_upload_record` (
  `record_id` varchar(32) NOT NULL COMMENT '记录id',
  `face_id` varchar(32) NOT NULL DEFAULT '' COMMENT '人脸id',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '上传类型 1 新增 2 编辑  3 删除',
  `face_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1:通过 0:未通过',
  `face_url` varchar(255) NOT NULL DEFAULT '' COMMENT '上传的人脸照片地址',
  `vip_card_id` varchar(32) NOT NULL DEFAULT '' COMMENT '会员卡号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `face_id_IDX` (`face_id`) USING BTREE,
  KEY `device_id_IDX` (`device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员人脸上传记录';

-- ----------------------------
-- Table structure for lb_cms_vip_level
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_vip_level`;
CREATE TABLE `lb_cms_vip_level` (
  `level_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT NULL COMMENT '等级名称',
  `level_point` bigint(20) NOT NULL DEFAULT '0' COMMENT '累计积分',
  `amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '一次性充值金额',
  `org_id` varchar(32) NOT NULL COMMENT '机构ID',
  `level_order` tinyint(1) NOT NULL COMMENT '等级顺序',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `vip_discount` decimal(10,2) DEFAULT NULL COMMENT '会员折扣',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`level_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员等级表';

-- ----------------------------
-- Table structure for lb_cms_ward_rounds_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_ward_rounds_record`;
CREATE TABLE `lb_cms_ward_rounds_record` (
  `ward_rounds_record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `ward_rounds_way` int(10) DEFAULT NULL COMMENT '查房方式（同设备类型deviceType，联系电话用999表示，-999表示未通话）',
  `ward_rounds_way_name` varchar(100) DEFAULT NULL COMMENT '查房方式名称（同设备名称）',
  `device_iteration_number` varchar(10) DEFAULT NULL COMMENT '设备版本号',
  `ward_rounds_name` varchar(100) DEFAULT NULL COMMENT '查房人员',
  `care_object_feedback` varchar(100) DEFAULT NULL COMMENT '长者反馈',
  `care_object_info` text COMMENT '长者信息',
  `device_info` text COMMENT '设备信息',
  `health_record_info` text COMMENT '健康动态数据',
  `commdict_editable_info` text COMMENT '数据字典信息',
  `work_order_id` varchar(32) DEFAULT NULL COMMENT '工单id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL DEFAULT '' COMMENT '创建人',
  `update_by` varchar(32) NOT NULL DEFAULT '' COMMENT '修改人',
  `remark` varchar(100) DEFAULT NULL COMMENT '备注',
  `call_id` text COMMENT '通话id,多条用逗号隔开',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`ward_rounds_record_id`),
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='远程查房记录表';

-- ----------------------------
-- Table structure for lb_cms_warehouse
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_warehouse`;
CREATE TABLE `lb_cms_warehouse` (
  `warehouse_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_name` varchar(64) DEFAULT '' COMMENT '仓库名称',
  `admin_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `warehouse_position` varchar(125) DEFAULT '' COMMENT '仓库位置',
  `warehouse_use_description` varchar(255) DEFAULT '' COMMENT '仓库用途描述',
  `warehouse_type` tinyint(1) DEFAULT '0' COMMENT '0:库存管理,1:药品仓库,2:辅具仓库',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`warehouse_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='仓库表';

-- ----------------------------
-- Table structure for lb_cms_warehouse_change_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_warehouse_change_record`;
CREATE TABLE `lb_cms_warehouse_change_record` (
  `warehouse_record_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_type` tinyint(1) DEFAULT '0' COMMENT '物资来源/去向类型',
  `record_type` tinyint(1) DEFAULT '0' COMMENT '1 入库记录 2出库记录 3 调拨记录 4 盘点记录',
  `warehouse_id` varchar(32) DEFAULT '' COMMENT '仓库id',
  `handle_account_id` varchar(32) DEFAULT '' COMMENT '经办人id',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人id',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_number` int(3) DEFAULT '0' COMMENT '变动数量',
  `supplies_price` decimal(10,2) DEFAULT '0.00' COMMENT '单价',
  `supplies_product_time` bigint(20) DEFAULT '0' COMMENT '生产日期',
  `recipients_type` varchar(32) DEFAULT '0' COMMENT '物资使用人员部门',
  `is_check` tinyint(1) DEFAULT '0' COMMENT '审核状态0审核中1审核通过2审核不通过',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `supplier_id` varchar(32) DEFAULT '' COMMENT '供应商id',
  `check_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `handle_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `type` tinyint(1) DEFAULT '0' COMMENT '0:库存管理,1:药品仓库',
  `recipients_name` varchar(64) DEFAULT NULL COMMENT '使用人姓名',
  `supplies_original_number` int(3) DEFAULT NULL COMMENT '变动前数量',
  `supplies_rest_number` int(3) DEFAULT NULL COMMENT '变动后数量',
  `record_group_id` varchar(32) DEFAULT '' COMMENT '所属组别id',
  `scrapped_reason` varchar(255) DEFAULT '' COMMENT '报废原因',
  `approve_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `approve_content` varchar(255) DEFAULT '' COMMENT '审批备注',
  `approve_account_id` varchar(32) DEFAULT '' COMMENT '审批人id',
  `photo` varchar(255) DEFAULT NULL COMMENT '图片',
  `approve_time` bigint(20) DEFAULT '0' COMMENT '审批时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`warehouse_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='库存记录变动表';

-- ----------------------------
-- Table structure for lb_cms_warehouse_supplies
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_warehouse_supplies`;
CREATE TABLE `lb_cms_warehouse_supplies` (
  `warehouse_supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_id` varchar(32) DEFAULT NULL COMMENT '仓库id',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_out_number` int(10) DEFAULT '0' COMMENT '出库数量',
  `supplies_in_number` int(10) DEFAULT '0' COMMENT '入库数量',
  `store_number` int(10) DEFAULT '0' COMMENT '库存数量',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `scrapped_number` int(10) DEFAULT '0' COMMENT '报废数量',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`warehouse_supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='库存表';

-- ----------------------------
-- Table structure for lb_cms_withdrawal_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_withdrawal_record`;
CREATE TABLE `lb_cms_withdrawal_record` (
  `withdrawal_record_id` varchar(32) NOT NULL,
  `account_id` varchar(32) NOT NULL,
  `name` varchar(32) DEFAULT NULL COMMENT '提现人',
  `amount` decimal(10,2) DEFAULT NULL COMMENT '提现金额',
  `status` tinyint(4) DEFAULT '1' COMMENT '提现状态 1 提现申请已提交 2 提现成功 3 提现失败',
  `phone_num` varchar(32) NOT NULL COMMENT '提现支付宝',
  `org_id` varchar(32) NOT NULL COMMENT '机构Id',
  `remain_amount` decimal(10,2) DEFAULT NULL COMMENT '剩余金额',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`withdrawal_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_cms_work_operation_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_work_operation_log`;
CREATE TABLE `lb_cms_work_operation_log` (
  `id` varchar(64) NOT NULL DEFAULT '' COMMENT '操作日志主键',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户主键',
  `account_type` tinyint(1) DEFAULT '0' COMMENT '用户类型',
  `org_id` varchar(64) DEFAULT '' COMMENT '账号所属机构',
  `operation` varchar(64) NOT NULL DEFAULT '' COMMENT '操作内容',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `login_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登录时间',
  `username` varchar(32) DEFAULT '' COMMENT '登录账号',
  `display_name` varchar(64) DEFAULT '' COMMENT '用户昵称',
  `work_order_id` varchar(32) NOT NULL COMMENT '工单id',
  `operation_type` tinyint(1) NOT NULL COMMENT '操作类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单维护处理操作日志';

-- ----------------------------
-- Table structure for lb_cms_work_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_work_order`;
CREATE TABLE `lb_cms_work_order` (
  `work_order_id` varchar(32) NOT NULL COMMENT '主键',
  `order_handle_type` tinyint(4) DEFAULT '0' COMMENT '工单处理类型 1 上门救助 2 上门服务 3 120报警 4 测试或误按 5 电话咨询 6 投诉 7 上门关怀 8 电话关怀',
  `order_type` tinyint(4) DEFAULT '0' COMMENT '工单来源类型 1 报警 2 电话咨询 3 自主下单 4 上门关怀 5 工单详情下单 6 长者小程序下单',
  `care_object_id` varchar(32) NOT NULL COMMENT '工单绑定的长者id',
  `source_id` varchar(32) DEFAULT NULL COMMENT '工单来源主键   报警，电话咨询',
  `care_object_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '长者类型 ',
  `order_status` tinyint(4) DEFAULT '0' COMMENT '工单状态 1 报警 2 坐席响应 3 需求调度 4 服务安排 5 完结 6 工单关闭 7 工单取消',
  `gender` varchar(32) DEFAULT NULL COMMENT '长者性别',
  `age` int(4) DEFAULT '45' COMMENT '长者年龄',
  `is_book_order` tinyint(4) DEFAULT '0' COMMENT '是否是预约工单 0 否 1 是',
  `order_format_time` varchar(32) DEFAULT NULL COMMENT '预约时间字符串格式',
  `book_order_time` bigint(20) DEFAULT NULL COMMENT '预约上门时间',
  `book_order_type` tinyint(4) DEFAULT '1' COMMENT '预约时间段 1 上午 2 下午',
  `is_revisit` tinyint(1) DEFAULT '0' COMMENT '是否扣费 0 否 1 是',
  `send_time` bigint(20) DEFAULT NULL COMMENT '派单时间',
  `sign_time` bigint(20) DEFAULT NULL COMMENT '签到时间',
  `sign_position` varchar(255) DEFAULT NULL COMMENT '签到位置',
  `sign_way` tinyint(1) NOT NULL DEFAULT '1' COMMENT '签到方式 1 定位 2 小度扫码',
  `coordsys` tinyint(1) NOT NULL DEFAULT '1' COMMENT '签到地图  2高德 1 百度',
  `lng` varchar(32) DEFAULT NULL COMMENT '纬度',
  `lat` varchar(32) DEFAULT NULL COMMENT '经度',
  `province_id` int(11) DEFAULT NULL COMMENT '省级区域id',
  `city_id` int(11) DEFAULT NULL COMMENT '市级区域id',
  `area_id` int(11) DEFAULT NULL COMMENT '区级区域id',
  `street_id` int(11) DEFAULT NULL COMMENT '街道区域id',
  `call_aid_time` bigint(20) DEFAULT '0' COMMENT '拨打120时间',
  `serve_finish_time` bigint(20) DEFAULT '0' COMMENT '服务完结时间',
  `relation_desc` varchar(255) DEFAULT NULL COMMENT '电话咨询信息',
  `dispose_result` varchar(255) DEFAULT NULL COMMENT '处理结果',
  `add_process` varchar(255) DEFAULT NULL COMMENT '追加处理',
  `version` int(10) DEFAULT '0' COMMENT '乐观锁配置字段',
  `org_id` varchar(32) NOT NULL COMMENT '机构Id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `sign_url` text COMMENT '签到图片',
  `effective_time_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否有效 1 当天有效 2 一直有效',
  `is_visit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否回访 0 不回访 1 回访',
  `review_comments` text COMMENT '审核意见',
  `review_time` bigint(20) DEFAULT NULL COMMENT '审核时间',
  `last_synch_time` bigint(20) DEFAULT '0' COMMENT '工单同步到芜湖智慧养老 上次同步时间',
  `is_upload_today` tinyint(1) DEFAULT '0' COMMENT '南陵今日是否上传',
  `account_type` tinyint(1) NOT NULL DEFAULT '17' COMMENT '客服类型',
  `end_position` varchar(255) DEFAULT NULL COMMENT '工单完结位置',
  `end_lat` varchar(100) DEFAULT NULL COMMENT '工单完结经度',
  `end_lng` varchar(100) DEFAULT NULL COMMENT '工单完结纬度',
  `end_way` tinyint(1) DEFAULT NULL COMMENT '完结方式 1 定位 2 小度扫码',
  `cancel_before_status` tinyint(1) DEFAULT NULL COMMENT '作废前工单状态',
  `alarm_time` bigint(20) DEFAULT NULL COMMENT '报警工单-报警时间',
  `alarm_type` tinyint(1) DEFAULT NULL COMMENT '报警工单-报警类型',
  `alarm_desc` varchar(32) DEFAULT NULL COMMENT '报警叙述',
  `work_order_remarks` varchar(128) NOT NULL DEFAULT '' COMMENT '工单备注',
  `reviewer` varchar(128) NOT NULL DEFAULT '' COMMENT '审核人员',
  `booking_id` varchar(32) NOT NULL DEFAULT '' COMMENT '定时工单任务id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`work_order_id`) USING BTREE,
  UNIQUE KEY `pk_work_id` (`work_order_id`) USING BTREE,
  UNIQUE KEY `uk_source_id` (`source_id`) USING BTREE,
  KEY `nk_org_id` (`org_id`) USING BTREE,
  KEY `finish_time_index` (`serve_finish_time`) USING BTREE,
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `order_format_time_IDX` (`order_format_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='社区服务工单表';

-- ----------------------------
-- Table structure for lb_cms_work_order_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_work_order_setting`;
CREATE TABLE `lb_cms_work_order_setting` (
  `work_order_setting_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `process_model` tinyint(1) NOT NULL COMMENT '工单审核方式 1 自动 2 手动',
  `is_update` tinyint(1) NOT NULL COMMENT '是否可以修改服务项目 0 否 1 是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_staff_update` tinyint(1) NOT NULL DEFAULT '0' COMMENT '服务人员是否支持修改服务项目 0 否 1 是',
  `is_display_amount` tinyint(1) NOT NULL DEFAULT '0' COMMENT '助老APP是否显示服务金额 0 否 1 是',
  `is_display_staff_update` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示服务人员修改记录 0 否 1 是',
  `is_display_account_update` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示坐席客服修改服务项目记录 0 否 1 是',
  `is_display_all_order_update` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否显示服务工单修改记录',
  `serve_content_format` varchar(100) NOT NULL DEFAULT '{服务项目/服务套餐}：价格 ({服务价格}) , 数量({服务次数/时长})；' COMMENT '服务内容格式',
  `serve_clock_in_way` tinyint(1) NOT NULL DEFAULT '1' COMMENT '服务人员上门服务签到以及完成的打卡方式：1 定位 2 扫码',
  `is_send_sms` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否给服务人员发送短信 0 否 1 是',
  `is_confirm_info` tinyint(1) NOT NULL DEFAULT '0' COMMENT '长者信息确认（长者头像照片、入户门照片、历史工单定位）',
  `serve_content` text COMMENT '自定义服务内容',
  `is_booking_order` tinyint(1) NOT NULL DEFAULT '0' COMMENT '余额不足是否可预约工单 0 不可 1 可',
  `is_allow_appoint_serve_staff` tinyint(1) NOT NULL DEFAULT '1' COMMENT '用户预约工单是否允许指定服务人员 1 允许 0 不允许',
  `allow_appoint_staff_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '允许指定服务人员类型 1 全部 2 与长者关联服务人员（isAllowAppointServeStaff == 0 该字段无效）',
  `send_order_way` tinyint(1) NOT NULL DEFAULT '1' COMMENT '工单未指定服务人员派单方式 1 客服派单 2 服务人员抢单（客服派单即为服务人员不允许抢单，服务人员抢单，平台客服依旧可给指定客服派单）',
  `allow_send_order_staff_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '允许派单人员类型 1 全部 2 与长者关联服务人员',
  `is_use_album` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否允许使用相册',
  `coupon_cash_lack` tinyint(1) NOT NULL DEFAULT '2' COMMENT '代金券与现金都不足是否可创建工单 1 允许 2 允许，但需确认 3 不允许',
  `coupon_lack_cash_enough` tinyint(1) NOT NULL DEFAULT '2' COMMENT '代金券不足现金充足是否可创建工单 1 允许 2 允许但需确认 3 不允许',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`work_order_setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工单审核设置';

-- ----------------------------
-- Table structure for lb_cms_work_order_stat
-- ----------------------------
DROP TABLE IF EXISTS `lb_cms_work_order_stat`;
CREATE TABLE `lb_cms_work_order_stat` (
  `work_order_id` varchar(32) NOT NULL COMMENT '工单id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `serve_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '订单id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `order_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '工单状态',
  `order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '工单来源类型 1 报警 2 电话咨询 3 自主下单 4 上门关怀 5 工单详情下单 6 长者小程序下单',
  `order_handle_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '工单类型',
  `is_visit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否回访',
  `is_book_order` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为预约工单',
  `province_id` varchar(32) NOT NULL DEFAULT '' COMMENT '升级区域id',
  `city_id` varchar(32) NOT NULL DEFAULT '' COMMENT '市级区域id',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区级区域id',
  `street_id` varchar(32) NOT NULL DEFAULT '' COMMENT '街道区域id',
  `is_have_picture` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否有图片',
  `serve_finish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '服务完结时间',
  `order_create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '工单创建时间',
  `book_order_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '预约上门时间',
  `book_order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '预约时间段 1 上午 2 下午',
  `sys_dict_id` text COMMENT '服务类别id',
  `serve_staff_id` text COMMENT '服务人员',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `start_picture_url` text NOT NULL COMMENT '服务开始图片',
  `picture_url` text NOT NULL COMMENT '服务完结图片',
  `order_detail` text NOT NULL COMMENT '工单详情',
  `sign_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '签到时间（服务开始时间）',
  `evaluation` varchar(255) NOT NULL DEFAULT '' COMMENT '服务评价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`work_order_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `area_id_IDX` (`area_id`) USING BTREE,
  KEY `is_delete` (`is_delete`),
  KEY `idx_lcwos_org_delete_area_care` (`org_id`,`is_delete`,`area_id`,`care_object_id`),
  KEY `order_create_time` (`order_create_time`),
  KEY `serve_finish_time_IDX` (`serve_finish_time`) USING BTREE,
  KEY `lb_cms_work_order_stat_org_id_IDX` (`org_id`,`order_status`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='全部服务工单详情';

-- ----------------------------
-- Table structure for lb_code_generate
-- ----------------------------
DROP TABLE IF EXISTS `lb_code_generate`;
CREATE TABLE `lb_code_generate` (
  `code_generate_id` varchar(32) NOT NULL COMMENT '主键',
  `code_prefix` varchar(32) DEFAULT '' COMMENT '前缀',
  `code_num` int(11) DEFAULT '0' COMMENT '数值',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构编号',
  `create_time` bigint(20) DEFAULT '0' COMMENT ' 生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `code_type` tinyint(1) DEFAULT '0' COMMENT '类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`code_generate_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_comm_center_dynamic
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_dynamic`;
CREATE TABLE `lb_comm_center_dynamic` (
  `dynamic_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '',
  `context` text NOT NULL,
  `business_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '业务类型(详见枚举文档)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0未删除/ 1已删除',
  `sender_name` varchar(128) NOT NULL DEFAULT '' COMMENT '短信发送者名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_succeeded` tinyint(1) DEFAULT '1' COMMENT '短信发送成功标志，0 失败 1 成功',
  PRIMARY KEY (`dynamic_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通讯中心动态表';

-- ----------------------------
-- Table structure for lb_comm_center_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_info`;
CREATE TABLE `lb_comm_center_info` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `balance` int(10) NOT NULL DEFAULT '0' COMMENT '余额(短信剩余条数/智能语音剩余分钟)',
  `business_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '业务类型(详见枚举文档)',
  `switch_state` tinyint(1) NOT NULL DEFAULT '1' COMMENT '功能开关(0:关闭 1:开启)',
  `consumption` int(10) NOT NULL DEFAULT '0' COMMENT '消费',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0未删除/ 1已删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通讯中心信息表';

-- ----------------------------
-- Table structure for lb_comm_center_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_order`;
CREATE TABLE `lb_comm_center_order` (
  `order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '短信充值订单主键',
  `pay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '支付方式  1支付宝、2微信',
  `pay_order_id` varchar(32) DEFAULT '' COMMENT '支付订单id(lb_wechat_order/ lb_alipay_order)',
  `content` int(11) NOT NULL DEFAULT '0' COMMENT '充值内容（条数/分钟/月数/）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `status` int(11) NOT NULL DEFAULT '0' COMMENT '订单状态 0待支付、1支付成功、2支付失败、3超时',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0未删除/ 1已删除',
  `is_invoice` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已开票 0未开/ 1已开',
  `invoice_id` varchar(32) DEFAULT '' COMMENT '开票记录id',
  `business_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单业务类型(详见枚举文档)',
  `recharge_num` int(11) NOT NULL DEFAULT '1' COMMENT '充值人数',
  `account_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作员',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通信中心充值订单';

-- ----------------------------
-- Table structure for lb_comm_center_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_template`;
CREATE TABLE `lb_comm_center_template` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `code_num` varchar(16) NOT NULL DEFAULT '' COMMENT '模板代号(ali_template)',
  `sign_code` varchar(16) NOT NULL DEFAULT '' COMMENT '签名code (ali_sign)',
  `receive` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接收人 0本人/1亲属/2紧急联系人',
  `reminder` tinyint(1) NOT NULL DEFAULT '0' COMMENT '提醒时间 -1:不提醒(手动)/0实时/1两小时后/2六小时后',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态 0待审批/1启用/2停用/3不通过',
  `validity_time_start` varchar(8) NOT NULL DEFAULT '00:00' COMMENT '有效时间段(开始)',
  `validity_time_end` varchar(8) NOT NULL DEFAULT '00:00' COMMENT '有效时间段(结束)',
  `usage_amount` int(11) NOT NULL DEFAULT '0' COMMENT '使用量',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通讯中心模版信息表';

-- ----------------------------
-- Table structure for lb_comm_center_template_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_template_detail`;
CREATE TABLE `lb_comm_center_template_detail` (
  `code_num` varchar(16) NOT NULL DEFAULT '' COMMENT '模板代号',
  `code_value` varchar(16) NOT NULL DEFAULT '' COMMENT '阿里模板code',
  `context` text NOT NULL COMMENT '模板信息',
  `param` varchar(64) NOT NULL DEFAULT '' COMMENT '参数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`code_num`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='通讯中心模版详情表';

-- ----------------------------
-- Table structure for lb_comm_center_template_param
-- ----------------------------
DROP TABLE IF EXISTS `lb_comm_center_template_param`;
CREATE TABLE `lb_comm_center_template_param` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `key_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'code_num/sms_template_id',
  `param_name` varchar(16) NOT NULL DEFAULT '',
  `param_value` varchar(32) NOT NULL DEFAULT '',
  `is_modify` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可修改(0: 否 1:是)',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='通讯中心模版参数表';

-- ----------------------------
-- Table structure for lb_commdict
-- ----------------------------
DROP TABLE IF EXISTS `lb_commdict`;
CREATE TABLE `lb_commdict` (
  `commdict_id` int(32) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `type` varchar(64) DEFAULT '' COMMENT '类型',
  `key` varchar(32) DEFAULT '' COMMENT '键',
  `value` mediumtext COMMENT '值',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_open` tinyint(4) DEFAULT '2' COMMENT '1开放查询 2不开放查询',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`commdict_id`),
  KEY `lb_commdict_type_IDX` (`type`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=30440 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_commdict_editable
-- ----------------------------
DROP TABLE IF EXISTS `lb_commdict_editable`;
CREATE TABLE `lb_commdict_editable` (
  `commdict_id` int(32) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `type` varchar(32) DEFAULT '' COMMENT '类型',
  `key` varchar(32) DEFAULT '' COMMENT '键',
  `value` varchar(255) DEFAULT NULL COMMENT '值',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_open` tinyint(4) DEFAULT '2' COMMENT '1开放查询 2不开放查询',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `order_num` int(10) NOT NULL DEFAULT '0' COMMENT '排序字段',
  `is_editable` tinyint(1) DEFAULT '1' COMMENT '是否可编辑，0否,1可编辑',
  `type_desc` varchar(32) DEFAULT '' COMMENT '字典数据类型描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '默认数据标识',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`commdict_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `type_IDX` (`type`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=1003271658 DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_common_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_common_account`;
CREATE TABLE `lb_common_account` (
  `id` int(32) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型（1-账号，2-密码）',
  `value` varchar(32) NOT NULL DEFAULT '' COMMENT '值',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `type` (`type`) USING BTREE,
  KEY `value` (`value`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=22840 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='常见账号/密码表';

-- ----------------------------
-- Table structure for lb_community
-- ----------------------------
DROP TABLE IF EXISTS `lb_community`;
CREATE TABLE `lb_community` (
  `community_id` varchar(32) NOT NULL COMMENT '主键',
  `community_name` varchar(255) DEFAULT '' COMMENT '小区名字',
  `community_type` tinyint(4) DEFAULT '1' COMMENT '小区展示类型：1 楼房床拼接展示 2 详细地址展示',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '小区类型：1 机构小区 2 社区居家小区',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `is_use` varchar(1) DEFAULT '' COMMENT '1使用 2未使用',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `bed_code_zip_url` varchar(128) NOT NULL DEFAULT '' COMMENT '小区下床位码压缩包地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`community_id`),
  KEY `lb_community_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_construct_inventory
-- ----------------------------
DROP TABLE IF EXISTS `lb_construct_inventory`;
CREATE TABLE `lb_construct_inventory` (
  `construct_inventory_id` varchar(32) NOT NULL COMMENT '主键',
  `suit_aged_manage_id` varchar(32) NOT NULL COMMENT '适老改造项目（包）id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `device_kind` varchar(16) NOT NULL COMMENT '设备类别 具体见数据字典',
  `device_name` varchar(32) NOT NULL COMMENT '设备名称',
  `device_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '设备类型 1 基础 2 可选',
  `unit` varchar(16) NOT NULL COMMENT '单位',
  `specs` varchar(64) NOT NULL COMMENT '规格',
  `price` decimal(8,2) NOT NULL COMMENT '单价（元）',
  `notes` varchar(128) NOT NULL DEFAULT '' COMMENT '备注',
  `is_lonbon` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否是来邦设备',
  `device_model` varchar(64) NOT NULL DEFAULT '' COMMENT '设备型号 ，来邦设备，设备型号必填',
  `device_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '设备描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `device_photo` varchar(255) NOT NULL DEFAULT '' COMMENT '设备图片',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`construct_inventory_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `suit_aged_manage_id_IDX` (`suit_aged_manage_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造建设清单表';

-- ----------------------------
-- Table structure for lb_consumption_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_consumption_record`;
CREATE TABLE `lb_consumption_record` (
  `consumption_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '消费详情记录主键',
  `consumption_type` tinyint(1) NOT NULL COMMENT '消费类型（0 账户充值，1 一卡通充值，2 账户余额消费， 3 一卡通消费，4 押金充值）',
  `consumer` varchar(32) NOT NULL DEFAULT '' COMMENT '消费人',
  `consumption_pattern` tinyint(1) NOT NULL COMMENT '消费方式（0 账户余额，1 一卡通余额，2 微信，3 支付宝，4 银行卡，5 现金）',
  `consumption_amount` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '消费金额',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费结束时间',
  `toll_person` varchar(32) NOT NULL DEFAULT '' COMMENT '收费人',
  `consumption_remark` text COMMENT '消费备注',
  `expense_name` varchar(32) DEFAULT '' COMMENT '费用名称',
  `expense_amount` varchar(32) DEFAULT '' COMMENT '费用金额',
  `expense_type` tinyint(1) DEFAULT NULL COMMENT '费用类型',
  `expense_nature` tinyint(1) DEFAULT NULL COMMENT '费用性质',
  `expense_remark` text COMMENT '费用备注',
  `account_preparatory_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '账户预存款余额',
  `one_card_balance` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '一卡通余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费状态（0 正常，1 作废，2 已结算）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_record_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `record_id` (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='消费记录表';

-- ----------------------------
-- Table structure for lb_contactinteractive
-- ----------------------------
DROP TABLE IF EXISTS `lb_contactinteractive`;
CREATE TABLE `lb_contactinteractive` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `track_id` varchar(64) DEFAULT NULL COMMENT '信息所属记录id',
  `record_type` tinyint(1) DEFAULT NULL COMMENT '1图片 2文字 3语音 4视频',
  `picture_width` int(9) DEFAULT '0' COMMENT '图片宽度(px)',
  `picture_height` int(9) DEFAULT '0' COMMENT '图片高度(px)',
  `record_content` text COMMENT '信息内容',
  `record_contact_id` varchar(64) DEFAULT NULL COMMENT '互动人Id',
  `record_contact_name` varchar(128) DEFAULT NULL COMMENT '互动人姓名',
  `time_length` tinyint(2) DEFAULT NULL COMMENT '语音时长',
  `read_account` text COMMENT '已读账号',
  `status` tinyint(1) DEFAULT '0' COMMENT '记录状态，0正常，1撤回',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `user_type` tinyint(1) DEFAULT NULL COMMENT '用户类型',
  `content_type` tinyint(1) DEFAULT '1' COMMENT '内容类型（1 普通互动，2 血压计客服互动，3 来邦小助手提示）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `track_id` (`track_id`) USING BTREE,
  KEY `record_contact_id` (`record_contact_id`) USING BTREE,
  KEY `read_account` (`read_account`(128)) USING BTREE,
  KEY `create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='互动信息';

-- ----------------------------
-- Table structure for lb_count_number
-- ----------------------------
DROP TABLE IF EXISTS `lb_count_number`;
CREATE TABLE `lb_count_number` (
  `id` tinyint(4) NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `count_type` varchar(32) NOT NULL DEFAULT '' COMMENT '统计数据类型',
  `count_number` int(11) DEFAULT '0' COMMENT '数据值',
  `app_type` int(11) DEFAULT '1' COMMENT 'app类型,1子女app,14安卓护工app，15ios护工app,16安卓医生app,17ios医生app',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8 COMMENT='计数统计表';

-- ----------------------------
-- Table structure for lb_crutch
-- ----------------------------
DROP TABLE IF EXISTS `lb_crutch`;
CREATE TABLE `lb_crutch` (
  `crutch_id` varchar(32) NOT NULL COMMENT '设备id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '绑定长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '绑定时机构id',
  `mac` varchar(32) DEFAULT NULL COMMENT 'mac地址',
  `device_type` tinyint(3) NOT NULL DEFAULT '105' COMMENT '设备类型',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '电话号码',
  `iccid` varchar(32) NOT NULL DEFAULT '' COMMENT '物联网卡iccid',
  `work_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '工作状态 0默认正常 1休眠 2唤醒 3手动关机 4欠压关机',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '在线 0离线 1在线',
  `power` int(3) NOT NULL DEFAULT '0' COMMENT '电量',
  `energy_check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新电量检测时间',
  `play_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '播放模式 0静音 1MP3  2收音机',
  `malfunction` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备故障 正常 0  故障1',
  `protocol_name` varchar(32) DEFAULT '' COMMENT '协议名称',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本',
  `software_version` varchar(32) DEFAULT '' COMMENT '软件版本',
  `manufacturer` varchar(32) DEFAULT '' COMMENT '制造厂家',
  `make_date` varchar(32) DEFAULT '' COMMENT '制造日期,格式为yyyy-mm-dd',
  `device_name` varchar(32) DEFAULT '' COMMENT '设备名称',
  `heartbeat_cycle` int(3) DEFAULT '0' COMMENT '协议心跳周期 单位秒，默认60 秒',
  `position_upload_cycle` int(3) DEFAULT '0' COMMENT '位置上传周期 单位秒，默认60 秒',
  `emergency_num` varchar(255) DEFAULT '' COMMENT '应急电话  {1:"15056594545",2:"15056594545",3:"15056594545",4:"15056594545"}',
  `tcp_server_ip` varchar(24) DEFAULT '' COMMENT '连接服务器ip',
  `tcp_server_port` varchar(8) DEFAULT '' COMMENT '连接服务器port',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`crutch_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能拐杖';

-- ----------------------------
-- Table structure for lb_csr_chat_list
-- ----------------------------
DROP TABLE IF EXISTS `lb_csr_chat_list`;
CREATE TABLE `lb_csr_chat_list` (
  `csr_id` varchar(64) NOT NULL COMMENT '客服Id',
  `chat_list` mediumtext NOT NULL COMMENT '聊天列表',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`csr_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='客服聊天列表';

-- ----------------------------
-- Table structure for lb_csr_phone
-- ----------------------------
DROP TABLE IF EXISTS `lb_csr_phone`;
CREATE TABLE `lb_csr_phone` (
  `csr_phone_id` varchar(32) NOT NULL COMMENT '主键',
  `csr_name` varchar(32) NOT NULL DEFAULT '' COMMENT '客服名称',
  `csr_photo` varchar(60) NOT NULL DEFAULT '' COMMENT '客服头像',
  `phone_num` varchar(20) NOT NULL DEFAULT '' COMMENT '电话号码',
  `is_valid` tinyint(1) DEFAULT '0' COMMENT '是否有效  0 有效，1 失效',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`csr_phone_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='客服电话表';

-- ----------------------------
-- Table structure for lb_customer
-- ----------------------------
DROP TABLE IF EXISTS `lb_customer`;
CREATE TABLE `lb_customer` (
  `customer_id` varchar(32) NOT NULL COMMENT '主键',
  `customer_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `customer_phone` varchar(32) DEFAULT '' COMMENT '客服电话',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `return_visit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回访状态（0 无需回访，1 待回访）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`customer_id`),
  KEY `nk_org_id` (`org_id`) USING BTREE,
  KEY `customer_phone` (`customer_phone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='咨询客户';

-- ----------------------------
-- Table structure for lb_customer_call_history
-- ----------------------------
DROP TABLE IF EXISTS `lb_customer_call_history`;
CREATE TABLE `lb_customer_call_history` (
  `call_history_id` varchar(32) NOT NULL COMMENT '主键',
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `call_time` bigint(20) DEFAULT '0' COMMENT '呼叫时间',
  `answer_start_time` bigint(20) DEFAULT '0' COMMENT '开始接听时间',
  `answer_end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `status` tinyint(4) DEFAULT '3' COMMENT '1异常，2未接通，3正在接听，4已处理，5等待接听\n',
  `answer_account_id` varchar(32) DEFAULT '' COMMENT '接听人主键',
  `answer_account_name` varchar(128) DEFAULT '' COMMENT '接听人姓名',
  `audio_url` varchar(255) DEFAULT NULL COMMENT '通话录音地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `type` tinyint(2) DEFAULT '1' COMMENT '电话呼叫类型 1呼入2呼出',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `call_id` varchar(64) DEFAULT NULL COMMENT '通话标识',
  `call_seq` varchar(32) DEFAULT '' COMMENT '通话转接标识',
  `seat_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '席位类型（0 电话席位， 1 处警席位，2 视频席位）',
  `alarm_id` varchar(32) DEFAULT '' COMMENT '报警记录主键',
  `customer_name` varchar(255) DEFAULT NULL COMMENT '咨询客户姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_history_id`),
  KEY `phone_num` (`phone_num`) USING BTREE,
  KEY `idx_answer_account_id_seat_type` (`answer_account_id`,`seat_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='客户通话记录表';

-- ----------------------------
-- Table structure for lb_customer_remark
-- ----------------------------
DROP TABLE IF EXISTS `lb_customer_remark`;
CREATE TABLE `lb_customer_remark` (
  `remark_id` varchar(32) NOT NULL COMMENT '主键',
  `customer_phone` varchar(32) DEFAULT '' COMMENT '客服电话',
  `remark_time` varchar(32) DEFAULT '' COMMENT '备注时间',
  `remark_account_id` varchar(32) DEFAULT '' COMMENT '备注账号id',
  `remark_account_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `remark_content` varchar(255) DEFAULT '' COMMENT '客服备注内容',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者Id',
  `remark_type` tinyint(1) DEFAULT '0' COMMENT '备注类型（0 电话咨询，1 客服通话）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `return_visit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '回访状态（0 无需回访，1 待回访）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`remark_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='客户备注';

-- ----------------------------
-- Table structure for lb_customer_service_consult
-- ----------------------------
DROP TABLE IF EXISTS `lb_customer_service_consult`;
CREATE TABLE `lb_customer_service_consult` (
  `customer_service_consult_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_id` varchar(32) DEFAULT NULL COMMENT '所在商品',
  `account_id` varchar(32) NOT NULL COMMENT '用户',
  `csr_account_id` varchar(32) DEFAULT NULL COMMENT '客服',
  `message_content` text NOT NULL COMMENT '消息内容',
  `message_duration` bigint(20) DEFAULT '0' COMMENT '音频、视频的时长(秒)',
  `message_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消息类型(0:文本,1:语音,2:图片,3:视频,4:商品)',
  `sender_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '发送人类型(0:用户,1客服)',
  `message_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消息状态(0:正常,1:撤回)',
  `is_read` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已读（0未读,1已读）',
  `is_delivery` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否送达（0未送达,1已送达）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`customer_service_consult_id`),
  KEY `goods_id` (`goods_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `csr_account_id` (`csr_account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='客服咨询表';

-- ----------------------------
-- Table structure for lb_data_server_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_data_server_config`;
CREATE TABLE `lb_data_server_config` (
  `data_server_config_id` varchar(64) NOT NULL DEFAULT '' COMMENT '唯一标识',
  `name` varchar(64) NOT NULL DEFAULT '' COMMENT '名称',
  `ip` varchar(32) NOT NULL DEFAULT '' COMMENT 'ip',
  `port` varchar(12) NOT NULL DEFAULT '' COMMENT '端口',
  `url` varchar(32) NOT NULL DEFAULT '' COMMENT '路径',
  `type` tinyint(3) NOT NULL DEFAULT '1' COMMENT '配置类型',
  `expand` varchar(32) NOT NULL DEFAULT '' COMMENT '扩展字段（备用）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生产时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`data_server_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='数据采集服务器配置表';

-- ----------------------------
-- Table structure for lb_db_op
-- ----------------------------
DROP TABLE IF EXISTS `lb_db_op`;
CREATE TABLE `lb_db_op` (
  `db_op_id` int(11) NOT NULL COMMENT '主键',
  `db_op_name` varchar(16) DEFAULT '' COMMENT 'db操作名称',
  `db_op_flag` int(1) DEFAULT '0' COMMENT 'db操作标识',
  `description` varchar(255) DEFAULT '' COMMENT '叙述',
  `type` varchar(32) DEFAULT '' COMMENT '类型',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`db_op_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_debugging_temp_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_debugging_temp_record`;
CREATE TABLE `lb_debugging_temp_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT 'nb设备电信平台id',
  `env_temp` varchar(32) DEFAULT NULL COMMENT '环境温度',
  `wrist_temp` varchar(32) DEFAULT NULL COMMENT '手腕温度',
  `body_temp` varchar(32) DEFAULT NULL COMMENT '身体温度',
  `wear_status` int(3) DEFAULT '0' COMMENT '佩戴状态',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE,
  KEY `lb_debugging_temp_record_iot_device_id_IDX` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='测温模块调试记录表';

-- ----------------------------
-- Table structure for lb_device_activity_track
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_activity_track`;
CREATE TABLE `lb_device_activity_track` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` smallint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `handle_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `content` text COMMENT '内容',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `iot_device_id` (`iot_device_id`),
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_device_alarm_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_alarm_config`;
CREATE TABLE `lb_device_alarm_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置对象标识',
  `report_device_type` tinyint(1) NOT NULL COMMENT 'NB上报设备类型',
  `device_iteration_number` tinyint(1) NOT NULL COMMENT '设备迭代版本号',
  `device_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `area_type` tinyint(1) NOT NULL COMMENT '区域类型（0-非公共卫生间，5-公共卫生间）',
  `area_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '区域类型描述',
  `set_type` tinyint(1) NOT NULL COMMENT '设置类型（1-处警方式，2-报警延迟）',
  `set_param` tinyint(3) unsigned NOT NULL COMMENT '设置参数（1：0-双向，1-单向；2：分钟）',
  `support_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '支持处警方式（1-单向，2-双向，3-单双向）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '配置类型',
  `device_type_desc_delay` varchar(32) DEFAULT '' COMMENT '设备类型描述（报警延迟）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  UNIQUE KEY `uni_device_alarm_config` (`object_id`,`report_device_type`,`device_iteration_number`,`area_type`,`set_type`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备报警配置表';

-- ----------------------------
-- Table structure for lb_device_alarm_configcs
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_alarm_configcs`;
CREATE TABLE `lb_device_alarm_configcs` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置对象标识',
  `report_device_type` tinyint(1) NOT NULL COMMENT 'NB上报设备类型',
  `device_iteration_number` tinyint(1) DEFAULT NULL COMMENT '设备迭代版本号',
  `area_type` tinyint(1) NOT NULL COMMENT '区域类型（0-非公共卫生间，5-公共卫生间）',
  `set_type` tinyint(1) NOT NULL COMMENT '设置类型（1-处警方式，2-报警延迟）',
  `count` int(11) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `3333` (`area_type`,`set_type`,`report_device_type`,`device_iteration_number`,`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备报警配置表';

-- ----------------------------
-- Table structure for lb_device_base_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_base_info`;
CREATE TABLE `lb_device_base_info` (
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备实体主键',
  `device_unique_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备唯一标识(优先级 imei > mac > sn)',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备imei',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '序列号',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '-3' COMMENT '设备迭代号',
  `device_type` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `position_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '安装位置类型',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目主键',
  `online_status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '在线状态(0:离线 1:在线)',
  `online_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '设备上次在线时间',
  `battery_level` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备电量百分比(%)',
  `battery_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量,2充电中)',
  `battery_update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '设备电量更新时间',
  `config_version` smallint(1) NOT NULL DEFAULT '1' COMMENT '配置版本号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_bind` tinyint(1) NOT NULL DEFAULT '0' COMMENT '绑定标识（0：未绑定，1：已绑定）',
  `real_time_track_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '实时轨迹功能状态，0关闭，1开启中',
  `real_time_track_last_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上一次开启实时轨迹的开始时间',
  PRIMARY KEY (`device_id`),
  UNIQUE KEY `uk_device_unique_id` (`device_unique_id`),
  KEY `idx_imei` (`imei`),
  KEY `idx_mac` (`mac`),
  KEY `idx_sn` (`sn`),
  KEY `idx_device_unique_id` (`device_unique_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备基础信息表';

-- ----------------------------
-- Table structure for lb_device_care_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_care_config`;
CREATE TABLE `lb_device_care_config` (
  `device_care_config_id` varchar(32) NOT NULL COMMENT '主键',
  `device_id` varchar(32) DEFAULT '' COMMENT '设备id',
  `care_config_type` tinyint(1) DEFAULT '0' COMMENT '监护配置类型',
  `is_care` tinyint(1) DEFAULT '0',
  `delay` int(11) DEFAULT '0' COMMENT '时间',
  `care_time` mediumtext COMMENT '看护时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `work_pattern` tinyint(1) DEFAULT '1' COMMENT '工作模式',
  `start_time` varchar(64) DEFAULT NULL COMMENT '手表上报时间/每日统计上报时间',
  `danger_level` tinyint(1) DEFAULT NULL COMMENT '危险等级',
  `care_setting` tinyint(1) DEFAULT NULL COMMENT '看护设置',
  `factory_pattern` char(1) DEFAULT NULL COMMENT '工厂模式',
  `band_delay` double(11,1) DEFAULT '0.0' COMMENT '手表报警阈值',
  `lowest_heart_rate` int(11) DEFAULT NULL COMMENT '心率最低阈值',
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'NB上报时设备类型（0 手环，1 按钮）',
  `highest_heart_rate` int(11) DEFAULT NULL COMMENT '心率最高阈值',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_care_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_device_change_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_change_record`;
CREATE TABLE `lb_device_change_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '操作人id',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `action_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1 添加，2 解绑，3 换绑）',
  `device_type` int(11) DEFAULT NULL COMMENT '设备类型',
  `key_id` varchar(32) DEFAULT '' COMMENT '设备所属',
  `last_key_id` varchar(32) DEFAULT '' COMMENT '操作前设备所属',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `account_id` (`account_id`),
  KEY `idx_mac` (`mac`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备变更记录表';

-- ----------------------------
-- Table structure for lb_device_energy
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_energy`;
CREATE TABLE `lb_device_energy` (
  `device_energy_id` varchar(32) NOT NULL COMMENT '主键',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac信息',
  `energy` int(3) NOT NULL COMMENT '电量百分比',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `rsrp` int(3) DEFAULT '-1' COMMENT 'cat1信号强度，-1代表无效',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_energy_id`),
  KEY `mac` (`mac`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='设备电量记录表';

-- ----------------------------
-- Table structure for lb_device_energy_monitor_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_energy_monitor_record`;
CREATE TABLE `lb_device_energy_monitor_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `start_time` bigint(20) DEFAULT '0' COMMENT '监控开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '监控结束时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `min_energy` int(11) DEFAULT '0' COMMENT '电量',
  `result` tinyint(1) DEFAULT '1' COMMENT '电量监控结果 1监测中,2正常,3异常',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备电量监控记录表';

-- ----------------------------
-- Table structure for lb_device_entity_binding_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_entity_binding_relation`;
CREATE TABLE `lb_device_entity_binding_relation` (
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备主键',
  `entity_id` varchar(64) NOT NULL DEFAULT '' COMMENT '实体主键',
  `entity_category` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '实体类别（0:用户、1:区域、2:设备）',
  `entity_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '实体类型（长者、 床位、房间、公共区域、 信标设备、按钮设备、...）',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '安装位置类型',
  `device_type` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代号',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0:否，1:是）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间（时间戳）',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间（时间戳）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`,`entity_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备-实体绑定关系表';

-- ----------------------------
-- Table structure for lb_device_entity_binding_relation_backup
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_entity_binding_relation_backup`;
CREATE TABLE `lb_device_entity_binding_relation_backup` (
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备主键',
  `entity_id` varchar(64) NOT NULL DEFAULT '' COMMENT '实体主键',
  `entity_category` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '实体类别（0:用户、1:区域、2:设备）',
  `entity_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '实体类型（长者、 床位、房间、公共区域、 信标设备、按钮设备、...）',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '安装位置类型',
  `device_type` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间（时间戳）',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间（时间戳）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0:否，1:是）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备-实体绑定关系表(备份)';

-- ----------------------------
-- Table structure for lb_device_entity_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_entity_relation`;
CREATE TABLE `lb_device_entity_relation` (
  `device_entity_relation_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备-实体关系主键',
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备主键',
  `entity_id` varchar(64) NOT NULL DEFAULT '' COMMENT '实体主键',
  `entity_category` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '实体类别（详见枚举文档）',
  `entity_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '实体类型（详见枚举文档）',
  `relation_mode` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '关系模式（1:绑定 2:同步长者）',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `position_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '安装位置类型',
  `device_iteration_number` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备迭代号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间（时间戳）',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间（时间戳）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除（0:否，1:是）',
  `unique_id` varchar(255) NOT NULL DEFAULT '' COMMENT '唯一键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_entity_relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备-实体关系表';

-- ----------------------------
-- Table structure for lb_device_find_monitor_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_find_monitor_record`;
CREATE TABLE `lb_device_find_monitor_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备编号',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '监控开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '监控结束时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `frequency` int(11) NOT NULL DEFAULT '0' COMMENT '频次',
  `real_time_track_last_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上一次开启实时轨迹的开始时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备查找监控记录表';

-- ----------------------------
-- Table structure for lb_device_flag
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_flag`;
CREATE TABLE `lb_device_flag` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `iot_device_id` varchar(32) NOT NULL,
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `flag_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '标识类型(1：固件是否需要升级，2：软件是否需要升级，...)',
  `flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '标识值',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备标识';

-- ----------------------------
-- Table structure for lb_device_heart_track
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_heart_track`;
CREATE TABLE `lb_device_heart_track` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '0信标位置,1非信标位置(粗定位,gps,wifi)',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` smallint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '粗纬度',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '粗经度',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '心率值',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `track_group_id` varchar(64) DEFAULT '' COMMENT '轨迹组名',
  `handle_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `blood_oxygen` int(3) DEFAULT '-1' COMMENT '血氧值',
  `device_status` tinyint(1) DEFAULT '1' COMMENT '手表佩带情况，0不显示佩带情况，1佩戴中，2未佩戴，3充电中',
  `content` text COMMENT '内容',
  `device_status_duration` bigint(20) DEFAULT '0' COMMENT '佩带状态持续时长',
  `systolic_pressure` int(3) DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT '-1' COMMENT '舒张压',
  `position_status` text COMMENT '位置状态记录',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `temperature` tinyint(3) DEFAULT '-10' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_humiture_sensor` tinyint(3) DEFAULT '0' COMMENT '是否有温湿度传感器 0:没有 1:有',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `track_open_id` varchar(64) DEFAULT '' COMMENT '轨迹开启人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `heart_rate_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示心率数据，1显示，0不显示',
  `blood_pressure_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血压数据，1显示，0不显示',
  `blood_oxygen_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血氧数据，1显示，0不显示',
  `is_intact` tinyint(1) DEFAULT '0' COMMENT '当前数据是否完整，1完整，0,不完整',
  `device_status_is_show` tinyint(1) DEFAULT '1' COMMENT '是否显示佩戴状态 0不显示,1显示',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `use_type` tinyint(1) DEFAULT '1' COMMENT '记录用途类型，1查找长者,2查找设备',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `uncalibrated_day_num` int(11) DEFAULT NULL COMMENT '血压计未校准天数',
  `is_applets_measure` tinyint(1) DEFAULT '0' COMMENT '是否小程序测量值 0:否1:是',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `is_health_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `is_position_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `body_temperature_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示体温数据，1显示，0不显示',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `breath` int(3) DEFAULT '-1' COMMENT '呼吸值',
  `breath_is_show` tinyint(1) DEFAULT '0' COMMENT '呼吸数据是否显示（0-不显示，1-显示）',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `track_group_id` (`track_group_id`),
  KEY `iot_device_id` (`iot_device_id`),
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_device_install_photo
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_install_photo`;
CREATE TABLE `lb_device_install_photo` (
  `install_photo_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `device_id` varchar(32) DEFAULT NULL COMMENT '设备id',
  `install_before_url` text COMMENT '设备安装前的照片链接',
  `install_after_url` text COMMENT '设备安装后的照片',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `device_name` varchar(100) DEFAULT NULL COMMENT '设备名称',
  `is_assist_device` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否是辅助设备 0 不是 1 是',
  `device_type` tinyint(1) DEFAULT NULL COMMENT '设备类型',
  `transformation_data_url` text COMMENT '改造资料图片链接',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`install_photo_id`),
  KEY `idx_device_id` (`device_id`) USING BTREE,
  KEY `is_delete` (`is_delete`),
  KEY `is_assist_device` (`is_assist_device`),
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备安装拍照信息';

-- ----------------------------
-- Table structure for lb_device_location_track
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_location_track`;
CREATE TABLE `lb_device_location_track` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '0信标位置,1非信标位置(粗定位,gps,wifi)',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` smallint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '粗纬度',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '粗经度',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '心率值',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `track_group_id` varchar(64) DEFAULT '' COMMENT '轨迹组名',
  `handle_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `blood_oxygen` int(3) DEFAULT '-1' COMMENT '血氧值',
  `device_status` tinyint(1) DEFAULT '1' COMMENT '手表佩带情况，0不显示佩带情况，1佩戴中，2未佩戴，3充电中',
  `content` text COMMENT '内容',
  `device_status_duration` bigint(20) DEFAULT '0' COMMENT '佩带状态持续时长',
  `systolic_pressure` int(3) DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT '-1' COMMENT '舒张压',
  `position_status` text COMMENT '位置状态记录',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `temperature` tinyint(3) DEFAULT '-10' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_humiture_sensor` tinyint(3) DEFAULT '0' COMMENT '是否有温湿度传感器 0:没有 1:有',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `track_open_id` varchar(64) DEFAULT '' COMMENT '轨迹开启人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `heart_rate_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示心率数据，1显示，0不显示',
  `blood_pressure_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血压数据，1显示，0不显示',
  `blood_oxygen_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血氧数据，1显示，0不显示',
  `is_intact` tinyint(1) DEFAULT '0' COMMENT '当前数据是否完整，1完整，0,不完整',
  `device_status_is_show` tinyint(1) DEFAULT '1' COMMENT '是否显示佩戴状态 0不显示,1显示',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `use_type` tinyint(1) DEFAULT '1' COMMENT '记录用途类型，1查找长者,2查找设备',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `uncalibrated_day_num` int(11) DEFAULT NULL COMMENT '血压计未校准天数',
  `is_applets_measure` tinyint(1) DEFAULT '0' COMMENT '是否小程序测量值 0:否1:是',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `is_health_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `is_position_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `body_temperature_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示体温数据，1显示，0不显示',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `breath` int(3) DEFAULT '-1' COMMENT '呼吸值',
  `breath_is_show` tinyint(1) DEFAULT '0' COMMENT '呼吸数据是否显示（0-不显示，1-显示）',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `track_group_id` (`track_group_id`),
  KEY `iot_device_id` (`iot_device_id`),
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_device_model
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_model`;
CREATE TABLE `lb_device_model` (
  `device_model_id` varchar(32) NOT NULL COMMENT '主键',
  `device_type` tinyint(1) NOT NULL COMMENT '设备类型',
  `device_iteration_number` tinyint(1) NOT NULL COMMENT '设备迭代号',
  `device_model` varchar(32) NOT NULL COMMENT '设备型号',
  `device_desc` varchar(64) NOT NULL COMMENT '设备描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `order_num` tinyint(1) NOT NULL COMMENT '顺序优先级',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_model_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备型号表';

-- ----------------------------
-- Table structure for lb_device_msg_push_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_msg_push_record`;
CREATE TABLE `lb_device_msg_push_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `content` mediumtext COMMENT '消息内容 jsonString',
  `is_receive` tinyint(1) DEFAULT '0' COMMENT '是否已经收到，1是 0否',
  `push_times` tinyint(4) DEFAULT '1' COMMENT '已推送次数',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '报警所属NB设备iotid',
  `device_type` smallint(6) DEFAULT '0' COMMENT '设备类型',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `msg_type` tinyint(1) DEFAULT '53' COMMENT '消息类型:53心跳',
  `org_type` tinyint(1) DEFAULT '1' COMMENT '机构类型',
  `region_id` varchar(64) DEFAULT '' COMMENT '区域id',
  `client_type` tinyint(1) DEFAULT '4' COMMENT '客户端类型',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `is_receive` (`is_receive`,`push_times`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备信息推送记录表';

-- ----------------------------
-- Table structure for lb_device_position
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_position`;
CREATE TABLE `lb_device_position` (
  `device_position_id` varchar(64) NOT NULL DEFAULT '' COMMENT '位置id',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `position_desc` varchar(64) NOT NULL DEFAULT '' COMMENT '位置叙述',
  `longitude` varchar(32) NOT NULL DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) NOT NULL DEFAULT '' COMMENT '纬度',
  `device_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构组织id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生产时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_position_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备位置信息表';

-- ----------------------------
-- Table structure for lb_device_pre_entry
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_pre_entry`;
CREATE TABLE `lb_device_pre_entry` (
  `device_pre_entry_id` varchar(32) NOT NULL COMMENT '主键',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '-3' COMMENT '设备迭代版本号',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备imei',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '序列号',
  `manufacturer_name` varchar(32) NOT NULL DEFAULT '' COMMENT '厂商名称',
  `operator_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人id',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `pre_entry_start_time` bigint(20) NOT NULL DEFAULT '-1' COMMENT '预入库有效期开始时间(-1代表无开始时间)',
  `pre_entry_end_time` bigint(20) NOT NULL DEFAULT '-1' COMMENT '预入库有效期结束时间(-1代表永久授权)',
  `pre_entry_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '预入库时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:已删除',
  PRIMARY KEY (`device_pre_entry_id`),
  KEY `idx_imei` (`imei`),
  KEY `idx_mac` (`mac`),
  KEY `idx_sn` (`sn`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备预录入信息表';

-- ----------------------------
-- Table structure for lb_device_public
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_public`;
CREATE TABLE `lb_device_public` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备业务id',
  `module_factory_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '模组厂商类型(0-未知，1-移远，2-芯讯通)',
  `module_hardware` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '模组硬件版本号',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `sleep_status` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '睡眠模式状态 0正常模式 1 睡眠模式',
  `sleep_model` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '睡眠模块状态 0无模块 1有',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `ble_control_433_bind` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '是否支持蓝牙对码 -1设备默认配置，0不支持，1支持',
  `mqtt_control_433_bind` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '是否支持MQTT对码 -1设备默认配置，0不支持，1支持',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `sip_support` tinyint(4) NOT NULL DEFAULT '0' COMMENT 'sip功能是否支持，0不支持，1支持',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备通用属性表';

-- ----------------------------
-- Table structure for lb_device_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_report`;
CREATE TABLE `lb_device_report` (
  `iot_device_id` varchar(64) NOT NULL COMMENT '设备id（电信云平台注册返回）',
  `report_type` varchar(32) NOT NULL DEFAULT '' COMMENT '上报消息类型',
  `report_time` bigint(20) DEFAULT '0' COMMENT '上报时间',
  `push_status` tinyint(1) DEFAULT '0' COMMENT '推送状态，0未推送，1已推送',
  `send_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '发送类型',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_id`,`report_type`,`send_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备上报时间表';

