  `track_open_id` varchar(64) DEFAULT '' COMMENT '轨迹开启人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `heart_rate_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示心率数据，1显示，0不显示',
  `blood_pressure_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血压数据，1显示，0不显示',
  `blood_oxygen_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血氧数据，1显示，0不显示',
  `is_intact` tinyint(1) DEFAULT '0' COMMENT '当前数据是否完整，1完整，0,不完整',
  `device_status_is_show` tinyint(1) DEFAULT '1' COMMENT '是否显示佩戴状态 0不显示,1显示',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `use_type` tinyint(1) DEFAULT '1' COMMENT '记录用途类型，1查找长者,2查找设备',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `uncalibrated_day_num` int(11) DEFAULT NULL COMMENT '血压计未校准天数',
  `is_applets_measure` tinyint(1) DEFAULT '0' COMMENT '是否小程序测量值 0:否1:是',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `is_health_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `is_position_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `body_temperature_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示体温数据，1显示，0不显示',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `breath` int(3) DEFAULT '-1' COMMENT '呼吸值',
  `breath_is_show` tinyint(1) DEFAULT '0' COMMENT '呼吸数据是否显示（0-不显示，1-显示）',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `track_group_id` (`track_group_id`),
  KEY `iot_device_id` (`iot_device_id`),
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_device_server_version
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_server_version`;
CREATE TABLE `lb_device_server_version` (
  `version_id` varchar(64) NOT NULL COMMENT '主键',
  `version_code` varchar(255) DEFAULT '' COMMENT '版本号',
  `version_name` varchar(255) DEFAULT '' COMMENT '版本名称',
  `version_validate` tinyint(1) DEFAULT '0' COMMENT '是否是最新版本 0不是 1是',
  `version_update` mediumtext COMMENT '版本更新内容',
  `type` varchar(10) DEFAULT '' COMMENT '类型 1信标2按键3探头4门灯5发射小板6手表',
  `download_url` mediumtext COMMENT '下载地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `md_key` varchar(255) DEFAULT '' COMMENT 'md_key',
  `is_urgency` tinyint(4) DEFAULT '0' COMMENT '是否为紧急版本，1是，0否',
  `device_iteration_number` varchar(32) DEFAULT '0' COMMENT '设备迭代版本号',
  `is_support_upgrade` tinyint(1) DEFAULT '1' COMMENT '是否支持升级 0:否 1:是',
  `org_id` varchar(32) DEFAULT 'lonbon' COMMENT '所属项目id，lonbon为通用版本',
  `channel` tinyint(4) NOT NULL DEFAULT '0' COMMENT '渠道',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`version_id`),
  KEY `idx_type` (`org_id`,`type`,`version_validate`) USING BTREE,
  KEY `lb_device_server_version_version_name_index` (`version_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='NB设备软件版本记录表';

-- ----------------------------
-- Table structure for lb_device_sign_contact
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_sign_contact`;
CREATE TABLE `lb_device_sign_contact` (
  `contact_id` varchar(32) NOT NULL COMMENT '主键',
  `device_sign` varchar(32) NOT NULL DEFAULT '' COMMENT '设备标识',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `sign_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目标记主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `guardianship_center_fee` varchar(128) NOT NULL DEFAULT '' COMMENT '守护中心服务费用',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类，参见设备种类枚举',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contact_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备标识记录表';

-- ----------------------------
-- Table structure for lb_device_third_party_app
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_third_party_app`;
CREATE TABLE `lb_device_third_party_app` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `app_name` varchar(32) NOT NULL DEFAULT '' COMMENT '应用名称',
  `app_package_name` varchar(64) NOT NULL DEFAULT '' COMMENT '应用包名称',
  `app_icon_url` varchar(128) NOT NULL DEFAULT '' COMMENT '应用图标下载地址',
  `app_url` varchar(128) NOT NULL DEFAULT '' COMMENT '应用下载地址',
  `app_sign` varchar(128) NOT NULL DEFAULT '' COMMENT '应用签名',
  `app_md5` varchar(128) NOT NULL DEFAULT '' COMMENT '应用包md5值',
  `app_size_kb` int(11) NOT NULL DEFAULT '0' COMMENT '应用大小（kb）',
  `operator_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人id',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `operator_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '操作时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0否 1是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备第三方应用管理表';

-- ----------------------------
-- Table structure for lb_device_type_desc
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_type_desc`;
CREATE TABLE `lb_device_type_desc` (
  `device_type` tinyint(1) NOT NULL COMMENT '设备类型',
  `device_iteration_number` smallint(6) NOT NULL COMMENT '设备迭代版本号',
  `device_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `device_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_type`,`device_iteration_number`,`is_delete`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备类型描述配置表（已废弃，参见`lb_device_type_enum`表）';

-- ----------------------------
-- Table structure for lb_device_type_enum
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_type_enum`;
CREATE TABLE `lb_device_type_enum` (
  `device_type_enum_id` varchar(32) NOT NULL DEFAULT '',
  `device_type` smallint(1) NOT NULL COMMENT '设备类型',
  `device_iteration_number` smallint(6) NOT NULL COMMENT '设备迭代版本号',
  `device_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `device_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备描述',
  `is_wear` tinyint(1) NOT NULL DEFAULT '0' COMMENT '穿戴标识（0-固定设备，1-穿戴设备）',
  `is_send` tinyint(1) NOT NULL DEFAULT '0' COMMENT '下发标识（0-不下发，1-下发），用于护工手表',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `report_device_type` smallint(6) DEFAULT NULL COMMENT '上报设备类型',
  `report_device_model` tinyint(3) DEFAULT NULL COMMENT '上报设备型号',
  `device_model` varchar(16) NOT NULL DEFAULT '' COMMENT '设备型号',
  `is_call` tinyint(1) NOT NULL DEFAULT '0' COMMENT '通话标识（0-非通话设备，1-通话设备）',
  `power_supply_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '供电方式（1-内部电池，2-外部电源）',
  `heart_rate` tinyint(1) NOT NULL DEFAULT '0' COMMENT '心率（0-不支持，1-支持，2-动态(具体版本支持)）',
  `blood_pressure` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血压（0-不支持，1-支持，2-动态(具体版本支持)）',
  `blood_oxygen` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血氧（0-不支持，1-支持，2-动态(具体版本支持)）',
  `body_temperature` tinyint(1) NOT NULL DEFAULT '0' COMMENT '体温（0-不支持，1-支持，2-动态(具体版本支持)）',
  `breath` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼吸（0-不支持，1-支持，2-动态(具体版本支持)）',
  `blood_sugar` tinyint(1) NOT NULL DEFAULT '0' COMMENT '血糖（0-不支持，1-支持，2-动态(具体版本支持)）',
  `platform_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '设备平台类型',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `sleep` tinyint(1) NOT NULL DEFAULT '0' COMMENT '睡眠（0-不支持，1-支持，2-动态(具体版本支持)）',
  `away_home` tinyint(1) NOT NULL DEFAULT '0' COMMENT '离家（0-不支持，1-支持，2-动态(具体版本支持)）',
  `step_count` tinyint(1) NOT NULL DEFAULT '0' COMMENT '计步（0-不支持，1-支持，2-动态(具体版本支持)）',
  `in_bed` tinyint(1) NOT NULL DEFAULT '0' COMMENT '在床（0-不支持，1-支持，2-动态(具体版本支持)）',
  `enter_toilet` tinyint(1) NOT NULL DEFAULT '0' COMMENT '入厕（0-不支持，1-支持，2-动态(具体版本支持)）',
  `defecation` tinyint(1) NOT NULL DEFAULT '0' COMMENT '大解（0-不支持，1-支持，2-动态(具体版本支持)）',
  `nocturia` tinyint(1) NOT NULL DEFAULT '0' COMMENT '夜尿（0-不支持，1-支持，2-动态(具体版本支持)）',
  `device_model_online` varchar(16) NOT NULL DEFAULT '' COMMENT '线上设备型号',
  `is_push_alarm` tinyint(1) NOT NULL DEFAULT '0' COMMENT '报警推送标识（0-不推送，1-推送），用于报警推送配置',
  `show_power` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否显示电量(0:不显示  1:显示)',
  `show_status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否显示状态(0:不显示  1:显示)',
  `show_version` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否显示版本号(0:不显示  1:显示)',
  `show_custom_version` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否显示版本定制标识(0:不显示  1:显示)',
  `is_guardian` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否配置守护服务(0:否  1:是)',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `pressure` tinyint(1) NOT NULL DEFAULT '0' COMMENT '压力（0-不支持，1-支持，2-动态(具体版本支持)）',
  `electrocardiogram` tinyint(1) NOT NULL DEFAULT '0' COMMENT '心电（0-不支持，1-支持，2-动态(具体版本支持)）',
  `is_beacon_support` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否支持信标功能(0:不支持  1:支持)',
  `device_image_path` varchar(64) NOT NULL DEFAULT '' COMMENT '设备图片路径',
  `health_device_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '健康数据设备展示名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_pre_entry` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否需要预录入（0：不需要，1：需要）',
  PRIMARY KEY (`device_type_enum_id`),
  UNIQUE KEY `lb_device_type_enum_pk` (`device_category`,`device_iteration_number`,`position_type`),
  KEY `device_type_desc` (`device_type_desc`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备类型枚举表';

-- ----------------------------
-- Table structure for lb_device_vending_machine_ext
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_vending_machine_ext`;
CREATE TABLE `lb_device_vending_machine_ext` (
  `device_vending_machine_ext_id` varchar(64) NOT NULL COMMENT '设备扩展信息主键',
  `device_id` varchar(64) NOT NULL COMMENT '设备主键',
  `open_door_min_amount` double(10,2) NOT NULL DEFAULT '0.00' COMMENT '开门最低金额',
  `goods_shop_id` varchar(64) NOT NULL DEFAULT '' COMMENT '所属购物店铺id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除（0:否，1:是）',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_vending_machine_ext_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='自动售卖机设备扩展信息表';

-- ----------------------------
-- Table structure for lb_device_white_list_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_white_list_record`;
CREATE TABLE `lb_device_white_list_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `msisdn` varchar(64) NOT NULL DEFAULT '' COMMENT '卡号',
  `phone` varchar(32) NOT NULL COMMENT '变动号码',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '移动语音白名单配置类型： 1：新增 4：删除',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录状态 1未生效 2操作中 3 已生效',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_use` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否使用 0 未使用 1 使用中',
  `is_operable` tinyint(4) NOT NULL DEFAULT '1' COMMENT '当前是否可执行 0不可执行 1可执行',
  `account_id` varchar(32) NOT NULL COMMENT '账号id',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `relation_commdict_id` int(32) DEFAULT NULL COMMENT '关系描述字典表id',
  `account_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '白名单账号类型： 1：子女app用户 2:语音网关用户 3:网页编辑用户  4:客服坐席用户 5:来邦客服 6:三方客服',
  `order_num` varchar(64) NOT NULL DEFAULT '' COMMENT '操作订单号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE,
  KEY `status` (`status`) USING BTREE,
  KEY `msisdn` (`msisdn`) USING BTREE,
  KEY `is_use` (`is_use`),
  KEY `is_operable` (`is_operable`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备白名单变更记录表';

-- ----------------------------
-- Table structure for lb_device_white_sms_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_white_sms_record`;
CREATE TABLE `lb_device_white_sms_record` (
  `sms_record_id` varchar(32) NOT NULL COMMENT '主键',
  `terminal_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '主机sim卡号码',
  `sms_content` varchar(255) NOT NULL DEFAULT '' COMMENT '短息内容',
  `sms_receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '短信接收时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sms_record_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `terminal_phone` (`terminal_phone`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备白名单验证码短信记录';

-- ----------------------------
-- Table structure for lb_device_whitelist_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_device_whitelist_config`;
CREATE TABLE `lb_device_whitelist_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键ID',
  `config_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '配置类型，见枚举文档WhiteConfigTypeEnum',
  `name` varchar(128) NOT NULL DEFAULT '' COMMENT '名称（如：24小时呼叫中心）',
  `phone_number` varchar(32) NOT NULL DEFAULT '' COMMENT '电话号码',
  `display_name` varchar(128) NOT NULL DEFAULT '' COMMENT '来电显示名称描述',
  `gateway_ip` varchar(64) NOT NULL DEFAULT '' COMMENT '网关IP地址',
  `gateway_port` varchar(16) NOT NULL DEFAULT '' COMMENT '网关端口号',
  `priority_level` tinyint(4) NOT NULL DEFAULT '1' COMMENT '优先级顺序（1-最高优先级）',
  `is_active` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否启用 0不启用 1启用',
  `is_editable` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否可编辑，0否,1可编辑',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备白名单初始化配置表';

-- ----------------------------
-- Table structure for lb_disease
-- ----------------------------
DROP TABLE IF EXISTS `lb_disease`;
CREATE TABLE `lb_disease` (
  `disease_id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `disease_enumerate` varchar(32) DEFAULT '' COMMENT '枚举值',
  `disease_name` varchar(32) DEFAULT '' COMMENT '病名',
  `serial_num` int(11) DEFAULT '1' COMMENT '序号',
  `activated` tinyint(1) NOT NULL DEFAULT '0' COMMENT '病例激活,0激活，1非激活',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `default_status` tinyint(1) DEFAULT '0' COMMENT '默认状态 0 未勾选 1 勾选',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`disease_id`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COMMENT='疾病字典表';

-- ----------------------------
-- Table structure for lb_dispose_alarm_mode
-- ----------------------------
DROP TABLE IF EXISTS `lb_dispose_alarm_mode`;
CREATE TABLE `lb_dispose_alarm_mode` (
  `dispose_alarm_mode_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `mainframe_number` int(10) DEFAULT NULL COMMENT '主机号',
  `dispose_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '处理模式，0默认需要到现场长按3秒，1主机确认解除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最后更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`dispose_alarm_mode_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='主机处理报警模式';

-- ----------------------------
-- Table structure for lb_docking_platform
-- ----------------------------
DROP TABLE IF EXISTS `lb_docking_platform`;
CREATE TABLE `lb_docking_platform` (
  `docking_platform_id` varchar(32) NOT NULL COMMENT '主键',
  `docking_manufacturers_name` varchar(64) NOT NULL COMMENT '对接厂商',
  `docking_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '对接厂商类型 1 大华 2 萤石',
  `platform_name` varchar(64) NOT NULL COMMENT '平台名称',
  `platform_website` varchar(255) NOT NULL COMMENT '平台网址',
  `app_id` varchar(64) NOT NULL COMMENT '对接账号',
  `app_secret` varchar(100) NOT NULL COMMENT '账号密码',
  `synchronization_cycle` int(11) NOT NULL DEFAULT '5' COMMENT '同步周期(分钟)',
  `is_connect` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否连接 0 未连接 1 已连接',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `token` varchar(100) DEFAULT NULL COMMENT '管理员token',
  `token_time` bigint(20) DEFAULT '0' COMMENT 'token过期时间',
  `is_synchro` bigint(1) NOT NULL DEFAULT '0' COMMENT '是否启用连接 0 未启用 1 启用',
  `last_dock_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上一次对接同步时间',
  `app_algorithm_cipher` text COMMENT '视频对接密钥',
  `additional_information` text NOT NULL COMMENT '附加信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`docking_platform_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管对接平台表';

-- ----------------------------
-- Table structure for lb_doctor
-- ----------------------------
DROP TABLE IF EXISTS `lb_doctor`;
CREATE TABLE `lb_doctor` (
  `doctor_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `description` varchar(32) DEFAULT '' COMMENT '描述',
  `gender` varchar(32) DEFAULT '' COMMENT '性别 1男2女',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `photo` varchar(128) DEFAULT '' COMMENT '照片',
  `department` varchar(32) DEFAULT '' COMMENT '科室',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `entry_time` bigint(20) DEFAULT '0' COMMENT '入职时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '是否离职 1在职2离职',
  `phone_num` varchar(11) DEFAULT '' COMMENT '手机号',
  `dimission_time` bigint(20) DEFAULT '0' COMMENT '离职时间',
  `code` varchar(32) DEFAULT '' COMMENT '编号',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`doctor_id`),
  KEY `lb_doctor_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_doctor_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_doctor_care_object`;
CREATE TABLE `lb_doctor_care_object` (
  `doctor_care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `doctor_name` varchar(32) DEFAULT NULL COMMENT '医生姓名',
  `doctor_id` varchar(32) DEFAULT '' COMMENT '医生id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`doctor_care_object_id`),
  KEY `doctor_id` (`doctor_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_drug_frequency
-- ----------------------------
DROP TABLE IF EXISTS `lb_drug_frequency`;
CREATE TABLE `lb_drug_frequency` (
  `drug_frequency_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用药频次id',
  `frequency_name` varchar(64) NOT NULL DEFAULT '' COMMENT '用药频次名称',
  `frequency_short_name` varchar(32) NOT NULL DEFAULT '' COMMENT '用药频次简称',
  `frequency` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用药频次数，单位天',
  `interval_days` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用药间隔天数',
  `frequency_time` varchar(255) NOT NULL DEFAULT '' COMMENT '用药时间，格式：HH:mm|HH:mm',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认配置 0否1是',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) CHARACTER SET utf8mb4 NOT NULL DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_frequency_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='用药频次表';

-- ----------------------------
-- Table structure for lb_dueros
-- ----------------------------
DROP TABLE IF EXISTS `lb_dueros`;
CREATE TABLE `lb_dueros` (
  `dueros_id` varchar(32) NOT NULL COMMENT '主键',
  `sn_number` varchar(32) NOT NULL COMMENT 'sn号',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `device_type` int(4) NOT NULL DEFAULT '113' COMMENT '设备类型',
  `position_desc` varchar(255) NOT NULL COMMENT '安装位置',
  `device_iteration_number` varchar(10) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `call_address` varchar(200) DEFAULT NULL COMMENT '呼叫地址',
  `call_appid` varchar(100) DEFAULT NULL,
  `number` varchar(32) DEFAULT NULL COMMENT '设备号',
  `online_status` tinyint(1) DEFAULT NULL COMMENT '是否在线:　1在线　, 0不在线',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `area_id` varchar(32) NOT NULL COMMENT '房间id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`dueros_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='小度智能屏设备';

-- ----------------------------
-- Table structure for lb_elder_subsidy_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_elder_subsidy_type`;
CREATE TABLE `lb_elder_subsidy_type` (
  `elder_subsidy_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `subsidy_type_setting_id` varchar(32) NOT NULL DEFAULT '' COMMENT '补贴类型id',
  `subsidy_name` varchar(32) NOT NULL DEFAULT '' COMMENT '补贴名称',
  `status` tinyint(1) NOT NULL DEFAULT '3' COMMENT '助餐补贴类型审核状态 1 待审核 2 审核失败 3 审核通过',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_apply` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为申请助餐长者 1 是 0 否',
  `apply_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '申请所属机构id',
  `reject_reason` varchar(128) NOT NULL COMMENT '审核驳回原因',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elder_subsidy_type_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `subsidy_type_setting_id_IDX` (`subsidy_type_setting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='民政长者助餐补贴类型';

-- ----------------------------
-- Table structure for lb_elderly_care_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_elderly_care_config`;
CREATE TABLE `lb_elderly_care_config` (
  `elderly_care_config_id` varchar(32) NOT NULL COMMENT '主键',
  `elderly_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `care_config_type` tinyint(1) DEFAULT '0' COMMENT '监护类型 1 卫生间滞留 2 在床不动 3 久坐不动 4 活动检测 8洗手间长时间不动 9长时间不动',
  `is_care` tinyint(1) DEFAULT '0' COMMENT '1  开启  2  关闭',
  `delay` int(11) DEFAULT '0' COMMENT '时间',
  `care_time` mediumtext COMMENT '关注时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `work_pattern` tinyint(1) DEFAULT '1' COMMENT '工作模式 1 普通模式 2 防丢模式',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`elderly_care_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_electrocardiogram_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_electrocardiogram_record_statistics`;
CREATE TABLE `lb_electrocardiogram_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录结束时间',
  `content` text COMMENT '心电数据',
  `record_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '记录类型（1 日常，2 轨迹，3 心电设备测量, 4 实时守护, 5 报警测量, 6 主动测量）',
  `record_time_date` datetime NOT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `lb_electrocardiogram_record_statistics_update_time_IDX` (`update_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='心电记录统计表';

-- ----------------------------
-- Table structure for lb_electrocardiogram_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_electrocardiogram_report`;
CREATE TABLE `lb_electrocardiogram_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `total_times` int(11) NOT NULL DEFAULT '0' COMMENT '心电总次数',
  `sinus_heart_times` int(11) NOT NULL DEFAULT '0' COMMENT '窦性心率次数',
  `atrial_fibrillation_times` int(11) NOT NULL DEFAULT '0' COMMENT '房颤次数',
  `tachycardia_times` int(11) NOT NULL DEFAULT '0' COMMENT '心率过速次数',
  `premature_beat_times` int(11) NOT NULL DEFAULT '0' COMMENT '早博次数',
  `unknow_times` int(11) NOT NULL DEFAULT '0' COMMENT '不确定次数',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='心电报表';

-- ----------------------------
-- Table structure for lb_electronic_fence
-- ----------------------------
DROP TABLE IF EXISTS `lb_electronic_fence`;
CREATE TABLE `lb_electronic_fence` (
  `fence_id` varchar(32) NOT NULL COMMENT '主键',
  `fence_name` varchar(255) DEFAULT '' COMMENT '围栏名称',
  `fence_type` tinyint(1) DEFAULT '0' COMMENT '围栏类型 ',
  `fence_start_time` varchar(64) DEFAULT '' COMMENT '围栏开始时间',
  `fence_end_time` varchar(64) DEFAULT '' COMMENT '围栏关闭时间',
  `fence_set_type` tinyint(1) DEFAULT '0' COMMENT '围栏设置方式 1 圆形 2 多边形',
  `fence_distance` varchar(32) DEFAULT '' COMMENT '围栏半径',
  `fence_content` text COMMENT '围栏内容',
  `is_enable` tinyint(1) DEFAULT '1' COMMENT '围栏是否启用 0 未启用 1 启用',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者唯一标识',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `delay_time` int(11) DEFAULT '0' COMMENT '触发后报警延迟时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`fence_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='电子围栏表';

-- ----------------------------
-- Table structure for lb_electronic_fence_delay_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_electronic_fence_delay_record`;
CREATE TABLE `lb_electronic_fence_delay_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `device_type` int(11) NOT NULL COMMENT '设备类型',
  `content` text COMMENT '报警内容',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `delay_alarm_time` bigint(20) DEFAULT '0' COMMENT '报警延迟触发时间点',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='电子围栏触发延时记录';

-- ----------------------------
-- Table structure for lb_emergency_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_emergency_contacts`;
CREATE TABLE `lb_emergency_contacts` (
  `emergency_contacts_id` varchar(32) NOT NULL COMMENT '主键',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭id',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `contacts_name` varchar(128) DEFAULT NULL,
  `contacts_phone` varchar(32) DEFAULT '' COMMENT '联系方式',
  `contacts_relation` varchar(32) DEFAULT '' COMMENT '关系',
  `address` varchar(32) DEFAULT '' COMMENT '住址',
  `distance` int(11) NOT NULL DEFAULT '0' COMMENT '与老人距离（单位：米）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_guardian` tinyint(1) DEFAULT NULL COMMENT '是否是监护人,0不是，1是',
  `identity` varchar(32) DEFAULT NULL COMMENT '身份证',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` varchar(32) DEFAULT NULL COMMENT '生日,计算年龄',
  `is_local` tinyint(1) DEFAULT NULL COMMENT '是否本地户籍',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `region` varchar(255) DEFAULT '' COMMENT '省市区',
  `telephone` varchar(30) DEFAULT NULL COMMENT '固定电话',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`emergency_contacts_id`),
  KEY `family_id` (`family_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `is_delete` (`is_delete`),
  KEY `idx_contacts_phone` (`contacts_phone`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_empty_number_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_empty_number_record`;
CREATE TABLE `lb_empty_number_record` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `contact_id` varchar(64) NOT NULL DEFAULT '' COMMENT '联系人主键',
  `contact_name` varchar(64) NOT NULL DEFAULT '' COMMENT '联系人姓名',
  `contact_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '联系人类型（参见联系人类型枚举）',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '电话号码',
  `last_call_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '前次呼叫时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `phone_num` (`phone_num`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='空号记录表';

-- ----------------------------
-- Table structure for lb_event_additional_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_event_additional_info`;
CREATE TABLE `lb_event_additional_info` (
  `alarm_id` varchar(32) NOT NULL COMMENT '事件标识',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构标识',
  `device_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '设备号码',
  `additional_content` text NOT NULL COMMENT '附加内容',
  `session_id` varchar(128) NOT NULL DEFAULT '' COMMENT '事件会话标识（对讲设备事件有效）',
  `event_code` int(11) NOT NULL DEFAULT '0' COMMENT '事件编码（对讲设备事件有效）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `code_system` tinyint(1) NOT NULL DEFAULT '0' COMMENT '编码系统（0-养老，其他参见lb_event_code_system）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`alarm_id`),
  KEY `session_id` (`session_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='事件附加信息表';

-- ----------------------------
-- Table structure for lb_event_category_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_event_category_config`;
CREATE TABLE `lb_event_category_config` (
  `event_category` smallint(6) NOT NULL COMMENT '事件类别',
  `event_type` smallint(6) NOT NULL COMMENT '事件类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`event_category`,`event_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='事件类别配置表';

-- ----------------------------
-- Table structure for lb_event_code_system
-- ----------------------------
DROP TABLE IF EXISTS `lb_event_code_system`;
CREATE TABLE `lb_event_code_system` (
  `code_system` tinyint(1) NOT NULL COMMENT '编码系统（1-对讲）',
  `event_code` int(11) NOT NULL COMMENT '事件编码',
  `event_code_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '事件编码描述',
  `event_type` smallint(6) NOT NULL DEFAULT '0' COMMENT '事件类型',
  `event_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '事件状态（1-开始，2-取消，3-过程，4-结束）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `receive_alarm_terminal` bigint(20) NOT NULL DEFAULT '0' COMMENT '接警终端（终端类型位掩码）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`code_system`,`event_code`),
  KEY `event_type` (`event_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='事件编码系统（已弃用旧表，新表：lb_event_convert_config）';

-- ----------------------------
-- Table structure for lb_event_convert_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_event_convert_config`;
CREATE TABLE `lb_event_convert_config` (
  `source_event_system` tinyint(1) NOT NULL COMMENT '源事件系统（详见枚举文档）',
  `source_event_type` int(11) NOT NULL COMMENT '源事件类型',
  `source_event_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '源事件类型描述',
  `source_event_status` int(11) NOT NULL DEFAULT '-1' COMMENT '源事件状态',
  `source_event_status_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '源事件状态描述',
  `target_event_system` tinyint(1) NOT NULL COMMENT '目标事件系统',
  `target_event_type` int(11) NOT NULL COMMENT '目标事件类型',
  `target_event_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '目标事件类型描述',
  `target_event_status` int(11) NOT NULL DEFAULT '-1' COMMENT '目标事件状态',
  `target_event_status_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '目标事件状态描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`source_event_system`,`source_event_type`,`source_event_status`,`target_event_system`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='事件转换配置表';

-- ----------------------------
-- Table structure for lb_event_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_event_record`;
CREATE TABLE `lb_event_record` (
  `event_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `care_object_name` varchar(128) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `event_type` tinyint(1) NOT NULL COMMENT '事件类型',
  `event_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '事件描述',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '事件状态（1-待处理，3-处理中，4-处理完成）',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域主键',
  `bed_id` varchar(32) NOT NULL DEFAULT '' COMMENT '床位主键',
  `lgt` varchar(32) NOT NULL DEFAULT '' COMMENT '经度',
  `lat` varchar(32) NOT NULL DEFAULT '' COMMENT '纬度',
  `coordsys` tinyint(1) DEFAULT NULL COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `position_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '位置描述',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台设备标识',
  `device_type` tinyint(3) NOT NULL COMMENT '设备类型',
  `device_iteration_number` int(11) NOT NULL COMMENT '设备迭代版本号',
  `power` tinyint(3) NOT NULL COMMENT '设备电量',
  `device_phone` varchar(32) DEFAULT '' COMMENT '设备号码',
  `device_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '设备类型描述',
  `mainframe_num` varchar(32) NOT NULL DEFAULT '' COMMENT '主机号',
  `dispose_account_id` varchar(32) DEFAULT '' COMMENT '处理人标识',
  `dispose_type` tinyint(3) DEFAULT NULL COMMENT '处理类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `dispose_account_name` varchar(32) DEFAULT '' COMMENT '处理人姓名',
  `dispose_account_type` tinyint(1) DEFAULT NULL COMMENT '处理人类型',
  `report_device_type` tinyint(3) NOT NULL COMMENT '上报设备类型',
  `device_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac',
  `gather_people` text COMMENT '聚集人员（聚集提醒有效）',
  `gps_is_detail` tinyint(1) NOT NULL DEFAULT '0' COMMENT '定位类型',
  `track_id` varchar(64) NOT NULL DEFAULT '' COMMENT '轨迹主键',
  `session_id` varchar(255) NOT NULL DEFAULT '' COMMENT '事件会话标识',
  `event_code` int(11) NOT NULL DEFAULT '0' COMMENT '事件编码',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`event_id`),
  KEY `care_object_id` (`care_object_id`,`event_type`,`status`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`,`event_type`,`status`) USING BTREE,
  KEY `org_id` (`org_id`,`status`,`event_type`) USING BTREE,
  KEY `device_mac` (`device_mac`,`event_type`,`status`) USING BTREE,
  KEY `session_id` (`session_id`(191)) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='事件记录表';

-- ----------------------------
-- Table structure for lb_export_history
-- ----------------------------
DROP TABLE IF EXISTS `lb_export_history`;
CREATE TABLE `lb_export_history` (
  `export_history_id` varchar(32) NOT NULL COMMENT '主键',
  `url` varchar(255) NOT NULL DEFAULT '' COMMENT '路径',
  `method` varchar(32) NOT NULL DEFAULT '' COMMENT '方法',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `oper_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '操作类型 0导出/1导入',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`export_history_id`),
  KEY `idx_url` (`url`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='记录导出历史表';

-- ----------------------------
-- Table structure for lb_face_charge_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_face_charge_device`;
CREATE TABLE `lb_face_charge_device` (
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `device_name` varchar(32) NOT NULL DEFAULT '' COMMENT '设备名称',
  `merchant_code` varchar(32) NOT NULL DEFAULT '' COMMENT '商户号',
  `device_num` varchar(32) NOT NULL DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac号',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属商店',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '设备状态 1 可用 2 不可用',
  `install_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '安装时间',
  `store_id` int(11) NOT NULL DEFAULT '1' COMMENT '门店店铺id（对接点餐机，要求id必须是数字，通过food_shop_id关联）',
  `is_init_face` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否初始化设备人脸信息 1 初始化 0 正常',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`),
  KEY `mac_IDX` (`mac`) USING BTREE,
  KEY `imei_IDX` (`imei`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会员面部识别扣费设备';

-- ----------------------------
-- Table structure for lb_factory_band
-- ----------------------------
DROP TABLE IF EXISTS `lb_factory_band`;
CREATE TABLE `lb_factory_band` (
  `band_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `iccid` varchar(64) DEFAULT '' COMMENT 'nb卡号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`band_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='静态资源表';

-- ----------------------------
-- Table structure for lb_factory_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_factory_device`;
CREATE TABLE `lb_factory_device` (
  `factory_device_id` varchar(64) NOT NULL COMMENT '工厂测试设备主键',
  `mac` varchar(32) DEFAULT '',
  `imei` varchar(32) DEFAULT '',
  `device_type` tinyint(3) DEFAULT '1' COMMENT '1:按钮 2:手表',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置叙述',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '电信平台id',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '应用id',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `org_id` varchar(64) DEFAULT '' COMMENT '组织机构唯一标识',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `production_line` varchar(32) DEFAULT '' COMMENT '生产线',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`factory_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工厂测试设备表';

-- ----------------------------
-- Table structure for lb_failed_request_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_failed_request_record`;
CREATE TABLE `lb_failed_request_record` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `business` varchar(64) NOT NULL DEFAULT '' COMMENT '所属业务标示/方法名',
  `url` text NOT NULL COMMENT '请求url',
  `param` json DEFAULT NULL COMMENT '请求参数JSON/方法调用参数',
  `is_enabled` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否需要执行 0:无需执行 1：需要执行',
  `failed_response` text NOT NULL COMMENT '调用失败出参',
  `retry_count` tinyint(1) NOT NULL DEFAULT '0' COMMENT '重试次数',
  `retry_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上次重试时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `header` json DEFAULT NULL COMMENT '请求头',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `lb_failed_request_record_business_IDX` (`business`,`is_enabled`,`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='业务请求失败需重试记录表';

-- ----------------------------
-- Table structure for lb_fall_alarm_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_fall_alarm_data`;
CREATE TABLE `lb_fall_alarm_data` (
  `data_id` varchar(32) NOT NULL COMMENT '主键',
  `svm_down_time` int(3) DEFAULT NULL COMMENT 'SVM下降次数',
  `variation_index_change_time` int(3) DEFAULT NULL COMMENT '变异指数改变次数',
  `fall_direction` int(3) DEFAULT NULL COMMENT '跌倒方向',
  `fall_interval` int(3) DEFAULT NULL COMMENT '跌倒时间间隔',
  `svm_min` int(3) DEFAULT NULL COMMENT 'SVM达到最小值',
  `variation_index_change_num` varchar(32) DEFAULT NULL COMMENT '变异指数具体值',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`data_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='跌倒报警数据记录表（仅调试使用）';

-- ----------------------------
-- Table structure for lb_family
-- ----------------------------
DROP TABLE IF EXISTS `lb_family`;
CREATE TABLE `lb_family` (
  `family_id` varchar(64) NOT NULL COMMENT '主键',
  `family_name` varchar(128) DEFAULT NULL COMMENT '家庭名字',
  `family_desc` varchar(32) DEFAULT '' COMMENT '叙述',
  `family_phone` varchar(16) NOT NULL DEFAULT '' COMMENT '家庭手机号码',
  `family_region_desc` varchar(255) NOT NULL DEFAULT '' COMMENT '家庭现居住区域描述',
  `family_region_id` varchar(255) NOT NULL DEFAULT '' COMMENT '家庭现居住区域id',
  `family_address` varchar(255) NOT NULL DEFAULT '' COMMENT '家庭现居住详细地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `at_home` tinyint(1) DEFAULT '1' COMMENT '是否有老人在家，1是，0否',
  `out_home_time` bigint(20) DEFAULT '0' COMMENT '最近一次离家时间',
  `wifi_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '家庭wifi地址',
  `wifi_name` varchar(32) NOT NULL DEFAULT '' COMMENT '家庭wifi名称',
  `heart_alarm_model` tinyint(2) DEFAULT NULL COMMENT '心率异常报警模式（失效）',
  `account_id` varchar(32) DEFAULT NULL COMMENT '管理员账号id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`family_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_family_account_push_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_account_push_record`;
CREATE TABLE `lb_family_account_push_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `record_content` mediumtext COMMENT '推送信息内容',
  `record_time` bigint(20) DEFAULT '0' COMMENT '推送时间',
  `record_type` tinyint(1) DEFAULT '0' COMMENT '0，报警相关信息',
  `push_account_id` varchar(64) DEFAULT '' COMMENT '推送的用户id（客服id）',
  `push_account_type` tinyint(1) DEFAULT '0' COMMENT '推送人类型（客服）',
  `receive_account_id` varchar(64) DEFAULT NULL COMMENT '接收人id（app用户id）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_family_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_contacts`;
CREATE TABLE `lb_family_contacts` (
  `family_contacts_id` varchar(32) NOT NULL COMMENT '主键',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `name` varchar(128) DEFAULT '' COMMENT '姓名',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭id',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `is_admin` tinyint(1) DEFAULT '3' COMMENT '1 超级管理员 2 二级管理员 3 普通成员',
  `account_id` varchar(32) DEFAULT NULL COMMENT '账号id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`family_contacts_id`),
  KEY `account_id` (`account_id`),
  KEY `family_id` (`family_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='关注人列表';

-- ----------------------------
-- Table structure for lb_family_contacts_apply_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_contacts_apply_record`;
CREATE TABLE `lb_family_contacts_apply_record` (
  `apply_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `care_object_photo` varchar(255) DEFAULT '' COMMENT '头像',
  `contacts_account_id` varchar(32) DEFAULT '' COMMENT '申请人账号id',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系描述',
  `contacts_phone` varchar(32) DEFAULT '' COMMENT '联系人电话',
  `status` tinyint(4) DEFAULT '1' COMMENT '记录状态，1等待处理，2已接受，3已拒绝',
  `dispose_account_id` varchar(32) DEFAULT '' COMMENT '处理人id',
  `dispose_account_name` varchar(32) DEFAULT NULL COMMENT '处理人名字',
  `dispose_account_type` tinyint(4) DEFAULT '0' COMMENT '处理人类型',
  `dispose_time` bigint(20) DEFAULT '0' COMMENT '处理事件',
  `apply_time` bigint(20) DEFAULT '0' COMMENT '申请时间',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭组id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `contacts_account_name` varchar(32) DEFAULT '' COMMENT '联系人账户',
  `care_object_name` varchar(32) DEFAULT '' COMMENT '老人姓名',
  `contacts_photo` varchar(255) DEFAULT '' COMMENT '联系人头像',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`apply_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='家庭圈成员申请记录表;';

-- ----------------------------
-- Table structure for lb_family_feedback
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_feedback`;
CREATE TABLE `lb_family_feedback` (
  `feedback_id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `opinion` mediumtext COMMENT '意见内容',
  `photo_one` varchar(128) DEFAULT '' COMMENT '意见反馈图片一',
  `photo_two` varchar(128) DEFAULT '' COMMENT '意见反馈图片二',
  `photo_three` varchar(128) DEFAULT '' COMMENT '意见反馈图片三',
  `photo_four` varchar(128) DEFAULT '' COMMENT '意见反馈图片四',
  `photo_five` varchar(128) DEFAULT '' COMMENT '意见反馈图片五',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型，0:安卓，1：iOS',
  `device_model` varchar(32) DEFAULT '' COMMENT '设备型号',
  `device_version` varchar(32) DEFAULT '' COMMENT '设备系统版本号',
  `name` varchar(32) DEFAULT '' COMMENT '反馈人姓名',
  `telephone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `app_version` varchar(32) DEFAULT '' COMMENT 'app版本号',
  `status` varchar(32) DEFAULT '' COMMENT '反馈信息状态',
  `reply_result` mediumtext COMMENT '反馈结果',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '反馈信息更新时间',
  `app_type` tinyint(1) DEFAULT '1' COMMENT 'app类型，1子女app，14护工app，15医生app',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '账号主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`feedback_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2306 DEFAULT CHARSET=utf8mb4 COMMENT='子女app意见反馈表';

-- ----------------------------
-- Table structure for lb_family_member
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_member`;
CREATE TABLE `lb_family_member` (
  `member_id` varchar(32) NOT NULL COMMENT '主键',
  `username` varchar(32) DEFAULT '' COMMENT 'APP账号',
  `password` varchar(32) DEFAULT '' COMMENT 'APP密码',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `description` varchar(32) DEFAULT '' COMMENT '描述',
  `photo` varchar(128) DEFAULT '' COMMENT 'app头像（照片）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `gender` tinyint(1) DEFAULT '1' COMMENT '1  男 2女',
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`member_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='手环用户家属信息';

-- ----------------------------
-- Table structure for lb_family_member_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_member_relation`;
CREATE TABLE `lb_family_member_relation` (
  `relation_id` varchar(32) NOT NULL COMMENT '主键',
  `member_username` varchar(32) DEFAULT '' COMMENT '家属id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '家庭id',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系叙述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_admin` tinyint(1) DEFAULT '3' COMMENT '1  是超级管理员    2   普通管理员 ，3不是管理员',
  `care_object_photo` varchar(128) DEFAULT '' COMMENT '老人头像',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='家属关系表';

-- ----------------------------
-- Table structure for lb_family_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_family_relation`;
CREATE TABLE `lb_family_relation` (
  `family_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `family_contacts_id` varchar(32) DEFAULT '' COMMENT '关注人id',
  `care_object_photo` varchar(128) DEFAULT '' COMMENT '头像',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `family_id` varchar(32) DEFAULT '' COMMENT '家庭id',
  `is_admin` tinyint(1) DEFAULT '3' COMMENT '1 超级管理员 2 二级管理员 3 普通成员',
  `account_id` varchar(32) DEFAULT NULL COMMENT '账号id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`family_relation_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `lb_family_relation_family_id_index` (`family_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_faq
-- ----------------------------
DROP TABLE IF EXISTS `lb_faq`;
CREATE TABLE `lb_faq` (
  `faq_id` varchar(32) NOT NULL COMMENT '主键',
