  PRIMARY KEY (`faq_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_fee_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_account`;
CREATE TABLE `lb_fee_account` (
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用户类型：0 长者 1 员工 2 其他',
  `balance` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '余额',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '账户类型：1 账户余额 2 一卡通 3 押金 4 代金券 5 现金',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态:1 激活 2 注销',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用账户表';

-- ----------------------------
-- Table structure for lb_fee_account_consume_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_account_consume_record`;
CREATE TABLE `lb_fee_account_consume_record` (
  `account_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '老人入住编号',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用户类型：0 长者 1 员工 2 其他',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `before_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更前余额',
  `amount` decimal(32,2) DEFAULT '0.00' COMMENT '变更金额',
  `after_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更后余额',
  `register_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人-运营账号id',
  `register_name` varchar(128) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `consume_account_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '账户类型：（1：普通账户余额 2:一卡通账户 3:医疗保证金账户 4:风险保证金账户 5:线下(外部)账户）',
  `consume_account_pattern` varchar(32) NOT NULL DEFAULT '' COMMENT '账户消费方式（ 0:未知 1：账户余额 2:一卡通 3:医疗保证金 4:风险保证金 5:现金 6:银行卡 7:支付宝 8:微信）',
  `consume_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费时间',
  `remark` text COMMENT '备注',
  `refund_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退费状态:0:未退费 1:退费成功 2:退费失败',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费状态:1 消费成功 2:消费失败',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联业务记录主键（费用账单、点餐、购物）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `bank_id` varchar(32) NOT NULL DEFAULT '' COMMENT '银行主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `fee_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '账户id',
  PRIMARY KEY (`account_record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`),
  KEY `consume_account_type_index` (`consume_account_type`) USING BTREE,
  KEY `consume_time_index` (`consume_time`) USING BTREE,
  KEY `object_type_index` (`object_type`) USING BTREE,
  KEY `relation_id_index` (`relation_id`) USING BTREE,
  KEY `fee_account_id_index` (`fee_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用账户消费流水记录表';

