-- ----------------------------
-- Table structure for lb_fee_account_kingdee_sync_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_account_kingdee_sync_record`;
CREATE TABLE `lb_fee_account_kingdee_sync_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '业务关联id',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '对接类型：1:长者（客户）信息对接 2:应收单对接 3:退款单对接',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态:1 成功 2 失败 0 未知',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `req_param` text COMMENT '接口请求参数',
  `res_param` text COMMENT '接口返回参数',
  `remark` text COMMENT '备注',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用账户同步对接金蝶记录';

-- ----------------------------
-- Table structure for lb_fee_account_recharge_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_account_recharge_record`;
CREATE TABLE `lb_fee_account_recharge_record` (
  `account_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用户类型：0 长者 1 员工 2 其他',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `before_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更前余额',
  `amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更金额',
  `recharge_name` varchar(128) NOT NULL DEFAULT '' COMMENT '缴费人',
  `after_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更后余额',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人-运营账号id',
  `register_name` varchar(128) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `recharge_account_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '缴费账户类型：（1：普通账户 2:一卡通账户 3:医疗保证金账户 4:风险保证金账户）',
  `record_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '费用余额账户变更记录类型(0:未知 1:缴费充值 2:退费充值)',
  `recharge_pattern` int(10) NOT NULL DEFAULT '0' COMMENT '缴费方式（见字典数据）',
  `refund_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '该条充值记录已退金额',
  `recharge_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '缴费时间',
  `remark` text COMMENT '备注',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '充值状态:0 未知 1:成功  2:失败  3：作废 ',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `bank_id` varchar(32) NOT NULL DEFAULT '' COMMENT '银行主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `fee_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '账户id',
  PRIMARY KEY (`account_record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`),
  KEY `register_id_index` (`register_id`) USING BTREE,
  KEY `fee_account_id_index` (`fee_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用账户充值流水记录表';

-- ----------------------------
-- Table structure for lb_fee_account_refund_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_account_refund_record`;
CREATE TABLE `lb_fee_account_refund_record` (
  `account_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用户类型：0 长者 1 员工 2 其他',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '退费金额',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人-运营账号id',
  `register_name` varchar(128) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `refund_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退款类型（0:未知 1:账户退款 2:订单/账单交易退款 3.充值记录退费）',
  `refund_account_type` tinyint(1) NOT NULL COMMENT '退款账户类型：（1：普通账户 2:一卡通账户 3:医疗保证金账户 4:风险保证金账户 ）',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '退款来源业务数据',
  `refund_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '退费时间',
  `remark` text COMMENT '备注',
  `refund_tag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退费标识: 1:全退 2:部分退',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '退费状态:1:退款成功 2:退款失败 ',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `refund_account_pattern` int(11) NOT NULL DEFAULT '0' COMMENT '退款方式',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `fee_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '费用账户id',
  PRIMARY KEY (`account_record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`),
  KEY `register_id_index` (`register_id`) USING BTREE,
  KEY `fee_account_id_index` (`fee_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用账户退费流水记录表';

-- ----------------------------
-- Table structure for lb_fee_bill_generate
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_bill_generate`;
CREATE TABLE `lb_fee_bill_generate` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者、员工',
  `generate_time` bigint(20) DEFAULT '0' COMMENT '生成账单时间',
  `bill_time` bigint(20) DEFAULT '0' COMMENT '账单月份',
  `bill_info` text COMMENT '生成账单信息',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态:0 未生成 1:已生成',
  `check_in_month` tinyint(1) DEFAULT '0' COMMENT '是否入住缴费月账单:0 不是 1:是',
  `lock_bill` tinyint(1) DEFAULT '0' COMMENT '月账单是否锁定:0 不是 1:是',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人-账号id',
  `register_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `register_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='月度账单生成记录表';

