-- ----------------------------
-- Table structure for lb_fee_bill_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_fee_bill_record`;
CREATE TABLE `lb_fee_bill_record` (
  `bill_record_id` varchar(32) NOT NULL DEFAULT '0.00' COMMENT '主键',
  `object_id` varchar(32) NOT NULL COMMENT '用户主键',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用户类型：0 长者 1 员工 2 其他',
  `type` tinyint(1) DEFAULT '1' COMMENT '记录类型:1 消费 2:退费',
  `relation_id` varchar(64) NOT NULL COMMENT '关联业务主键',
  `expense_id` varchar(32) NOT NULL COMMENT '主键',
  `expense_name` varchar(32) NOT NULL COMMENT '费用名称',
  `expense_category` int(11) DEFAULT '1' COMMENT '费用类别',
  `expense_nature` tinyint(1) DEFAULT '1' COMMENT '计费方式',
  `amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '费用金额',
  `fixed_return_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '固定退费金额',
  `return_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '退费金额',
  `discount_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '优惠金额',
  `bill_time` bigint(20) DEFAULT '0' COMMENT '账单月份',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `time_info` varchar(32) NOT NULL COMMENT '费用发生时间段',
  `adjust_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '手动调整金额',
  `adjust_amount_remark` varchar(512) NOT NULL COMMENT '手动调整金额备注',
  `remark` text NOT NULL COMMENT '备注',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态:1 未缴费 2:已缴费',
  `settlement_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '缴费、退费时间',
  `return_type` tinyint(1) unsigned NOT NULL DEFAULT '0' COMMENT '退费类型，1外出退费',
  `register_id` varchar(64) NOT NULL COMMENT '登记人-账号id',
  `register_name` varchar(128) NOT NULL COMMENT '登记人名称',
  `register_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `check_in_num` varchar(32) NOT NULL COMMENT '入住编号',
  `org_id` varchar(32) NOT NULL COMMENT '项目主键',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`bill_record_id`),
  KEY `org_id_index` (`org_id`),
  KEY `object_id_index` (`object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='账单记录表';

