  `id` varchar(32) NOT NULL DEFAULT '',
  `feedback_id` varchar(32) NOT NULL DEFAULT '' COMMENT '反馈表id',
  `info_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '信息类型(0:反馈 1:处理)',
  `info_content` text NOT NULL COMMENT '信息内容',
  `handle_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人id',
  `handle_account_name` varchar(16) NOT NULL DEFAULT '' COMMENT '操作人姓名',
  `handle_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处理时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `feedback_id_index` (`feedback_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='反馈信息表';

-- ----------------------------
-- Table structure for lb_feedback_info_annex
-- ----------------------------
DROP TABLE IF EXISTS `lb_feedback_info_annex`;
CREATE TABLE `lb_feedback_info_annex` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `feedback_info_id` varchar(32) NOT NULL DEFAULT '' COMMENT '反馈信息id',
  `annex_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '附件类型(0:图片 1:视频)',
  `annex_content` text NOT NULL COMMENT '附件内容',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `feedback_info_id_index` (`feedback_info_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='反馈信息附件表';

-- ----------------------------
-- Table structure for lb_feedback_reply
-- ----------------------------
DROP TABLE IF EXISTS `lb_feedback_reply`;
CREATE TABLE `lb_feedback_reply` (
  `reply_id` varchar(64) NOT NULL COMMENT '回复记录id',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '账号主键',
  `feedback_id` varchar(32) NOT NULL DEFAULT '' COMMENT '上报消息类型',
  `content` varchar(100) NOT NULL DEFAULT '' COMMENT '回复结果',
  `read_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '阅读状态，0未读，1已读',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `name` varchar(32) DEFAULT '' COMMENT '回复人描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`reply_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='反馈回复记录表';

-- ----------------------------
-- Table structure for lb_file_library
-- ----------------------------
DROP TABLE IF EXISTS `lb_file_library`;
CREATE TABLE `lb_file_library` (
  `file_id` varchar(32) NOT NULL COMMENT '主键',
  `file_name` varchar(64) NOT NULL DEFAULT '' COMMENT '文件名称',
  `file_path` varchar(255) NOT NULL DEFAULT '' COMMENT '文件地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `file_use_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '文件使用类型 1 社区服务项目图片库',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `file_type` varchar(32) NOT NULL DEFAULT '' COMMENT '文件类型',
  `md5_hash` text COMMENT '文件MD5加密',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`file_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='文件库表';

-- ----------------------------
-- Table structure for lb_floor
-- ----------------------------
DROP TABLE IF EXISTS `lb_floor`;
CREATE TABLE `lb_floor` (
  `floor_id` varchar(32) NOT NULL COMMENT '主键',
  `building_id` varchar(32) DEFAULT '' COMMENT '所属楼栋',
  `floor_name` varchar(32) DEFAULT '' COMMENT '楼层名称',
  `descrition` varchar(32) DEFAULT '' COMMENT '楼层描述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `area_num_role` tinyint(1) DEFAULT '1' COMMENT '房间号是否带楼栋编号0:否1:是',
  `bed_num_role` tinyint(1) DEFAULT '0' COMMENT '床位编号方式  0:按房间计数1:按楼层计数',
  `building_floor_connector` varchar(16) DEFAULT '' COMMENT '楼栋楼层连接符',
  `floor_area_connector` varchar(16) DEFAULT '' COMMENT '楼层房间连接符',
  `area_bed_connector` varchar(16) DEFAULT '' COMMENT '房间床位连接符',
  `aisle_desc` text COMMENT '走道详情',
  `floor_map` varchar(125) DEFAULT '' COMMENT '楼层地图',
  `floor_map_content` text COMMENT '楼层地图附加信息',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `order_num` int(10) NOT NULL DEFAULT '0' COMMENT '排序字段',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`floor_id`),
  KEY `lb_floor_org_id_IDX` (`org_id`) USING BTREE,
  KEY `building_id_IDX` (`building_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='楼层 未使用';

-- ----------------------------
-- Table structure for lb_func_opor
-- ----------------------------
DROP TABLE IF EXISTS `lb_func_opor`;
CREATE TABLE `lb_func_opor` (
  `func_op_id` varchar(32) NOT NULL COMMENT '功能模块操作唯一id',
  `func_id` varchar(32) DEFAULT '' COMMENT '权限标识',
  `db_op_id` varchar(32) DEFAULT '' COMMENT '数据库操作id',
  `url` varchar(600) DEFAULT '' COMMENT '路径',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `active` int(1) DEFAULT '0' COMMENT '当前权限是否处于激活状态,1激活，0 未激活.',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`func_op_id`),
  KEY `lb_func_opor_func_id_IDX` (`func_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_function
-- ----------------------------
DROP TABLE IF EXISTS `lb_function`;
CREATE TABLE `lb_function` (
  `func_id` varchar(64) NOT NULL COMMENT '权限标识',
  `type` tinyint(4) DEFAULT '0' COMMENT '权限类型(来邦权限1/机构权限2/等)',
  `func_name` varchar(32) DEFAULT '' COMMENT '权限名称',
  `parent_id` varchar(32) DEFAULT '' COMMENT '父权限标识',
  `level` tinyint(4) DEFAULT '0' COMMENT '权限级别,1代表一级菜单,2代表二级菜单',
  `order_num` tinyint(4) DEFAULT '0' COMMENT '显示顺序',
  `route` varchar(255) DEFAULT '' COMMENT '权限路由',
  `icon_path` varchar(255) DEFAULT '' COMMENT '菜单图标相对路径',
  `description` varchar(64) DEFAULT '' COMMENT '备注',
  `is_allot` tinyint(1) DEFAULT '0' COMMENT '菜单权限是否开放 0不开放 1开放',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '菜单所属机构',
  `func_code` varchar(32) DEFAULT NULL,
  `func_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '菜单类型（0-普通菜单，1-客服菜单，2-审批菜单，3-餐饮菜单）',
  `is_register_websocket` tinyint(1) NOT NULL DEFAULT '2' COMMENT '是否注册websocket（1-是，2-否）',
  `func_use_model` tinyint(1) NOT NULL DEFAULT '0' COMMENT '菜单使用范围类型: 0 公用菜单 1社区机构用菜单 2 社区居家用菜单',
  `module_type` tinyint(1) DEFAULT '0' COMMENT '0:基础模块 1:扩展模块',
  `func_authority` varchar(64) NOT NULL DEFAULT '1' COMMENT '菜单权限 1浏览 2 编辑 3 增加 4 删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`func_id`),
  KEY `lb_function_org_id_IDX` (`org_id`) USING BTREE,
  KEY `lb_function_func_code_IDX` (`func_code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='权限菜单表';

-- ----------------------------
-- Table structure for lb_gas_detector
-- ----------------------------
DROP TABLE IF EXISTS `lb_gas_detector`;
CREATE TABLE `lb_gas_detector` (
  `gas_detector_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `alarm_type` tinyint(3) DEFAULT '0' COMMENT '0：为不报警 1： 为GAS报警恢复 2：为GAS轻度泄漏 3：为GAS重度泄漏 4：为短路故障 5：为开路故障 6：为机械手故障 7：为其他故障 8：自检完成 9：设备断电',
  `gas_sensing_value` varchar(10) DEFAULT '' COMMENT '气感值',
  `position_desc` varchar(64) DEFAULT '' COMMENT '安装位置',
  `area_id` varchar(64) DEFAULT '' COMMENT '房间id',
  `family_id` varchar(64) DEFAULT '' COMMENT '家庭id',
  `org_id` varchar(64) DEFAULT '' COMMENT '组织机构id',
  `status` tinyint(3) DEFAULT '0' COMMENT '0 ：正常1：正在自检  2：正在预热  3：自检成功 4：设备故障',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `online_status` tinyint(1) DEFAULT '0' COMMENT '在线状态（0:离线，1:在线）',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生产时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`gas_detector_id`),
  KEY `imei` (`imei`) USING BTREE,
  KEY `index_area_id` (`area_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='气体探测器表';

-- ----------------------------
-- Table structure for lb_gate_magnet
-- ----------------------------
DROP TABLE IF EXISTS `lb_gate_magnet`;
CREATE TABLE `lb_gate_magnet` (
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_type` tinyint(3) DEFAULT '7' COMMENT '设备类型: 7 智能门磁',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `area_id` varchar(64) DEFAULT '' COMMENT '房间id',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `online_status` tinyint(1) DEFAULT NULL COMMENT '在线状态（0:离线，1:在线）',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `open_status` tinyint(1) DEFAULT NULL COMMENT '开关状态（0-关门，1-开门）',
  `open_time` bigint(20) DEFAULT '0' COMMENT '开关时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量)',
  `position_desc` varchar(32) DEFAULT '' COMMENT '位置描述',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `nb_version` smallint(1) DEFAULT '1' COMMENT '版本号',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `family_id` varchar(64) DEFAULT '' COMMENT '家庭id',
  `not_open_door_remind_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '未开门提醒次数',
  `not_close_door_remind_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '未关门提醒次数',
  `software_version` varchar(32) DEFAULT '' COMMENT '软件版本号',
  `not_close_door_alarm_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '未关门报警状态（0-未报警，1-已报警）',
  `not_open_door_alarm_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '未开门报警状态（0-未报警，1-已报警）',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `device_secret_key` text COMMENT '设备密钥',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`),
  KEY `imei` (`imei`) USING BTREE,
  KEY `idx_area_id` (`area_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='门磁设备表';

-- ----------------------------
-- Table structure for lb_gate_magnet_open_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_gate_magnet_open_record`;
CREATE TABLE `lb_gate_magnet_open_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间主键',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台设备Id',
  `dump_energy` tinyint(3) NOT NULL DEFAULT '0' COMMENT '电量',
  `open_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '开关状态（0-关门，1-开门）',
  `open_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开关时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `area_id` (`area_id`) USING BTREE,
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='门磁开关门记录表';

-- ----------------------------
-- Table structure for lb_gate_magnet_password
-- ----------------------------
DROP TABLE IF EXISTS `lb_gate_magnet_password`;
CREATE TABLE `lb_gate_magnet_password` (
  `gate_magnet_password_id` varchar(32) NOT NULL DEFAULT '',
  `gate_magnet_id` varchar(32) NOT NULL DEFAULT '' COMMENT '门磁设备id',
  `password` text NOT NULL COMMENT '密码',
  `password_name` varchar(32) NOT NULL DEFAULT '' COMMENT '密码名称',
  `password_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '密码类型(1:数字密码 2:指纹密码 3：门禁ic密码)',
  `validity_time_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '密码有效期限类型(1:单次 2:期限 3:永久)',
  `validity_start_time` bigint(20) DEFAULT '0' COMMENT '密码有效期开始时间',
  `validity_end_time` bigint(20) DEFAULT '0' COMMENT '密码有效期结束时间',
  `register_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_account_name` varchar(16) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `register_account_category` varchar(16) NOT NULL DEFAULT '' COMMENT '登记人类别 1 客服人员 2 个人用户',
  `operate_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '操作状态 1 操作完成 2、添加中 3 删除中',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`gate_magnet_password_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='门磁设备密码表';

-- ----------------------------
-- Table structure for lb_gateway_device_contact
-- ----------------------------
DROP TABLE IF EXISTS `lb_gateway_device_contact`;
CREATE TABLE `lb_gateway_device_contact` (
  `gateway_device_contact_id` varchar(32) NOT NULL COMMENT '主键',
  `gateway_device_id` varchar(32) DEFAULT '' COMMENT '网关设备id',
  `contact_device_id` varchar(32) DEFAULT '' COMMENT '关联设备id',
  `device_type` smallint(1) NOT NULL DEFAULT '0' COMMENT '关联设备类型',
  `sign` varchar(32) DEFAULT NULL COMMENT '设备标识',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`gateway_device_contact_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='网关设备关联表';

-- ----------------------------
-- Table structure for lb_gms_purview_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_gms_purview_setting`;
CREATE TABLE `lb_gms_purview_setting` (
  `purview_setting_id` varchar(32) NOT NULL COMMENT '主键',
  `type` tinyint(1) DEFAULT NULL COMMENT '权限设置类型 1 财务管理权限 2 服务项目权限',
  `org_id` varchar(32) NOT NULL COMMENT '民政监管机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '创建人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '修改人',
  `is_hava_gms_purview` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否有民政监管权限',
  `is_hava_cms_purview` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否有服务商权限',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`purview_setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='民政监管及服务商平台权限设置';

-- ----------------------------
-- Table structure for lb_goods
-- ----------------------------
DROP TABLE IF EXISTS `lb_goods`;
CREATE TABLE `lb_goods` (
  `goods_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_title` varchar(64) DEFAULT '' COMMENT '商品',
  `goods_detail` text COMMENT '卖点描述',
  `weight` float(4,2) NOT NULL DEFAULT '0.00' COMMENT '商品重量(kg)',
  `length` float(4,2) NOT NULL DEFAULT '0.00' COMMENT '商品长度(cm)',
  `width` float(4,2) NOT NULL DEFAULT '0.00' COMMENT '商品宽度(cm)',
  `height` float(4,2) NOT NULL DEFAULT '0.00' COMMENT '商品高度(cm)',
  `specification` tinyint(1) NOT NULL COMMENT '商品规格(0:套,1:只,2:个,3:台)',
  `versions` varchar(32) NOT NULL COMMENT '商品型号',
  `order_num` tinyint(255) DEFAULT '0' COMMENT '显示顺序',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `goods_url` varchar(64) DEFAULT '' COMMENT '路径',
  `show_type` tinyint(1) DEFAULT '1' COMMENT '商品显示方式，1左侧图标右侧描述显示商品，2上面图标下面描述，3类别分隔',
  `additional_desc` text COMMENT '附加描述信息',
  `is_release` tinyint(1) DEFAULT '0' COMMENT '上架状态(0:未上架,1:正在销售,2:已下架,3:已删除)',
  `is_suit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '商品类型（详见字典表 goods_type）',
  `share_detail` text COMMENT '分享描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_goods_attribute
-- ----------------------------
DROP TABLE IF EXISTS `lb_goods_attribute`;
CREATE TABLE `lb_goods_attribute` (
  `goods_attribute_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_id` varchar(32) NOT NULL COMMENT '商品',
  `color` varchar(20) NOT NULL COMMENT '商品颜色',
  `original_price` float(8,2) DEFAULT '0.00' COMMENT '商品原价',
  `selling_price` float(8,2) NOT NULL DEFAULT '0.00' COMMENT '商品售价',
  `stock` int(11) NOT NULL DEFAULT '0' COMMENT '库存',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_attribute_id`),
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品属性表';

-- ----------------------------
-- Table structure for lb_goods_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_goods_order`;
CREATE TABLE `lb_goods_order` (
  `goods_order_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '用户',
  `goods_total_prices` float(8,2) NOT NULL COMMENT '商品总价',
  `discounts_prices` float(8,2) NOT NULL DEFAULT '0.00' COMMENT '优惠金额',
  `freight_prices` float(8,2) NOT NULL DEFAULT '0.00' COMMENT '运费金额',
  `order_total_prices` float(8,2) NOT NULL COMMENT '订单总价',
  `status` tinyint(3) NOT NULL DEFAULT '0' COMMENT '订单状态(0:待付款，1:待发货，2:待收货，3:已收货，4:申请退款，10:退款中，5:退款完成，11:退款失败，6:申请退货退款，12:退货退款中，7:退货退款完成，13:退货退款失败，8:超时未支付，9:已取消，97:已删除（退款成功），98:已删除（交易关闭），99:已删除（交易成功）)',
  `pay_id` varchar(64) DEFAULT NULL COMMENT '支付平台订单号',
  `pay_way` tinyint(2) DEFAULT NULL COMMENT '支付方式(6:微信H5支付,7:微信JSAPI支付,8:支付宝H5支付,9:微信小程序JSAPI支付,10:微信扫码支付,11:支付宝扫码支付)',
  `pay_time` bigint(20) DEFAULT NULL COMMENT '付款时间',
  `invoice_title` varchar(100) DEFAULT '' COMMENT '发票抬头',
  `customer_message` text COMMENT '客户留言',
  `shipping_method` tinyint(1) NOT NULL DEFAULT '0' COMMENT '配送方式(0 快递免运费，1 ，2  )',
  `name` varchar(32) NOT NULL COMMENT '收货人姓名',
  `phone_num` varchar(11) NOT NULL COMMENT '联系电话',
  `province` int(9) NOT NULL DEFAULT '0' COMMENT '省份',
  `city` int(9) DEFAULT '0' COMMENT '城市',
  `prefecture` int(9) DEFAULT '0' COMMENT '区、县',
  `town` int(9) DEFAULT '0' COMMENT '城镇',
  `address` varchar(100) NOT NULL COMMENT '详细地址',
  `region_desc` varchar(100) NOT NULL COMMENT '地区描述',
  `apply_time` bigint(20) DEFAULT NULL COMMENT '退货/款申请时间',
  `return_reason` text COMMENT '退货/款原因',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `dispose_time` bigint(20) DEFAULT NULL COMMENT '处理时间',
  `return_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退货状态（0 未退货，1 已退货解绑）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_order_id`),
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `pay_id` (`pay_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单表';

-- ----------------------------
-- Table structure for lb_goods_photo
-- ----------------------------
DROP TABLE IF EXISTS `lb_goods_photo`;
CREATE TABLE `lb_goods_photo` (
  `goods_photo_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品Id',
  `goods_attribute_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品属性Id',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '图片地址',
  `photo_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '图片类型（0 商品图片，1 主图视频，2 商品详情）',
  `order_num` tinyint(2) NOT NULL DEFAULT '0' COMMENT '显示顺序',
  `show_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '显示状态,0:生效,1:失效',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_photo_id`,`goods_id`,`goods_attribute_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品图片表';

-- ----------------------------
-- Table structure for lb_goods_return
-- ----------------------------
DROP TABLE IF EXISTS `lb_goods_return`;
CREATE TABLE `lb_goods_return` (
  `goods_return_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `gender` tinyint(1) DEFAULT NULL COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `address` text COMMENT '居住地址',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `return_num` varchar(32) DEFAULT '' COMMENT '退货编号（针对来邦商城退货）',
  `return_type` tinyint(1) NOT NULL COMMENT '退货渠道（0 来邦商城，1 天猫商店）',
  `return_device` text COMMENT '退货维修设备',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `account_name` varchar(64) DEFAULT '' COMMENT '登记人姓名',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `care_object_status` tinyint(1) NOT NULL COMMENT '长者状态（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_return_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='商品退货表';

-- ----------------------------
-- Table structure for lb_gps_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_gps_record`;
CREATE TABLE `lb_gps_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '电信设备id',
  `lat_primitive` varchar(32) DEFAULT NULL COMMENT '粗纬度',
  `lng_primitive` varchar(32) DEFAULT NULL COMMENT '粗经度',
  `lat` varchar(64) DEFAULT NULL COMMENT '纬度',
  `lng` varchar(64) DEFAULT NULL COMMENT '经度',
  `position_desc` varchar(128) DEFAULT NULL COMMENT '位置描述',
  `open_time` varchar(32) DEFAULT NULL COMMENT '开启时间',
  `data` varchar(128) DEFAULT NULL COMMENT '上报报文',
  `create_time` bigint(20) DEFAULT '0' COMMENT '记录入库时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '记录更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备gps定位记录表';

-- ----------------------------
-- Table structure for lb_guardian_service_experience_coupon
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_experience_coupon`;
CREATE TABLE `lb_guardian_service_experience_coupon` (
  `guardian_service_experience_coupon_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `coupon_id` varchar(64) NOT NULL DEFAULT '' COMMENT '优惠卷id',
  `service_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '服务类型(1:守护服务 2:救护服务(基础版) 3:救护服务(救助版版))',
  `guardian_service_time` smallint(6) NOT NULL DEFAULT '0' COMMENT '守护服务时长(天)',
  `gift_guardian_service_time` smallint(6) NOT NULL DEFAULT '0' COMMENT '赠送守护服务时长(天)',
  `gift_rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '赠送救助服务次数(次)',
  `status` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '状态 1:待使用，2:已使用',
  `use_owner_id` varchar(32) NOT NULL DEFAULT '' COMMENT '使用者id',
  `used_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '使用时间',
  `register_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_account_name` varchar(16) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `qr_code_url` varchar(128) NOT NULL DEFAULT '' COMMENT '二维码地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:已删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_experience_coupon_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务体验劵表';

-- ----------------------------
-- Table structure for lb_guardian_service_price_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_price_config`;
CREATE TABLE `lb_guardian_service_price_config` (
  `guardian_service_price_config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `service_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '服务类型(1:守护服务 2:救护服务(基础版) 3:救护服务(救助版版))',
  `recharge_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '充值规则类型：1:首次开通，2:续费',
  `price_config_name` varchar(32) NOT NULL DEFAULT '' COMMENT '价目名称',
  `original_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '原价',
  `discount_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '折后价',
  `guardian_service_time` smallint(6) NOT NULL DEFAULT '0' COMMENT '守护服务时长(天)',
  `gift_guardian_service_time` smallint(6) NOT NULL DEFAULT '0' COMMENT '赠送守护服务时长(天)',
  `gift_rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '赠送救助服务次数(次)',
  `sort_num` smallint(6) NOT NULL DEFAULT '0' COMMENT '排序字段',
  `open_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否开启 0:未开启 1:已开启',
  `is_default` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否默认配置 0:非默认 1:默认',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:已删除',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_price_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务价目配置表';

-- ----------------------------
-- Table structure for lb_guardian_service_subscription
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_subscription`;
CREATE TABLE `lb_guardian_service_subscription` (
  `guardian_service_subscription_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `subscription_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '订阅者id',
  `service_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '服务类型(1:守护服务 2:救护服务)',
  `guardian_service_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '守护服务开始时间',
  `guardian_service_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '守护服务到期时间',
  `rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '救助服务剩余次数',
  `rescue_service_first_open_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '救助服务首次开通时间(0点秒级时间戳)',
  `rescue_service_last_reset_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上一次重置救护次数的时间',
  `last_guardian_service_price_config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '上一次订阅id',
  `experience_used` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否已使用体验券0:未使用，1:已使用',
  `gift_device_unique_id` varchar(64) NOT NULL DEFAULT '' COMMENT '绑定设备赠送守护服务设备唯一id(旧规则兼容)',
  `is_gift_device_bind` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否绑定设备赠送守护服务 0:未赠送，1:已赠送 (旧规则兼容)',
  `notice_record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上次订阅即将到期提醒消息发送时间',
  `expire_record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上次订阅已到期提醒消息发送时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:已删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_subscription_id`),
  KEY `lb_guardian_service_subscription_subscription_object_id_index` (`subscription_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务订阅记录表';

-- ----------------------------
-- Table structure for lb_guardian_service_subscription_change_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_subscription_change_record`;
CREATE TABLE `lb_guardian_service_subscription_change_record` (
  `guardian_service_subscription_change_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `subscription_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '订阅者id',
  `change_source_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '变更类型：1:用户充值 2:客服操作 3:系统赠送 4:体验券',
  `change_action_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '变更行为：1:增加时长 2:扣除时长 3:增加次数 4:扣除次数 5:增加时长 + 增加次数 6:服务类型变更',
  `change_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '变更描述',
  `change_status` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '变更状态 0: 待确认 1:成功 2:失败',
  `before_guardian_service_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '变更前守护服务到期时间',
  `after_guardian_service_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '变更后守护服务到期时间',
  `before_rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '变更前救助服务次数',
  `after_rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '变更前救助服务次数',
  `source_id` varchar(32) NOT NULL DEFAULT '' COMMENT '订单来源id(支付宝/微信订单号、体验劵id)',
  `guardian_service_price_config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '价目配置id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `is_invoice` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已开票 0未开/ 1已开',
  `amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '变更付款金额',
  `org_guardian_service_config` text NOT NULL COMMENT '项目守护服务配置',
  `guardian_service_withdrawal_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联提现记录id',
  `operator_id` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人ID',
  `operator_name` varchar(64) DEFAULT '' COMMENT '操作人名称（可选）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:已删除',
  `day` int(11) NOT NULL DEFAULT '0' COMMENT '自定义充值天数',
  `guardian_service_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '守护服务时长(天)',
  `rescue_service_number` tinyint(4) NOT NULL DEFAULT '0' COMMENT '救助服务次数(次)',
  `service_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '服务类型(1:守护服务 2:救护服务(基础版) 3:救护服务(救助版))',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_subscription_change_record_id`),
  KEY `subscription_object_id_index` (`subscription_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务订阅变动记录表';

-- ----------------------------
-- Table structure for lb_guardian_service_withdrawal_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_withdrawal_record`;
CREATE TABLE `lb_guardian_service_withdrawal_record` (
  `guardian_service_withdrawal_record_id` varchar(32) NOT NULL DEFAULT '',
  `title_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '抬头类型 (0企业/1个人)',
  `title_name` varchar(32) NOT NULL DEFAULT '' COMMENT '抬头名称(企业-公司名称/个人-个人姓名)',
  `vat` varchar(32) NOT NULL DEFAULT '' COMMENT '税号',
  `address` varchar(64) NOT NULL DEFAULT '' COMMENT '地址',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '电话',
  `bank` varchar(16) NOT NULL DEFAULT '' COMMENT '开户银行',
  `bank_num` varchar(32) NOT NULL DEFAULT '' COMMENT '银行账户',
  `amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '提现金额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '提现状态  1:已付款 2:待付款',
  `bill_url` text NOT NULL COMMENT '提现发票图片地址url',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_withdrawal_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务提现设置表';

-- ----------------------------
-- Table structure for lb_guardian_service_withdrawal_settings
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardian_service_withdrawal_settings`;
CREATE TABLE `lb_guardian_service_withdrawal_settings` (
  `guardian_service_withdrawal_settings_id` varchar(32) NOT NULL DEFAULT '',
  `title_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '抬头类型 (0企业/1个人)',
  `title_name` varchar(32) NOT NULL DEFAULT '' COMMENT '抬头名称(企业-公司名称/个人-个人姓名)',
  `vat` varchar(32) NOT NULL DEFAULT '' COMMENT '税号',
  `address` varchar(64) NOT NULL DEFAULT '' COMMENT '地址',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '电话',
  `bank` varchar(16) NOT NULL DEFAULT '' COMMENT '开户银行',
  `bank_num` varchar(32) NOT NULL DEFAULT '' COMMENT '银行账户',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardian_service_withdrawal_settings_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护服务提现设置表';

-- ----------------------------
-- Table structure for lb_guardianship_center
-- ----------------------------
DROP TABLE IF EXISTS `lb_guardianship_center`;
CREATE TABLE `lb_guardianship_center` (
  `guardianship_center_id` varchar(32) NOT NULL DEFAULT '' COMMENT '守护中心主键',
  `guardianship_center_name` varchar(64) DEFAULT '' COMMENT '守护中心名称',
  `guardianship_center_address` varchar(64) DEFAULT '' COMMENT '守护中心地址',
  `region_id` varchar(32) DEFAULT '' COMMENT '区域主键（预留字段）',
  `principal_id` varchar(32) DEFAULT '' COMMENT '负责人主键（预留字段）',
  `principal_name` varchar(32) DEFAULT '' COMMENT '负责人姓名',
  `principal_phone` varchar(32) DEFAULT '' COMMENT '负责人电话',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`guardianship_center_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='守护中心表';

-- ----------------------------
-- Table structure for lb_gw_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_gw_config`;
CREATE TABLE `lb_gw_config` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `kind` smallint(1) NOT NULL DEFAULT '0' COMMENT '路由预言类型：0-path,1-header,2-qeruy',
  `path` varchar(255) NOT NULL DEFAULT '' COMMENT '请求路径匹配(可使用通配符,如/api/**)',
  `key` varchar(32) NOT NULL DEFAULT '' COMMENT '参数键值(header或者query)',
  `regex` varchar(32) NOT NULL DEFAULT '' COMMENT '参数匹配(可使用正则表达式，如 -?[1-9]\\\\d* )',
  `uri` varchar(255) NOT NULL DEFAULT '' COMMENT '目标服务地址：负载均衡(lb://)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='动态网关配置表';

-- ----------------------------
-- Table structure for lb_hb_auth_client_details
-- ----------------------------
DROP TABLE IF EXISTS `lb_hb_auth_client_details`;
CREATE TABLE `lb_hb_auth_client_details` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `app_id` varchar(128) NOT NULL DEFAULT '' COMMENT '接入的客户端唯一标识',
  `app_name` varchar(64) NOT NULL DEFAULT '' COMMENT '客户端名称',
  `app_secret` varchar(255) NOT NULL DEFAULT '' COMMENT '接入的客户端的密钥',
  `client_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '7通用三方应用',
  `redirect_uri` varchar(255) NOT NULL DEFAULT '' COMMENT '回调地址',
  `scope` varchar(255) NOT NULL DEFAULT '' COMMENT '应用权限范围',
  `description` varchar(255) NOT NULL DEFAULT '' COMMENT '描述信息',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0表示禁用；1表示开通',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0未删除；1已删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='接入的客户端信息表';

-- ----------------------------
-- Table structure for lb_hb_auth_refresh_token
-- ----------------------------
DROP TABLE IF EXISTS `lb_hb_auth_refresh_token`;
CREATE TABLE `lb_hb_auth_refresh_token` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `token_id` varchar(32) NOT NULL DEFAULT '' COMMENT '表auth_access_token对应的主键',
  `refresh_token` varchar(255) NOT NULL COMMENT 'Refresh Token',
  `expire_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '过期时间戳',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='Refresh Token信息表';

-- ----------------------------
-- Table structure for lb_health_machine
-- ----------------------------
DROP TABLE IF EXISTS `lb_health_machine`;
CREATE TABLE `lb_health_machine` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `code` varchar(32) NOT NULL DEFAULT '' COMMENT '设备编码',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康一体机';

-- ----------------------------
-- Table structure for lb_heart_rate_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_heart_rate_report`;
CREATE TABLE `lb_heart_rate_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `max_heart_rate` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内的最高心率',
  `max_heart_rate_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最高心率触发时间',
  `min_heart_rate` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内的最低心率',
  `min_heart_rate_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最低心率触发时间',
  `total_heart_rate` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内心率数值汇总（用于计算平均心率）',
  `report_count` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内心率上报次数统计（用于计算平均心率）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='心率报表';

-- ----------------------------
-- Table structure for lb_heartbeat_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_heartbeat_record`;
CREATE TABLE `lb_heartbeat_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `heart_rate` int(4) DEFAULT '0' COMMENT '心率',
  `care_object_name` varchar(128) DEFAULT '' COMMENT '老人名字',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `resting_heart_rate` tinyint(4) DEFAULT '0' COMMENT '安静心率',
  `is_normal` tinyint(1) DEFAULT '1' COMMENT '数据是否正常，1正常，0异常',
  `is_automatic` tinyint(1) DEFAULT '1' COMMENT '是否为自动测量，1自动测量，0手动测量',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1 日常，2 轨迹，3 血压测量 ）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='心率记录';

-- ----------------------------
-- Table structure for lb_heartbeat_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_heartbeat_record_statistics`;
CREATE TABLE `lb_heartbeat_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '看护对象',
  `record_start_time` bigint(20) DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) DEFAULT '0' COMMENT '记录结束时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `content` text COMMENT '心率数据',
  `record_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '记录类型（1 日常，2 轨迹，3 血压测量, 4 实时守护, 5 报警测量, 6 主动测量）',
  `record_time_date` datetime DEFAULT NULL,
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台设备Id',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `lb_heartbeat_record_statistics_record_time_date_IDX` (`record_time_date`) USING BTREE,
  KEY `create_time` (`create_time`),
  KEY `org_id` (`org_id`,`iot_device_id`) USING BTREE,
  KEY `update_time` (`update_time`),
  KEY `record_type_index` (`record_type`),
  KEY `iot_device_id_index` (`iot_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='心率记录统计';

-- ----------------------------
-- Table structure for lb_hm_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_hm_device`;
CREATE TABLE `lb_hm_device` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `device_name` varchar(32) NOT NULL DEFAULT '' COMMENT '设备名称',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `operator_time` bigint(20) DEFAULT '0' COMMENT '录入时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='海曼设备表';

-- ----------------------------
-- Table structure for lb_home_account_org_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_home_account_org_relation`;
CREATE TABLE `lb_home_account_org_relation` (
  `account_org_re_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_org_re_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='子女账号项目关联表';

-- ----------------------------
-- Table structure for lb_home_installation_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_home_installation_account`;
CREATE TABLE `lb_home_installation_account` (
  `relation_id` varchar(32) NOT NULL COMMENT '主键',
  `phone` varchar(64) DEFAULT '' COMMENT '注册手机号',
  `installation_account_id` varchar(32) DEFAULT '' COMMENT '注册人员账号',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='上门安装账号关联表';

-- ----------------------------
-- Table structure for lb_home_installation_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_home_installation_care_object`;
CREATE TABLE `lb_home_installation_care_object` (
  `care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `photo` varchar(128) DEFAULT '' COMMENT '头像地址',
  `age` tinyint(3) DEFAULT '0' COMMENT '年龄',
  `disease_status` text COMMENT '病情状态描述',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `account_phone` varchar(11) DEFAULT '' COMMENT '关联的录入账号',
  `own_name` varchar(32) DEFAULT '' COMMENT '本人姓名',
  `own_phone` varchar(11) DEFAULT '' COMMENT '本人电话号码',
  `own_relation` varchar(32) DEFAULT '' COMMENT '本人和关系',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`) USING BTREE
