-- ----------------------------
-- Table structure for lb_hospital_device_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_hospital_device_relation`;
CREATE TABLE `lb_hospital_device_relation` (
  `id` varchar(32) NOT NULL,
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `device_type` int(3) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `relation_device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联设备id',
  `relation_device_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '关联设备mac',
  `relation_device_type` int(3) NOT NULL DEFAULT '0' COMMENT '关联设备类型',
  `relation_device_model` varchar(64) NOT NULL DEFAULT '' COMMENT '关联设备型号',
  `relation_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '关联类型 1-床位关联',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_deviceid` (`device_id`),
  KEY `idx_orgid` (`org_id`)
