-- ----------------------------
-- Table structure for lb_ims_accident_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_accident_record`;
CREATE TABLE `lb_ims_accident_record` (
  `accident_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者唯一标识',
  `accident_time` bigint(20) DEFAULT '0' COMMENT '事故时间',
  `accident_type` varchar(32) DEFAULT '0' COMMENT '事故类型',
  `accident_level` varchar(32) DEFAULT NULL COMMENT '事故等级',
  `nurse_id` varchar(32) DEFAULT ' ' COMMENT '值班护工唯一标识',
  `reasons` text COMMENT '原因',
  `accident_describe` text COMMENT '叙述',
  `photo` text COMMENT '现场照片',
  `is_handle` tinyint(1) DEFAULT '0' COMMENT '0:未处理1:处理',
  `register_account_id` varchar(32) DEFAULT ' ' COMMENT '登记账号',
  `register_name` varchar(125) DEFAULT '' COMMENT '登记人姓名',
  `handle_time` bigint(20) DEFAULT '0' COMMENT '处理时间',
  `accident_result` varchar(255) DEFAULT ' ' COMMENT '结果',
  `org_id` varchar(32) DEFAULT ' ' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `handle_account_id` varchar(100) DEFAULT '' COMMENT '处理账号',
  `handle_name` varchar(100) DEFAULT '' COMMENT '处理人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`accident_record_id`),
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='综合管理平台事故记录信息';

-- ----------------------------
-- Table structure for lb_ims_accident_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_accident_type`;
CREATE TABLE `lb_ims_accident_type` (
  `accident_type_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `accident_name` varchar(32) NOT NULL COMMENT '事故类型名称',
  `accident_type_level` varchar(32) NOT NULL DEFAULT '0' COMMENT '事故等级',
  `contact` varchar(32) DEFAULT NULL COMMENT '联系人',
  `phone` varchar(32) DEFAULT NULL COMMENT '手机号',
  `remark` varchar(125) DEFAULT NULL COMMENT '类型描述',
  `dispose_plan` varchar(125) DEFAULT NULL COMMENT '处理预案',
  `register_id` varchar(32) NOT NULL COMMENT '登记id',
  `register_name` varchar(32) NOT NULL COMMENT '登记人name',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`accident_type_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='事故类型表';

-- ----------------------------
-- Table structure for lb_ims_accompany_medical
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_accompany_medical`;
CREATE TABLE `lb_ims_accompany_medical` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `care_object_id` varchar(32) NOT NULL DEFAULT '',
  `accompany_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '陪同人员类型(-1:无 0:护理人员 1:紧急联系人 2:长者亲属 3:其他亲属 4:其他人员)',
  `accompany_name` varchar(128) NOT NULL DEFAULT '' COMMENT '陪同人员姓名',
  `accompany_phone` varchar(16) NOT NULL DEFAULT '' COMMENT '陪同人员手机号',
  `accompany_identity` varchar(32) NOT NULL DEFAULT '' COMMENT '人员身份证',
  `accompany_address` varchar(64) NOT NULL DEFAULT '' COMMENT '陪同人员地址',
  `accompany_address_detail` varchar(64) NOT NULL DEFAULT '' COMMENT '陪同人员地址-详细地址',
  `medical_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '去医院时间',
  `medical_reason` text NOT NULL COMMENT '就医原因',
  `condition` text NOT NULL COMMENT '长者身体状态',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '状态(0:陪同就医待签字确认 1:待登记问诊信息 2:问诊信息待签字确认 3:已完成)',
  `inquiry_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '问诊时间',
  `inquiry_condition` text NOT NULL COMMENT '医生问诊情况',
  `is_drug` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否开药(0:否 1:是)',
  `drug_condition` text NOT NULL COMMENT '长者开药情况',
  `accompany_sign` text NOT NULL COMMENT '陪同就医确认签字(url)',
  `accompany_sign_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '陪同就医确认签字(签字时间)',
  `inquiry_sign` text NOT NULL COMMENT '问诊信息确认签字(url)',
  `inquiry_sign_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '问诊信息确认签字(签字时间)',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='陪同就医';

-- ----------------------------
-- Table structure for lb_ims_account_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_account_relation`;
CREATE TABLE `lb_ims_account_relation` (
  `ims_account_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `account_type` tinyint(1) DEFAULT '28' COMMENT '账号类型，参见字典表,默认长者app',
  `object_id` varchar(64) DEFAULT '' COMMENT '实体唯一标识',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除(0未删除,1删除)',
  `management_type` tinyint(1) DEFAULT NULL COMMENT '长者管理类型（1-分组，2-所有），护理好帮手账号有效',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`ims_account_relation_id`),
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `object_id` (`object_id`,`account_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='用户关联信息表';

