  `try_bed_price` decimal(10,2) DEFAULT '0.00' COMMENT '试住床位价格',
  `tax_rate` tinyint(1) DEFAULT '0' COMMENT '税率',
  `remark` varchar(255) DEFAULT '' COMMENT '备注',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
