  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_care_level_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='评估结果与护理等级关系';

