  `criteria` varchar(32) NOT NULL DEFAULT '' COMMENT '分级名称',
  `remark` text NOT NULL COMMENT '判定标准',
  `risk_level` varchar(32) NOT NULL DEFAULT '' COMMENT '风险等级',
  `care_level` varchar(32) NOT NULL DEFAULT '' COMMENT '护理等级',
