-- ----------------------------
-- Table structure for lb_ims_assessment_custom_template_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_custom_template_setting`;
CREATE TABLE `lb_ims_assessment_custom_template_setting` (
