  PRIMARY KEY (`assessment_health_drug_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='能力评估健康信息用药情况表';

-- ----------------------------
-- Table structure for lb_ims_assessment_health_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_health_info`;
CREATE TABLE `lb_ims_assessment_health_info` (
  `assessment_health_info_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `history_present_illness` varchar(128) NOT NULL DEFAULT '' COMMENT '现病史',
  `previous_history` varchar(128) NOT NULL DEFAULT '' COMMENT '既往史',
  `disease_diagnosis` varchar(128) NOT NULL DEFAULT '' COMMENT '疾病诊断',
  `pressure_loss` varchar(32) NOT NULL DEFAULT '' COMMENT '压力型损失',
  `joint_range` varchar(32) NOT NULL DEFAULT '' COMMENT '关节活动度',
  `wound_condition` varchar(32) NOT NULL DEFAULT '' COMMENT '伤口情况',
  `special_care_condition` varchar(32) NOT NULL DEFAULT '' COMMENT '特殊护理情况',
  `pain` varchar(32) NOT NULL DEFAULT '' COMMENT '疼痛感',
  `absence_tooth` varchar(32) NOT NULL DEFAULT '' COMMENT '牙齿缺失情况',
  `false_tooth_condition` varchar(32) NOT NULL DEFAULT '' COMMENT '义齿佩戴情况',
  `dysphagia_condition` varchar(32) NOT NULL DEFAULT '' COMMENT '吞咽困难的情形和症状',
  `malnutrition` varchar(32) NOT NULL DEFAULT '' COMMENT '营养不良-体质指数（BMI）低于正常值',
  `airway_invalid` varchar(32) NOT NULL DEFAULT '' COMMENT '清理呼吸道无效',
  `coma` varchar(32) NOT NULL DEFAULT '' COMMENT '昏迷',
  `other` varchar(128) NOT NULL DEFAULT '' COMMENT '其他',
  `conclusion` varchar(128) NOT NULL DEFAULT '' COMMENT '结论',
  `doctor_id` varchar(32) NOT NULL DEFAULT '' COMMENT '责任医生',
  `doctor_name` varchar(32) NOT NULL DEFAULT '' COMMENT '责任医生',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `vision` varchar(32) NOT NULL DEFAULT '' COMMENT '视力',
  `hearing` varchar(32) NOT NULL DEFAULT '' COMMENT '听力',
  `hospital` varchar(32) NOT NULL DEFAULT '' COMMENT '主治医院',
  `hospital_doctor` varchar(128) NOT NULL COMMENT '主治医生',
  `hospital_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '医院电话',
  `drug_allergy` varchar(255) NOT NULL COMMENT '过敏药物',
  `major_diseases` varchar(32) NOT NULL DEFAULT '' COMMENT '主要疾病',
  `medical_history` varchar(255) NOT NULL COMMENT '病史',
  `food_allergy_history` varchar(255) NOT NULL COMMENT '食物过敏史',
  `assessmentRecord_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录id',
  `coma_flag` varchar(64) NOT NULL DEFAULT '' COMMENT '昏迷标识',
  `health_other` varchar(64) NOT NULL DEFAULT '' COMMENT '其他',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_health_info_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='能力评估健康信息附属表';

-- ----------------------------
-- Table structure for lb_ims_assessment_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_record`;
CREATE TABLE `lb_ims_assessment_record` (
  `assessment_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `height` varchar(32) NOT NULL DEFAULT '' COMMENT '身高',
  `weight` varchar(32) NOT NULL DEFAULT '' COMMENT '体重',
  `assessment_standard` tinyint(1) DEFAULT '1' COMMENT '评估标准： 1-2013评估标准 2-2022评估标准',
  `assessment_number` varchar(32) NOT NULL COMMENT '评估编号',
  `assessment_class` varchar(32) NOT NULL DEFAULT '' COMMENT '评估分类',
  `assessment_reason` varchar(255) DEFAULT NULL COMMENT '评估原因',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估时间',
  `assessment_grade` text COMMENT '评估得分,每项得分拼接',
  `social_security_card` varchar(32) DEFAULT NULL COMMENT '社保卡号',
  `pay_type` varchar(128) DEFAULT '' COMMENT '医疗费用支付方式',
  `provide_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `provide_relation` varchar(32) DEFAULT NULL COMMENT '信息提供者与长者关系',
  `provide_phone` varchar(32) DEFAULT NULL COMMENT '信息提供者手机号',
  `assessment_result` text COMMENT '评估结果',
  `assessment_type` varchar(32) DEFAULT NULL COMMENT '评估类型 1能力评估 2健康评估 3心理 4社会角色 5主观健康 6 其他 7风险 8失智 9压疮 10跌倒',
  `assessment_type_relation` varchar(32) NOT NULL DEFAULT '' COMMENT '关联业务评估类型',
  `assessment_person` varchar(32) DEFAULT NULL COMMENT '评估人',
  `assessment_person_two` varchar(32) NOT NULL DEFAULT '' COMMENT '评估人员2',
  `assessment_address` varchar(32) DEFAULT NULL COMMENT '评估地点',
  `assessment_file_url` text COMMENT '附件,多个拼接使用',
  `assessment_file_name` text COMMENT '附件名称,多个拼接使用',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_first` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为试(入)住登记录入',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registration_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `assessment_level` varchar(100) DEFAULT NULL COMMENT '评估后的等级',
  `assessment_care_level_id` varchar(32) DEFAULT NULL COMMENT '评估对应的护理等级',
  `choose_answer` json DEFAULT NULL COMMENT '评估题目的选择答案',
  `topic_answer` text COMMENT '评估时题目,选项等信息',
  `again_assessment_result` varchar(200) DEFAULT NULL COMMENT '再次评估结果',
  `again_assessment_grade` varchar(512) DEFAULT NULL COMMENT '再次评估得分',
  `again_assessment_person` varchar(32) DEFAULT NULL COMMENT '再次评估人',
  `again_provide_name` varchar(32) DEFAULT NULL COMMENT '再次评估信息提供着姓名',
  `again_provide_relation` varchar(32) DEFAULT NULL COMMENT '再次评估信息提供者与长者关系',
  `again_assessment_time` bigint(20) DEFAULT NULL COMMENT '评估时间',
  `sign_url` varchar(128) DEFAULT NULL COMMENT '签字地址',
  `sign_url_again` varchar(128) DEFAULT NULL COMMENT '再次签字',
  `remark` text COMMENT '备注',
  `assessment_report_url` varchar(255) DEFAULT NULL COMMENT '第三方评估报告链接',
  `assessment_report_file_name` varchar(100) DEFAULT NULL COMMENT '第三方评估报告文件名称',
  `assessment_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '评估是否有效 0 作废 1 有效',
  `tumble_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '跌倒风险',
  `lost_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '走失风险',
  `dysphoria_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '噎食风险',
  `suicide_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '自杀、自伤风险',
  `other_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '其他风险',
  `custom_template_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '自定义评估模版id',
  `assessment_group_id` varchar(32) NOT NULL DEFAULT '' COMMENT '评估记录组标识',
  `assessment_finish_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '评估记录是否完成状态 0:未完成 1:已完成',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `diagnosis` varchar(255) NOT NULL DEFAULT '' COMMENT '诊断',
  `group_finish_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '评估组完成状态 0:未完成 1:已完成',
  `assess_device_recommend` varchar(128) NOT NULL DEFAULT '' COMMENT '评估设备推荐',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_record_id`) USING BTREE,
  KEY `lb_assessment_record_org_id_IDX` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='评估记录表';

-- ----------------------------
-- Table structure for lb_ims_assessment_topic
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_topic`;
CREATE TABLE `lb_ims_assessment_topic` (
  `assessment_topic_id` varchar(64) NOT NULL DEFAULT '' COMMENT '自然主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `topic_type_id` varchar(64) NOT NULL COMMENT '类型主键',
  `topic_name` varchar(255) NOT NULL COMMENT '题目名称',
  `description` varchar(255) DEFAULT NULL COMMENT '情况描述',
  `component_type` varchar(32) DEFAULT NULL COMMENT '分项类型',
  `choice_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 单选 2 多选',
  `order_num` tinyint(1) NOT NULL DEFAULT '0' COMMENT '预留排序字段',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_topic_id`) USING BTREE,
  KEY `lb_ims_assessment_topic_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康评估题目';

-- ----------------------------
-- Table structure for lb_ims_assessment_topic_option
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_topic_option`;
CREATE TABLE `lb_ims_assessment_topic_option` (
  `assessment_topic_option_id` varchar(64) NOT NULL COMMENT '自然主键',
  `org_id` varchar(64) NOT NULL DEFAULT 'lonbonims' COMMENT '机构id',
  `topic_id` varchar(64) DEFAULT NULL COMMENT '题目主键',
  `option_name` varchar(255) NOT NULL DEFAULT '' COMMENT '选项名称',
  `option_number` int(10) NOT NULL DEFAULT '0' COMMENT '选项分值',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_topic_option_id`),
  KEY `lb_ims_assessment_topic_option_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康评估题目选项';

-- ----------------------------
-- Table structure for lb_ims_assessment_topic_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_assessment_topic_type`;
CREATE TABLE `lb_ims_assessment_topic_type` (
  `assessment_topic_type_id` varchar(64) NOT NULL COMMENT '自然主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `type_name` varchar(32) NOT NULL DEFAULT '' COMMENT '类型名称',
  `order_num` tinyint(1) DEFAULT '0' COMMENT '预留排序字段，暂时不用，使用type排序',
  `zero_level` varchar(32) NOT NULL DEFAULT '' COMMENT '零级范围值 逗号隔开2个数字',
  `one_level` varchar(32) NOT NULL DEFAULT '' COMMENT '一级范围值 逗号隔开2个数字',
  `two_level` varchar(32) NOT NULL DEFAULT '' COMMENT '二级范围值 逗号隔开2个数字',
  `three_level` varchar(32) NOT NULL DEFAULT '' COMMENT '三级范围值 逗号隔开2个数字',
  `is_asc` tinyint(1) NOT NULL DEFAULT '1' COMMENT '分值范围是否是正序 1是正序 2是倒序',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '类型',
  `assessment_standard` tinyint(1) NOT NULL DEFAULT '1' COMMENT '评估标准： 1-2013评估标准 2-2022评估标准',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`assessment_topic_type_id`) USING BTREE,
  KEY `lb_ims_assessment_type_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康评估题目类型';

-- ----------------------------
-- Table structure for lb_ims_attachment
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attachment`;
CREATE TABLE `lb_ims_attachment` (
  `attachment_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `file_url` varchar(255) DEFAULT NULL COMMENT '文件路径',
  `file_name` varchar(255) DEFAULT NULL COMMENT '文件名称',
  `file_url_tmp` varchar(255) DEFAULT NULL COMMENT '临时路径',
  `file_name_tmp` varchar(255) DEFAULT NULL COMMENT '临时名称',
  `file_type` varchar(32) NOT NULL DEFAULT '' COMMENT '文件类型，身份证，体检报告等,投诉文件等',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `file_relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '文件关联业务id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attachment_id`) USING BTREE,
  KEY `idx_file_relation_id` (`file_relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='附件管理表';

-- ----------------------------
-- Table structure for lb_ims_attendance
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance`;
CREATE TABLE `lb_ims_attendance` (
  `attendance_id` varchar(32) NOT NULL COMMENT '护理项目id',
  `attendance_item_id` varchar(32) NOT NULL COMMENT '项目模板id',
  `attendance_level_id` varchar(32) DEFAULT NULL COMMENT '护理项目级别id',
  `task_type` tinyint(1) DEFAULT '0' COMMENT '任务类型,0一般任务;1关键任务',
  `task_frequency` tinyint(1) DEFAULT NULL COMMENT '执行频率　0-月 1-周 2-天 3-按需',
  `demand_type` tinyint(1) DEFAULT NULL COMMENT '按需细分 1-指定周期 2-不限制次数 3-限制次数 ',
  `task_cycle` varchar(200) DEFAULT NULL COMMENT '执行周期',
  `task_time` varchar(400) DEFAULT NULL COMMENT '执行时间',
  `attendance_level_name` varchar(32) DEFAULT NULL COMMENT '护理等级名称',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者ID',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `task_cron` varchar(400) DEFAULT NULL COMMENT 'Cron表达式(按需任务除外)',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `source` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 护理、风险等级设置　2 管家工作站　3 长者App  4 健康管理计划 5 员工App',
  `package_number` bigint(20) DEFAULT '0' COMMENT '套餐内免费次数',
  `validity_period` bigint(20) DEFAULT NULL COMMENT '项目有效期',
  `health_plan_id` varchar(32) DEFAULT NULL COMMENT '健康管理计划主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_id`) USING BTREE,
  KEY `attendance_item_id` (`attendance_item_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理项目表';

-- ----------------------------
-- Table structure for lb_ims_attendance_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_item`;
CREATE TABLE `lb_ims_attendance_item` (
  `attendance_item_id` varchar(32) NOT NULL COMMENT '护理项目模板id',
  `name` varchar(32) NOT NULL COMMENT '项目名称',
  `attendance_type_id` varchar(32) NOT NULL COMMENT '项目类型',
  `need_time` varchar(32) DEFAULT NULL COMMENT '任务所需时间',
  `cost` decimal(32,2) DEFAULT NULL COMMENT '费用',
  `package_once_cost` decimal(10,2) DEFAULT NULL COMMENT '套餐外单次费用',
  `package_number` bigint(20) DEFAULT '0' COMMENT '套餐内免费次数',
  `package_period` tinyint(2) DEFAULT '1' COMMENT '套餐有效期',
  `freight_basis` tinyint(1) DEFAULT NULL COMMENT '收费方式 0：按次、1：按月、２：按套餐',
  `introduction` varchar(120) DEFAULT NULL COMMENT '要求执行时间',
  `url_video` varchar(120) DEFAULT NULL COMMENT '视频地址',
  `attendance_type_name` varchar(32) DEFAULT NULL,
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `upload_person` varchar(32) DEFAULT NULL COMMENT '上传人',
  `upload_time` bigint(20) DEFAULT '0' COMMENT '上传时间',
  `video_time` varchar(32) DEFAULT NULL COMMENT '视频时长',
  `video_size` varchar(32) DEFAULT NULL COMMENT '视频大小',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `icon_url` varchar(128) NOT NULL DEFAULT '' COMMENT '图标地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_item_id`) USING BTREE,
  KEY `attendance_type_id` (`attendance_type_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理项目模板表';

-- ----------------------------
-- Table structure for lb_ims_attendance_level
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_level`;
CREATE TABLE `lb_ims_attendance_level` (
  `attendance_level_id` varchar(32) NOT NULL,
  `attendance_type_id` varchar(32) NOT NULL COMMENT '项目类型',
  `name` varchar(32) DEFAULT NULL COMMENT '护理级别名称',
  `cost` decimal(32,0) DEFAULT '0' COMMENT '护理费用',
  `introduction` varchar(250) DEFAULT NULL COMMENT '护理级别说明',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_level_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='护理项目级别表';

-- ----------------------------
-- Table structure for lb_ims_attendance_model
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_model`;
CREATE TABLE `lb_ims_attendance_model` (
  `attendance_model_id` varchar(32) NOT NULL COMMENT '护理项目id',
  `attendance_level_id` varchar(32) NOT NULL COMMENT '护理项目级别id',
  `attendance_level_name` varchar(32) NOT NULL COMMENT '护理项目级别id',
  `attendance_item_id` varchar(32) NOT NULL COMMENT '项目模板id',
  `task_type` tinyint(1) DEFAULT '0' COMMENT '任务类型,0一般任务;1关键任务',
  `task_frequency` tinyint(1) DEFAULT NULL COMMENT '执行频率　0-月 1-周 2-天 3-按需',
  `demand_type` tinyint(1) DEFAULT NULL COMMENT '按需细分 1-指定周期 2-不限制次数 3-限制次数 ',
  `task_cycle` varchar(200) DEFAULT NULL COMMENT '执行周期',
  `task_time` varchar(400) DEFAULT NULL COMMENT '执行时间',
  `task_cron` varchar(400) DEFAULT NULL COMMENT 'Cron表达式(按需任务除外)',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_model_id`) USING BTREE,
  KEY `attendance_level_id` (`attendance_level_id`) USING BTREE,
  KEY `attendance_item_id` (`attendance_item_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理模型表';

-- ----------------------------
-- Table structure for lb_ims_attendance_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_order`;
CREATE TABLE `lb_ims_attendance_order` (
  `attendance_order_id` varchar(32) NOT NULL COMMENT '预约记录id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `attendance_item_id` varchar(32) NOT NULL COMMENT '护理项目id',
  `attendance_name` varchar(32) NOT NULL COMMENT '护理项目名称',
  `attendance_cost` decimal(10,2) NOT NULL COMMENT '护理项目费用',
  `order_time` bigint(20) DEFAULT NULL COMMENT '下单时间',
  `order_person` varchar(128) DEFAULT NULL COMMENT '下单人',
  `order_source` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1-健康管理计划预约　2-管家工作站预约　3-长者好帮手App预约 4—员工好帮手App预约',
  `health_plan_id` varchar(32) DEFAULT NULL COMMENT '健康管理计划主键',
  `attendance_id` varchar(32) DEFAULT NULL COMMENT '长者项目主键id',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '预约状态：1-新建　2-确认 3-取消 4-已完成 5-已评价',
  `service_start_time` bigint(20) DEFAULT NULL COMMENT '服务开始时间',
  `service_end_time` bigint(20) DEFAULT NULL COMMENT '服务结束时间',
  `service_order_time` bigint(20) DEFAULT NULL COMMENT '服务预约日期',
  `service_order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '服务预约类型 1-购买服务 2-长者照护计划 3-已购买服务套餐 ',
  `lat` varchar(32) DEFAULT NULL COMMENT '经度',
  `lng` varchar(32) DEFAULT NULL COMMENT '纬度',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `position_desc` varchar(225) DEFAULT NULL COMMENT '坐标位置名称',
  `sign_in_time` bigint(20) DEFAULT '0' COMMENT '签到时间',
  `service_result` varchar(255) DEFAULT NULL COMMENT '服务结果',
  `audio_url` text COMMENT '录音',
  `picture_url` text COMMENT '图片',
  `evaluation` varchar(255) DEFAULT NULL COMMENT '评价',
  `evaluation_time` bigint(20) DEFAULT '0' COMMENT '评价时间',
  `staff_id` varchar(32) DEFAULT NULL COMMENT '服务人员id',
  `staff_name` varchar(32) DEFAULT NULL COMMENT '服务人员姓名',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_order_id`),
  KEY `attendance_item_id` (`attendance_item_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='护理项目预约表';

-- ----------------------------
-- Table structure for lb_ims_attendance_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_record`;
CREATE TABLE `lb_ims_attendance_record` (
  `attendance_record_id` varchar(32) NOT NULL COMMENT '护理记录id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `attendance_id` varchar(32) NOT NULL COMMENT '护理项目id',
  `nurse_id_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1: lb_account表account_id、2：lb_ims_staff表staff_id',
  `nurse_id` varchar(32) DEFAULT NULL COMMENT '护工id',
  `nurse_name` varchar(32) DEFAULT NULL COMMENT '护工名字',
  `start_execute_time` bigint(20) DEFAULT NULL COMMENT '开始执行时间',
  `end_execute_time` bigint(20) DEFAULT NULL COMMENT '结束执行时间',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `attendance_execute_time` bigint(20) DEFAULT NULL COMMENT '护理执行时间',
  `remark` varchar(255) DEFAULT '' COMMENT '备注',
  `image` text COMMENT '图片',
  `attendance_item_id` varchar(32) DEFAULT NULL COMMENT '护理项目ＩＤ',
  `cancellation_id` varchar(32) DEFAULT NULL COMMENT '作废人Id',
  `cancellation_name` varchar(32) DEFAULT NULL COMMENT '作废人',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态 1:未开始 2:进行中 3:已完成 4：作废',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_record_id`) USING BTREE,
  KEY `attendance_id` (`attendance_id`) USING BTREE,
  KEY `attendance_item_id` (`attendance_item_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `is_delete` (`is_delete`) USING BTREE,
  KEY `attendance_execute_time` (`attendance_execute_time`) USING BTREE,
  KEY `end_execute_time` (`end_execute_time`) USING BTREE,
  KEY `start_execute_time` (`start_execute_time`) USING BTREE,
  KEY `idx_update_time` (`update_time`),
  KEY `idx_nurse_id` (`nurse_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理项目记录表';

-- ----------------------------
-- Table structure for lb_ims_attendance_record_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_record_info`;
CREATE TABLE `lb_ims_attendance_record_info` (
  `record_info_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `date_str` varchar(32) NOT NULL DEFAULT '' COMMENT '日期',
  `defecation` varchar(125) NOT NULL DEFAULT '' COMMENT '排便情况',
  `skin_condition` varchar(125) NOT NULL DEFAULT '' COMMENT '皮肤情况',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_info_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='按需护理表单表';

-- ----------------------------
-- Table structure for lb_ims_attendance_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_attendance_type`;
CREATE TABLE `lb_ims_attendance_type` (
  `attendance_type_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT NULL COMMENT '名称',
  `introduction` varchar(250) DEFAULT NULL COMMENT '说明',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`attendance_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理项目类型表';

-- ----------------------------
-- Table structure for lb_ims_balance
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_balance`;
CREATE TABLE `lb_ims_balance` (
  `balance_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `account_preparatory_balance` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '账户预存款余额',
  `one_card_balance` decimal(32,2) DEFAULT '0.00' COMMENT '一卡通余额',
  `total_deposit_balance` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总押金余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '账户状态（0 正常，1 冻结（退住结算中），2 注销（已结算退住））',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `version` int(32) NOT NULL DEFAULT '1' COMMENT '版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`balance_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='余额表';

