  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者费用调整表';

-- ----------------------------
-- Table structure for lb_ims_care_object_expense_discount
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_care_object_expense_discount`;
CREATE TABLE `lb_ims_care_object_expense_discount` (
  `expense_discount_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `discount_flag` tinyint(1) NOT NULL COMMENT '0首次减免 1 每月减免 2 历史数据状态 3 无减免优惠',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `discount_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '减免开始时间',
  `discount_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '减免结束时间',
  `pay_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT ' 缴费模式 0 缴费至月底 1 整月缴费',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`expense_discount_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者入住缴费优惠折扣表';

-- ----------------------------
-- Table structure for lb_ims_care_object_expense_settle
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_care_object_expense_settle`;
CREATE TABLE `lb_ims_care_object_expense_settle` (
  `expense_settle_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `relation_id` varchar(32) DEFAULT NULL COMMENT '床位、餐饮、护理关联主键',
  `expense_id` varchar(64) NOT NULL COMMENT '费用主键',
  `expense_name` varchar(32) NOT NULL COMMENT '费用名称',
  `expense_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '收费标准',
  `discount_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '折扣金额',
  `discount_rate` decimal(14,12) NOT NULL DEFAULT '1.000000000000' COMMENT '折扣率',
  `settle_amount` varchar(32) NOT NULL COMMENT '当月实际收费',
  `settle_month` varchar(32) NOT NULL COMMENT '收费月份',
  `settle_type` tinyint(1) DEFAULT '0' COMMENT '结算账单类型（缴费日期前：0、缴费日期后：1、自动扣费：2）',
  `recharge_status` tinyint(1) DEFAULT '0' COMMENT '账单是否月结充值;0:未月结充值,1:已月结充值',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`expense_settle_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者月度结算费用记录表';

-- ----------------------------
-- Table structure for lb_ims_care_object_expense_settle_month
-- ----------------------------
