  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `settle_month` varchar(32) NOT NULL DEFAULT '' COMMENT '收费月份',
  `payment_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '缴费时间',
  `pay_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '缴费金额',
  `consumption_pattern` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费方式',
  `remark` text NOT NULL COMMENT '备注',
  `bank_id` varchar(32) NOT NULL DEFAULT '' COMMENT '银行主键',
  `bank_name` varchar(32) NOT NULL DEFAULT '' COMMENT '银行名称',
  `bank_card_num` varchar(32) NOT NULL DEFAULT '' COMMENT '银行卡号',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `is_sync` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否同步到金蝶（0 未同步，1 已同步）',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 月结账单缴费 2 账户余额充值退费 ',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0 正常 1 作废 ',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`expense_month_pay_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者月结账单缴费记录表';

