-- ----------------------------
-- Table structure for lb_ims_care_object_treaty
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_care_object_treaty`;
CREATE TABLE `lb_ims_care_object_treaty` (
  `care_object_treaty_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT 'object主键',
  `contacts_id` varchar(64) NOT NULL COMMENT '看护对象亲属表主键',
  `sign_time` bigint(20) DEFAULT '0' COMMENT '签约时间',
  `cost` decimal(10,2) DEFAULT '0.00' COMMENT '费用',
  `consumption_pattern` varchar(32) NOT NULL DEFAULT '' COMMENT '消费方式（0 账户余额，1 一卡通余额，2 微信，3 支付宝，4 银行卡，5 现金）',
  `remark` varchar(128) DEFAULT NULL COMMENT '备注',
  `contacts_name` varchar(32) DEFAULT '' COMMENT '签订协议亲属姓名',
  `contacts_phone` varchar(32) DEFAULT '' COMMENT '签订协议亲属联系方式',
  `contacts_relation` varchar(32) DEFAULT '' COMMENT '签订协议亲属与看护人的关系',
  `region` varchar(32) DEFAULT '' COMMENT '签订协议亲属的省/市/区',
  `address` varchar(32) DEFAULT '' COMMENT '签订协议亲属的地址',
  `signing_time` bigint(20) DEFAULT '0' COMMENT '签约时间',
  `file_url` text COMMENT '文件地址',
  `file_name` text COMMENT '文件名称',
  `registrant_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人Id',
  `registrant_name` varchar(20) DEFAULT NULL COMMENT '登记人',
  `registrant` varchar(20) DEFAULT '' COMMENT '登记人',
  `registrant_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `remarks` varchar(128) DEFAULT '' COMMENT '备注',
  `expense_amount` decimal(10,2) DEFAULT '0.00' COMMENT '费用',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_treaty_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='协议表';

-- ----------------------------
-- Table structure for lb_ims_case_service_record
-- ----------------------------
