CREATE TABLE `lb_ims_case_service_record` (
  `case_service_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '服务长者id',
  `service_mode` varchar(32) NOT NULL DEFAULT '' COMMENT '服务方式',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `appeal` text COMMENT '长者主诉(诉求)',
  `future_concerns` text COMMENT '长者对将来的忧虑',
  `service_process` text COMMENT '服务信息-服务过程',
  `service_evaluation` text COMMENT '评估信息-服务评估',
  `follow_advice` text COMMENT '跟进建议',
  `signature_picture_url` varchar(64) DEFAULT '' COMMENT '签名图片地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `attachment_id` varchar(512) NOT NULL DEFAULT '' COMMENT '上传附件id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`case_service_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='个案服务记录表';

-- ----------------------------
-- Table structure for lb_ims_certificate
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_certificate`;
