  `register_account_id` varchar(32) DEFAULT ' ' COMMENT '登记账号',
  `register_name` varchar(125) DEFAULT '' COMMENT '登记人姓名',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `settle_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结算时间',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`check_out_record_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='退住登记信息';

-- ----------------------------
-- Table structure for lb_ims_clean_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_clean_record`;
CREATE TABLE `lb_ims_clean_record` (
  `clean_record_id` varchar(32) NOT NULL,
  `area_id` varchar(32) NOT NULL COMMENT '保洁房间id',
  `clean_reason` varchar(32) NOT NULL COMMENT '保洁原因',
  `clean_name` varchar(32) DEFAULT NULL COMMENT '保洁人姓名',
  `account_id` varchar(32) DEFAULT NULL COMMENT '清洁人员主键',
  `is_clean` tinyint(4) NOT NULL DEFAULT '1' COMMENT '保洁状态 1 未完成 2 已完成 3 保洁中',
  `phone_num` varchar(20) DEFAULT NULL COMMENT '保洁手机号',
  `start_time` bigint(20) DEFAULT '0' COMMENT '保洁开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '保洁结束时间',
  `finish_time` bigint(20) DEFAULT NULL COMMENT '保洁完成时间',
  `check_account_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `check_account_name` varchar(32) DEFAULT NULL COMMENT '登记人姓名',
  `check_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否 删除 0 否 1 是',
  `pic_url` text COMMENT '图片URL ；分号隔开',
  `sign_url` text COMMENT '签字图片url',
  `relation` int(4) DEFAULT NULL COMMENT '签字人与长者关系',
  `door_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上门时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`clean_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='机构保洁记录表';

-- ----------------------------
-- Table structure for lb_ims_complaint_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_complaint_record`;
CREATE TABLE `lb_ims_complaint_record` (
  `complaint_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `complaint_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `complaint_object` varchar(128) DEFAULT NULL COMMENT '姓名',
  `complaint_type` int(11) DEFAULT NULL COMMENT '投诉方式',
  `complaint_content` varchar(255) DEFAULT NULL COMMENT '投诉内容',
  `complaint_time` bigint(20) DEFAULT '0' COMMENT '投诉时间',
  `dispose_state` tinyint(1) DEFAULT '0' COMMENT '处理state 0未处理1已经处理',
  `dispose_time` bigint(20) DEFAULT '0' COMMENT '处理时间',
  `return_state` tinyint(1) DEFAULT '0' COMMENT '回访state 0未回访1已经回访',
  `return_remark` varchar(255) DEFAULT NULL COMMENT '回访说明',
  `record_url` text COMMENT '录音地址',
  `register_account_id` varchar(32) NOT NULL COMMENT '登记id',
  `register_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `dispose_result` varchar(255) DEFAULT '' COMMENT '处理结果',
  `return_time` bigint(20) DEFAULT '0' COMMENT '回访时间',
  `dispose_name` varchar(32) DEFAULT '' COMMENT '处理人',
  `return_name` varchar(100) DEFAULT '' COMMENT '回访人',
  `complaint_phone` varchar(32) DEFAULT '' COMMENT '投诉人手机号',
  `dispose_account_id` varchar(32) DEFAULT '' COMMENT '处理人账号唯一标识',
  `return_account_id` varchar(32) DEFAULT '',
  `source_id` varchar(32) NOT NULL DEFAULT '' COMMENT '投诉来源',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `platform_scene` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:社区/家床 1:机构 默认0',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`complaint_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='投诉记录表';

-- ----------------------------
-- Table structure for lb_ims_consult_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_consult_record`;
CREATE TABLE `lb_ims_consult_record` (
  `consult_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `consult_class` varchar(32) DEFAULT '1' COMMENT '咨询分类 字典表：consult_type ',
  `consult_hobby` varchar(32) DEFAULT NULL COMMENT '咨询人兴趣爱好',
  `elder_name` varchar(128) DEFAULT NULL COMMENT '长者姓名',
  `identity` varchar(32) DEFAULT NULL COMMENT '长者身份证',
  `gender` varchar(32) DEFAULT NULL COMMENT '性别',
  `birthday` bigint(20) DEFAULT NULL COMMENT '生日',
  `elder_phone` varchar(32) DEFAULT NULL COMMENT '长者手机号',
  `oneself_situation` varchar(32) DEFAULT NULL COMMENT '自理情况',
  `census_register_region` varchar(255) DEFAULT NULL COMMENT '户籍地址region',
  `census_register` varchar(255) DEFAULT NULL COMMENT '户籍地址',
  `home_region` varchar(255) DEFAULT NULL COMMENT '家庭住址region',
  `home_address` varchar(255) DEFAULT NULL COMMENT '家庭住址',
  `hobbies_interests` varchar(255) NOT NULL DEFAULT '' COMMENT '兴趣爱好',
  `consult_name` varchar(128) NOT NULL COMMENT '咨询人姓名',
  `consult_phone` varchar(32) NOT NULL COMMENT '咨询人手机号',
  `relation` varchar(32) NOT NULL COMMENT '与长者关系',
  `consult_mode` varchar(32) NOT NULL COMMENT '咨询方式',
  `consult_time` bigint(20) NOT NULL COMMENT '咨询时间',
  `media_channel` varchar(32) DEFAULT NULL COMMENT '媒体渠道',
  `consult_content` text COMMENT '接待情况描述',
  `consult_resistance_problem` varchar(255) DEFAULT NULL COMMENT '咨询人抗性问题',
  `housing_situation` varchar(255) DEFAULT NULL COMMENT '客户住房情况',
  `focus_other` varchar(255) DEFAULT NULL COMMENT '客户关注竞品情况',
  `receiver_id` bigint(20) DEFAULT NULL COMMENT '接待人id',
  `receiver_name` varchar(32) NOT NULL COMMENT '接待人name',
  `receiver_phone` varchar(20) DEFAULT NULL COMMENT '接待人手机号',
  `is_in` tinyint(1) DEFAULT NULL COMMENT '是否已经转入住',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '登记人账号id',
  `registration_name` varchar(32) DEFAULT NULL COMMENT '登记人账号名称',
  `return_visit_relation` varchar(32) DEFAULT NULL COMMENT '被回访人与长者关系',
  `return_visit_result` varchar(255) DEFAULT NULL COMMENT '回访结果',
  `return_visit_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '回访时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `age` int(10) DEFAULT NULL COMMENT '年龄',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consult_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='咨询登记记录表';

-- ----------------------------
-- Table structure for lb_ims_consumer_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_consumer_device`;
CREATE TABLE `lb_ims_consumer_device` (
  `device_id` varchar(32) NOT NULL COMMENT '设备id',
  `num` varchar(32) DEFAULT NULL COMMENT '编号',
  `name` varchar(32) DEFAULT NULL COMMENT '名称',
  `type` tinyint(1) DEFAULT '0' COMMENT '类型：0食堂消费机1超市消费机2其他',
  `department_id` varchar(32) DEFAULT NULL COMMENT '部门id',
  `manager` varchar(32) DEFAULT NULL COMMENT '管理人员',
  `max_pay` decimal(10,2) DEFAULT '0.00' COMMENT '最大消费金额',
  `auto_change` tinyint(1) DEFAULT NULL COMMENT '是否自动变换定额0否1是',
  `ip` varchar(32) DEFAULT NULL COMMENT 'ip地址',
  `status` tinyint(1) DEFAULT '0' COMMENT '设备状态0离线1在线',
  `last_online_time` bigint(20) DEFAULT NULL COMMENT '最后在线时间',
  `open_time` bigint(20) DEFAULT NULL COMMENT '开通时间',
  `pay_mode` tinyint(1) DEFAULT NULL COMMENT '消费模式0手动',
  `total_expend` decimal(8,2) DEFAULT '0.00' COMMENT '累计消费金额',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='消费机';

-- ----------------------------
-- Table structure for lb_ims_consumption_adjust
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_consumption_adjust`;
CREATE TABLE `lb_ims_consumption_adjust` (
  `consumption_adjust_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `consumption_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '消费记录id',
  `adjust_month` varchar(32) NOT NULL DEFAULT '' COMMENT '退费月份',
  `before_expense_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '调整前月实收金额',
  `after_expense_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '调整后月实收金额',
  `expense_id` varchar(64) NOT NULL DEFAULT '' COMMENT '费用项目主键',
  `expense_name` varchar(32) NOT NULL DEFAULT '' COMMENT '费用类别名称',
  `expense_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '调整金额',
  `remark` varchar(255) NOT NULL DEFAULT '' COMMENT '备注',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_adjust_id`),
  KEY `org_id_index` (`org_id`),
  KEY `care_object_id_index` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消费变更记录表';

-- ----------------------------
-- Table structure for lb_ims_consumption_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_consumption_record`;
CREATE TABLE `lb_ims_consumption_record` (
  `consumption_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_id` varchar(64) DEFAULT NULL COMMENT '消费详情记录主键',
  `consumption_type` tinyint(1) NOT NULL COMMENT '消费类型（0 账户充值，1 一卡通充值，2 押金充值， 3 账户余额消费，4 一卡通余额消费，5  入住缴费）',
  `consumer` varchar(32) DEFAULT '' COMMENT '消费人',
  `consumption_pattern` varchar(32) NOT NULL DEFAULT '' COMMENT '消费方式',
  `consumption_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '消费金额',
  `consumption_return_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '退费金额',
  `start_time` bigint(20) DEFAULT '0' COMMENT '消费开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '消费结束时间',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '收费人',
  `registrant_name` varchar(32) NOT NULL DEFAULT '' COMMENT '收费人姓名',
  `consumption_remark` text COMMENT '消费备注',
  `consumption_detail` text COMMENT '流水详情说明',
  `expense_name` varchar(32) DEFAULT '' COMMENT '费用名称,(记录为入院总缴费时,0:首月减免,1每月减免,2老数据总费用减免)',
  `expense_amount` varchar(32) DEFAULT '' COMMENT '费用金额',
  `expense_type` tinyint(1) DEFAULT NULL COMMENT '费用类型',
  `expense_nature` tinyint(1) DEFAULT NULL COMMENT '费用性质 0-日常费用 1-月收费用 2-年收费用 3-特殊费用 4-押金 5-阶段性费用 6-床位费 7-餐饮费 8-护理费 9-定制护理费 10-水费 11-电费 12-医嘱取药 13-检查化验 14-自主点餐 99-入住总缴费',
  `expense_remark` text COMMENT '费用备注',
  `account_preparatory_balance` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '账户预存款余额',
  `one_card_balance` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '一卡通余额',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '消费状态（0 正常，1 作废，2 退费 ,3入院缴费退住结算）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `discount_rate` varchar(32) NOT NULL DEFAULT '1' COMMENT '折扣率',
  `discount_amount` decimal(10,2) DEFAULT '0.00' COMMENT '折扣金额',
  `expense_id` varchar(64) DEFAULT NULL COMMENT '费用主键，暂为入院缴费使用',
  `derate_after` decimal(10,2) DEFAULT NULL COMMENT '减免后应收费',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `round_off` tinyint(1) NOT NULL DEFAULT '1' COMMENT '账单金额计算模式 1 保留两位（默认） 2 取整',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`consumption_record_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `record_id` (`record_id`) USING BTREE,
  KEY `registrant` (`registrant`) USING BTREE,
  KEY `consumption_type` (`consumption_type`),
  KEY `start_time` (`start_time`),
  KEY `expense_nature` (`expense_nature`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消费记录表';

-- ----------------------------
-- Table structure for lb_ims_dementia_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_dementia_config`;
CREATE TABLE `lb_ims_dementia_config` (
  `dementia_config_id` varchar(64) NOT NULL COMMENT '主键',
  `educational` varchar(32) DEFAULT NULL COMMENT '学历情况',
  `assessment` varchar(255) DEFAULT NULL COMMENT '综合评价',
  `tag` int(1) DEFAULT NULL COMMENT '评价标识',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `score_start` int(11) NOT NULL DEFAULT '0' COMMENT '得分标准开始',
  `score_end` int(11) NOT NULL DEFAULT '0' COMMENT '得分标准结束',
  `dementia_standard` varchar(128) NOT NULL DEFAULT '' COMMENT '得分标准等级',
  `device_recommend` varchar(128) NOT NULL DEFAULT '' COMMENT '设备推荐',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`dementia_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='失智评估标准配置';

-- ----------------------------
-- Table structure for lb_ims_department
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_department`;
CREATE TABLE `lb_ims_department` (
  `department_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `department_name` varchar(32) NOT NULL DEFAULT '' COMMENT '部门名称',
  `department_head` varchar(32) DEFAULT '' COMMENT '部门领导',
  `office_location` varchar(32) DEFAULT '' COMMENT '办公位置',
  `phone_num` varchar(11) DEFAULT '' COMMENT '手机号码',
  `superior_department` varchar(32) DEFAULT '0' COMMENT '上级部门',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `department_type` varchar(32) DEFAULT NULL COMMENT '部门类型:0其他部门 1综合管理部 2财务管理部 3安全保障部 4后勤管理部 5护理管理部 6医务管理部 7人事管理部 8管家管理部',
  `in_care_notice` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否接收长者入住通知(0:否  1:是)',
  `order_num` int(11) NOT NULL DEFAULT '1' COMMENT '序号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`department_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='部门表';

-- ----------------------------
-- Table structure for lb_ims_department_framework
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_department_framework`;
CREATE TABLE `lb_ims_department_framework` (
  `department_id` varchar(32) NOT NULL COMMENT '主键',
  `department_name` varchar(32) NOT NULL DEFAULT '' COMMENT '部门名称',
  `superior_department_id` varchar(32) DEFAULT '0' COMMENT '上级部门',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`department_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='部门下级组织表';

-- ----------------------------
-- Table structure for lb_ims_deposit_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_deposit_record`;
CREATE TABLE `lb_ims_deposit_record` (
  `deposit_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `consumer` varchar(32) DEFAULT '' COMMENT '交费人',
  `consumption_pattern` varchar(32) NOT NULL DEFAULT '' COMMENT '消费方式',
  `consumption_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '交费金额',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '交费时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '退还时间',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '收费人',
  `registrant_name` varchar(32) NOT NULL COMMENT '收费人姓名',
  `consumption_remark` text COMMENT '备注',
  `expense_name` varchar(32) DEFAULT '' COMMENT '费用名称',
  `expense_amount` varchar(32) DEFAULT '' COMMENT '费用金额',
  `expense_type` tinyint(1) DEFAULT NULL COMMENT '费用类型',
  `expense_nature` tinyint(1) DEFAULT NULL COMMENT '费用性质',
  `expense_remark` text COMMENT '费用备注',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '押金状态（0 已交， 1 已退还）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `total_deposit_balance` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总押金余额',
  `round_off` tinyint(1) NOT NULL DEFAULT '1' COMMENT '账单金额计算模式 1 保留两位（默认） 2 取整',
  `refund_percentage` int(11) NOT NULL DEFAULT '0' COMMENT '退款百分比',
  `refund_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '退款金额',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`deposit_record_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `registrant` (`registrant`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='押金记录表';

-- ----------------------------
-- Table structure for lb_ims_dept_approval
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_dept_approval`;
CREATE TABLE `lb_ims_dept_approval` (
  `dept_approval_id` varchar(32) NOT NULL COMMENT '审批主健',
  `dept_id` varchar(32) NOT NULL DEFAULT '1' COMMENT '部门id 或员工id',
  `approval_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '类型 1 部门 2 员工',
  `type` tinyint(4) NOT NULL COMMENT '审批类型 1：用人管理审批 2 内外勤审批 3 物品管理审批 4 事务工作审批  5 公司福利审批 6 报销付款审批',
  `account_id` varchar(32) NOT NULL COMMENT '审批人id',
  `level` int(10) NOT NULL COMMENT '审批级别',
  `create_time` bigint(20) NOT NULL COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`dept_approval_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='部门审批表';

-- ----------------------------
-- Table structure for lb_ims_device_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_device_type`;
CREATE TABLE `lb_ims_device_type` (
  `device_type_id` varchar(32) NOT NULL COMMENT '主键',
  `device_name` varchar(32) DEFAULT '' COMMENT '设备名称',
  `device_mode` varchar(32) DEFAULT '' COMMENT '设备型号',
  `device_product_factory` varchar(64) DEFAULT '' COMMENT '设备厂家',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='设备型号表';

-- ----------------------------
-- Table structure for lb_ims_disease_course
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_disease_course`;
CREATE TABLE `lb_ims_disease_course` (
  `disease_course_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者主键',
  `general_situation` text COMMENT '一般情况',
  `check_result` text COMMENT '检查结果',
  `condition_change` text COMMENT '病情变化',
  `treatment` text COMMENT '治疗情况',
  `register_doctor` varchar(500) DEFAULT NULL COMMENT '登记医生',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` varchar(100) DEFAULT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`disease_course_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='病程表';

-- ----------------------------
-- Table structure for lb_ims_disease_course_first
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_disease_course_first`;
CREATE TABLE `lb_ims_disease_course_first` (
  `disease_course_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者主键',
  `characteristics` text COMMENT '病历特点',
  `tentative_diagnosis` text COMMENT '初步诊断',
  `discuss` text COMMENT '拟诊讨论',
  `treatment_plan` text COMMENT '诊疗计划',
  `register_doctor` varchar(500) DEFAULT NULL COMMENT '登记医生',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` varchar(100) DEFAULT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`disease_course_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='首次病程表';

-- ----------------------------
-- Table structure for lb_ims_drug
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug`;
CREATE TABLE `lb_ims_drug` (
  `drug_id` varchar(32) NOT NULL COMMENT '药物id',
  `code` varchar(32) NOT NULL COMMENT '编码',
  `name` varchar(32) NOT NULL COMMENT '名称',
  `type` varchar(32) NOT NULL COMMENT '类型:1中药2西药',
  `specifications` varchar(32) DEFAULT NULL COMMENT '规格:1片2支3粒4瓶5袋6其他',
  `dosage_form` varchar(32) DEFAULT NULL COMMENT '剂型:1片剂2针剂3颗粒4胶囊5其他',
  `factory` varchar(32) DEFAULT NULL COMMENT '厂家',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='药物表';

-- ----------------------------
-- Table structure for lb_ims_drug_apply_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug_apply_record`;
CREATE TABLE `lb_ims_drug_apply_record` (
  `drug_apply_record_id` varchar(32) NOT NULL COMMENT '用药记录id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `drug_id` varchar(32) NOT NULL COMMENT '药品id',
  `apply_type` tinyint(1) DEFAULT NULL COMMENT '0:常规1:临时',
  `register_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
  `register_staff_id` varchar(32) DEFAULT NULL COMMENT '登记人主键',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `apply_time` bigint(20) DEFAULT NULL COMMENT '用药时间',
  `apply_time_part` tinyint(3) DEFAULT NULL COMMENT '0:早1:中2:晚',
  `apply_count` varchar(32) NOT NULL DEFAULT '0' COMMENT '用药数量',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0 护士工作站用药登记  1 药剂师工作站发药登记 2 医嘱用药记录',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_apply_record_id`) USING BTREE,
  KEY `drug_id` (`drug_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `idx_type` (`type`),
  KEY `idx_is_delete` (`is_delete`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='用药记录表';

-- ----------------------------
-- Table structure for lb_ims_drug_apply_remark
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug_apply_remark`;
CREATE TABLE `lb_ims_drug_apply_remark` (
  `drug_apply_remark_id` varchar(32) NOT NULL COMMENT '用药登记备注id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `apply_time` bigint(20) DEFAULT NULL COMMENT '用药时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_apply_remark_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用药登记备注表';

-- ----------------------------
-- Table structure for lb_ims_drug_apply_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug_apply_setting`;
CREATE TABLE `lb_ims_drug_apply_setting` (
  `drug_apply_setting_id` varchar(32) NOT NULL COMMENT '用药设置id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `drug_id` varchar(32) NOT NULL COMMENT '药品id',
  `apply_time_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0：餐前 1：餐后 2：餐中 3:睡前',
  `register_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `apply_count` tinyint(3) DEFAULT '0' COMMENT '用药次数',
  `day_count` tinyint(3) DEFAULT '0' COMMENT '天数',
  `morning_count` float DEFAULT '0' COMMENT '早上用药数量',
  `noon_count` float DEFAULT '0' COMMENT '中午用药数量',
  `night_count` float DEFAULT '0' COMMENT '晚上用药数量',
  `custom_one_count` float NOT NULL DEFAULT '0' COMMENT '自定义用药数量一',
  `custom_two_count` float NOT NULL DEFAULT '0' COMMENT '自定义用药数量二',
  `custom_three_count` float NOT NULL DEFAULT '0' COMMENT '自定义用药数量三',
  `medicate_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '用药方式 0-手动登记 1-自动登记',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 本人自带药品  2 医嘱药品记录',
  `drug_frequency_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用药频次id',
  `drug_frequency_count` varchar(10) NOT NULL DEFAULT '' COMMENT '每次用药量,支持分数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_apply_setting_id`) USING BTREE,
  KEY `drug_id` (`drug_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='用药设置表';

-- ----------------------------
-- Table structure for lb_ims_drug_storage
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug_storage`;
CREATE TABLE `lb_ims_drug_storage` (
  `drug_storage_id` varchar(32) NOT NULL COMMENT '缴存药品id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `drug_id` varchar(32) NOT NULL COMMENT '药品id',
  `COUNT` varchar(10) NOT NULL DEFAULT '0' COMMENT '用药数量',
  `warn_count` float DEFAULT '0' COMMENT '预警数量',
  `correction_status` varchar(32) DEFAULT NULL COMMENT '校正状态 1 损耗　2 补录',
  `refund_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退缴状态 0-未退缴 1-已退缴',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 本人自带药品  2 医嘱药品记录',
  `is_common_drug` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否常用药 0否1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_storage_id`) USING BTREE,
  KEY `drug_id` (`drug_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='缴存药品表';

-- ----------------------------
-- Table structure for lb_ims_drug_storage_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_drug_storage_record`;
CREATE TABLE `lb_ims_drug_storage_record` (
  `drug_storage_recorｄ_id` varchar(32) NOT NULL COMMENT '缴存记录id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `drug_id` varchar(32) NOT NULL COMMENT '药品id',
  `storage_way` tinyint(1) DEFAULT '0' COMMENT '0:本人缴存、1:院方缴存、２:家属代缴',
  `storage_account_name` varchar(128) DEFAULT NULL COMMENT '缴存人姓名',
  `register_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `count` float DEFAULT '0' COMMENT '数量',
  `status` tinyint(3) DEFAULT '0' COMMENT '缴存记录状态　０－缴存　１－退缴',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `sign_url` varchar(128) DEFAULT NULL COMMENT '签字地址',
  `relation` varchar(128) DEFAULT NULL COMMENT '关系',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 本人自带药品  2 医嘱药品记录',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`drug_storage_recorｄ_id`),
  KEY `drug_id` (`drug_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='缴存记录表';

-- ----------------------------
-- Table structure for lb_ims_electronic_medical_history
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_electronic_medical_history`;
CREATE TABLE `lb_ims_electronic_medical_history` (
  `electronic_medical_history_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `narrator` varchar(32) DEFAULT NULL COMMENT '病史叙述者',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `main_suit` text COMMENT '主诉',
  `history_present_illness` text COMMENT '现病史',
  `previous_history` text COMMENT '既往史',
  `personal_history` text COMMENT '个人史',
  `exposure_history` text COMMENT '暴露史',
  `food_drug_allergic_history` text COMMENT '食物及药物过敏史',
  `obstetrical_history` text COMMENT '婚育史',
  `temperature` varchar(100) DEFAULT NULL COMMENT '体温',
  `pulse` varchar(100) DEFAULT NULL COMMENT '脉搏',
  `breathe` varchar(100) DEFAULT NULL COMMENT '呼吸',
  `high_pressure` varchar(100) DEFAULT NULL COMMENT '血压高压',
  `low_pressure` varchar(100) DEFAULT NULL COMMENT '血压低压',
  `bloodSugar` varchar(32) DEFAULT NULL COMMENT '血糖',
  `weight` varchar(32) DEFAULT NULL COMMENT '体重',
  `height` varchar(32) DEFAULT NULL COMMENT '身高',
  `blood_sugar` varchar(32) DEFAULT NULL COMMENT '血糖',
  `speciality_check_up` text COMMENT '专科检查',
  `auxiliary_examination` text COMMENT '辅助检查',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `record_time` bigint(20) DEFAULT NULL COMMENT '首次病程记录时间',
  `record_doctor_name` varchar(100) DEFAULT NULL COMMENT '记录医生',
  `record_doctor_id` varchar(100) DEFAULT NULL COMMENT '记录医生主键id',
  `characteristics` text COMMENT '病历特点',
  `tentative_diagnosis` text COMMENT '初步诊断',
  `discuss` text COMMENT '拟诊讨论',
  `treatment_plan` text COMMENT '诊疗计划',
  `family_history` text COMMENT '家族史',
  `disease` varchar(100) DEFAULT NULL COMMENT '疾病编码',
  `outpatient_info_id` varchar(32) DEFAULT NULL COMMENT '就诊记录ID',
  `total_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '就诊费用',
  `physical_check` text COMMENT '体格检查',
  `diagnosis_type` tinyint(1) DEFAULT NULL COMMENT '诊断类型',
  `diagnosis_result` varchar(100) DEFAULT '' COMMENT '诊断结果',
  `suggest` varchar(100) DEFAULT '' COMMENT '建议',
  `handle_suggest` varchar(100) DEFAULT '' COMMENT '处理意见',
  `create_doctor_id` varchar(32) DEFAULT '' COMMENT '就诊医生id',
  `create_doctor_name` varchar(32) DEFAULT '' COMMENT '就诊医生姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`electronic_medical_history_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='电力病历表';

-- ----------------------------
-- Table structure for lb_ims_evaluate
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_evaluate`;
CREATE TABLE `lb_ims_evaluate` (
  `id` varchar(32) NOT NULL,
  `star_rating` tinyint(4) NOT NULL DEFAULT '0' COMMENT '星级',
  `evaluate` tinytext NOT NULL COMMENT '评价',
  `evaluate_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '评价类型(0:未知 1:点餐评价 2:购物评价)',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联id',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='评价表';

-- ----------------------------
-- Table structure for lb_ims_expense
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_expense`;
CREATE TABLE `lb_ims_expense` (
  `expense_id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `expense_name` varchar(32) NOT NULL DEFAULT '' COMMENT '费用名称',
  `expense_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '费用类型（0 默认初始费用，1 非初始费用，2 设置初始费用 ）',
  `expense_nature` tinyint(1) NOT NULL COMMENT '费用性质（0 日常费用，1 月收费用，2 年收费用，3 特殊费用，4 押金，5 阶段性费用，6 床位费，7 餐饮费，8 护理费，9 定制护理费 ）',
  `expense_amount` varchar(32) NOT NULL DEFAULT '' COMMENT '收费标准',
  `tax_rate` tinyint(1) NOT NULL DEFAULT '0' COMMENT '税率',
  `tax_rate_remark` varchar(255) DEFAULT NULL COMMENT '税率备注',
  `expense_remark` text COMMENT '费用备注',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人',
  `registrant_name` varchar(32) NOT NULL COMMENT '登记人姓名',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `expense_period` tinyint(1) NOT NULL DEFAULT '0' COMMENT '收费时段',
  `kingdee_code` varchar(32) NOT NULL DEFAULT '' COMMENT '金蝶费用编码',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`expense_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `expense_name` (`expense_name`),
  KEY `create_time` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用表';

-- ----------------------------
-- Table structure for lb_ims_expense_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_expense_setting`;
CREATE TABLE `lb_ims_expense_setting` (
  `setting_id` varchar(20) NOT NULL,
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `percent` int(11) NOT NULL DEFAULT '0' COMMENT '违约金收费比例',
  `out_days` int(11) DEFAULT NULL COMMENT '请假外出天数',
  `settle_data` tinyint(1) NOT NULL DEFAULT '0' COMMENT '自动扣费日期',
  `settle_update_time` bigint(20) DEFAULT '0' COMMENT '自动扣费日期更新时间',
  `expense_natures` varchar(20) NOT NULL DEFAULT '' COMMENT '费用性质（6 床位费，7 餐饮费，8 护理费，9 定制护理费 ）',
  `balance_warning` decimal(10,2) NOT NULL DEFAULT '100.00' COMMENT '账户余额提醒设置',
  `expire_warning` int(11) NOT NULL DEFAULT '90' COMMENT '合同到期提醒设置',
  `bill_push` tinyint(1) NOT NULL DEFAULT '1' COMMENT '预缴账单推送设置 1、默认 2、所有长者推送 3、部分长者推送',
  `display_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '账单显示 1、账单为0元时显示 2、账单为0元时不显示 ',
  `deduction_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '扣费模式 1、形成账单时扣除账户余额费用 2、形成账单时不扣除费用，需手动扣费 ',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `default_time` tinyint(1) DEFAULT '7' COMMENT '按需护理表单登记默认开始时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='费用管理设置';

-- ----------------------------
-- Table structure for lb_ims_expense_setting_out
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_expense_setting_out`;
CREATE TABLE `lb_ims_expense_setting_out` (
  `setting_id` varchar(20) NOT NULL,
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `out_days` int(11) DEFAULT NULL COMMENT '请假外出天数',
  `expense_natures` varchar(20) DEFAULT NULL COMMENT '费用性质（6 床位费，7 餐饮费，8 护理费，9 定制护理费 ）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='请假外出设置历史记录';

-- ----------------------------
-- Table structure for lb_ims_fire_fighting_activity
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_fire_fighting_activity`;
CREATE TABLE `lb_ims_fire_fighting_activity` (
  `activity_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `activity_content` varchar(32) NOT NULL DEFAULT '' COMMENT '活动内容',
  `activity_location` varchar(64) DEFAULT '' COMMENT '活动地点',
  `department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '承办部门主键',
  `department_name` varchar(32) NOT NULL DEFAULT '' COMMENT '承办部门名称',
  `convener_id` varchar(64) NOT NULL DEFAULT '' COMMENT '召集人主键',
  `convener_name` varchar(64) NOT NULL DEFAULT '' COMMENT '召集人姓名',
  `registrant_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `activity_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '活动时间',
  `participant` text NOT NULL COMMENT '参与人员',
  `activity_desc` varchar(255) DEFAULT '' COMMENT '活动详情',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`activity_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `department_id` (`department_id`) USING BTREE,
  KEY `convener_id` (`convener_id`) USING BTREE,
  KEY `registrant_id` (`registrant_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消防活动记录表';

-- ----------------------------
-- Table structure for lb_ims_fire_fighting_inspect
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_fire_fighting_inspect`;
CREATE TABLE `lb_ims_fire_fighting_inspect` (
  `inspect_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `inspect_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查类型（0 报警器检查，1 水电线路检查， 2 防火巡查，3 灭火器检查）',
  `device_name` varchar(32) DEFAULT '' COMMENT '设备名称',
  `inspect_location` varchar(255) NOT NULL DEFAULT '' COMMENT '检查位置',
  `inspect_content_one` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容一（0 正常，1 异常）',
  `inspect_content_two` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容二（0 正常，1 异常）',
  `inspect_content_three` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容三（0 正常，1 异常）',
  `inspect_content_four` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容四（0 正常，1 异常）',
  `inspect_content_five` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容五（0 正常，1 异常）',
  `inspect_content_six` tinyint(1) NOT NULL DEFAULT '0' COMMENT '检查内容六（0 正常，1 异常）',
  `inspector_id` varchar(64) NOT NULL DEFAULT '' COMMENT '检查人主键',
  `inspector_name` varchar(64) DEFAULT '' COMMENT '检查人姓名',
  `inspect_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '检查时间',
  `remark` varchar(255) DEFAULT '' COMMENT '备注',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态（0 正常，1 异常）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inspect_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `inspector_id` (`inspector_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='消防检查记录表';

-- ----------------------------
-- Table structure for lb_ims_follow_up_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_follow_up_record`;
CREATE TABLE `lb_ims_follow_up_record` (
  `follow_up_record_id` varchar(32) NOT NULL COMMENT '主键',
  `marketing_customer_id` varchar(32) NOT NULL COMMENT '客户记录id',
  `staff_id` varchar(32) NOT NULL COMMENT '跟进业务员id',
  `staff_name` varchar(32) NOT NULL COMMENT '业务员姓名',
  `follow_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '跟进时间',
  `follow_way` varchar(32) DEFAULT NULL COMMENT '跟进方式',
  `remark` text COMMENT '备注',
  `picture` text COMMENT '图片',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`follow_up_record_id`),
  KEY `org_id` (`org_id`),
  KEY `index_follow_time` (`follow_time`),
  KEY `index_marketing_customer_id` (`marketing_customer_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='跟进记录表';

-- ----------------------------
-- Table structure for lb_ims_food
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food`;
CREATE TABLE `lb_ims_food` (
  `food_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `food_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食物类别主键',
  `food_name` varchar(32) NOT NULL DEFAULT '' COMMENT '食物名称',
  `spice` varchar(32) NOT NULL DEFAULT '' COMMENT '辣味',
  `texture` varchar(32) NOT NULL DEFAULT '' COMMENT '口感',
  `taste` varchar(32) NOT NULL DEFAULT '' COMMENT '口味',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '价格',
  `is_order` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可点（0 不可点，1 可点）',
  `term` tinyint(1) DEFAULT NULL COMMENT '长短期（0 短期，1 长期）',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `food_desc` text COMMENT '食材说明',
  `taboo` text COMMENT '禁忌项',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '食物图片地址',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `food_type` varchar(32) NOT NULL DEFAULT '' COMMENT '菜品类型',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `meal` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次类别',
  `food_name_initial` varchar(32) NOT NULL DEFAULT '' COMMENT '食物名称首字母',
  `is_discount` tinyint(1) NOT NULL DEFAULT '1' COMMENT '参与折扣（0 不参与，1 参与）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_sort_id` (`food_sort_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食物表';

-- ----------------------------
-- Table structure for lb_ims_food_export
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_export`;
CREATE TABLE `lb_ims_food_export` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '类型(0:未知 1:点餐订单 2:线上订单 3:食谱订单)',
  `num` int(11) NOT NULL DEFAULT '0' COMMENT '导出数量',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '状态(进度 0:等待导出 1:导出中 2:导出完成)',
  `result` varchar(64) NOT NULL DEFAULT '' COMMENT '结果',
  `url` varchar(64) NOT NULL DEFAULT '' COMMENT '地址',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='点餐导出';

-- ----------------------------
-- Table structure for lb_ims_food_meal
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_meal`;
CREATE TABLE `lb_ims_food_meal` (
  `food_meal_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `meal` tinyint(1) NOT NULL COMMENT '餐次（0 早茶，1 早餐，2 午餐，3 下午茶，4 晚餐，5 宵夜）',
  `start_time` varchar(16) NOT NULL DEFAULT '' COMMENT '开始时间',
  `end_time` varchar(16) NOT NULL DEFAULT '' COMMENT '结束时间',
  `registrant` varchar(32) DEFAULT '' COMMENT '登记人',
  `registrant_id` varchar(64) DEFAULT '' COMMENT '登记人主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `delivery_expense` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '送餐费用',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认 0否 1是',
  `meal_desc` varchar(16) NOT NULL DEFAULT '' COMMENT '餐次描述',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_meal_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `meal` (`meal`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='餐次表';

-- ----------------------------
-- Table structure for lb_ims_food_meal_daily
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_meal_daily`;
CREATE TABLE `lb_ims_food_meal_daily` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键id',
  `food_meal_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次id',
  `food_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食物id',
  `order_num` int(3) NOT NULL DEFAULT '1' COMMENT '展示顺序',
  `day_of_week` tinyint(1) NOT NULL DEFAULT '1' COMMENT '星期数',
  `meal_week` bigint(20) NOT NULL DEFAULT '0' COMMENT '餐次所属周（时间戳）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='今日菜品:餐次-食物';

-- ----------------------------
-- Table structure for lb_ims_food_meal_daily_photo
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_meal_daily_photo`;
CREATE TABLE `lb_ims_food_meal_daily_photo` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `meal_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次id',
  `photo` text COMMENT '图片地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='今日菜品一览表-大屏显示图片信息';

-- ----------------------------
-- Table structure for lb_ims_food_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_order`;
CREATE TABLE `lb_ims_food_order` (
  `food_order_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `orderer` varchar(128) NOT NULL DEFAULT '' COMMENT '下单人',
  `meal` tinyint(1) NOT NULL COMMENT '餐次（0 早茶，1 早餐，2 午餐，3 下午茶，4 晚餐，5 宵夜）',
  `order_content` text NOT NULL COMMENT '点餐内容',
  `order_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '点餐总价',
  `delivery_address` varchar(100) DEFAULT '' COMMENT '送餐地址',
  `meal_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '就餐时间',
  `order_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '下单时间',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订餐状态（0 待送餐/出餐，1 已送餐/出餐，2 已取消，3 已超时，4 送餐中，5 预约待确认）',
  `deliverer` varchar(32) NOT NULL DEFAULT '' COMMENT '送餐人',
  `delivery_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '送餐时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `deliverer_id` varchar(64) NOT NULL DEFAULT '' COMMENT '送餐人主键',
  `orderer_id` varchar(64) NOT NULL DEFAULT '' COMMENT '下单人主键',
  `settle_method` tinyint(1) NOT NULL DEFAULT '0' COMMENT '结算方式（0-账户余额，1-一卡通余额， 2-现金支付）',
  `order_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '点餐类型（0-食谱点餐，1-平台在线点餐，2-护工APP点餐，3-长者APP点餐，4-管家工作站点餐）',
  `cancel_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '取消类型（0 未取消，1 系统取消，2 人为取消）',
  `refund_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '退款状态（0 未退款，1 待退款，2 已退款，3-无法退款, 4 已作废）',
  `timeout_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '超时时间',
  `meal_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '就餐方式（0-店内就餐， 1-送餐上门， 2-打包带走 ）',
  `diners_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '就餐人类型（0-长者，1-员工，2-其他）',
  `delivery_expense` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '送餐费用',
  `remark` text COMMENT '备注',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `serial_num` smallint(6) NOT NULL DEFAULT '0' COMMENT '流水号',
  `take_num` varchar(3) NOT NULL DEFAULT '' COMMENT '取餐号',
  `actual_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '实收金额（现金支付有效）',
  `refund_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '退款时间',
  `refunder_id` varchar(64) NOT NULL DEFAULT '' COMMENT '退款人主键',
  `refunder_name` varchar(128) NOT NULL DEFAULT '' COMMENT '退款人姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `fee_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '费用账户id',
  PRIMARY KEY (`food_order_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `orderer_id` (`orderer_id`) USING BTREE,
  KEY `status` (`status`) USING BTREE,
  KEY `refund_status` (`refund_status`) USING BTREE,
  KEY `order_type_IDX` (`order_type`) USING BTREE,
  KEY `create_time_IDX` (`create_time`) USING BTREE,
  KEY `fee_account_id_index` (`fee_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='订餐记录表';

-- ----------------------------
-- Table structure for lb_ims_food_order_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_order_detail`;
CREATE TABLE `lb_ims_food_order_detail` (
  `food_order_detail_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `food_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '点餐订单主键',
  `food_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食物类别主键',
  `food_id` varchar(32) DEFAULT '' COMMENT '食物主键',
  `food_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '食物类型（0-食谱，1-食物）',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '食物名称',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '食物图片',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '食物价格',
  `food_content` text COMMENT '食物内容',
  `num` float(10,1) NOT NULL DEFAULT '0.0' COMMENT '点餐数量',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `recipe_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱类别主键',
  `recipe_id` varchar(32) DEFAULT '' COMMENT '食谱主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_order_detail_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `food_order_id` (`food_order_id`) USING BTREE,
  KEY `food_sort_id` (`food_sort_id`) USING BTREE,
  KEY `food_id` (`food_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='订餐明细表';

-- ----------------------------
-- Table structure for lb_ims_food_order_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_order_setting`;
CREATE TABLE `lb_ims_food_order_setting` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `settle_method` varchar(16) NOT NULL DEFAULT '0,1,2' COMMENT '点餐支付方式设置(type=1:0-账户余额，1-一卡通余额， 2-现金支付，3-微信支付，4-支付宝支付，type=2:1-一卡通余额，2-账户余额，3-现金支付，4-微信，5-支付宝)',
  `is_take_num` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否弹窗设置取参号(1:弹窗  0:不弹窗)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '类型(1:点餐、2:商品)',
  `food_show_flag` tinyint(1) NOT NULL DEFAULT '1' COMMENT '菜品信息查询规则：1:当天设置的菜品信息 0:当天所有菜品信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='点餐流程设置';

-- ----------------------------
-- Table structure for lb_ims_food_purchase
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_purchase`;
CREATE TABLE `lb_ims_food_purchase` (
  `food_purchase_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `purchase_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '采购日期',
  `purchase_detail` text NOT NULL COMMENT '采购食材明细',
  `purchase_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '采购总金额',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `remark` varchar(200) DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_purchase_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食材采购记录表';

-- ----------------------------
-- Table structure for lb_ims_food_shop
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_shop`;
CREATE TABLE `lb_ims_food_shop` (
  `food_shop_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `shop_name` varchar(32) NOT NULL DEFAULT '' COMMENT '店铺名称',
  `shop_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '店铺类型（0-食堂， 1-餐饮店）',
  `shop_address` varchar(256) NOT NULL DEFAULT '' COMMENT '店铺地址',
  `contact_name` varchar(32) NOT NULL DEFAULT '' COMMENT '联系人',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '联系人手机号',
  `remark` varchar(256) DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `shop_photo` varchar(64) NOT NULL DEFAULT '' COMMENT '店铺图片地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_shop_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='餐饮店铺表';

-- ----------------------------
-- Table structure for lb_ims_food_shop_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_shop_account`;
CREATE TABLE `lb_ims_food_shop_account` (
  `food_shop_account_id` varchar(32) NOT NULL COMMENT '主键',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_shop_account_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='餐饮店铺用户关联表';

-- ----------------------------
-- Table structure for lb_ims_food_sort
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_food_sort`;
CREATE TABLE `lb_ims_food_sort` (
  `food_sort_id` varchar(32) NOT NULL COMMENT '主键',
