  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`food_sort_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食物类别表';

-- ----------------------------
-- Table structure for lb_ims_go_to_doctor_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_go_to_doctor_record`;
CREATE TABLE `lb_ims_go_to_doctor_record` (
  `go_to_doctor_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `time` bigint(20) DEFAULT '0' COMMENT '就医时间',
  `doctor_name` varchar(32) DEFAULT NULL COMMENT '医生',
  `doctor_adress` varchar(255) DEFAULT NULL COMMENT '就医地点',
  `symptoms` text COMMENT '症状',
  `diagnosis` text COMMENT '诊断',
  `doctor_advice` text COMMENT '医嘱',
  `receiver_id` bigint(20) DEFAULT NULL COMMENT '登记id',
  `receiver_name` varchar(32) DEFAULT NULL COMMENT '登记人name',
  `registration_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `registration_type` varchar(32) DEFAULT '' COMMENT '登记人员类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`go_to_doctor_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='就医记录表';

-- ----------------------------
-- Table structure for lb_ims_good_borrow
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_good_borrow`;
CREATE TABLE `lb_ims_good_borrow` (
  `good_borrow_id` varchar(32) NOT NULL COMMENT '主键',
  `good_id` varchar(32) NOT NULL COMMENT '物品id',
  `borrow_user_id` varchar(32) NOT NULL COMMENT '借用人id',
  `borrow_user_name` varchar(32) NOT NULL COMMENT '借用人姓名',
  `borrow_duration` int(10) DEFAULT NULL COMMENT '借用时长',
  `use` varchar(255) DEFAULT NULL COMMENT '用途',
  `register_name` varchar(32) NOT NULL COMMENT '登记人',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `borrow_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '借用时间',
  `return_time` bigint(20) DEFAULT NULL COMMENT '归还时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `amount` int(10) DEFAULT '1' COMMENT '借用物品数量',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`good_borrow_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='公共物品借用';

-- ----------------------------
-- Table structure for lb_ims_goods
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods`;
CREATE TABLE `lb_ims_goods` (
  `goods_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_title` varchar(64) DEFAULT '' COMMENT '商品',
  `goods_detail` text COMMENT '卖点描述',
  `original_price` decimal(10,2) DEFAULT '0.00' COMMENT '商品原价',
  `selling_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品售价',
  `status` tinyint(4) DEFAULT '1' COMMENT '状态(1:正在销售,2:停止售卖)',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '商品类型',
  `goods_url` varchar(128) DEFAULT '' COMMENT '商品图片路径',
  `specification` varchar(32) DEFAULT '' COMMENT '商品规格(套,只,个,台)',
  `goods_packing` varchar(32) DEFAULT '' COMMENT '商品包装',
  `recommend_level` tinyint(4) DEFAULT '0' COMMENT '推荐级别',
  `pull_time` bigint(20) DEFAULT NULL COMMENT '下架时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '生成人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `barcode` varchar(128) NOT NULL DEFAULT '' COMMENT '条码',
  `inventory` int(11) NOT NULL DEFAULT '0' COMMENT '库存',
  `warning_inventory` int(11) NOT NULL DEFAULT '0' COMMENT '预警库存',
  `cost_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品成本价',
  `is_automatic_sales` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为自动售卖机售卖商品 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_id`),
  KEY `org_index` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `barcode` (`barcode`) USING BTREE,
  KEY `goods_type_id` (`goods_type_id`) USING BTREE,
  KEY `is_delete` (`is_delete`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='商品表';

-- ----------------------------
-- Table structure for lb_ims_goods_barcode
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_barcode`;
