  `goods_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品主键',
  `goods_title` varchar(64) NOT NULL DEFAULT '' COMMENT '商品名称',
  `barcode` varchar(128) NOT NULL DEFAULT '' COMMENT '商品条码',
  `specification` varchar(32) DEFAULT '' COMMENT '商品规格',
  `goods_packing` varchar(32) DEFAULT '' COMMENT '商品包装',
  `inventory_num` int(11) NOT NULL DEFAULT '0' COMMENT '库存数量',
  `change_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '变动类型（1-入库，2-出库，3-报废）',
  `change_num` int(11) NOT NULL DEFAULT '0' COMMENT '变动数量',
  `remark` varchar(100) DEFAULT '' COMMENT '备注',
