  `operator` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `operate_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '操作时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
