  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='商品库存变动记录表';

-- ----------------------------
