-- ----------------------------
-- Table structure for lb_ims_goods_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_order`;
CREATE TABLE `lb_ims_goods_order` (
  `goods_order_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '用户',
  `goods_total_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '商品总价',
  `discounts_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '优惠金额',
  `order_total_prices` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '订单总价',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '订单状态(1：长者下单  2:管家已确认 3:送货中 4:已取消 5 送货完成)',
  `refund_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '退款状态 （0 未退款 1 已退款）',
  `buy_way` tinyint(4) NOT NULL DEFAULT '1' COMMENT '购买方式(1:平台商城下单，2:长者APP下单)',
  `pay_way` tinyint(2) DEFAULT '1' COMMENT '支付方式(1 一卡通余额 2 账户余额)',
  `pay_time` bigint(20) DEFAULT NULL COMMENT '付款时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '生成人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `actual_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '实收金额（现金支付有效）',
  `total_cost` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总成本',
  `serial_num` smallint(6) NOT NULL DEFAULT '1' COMMENT '流水号',
  `delivery_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '送货时间',
  `place_order_name` varchar(32) NOT NULL DEFAULT '' COMMENT '下单人姓名',
  `consumer_name` varchar(128) NOT NULL DEFAULT '' COMMENT '消费人姓名',
  `device_sn` varchar(32) NOT NULL DEFAULT '' COMMENT '消费设备编码（售货柜编码）',
  `pay_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '订单支付状态 0 未支付 1 已支付',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `fee_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '费用账户id',
  PRIMARY KEY (`goods_order_id`),
  KEY `care_object_index` (`care_object_id`) USING BTREE,
  KEY `org_index` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `fee_account_id_index` (`fee_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单表';

-- ----------------------------
-- Table structure for lb_ims_goods_order_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_order_detail`;
CREATE TABLE `lb_ims_goods_order_detail` (
  `goods_order_detail_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_order_id` varchar(32) NOT NULL COMMENT '订单号',
  `goods_id` varchar(20) NOT NULL COMMENT '商品id',
  `goods_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品支付的时单价',
  `discounted_goods_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品折扣后支付的时单价',
  `goods_num` int(10) NOT NULL COMMENT '商品的数量',
  `order_amount` decimal(10,2) DEFAULT NULL COMMENT '订单金额',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) DEFAULT NULL COMMENT '生成人',
  `update_by` varchar(32) DEFAULT NULL COMMENT '更新人',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `cost_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '商品成本价',
  `goods_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商品类别主键',
  `order_cost` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '订单成本',
  `goods_title` varchar(64) DEFAULT '' COMMENT '商品名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_order_detail_id`) USING BTREE,
  KEY `goods_order_index` (`goods_order_id`) USING BTREE,
  KEY `goods_id` (`goods_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单详细表';

-- ----------------------------
-- Table structure for lb_ims_goods_shop
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_shop`;
CREATE TABLE `lb_ims_goods_shop` (
  `goods_shop_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `shop_name` varchar(32) NOT NULL DEFAULT '' COMMENT '店铺名称',
  `shop_address` varchar(255) NOT NULL DEFAULT '' COMMENT '店铺地址',
  `shop_photo` varchar(64) NOT NULL DEFAULT '' COMMENT '店铺图片地址',
  `business` varchar(255) DEFAULT '' COMMENT '主营业务',
  `contact_name` varchar(32) NOT NULL DEFAULT '' COMMENT '负责人姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '负责人手机号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_shop_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='商家店铺表';

-- ----------------------------
-- Table structure for lb_ims_goods_shop_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_shop_account`;
CREATE TABLE `lb_ims_goods_shop_account` (
  `goods_shop_account_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_shop_account_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='商家店铺用户关联表';

-- ----------------------------
-- Table structure for lb_ims_goods_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_goods_type`;
CREATE TABLE `lb_ims_goods_type` (
  `goods_type_id` varchar(32) NOT NULL COMMENT '商品类型主键',
  `name` varchar(32) NOT NULL COMMENT '类别名称',
  `icon_path` varchar(64) DEFAULT NULL COMMENT '图标',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `org_id` varchar(32) NOT NULL,
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `goods_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '商家店铺主键',
  `is_automatic_sales` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为自动售卖机商品类别 1 是 0 否',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`goods_type_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `goods_shop_id` (`goods_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品类型表';

-- ----------------------------
-- Table structure for lb_ims_group_activities
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_group_activities`;
CREATE TABLE `lb_ims_group_activities` (
  `group_activities_id` varchar(32) NOT NULL COMMENT '小组活动id',
  `group_name` varchar(32) NOT NULL DEFAULT '' COMMENT '小组名称',
  `activity_theme` varchar(32) DEFAULT '' COMMENT '活动主题',
  `activity_period` varchar(32) DEFAULT '' COMMENT '活动期次',
  `activity_place` varchar(32) DEFAULT '' COMMENT '活动地点',
  `attendance` int(10) DEFAULT '0' COMMENT '出席人数',
  `attendance_prob` varchar(10) DEFAULT '' COMMENT '出席率',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `activity_evaluation` text COMMENT '活动评估-评估内容',
  `signature_picture_url` varchar(64) DEFAULT '' COMMENT '签名图片地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`group_activities_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='小组活动表';

-- ----------------------------
-- Table structure for lb_ims_group_activities_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_group_activities_record`;
CREATE TABLE `lb_ims_group_activities_record` (
  `group_activities_record_id` varchar(32) NOT NULL COMMENT '活动情况记录id',
  `group_activities_id` varchar(32) NOT NULL COMMENT '小组活动id',
  `activities_time` bigint(20) DEFAULT '0' COMMENT '活动时间',
  `activity_content` text COMMENT '活动内容',
  `activity_condition` text COMMENT '活动情况',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`group_activities_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='小组活动-活动情况表';

-- ----------------------------
-- Table structure for lb_ims_health_assessment_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_assessment_object`;
CREATE TABLE `lb_ims_health_assessment_object` (
  `care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `identity_type` tinyint(1) DEFAULT '0' COMMENT '身份证类型;0:中国居民身份证,1:香港身份证,2:澳门身份证,3:台湾身份证',
  `name` varchar(128) DEFAULT '' COMMENT '名字',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `height` varchar(32) NOT NULL DEFAULT '' COMMENT '身高',
  `weight` varchar(32) NOT NULL DEFAULT '' COMMENT '体重',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `photo` varchar(128) DEFAULT '' COMMENT '头像地址',
  `nation` varchar(32) DEFAULT '' COMMENT '民族',
  `marital_status` varchar(32) DEFAULT NULL COMMENT '婚姻状况',
  `political_status` varchar(32) DEFAULT '' COMMENT '政治面貌',
  `faith` varchar(32) DEFAULT '' COMMENT '宗教信仰',
  `elderly_type` varchar(32) DEFAULT NULL,
  `educational_level` varchar(32) DEFAULT NULL COMMENT '文化程度 9文盲 8半文盲 7小学 6初中 5高中 4中专 3本科 2大专 1研究生 0博士',
  `retired_occupation` varchar(32) DEFAULT '' COMMENT '退休职业',
  `disease_status` text COMMENT '病情状态描述',
  `care_level_id` varchar(32) DEFAULT '' COMMENT '看护等级',
  `assessment_number` varchar(32) NOT NULL COMMENT '评估编号',
  `assessment_class` varchar(32) NOT NULL DEFAULT '' COMMENT '评估分类',
  `assessment_address` varchar(32) NOT NULL DEFAULT '' COMMENT '评估地点',
  `assessment_person` varchar(32) NOT NULL DEFAULT '' COMMENT '评估人员1',
  `assessment_person_two` varchar(32) NOT NULL DEFAULT '' COMMENT '评估人员2',
  `assessment_reason` varchar(32) DEFAULT NULL COMMENT '评估原因',
  `assessment_standard` tinyint(1) DEFAULT '1' COMMENT '评估标准： 1-2013评估标准 2-2022评估标准',
  `social_security_card` varchar(32) DEFAULT NULL COMMENT '社保卡号',
  `pay_type` varchar(128) DEFAULT '' COMMENT '医疗费用支付方式',
  `provide_name` varchar(32) DEFAULT NULL COMMENT '信息提供着姓名',
  `provide_relation` varchar(32) DEFAULT NULL COMMENT '信息提供者与长者关系',
  `provide_phone` varchar(32) DEFAULT NULL COMMENT '信息提供者手机号',
  `contacts_name` varchar(32) DEFAULT '' COMMENT '紧急联系人名字',
  `contacts_phone` varchar(32) DEFAULT '' COMMENT '紧急联系人联系方式',
  `vision` varchar(32) DEFAULT NULL COMMENT '视力',
  `hearing` varchar(32) DEFAULT NULL COMMENT '听力',
  `hospital` varchar(32) DEFAULT NULL COMMENT '主治医院',
  `hospital_doctor` varchar(32) DEFAULT NULL COMMENT '主治医生',
  `hospital_phone` varchar(32) DEFAULT NULL COMMENT '医院电话',
  `drug_allergy` varchar(32) DEFAULT NULL COMMENT '过敏药物',
  `major_diseases` varchar(32) DEFAULT NULL COMMENT '主要疾病',
  `medical_history` varchar(255) DEFAULT '' COMMENT '病史',
  `medicare_type` varchar(255) DEFAULT '' COMMENT '医保类型',
  `src_live` varchar(128) DEFAULT '' COMMENT '居住情况',
  `economic_sources` varchar(128) DEFAULT '' COMMENT '经济来源',
  `assessment_result` varchar(100) DEFAULT NULL COMMENT '健康评估结果',
  `assessment_time` bigint(20) DEFAULT NULL COMMENT '评估时间',
  `choose_answer` json DEFAULT NULL COMMENT '评估题目的选择答案',
  `assessment_level` varchar(100) DEFAULT '' COMMENT '评估等级',
  `labor_power` varchar(32) DEFAULT '' COMMENT '劳动能力',
  `food_allergy_history` varchar(255) DEFAULT NULL COMMENT '食物过敏史',
  `sign_url` varchar(128) DEFAULT NULL COMMENT '签字地址',
  `remark` text COMMENT '备注',
  `assessment_file_url` text COMMENT '附件,多个拼接使用',
  `assessment_file_name` text COMMENT '附件名称,多个拼接使用',
  `tumble_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '跌倒风险',
  `lost_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '走失风险',
  `dysphoria_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '噎食风险',
  `suicide_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '自杀、自伤风险',
  `other_risk` varchar(32) NOT NULL DEFAULT '' COMMENT '其他风险',
  `assessment_type` varchar(32) NOT NULL DEFAULT '1' COMMENT '评估类型',
  `registration_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `registration_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `custom_template_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '模版id',
  `assessment_finish_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '评估状态 0:未评估 1:已评估',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `diagnosis` varchar(255) NOT NULL DEFAULT '' COMMENT '诊断',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='入住前健康评估';

-- ----------------------------
-- Table structure for lb_ims_health_collect_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_collect_data`;
CREATE TABLE `lb_ims_health_collect_data` (
  `health_collect_data_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(100) DEFAULT NULL COMMENT '长者id',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `lowPressure` int(11) DEFAULT NULL COMMENT '舒张压(mmHg)',
  `bloodPressure` int(11) DEFAULT NULL COMMENT '收缩压(mmHg)',
  `bloodSugar` float DEFAULT NULL COMMENT '空腹血糖(mmHg)',
  `PBG` float DEFAULT NULL COMMENT '餐后血糖(mmHg)',
  `bloodOxygen` float DEFAULT NULL COMMENT '血氧饱和度',
  `pulse` int(11) DEFAULT NULL COMMENT '脉搏(分/次)',
  `collect_result` varchar(225) DEFAULT NULL COMMENT '采集结果',
  `registrant_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registrant_name` varchar(32) DEFAULT NULL COMMENT '登记人',
  `registrant_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `breatheRate` int(11) DEFAULT NULL COMMENT '呼吸率',
  `temperature` float DEFAULT NULL COMMENT '体温',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_collect_data_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康采集数据';

-- ----------------------------
-- Table structure for lb_ims_health_guide
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_guide`;
CREATE TABLE `lb_ims_health_guide` (
  `health_guide_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `health_guide_type_id` varchar(32) NOT NULL COMMENT '健康指导类型主键',
  `health_guide_title` varchar(255) NOT NULL COMMENT '项目标题',
  `health_guide_content` varchar(1024) DEFAULT NULL COMMENT '内容',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最后操作时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `release_user_id` varchar(32) DEFAULT NULL COMMENT '发布人id',
  `release_user_name` varchar(32) DEFAULT NULL COMMENT '发布人姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_guide_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='健康指导项目表';

-- ----------------------------
-- Table structure for lb_ims_health_guide_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_guide_type`;
CREATE TABLE `lb_ims_health_guide_type` (
  `health_guide_type_id` varchar(32) NOT NULL COMMENT '主键',
  `health_guide_type_name` varchar(255) NOT NULL DEFAULT '' COMMENT '类型名称',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0否,1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_guide_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='健康指导类型';

-- ----------------------------
-- Table structure for lb_ims_health_index
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_index`;
CREATE TABLE `lb_ims_health_index` (
  `health_index_id` int(10) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `index_type` varchar(32) NOT NULL COMMENT '指标类型',
  `index_name` varchar(32) NOT NULL COMMENT '指标名称',
  `index_min` decimal(10,4) DEFAULT NULL COMMENT '取值范围下界限',
  `index_max` decimal(10,4) DEFAULT NULL COMMENT '取值范围上界限',
  `unit` varchar(32) DEFAULT '' COMMENT '单位',
  `index_describe` varchar(32) NOT NULL COMMENT '描述',
  `color` varchar(32) DEFAULT NULL COMMENT '颜色',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `gender` int(2) DEFAULT NULL,
  `normal` int(2) DEFAULT '0',
  `index_symbol` varchar(32) DEFAULT NULL COMMENT '符号描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_index_id`)
) ENGINE=InnoDB AUTO_INCREMENT=82 DEFAULT CHARSET=utf8mb4 COMMENT='健康数据范围';

-- ----------------------------
-- Table structure for lb_ims_health_plan
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_plan`;
CREATE TABLE `lb_ims_health_plan` (
  `health_plan_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(100) DEFAULT NULL COMMENT '长者id',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `plan_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '计划开始时间',
  `cycle` varchar(32) DEFAULT NULL COMMENT '健康管理周期 字典heal_plan_cycle',
  `type` varchar(32) DEFAULT '' COMMENT '健康管理类别 字典heal_plan_type',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 开启 2关闭',
  `registrant_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registrant_name` varchar(32) DEFAULT NULL COMMENT '登记人',
  `registrant_time` bigint(20) DEFAULT NULL,
  `plan_start_data` json DEFAULT NULL COMMENT '计划开始健康数据',
  `plan_end_data` json DEFAULT NULL COMMENT '计划结束健康数据',
  `advice` text COMMENT '健康建议',
  `summary` varchar(255) DEFAULT NULL COMMENT '健康小结',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `attachment_url` text COMMENT '附件url，多个使用;分号分割',
  `attachment_file_name` text COMMENT '附件文件名称',
  `health_plan_name` varchar(32) NOT NULL DEFAULT '' COMMENT '健康管理计划名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_plan_id`),
  KEY `lb_ism_health_plan_org_id_IDX` (`org_id`,`type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康管理计划';

-- ----------------------------
-- Table structure for lb_ims_health_plan_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_plan_data`;
CREATE TABLE `lb_ims_health_plan_data` (
  `health_plan_data_id` varchar(32) NOT NULL COMMENT '主键',
  `health_plan_id` varchar(32) NOT NULL COMMENT '健康管理计划主键',
  `care_object_id` varchar(100) DEFAULT NULL COMMENT '长者id',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `plan_data` json DEFAULT NULL COMMENT '健康计划数据',
  `record_time` bigint(20) DEFAULT '0' COMMENT '测量时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_plan_data_id`),
  KEY `health_plan_id_org_id_IDX` (`org_id`,`health_plan_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康体征数据';

-- ----------------------------
-- Table structure for lb_ims_health_plan_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_plan_type`;
CREATE TABLE `lb_ims_health_plan_type` (
  `health_plan_type_id` varchar(32) NOT NULL COMMENT '主键',
  `type_name` varchar(32) DEFAULT NULL COMMENT '类别名称',
