  `index_type` text COMMENT '指标英文简称',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_plan_type_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康管理类别';

-- ----------------------------
-- Table structure for lb_ims_health_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_health_record`;
CREATE TABLE `lb_ims_health_record` (
  `health_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '老人姓名',
  `index` varchar(64) NOT NULL DEFAULT '' COMMENT '指标类型',
  `number` varchar(750) DEFAULT NULL COMMENT '指标',
  `monitor_type` varchar(32) NOT NULL DEFAULT '' COMMENT '监测类型',
  `data_src` varchar(32) DEFAULT NULL COMMENT '数据来源,0手动录入 1设备上报 2 健康一体机',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `medical_time` bigint(20) DEFAULT NULL COMMENT '体检时间',
  `device_number` varchar(100) DEFAULT NULL COMMENT '设备型号',
  `device_vendor` varchar(100) DEFAULT NULL COMMENT '设备厂商',
  `medical_record_id` varchar(32) DEFAULT NULL COMMENT '体检记录主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`health_record_id`) USING BTREE,
  KEY `lb_health_record_org_id_IDX` (`org_id`,`care_object_id`,`index`) USING BTREE,
  KEY `medical_record_id_index` (`medical_record_id`),
  KEY `care_object_id_index` (`care_object_id`),
  KEY `lb_ims_health_record_index_IDX` (`index`) USING BTREE,
  KEY `lb_ims_health_record_update_time_IDX` (`update_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='健康档案表';

