-- ----------------------------
-- Table structure for lb_ims_ic_card
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_ic_card`;
CREATE TABLE `lb_ims_ic_card` (
  `card_id` varchar(32) NOT NULL COMMENT '卡id',
  `card_num` varchar(128) NOT NULL COMMENT '卡号',
  `account_id` varchar(32) NOT NULL COMMENT '使用者id',
  `account_name` varchar(128) NOT NULL DEFAULT '' COMMENT '绑定人名称',
  `type_desc` varchar(32) DEFAULT NULL COMMENT '其他人员类型',
  `phone_num` varchar(32) DEFAULT NULL COMMENT '手机号码',
  `account_type` tinyint(1) DEFAULT NULL COMMENT '使用者类型:0长者，1员工， 2其他',
  `card_type` int(11) NOT NULL DEFAULT '0' COMMENT '一卡通类型 默认是普通会员，无折扣率',
  `open_time` bigint(20) DEFAULT '0' COMMENT '开通时间',
  `balance` decimal(10,2) DEFAULT '0.00' COMMENT '余额',
  `total_expend` decimal(10,2) DEFAULT '0.00' COMMENT '累计花费',
  `last_expend_time` bigint(20) DEFAULT '0' COMMENT '上一次消费时间',
  `status` tinyint(1) DEFAULT NULL COMMENT '状态：0已激活，1已冻结，2已注销',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `card_name` varchar(32) NOT NULL DEFAULT '' COMMENT '卡名称',
  `version` int(11) NOT NULL DEFAULT '0' COMMENT '版本号',
  PRIMARY KEY (`card_id`) USING BTREE,
  KEY `card_num_index` (`card_num`),
  KEY `account_id_index` (`account_id`),
  KEY `org_id_index` (`org_id`),
  KEY `card_type_index` (`card_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='IC卡信息表';

