-- Table structure for lb_ims_ic_card_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_ic_card_type`;
CREATE TABLE `lb_ims_ic_card_type` (
  `card_type_id` varchar(32) NOT NULL COMMENT '卡类型id',
  `name` varchar(32) NOT NULL COMMENT '卡类型名称',
  `card_type` int(11) NOT NULL COMMENT '卡类型',
  `discount_rate` varchar(32) NOT NULL COMMENT '折扣率',
  `org_id` varchar(32) NOT NULL COMMENT '机构',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`card_type_id`),
  KEY `card_type_index` (`card_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='IC卡类型表';

-- ----------------------------
-- Table structure for lb_ims_ic_operate_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_ic_operate_record`;
CREATE TABLE `lb_ims_ic_operate_record` (
  `operate_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `operate_type` tinyint(1) DEFAULT NULL COMMENT '操作类型：0激活，1冻结，2注销',
  `operator` varchar(32) NOT NULL COMMENT '操作人',
  `card_id` varchar(32) NOT NULL COMMENT '卡id',
  `card_num` varchar(128) NOT NULL DEFAULT '' COMMENT '卡号',
  `account_id` varchar(32) NOT NULL COMMENT '使用者id',
  `account_name` varchar(128) NOT NULL DEFAULT '' COMMENT '使用者名字',
  `account_type` tinyint(1) DEFAULT NULL COMMENT '使用者类型:0长者，1员工',
  `record_time` bigint(20) DEFAULT '0' COMMENT '操作时间',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`operate_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='卡操作记录';

-- ----------------------------
-- Table structure for lb_ims_ic_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_ic_setting`;
CREATE TABLE `lb_ims_ic_setting` (
  `setting_id` varchar(32) NOT NULL COMMENT '设置id',
  `meal_name` varchar(32) DEFAULT NULL COMMENT '餐次名称',
  `start_time` bigint(20) DEFAULT NULL COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT NULL COMMENT '结束时间',
  `max_amount` decimal(32,2) DEFAULT NULL COMMENT '单次最大金额',
  `max_times` int(10) DEFAULT NULL COMMENT '餐次内最大次数',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `meal` tinyint(1) DEFAULT NULL COMMENT '餐次（0 早茶，1 早餐，2 午餐，3 下午茶，4 晚餐，5 宵夜）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_ims_ic_setting_staff
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_ic_setting_staff`;
CREATE TABLE `lb_ims_ic_setting_staff` (
  `setting_id` varchar(32) NOT NULL COMMENT '设置id',
  `department_id` varchar(32) DEFAULT NULL COMMENT '餐次名称',
  `office_type` varchar(32) NOT NULL DEFAULT '' COMMENT '职务',
  `recharge_amount` decimal(10,2) DEFAULT NULL COMMENT '充值金额',
  `is_auto` tinyint(1) DEFAULT NULL COMMENT '是否自动充值　0非自动　1自动',
  `auto_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 每月自动清除卡余额并自动充值, 2每月自动充值卡余额',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_ims_import_export_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_import_export_task`;
CREATE TABLE `lb_ims_import_export_task` (
  `task_id` varchar(32) NOT NULL DEFAULT '' COMMENT '任务id',
  `task_name` varchar(64) NOT NULL DEFAULT '' COMMENT '任务名称',
  `task_code` varchar(32) NOT NULL DEFAULT '' COMMENT '任务编码',
  `task_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务类型 ',
  `task_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '任务状态1: 待处理2: 导出中3: 已完成4: 导出异常',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '组织id',
  `user_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `priority` int(11) NOT NULL DEFAULT '0' COMMENT '优先级(预留)',
  `task_param` text COMMENT '任务参数',
  `path_key` varchar(64) NOT NULL DEFAULT '' COMMENT '文件存储key',
  `path` text COMMENT '文件路径',
  `file_expiry_date` int(11) NOT NULL DEFAULT '30' COMMENT '文件有效期 单位（天）',
  `result` text COMMENT '处理结果',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `deal_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处理时间',
  `finish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '完成时间',
  `parent_task_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '父任务id,0为无父任务',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务是否删除 0未删除 1已删除',
  `file_is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '文件是否删除 0未删除 1已删除',
  `total` int(11) NOT NULL DEFAULT '0' COMMENT '文件总数',
  `execute_count` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务执行次数',
  `sub_task_count` int(11) NOT NULL DEFAULT '0' COMMENT '子任务数量',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='异步导入导出任务表';

-- ----------------------------
-- Table structure for lb_ims_import_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_import_record`;
CREATE TABLE `lb_ims_import_record` (
  `import_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `file_name` varchar(32) NOT NULL DEFAULT '' COMMENT '导入文件名称',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '导入状态（0-开始，1-完成）',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1-试住长者模板   0-入住长者模板',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `registrant_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`import_record_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='导入长者任务记录表';

-- ----------------------------
-- Table structure for lb_ims_information_exchange
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_information_exchange`;
CREATE TABLE `lb_ims_information_exchange` (
  `information_exchange_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `setting` varchar(32) DEFAULT NULL COMMENT '统计设置',
  `days` tinyint(1) DEFAULT NULL COMMENT '统计天数',
  `type` tinyint(1) DEFAULT NULL COMMENT '统计类型  1-出入场所类型 2-预警信息 3-用药信息 4-用餐信息 5-健康信息',
  `analysis` varchar(255) DEFAULT NULL COMMENT '分析',
  `suggest` varchar(255) DEFAULT NULL COMMENT '建议',
  `is_send` tinyint(1) DEFAULT '0' COMMENT '是否同步发送给子女 0-不发送 1-发送',
  `send_time` bigint(20) DEFAULT '0' COMMENT '发送时间',
  `registrant_id` varchar(32) DEFAULT NULL COMMENT '登记人id',
  `registrant_name` varchar(32) DEFAULT NULL COMMENT '登记人',
  `registrant_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`information_exchange_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='信息交流互动表';

-- ----------------------------
-- Table structure for lb_ims_inspection_health_guide
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_inspection_health_guide`;
CREATE TABLE `lb_ims_inspection_health_guide` (
  `inspection_health_guide_id` varchar(32) NOT NULL COMMENT '主键',
  `inspection_id` varchar(32) NOT NULL COMMENT '巡诊记录主键',
  `health_guide_id` varchar(32) NOT NULL COMMENT '健康指导主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最后操作时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inspection_health_guide_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='巡诊记录健康指导关系';

-- ----------------------------
-- Table structure for lb_ims_inspection_leave_summary
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_inspection_leave_summary`;
CREATE TABLE `lb_ims_inspection_leave_summary` (
  `inspection_leave_summary_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `inspection_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '巡诊日期',
  `check_in_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '入院日期',
  `leave_hospital_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '出院日期',
  `inspection_doctor` varchar(32) NOT NULL COMMENT '巡诊医生',
  `inspection_doctor_id` varchar(32) NOT NULL COMMENT '医生主键',
  `admission_condition` text NOT NULL COMMENT '入院情况',
  `admission_diagnosis` text NOT NULL COMMENT '入院诊断',
  `medicate_history` text NOT NULL COMMENT '用药经过',
  `leave_hospital_condition` text NOT NULL COMMENT '出院时情况',
  `leave_hospital_diagnosis` text NOT NULL COMMENT '出院诊断',
  `leave_hospital_prescribe` text NOT NULL COMMENT '出院医嘱',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inspection_leave_summary_id`),
  KEY `inspection_doctor_id` (`inspection_doctor_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡诊记录-出院小结';

-- ----------------------------
-- Table structure for lb_ims_inspection_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_inspection_record`;
CREATE TABLE `lb_ims_inspection_record` (
  `inspection_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `inspection_time` bigint(20) DEFAULT '0' COMMENT '巡诊日期',
  `inspection_doctor` varchar(32) NOT NULL COMMENT '巡诊医生',
  `temperature` varchar(32) DEFAULT NULL COMMENT '体温',
  `pulse` varchar(32) DEFAULT NULL COMMENT '脉搏',
  `breathe` varchar(32) DEFAULT NULL COMMENT '呼吸',
  `right_blood_pressure_before` varchar(32) DEFAULT NULL COMMENT '右侧血压，前',
  `right_blood_pressure_after` varchar(32) DEFAULT NULL COMMENT '右侧血压后',
  `left_blood_pressure_before` varchar(32) DEFAULT NULL COMMENT '左侧血压，前',
  `left_blood_pressure_after` varchar(32) DEFAULT NULL COMMENT '左侧血压，后',
  `blood_oxygen` varchar(32) DEFAULT NULL COMMENT '血氧饱和度',
  `diet` varchar(255) DEFAULT NULL COMMENT '饮食状况',
  `sleep` varchar(255) DEFAULT NULL COMMENT '睡眠状况',
  `movement` varchar(255) DEFAULT NULL COMMENT '运动状况',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后操作时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '最后更新时间',
  `stool_urine` varchar(255) DEFAULT NULL COMMENT '二便状况',
  `spirit` varchar(255) DEFAULT NULL COMMENT '精神状况',
  `walk_see` varchar(255) DEFAULT NULL COMMENT '巡房所见',
  `doctor_id` varchar(32) DEFAULT '' COMMENT '医生主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inspection_record_id`) USING BTREE,
  KEY `doctor_id` (`doctor_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='巡诊记录';

-- ----------------------------
-- Table structure for lb_ims_inspection_summary
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_inspection_summary`;
CREATE TABLE `lb_ims_inspection_summary` (
  `inspection_summary_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者主键',
  `inspection_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '巡诊日期',
  `inspection_doctor` varchar(32) NOT NULL COMMENT '巡诊医生',
  `inspection_doctor_id` varchar(32) NOT NULL COMMENT '医生主键',
  `general_situation` text NOT NULL COMMENT '一般情况',
  `main_suit` text NOT NULL COMMENT '主诉',
  `history_present_illness` text NOT NULL COMMENT '现病史',
  `evaluation_conclusion` text NOT NULL COMMENT '评估结论',
  `current_situation` text NOT NULL COMMENT '长者目前情况',
  `previous_history` text NOT NULL COMMENT '既往史',
  `physique_examination` text NOT NULL COMMENT '体格检查',
  `auxiliary_examination` text NOT NULL COMMENT '辅助检查',
  `east_diagnosis` text NOT NULL COMMENT '中医诊断',
  `western_diagnosis` text NOT NULL COMMENT '西医诊断',
  `medication_situation` text NOT NULL COMMENT '患者目前用药情况',
  `instruction` text NOT NULL COMMENT '医生指导意见',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1-巡诊记录 2-巡诊小结',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inspection_summary_id`),
  KEY `inspection_doctor_id` (`inspection_doctor_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡诊记录、巡诊小结';

-- ----------------------------
-- Table structure for lb_ims_intention_level
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_intention_level`;
CREATE TABLE `lb_ims_intention_level` (
  `intention_level_id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `intention_level` varchar(32) NOT NULL COMMENT '意向等级',
  `follow_up` int(11) NOT NULL COMMENT '跟进周期',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`intention_level_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='意向等级设置表';

-- ----------------------------
-- Table structure for lb_ims_interactive_registration
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_interactive_registration`;
CREATE TABLE `lb_ims_interactive_registration` (
  `interactive_registration_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `contacts_name` varchar(128) DEFAULT '' COMMENT '亲属姓名',
  `contacts_relation` int(4) DEFAULT '0' COMMENT '亲属和互动对象的关系(字典表type=relation)',
  `interactive_mod` int(4) DEFAULT '0' COMMENT '互动方式(字典表type=interactive_mod)',
  `interactive_content` varchar(128) DEFAULT '' COMMENT '互动内容',
  `concat_time` bigint(20) DEFAULT '0' COMMENT '联系时间',
  `remark` varchar(128) DEFAULT '' COMMENT '备注',
  `registrant` varchar(32) DEFAULT NULL COMMENT '登记人',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`interactive_registration_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='亲属互动登记表';

-- ----------------------------
-- Table structure for lb_ims_interview_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_interview_record`;
CREATE TABLE `lb_ims_interview_record` (
  `interview_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `interview_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '面谈类型（1-健康面谈， 2-营养面谈）',
  `target` text NOT NULL COMMENT '面谈目标',
  `detail` text NOT NULL COMMENT '面谈详情',
  `interview_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '面谈时间',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`interview_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='面谈记录表';

-- ----------------------------
-- Table structure for lb_ims_inventory_supplies
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_inventory_supplies`;
CREATE TABLE `lb_ims_inventory_supplies` (
  `inventory_supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_id` varchar(32) DEFAULT '' COMMENT '仓库id',
  `admin_name` varchar(64) DEFAULT '' COMMENT '管理员姓名',
  `admin_id` varchar(32) DEFAULT '' COMMENT '管理员',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人id',
  `type` tinyint(1) DEFAULT '0' COMMENT '0:库存管理,1:药品仓库',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`inventory_supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='盘点物资信息表';

-- ----------------------------
-- Table structure for lb_ims_invoice_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_invoice_record`;
CREATE TABLE `lb_ims_invoice_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '',
  `title_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '抬头类型 (0企业/1个人)',
  `titel_name` varchar(32) NOT NULL DEFAULT '' COMMENT '抬头名称(企业-公司名称/个人-个人姓名)',
  `vat` varchar(32) NOT NULL DEFAULT '' COMMENT '税号',
  `address` varchar(64) NOT NULL DEFAULT '' COMMENT '地址',
  `phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '电话',
  `bank` varchar(16) NOT NULL DEFAULT '' COMMENT '开户银行',
  `bank_num` varchar(32) NOT NULL DEFAULT '' COMMENT '银行账户',
  `remark` varchar(64) DEFAULT '' COMMENT '备注',
  `total_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '开票金额',
  `email` varchar(32) NOT NULL DEFAULT '' COMMENT '邮箱',
  `status` tinyint(1) NOT NULL COMMENT '开票状态 (0待开/1已开)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `order_content` text NOT NULL COMMENT '充值订单记录(lb_ims_sms_topup_order)',
  `record_type` varchar(10) NOT NULL DEFAULT '1' COMMENT '开票类型(1 短信充值 2 守护长者充值  多个逗号分割)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='发票申请记录';

-- ----------------------------
-- Table structure for lb_ims_kingdee_bank
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_kingdee_bank`;
CREATE TABLE `lb_ims_kingdee_bank` (
  `bank_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `bank_name` varchar(32) NOT NULL DEFAULT '' COMMENT '银行卡名称',
  `bank_card_num` varchar(32) NOT NULL DEFAULT '' COMMENT '银行卡号',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 银行账号 2 微信账号 3 支付宝账号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`bank_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='金蝶银行账号设置表';

-- ----------------------------
-- Table structure for lb_ims_kingdee_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_kingdee_care_object`;
CREATE TABLE `lb_ims_kingdee_care_object` (
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `care_object_name` varchar(32) NOT NULL DEFAULT '' COMMENT '长者名称',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联金蝶系统id',
  `number` varchar(32) NOT NULL DEFAULT '' COMMENT '关联金蝶系统number',
  `bank_name` varchar(64) NOT NULL DEFAULT '' COMMENT '开户行',
  `bank_account` varchar(32) NOT NULL DEFAULT '' COMMENT '银行账号',
  `bank_user` varchar(32) NOT NULL DEFAULT '' COMMENT '开户人',
  `bank_phone_num` varchar(32) NOT NULL DEFAULT '' COMMENT '开户人联系电话',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_object_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='金蝶关联客户表';

-- ----------------------------
-- Table structure for lb_ims_kingdee_sync
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_kingdee_sync`;
CREATE TABLE `lb_ims_kingdee_sync` (
  `kingdee_sync_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '长者主键',
  `check_in_num` varchar(64) NOT NULL DEFAULT '' COMMENT '长者入住编号',
  `settle_month` varchar(32) NOT NULL DEFAULT '' COMMENT '收费月份',
  `receivable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '应收单 0未同步 1已同步',
  `payment` tinyint(1) NOT NULL DEFAULT '0' COMMENT '收款单 0未同步 1已同步',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`kingdee_sync_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='金蝶同步记录表';

-- ----------------------------
-- Table structure for lb_ims_marketing_building
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_building`;
CREATE TABLE `lb_ims_marketing_building` (
  `building_id` varchar(32) NOT NULL DEFAULT '' COMMENT '楼栋id',
  `building_name` varchar(32) NOT NULL DEFAULT '' COMMENT '楼栋名称id',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`building_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='房源管理';

-- ----------------------------
-- Table structure for lb_ims_marketing_buy_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_buy_record`;
CREATE TABLE `lb_ims_marketing_buy_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '',
  `room_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间id',
  `customer_id` varchar(32) NOT NULL DEFAULT '' COMMENT '客户id',
  `staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '业务员id',
  `pay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '付款方式(0:商业贷款 1:公积金贷款 2:组合贷款)',
  `discount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '优惠金额',
  `discount_total` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '折后总价',
  `down_payment` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '首付',
  `business_loan` decimal(10,1) DEFAULT '0.0' COMMENT '商业贷款',
  `fund_loan` decimal(10,1) DEFAULT '0.0' COMMENT '公积金贷款',
  `lpr` decimal(5,2) DEFAULT '0.00' COMMENT 'LPR',
  `bp` decimal(5,2) DEFAULT '0.00' COMMENT '基点(BP)',
  `business_rate` decimal(5,2) DEFAULT '0.00' COMMENT '商贷利率',
  `fund_rate` decimal(5,2) DEFAULT '0.00' COMMENT '公积金利率',
  `loan_time` int(10) NOT NULL DEFAULT '0' COMMENT '贷款期限',
  `repay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '还款方式(0:等额本息  1:等额本金)',
  `remark` text COMMENT '备注',
  `register_name` varchar(20) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='购房成单记录';

-- ----------------------------
-- Table structure for lb_ims_marketing_customer_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_customer_record`;
CREATE TABLE `lb_ims_marketing_customer_record` (
  `marketing_customer_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(128) DEFAULT NULL COMMENT '名字',
  `gender` varchar(32) DEFAULT NULL COMMENT '性别',
  `phone_num` varchar(32) DEFAULT NULL COMMENT '电话号码',
  `phone_num_standby` varchar(32) DEFAULT NULL COMMENT '备用手机号码',
  `intention_level` varchar(64) DEFAULT NULL COMMENT '意向等级',
  `first_intention_level` varchar(64) DEFAULT NULL COMMENT '首次意向等级',
  `next_follow_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '下次跟进时间',
  `consult_way` varchar(32) DEFAULT NULL COMMENT '咨询方式',
  `media_channel` varchar(32) DEFAULT NULL COMMENT '媒体渠道',
  `remark` text COMMENT '备注',
  `customer_source` varchar(125) DEFAULT NULL COMMENT '客户来源',
  `visit_number` varchar(125) DEFAULT NULL COMMENT '来访次数',
  `first_visit_time` bigint(20) DEFAULT NULL COMMENT '首次来访时间',
  `purpose_purchase` varchar(125) DEFAULT NULL COMMENT '购房用途',
  `age_group` varchar(125) DEFAULT NULL COMMENT '年龄段',
  `industry` varchar(125) DEFAULT NULL COMMENT '所属行业',
  `profession` varchar(125) DEFAULT NULL COMMENT '职业',
  `residential_area` varchar(125) DEFAULT NULL COMMENT '居住区域',
  `work_area` varchar(125) DEFAULT NULL COMMENT '工作区域',
  `marital_status` varchar(32) DEFAULT NULL COMMENT '婚姻状况  1已婚 3未婚 2离异 4丧偶',
  `residential_structure` varchar(125) DEFAULT NULL COMMENT '居住结构',
  `intention_area` varchar(125) DEFAULT NULL COMMENT '意向面积',
  `intention_floor` varchar(125) DEFAULT NULL COMMENT '意向楼层',
  `intention_house_type` varchar(125) DEFAULT NULL COMMENT '意向房型',
  `intention_price` varchar(125) DEFAULT NULL COMMENT '意向价格',
  `concern_factor` varchar(125) DEFAULT NULL COMMENT '关注因素',
  `children_view` varchar(32) DEFAULT NULL COMMENT '子女对于养老机构观念',
  `financial_support` varchar(32) DEFAULT NULL COMMENT '资金支持',
  `last_allocation_time` bigint(20) DEFAULT NULL COMMENT '最近分配时间',
  `house_condition` varchar(32) DEFAULT NULL COMMENT '房屋状况',
  `reservation_count` int(11) NOT NULL DEFAULT '0' COMMENT '预约入住次数',
  `house_purchase_count` int(11) NOT NULL DEFAULT '0' COMMENT '购房成交次数',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '客户状态：1、公共客户 2、无效客户 3、跟进中客户',
  `staff_id` varchar(32) NOT NULL COMMENT '业务员id',
  `staff_name` varchar(32) NOT NULL COMMENT '业务员姓名',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `recycle_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '回收时间',
  `recycle_remark` varchar(32) NOT NULL DEFAULT '' COMMENT '回收说明',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`marketing_customer_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='营销客户记录表';

-- ----------------------------
-- Table structure for lb_ims_marketing_customer_recycle
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_customer_recycle`;
CREATE TABLE `lb_ims_marketing_customer_recycle` (
  `customer_recycle_id` varchar(32) NOT NULL COMMENT '主键',
  `marketing_customer_id` varchar(32) NOT NULL DEFAULT '' COMMENT '客户id',
  `staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '业务员id',
  `staff_name` varchar(32) NOT NULL DEFAULT '' COMMENT '业务员姓名',
  `recycle_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '回收时间',
  `recycle_remark` varchar(32) NOT NULL DEFAULT '' COMMENT '回收说明',
  `read_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0未读、1已读',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`customer_recycle_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='回收提醒记录表';

-- ----------------------------
-- Table structure for lb_ims_marketing_customer_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_customer_relation`;
CREATE TABLE `lb_ims_marketing_customer_relation` (
  `customer_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `marketing_customer_id` varchar(32) NOT NULL DEFAULT '' COMMENT '客户A主键',
  `marketing_customer_relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联客户B主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`customer_relation_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='关联客户关系表';

-- ----------------------------
-- Table structure for lb_ims_marketing_plan
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_plan`;
CREATE TABLE `lb_ims_marketing_plan` (
  `plan_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `plan_name` varchar(32) NOT NULL DEFAULT '' COMMENT '方案名称',
  `media_channel` varchar(32) NOT NULL DEFAULT '' COMMENT '媒体渠道',
  `plan_detail` varchar(255) NOT NULL DEFAULT '' COMMENT '方案详情',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant_name` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`plan_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='营销方案表';

-- ----------------------------
-- Table structure for lb_ims_marketing_room
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_marketing_room`;
CREATE TABLE `lb_ims_marketing_room` (
  `room_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间id',
  `building_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属楼栋id',
  `unit` varchar(16) NOT NULL DEFAULT '' COMMENT '单元',
  `floor` int(10) NOT NULL DEFAULT '0' COMMENT '楼层',
  `room_num` varchar(32) NOT NULL DEFAULT '0' COMMENT '房号',
  `room_type_id` varchar(32) NOT NULL DEFAULT '' COMMENT '户型id',
  `space` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '建筑面积',
  `build_unit_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '建筑单价',
  `unit_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '套内单价',
  `total_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总价',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '房屋状态(0:待售、1:已售)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `sort_field` int(10) DEFAULT NULL COMMENT '排序字段',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`room_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='房源房间信息';

-- ----------------------------
-- Table structure for lb_ims_marketing_room_type
-- ----------------------------
