  `url` text COMMENT '图片地址url',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`room_type_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='房源管理-户型';

-- ----------------------------
-- Table structure for lb_ims_medical_department
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_medical_department`;
CREATE TABLE `lb_ims_medical_department` (
  `medical_department_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `department_name` varchar(32) NOT NULL DEFAULT '' COMMENT '科室名称',
  `department_address` varchar(256) NOT NULL DEFAULT '' COMMENT '科室地址',
  `contact_name` varchar(32) NOT NULL DEFAULT '' COMMENT '负责人姓名',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '负责人手机号',
  `remark` varchar(256) DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`medical_department_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='医疗科室表';

-- ----------------------------
-- Table structure for lb_ims_medical_department_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_medical_department_account`;
CREATE TABLE `lb_ims_medical_department_account` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `medical_department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '医疗科室主键',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用户主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `medical_department_id` (`medical_department_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='医疗科用户关联表';

-- ----------------------------
-- Table structure for lb_ims_medical_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_medical_record`;
CREATE TABLE `lb_ims_medical_record` (
  `medical_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `registration_name` varchar(32) DEFAULT NULL COMMENT '登记人',
  `registration_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `medical_hospital` varchar(32) DEFAULT NULL COMMENT '体检医院',
  `medical_time` bigint(20) DEFAULT NULL COMMENT '体检时间',
  `medical_result` text COMMENT '体检结果',
  `medical_img` text COMMENT '体检图片,多张隔开url',
  `height` varchar(32) DEFAULT NULL COMMENT '身高',
  `weight` varchar(32) DEFAULT NULL COMMENT '体重',
  `temperature` varchar(32) DEFAULT NULL COMMENT '体温',
  `blood_pressure` varchar(32) DEFAULT NULL COMMENT '血压',
  `low_pressure` varchar(32) DEFAULT NULL COMMENT '低压',
  `pulse` varchar(32) DEFAULT NULL COMMENT '脉搏',
  `blood_oxygen` varchar(32) DEFAULT NULL COMMENT '血氧',
  `fbg` varchar(32) DEFAULT NULL COMMENT '空腹血糖',
  `pbg` varchar(32) DEFAULT NULL COMMENT '餐后血糖',
  `cholesterol` varchar(32) DEFAULT NULL COMMENT '总胆固醇',
  `hdl_cholesterol` varchar(32) DEFAULT NULL COMMENT '高密度脂蛋白胆固醇',
  `triglycerides` varchar(32) DEFAULT NULL COMMENT '甘油三脂',
  `ldl_cholesterol` varchar(32) DEFAULT NULL COMMENT '低密度脂蛋白胆固醇',
  `ua` varchar(32) DEFAULT NULL COMMENT '尿酸',
  `qrs` varchar(32) DEFAULT NULL COMMENT 'qrs',
  `notation` varchar(1024) DEFAULT NULL COMMENT '全科医生批注',
  `rr` varchar(32) DEFAULT NULL COMMENT 'rr',
  `doctor_analysis` varchar(1024) DEFAULT NULL COMMENT '医生分析',
  `heart_rate` varchar(32) DEFAULT NULL COMMENT '心率',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_first` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否第一次入院录入',
  `disease` varchar(255) DEFAULT NULL COMMENT '疾病字典值，隔开',
  `breathe` varchar(32) DEFAULT NULL COMMENT '呼吸',
  `registration_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`medical_record_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='体检记录表';

-- ----------------------------
-- Table structure for lb_ims_meeting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_meeting`;
CREATE TABLE `lb_ims_meeting` (
  `meeting_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `meeting_name` varchar(32) NOT NULL DEFAULT '' COMMENT '会议名称',
  `meeting_type` varchar(32) NOT NULL DEFAULT '' COMMENT '会议类型',
  `presenter` varchar(32) NOT NULL DEFAULT '' COMMENT '主讲人',
  `meeting_unit` varchar(32) DEFAULT '' COMMENT '会议单位',
  `meeting_location` varchar(32) DEFAULT '' COMMENT '会议地点',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `meeting_content` text NOT NULL COMMENT '会议内容',
  `attachment` text NOT NULL COMMENT '附件地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `attachment_name` text NOT NULL COMMENT '附件名称',
  `remark` varchar(125) DEFAULT '' COMMENT '备注',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meeting_id`),
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `idx_meeting_id` (`meeting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会议信息表';

-- ----------------------------
-- Table structure for lb_ims_meeting_staff
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_meeting_staff`;
CREATE TABLE `lb_ims_meeting_staff` (
  `meeting_staff_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `staff_id` varchar(32) NOT NULL COMMENT '员工id',
  `meeting_id` varchar(32) NOT NULL COMMENT '培训记录id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meeting_staff_id`),
  KEY `idx_meeting_id` (`meeting_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='会议参与员工关系表';

-- ----------------------------
-- Table structure for lb_ims_month_check
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_month_check`;
CREATE TABLE `lb_ims_month_check` (
  `month_check_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_id` varchar(32) DEFAULT '' COMMENT '仓库id',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_in_number` int(10) DEFAULT '0' COMMENT '入库数量',
  `supplies_out_number` int(10) DEFAULT '0' COMMENT '出库数量',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `final_number` int(10) DEFAULT '0' COMMENT '期末库存',
  `last_month_number` int(10) DEFAULT '0' COMMENT '上月库存',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`month_check_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='月度盘点表';

-- ----------------------------
-- Table structure for lb_ims_notification_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_notification_record`;
CREATE TABLE `lb_ims_notification_record` (
  `notification_record_id` varchar(32) NOT NULL COMMENT '记录id',
  `account_id` varchar(32) DEFAULT NULL COMMENT '用户id',
  `record_type` varchar(11) DEFAULT NULL COMMENT '1：护工APP公告,2医生app公告，3网页端公告，多客户端通知类型之间用逗号拼接',
  `account_type` tinyint(3) DEFAULT NULL COMMENT '用户类型',
  `content` text COMMENT '内容',
  `record_time` bigint(20) DEFAULT '0',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除标识0否1是',
  `org_id` varchar(32) DEFAULT NULL,
  `create_time` bigint(20) DEFAULT '0',
  `update_time` bigint(20) DEFAULT '0',
  `title` varchar(128) DEFAULT NULL COMMENT '通知标题',
  `read_account` text,
  `publish_status` tinyint(3) DEFAULT '0' COMMENT '发布状态，0未发布，１已发布',
  `source_id` varchar(32) DEFAULT NULL COMMENT '消息通知来源id',
  `is_all` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否全选(recordType包含7或10时有效)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`notification_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_ims_notification_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_notification_relation`;
CREATE TABLE `lb_ims_notification_relation` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '通知记录id',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域id',
  `level` tinyint(1) NOT NULL DEFAULT '1' COMMENT '等级',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通知公告通知范围';

-- ----------------------------
-- Table structure for lb_ims_object_relation_recipe
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_object_relation_recipe`;
CREATE TABLE `lb_ims_object_relation_recipe` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `recipe_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱id',
  `recipe_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱点餐id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者与点餐信息映射表';

-- ----------------------------
-- Table structure for lb_ims_out_registration
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_out_registration`;
CREATE TABLE `lb_ims_out_registration` (
  `out_registration_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT ' ' COMMENT '长者id',
  `entourage_type` tinyint(1) DEFAULT '0' COMMENT '陪同类型',
  `entourage_name` varchar(125) DEFAULT ' ' COMMENT '陪同人姓名',
  `entourage_phone_num` varchar(11) DEFAULT ' ' COMMENT '电话号码',
  `entourage_identity` varchar(32) DEFAULT ' ' COMMENT '身份证',
  `return_time` bigint(20) DEFAULT '0' COMMENT '实际返回时间',
  `entourage_region` varchar(255) DEFAULT ' ' COMMENT '陪同人行政区域',
  `entourage_address` varchar(255) DEFAULT ' ' COMMENT '陪同人地址',
  `out_time` bigint(20) DEFAULT '0' COMMENT '外出时间',
  `plan_return_time` bigint(20) DEFAULT '0' COMMENT '计划返回时间',
  `reasons` varchar(255) DEFAULT ' ' COMMENT '外出原因',
  `is_return` tinyint(1) DEFAULT '0' COMMENT '0:未返回1:返回',
  `register_account_id` varchar(32) DEFAULT ' ' COMMENT '登记账号',
  `register_name` varchar(125) DEFAULT ' ' COMMENT '登记人姓名',
  `org_id` varchar(32) DEFAULT ' ' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `entourage_region_id` varchar(255) DEFAULT '' COMMENT '区域id',
  `staff_id` varchar(32) DEFAULT '' COMMENT '陪同人员唯一标识',
  `is_refund` tinyint(1) DEFAULT '0' COMMENT '0:未退费 1:已退费',
  `refund_type` tinyint(1) DEFAULT '0' COMMENT '0:按日期 1:按时长',
  `custom_out_days` int(11) DEFAULT NULL COMMENT '自定义退费天数',
  `sign_url` varchar(128) DEFAULT NULL COMMENT '签字地址',
  `relation` varchar(32) DEFAULT NULL COMMENT '签字人与长者关系',
  `physical_condition` varchar(255) DEFAULT NULL COMMENT '长者身体状况',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`out_registration_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='外出登记信息';

-- ----------------------------
-- Table structure for lb_ims_outpatient_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_outpatient_info`;
CREATE TABLE `lb_ims_outpatient_info` (
  `outpatient_info_id` varchar(32) NOT NULL COMMENT '主键',
  `outpatient_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '患者类型 0普通病人 1护理楼长者 2 公寓楼长者 3 社区居家长者',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '就诊状态 0 未就诊 1就诊中 2 完成就诊',
  `medical_department_id` varchar(32) NOT NULL COMMENT '就诊科室ID',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者ID',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '名字',
  `identity` varchar(32) DEFAULT NULL COMMENT '身份证',
  `identity_type` tinyint(1) DEFAULT '0' COMMENT '身份证类型;0:中国居民身份证,1:香港身份证,2:澳门身份证,3:台湾身份证',
  `gender` varchar(32) DEFAULT NULL COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `phone_num` varchar(11) DEFAULT NULL COMMENT '电话号码',
  `physiological_feature` varchar(32) DEFAULT NULL COMMENT '生理特征',
  `marital_status` varchar(32) DEFAULT NULL COMMENT '婚姻状况  1已婚 3未婚 2离异 4丧偶',
  `nation` varchar(32) DEFAULT NULL COMMENT '民族',
  `office` varchar(32) DEFAULT NULL COMMENT '职业',
  `work_unit` varchar(32) DEFAULT NULL COMMENT '工作单位',
  `emergency_contact` varchar(128) DEFAULT NULL COMMENT '紧急联系人',
  `address` varchar(255) DEFAULT NULL COMMENT 'address',
  `region` varchar(255) DEFAULT NULL COMMENT '区域',
  `photo` varchar(128) DEFAULT NULL COMMENT '头像地址',
  `drug_allergy_history` varchar(255) DEFAULT NULL COMMENT '药物过敏史',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`outpatient_info_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='就诊长者信息表';

-- ----------------------------
-- Table structure for lb_ims_overview_map
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_overview_map`;
CREATE TABLE `lb_ims_overview_map` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `map_url` text NOT NULL COMMENT '地图图片地址',
  `map_content` text COMMENT '地图图片位置信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='运维管理-院内地图设置-总览地图';

-- ----------------------------
-- Table structure for lb_ims_overview_map_public
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_overview_map_public`;
CREATE TABLE `lb_ims_overview_map_public` (
  `public_id` varchar(32) NOT NULL DEFAULT '',
  `public_name` varchar(16) NOT NULL COMMENT '公区名称',
  `describe` text NOT NULL COMMENT '公区描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`public_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='运维管理-院内地图设置-总览地图-公区信息';

-- ----------------------------
-- Table structure for lb_ims_overview_map_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_overview_map_setting`;
CREATE TABLE `lb_ims_overview_map_setting` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区域id(building_id/map_id/.)',
  `area_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '区域类型(0:楼栋  1:室外地图  2:公区)',
  `map_content` text NOT NULL COMMENT '区域在地图中位置信息(给前端使用)',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`),
  KEY `area_id` (`area_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='运维管理-院内地图设置-总览地图-设置楼栋信息';

-- ----------------------------
-- Table structure for lb_ims_patrol
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol`;
CREATE TABLE `lb_ims_patrol` (
  `patrol_id` varchar(32) NOT NULL COMMENT '巡查主键',
  `name` varchar(32) NOT NULL COMMENT '巡查名称',
  `patrol_line_id` varchar(32) NOT NULL COMMENT '巡查路线主键',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '类型：1 巡查 2 巡更',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '巡查状态 0 未开始 1 进行中 2 已取消',
  `dept_id` varchar(32) NOT NULL COMMENT '部门主键',
  `patrol_account_id` text COMMENT '巡查人主键集合逗号隔开',
  `check_account_id` varchar(32) NOT NULL COMMENT '登记人',
  `check_account_name` varchar(32) NOT NULL COMMENT '登记人姓名',
  `patrol_frequency` tinyint(4) NOT NULL DEFAULT '0' COMMENT '巡查频次 1 天  2  周 3 月',
  `patrol_duration` int(10) NOT NULL COMMENT '巡查时长',
  `patrol_cycle` varchar(512) NOT NULL COMMENT '巡查周期',
  `patrol_time` varchar(512) NOT NULL COMMENT '巡查时间段',
  `patrol_corn` varchar(512) NOT NULL COMMENT '巡查时间表达式，";"分割',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `patrol_type` tinyint(2) DEFAULT NULL COMMENT '1:固定人员巡查2：排班表巡查',
  `schedule_plan_id` varchar(32) DEFAULT NULL COMMENT '排班表主键',
  `last_execution_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '前次执行时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`patrol_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查计划表';

-- ----------------------------
-- Table structure for lb_ims_patrol_line
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol_line`;
CREATE TABLE `lb_ims_patrol_line` (
  `patrol_line_id` varchar(32) NOT NULL COMMENT '巡查线路主键',
  `line_name` varchar(32) NOT NULL COMMENT '名称',
  `type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '类型：1 巡查 2 巡更',
  `patrol_demand` tinyint(4) NOT NULL DEFAULT '1' COMMENT '巡查要求 1 按路线巡查 2 不要求巡查线路顺序',
  `check_account_id` varchar(32) NOT NULL COMMENT '登记人id',
  `check_account_name` varchar(32) NOT NULL COMMENT '登记人姓名',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `org_id` varchar(32) NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`patrol_line_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查路线表';

-- ----------------------------
-- Table structure for lb_ims_patrol_line_point
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol_line_point`;
CREATE TABLE `lb_ims_patrol_line_point` (
  `patrol_line_point_id` varchar(32) NOT NULL COMMENT '巡查点主键',
  `patrol_line_id` varchar(32) NOT NULL COMMENT '巡查线路主键',
  `point_location` varchar(64) NOT NULL COMMENT '巡查点位置',
  `device_type` int(10) NOT NULL COMMENT '巡查点设备类型',
  `device_name` varchar(32) NOT NULL COMMENT '设备名称',
  `mac` varchar(64) NOT NULL COMMENT 'mac地址',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `patrol_device_info` json DEFAULT NULL COMMENT '设备信息，数组格式的json',
  `order_num` int(10) NOT NULL COMMENT '排序字段',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`patrol_line_point_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查点表';

-- ----------------------------
-- Table structure for lb_ims_patrol_point_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol_point_record`;
CREATE TABLE `lb_ims_patrol_point_record` (
  `patrol_point_record_id` varchar(32) NOT NULL COMMENT '巡查任务点主键',
  `patrol_task_id` varchar(32) NOT NULL COMMENT '巡查任务id',
  `punch_card_status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '打卡状态 1 未打卡 2 已打卡',
  `site_status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '巡查状态 1 未巡查 2 巡查正常 3 巡查异常',
  `description` varchar(255) DEFAULT NULL COMMENT '描述',
  `picture_url` varchar(400) DEFAULT NULL COMMENT '图片',
  `video_url` varchar(400) DEFAULT NULL COMMENT '视频',
  `point_location` varchar(64) NOT NULL COMMENT '巡查位置',
  `patrol_time` bigint(20) DEFAULT NULL COMMENT '巡查时间',
  `device_type` int(10) NOT NULL COMMENT '巡查设备类型',
  `device_name` varchar(32) NOT NULL COMMENT '设备名称',
  `mac` varchar(64) NOT NULL COMMENT 'mac地址',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `patrol_device_info` json DEFAULT NULL COMMENT '设备信息',
  `order_num` int(10) NOT NULL COMMENT '巡查顺序',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`patrol_point_record_id`),
  KEY `patrol_task_id` (`patrol_task_id`) USING BTREE,
  KEY `order_num` (`order_num`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查任务点表';

-- ----------------------------
-- Table structure for lb_ims_patrol_record_relation_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol_record_relation_object`;
CREATE TABLE `lb_ims_patrol_record_relation_object` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `patrol_point_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '巡查任务点记录主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id_index` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查记录与长者关联信息';

-- ----------------------------
-- Table structure for lb_ims_patrol_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_patrol_task`;
CREATE TABLE `lb_ims_patrol_task` (
  `patrol_task_id` varchar(32) NOT NULL COMMENT '巡查任务主键',
  `patrol_id` varchar(32) NOT NULL COMMENT '巡查主键',
  `patrol_day` varchar(32) NOT NULL COMMENT '巡查日期',
  `line_name` varchar(32) DEFAULT NULL COMMENT '巡查路线名称',
  `point_count` int(10) NOT NULL COMMENT '巡查点数量',
  `patrol_start_time` bigint(20) NOT NULL COMMENT '巡查开始时间',
  `patrol_end_time` bigint(20) NOT NULL COMMENT '巡查结束时间',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '状态  1 未开始 2 进行中 3 已完成 4 已取消',
  `create_time` bigint(20) NOT NULL,
  `update_time` bigint(20) NOT NULL,
  `org_id` varchar(32) NOT NULL,
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `patrol_name` varchar(32) DEFAULT NULL COMMENT '巡查人姓名',
  `patrol_account_id` varchar(64) DEFAULT NULL COMMENT '巡查人主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`patrol_task_id`),
  KEY `patrol_id` (`patrol_id`) USING BTREE,
  KEY `idx_patrol_time` (`patrol_start_time`,`patrol_end_time`),
  KEY `idx_status` (`status`),
  KEY `idx_org` (`org_id`),
  KEY `idx_optimize_covering` (`org_id`,`patrol_account_id`,`status`,`is_delete`,`patrol_day`,`patrol_end_time`,`patrol_start_time`,`patrol_task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='巡查任务表';

-- ----------------------------
-- Table structure for lb_ims_photo
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_photo`;
CREATE TABLE `lb_ims_photo` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联记录id',
  `type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '图片类型(1:维修故障前  2:维修故障后)',
  `url` varchar(64) NOT NULL DEFAULT '' COMMENT '图片地址',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='图片表';

-- ----------------------------
-- Table structure for lb_ims_photo_album
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_photo_album`;
CREATE TABLE `lb_ims_photo_album` (
  `photo_album_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '老人id',
  `name` varchar(255) NOT NULL COMMENT '相册名称',
  `url` text COMMENT '相片url',
  `parent_id` varchar(32) DEFAULT NULL COMMENT '父相册id，空为相册，不空为照片',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认相册 0:不是 1:是',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`photo_album_id`) USING BTREE,
  KEY `care_object_id_index` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='相册管理表';

-- ----------------------------
-- Table structure for lb_ims_prescribe
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe`;
CREATE TABLE `lb_ims_prescribe` (
  `prescribe_id` varchar(32) NOT NULL COMMENT '医嘱id',
  `prescribe_item_id` varchar(32) NOT NULL COMMENT '医嘱项目id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `remarks` varchar(128) DEFAULT '' COMMENT '嘱托',
  `type` tinyint(1) DEFAULT '0' COMMENT '类型：0长嘱、1临嘱',
  `number` int(10) DEFAULT '0' COMMENT '数量',
  `remain_number` int(10) DEFAULT '0' COMMENT '剩余数量',
  `total_amount` decimal(10,2) DEFAULT '0.00' COMMENT '总金额',
  `freight_basis` varchar(32) DEFAULT NULL COMMENT '是否收费 0-免费 1-收费',
  `create_doctor_id` varchar(32) DEFAULT '0' COMMENT '开医嘱医生id',
  `create_doctor_name` varchar(32) DEFAULT '' COMMENT '开医嘱医生name',
  `prescribe_create_time` bigint(20) DEFAULT '0' COMMENT '开医嘱时间',
  `stop_doctor_id` varchar(32) DEFAULT '0' COMMENT '停医嘱医生id',
  `stop_doctor_name` varchar(32) DEFAULT '' COMMENT '停医嘱医生name',
  `prescribe_stop_time` bigint(20) DEFAULT '0' COMMENT '停医嘱时间',
  `status` int(11) DEFAULT '1' COMMENT '医嘱状态 0：新开 1：暂停 2：停止',
  `task_cycle` varchar(200) DEFAULT NULL COMMENT '执行周期',
  `task_type` int(11) DEFAULT '0' COMMENT '任务类型,0一般任务;1关键任务',
  `task_frequency` int(2) DEFAULT NULL COMMENT '执行频率　０月１周２天',
  `task_time` varchar(400) DEFAULT NULL COMMENT '执行时间',
  `task_cron` varchar(400) DEFAULT NULL COMMENT 'cron表达式',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `prescribe_item_type` tinyint(1) DEFAULT '0' COMMENT '类型：0　药物　1　诊疗　２化验',
  `prescribe_item_name` varchar(32) DEFAULT NULL COMMENT '项目名称',
  `prescribe_type_id` varchar(32) DEFAULT NULL COMMENT '所属模板',
  `prescribe_type_name` varchar(32) DEFAULT NULL COMMENT '模板名称',
  `supplies_drug_id` varchar(32) DEFAULT NULL COMMENT '药品ＩＤ',
  `code` varchar(32) DEFAULT NULL COMMENT '编号',
  `dose_unit` varchar(100) DEFAULT NULL COMMENT '剂量单位',
  `specifications` varchar(32) DEFAULT NULL COMMENT '规格',
  `medicine_way` varchar(32) DEFAULT '0' COMMENT '给药途径',
  `unit_price` decimal(32,2) DEFAULT '0.00' COMMENT '单价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `prescribe_item_id` (`prescribe_item_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='长者医嘱记录表';

-- ----------------------------
-- Table structure for lb_ims_prescribe_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_info`;
CREATE TABLE `lb_ims_prescribe_info` (
  `prescribe_id` varchar(32) NOT NULL COMMENT '医嘱id',
  `type` tinyint(1) DEFAULT '1' COMMENT '1 门诊医嘱 2: 住院医嘱 ',
  `prescribe_item_type` varchar(32) NOT NULL COMMENT 'inspection：检验、check, 检查、dispose, 处置、 chinesePrescription, 中药处方、westernPrescription, 西药处方',
  `prescribe_item_id` varchar(32) NOT NULL COMMENT '医嘱项目id',
  `outpatient_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '患者类型 0普通病人 1护理楼长者 2 公寓楼长者 3 社区居家长者',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '长者id',
  `NUMBER` int(10) DEFAULT '0' COMMENT '开药数量',
  `remain_number` int(10) DEFAULT '0' COMMENT '剩余数量',
  `total_amount` decimal(10,2) DEFAULT '0.00' COMMENT '总金额',
  `create_doctor_id` varchar(32) DEFAULT NULL COMMENT '开医嘱医生id',
  `create_doctor_name` varchar(32) DEFAULT NULL COMMENT '开医嘱医生name',
  `prescribe_create_time` bigint(20) DEFAULT '0' COMMENT '开医嘱时间',
  `status` int(11) DEFAULT '0' COMMENT '医嘱状态 0：新开 1：已下达 2：已完成',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `medical_history` varchar(32) DEFAULT NULL,
  `pay_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '缴费状态（0-待缴费，1-已缴费）',
  `execute_status` int(11) DEFAULT '0' COMMENT '执行状态 0：未执行 1：已执行',
  `file_url` text COMMENT '文件地址',
  `file_name` text COMMENT '文件名称',
  `drug_frequency_id` varchar(32) NOT NULL DEFAULT '' COMMENT '用药频次id',
  `drug_frequency_count` varchar(10) NOT NULL DEFAULT '' COMMENT '每次用药量,支持分数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_id`),
  KEY `org_id` (`org_id`),
  KEY `idx_outpatient_care_object` (`care_object_id`),
  KEY `idx_prescribe_item_id` (`prescribe_item_id`),
  KEY `idx_drug_frequency_id` (`drug_frequency_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者医嘱记录表';

-- ----------------------------
-- Table structure for lb_ims_prescribe_item
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_item`;
CREATE TABLE `lb_ims_prescribe_item` (
  `prescribe_item_id` varchar(32) NOT NULL COMMENT '医嘱项目id',
  `prescribe_type_id` varchar(32) NOT NULL COMMENT '所属模板',
  `prescribe_type_name` varchar(32) DEFAULT NULL COMMENT '模板名称',
  `type` tinyint(1) DEFAULT '0' COMMENT '类型：0　药物　1　诊疗　２化验',
  `name` varchar(32) DEFAULT NULL COMMENT '项目名称',
  `supplies_drug_id` varchar(32) DEFAULT '' COMMENT '药品ＩＤ',
  `code` varchar(32) DEFAULT NULL COMMENT '编号',
  `dose_unit` varchar(100) DEFAULT NULL COMMENT '剂量单位',
  `specifications` varchar(32) DEFAULT NULL COMMENT '规格',
  `medicine_way` varchar(32) DEFAULT '0' COMMENT '给药途径',
  `unit_price` decimal(32,2) DEFAULT '0.00',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_item_id`) USING BTREE,
  KEY `prescribe_type_id` (`prescribe_type_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='医嘱项目表';

-- ----------------------------
-- Table structure for lb_ims_prescribe_item_check
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_item_check`;
CREATE TABLE `lb_ims_prescribe_item_check` (
  `prescribe_item_id` varchar(32) NOT NULL COMMENT '医嘱项目id',
  `code` varchar(32) DEFAULT NULL COMMENT '医嘱编号',
  `name` varchar(32) DEFAULT NULL COMMENT '检查项目',
  `price` decimal(32,2) DEFAULT '0.00' COMMENT '费用',
  `amount` varchar(32) DEFAULT NULL COMMENT '数量',
  `check_site_method` varchar(100) DEFAULT NULL COMMENT '检查部位和方法',
  `entrust` varchar(100) DEFAULT NULL COMMENT '嘱托',
  `medical_department_id` varchar(32) DEFAULT NULL COMMENT '科室id',
  `medical_department_name` varchar(32) DEFAULT NULL COMMENT '科室名称',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_item_id`),
  KEY `org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='医嘱项目表-检查';

-- ----------------------------
