-- ----------------------------
-- Table structure for lb_ims_prescribe_item_inspection
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_item_inspection`;
CREATE TABLE `lb_ims_prescribe_item_inspection` (
