-- ----------------------------
-- Table structure for lb_ims_prescribe_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_record`;
CREATE TABLE `lb_ims_prescribe_record` (
  `prescribe_record_id` varchar(32) NOT NULL COMMENT '医嘱执行记录id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `prescribe_id` varchar(32) NOT NULL COMMENT '医嘱id',
  `prescribe_execute_status` tinyint(4) DEFAULT '0' COMMENT '医嘱执行状态,0 未执行;1已执行;2执行中',
  `prescribe_execute_time` bigint(20) DEFAULT NULL COMMENT '医嘱执行时间',
  `nurse_id` varchar(32) DEFAULT NULL COMMENT '护工id',
  `nurse_name` varchar(32) DEFAULT NULL COMMENT '护工名字',
  `start_execute_time` bigint(20) DEFAULT NULL COMMENT '开始执行时间',
  `end_execute_time` bigint(20) DEFAULT NULL COMMENT '结束执行时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_record_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `prescribe_id` (`prescribe_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `end_execute_time` (`end_execute_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='长者医嘱执行记录表';

-- ----------------------------
-- Table structure for lb_ims_prescribe_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_template`;
CREATE TABLE `lb_ims_prescribe_template` (
  `prescribe_template_id` varchar(32) NOT NULL COMMENT '医嘱id',
  `prescribe_item_id` varchar(32) NOT NULL COMMENT '医嘱项目id',
  `remarks` varchar(128) DEFAULT NULL COMMENT '嘱托',
  `number` int(10) DEFAULT '0' COMMENT '数量',
  `total_amount` decimal(10,2) DEFAULT '0.00' COMMENT '总金额',
  `freight_basis` varchar(32) DEFAULT NULL COMMENT '计费标准',
  `task_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务类型,0一般任务;1关键任务',
  `task_frequency` tinyint(2) DEFAULT NULL,
  `task_cycle` varchar(200) DEFAULT NULL COMMENT '执行周期',
  `task_time` varchar(400) DEFAULT NULL COMMENT '执行时间',
  `task_cron` varchar(400) DEFAULT NULL COMMENT 'cron表达式',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_template_id`) USING BTREE,
  KEY `prescribe_item_id` (`prescribe_item_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='医嘱模型表';

-- ----------------------------
-- Table structure for lb_ims_prescribe_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_prescribe_type`;
CREATE TABLE `lb_ims_prescribe_type` (
  `prescribe_type_id` varchar(32) NOT NULL COMMENT '医嘱模板id',
  `name` varchar(32) DEFAULT NULL COMMENT '模板名称',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`prescribe_type_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='医嘱模板表';

-- ----------------------------
-- Table structure for lb_ims_pressure_sores_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_pressure_sores_config`;
CREATE TABLE `lb_ims_pressure_sores_config` (
  `pressure_sores_config_id` varchar(64) NOT NULL COMMENT '主键',
  `start_number` int(10) DEFAULT '0' COMMENT '分数范围开始',
  `end_number` int(10) DEFAULT '0' COMMENT '分数范围结束',
  `assessment` varchar(255) DEFAULT NULL COMMENT '综合评价',
  `measure` varchar(512) DEFAULT NULL COMMENT '护理措施',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `device_recommend` varchar(128) NOT NULL DEFAULT '' COMMENT '设备推荐描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`pressure_sores_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='压疮评估标准配置';

-- ----------------------------
-- Table structure for lb_ims_public_activity
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_public_activity`;
CREATE TABLE `lb_ims_public_activity` (
  `activity_id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(32) DEFAULT '' COMMENT '活动名称',
  `synopsis` text COMMENT '活动简介',
  `photo` text COMMENT '活动图片',
  `date_type` tinyint(1) DEFAULT '1' COMMENT '活动日期类型 1.指定日期 2.长期活动',
  `start_date` bigint(20) DEFAULT '0' COMMENT '活动开始日期',
  `end_date` bigint(20) DEFAULT '0' COMMENT '活动结束日期',
  `start_time` int(11) DEFAULT '0' COMMENT '活动开始时间',
  `end_time` int(11) DEFAULT '0' COMMENT '活动结束时间',
  `enroll_type` tinyint(1) DEFAULT '1' COMMENT '报名模式   1.审批模式  2.人数模式',
  `field_type` tinyint(1) DEFAULT '1' COMMENT '场地限制   0 不指定场地  1 指定场地',
  `field_name` varchar(32) DEFAULT '' COMMENT '场地名称',
  `capacity` int(11) DEFAULT NULL COMMENT '每日人数上限',
  `enroll_cost` decimal(10,2) DEFAULT NULL COMMENT '报名费用',
  `apply_time` varchar(32) DEFAULT '' COMMENT '发布时间',
  `apply_account_name` varchar(64) DEFAULT '' COMMENT '发布人姓名',
  `apply_account_id` varchar(64) DEFAULT '' COMMENT '发布人id',
  `activity_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '活动类型（1 公共活动  2 公共课程)',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `status` tinyint(1) DEFAULT '1' COMMENT '活动状态 1 待审核 2已通过 3已驳回 4 进行中 5 已结束',
  `field_id` varchar(32) DEFAULT '' COMMENT '场地id',
  `summary` text COMMENT '总结',
  `summary_pic` text COMMENT '总结图片，分号分开',
  `summary_attend` text COMMENT '班级总结参加情况',
  `summary_date` bigint(20) DEFAULT '0' COMMENT '总结时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`activity_id`),
  KEY `applyAccountId` (`apply_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='公共活动表';

-- ----------------------------
-- Table structure for lb_ims_public_activity_care_object_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_public_activity_care_object_record`;
CREATE TABLE `lb_ims_public_activity_care_object_record` (
  `record_id` varchar(32) NOT NULL COMMENT '报名记录id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `activity_id` varchar(32) DEFAULT NULL COMMENT '活动id',
  `status` tinyint(1) DEFAULT '0' COMMENT '报名状态 0未审批,1已审批 2 被驳回',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `enroll_date` bigint(20) DEFAULT '0' COMMENT '参加日期',
  `is_evaluate` tinyint(1) DEFAULT '0' COMMENT '是否已评价  0未评价, 1 已评价',
  `is_enroll` tinyint(1) DEFAULT '0' COMMENT '是否已参加，0未参加，1已参加',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='公共活动报名记录表';

-- ----------------------------
-- Table structure for lb_ims_public_activity_class
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_public_activity_class`;
CREATE TABLE `lb_ims_public_activity_class` (
  `class_id` varchar(32) NOT NULL COMMENT '班级主键',
  `name` varchar(32) DEFAULT '' COMMENT '班级名称',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `max_num` int(3) DEFAULT '0' COMMENT '班级人数上限',
  `expenses` decimal(8,2) DEFAULT '0.00' COMMENT '报名费用',
  `status` tinyint(1) DEFAULT '1' COMMENT '班级状态 1 未开始 2已开课 3已结束 4 已取消 ',
  `field_name` varchar(32) DEFAULT '' COMMENT '场地名称',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `summary_date` bigint(20) NOT NULL DEFAULT '0' COMMENT '总结时间',
  `audit_mode` tinyint(1) DEFAULT '0' COMMENT '0- 默认审批模式（报名后需审批）1-“人数模式（报名后自动审批，人数满无法报名）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`class_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='班级表';

-- ----------------------------
-- Table structure for lb_ims_public_activity_class_care_object_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_public_activity_class_care_object_record`;
CREATE TABLE `lb_ims_public_activity_class_care_object_record` (
  `class_record_id` varchar(32) NOT NULL COMMENT '班级报名id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `class_id` varchar(32) DEFAULT NULL COMMENT '班级主键',
  `status` tinyint(1) DEFAULT '0' COMMENT '报名状态 0未审批,1已审批 2 被驳回',
  `pay` decimal(8,2) DEFAULT '0.00' COMMENT '实际缴费',
  `expenses` decimal(8,2) DEFAULT '0.00' COMMENT '费用',
  `remarks` varchar(128) DEFAULT '' COMMENT '备注',
  `is_enroll` tinyint(1) DEFAULT '0' COMMENT '是否已参加，0未参加，1已参加',
  `enroll_date` bigint(20) DEFAULT '0' COMMENT '报名日期',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `approval_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '审批时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`class_record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='报名者和班级记录表';

