-- Table structure for lb_ims_recipe
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_recipe`;
CREATE TABLE `lb_ims_recipe` (
  `recipe_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `recipe_sort_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱类别主键',
  `is_publish` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否发布（0 未发布，1 已发布）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `registrant` varchar(32) DEFAULT '' COMMENT '登记人',
  `recipe_name` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱名称',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `publish_week` varchar(32) DEFAULT '' COMMENT '发布周次（发布状态为已发布时有效）',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `meal` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次类别',
  `type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '类型 0:套餐 1:点餐',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recipe_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `recipe_sort_id` (`recipe_sort_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食谱表';

-- ----------------------------
-- Table structure for lb_ims_recipe_meal
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_recipe_meal`;
CREATE TABLE `lb_ims_recipe_meal` (
  `recipe_meal_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `recipe_id` varchar(32) NOT NULL DEFAULT '' COMMENT '食谱主键',
  `date` varchar(32) NOT NULL DEFAULT '' COMMENT '所属日期',
  `morning_tea` text COMMENT '早茶',
  `breakfast` text COMMENT '早餐',
  `lunch` text COMMENT '午餐',
  `afternoon_tea` text COMMENT '下午茶',
  `dinner` text COMMENT '晚餐',
  `night_snack` text COMMENT '宵夜',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `taboo` text COMMENT '禁忌项',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recipe_meal_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `recipe_id` (`recipe_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食谱餐次表';

-- ----------------------------
-- Table structure for lb_ims_recipe_sort
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_recipe_sort`;
CREATE TABLE `lb_ims_recipe_sort` (
  `recipe_sort_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `sort_name` varchar(32) NOT NULL DEFAULT '' COMMENT '类别名称',
  `month_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '包月价格',
  `single_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '单次价格',
  `remark` varchar(255) DEFAULT '' COMMENT '备注',
  `sort_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '类别详细',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '食谱图片地址',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐饮店铺主键',
  `morning_tea_limit` decimal(10,2) DEFAULT NULL COMMENT '早茶限额',
  `breakfast_limit` decimal(10,2) DEFAULT NULL COMMENT '早餐限额',
  `lunch_limit` decimal(10,2) DEFAULT NULL COMMENT '午餐限额',
  `afternoon_tea_limit` decimal(10,2) DEFAULT NULL COMMENT '下午茶限额',
  `dinner_limit` decimal(10,2) DEFAULT NULL COMMENT '晚餐限额',
  `night_snack_limit` decimal(10,2) DEFAULT NULL COMMENT '宵夜限额',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`recipe_sort_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `food_shop_id` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='食谱类别表';

-- ----------------------------
-- Table structure for lb_ims_recipe_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_recipe_task`;
CREATE TABLE `lb_ims_recipe_task` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `recipe_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '点餐类型(0:批量点餐，1:帮所有人点)',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '点餐时间段开始',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '点餐时间段结束',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人',
  `result` text COMMENT '执行结果',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `num` int(10) NOT NULL COMMENT '点餐长者数量',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='批量点餐任务表';

-- ----------------------------
-- Table structure for lb_ims_repair_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_repair_record`;
CREATE TABLE `lb_ims_repair_record` (
  `repair_record_id` varchar(32) NOT NULL,
  `device_name` varchar(64) DEFAULT '' COMMENT '设备名称',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `device_position` varchar(125) DEFAULT '' COMMENT '设备位置',
  `device_product_factory` varchar(64) DEFAULT '' COMMENT '设备厂家',
  `fault_type` tinyint(1) DEFAULT '0' COMMENT '故障类别',
  `repair_man_name` varchar(32) DEFAULT '' COMMENT '维修人员名称',
  `repair_man_phone` varchar(32) DEFAULT '' COMMENT '维修人员手机号',
  `is_repair` tinyint(1) DEFAULT '0' COMMENT '是否维修完成 0未完成 1维修完成',
  `fault_reason` varchar(255) DEFAULT '' COMMENT '故障原因',
  `check_account_id` varchar(64) DEFAULT '' COMMENT '登记人id',
  `repair_start_time` bigint(20) DEFAULT '0' COMMENT '维修开始时间',
  `repair_end_time` bigint(20) DEFAULT '0' COMMENT '维修结束时间',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `remark` text COMMENT '备注',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `check_account_name` varchar(32) DEFAULT '' COMMENT '登记人姓名',
  `position_type` tinyint(3) DEFAULT '1' COMMENT '位置类型  1 其他位置 2 房间',
  `staff_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '维修人员类型  (0: 院内工程部员工、1：其他人员)',
  `staff_id` varchar(32) DEFAULT '' COMMENT '员工id(staffType = 0 时必填)',
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备类型(0:院内设备  1:其他设备 )',
  `check_account_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人手机号',
  `repair_department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '维修部门id',
  `repair_emergency` varchar(32) NOT NULL DEFAULT '0' COMMENT '维修紧急度；0一般维修、1紧急维修',
  `evaluation_score` decimal(4,1) NOT NULL DEFAULT '0.0' COMMENT '综合评分',
  `evaluation` varchar(255) NOT NULL DEFAULT '' COMMENT '服务评价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`repair_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='维修记录表';

-- ----------------------------
-- Table structure for lb_ims_repast
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_repast`;
CREATE TABLE `lb_ims_repast` (
  `repast_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '老人id',
  `food_id` varchar(32) DEFAULT '' COMMENT '餐饮名称id',
  `is_send` tinyint(1) DEFAULT '0' COMMENT '是否送餐，0否;1需要送餐',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '是否生效',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `last_order_time` bigint(20) DEFAULT '0' COMMENT '前次下单时间',
  `last_update_food` bigint(20) DEFAULT '0' COMMENT '上次更换食谱时间',
  `is_charge` tinyint(1) DEFAULT '0' COMMENT '送餐是否收费 0不收 1收费',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`repast_id`) USING BTREE,
  KEY `org_id_index` (`org_id`),
  KEY `care_object_id_index` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='老人餐饮关系表';

-- ----------------------------
-- Table structure for lb_ims_reservation_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_reservation_record`;
CREATE TABLE `lb_ims_reservation_record` (
  `reservation_record_id` bigint(20) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `archives_id` bigint(20) NOT NULL COMMENT '档案号',
  `elder_name` varchar(128) NOT NULL DEFAULT '' COMMENT '长者姓名',
  `identity` varchar(32) NOT NULL COMMENT '长者身份证',
  `gender` varchar(32) NOT NULL COMMENT '性别',
  `birthday` varchar(32) NOT NULL COMMENT '生日',
  `elder_phone` varchar(32) NOT NULL COMMENT '长者手机号',
  `reservation_in_time` bigint(20) NOT NULL COMMENT '预约入住时间',
  `oneself_situation` varchar(32) NOT NULL COMMENT '自理情况',
  `bed_type` varchar(32) DEFAULT NULL COMMENT '预约床位类型',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '预约床位id',
  `home_address` varchar(255) DEFAULT NULL COMMENT '家庭住址',
  `reservation_name` varchar(128) NOT NULL COMMENT '预约人姓名',
  `reservation_phone` varchar(32) NOT NULL COMMENT '预约人手机号',
  `relation` varchar(32) NOT NULL COMMENT '与长者关系',
  `reservation_time` bigint(20) NOT NULL COMMENT '预约时间',
  `receiver_id` bigint(20) DEFAULT NULL COMMENT '接待人id',
  `receiver_name` varchar(32) NOT NULL COMMENT '接待人name',
  `receiver_phone` varchar(20) DEFAULT NULL COMMENT '接待人手机号',
  `is_in` tinyint(1) NOT NULL COMMENT '是否已经转入住,0:否;1:已转入住 2已转试住',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `home_address_region` varchar(100) DEFAULT NULL COMMENT '家庭住址',
  `reservation_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1预约中,2取消预约,3预约转入院',
  `age` int(10) DEFAULT NULL COMMENT '年龄',
  `marketing_customer_id` varchar(32) DEFAULT NULL COMMENT '客户记录id',
  `staff_id` varchar(32) DEFAULT NULL COMMENT '业务员id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`reservation_record_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT=' 预约登记记录表';

-- ----------------------------
-- Table structure for lb_ims_risk_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_risk_config`;
CREATE TABLE `lb_ims_risk_config` (
  `risk_config_id` varchar(32) NOT NULL COMMENT '主键',
  `start_number` int(10) DEFAULT NULL COMMENT '分数范围开始',
  `end_number` int(10) DEFAULT NULL COMMENT '分数范围结束',
  `risk_level_id` varchar(32) DEFAULT '' COMMENT '风险等级主键',
  `return_visit` varchar(255) DEFAULT '' COMMENT '回访',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `device_recommend` varchar(128) NOT NULL DEFAULT '' COMMENT '设备推荐',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`risk_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='风险评估标准配置';

-- ----------------------------
-- Table structure for lb_ims_rp
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_rp`;
CREATE TABLE `lb_ims_rp` (
  `rp_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '员工主键',
  `rp_type` tinyint(1) NOT NULL COMMENT '奖惩类型（0 奖励，1 惩罚）',
  `rp_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '奖惩时间',
  `rp_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '奖惩金额',
  `rp_reason` text COMMENT '奖惩原因',
  `register_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记账号',
  `remark` text COMMENT '备注',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `register_name` varchar(100) DEFAULT '' COMMENT '登记人姓名',
  `operate_name` varchar(100) DEFAULT '' COMMENT '操作人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`rp_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='奖惩信息表';

-- ----------------------------
-- Table structure for lb_ims_schedule_butler
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_butler`;
CREATE TABLE `lb_ims_schedule_butler` (
  `schedule_butler_id` varchar(32) NOT NULL COMMENT '主键',
  `type` tinyint(1) NOT NULL COMMENT '1-管家交接班 2-护理员交接班 3-部门交接班',
  `floor_id` varchar(32) DEFAULT NULL COMMENT '楼层id',
  `floor_name` varchar(125) DEFAULT NULL COMMENT '楼层名',
  `building_id` varchar(32) DEFAULT NULL COMMENT '楼栋id',
  `building_name` varchar(125) DEFAULT NULL COMMENT '楼栋名',
  `community_id` varchar(32) DEFAULT NULL COMMENT '小区id',
  `community_name` varchar(125) DEFAULT NULL COMMENT '小区名',
  `out_id` varchar(32) NOT NULL COMMENT '交班人id',
  `out_name` varchar(32) NOT NULL COMMENT '交班人姓名',
  `succession_id` varchar(32) NOT NULL COMMENT '接班人id',
  `succession_name` varchar(32) NOT NULL COMMENT '接班人姓名',
  `schedule_day` varchar(32) DEFAULT NULL COMMENT '替班日期',
  `schedule_shift` varchar(32) DEFAULT NULL COMMENT '替班班次',
  `elder_info` text COMMENT '交接班长者信息',
  `file_info` text COMMENT '附件信息',
  `receiver_id` varchar(32) NOT NULL COMMENT '登记id',
  `receiver_time` bigint(20) NOT NULL COMMENT '登记时间',
  `receiver_name` varchar(32) NOT NULL COMMENT '登记人name',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `statistics_info` text,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`schedule_butler_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='管家工作站交接班记录表';

-- ----------------------------
-- Table structure for lb_ims_schedule_butler_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_butler_setting`;
CREATE TABLE `lb_ims_schedule_butler_setting` (
  `butler_setting_id` varchar(32) NOT NULL COMMENT '主键',
  `shift_time` tinyint(2) NOT NULL DEFAULT '7' COMMENT '护理交接班默认开始时间',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1-文档模式 2-表格模式',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`butler_setting_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工作站交接班配置表';

-- ----------------------------
-- Table structure for lb_ims_schedule_plan
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_plan`;
CREATE TABLE `lb_ims_schedule_plan` (
  `schedule_plan_id` varchar(32) NOT NULL COMMENT '主键',
  `plan_name` varchar(32) DEFAULT '' COMMENT '方案名称',
  `plan_describe` varchar(255) DEFAULT NULL COMMENT '方案说明',
  `schedule_type` tinyint(1) DEFAULT '0' COMMENT '排班周期类型，1周2月',
  `schedule_number` tinyint(2) DEFAULT NULL COMMENT '班次数量',
  `receiver_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '登记id',
  `receiver_name` varchar(32) NOT NULL COMMENT '登记人name',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`schedule_plan_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护工排班方案表';

-- ----------------------------
-- Table structure for lb_ims_schedule_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_record`;
CREATE TABLE `lb_ims_schedule_record` (
  `schedule_record_id` varchar(32) NOT NULL COMMENT '主键',
  `schedule_name` varchar(32) DEFAULT NULL COMMENT '排班表名称',
  `schedule_day` bigint(20) DEFAULT NULL COMMENT '排班时间年月日 20200701',
  `start_day` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_day` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `execute_time` varchar(32) DEFAULT '' COMMENT '执行时间',
  `schedule_plan_id` varchar(32) DEFAULT NULL COMMENT '排班方案ID',
  `schedule_plan_name` varchar(32) DEFAULT NULL COMMENT '排班方案名称',
  `team_id` varchar(32) NOT NULL COMMENT '小组id',
  `team_name` varchar(32) NOT NULL COMMENT '小组名称',
  `nurse_id` varchar(32) NOT NULL COMMENT '护工id',
  `schedule_shift_id` varchar(32) DEFAULT NULL COMMENT '班次id',
  `schedule_shift_name` varchar(32) DEFAULT NULL COMMENT '班次名称',
  `is_replace` int(10) NOT NULL DEFAULT '0' COMMENT '是否替班，0不是，1是替班',
  `receiver_id` varchar(32) NOT NULL COMMENT '登记id',
  `receiver_name` varchar(32) NOT NULL COMMENT '登记人name',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `department_id` varchar(32) NOT NULL COMMENT '人员部门ID',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`schedule_record_id`) USING BTREE,
  KEY `schedule_day` (`schedule_day`),
  KEY `start_day` (`start_day`),
  KEY `end_day` (`end_day`),
  KEY `care_schedule_plan_id` (`schedule_plan_id`),
  KEY `nurse_id` (`nurse_id`),
  KEY `care_schedule_shift_id` (`schedule_shift_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='排班记录表';

-- ----------------------------
-- Table structure for lb_ims_schedule_remark
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_remark`;
CREATE TABLE `lb_ims_schedule_remark` (
  `schedule_remark_id` varchar(32) NOT NULL COMMENT '主键',
  `type` tinyint(1) NOT NULL COMMENT '1-管家交接班 2-护理员交接班 3-部门交接班',
  `remark` text COMMENT '备注',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`schedule_remark_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='工作站交接班备注模板表';

-- ----------------------------
-- Table structure for lb_ims_schedule_replace
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_replace`;
CREATE TABLE `lb_ims_schedule_replace` (
  `replace_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `team_id` varchar(32) DEFAULT NULL COMMENT '小组id',
  `team_name` varchar(32) DEFAULT NULL COMMENT '小组名称',
  `out_id` varchar(32) NOT NULL COMMENT '交班人id',
  `out_name` varchar(32) NOT NULL COMMENT '交班人姓名',
  `succession_id` varchar(32) NOT NULL COMMENT '接班人id',
  `succession_name` varchar(32) NOT NULL COMMENT '接班人姓名',
  `schedule_day` varchar(32) DEFAULT '' COMMENT '替班日期',
  `schedule_shift_id` varchar(32) DEFAULT NULL COMMENT '替班班次记录',
  `reason` varchar(300) DEFAULT NULL COMMENT '替班原因',
  `remark` varchar(300) DEFAULT NULL COMMENT '审批备注/撤销原因',
  `approval_state` tinyint(1) DEFAULT '0' COMMENT '审批状态 0未审批，1审批通过 ,2撤销',
  `receiver_id` varchar(32) NOT NULL COMMENT '登记id',
  `receiver_time` bigint(20) NOT NULL COMMENT '登记时间',
  `receiver_name` varchar(32) NOT NULL COMMENT '登记人name',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`replace_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='替班记录表';

-- ----------------------------
-- Table structure for lb_ims_schedule_shift
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_schedule_shift`;
CREATE TABLE `lb_ims_schedule_shift` (
  `schedule_shift_id` varchar(32) NOT NULL COMMENT '主键',
  `schedule_plan_id` varchar(32) NOT NULL COMMENT '排班方案id',
  `name` varchar(32) NOT NULL COMMENT '班次名称',
  `start_time` bigint(20) DEFAULT '0' COMMENT '起始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`schedule_shift_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='排班方案班次表';

-- ----------------------------
-- Table structure for lb_ims_settle_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_settle_record`;
CREATE TABLE `lb_ims_settle_record` (
  `settle_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `settle_type` tinyint(1) NOT NULL COMMENT '结算类型（0 退住结算，1 欠费管理）',
  `status` tinyint(4) NOT NULL COMMENT '结算状态（0 未结算，1 已结算）',
  `settle_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结算时间',
  `settle_list` mediumtext NOT NULL COMMENT '结算清单/欠费记录ID',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `settle_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '结算金额（正：退费，负：缴费）',
  `adjust_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更金额（正：补缴，负：退款）',
  `adjust_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结算变更时间',
  `remark` text COMMENT '结算变更备注',
  `settle_remark` varchar(255) DEFAULT NULL COMMENT '结算备注',
  `register_name` varchar(32) DEFAULT NULL COMMENT '登记人姓名',
  `register_id` varchar(32) DEFAULT NULL COMMENT '登记人ID',
  `check_in_num` varchar(32) NOT NULL DEFAULT '' COMMENT '入住编号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `receivable_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '账单结算应收金额',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`settle_record_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='结算记录表';

-- ----------------------------
-- Table structure for lb_ims_settle_record_change
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_settle_record_change`;
CREATE TABLE `lb_ims_settle_record_change` (
  `settle_record_change_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `settle_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '结算记录主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `adjust_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结算变更时间',
  `adjust_amount` decimal(32,2) NOT NULL DEFAULT '0.00' COMMENT '变更金额（正：补缴，负：退款）',
  `remark` text COMMENT '结算变更备注',
  `register_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人ID',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `adjust_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '变更类型 0:未知 1:退款 2:补缴',
  `adjust_amount_before` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '变更前金额',
  `adjust_amount_after` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '变更后金额',
  `adjust_source_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:未知 1:退住结算变更 2:手动结算变更',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`settle_record_change_id`),
  KEY `org_id` (`org_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='结算变更记录表';

-- ----------------------------
-- Table structure for lb_ims_sign_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sign_record`;
CREATE TABLE `lb_ims_sign_record` (
  `sign_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `relation_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联记录主键',
  `sign_type` varchar(32) NOT NULL DEFAULT '' COMMENT '签字类型',
  `sign_url` varchar(125) NOT NULL DEFAULT '' COMMENT '签字图片地址',
  `sign_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '签字时间',
  `sign_reason` varchar(32) NOT NULL DEFAULT '' COMMENT '签字原因',
  `sign_person_type` varchar(64) NOT NULL DEFAULT '' COMMENT '签字人类型',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sign_record_id`),
  KEY `idx_org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='签字记录表';

-- ----------------------------
-- Table structure for lb_ims_sms
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms`;
CREATE TABLE `lb_ims_sms` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `number` int(10) NOT NULL DEFAULT '0' COMMENT '短信剩余条数',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='短信服务条数记录';

-- ----------------------------
-- Table structure for lb_ims_sms_send_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms_send_record`;
CREATE TABLE `lb_ims_sms_send_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '记录主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '',
  `context` text NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(32) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='短信发送记录';

-- ----------------------------
-- Table structure for lb_ims_sms_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms_task`;
CREATE TABLE `lb_ims_sms_task` (
  `task_id` varchar(32) NOT NULL DEFAULT '',
  `template_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '模板类型',
  `sign_code` varchar(255) NOT NULL DEFAULT '' COMMENT '签名code',
  `phone_number` varchar(32) NOT NULL DEFAULT '' COMMENT '手机号',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `care_object_name` varchar(10) NOT NULL DEFAULT '' COMMENT '长者名称',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `content` text NOT NULL COMMENT '发送内容',
  `is_send` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已发送 0未发/1已发',
  `send_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '发送时间点，毫秒级时间戳',
  `extra_msg` varchar(255) DEFAULT '' COMMENT '额外消息内容 (不足的药品名称/扣费账单的月份)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='短信延时发送任务';

-- ----------------------------
-- Table structure for lb_ims_sms_task_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms_task_v2`;
CREATE TABLE `lb_ims_sms_task_v2` (
  `task_id` varchar(32) NOT NULL DEFAULT '',
  `code_num` varchar(16) NOT NULL DEFAULT '' COMMENT '模板code',
  `sign_code` varchar(255) NOT NULL DEFAULT '' COMMENT '签名code',
  `phone_number` varchar(32) NOT NULL DEFAULT '' COMMENT '手机号',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `care_object_name` varchar(10) NOT NULL DEFAULT '' COMMENT '长者名称',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `content` text NOT NULL COMMENT '发送内容',
  `is_send` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已发送 0未发/1已发',
  `send_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '发送时间点，毫秒级时间戳',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='短信延时发送任务';

-- ----------------------------
-- Table structure for lb_ims_sms_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms_template`;
CREATE TABLE `lb_ims_sms_template` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `template_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'lb_ali_template',
  `sign_code` varchar(16) NOT NULL DEFAULT 'sign02' COMMENT '签名code(lb_ali_sign)',
  `receive` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接收人 0本人/1亲属/2紧急联系人',
  `reminder` tinyint(1) NOT NULL DEFAULT '0' COMMENT '提醒时间  0实时/1两小时后/2六小时后',
  `sms_context` text COMMENT '内容',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态 0待审批/1启用/2停用/3不通过',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='用户定制模板短信发送内容';

-- ----------------------------
-- Table structure for lb_ims_sms_topup_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_sms_topup_order`;
CREATE TABLE `lb_ims_sms_topup_order` (
  `order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '短信充值订单主键',
  `pay_way` tinyint(1) DEFAULT '0' COMMENT '支付方式  0微信、1支付宝',
  `pay_order_id` varchar(32) DEFAULT NULL COMMENT '支付订单id(lb_wechat_order/lb_alipay_order)',
  `number` int(10) NOT NULL DEFAULT '0' COMMENT '充值条数（守护长者充值月数）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `status` int(10) NOT NULL DEFAULT '0' COMMENT '订单状态 0待支付、1支付成功、2支付失败、3超时',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_invoice` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已开票 0未开/1已开',
  `pay_order_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '充值订单类型 1 短信充值 2 守护长者充值',
  `recharge_num` int(10) NOT NULL DEFAULT '1' COMMENT '充值人数',
  `account_name` varchar(30) DEFAULT NULL COMMENT '操作员',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='短信充值订单';

-- ----------------------------
-- Table structure for lb_ims_staff
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_staff`;
CREATE TABLE `lb_ims_staff` (
  `staff_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '部门主键',
  `name` varchar(125) NOT NULL COMMENT '姓名',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证号',
  `gender` char(1) DEFAULT NULL COMMENT '性别',
  `age` tinyint(3) DEFAULT '0' COMMENT '年龄',
  `phone_num` varchar(11) NOT NULL DEFAULT '' COMMENT '联系电话',
  `emergency_contact_phone` varchar(11) DEFAULT '' COMMENT '紧急联系人电话',
  `nation` char(2) DEFAULT NULL COMMENT '民族',
  `political_status` char(1) DEFAULT NULL COMMENT '政治面貌',
  `hometown` varchar(32) DEFAULT '' COMMENT '籍贯',
  `job_title` varchar(32) DEFAULT NULL COMMENT '职称',
  `census_address_code` varchar(125) DEFAULT '' COMMENT '户籍地址行政区码',
  `census_address` varchar(125) DEFAULT '' COMMENT '户籍地址',
  `home_address_code` varchar(125) DEFAULT '' COMMENT '家庭地址行政区码',
  `home_address` varchar(125) DEFAULT '' COMMENT '家庭地址',
  `educational_level` varchar(32) NOT NULL COMMENT '文化程度',
  `specialty` varchar(32) DEFAULT '' COMMENT '专业',
  `job_title_level` char(1) DEFAULT NULL COMMENT '职称级别',
  `other_treatment` varchar(200) DEFAULT '' COMMENT '其他待遇',
  `office` varchar(32) DEFAULT NULL COMMENT '职务',
  `salary` varchar(32) DEFAULT '' COMMENT '薪金',
  `contract_type` char(1) DEFAULT NULL COMMENT '合同类型',
  `contract_num` varchar(32) DEFAULT '' COMMENT '合同编号',
  `contract_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '合同开始时间',
  `contract_end_update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '合同结束时间',
  `entry_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '入职时间',
  `personnel_type` varchar(32) NOT NULL COMMENT '人员类型0-其他人员类型1-管理人员2-财务人员3-安全人员4-后勤人员5-护理人员6-医务人员7-人事人员８-管家人员',
  `job_position` varchar(32) DEFAULT NULL COMMENT '工作岗位',
  `contract_attachment` varchar(255) DEFAULT '' COMMENT '合同附件',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '在职状态（0 在职，1 离职）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `photo` varchar(255) DEFAULT '' COMMENT '头像',
  `contract_attachment_name` varchar(255) DEFAULT '' COMMENT '合同附件名称',
  `account_id` varchar(32) DEFAULT '' COMMENT '职工app账号唯一标识',
  `ims_account_id` varchar(32) DEFAULT '' COMMENT 'ims平台帐号唯一标识',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `code` varchar(100) DEFAULT NULL COMMENT '人员编号',
  `dimission_time` bigint(20) DEFAULT NULL COMMENT '离职时间',
  `department_framework_id` varchar(32) DEFAULT '' COMMENT '所属部门组织id',
  `is_superior` tinyint(1) DEFAULT '0' COMMENT '是否是主管 0不是 1是',
  `kingdee_expense_department` varchar(32) NOT NULL DEFAULT '' COMMENT '金蝶部门编码',
  `verified_account` varchar(255) NOT NULL DEFAULT '' COMMENT '身份验证账号',
  `verified_password` varchar(255) NOT NULL DEFAULT '' COMMENT '身份验证密码',
  `complete_nursing_setup_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '完成护理设置类型 0-APP直接完成 1-定位到长者房间完成',
  `will_view_permissions` tinyint(1) NOT NULL DEFAULT '0' COMMENT '遗嘱查看权限 0-无权限 1-有权限',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `allow_view_material_price` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否允许查看库存物资价格 0-不允许 1-允许',
  PRIMARY KEY (`staff_id`) USING BTREE,
  KEY `department_id` (`department_id`) USING BTREE,
  KEY `org_id` (`org_id`,`personnel_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='员工表';

-- ----------------------------
-- Table structure for lb_ims_staff_manage_warehouse
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_staff_manage_warehouse`;
CREATE TABLE `lb_ims_staff_manage_warehouse` (
  `id` varchar(32) NOT NULL COMMENT 'id',
  `staff_id` varchar(32) NOT NULL DEFAULT '' COMMENT '员工id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `warehouse_id` varchar(32) NOT NULL DEFAULT '' COMMENT '仓库id',
  `warehouse_name` varchar(64) NOT NULL DEFAULT '' COMMENT '仓库名称',
  `warehouse_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:库存管理,1:药品仓库',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  PRIMARY KEY (`id`),
  KEY `staff_id_index` (`staff_id`) USING BTREE COMMENT '员工id索引',
  KEY `idx_org_id` (`org_id`),
  KEY `idx_warehouse_id` (`warehouse_id`),
  KEY `idx_is_delete` (`is_delete`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='员工管理仓库信息表';

-- ----------------------------
-- Table structure for lb_ims_statistics_time
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_statistics_time`;
CREATE TABLE `lb_ims_statistics_time` (
  `statistics_time_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`statistics_time_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='缴费/退费统计时间段范围';

-- ----------------------------
-- Table structure for lb_ims_supplier
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_supplier`;
CREATE TABLE `lb_ims_supplier` (
  `supplier_id` varchar(32) NOT NULL COMMENT '主键',
  `supplier_name` varchar(64) DEFAULT '' COMMENT '供应商名称',
  `supplier_type` tinyint(2) DEFAULT NULL COMMENT '供应商性质 1-制造商、2-代理商、3-批发商、4-零售商',
  `supplier_principal` varchar(64) DEFAULT '' COMMENT '负责人姓名',
  `supplier_phone` varchar(32) DEFAULT '' COMMENT '联系电话',
  `supplier_position` varchar(64) DEFAULT '0' COMMENT '联系地址',
  `supplier_region` varchar(255) DEFAULT NULL COMMENT '地址所在区域',
  `supplier_status` tinyint(1) DEFAULT '0' COMMENT '供应状态 0-正常供应 1-非正常供应',
  `supplier_level` tinyint(2) DEFAULT NULL COMMENT '供应商等级 1-A级、2-B级、3-C级、4-D级',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人',
  `check_time` bigint(20) DEFAULT '0' COMMENT '登记时间',
  `type` tinyint(1) DEFAULT '0' COMMENT '0:库存供应商,1:药品供应商',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplier_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='供应商表';

-- ----------------------------
-- Table structure for lb_ims_supplies
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_supplies`;
CREATE TABLE `lb_ims_supplies` (
  `supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_name` varchar(64) DEFAULT '' COMMENT '物资名称',
  `supplies_category_id` varchar(32) DEFAULT '' COMMENT '所属类别id',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `supplier_id` varchar(32) DEFAULT '' COMMENT '供应商id',
  `max_warning_value` int(3) DEFAULT '0' COMMENT '上限预警值',
  `min_warning_value` int(3) DEFAULT '0' COMMENT '下限预警值',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '是否可用0不可用1可用',
  `supplies_description` varchar(255) DEFAULT '' COMMENT '物资描述',
  `price` decimal(10,2) DEFAULT '0.00' COMMENT '单价',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `subsidiary_standard` varchar(32) NOT NULL DEFAULT '' COMMENT '副单位',
  `standard_multiple` int(3) NOT NULL DEFAULT '1' COMMENT '副单位倍数(主单位/副单位)',
  PRIMARY KEY (`supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='物资表';

-- ----------------------------
-- Table structure for lb_ims_supplies_category
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_supplies_category`;
CREATE TABLE `lb_ims_supplies_category` (
  `supplies_category_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_category_name` varchar(64) DEFAULT '' COMMENT '类别名称',
  `parent_id` varchar(32) DEFAULT '' COMMENT '所属类别id',
  `supplies_category_description` varchar(100) DEFAULT '' COMMENT '类别描述',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplies_category_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='物资类别表';

-- ----------------------------
-- Table structure for lb_ims_supplies_drug
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_supplies_drug`;
CREATE TABLE `lb_ims_supplies_drug` (
  `supplies_drug_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_drug_name` varchar(64) DEFAULT NULL COMMENT '物资药品名称',
  `specifications` varchar(32) DEFAULT NULL COMMENT '规格:1片2支3粒4瓶5袋6其他',
  `content` int(11) NOT NULL DEFAULT '1' COMMENT '药品容量',
  `dosage_form` varchar(32) DEFAULT NULL COMMENT '剂型:1片剂2针剂3颗粒4胶囊5其他',
  `type` varchar(32) NOT NULL COMMENT '类型 1－中药、２－西药',
  `max_warning_value` int(3) DEFAULT '0' COMMENT '上限预警值',
  `min_warning_value` int(3) DEFAULT '0' COMMENT '下限预警值',
  `supplier_id` varchar(32) DEFAULT NULL COMMENT '供应商id',
  `warehouse_id` varchar(32) NOT NULL COMMENT '仓库ID',
  `register_time` bigint(20) DEFAULT NULL COMMENT '登记时间',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `dose_unit` varchar(100) DEFAULT NULL COMMENT '用法用量',
  `medicine_way` varchar(32) DEFAULT NULL COMMENT '给药途径',
  `unit_price` decimal(32,2) DEFAULT '0.00' COMMENT '单价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`supplies_drug_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='物资表(药品)';

-- ----------------------------
-- Table structure for lb_ims_system_news
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_system_news`;
CREATE TABLE `lb_ims_system_news` (
  `system_news_id` varchar(32) NOT NULL DEFAULT '',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者唯一标识',
  `system_type` tinyint(1) DEFAULT '0' COMMENT '系统类型:默认0长者app',
  `news_type` tinyint(1) DEFAULT '0' COMMENT '消息类型:默认0在线点餐 1活动报名 2课程报名 3在线商城',
  `news_content` text COMMENT '消息内容',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否 删除 0 否 1 是',
  `record_id` varchar(32) DEFAULT '' COMMENT '记录唯一标识',
  `is_read` tinyint(1) DEFAULT '0' COMMENT '是否已读(0 未读，1 已读)',
  `news_status` tinyint(1) DEFAULT '1' COMMENT '1:确认/进行中 2:已确认 3:已完成 4:已取消/停止',
  `news_time` bigint(20) DEFAULT '0' COMMENT '下单/报名/消息时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`system_news_id`),
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='系统消息表';

-- ----------------------------
-- Table structure for lb_ims_team
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_team`;
CREATE TABLE `lb_ims_team` (
  `team_id` varchar(32) NOT NULL COMMENT '主键',
  `team_name` varchar(32) NOT NULL COMMENT '小组名称',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `personnel_type` tinyint(1) NOT NULL COMMENT '人员类型',
  `nurse_team_name` varchar(32) DEFAULT '' COMMENT '小组名称',
  `nurse_team_id` varchar(32) DEFAULT '' COMMENT '主键(临时)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`team_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理小组表';

-- ----------------------------
-- Table structure for lb_ims_team_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_team_relation`;
CREATE TABLE `lb_ims_team_relation` (
  `team_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `team_id` varchar(32) NOT NULL COMMENT '小组主键',
  `care_id` varchar(32) NOT NULL COMMENT '护工id',
  `is_leader` tinyint(1) NOT NULL COMMENT '是否是小组组长 1是 2 不是',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`team_relation_id`) USING BTREE,
  KEY `team_id` (`team_id`) USING BTREE,
  KEY `care_id` (`care_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='护理小组成员关系表';

-- ----------------------------
-- Table structure for lb_ims_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_template`;
CREATE TABLE `lb_ims_template` (
  `template_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构',
  `template_name` varchar(32) NOT NULL DEFAULT '' COMMENT '模板名称',
  `template_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '模板类型 1 护理单 2 病历单 3 交接班',
  `content` mediumtext COMMENT '模板内容',
  `editor_id` varchar(32) NOT NULL DEFAULT '' COMMENT '编辑人id',
  `editor_name` varchar(32) NOT NULL DEFAULT '' COMMENT '编辑人',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`template_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='自定义模板';

-- ----------------------------
-- Table structure for lb_ims_template_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_template_data`;
CREATE TABLE `lb_ims_template_data` (
  `template_data_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构',
  `name` varchar(32) NOT NULL DEFAULT '' COMMENT '名称',
  `content` text NOT NULL COMMENT '模板内容',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `edit` int(11) NOT NULL DEFAULT '1',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`template_data_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='基础数据管理';

-- ----------------------------
-- Table structure for lb_ims_template_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_template_object`;
CREATE TABLE `lb_ims_template_object` (
  `template_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `template_id` varchar(32) NOT NULL DEFAULT '' COMMENT '模板id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构',
  `template_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '模板类型 1 护理单 2 病历单 3 交接班',
  `content` mediumtext NOT NULL COMMENT '内容',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人名称',
  `department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '部门id',
  `department_name` varchar(32) NOT NULL DEFAULT '' COMMENT '部门名称',
  `is_print` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否打印 0 未打印 1 已打印',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`template_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者对应记录表';

-- ----------------------------
-- Table structure for lb_ims_train
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_train`;
CREATE TABLE `lb_ims_train` (
  `train_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `train_name` varchar(32) NOT NULL DEFAULT '' COMMENT '培训名称',
  `train_type` varchar(32) NOT NULL DEFAULT '' COMMENT '培训类型',
  `presenter` varchar(32) NOT NULL DEFAULT '' COMMENT '主讲人',
  `train_unit` varchar(32) DEFAULT '' COMMENT '培训单位',
  `train_location` varchar(32) DEFAULT '' COMMENT '培训地点',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `train_content` text COMMENT '培训内容',
  `attachment` text NOT NULL COMMENT '附件地址',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `attachment_name` text NOT NULL COMMENT '附件名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`train_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='培训信息表';

-- ----------------------------
-- Table structure for lb_ims_train_staff
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_train_staff`;
CREATE TABLE `lb_ims_train_staff` (
  `train_staff_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `staff_id` varchar(32) NOT NULL COMMENT '员工id',
  `train_id` varchar(32) NOT NULL COMMENT '培训记录id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`train_staff_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE,
  KEY `idx_staff_id` (`staff_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='培训参与员工关系表';

-- ----------------------------
-- Table structure for lb_ims_transfer_supplies_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_transfer_supplies_record`;
CREATE TABLE `lb_ims_transfer_supplies_record` (
  `transfer_supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `move_warehouse_id` varchar(32) DEFAULT '' COMMENT '调出仓库id',
  `warehouse_id` varchar(32) DEFAULT '' COMMENT '申请仓库id',
  `check_account_name` varchar(64) DEFAULT '' COMMENT '登记人姓名',
  `handle_account_name` varchar(64) DEFAULT '' COMMENT '经办人姓名',
  `handle_account_id` varchar(32) DEFAULT '' COMMENT '经办人id',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人id',
  `is_check` tinyint(1) DEFAULT '0' COMMENT '审核状态0审核中1审核通过2审核不通过',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`transfer_supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='调拨物资信息表';

-- ----------------------------
-- Table structure for lb_ims_tumble_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_tumble_config`;
CREATE TABLE `lb_ims_tumble_config` (
  `tumble_config_id` varchar(64) NOT NULL COMMENT '主键',
  `start_number` int(10) DEFAULT '0' COMMENT '分数范围开始',
  `end_number` int(10) DEFAULT '0' COMMENT '分数范围结束',
  `evaluate_standard` varchar(32) DEFAULT NULL COMMENT '评估标准',
  `assessment` varchar(255) DEFAULT NULL COMMENT '综合评价',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `device_recommend` varchar(128) NOT NULL DEFAULT '' COMMENT '设备推荐描述',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`tumble_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='跌倒评估标准配置';

-- ----------------------------
-- Table structure for lb_ims_visit
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_visit`;
CREATE TABLE `lb_ims_visit` (
  `visit_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `visit_name` varchar(128) DEFAULT '' COMMENT '来访人姓名',
  `visit_phone_num` varchar(125) DEFAULT '' COMMENT '来访人手机号',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者',
  `vsit_time` bigint(20) DEFAULT '0' COMMENT '探视时间',
  `vsit_type` varchar(32) NOT NULL DEFAULT '' COMMENT '来访人类型',
  `pass_through` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否放行 0 否 1 是',
  `return_time` bigint(20) DEFAULT '0' COMMENT '返回时间',
  `reasons` varchar(255) DEFAULT '' COMMENT '原因',
  `is_return` tinyint(1) DEFAULT '0' COMMENT '0:未返回1:返回',
  `register_account_id` varchar(32) DEFAULT '' COMMENT '登记账号',
  `register_name` varchar(125) DEFAULT '' COMMENT '登记人姓名',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`visit_id`) USING BTREE,
  KEY `idx_care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='来访信息';

-- ----------------------------
-- Table structure for lb_ims_warehouse
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_warehouse`;
CREATE TABLE `lb_ims_warehouse` (
  `warehouse_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_name` varchar(64) DEFAULT '' COMMENT '仓库名称',
  `admin_name` varchar(64) DEFAULT NULL COMMENT '仓库管理员',
  `warehouse_position` varchar(125) DEFAULT '' COMMENT '仓库位置',
  `warehouse_use_description` varchar(255) DEFAULT '' COMMENT '仓库用途描述',
  `warehouse_type` tinyint(1) DEFAULT '0' COMMENT '0:库存管理,1:药品仓库',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`warehouse_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='仓库表';

-- ----------------------------
-- Table structure for lb_ims_warehouse_change_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_warehouse_change_record`;
CREATE TABLE `lb_ims_warehouse_change_record` (
  `warehouse_record_id` varchar(32) NOT NULL COMMENT '主键',
  `supplies_type` tinyint(1) DEFAULT '0' COMMENT '物资来源/去向类型',
  `record_type` tinyint(1) DEFAULT '0' COMMENT '1 入库记录 2出库记录 3 调拨记录 4 盘点记录',
  `warehouse_id` varchar(32) DEFAULT '' COMMENT '仓库id',
  `handle_account_id` varchar(32) DEFAULT '' COMMENT '经办人id',
  `check_account_id` varchar(32) DEFAULT '' COMMENT '登记人id',
  `record_time` bigint(20) DEFAULT '0' COMMENT '登记日期',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_number` int(3) DEFAULT '0' COMMENT '变动数量',
  `supplies_price` decimal(10,2) DEFAULT '0.00' COMMENT '单价',
  `supplies_product_time` bigint(20) DEFAULT '0' COMMENT '生产日期',
  `recipients_department_id` varchar(32) DEFAULT '0' COMMENT '物资使用人员部门',
  `is_check` tinyint(1) DEFAULT '0' COMMENT '审核状态0审核中1审核通过2审核不通过',
  `supplies_standard` varchar(32) DEFAULT '' COMMENT '规格',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `supplier_id` varchar(32) DEFAULT '' COMMENT '供应商id',
  `check_account_name` varchar(64) DEFAULT '' COMMENT '登记人姓名',
  `handle_account_name` varchar(64) DEFAULT '' COMMENT '经办人姓名',
  `type` tinyint(1) DEFAULT '0' COMMENT '0:库存管理,1:药品仓库',
  `recipients_name` varchar(64) DEFAULT NULL COMMENT '使用人姓名',
  `supplies_original_number` int(3) DEFAULT NULL COMMENT '变动前数量',
  `supplies_rest_number` int(3) DEFAULT NULL COMMENT '变动后数量',
  `record_group_id` varchar(32) DEFAULT '' COMMENT '所属组别id',
  `scarapped_reason` varchar(255) DEFAULT '' COMMENT '报废原因',
  `apply_number` int(10) DEFAULT '0' COMMENT ' 龙柏康养中心项目-出库登记-申请数量',
  `approve_name` varchar(64) DEFAULT '' COMMENT '审批人姓名',
  `remark` text NOT NULL COMMENT '备注',
  `purchase_department_id` varchar(32) NOT NULL DEFAULT '' COMMENT '采购部门id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `standard_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '所选单位类型：1主单位 2副单位',
  `base_standard` varchar(32) NOT NULL DEFAULT '' COMMENT '主单位',
  `base_number` int(3) NOT NULL DEFAULT '0' COMMENT '主单位数量',
  `secondary_standard` varchar(32) NOT NULL DEFAULT '' COMMENT '副单位',
  `secondary_standard_multiple` int(3) NOT NULL DEFAULT '1' COMMENT '副单位倍数',
  `order_number` varchar(32) NOT NULL DEFAULT '' COMMENT '单号',
  `customer_name` varchar(32) NOT NULL DEFAULT '' COMMENT '客户姓名',
  PRIMARY KEY (`warehouse_record_id`) USING BTREE,
  KEY `idx_warehouse_id` (`warehouse_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='库存记录变动表';

-- ----------------------------
-- Table structure for lb_ims_warehouse_supplies
-- ----------------------------
DROP TABLE IF EXISTS `lb_ims_warehouse_supplies`;
CREATE TABLE `lb_ims_warehouse_supplies` (
  `warehouse_supplies_id` varchar(32) NOT NULL COMMENT '主键',
  `warehouse_id` varchar(32) DEFAULT NULL COMMENT '仓库id',
  `supplies_id` varchar(32) DEFAULT '' COMMENT '物资id',
  `supplies_out_number` int(10) DEFAULT '0' COMMENT '出库数量',
  `supplies_in_number` int(10) DEFAULT '0' COMMENT '入库数量',
  `store_number` int(10) DEFAULT '0' COMMENT '库存数量',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `version` int(11) NOT NULL DEFAULT '1' COMMENT '版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`warehouse_supplies_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='库存表';

-- ----------------------------
-- Table structure for lb_infusions_alarm_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_infusions_alarm_device`;
CREATE TABLE `lb_infusions_alarm_device` (
  `infusions_alarm_device_id` varchar(64) NOT NULL COMMENT '主键',
  `master_control_box_id` varchar(64) DEFAULT '' COMMENT 'master_control_box_id',
  `bed_num` varchar(32) DEFAULT '' COMMENT '床位号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `iot_chip_model` varchar(32) DEFAULT NULL COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(64) DEFAULT '' COMMENT '卡号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(3) DEFAULT '1' COMMENT '1:在线 2:离线',
  `work_state` tinyint(3) DEFAULT '2' COMMENT '1:工作状态 2：空闲状态',
  `bed_num_sbh` varchar(64) DEFAULT '' COMMENT 'bed_num_sbh',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `version` tinyint(3) unsigned DEFAULT '1' COMMENT '下发信息版本号',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `pic_version` varchar(32) DEFAULT '' COMMENT '图片版本',
  `is_delete` tinyint(3) DEFAULT '0' COMMENT '0:未删除 1:删除中 2：删除失败',
  `device_delete_time` bigint(20) DEFAULT '0' COMMENT '输液报警器设备计划删除时间',
  `device_iteration_number` varchar(32) DEFAULT '' COMMENT '设备迭代版本号',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构组织唯一标识',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间id',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位id',
  `device_type` tinyint(3) DEFAULT '109' COMMENT '设备类型',
  `custom_bed_num` varchar(32) DEFAULT '' COMMENT '自定义床位号',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的上报时间',
  `receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`infusions_alarm_device_id`),
  KEY `mac` (`mac`) USING BTREE,
  KEY `master_control_box_id` (`master_control_box_id`) USING BTREE,
  KEY `index_bed_id` (`bed_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_infusions_beacon
-- ----------------------------
DROP TABLE IF EXISTS `lb_infusions_beacon`;
CREATE TABLE `lb_infusions_beacon` (
  `beacon_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_type` tinyint(3) DEFAULT '20' COMMENT '设备类型 20:出口信标 21入口信标',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `position_re_id` varchar(32) DEFAULT '' COMMENT '位置id',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(1) DEFAULT '2' COMMENT '1:在线 2:离线',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `version` tinyint(3) DEFAULT '1' COMMENT '下发版本号',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`beacon_id`),
  KEY `orgId` (`org_id`) USING BTREE,
  KEY `mac` (`mac`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_infusions_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_infusions_data`;
CREATE TABLE `lb_infusions_data` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` tinyint(3) NOT NULL COMMENT '设备类型(109输液报警器)',
  `msg_type` tinyint(3) NOT NULL COMMENT '消息类型',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构组织唯一标识',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间id',
  `bed_id` varchar(32) DEFAULT '' COMMENT '床位id',
  `bed_num` varchar(32) DEFAULT '' COMMENT '床位号',
  `work_state` tinyint(1) DEFAULT '2' COMMENT '1:工作状态 2：空闲状态',
  `device_state` tinyint(3) DEFAULT '-1' COMMENT '输液设备上报状态',
  `version` varchar(32) DEFAULT '' COMMENT '版本号',
  `time_stamp` bigint(20) DEFAULT '0' COMMENT '设备上报时间戳',
  `speed` int(10) DEFAULT '0' COMMENT '滴速',
  `power` int(10) DEFAULT '0' COMMENT '电量',
  `signal` int(10) DEFAULT '0' COMMENT '信号强度',
  `outside_power` int(10) DEFAULT '0' COMMENT '外信标电量',
  `inside_power` int(10) DEFAULT '0' COMMENT '内信标电量',
  `beacon_mac` varchar(255) DEFAULT '' COMMENT '信标mac',
  `create_time` bigint(20) DEFAULT '0',
  `update_time` bigint(20) DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_device` (`org_id`,`iot_device_id`),
  KEY `time_stamp` (`time_stamp`),
  KEY `device_msg` (`iot_device_id`,`msg_type`),
  KEY `lb_infusions_data_iot_device_id_IDX` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_infusions_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_infusions_record`;
CREATE TABLE `lb_infusions_record` (
  `id` int(11) NOT NULL COMMENT '主键',
  `alarm_device_id` varchar(64) DEFAULT '' COMMENT '报警设备id',
  `speed` tinyint(4) unsigned DEFAULT '0' COMMENT '滴速,单位分钟',
  `status` tinyint(4) DEFAULT '0' COMMENT '输液状态： 0 输液结束 1输液开始 2 输液过慢 3 输液过快',
  `rssi` tinyint(4) DEFAULT '0' COMMENT '信号强度',
  `power` tinyint(3) DEFAULT '0' COMMENT '电量',
  `receive_time` bigint(20) DEFAULT '0' COMMENT '接受时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='输液记录';

-- ----------------------------
-- Table structure for lb_installtool_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_installtool_account`;
CREATE TABLE `lb_installtool_account` (
  `installtool_account_id` varchar(32) NOT NULL COMMENT '主键',
  `username` varchar(11) DEFAULT '' COMMENT '用户名',
  `password` varchar(32) DEFAULT '' COMMENT '密码',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`installtool_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_iot_app
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_app`;
CREATE TABLE `lb_iot_app` (
  `id` int(11) NOT NULL COMMENT '主键',
  `app_id` varchar(256) DEFAULT '' COMMENT '应用唯一标识',
  `secret` varchar(256) DEFAULT '' COMMENT '应用密码',
  `secret_password` varchar(32) DEFAULT '' COMMENT 'secret密钥',
  `electricity_mode` tinyint(1) DEFAULT '1' COMMENT '应用的电量模式 0:eDRX 1:DRX  2:PSM',
  `device_amount` int(11) DEFAULT '0' COMMENT '设备已注册总数',
  `is_subscribe` tinyint(1) DEFAULT '0' COMMENT '应用是否订阅标识,0未订阅,1已订阅',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_register` tinyint(4) DEFAULT '0' COMMENT '是否为注册应用',
  `api_url` varchar(256) DEFAULT NULL COMMENT '接口请求路由',
  `call_back_message_url` varchar(100) DEFAULT NULL COMMENT '消息推送地址',
  `call_back_cmd_url` varchar(100) DEFAULT NULL COMMENT '命令推送地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

