-- ----------------------------
-- Table structure for lb_iot_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device`;
CREATE TABLE `lb_iot_device` (
  `iot_device_id` varchar(64) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `psk` varchar(32) DEFAULT '' COMMENT '加密密钥',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '设备注册信息是否有效，1有效，0已失效',
  `iot_app_id` varchar(32) DEFAULT '' COMMENT '设备注册的应用id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `device_type` mediumint(9) DEFAULT '0' COMMENT '设备类型枚举,参见枚举文档',
  `product_id` varchar(32) DEFAULT NULL COMMENT '产品id',
  `feature_str` varchar(192) DEFAULT NULL COMMENT '特征串',
  `device_iteration_number` int(3) DEFAULT '-1' COMMENT '设备版本迭代号',
  `org_id` varchar(64) DEFAULT NULL COMMENT '机构id',
  `platform_type` tinyint(1) DEFAULT '0' COMMENT '平台类型，0：OC，1：AEP',
  `device_id` varchar(64) DEFAULT NULL COMMENT '电信平台id',
  `device_model` int(3) DEFAULT '0' COMMENT '设备型号',
  `is_bind` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否绑定，1是0否',
  `is_enter` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否为录入设备，1是0否',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_id`),
  KEY `lb_iot_device_device_id_IDX` (`device_id`) USING BTREE,
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备注册';

-- ----------------------------
-- Table structure for lb_iot_device_device_software_version_change_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_device_software_version_change_record`;
CREATE TABLE `lb_iot_device_device_software_version_change_record` (
  `iot_device_device_software_version_change_record_id` varchar(64) NOT NULL DEFAULT '' COMMENT '版本记录id',
  `device_unique_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `software_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '软件类型 (详见枚举文档)',
  `version_name` varchar(32) NOT NULL DEFAULT '' COMMENT '版本名称',
  `is_latest` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否是当前最新版本 (1: 最新, 0: 旧版本)',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_device_software_version_change_record_id`),
  KEY `ids_device_unique_id` (`device_unique_id`),
  KEY `idx_device_id` (`device_unique_id`,`software_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本变更记录表';

-- ----------------------------
-- Table structure for lb_iot_device_software_upgrade_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_upgrade_config`;
CREATE TABLE `lb_iot_device_software_upgrade_config` (
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备迭代号',
  `channel` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '渠道号',
  `software_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '软件类型(0:主控芯片软件 1:4G通信模组软件 2:跌倒算法软件 3:NB通信模组软件 4:语音识别芯片软件 5:433接收芯片软件)\n                    原蓝牙升级版本默认为 0:主控芯片软件',
  `manufacturer_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '厂商类型(对应远程升级协议中 升级包类型)',
  `chip_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '芯片型号类型',
  `is_ble_upgrade` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '是否支持蓝牙升级(0:不支持 1:支持)',
  `is_ota_upgrade` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '是否支持远程升级(0:不支持 1:支持)',
  `ota_upgrade_protocol` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '远程升级协议(0:TCP 1:HTTP)',
  `ota_upgrade_method` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '远程升级方法(0:全量升级 1:增量升级(差分))',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_category`,`device_iteration_number`,`channel`,`software_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件升级配置表';

-- ----------------------------
-- Table structure for lb_iot_device_software_upgrade_flag
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_upgrade_flag`;
CREATE TABLE `lb_iot_device_software_upgrade_flag` (
  `iot_device_software_upgrade_flag_id` varchar(64) NOT NULL DEFAULT '' COMMENT 'id',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `device_category` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` tinyint(4) NOT NULL DEFAULT '-3' COMMENT '设备迭代号',
  `channel` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '渠道号',
  `software_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '软件类型(详见枚举文档)',
  `flag` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_software_upgrade_flag_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_iot_device_software_upgrade_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_upgrade_task`;
CREATE TABLE `lb_iot_device_software_upgrade_task` (
  `iot_device_software_upgrade_task_id` varchar(64) NOT NULL DEFAULT '' COMMENT '任务id',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `device_category` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `software_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '软件类型(详见枚举文档)',
  `upgrade_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备升级方式 1统一升级  2分批升级',
  `upgrade_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '升级任务状态 1未开始 2进行中 3已完成 4已取消',
  `target_version_name` varchar(32) NOT NULL DEFAULT '' COMMENT '升级任务目标版本名称',
  `upgrade_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '程序升级时间段(开始)',
  `upgrade_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '程序升级时间段(结束)',
  `registrant_id` varchar(64) NOT NULL DEFAULT '' COMMENT '登记人id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_software_upgrade_task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本升级任务表';

-- ----------------------------
-- Table structure for lb_iot_device_software_upgrade_task_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_upgrade_task_detail`;
CREATE TABLE `lb_iot_device_software_upgrade_task_detail` (
  `iot_device_software_upgrade_task_detail_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `iot_device_software_upgrade_task_id` varchar(64) NOT NULL DEFAULT '' COMMENT '任务id',
  `device_unique_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `device_category` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` tinyint(4) NOT NULL DEFAULT '-3' COMMENT '设备迭代版本号',
  `care_object_name` text COMMENT '长者姓名(暂留)',
  `upgrade_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '升级状态 1未开始 2进行中 3已完成 4已取消',
  `current_version_name` varchar(32) NOT NULL DEFAULT '' COMMENT '设备当前程序版本名称',
  `target_version_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备升级目标版本id',
  `upgrade_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '升级开始时间',
  `upgrade_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '升级结束时间',
  `upgrade_result_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '程序升级结果状态  1未升级 2成功 3失败 4取消 5超时 ',
  `upgrade_result_enum` smallint(1) NOT NULL DEFAULT '0' COMMENT '程序升级结果枚举（参照枚举）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_software_upgrade_task_detail_id`),
  KEY `idx_ota_upgrade_task_id` (`iot_device_software_upgrade_task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本升级任务详情表';

-- ----------------------------
-- Table structure for lb_iot_device_software_version_file_sharding
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_version_file_sharding`;
CREATE TABLE `lb_iot_device_software_version_file_sharding` (
  `iot_device_software_version_file_sharding_id` varchar(64) NOT NULL DEFAULT '',
  `iot_device_software_version_record_id` varchar(64) NOT NULL DEFAULT '' COMMENT '版本id',
  `content` text NOT NULL COMMENT '分包内容',
  `num` int(3) NOT NULL DEFAULT '0' COMMENT '分包序号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_software_version_file_sharding_id`),
  KEY `idx_version_id` (`iot_device_software_version_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本文件分片数据表';

-- ----------------------------
-- Table structure for lb_iot_device_software_version_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_version_record`;
CREATE TABLE `lb_iot_device_software_version_record` (
  `iot_device_software_version_record_id` varchar(64) NOT NULL COMMENT '版本id',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `device_iteration_number` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备迭代号',
  `channel` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '渠道号',
  `software_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '软件类型(详见枚举文档)',
  `version_name` varchar(32) NOT NULL DEFAULT '' COMMENT '版本名称',
  `version_update_content` mediumtext NOT NULL COMMENT '版本更新内容',
  `file_url` varchar(128) NOT NULL DEFAULT '' COMMENT '下载地址',
  `appendix_file_url` varchar(128) NOT NULL DEFAULT '' COMMENT '附件下载地址',
  `is_urgency` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为紧急版本(0:否 1:是)',
  `is_support_upgrade` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否支持升级(0:否 1:是)',
  `md_key` varchar(255) NOT NULL DEFAULT '' COMMENT '升级包文件md5值',
  `base_version_name` varchar(64) NOT NULL DEFAULT '' COMMENT '基础版本-版本名称(差分)',
  `crc` varchar(16) NOT NULL DEFAULT '' COMMENT '文件crc校验码 TCP',
  `dat_file` text NOT NULL COMMENT '.dat文件内容 TCP',
  `file_size` int(10) NOT NULL DEFAULT '0' COMMENT 'bin文件大小(单位/byte) TCP',
  `signature` varchar(128) NOT NULL DEFAULT '' COMMENT '启动机制校验信息 TCP',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_software_version_record_id`),
  UNIQUE KEY `idx_target_version_name` (`device_category`,`device_iteration_number`,`channel`,`version_name`,`base_version_name`),
  KEY `idx_version_name` (`version_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本记录表 ';

-- ----------------------------
-- Table structure for lb_iot_device_software_version_record_org_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_software_version_record_org_relation`;
CREATE TABLE `lb_iot_device_software_version_record_org_relation` (
  `relation_id` varchar(64) NOT NULL DEFAULT '' COMMENT '关联id',
  `iot_device_software_version_record_id` varchar(64) NOT NULL DEFAULT '' COMMENT '版本id',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '所属项目id，非空代表为所属项目定制版本',
  `is_latest` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否是最新版本(0:不是 1:是)',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`),
  KEY `idx_iot_device_software_version_record_id` (`iot_device_software_version_record_id`),
  KEY `idx_org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物联设备的软件版本记录-项目关联表 ';

-- ----------------------------
-- Table structure for lb_iot_device_test
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_test`;
CREATE TABLE `lb_iot_device_test` (
  `iot_device_id` varchar(64) NOT NULL COMMENT '主键',
  `imei` varchar(64) DEFAULT '' COMMENT '设备编号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `device_type` int(1) DEFAULT '1' COMMENT '1 手表 2 按钮',
  `status` int(1) DEFAULT '0' COMMENT '0注册成功，1已取消注册',
  `device_id` varchar(64) DEFAULT '' COMMENT '设备id',
  `mac` varchar(64) DEFAULT '' COMMENT 'mac地址',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '设备注册的应用id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备注册测试';

-- ----------------------------
-- Table structure for lb_iot_device_track
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_track`;
CREATE TABLE `lb_iot_device_track` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '0信标位置,1非信标位置(粗定位,gps,wifi)',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '粗纬度',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '粗经度',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '心率值',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `track_group_id` varchar(64) DEFAULT '' COMMENT '轨迹组名',
  `handle_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `blood_oxygen` int(3) DEFAULT '-1' COMMENT '血氧值',
  `device_status` tinyint(1) DEFAULT '1' COMMENT '手表佩带情况，0不显示佩带情况，1佩戴中，2未佩戴，3充电中',
  `content` text COMMENT '内容',
  `device_status_duration` bigint(20) DEFAULT '0' COMMENT '佩带状态持续时长',
  `systolic_pressure` int(3) DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT '-1' COMMENT '舒张压',
  `position_status` text COMMENT '位置状态记录',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `temperature` tinyint(3) DEFAULT '-10' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_humiture_sensor` tinyint(3) DEFAULT '0' COMMENT '是否有温湿度传感器 0:没有 1:有',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `track_open_id` varchar(64) DEFAULT '' COMMENT '轨迹开启人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `heart_rate_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示心率数据，1显示，0不显示',
  `blood_pressure_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血压数据，1显示，0不显示',
  `blood_oxygen_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血氧数据，1显示，0不显示',
  `is_intact` tinyint(1) DEFAULT '0' COMMENT '当前数据是否完整，1完整，0,不完整',
  `device_status_is_show` tinyint(1) DEFAULT '1' COMMENT '是否显示佩戴状态 0不显示,1显示',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `use_type` tinyint(1) DEFAULT '1' COMMENT '记录用途类型，1查找长者,2查找设备',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `uncalibrated_day_num` int(11) DEFAULT NULL COMMENT '血压计未校准天数',
  `is_applets_measure` tinyint(1) DEFAULT '0' COMMENT '是否小程序测量值 0:否1:是',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `is_health_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `is_position_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `body_temperature_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示体温数据，1显示，0不显示',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `breath` int(3) DEFAULT '-1' COMMENT '呼吸值',
  `breath_is_show` tinyint(1) DEFAULT '0' COMMENT '呼吸数据是否显示（0-不显示，1-显示）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`),
  KEY `track_group_id` (`track_group_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `record_type` (`record_type`),
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`,`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_iot_device_track_part
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_device_track_part`;
CREATE TABLE `lb_iot_device_track_part` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `is_outdoor` tinyint(1) DEFAULT '0' COMMENT '0信标位置,1非信标位置(粗定位,gps,wifi)',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型,0手表，1按钮',
  `lat_primitive` varchar(32) DEFAULT '' COMMENT '粗纬度',
  `lng_primitive` varchar(32) DEFAULT '' COMMENT '粗经度',
  `report_reason` tinyint(1) DEFAULT '0' COMMENT '上报位置的原因，0心跳上报，1室外报警上报',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `heart_rate` int(3) DEFAULT '-1' COMMENT '心率值',
  `record_type` tinyint(1) DEFAULT '1' COMMENT '1轨迹记录，2开启记录，3关闭记录，4心跳记录，5报警产生，6离家记录，7回家记录，8离院记录，9回院记录,10故障记录,11超时记录,12轨迹统计记录',
  `track_group_id` varchar(64) DEFAULT '' COMMENT '轨迹组名',
  `handle_name` varchar(32) DEFAULT '' COMMENT '开启/关闭人',
  `blood_oxygen` int(3) DEFAULT '-1' COMMENT '血氧值',
  `device_status` tinyint(1) DEFAULT '1' COMMENT '手表佩带情况，0不显示佩带情况，1佩戴中，2未佩戴，3充电中',
  `content` text COMMENT '内容',
  `device_status_duration` bigint(20) DEFAULT '0' COMMENT '佩带状态持续时长',
  `systolic_pressure` int(3) DEFAULT '-1' COMMENT '收缩压',
  `diastolic_pressure` int(3) DEFAULT '-1' COMMENT '舒张压',
  `position_status` text COMMENT '位置状态记录',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `temperature` tinyint(3) DEFAULT '-10' COMMENT '温度',
  `humidity` tinyint(3) DEFAULT '-1' COMMENT '湿度',
  `is_humiture_sensor` tinyint(3) DEFAULT '0' COMMENT '是否有温湿度传感器 0:没有 1:有',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `track_open_id` varchar(64) DEFAULT '' COMMENT '轨迹开启人id',
  `read_account` text COMMENT '实时守护记录用户已读未读标识',
  `is_show` tinyint(1) DEFAULT '1' COMMENT '记录是否显示，0不显示，1显示',
  `heart_rate_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示心率数据，1显示，0不显示',
  `blood_pressure_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血压数据，1显示，0不显示',
  `blood_oxygen_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示血氧数据，1显示，0不显示',
  `is_intact` tinyint(1) DEFAULT '0' COMMENT '当前数据是否完整，1完整，0,不完整',
  `device_status_is_show` tinyint(1) DEFAULT '1' COMMENT '是否显示佩戴状态 0不显示,1显示',
  `track_end_time` bigint(20) DEFAULT '0' COMMENT '轨迹统计记录结束时间',
  `is_sphygmomanometer` tinyint(1) DEFAULT '0' COMMENT '是否有血压计 0:没有 1:有',
  `is_exercise_measure` tinyint(1) DEFAULT '0' COMMENT '标识健康数据测量时的设备运动状态，1运动测，0静止测',
  `use_type` tinyint(1) DEFAULT '1' COMMENT '记录用途类型，1查找长者,2查找设备',
  `area_id` varchar(32) DEFAULT '' COMMENT '位置所属区域id，仅对信标位置有效',
  `uncalibrated_day_num` int(11) DEFAULT NULL COMMENT '血压计未校准天数',
  `is_applets_measure` tinyint(1) DEFAULT '0' COMMENT '是否小程序测量值 0:否1:是',
  `map_area_id` varchar(32) DEFAULT NULL COMMENT '位置所属区域地图id',
  `is_health_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `is_position_intact` tinyint(1) DEFAULT '0' COMMENT '当前健康数据是否完整，1完整，0,不完整',
  `body_temperature` varchar(10) DEFAULT '' COMMENT '体温',
  `body_temperature_is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示体温数据，1显示，0不显示',
  `position_mac` varchar(32) DEFAULT NULL COMMENT '信标位置的mac',
  `device_iteration_number` int(3) DEFAULT NULL COMMENT '设备迭代版本号',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `breath` int(3) DEFAULT '-1' COMMENT '呼吸值',
  `breath_is_show` tinyint(1) DEFAULT '0' COMMENT '呼吸数据是否显示（0-不显示，1-显示）',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `record_time` (`record_time`) USING BTREE,
  KEY `care_object_id` (`care_object_id`),
  KEY `track_group_id` (`track_group_id`),
  KEY `iot_device_id` (`iot_device_id`),
  KEY `idx_position_mac` (`position_mac`) USING BTREE,
  KEY `create_time` (`create_time`) USING BTREE,
  KEY `record_type` (`record_type`) USING BTREE,
  KEY `org_id_update` (`org_id`,`update_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='存储部分轨迹数据，提供给信息交互服务器查询使用(目前:13,23)';

-- ----------------------------
-- Table structure for lb_iot_product
-- ----------------------------
DROP TABLE IF EXISTS `lb_iot_product`;
CREATE TABLE `lb_iot_product` (
  `iot_product_id` varchar(32) NOT NULL COMMENT '主键',
  `device_type` mediumint(9) DEFAULT '0' COMMENT '设备类型',
  `device_model` varchar(32) DEFAULT '' COMMENT '设备型号',
  `factory_id` varchar(32) DEFAULT '' COMMENT '厂商id',
  `factory_name` varchar(32) DEFAULT NULL COMMENT '厂商名称',
  `protocol_type` varchar(32) DEFAULT '' COMMENT '协议类型',
  `device_photo` varchar(32) DEFAULT '' COMMENT '设备图片',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `feature_str` varchar(64) DEFAULT NULL COMMENT '特征串',
  `master_key` varchar(64) DEFAULT '' COMMENT '令牌',
  `protocol` tinyint(1) DEFAULT '0' COMMENT '通信协议,0mq,1tcp,2lwm',
  `electricity_mode` tinyint(1) DEFAULT '1' COMMENT '应用的电量模式 0:eDRX 1:DRX  2:PSM',
  `platform_type` tinyint(1) DEFAULT '1' COMMENT '平台类型，1电信aep，2移动onenet',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`iot_product_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='自定义产品';

-- ----------------------------
-- Table structure for lb_jpush_member_re
-- ----------------------------
DROP TABLE IF EXISTS `lb_jpush_member_re`;
CREATE TABLE `lb_jpush_member_re` (
  `jpush_member_id` varchar(32) NOT NULL COMMENT '主键',
  `tag` varchar(32) DEFAULT NULL COMMENT '推送标签',
  `registration_id` varchar(11) DEFAULT NULL COMMENT '注册主键',
  `member_id` varchar(11) DEFAULT NULL COMMENT '成员主键',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`jpush_member_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_jpush_msg
-- ----------------------------
DROP TABLE IF EXISTS `lb_jpush_msg`;
CREATE TABLE `lb_jpush_msg` (
  `jpush_msg_id` varchar(32) NOT NULL COMMENT '主键',
  `msg_id` bigint(32) DEFAULT NULL COMMENT '消息id',
  `registration_id` varchar(32) DEFAULT NULL COMMENT '注册主键',
  `msg_title` varchar(32) DEFAULT NULL COMMENT '标题',
  `msg_content` mediumtext COMMENT '内容',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_receive` tinyint(1) DEFAULT NULL COMMENT '是否已经收到，1是 0否',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`jpush_msg_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='推送消息';

-- ----------------------------
-- Table structure for lb_jpush_msg_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_jpush_msg_config`;
CREATE TABLE `lb_jpush_msg_config` (
  `msg_type` int(11) NOT NULL COMMENT '消息类型',
  `msg_category` varchar(8) NOT NULL DEFAULT '' COMMENT '消息类别',
  `badge` tinyint(1) NOT NULL DEFAULT '1' COMMENT '角标',
  `is_open` tinyint(1) NOT NULL DEFAULT '1' COMMENT '开启标识（0-关闭，1-开启）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `sound` varchar(16) NOT NULL DEFAULT 'default' COMMENT '铃声',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`msg_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='极光推送消息配置表';

-- ----------------------------
-- Table structure for lb_jpush_third_party_channel_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_jpush_third_party_channel_config`;
CREATE TABLE `lb_jpush_third_party_channel_config` (
  `app_type` tinyint(1) NOT NULL COMMENT '应用类型',
  `msg_category` varchar(8) NOT NULL DEFAULT '' COMMENT '消息类别',
  `third_party_type` varchar(8) NOT NULL COMMENT '第三方类型',
  `channel_config` varchar(64) NOT NULL COMMENT '通道配置',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`app_type`,`msg_category`,`third_party_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='极光推送第三方通道配置表';

-- ----------------------------
-- Table structure for lb_lease_bill
-- ----------------------------
DROP TABLE IF EXISTS `lb_lease_bill`;
CREATE TABLE `lb_lease_bill` (
  `lease_bill_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `lease_registration_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联租赁登记ID',
  `expense_id` varchar(32) NOT NULL DEFAULT '' COMMENT '费用主键',
  `expense_name` varchar(128) NOT NULL DEFAULT '' COMMENT '费用名称',
  `expense_category` varchar(32) NOT NULL DEFAULT '' COMMENT '费用类别',
  `expense_nature` tinyint(1) NOT NULL DEFAULT '1' COMMENT '费用性质',
  `total_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '消费金额',
  `paid_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已缴金额',
  `refund_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已退金额',
  `payment_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '缴费状态：0-未缴费, 1-已缴费, 2-部分缴费, 3-部分退缴',
  `bill_source` tinyint(1) NOT NULL DEFAULT '0' COMMENT '账单来源：0-租赁登记同步, 1-手工计费',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `consume_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费时间段-开始',
  `consume_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消费时间段-结束',
  `remarks` varchar(512) NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除, 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  PRIMARY KEY (`lease_bill_id`),
  KEY `idx_org_lease` (`org_id`,`lease_registration_id`),
  KEY `idx_payment_status` (`payment_status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='房屋租赁计费单表';

-- ----------------------------
-- Table structure for lb_lease_bill_pay_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_lease_bill_pay_record`;
CREATE TABLE `lb_lease_bill_pay_record` (
  `lease_bill_pay_record_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `lease_bill_id` bigint(20) NOT NULL COMMENT '关联计费单ID',
  `pay_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '缴费金额',
  `pay_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '缴费类型 1:缴费, 2:退缴',
  `pay_method` int(3) NOT NULL DEFAULT '0' COMMENT '缴费方式,1微信，2支付宝，3银行卡，4现金，5一卡通',
  `pay_name` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费名称',
  `pay_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '缴费时间',
  `payer_name` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费人',
  `registrant_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作员',
  `card_num` varchar(64) DEFAULT '' COMMENT '一卡通卡号',
  `remarks` varchar(512) NOT NULL DEFAULT '' COMMENT '缴费备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除, 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  PRIMARY KEY (`lease_bill_pay_record_id`),
  KEY `idx_bill_id` (`lease_bill_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='房屋租赁缴费流水表';

-- ----------------------------
-- Table structure for lb_lease_registration
-- ----------------------------
DROP TABLE IF EXISTS `lb_lease_registration`;
CREATE TABLE `lb_lease_registration` (
  `lease_registration_id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间号ID',
  `lease_years` int(11) NOT NULL COMMENT '租赁年限 (1-50年)',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '租赁开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '租赁结束时间',
  `annual_rent` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '年租金',
  `total_rent` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '总租金',
  `owner_name` varchar(128) NOT NULL DEFAULT '' COMMENT '户主姓名',
  `owner_phone` varchar(20) NOT NULL DEFAULT '' COMMENT '户主手机号码',
  `salesman` varchar(32) NOT NULL DEFAULT '' COMMENT '销售员',
  `generate_bill` tinyint(1) NOT NULL DEFAULT '0' COMMENT '计费生成状态 (0:未生成, 1:已生成)',
  `payment_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '缴费状态 (0:未缴费, 1:已缴费, 2:部分缴费, 3:部分退缴)',
  `attachment_ids` varchar(300) NOT NULL DEFAULT '' COMMENT '上传附件id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除, 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  PRIMARY KEY (`lease_registration_id`),
  KEY `idx_org_id` (`org_id`),
  KEY `idx_room_search` (`org_id`,`area_id`),
  KEY `idx_owner_phone` (`owner_phone`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='租赁登记表';

-- ----------------------------
-- Table structure for lb_load_table
-- ----------------------------
DROP TABLE IF EXISTS `lb_load_table`;
CREATE TABLE `lb_load_table` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `table_name` varchar(32) NOT NULL DEFAULT '' COMMENT '表名',
  `date` varchar(32) NOT NULL DEFAULT '' COMMENT '保存天数',
  `date_time` date NOT NULL DEFAULT '0000-00-00' COMMENT '创建时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_location_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_location_record`;
CREATE TABLE `lb_location_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '看护对象',
  `care_object_name` varchar(32) DEFAULT '' COMMENT '看护对象名字',
  `position_desc` varchar(32) DEFAULT '' COMMENT '房间类型:机构房间/家庭房间',
  `lgt` varchar(32) DEFAULT '' COMMENT '经度',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `record_time` bigint(20) DEFAULT '0' COMMENT '时间',
  `is_outdoor` tinyint(4) DEFAULT '0' COMMENT '室内/室外',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='位置记录';

-- ----------------------------
-- Table structure for lb_log_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_log_record`;
CREATE TABLE `lb_log_record` (
  `log_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `software_type` int(11) DEFAULT NULL COMMENT '软件类型',
  `device_system_type` varchar(32) DEFAULT '' COMMENT '设备型号',
  `device_system_num` varchar(32) DEFAULT '' COMMENT '设备系统版本号',
  `app_version` varchar(64) DEFAULT NULL COMMENT 'app版本号',
  `account_name` varchar(128) DEFAULT '' COMMENT '用户名',
  `phone_num` varchar(64) DEFAULT '' COMMENT '登录手机号',
  `file_path` varchar(255) DEFAULT NULL COMMENT '日志地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `log_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '日志类型，1app业务日志，2app广播日志',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`log_record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='上传日志记录表';

-- ----------------------------
-- Table structure for lb_logistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_logistics`;
CREATE TABLE `lb_logistics` (
  `logistics_id` varchar(32) NOT NULL,
  `goods_order_id` varchar(32) NOT NULL COMMENT '订单',
  `logistics_company_id` varchar(32) DEFAULT NULL COMMENT '物流公司',
  `logistics_num` varchar(32) NOT NULL DEFAULT '' COMMENT '快递单号',
  `courier_name` varchar(32) DEFAULT '' COMMENT '快递员姓名',
  `phone_num` varchar(11) DEFAULT '' COMMENT '联系电话',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '快递状态(0:快递中,1:待签收,2:未签收,3:已签收)',
  `delivery_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '发货时间',
  `receiving_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '收货时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`logistics_id`),
  KEY `goods_order_id` (`goods_order_id`) USING BTREE,
  KEY `logistics_company_id` (`logistics_company_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物流表';

-- ----------------------------
-- Table structure for lb_logistics_company
-- ----------------------------
DROP TABLE IF EXISTS `lb_logistics_company`;
CREATE TABLE `lb_logistics_company` (
  `logistics_company_id` varchar(32) NOT NULL COMMENT '主键',
  `company_name` varchar(32) NOT NULL COMMENT '公司名称',
  `contacts_name` varchar(32) NOT NULL COMMENT '联系人姓名',
  `phone_num` varchar(11) NOT NULL COMMENT '联系电话',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`logistics_company_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='物流公司表';

-- ----------------------------
-- Table structure for lb_mainframe
-- ----------------------------
DROP TABLE IF EXISTS `lb_mainframe`;
CREATE TABLE `lb_mainframe` (
  `mainframe_id` varchar(32) NOT NULL COMMENT '主键',
  `num` varchar(32) DEFAULT '' COMMENT '主机号',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `description` varchar(128) DEFAULT '' COMMENT '叙述',
  `type` varchar(32) DEFAULT '' COMMENT '弃用',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `sn` varchar(100) DEFAULT NULL COMMENT '序列号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mainframe_id`),
  KEY `orgid_num` (`org_id`,`num`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_mainframe_area_re
-- ----------------------------
DROP TABLE IF EXISTS `lb_mainframe_area_re`;
CREATE TABLE `lb_mainframe_area_re` (
  `mainframe_area_re_id` varchar(32) NOT NULL COMMENT '主键',
  `mainframe_id` varchar(32) DEFAULT '' COMMENT '主机主键',
  `area_id` varchar(32) DEFAULT '' COMMENT '区域主键',
  `alarm_num` varchar(32) DEFAULT '' COMMENT '序号（弃用）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_mac` varchar(32) DEFAULT '' COMMENT '设备mac',
  `device_imei` varchar(32) DEFAULT '' COMMENT '设备的imei号',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `slave_num` int(10) DEFAULT '0' COMMENT '分机号',
  `device_type` int(3) DEFAULT '0' COMMENT '设备类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mainframe_area_re_id`),
  KEY `area_id` (`area_id`,`mainframe_id`) USING BTREE,
  KEY `device_mac` (`device_mac`),
  KEY `mainframe_id` (`mainframe_id`) USING BTREE,
  KEY `idx_device_imei` (`device_imei`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_mainframe_extension
-- ----------------------------
DROP TABLE IF EXISTS `lb_mainframe_extension`;
CREATE TABLE `lb_mainframe_extension` (
  `extension_id` varchar(32) NOT NULL COMMENT '主键',
  `extension_num` varchar(32) DEFAULT '' COMMENT '分机号',
  `mainframe_num` varchar(32) DEFAULT '' COMMENT '主机号',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `description` varchar(32) DEFAULT '' COMMENT '叙述',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `sn` varchar(100) DEFAULT NULL COMMENT '序列号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`extension_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='云分机表';

-- ----------------------------
-- Table structure for lb_mainframe_sn
-- ----------------------------
DROP TABLE IF EXISTS `lb_mainframe_sn`;
CREATE TABLE `lb_mainframe_sn` (
  `mainframe_sn_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `mainframe_number` int(10) NOT NULL COMMENT '主机号码',
  `sn` varchar(32) DEFAULT NULL COMMENT '序列号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最后操作时间',
  `is_delete` tinyint(1) DEFAULT NULL COMMENT '是否删除',
  `mainframe_version` varchar(32) DEFAULT NULL COMMENT '主机版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mainframe_sn_id`) USING BTREE,
  KEY `lb_mainframe_sn_org_id_IDX` (`org_id`,`mainframe_number`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='主机号绑定序列号关系';

-- ----------------------------
-- Table structure for lb_mainframe_subsidiary
-- ----------------------------
DROP TABLE IF EXISTS `lb_mainframe_subsidiary`;
CREATE TABLE `lb_mainframe_subsidiary` (
  `mainframe_subsidiary_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `delay_time` int(4) DEFAULT '0' COMMENT '延迟秒数',
  `subsidiary_num` varchar(255) DEFAULT '' COMMENT '附加主机号 ，隔开',
  `subsidiary_time` varchar(255) DEFAULT NULL COMMENT '禁止上传时间段，多段时间 ，隔开',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '最后操作时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `mainframe_num` varchar(32) DEFAULT NULL COMMENT '主机号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mainframe_subsidiary_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='主机附加关系及信息';

-- ----------------------------
-- Table structure for lb_master_control_box
-- ----------------------------
DROP TABLE IF EXISTS `lb_master_control_box`;
CREATE TABLE `lb_master_control_box` (
  `master_control_box_id` varchar(64) NOT NULL COMMENT '主键',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `num` int(11) DEFAULT '0' COMMENT 'num',
  `position_desc` varchar(32) DEFAULT '' COMMENT '位置叙述',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '设备id（电信云平台注册返回）',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(3) DEFAULT '2' COMMENT '1:在线 2:离线',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '删除状态,０:未删除,１：删除中,２：删除失败',
  `device_delete_time` bigint(20) DEFAULT '0' COMMENT '主控盒设备计划删除时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`master_control_box_id`),
  KEY `mac` (`mac`) USING BTREE,
  KEY `orgId` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='主控制盒';

-- ----------------------------
-- Table structure for lb_mattress
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress`;
CREATE TABLE `lb_mattress` (
  `mattress_id` varchar(32) NOT NULL COMMENT '主键',
  `device_type` tinyint(3) DEFAULT '101' COMMENT '101-wifi床垫 103-wifi床带 104-4g床垫 111-蓝牙床垫',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间id',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '床位id',
  `device_name` varchar(20) NOT NULL COMMENT '设备名称',
  `device_channel` varchar(10) DEFAULT '56963' COMMENT '设备渠道',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `status` tinyint(1) DEFAULT '0' COMMENT '1:在线 0:离线',
  `hardware_version` varchar(32) DEFAULT '2.25' COMMENT '硬件版本号',
  `building_id` varchar(32) DEFAULT '' COMMENT '楼栋',
  `floor_id` varchar(32) DEFAULT '' COMMENT '楼层',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置叙述',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `last_update_time` bigint(20) DEFAULT '0' COMMENT '上次更新时间',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id',
  `scene` tinyint(1) DEFAULT '0' COMMENT '场景 0:机构 1-社区(机构) 2-社区(居家) 3-子女app',
  `wifi` varchar(64) NOT NULL DEFAULT '' COMMENT '床垫配网wifi',
  `connect_server` varchar(32) NOT NULL DEFAULT '' COMMENT '床垫连接服务器',
  `install_config` mediumtext COMMENT '床垫安装配置',
  `iccid` varchar(32) DEFAULT '' COMMENT 'iccid号',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei号',
  `plaintext_id` varchar(32) DEFAULT '' COMMENT '明文id',
  `bind_id` varchar(255) NOT NULL DEFAULT '' COMMENT '床垫关联绑定id（用于报告查询）',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mattress_id`),
  KEY `areaId` (`area_id`) USING BTREE,
  KEY `careObjectId` (`care_object_id`),
  KEY `bedId` (`bed_id`),
  KEY `deviceType` (`device_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='智能床垫';

-- ----------------------------
-- Table structure for lb_mattress_cluster_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_cluster_config`;
CREATE TABLE `lb_mattress_cluster_config` (
  `id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `cluster_config` mediumtext COMMENT '床垫集群配置{"ip":["192.168.12.154","192.198.12.154"],"isOpen":1}',
  `weight` varchar(32) NOT NULL DEFAULT '' COMMENT '权重（轮询分配使用）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='床垫集群配置表';

-- ----------------------------
-- Table structure for lb_mattress_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_config`;
CREATE TABLE `lb_mattress_config` (
  `id` varchar(32) NOT NULL COMMENT '主键ID',
  `device_id` varchar(255) NOT NULL DEFAULT '' COMMENT '床垫设备id',
  `device_type` tinyint(1) DEFAULT '101' COMMENT '101:享睡 102:谷奇创新',
  `hrate_abnormal_alarm` mediumtext COMMENT '心率异常报警',
  `breath_abnormal_alarm` mediumtext COMMENT '呼吸异常报警',
  `breath_pause_alarm` mediumtext COMMENT '呼吸暂停报警',
  `obed_alnomal_alarm` mediumtext COMMENT '离床超时报警',
  `turnover_reminder` mediumtext COMMENT '翻身提醒',
  `bodyfrequent_reminder` mediumtext COMMENT '频繁体动提醒',
  `inbed_reminder` mediumtext COMMENT '上床提醒',
  `obed_reminder` mediumtext COMMENT '离床提醒',
  `install_env_setting` mediumtext COMMENT '床垫安装环境设置',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `scene` tinyint(1) NOT NULL DEFAULT '0' COMMENT '场景 0:机构 1-社区(机构) 2-社区(居家) 3-子女app',
  `is_custom` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否为自定义配置 0-统一配置 1-自定义配置',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='床垫配置表';

-- ----------------------------
-- Table structure for lb_mattress_device_yy
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_device_yy`;
CREATE TABLE `lb_mattress_device_yy` (
  `mattress_device_id` varchar(32) NOT NULL COMMENT '设备内部唯一ID',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT ' 设备序列号',
  `bed_id` varchar(32) DEFAULT '' COMMENT ' 设备床位号  bed_id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT ' 设备所属机构ID',
  `remote_device_id` varchar(32) NOT NULL DEFAULT '' COMMENT ' 跃杨平台中设备id',
  `remote_user_id` varchar(32) NOT NULL DEFAULT '' COMMENT ' 跃杨平台中用户id',
  `create_time` bigint(32) NOT NULL DEFAULT '0' COMMENT '记录创建时间 ',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `guardian_id` varchar(64) DEFAULT '',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mattress_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='跃杨床垫-床位绑定关系表';

-- ----------------------------
-- Table structure for lb_mattress_docking_config_yy
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_docking_config_yy`;
CREATE TABLE `lb_mattress_docking_config_yy` (
  `config_id` varchar(32) NOT NULL COMMENT '对接设置id',
  `docking_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '对接状态 1开启 0 关闭',
  `service_access_address` varchar(64) NOT NULL DEFAULT '' COMMENT '床垫服务访问地址',
  `docking_username` varchar(32) NOT NULL DEFAULT '' COMMENT '对接账号',
  `docking_password` varchar(32) NOT NULL DEFAULT '' COMMENT '对接密码',
  `data_sync_cycle` bigint(20) NOT NULL DEFAULT '180000' COMMENT '数据同步周期 默认三分钟，可选5分钟，10分钟，30分钟，1小时，6小时 (毫秒)',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `guardian_id` varchar(64) DEFAULT '',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='跃杨床垫对接设置表';

-- ----------------------------
-- Table structure for lb_mattress_forward
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_forward`;
CREATE TABLE `lb_mattress_forward` (
  `id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'orgId',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '床垫id',
  `forward_ip` varchar(16) NOT NULL DEFAULT '' COMMENT '转发服务器IP',
  `forward_port` varchar(10) NOT NULL DEFAULT '' COMMENT '转发服务器端口',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='机构内网床垫转发表';

-- ----------------------------
-- Table structure for lb_mattress_secret
-- ----------------------------
DROP TABLE IF EXISTS `lb_mattress_secret`;
CREATE TABLE `lb_mattress_secret` (
  `device_name` varchar(32) NOT NULL COMMENT '床垫名称',
  `device_secret` varchar(32) NOT NULL COMMENT '床垫密文',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_type` tinyint(3) NOT NULL DEFAULT '101' COMMENT '101:享睡 102:谷奇创新',
  `account_id` varchar(32) DEFAULT '' COMMENT '用户id',
  `account_name` varchar(32) DEFAULT '' COMMENT '用户姓名',
  `account_type` tinyint(1) DEFAULT '0' COMMENT '用户类型:0长者，1员工',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_name`),
  UNIQUE KEY `device_name_unique` (`device_name`) USING BTREE COMMENT '床垫名称唯一索引',
  UNIQUE KEY `device_secret_unique` (`device_secret`) USING BTREE COMMENT '床垫密文唯一索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='床垫-密文关联表';

-- ----------------------------
-- Table structure for lb_meal_subsidy
-- ----------------------------
DROP TABLE IF EXISTS `lb_meal_subsidy`;
CREATE TABLE `lb_meal_subsidy` (
  `meal_subsidy_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `setting_id` varchar(32) NOT NULL DEFAULT '' COMMENT '补贴设置主键',
  `business_hours_id` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次营业时间主键',
  `subsidy_rate_amount` decimal(8,1) NOT NULL DEFAULT '0.0' COMMENT '折扣率或补贴金额',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `subsidy_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '补贴方式 1 折扣补贴 2 减免补贴',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`meal_subsidy_id`),
  KEY `setting_id_IDX` (`setting_id`) USING BTREE,
  KEY `hours_id_IDX` (`business_hours_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='餐次补贴表';

-- ----------------------------
-- Table structure for lb_meals_business_hours
-- ----------------------------
DROP TABLE IF EXISTS `lb_meals_business_hours`;
CREATE TABLE `lb_meals_business_hours` (
  `business_hours_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `level` tinyint(1) NOT NULL DEFAULT '1' COMMENT '等级 1 民政监管 2 助餐点',
  `food_shop_id` varchar(32) NOT NULL DEFAULT '' COMMENT '助餐点id',
  `meals` varchar(32) NOT NULL DEFAULT '' COMMENT '餐次',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `parent_id` varchar(32) NOT NULL DEFAULT '' COMMENT '助餐点的父级餐次时间id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_use` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否使用 0 否 1 是',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`business_hours_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `food_shop_id_IDX` (`food_shop_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='助餐点餐次营业时间设置';

-- ----------------------------
-- Table structure for lb_mobile_wifi
-- ----------------------------
DROP TABLE IF EXISTS `lb_mobile_wifi`;
CREATE TABLE `lb_mobile_wifi` (
  `wifi_mac` varchar(32) NOT NULL COMMENT 'wifi地址',
  `content` varchar(64) NOT NULL DEFAULT '' COMMENT 'wifi说明',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`wifi_mac`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='移动WIFI记录表';

-- ----------------------------
-- Table structure for lb_mq_fail
-- ----------------------------
DROP TABLE IF EXISTS `lb_mq_fail`;
CREATE TABLE `lb_mq_fail` (
  `mq_fail_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `type` tinyint(3) DEFAULT '1' COMMENT '类型,1:位置信息',
  `msg` text COMMENT '消息内容',
  `status` tinyint(3) DEFAULT '1' COMMENT '状态,1:失败未补发,2:已经补发',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`mq_fail_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='MQTT失败记录表';

-- ----------------------------
-- Table structure for lb_msg_read_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_msg_read_record`;
CREATE TABLE `lb_msg_read_record` (
  `account_id` varchar(64) NOT NULL COMMENT '用户标识',
  `msg_id` varchar(64) NOT NULL DEFAULT '' COMMENT '消息标识',
  `msg_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '消息时间',
  `read_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '已读时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='消息已读记录表';

-- ----------------------------
-- Table structure for lb_nb_api_result
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_api_result`;
CREATE TABLE `lb_nb_api_result` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `app_id` varchar(32) DEFAULT NULL COMMENT '应用id',
  `action_type` tinyint(1) DEFAULT NULL COMMENT '事件类型',
  `result` mediumtext COMMENT '结果',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `command_data` mediumtext COMMENT '命令内容',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `lb_nb_api_result_iot_device_id_IDX` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='电信应用api调用记录表';

-- ----------------------------
-- Table structure for lb_nb_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_config`;
CREATE TABLE `lb_nb_config` (
  `id` int(11) NOT NULL COMMENT '主键',
  `device_id` varchar(64) DEFAULT NULL COMMENT '设备主键',
  `expire_time` int(11) DEFAULT NULL COMMENT '缓存下发时间 单位秒，设置0时，实际为48小时',
  `delay_time` int(11) DEFAULT NULL COMMENT '延迟下发时间 单位秒',
  `retransmit` int(11) DEFAULT '1' COMMENT '命令下发次数，默认1',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_nb_data
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_data`;
CREATE TABLE `lb_nb_data` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `msg_type` varchar(255) DEFAULT '' COMMENT '上报/下发',
  `device_id` varchar(64) DEFAULT '' COMMENT '设备id',
  `data_base64` mediumtext COMMENT '数据编码值',
  `data_binary` mediumtext COMMENT '数据十六进制值',
  `data_binary_decrypt` mediumtext COMMENT '报文解密后的数据',
  `crc_origin` int(11) DEFAULT '0' COMMENT '循环校验码十进制值',
  `crc_calculate` int(11) DEFAULT '0' COMMENT 'crc本地计算值',
  `is_data_error` varchar(255) DEFAULT '' COMMENT '正确/错误',
  `create_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '生成时间',
  `update_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '更新时间',
  `receive_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '接收时间',
  `last_china_telecom_response_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '电信上次的响应时间',
  `last_lb_server_response_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '服务器最近的响应时间',
  `command_id` varchar(64) DEFAULT '' COMMENT '电信接口创建的命令主键',
  `command_type` varchar(32) DEFAULT '' COMMENT '数据区自定义消息类型',
  `command_mid` varchar(11) DEFAULT '' COMMENT '命令消息条数编号',
  `status` tinyint(1) unsigned DEFAULT '0' COMMENT '0已下发，1执行成功，2执行失败，3超时',
  `event_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '事件时间',
  `is_repeat` tinyint(1) DEFAULT '0' COMMENT '0不重复，1重复记录',
  `fail_reason` varchar(5) DEFAULT NULL COMMENT 'NB命令执行失败的原因',
  `send_times` tinyint(1) DEFAULT '1' COMMENT '命令下发的次数',
  `device_type` mediumint(9) DEFAULT '0' COMMENT '设备类型，参见字典表',
  `report_time_hex` varchar(32) DEFAULT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `device_id` (`device_id`) USING BTREE,
  KEY `command_id` (`command_id`) USING BTREE,
  KEY `command_type` (`command_type`) USING BTREE,
  KEY `device_type` (`device_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_nb_data_infusions
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_data_infusions`;
CREATE TABLE `lb_nb_data_infusions` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `msg_type` varchar(255) DEFAULT '' COMMENT '上报/下发',
  `device_id` varchar(64) DEFAULT '' COMMENT 'device_id',
  `data_base64` mediumtext COMMENT '数据编码值',
  `data_binary` mediumtext COMMENT '数据十六进制值',
  `crc_origin` int(11) DEFAULT '0' COMMENT '循环校验码十进制值',
  `crc_calculate` int(11) DEFAULT '0' COMMENT 'crc本地计算值',
  `is_data_error` varchar(255) DEFAULT '' COMMENT '正确/错误',
  `create_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '生成时间',
  `last_china_telecom_response_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '电信上次的响应时间',
  `last_lb_server_response_time` datetime DEFAULT '0000-00-00 00:00:00' COMMENT '服务器最近的响应时间',
  `command_id` varchar(64) DEFAULT '' COMMENT '电信接口创建的命令主键',
  `command_type` varchar(11) DEFAULT '' COMMENT '数据区自定义消息类型',
  `command_mid` varchar(11) DEFAULT '' COMMENT '命令消息条数编号',
  `status` tinyint(1) DEFAULT '0' COMMENT '0已下发，1执行成功，2执行失败',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_nb_data_private
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_data_private`;
CREATE TABLE `lb_nb_data_private` (
  `id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(64) DEFAULT NULL COMMENT '机构id',
  `message` text COMMENT '消息内容',
  `is_receive` tinyint(4) DEFAULT '0' COMMENT '是否已接收',
  `send_time` bigint(20) DEFAULT NULL COMMENT '发送时间',
  `receive_time` bigint(20) DEFAULT '0' COMMENT '接收时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `message_type` varchar(100) DEFAULT NULL COMMENT '消息类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='私有化服务nb数据异常接收记录';

-- ----------------------------
-- Table structure for lb_nb_hardware_version
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_hardware_version`;
CREATE TABLE `lb_nb_hardware_version` (
  `nb_hardware_version_id` varchar(32) NOT NULL COMMENT '主键ID',
  `hardware_version` varchar(32) NOT NULL DEFAULT '' COMMENT '硬件版本号',
  `support_function` varchar(64) NOT NULL DEFAULT '' COMMENT '版本支持功能',
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '版本所属设备类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`nb_hardware_version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='NB设备硬件版本信息表';

-- ----------------------------
-- Table structure for lb_nb_test_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_nb_test_config`;
CREATE TABLE `lb_nb_test_config` (
  `id` int(11) NOT NULL COMMENT '主键',
  `type` varchar(255) DEFAULT NULL COMMENT '类型',
  `expireTime` int(11) DEFAULT NULL COMMENT '过期时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_nbdata_export_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_nbdata_export_task`;
CREATE TABLE `lb_nbdata_export_task` (
  `task_id` varchar(32) NOT NULL DEFAULT '' COMMENT '任务id',
  `device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设备电信id',
  `task_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '任务状态 0: 待处理1: 导出中2: 已完成3: 失败',
  `deal_start_time` bigint(20) DEFAULT '0' COMMENT '任务处理开始时间',
  `deal_end_time` bigint(20) DEFAULT '0' COMMENT '任务处理结束时间',
  `export_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '导出时间段-开始',
  `export_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '导出时间段-结束',
  `path` varchar(255) DEFAULT '' COMMENT '文件地址',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) DEFAULT '0',
  `result` varchar(255) DEFAULT '' COMMENT '任务处理结果',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_night_toilet_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_night_toilet_report`;
CREATE TABLE `lb_night_toilet_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '夜尿次数',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '夜尿时长',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='夜尿报表';

-- ----------------------------
-- Table structure for lb_notice
-- ----------------------------
DROP TABLE IF EXISTS `lb_notice`;
CREATE TABLE `lb_notice` (
  `notice_id` varchar(32) NOT NULL COMMENT '主键',
  `title` varchar(255) NOT NULL DEFAULT '' COMMENT '标题',
  `content` longtext COMMENT '内容',
  `system_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '系统类型',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `publisher` varchar(32) NOT NULL DEFAULT '' COMMENT '发布人',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 删除',
  `brief_introduction` text NOT NULL COMMENT '简介',
  `publish_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '发布时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1 已发布 2 待发布',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`notice_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='通知表';

-- ----------------------------
-- Table structure for lb_number
-- ----------------------------
DROP TABLE IF EXISTS `lb_number`;
CREATE TABLE `lb_number` (
  `num` smallint(6) NOT NULL COMMENT '主键',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`num`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='数字表（业务查询使用，不得擅自增删改）';

-- ----------------------------
-- Table structure for lb_nurse_app_indicators_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_nurse_app_indicators_record`;
CREATE TABLE `lb_nurse_app_indicators_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '看护对象',
  `care_object_name` varchar(128) DEFAULT NULL COMMENT '老人名字',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `indicator_type` varchar(64) NOT NULL DEFAULT '' COMMENT '指标类型 体温(bodyTemperature) 餐前血糖(bloodSugarBefore)  餐后血糖（bloodSugarAfter）呼吸(breathe)',
  `fact_a` varchar(750) DEFAULT '0' COMMENT '指标值(餐前血糖体温呼吸)',
  `fact_b` varchar(32) DEFAULT '0' COMMENT '指标值(餐后血糖)',
  `is_normal` tinyint(1) DEFAULT '1' COMMENT '数据是否正常，1正常，0异常',
  `is_automatic` tinyint(1) DEFAULT '1' COMMENT '是否为自动测量，1自动测量，0手动测量',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1 日常，2 轨迹，3 指标测量 ）',
  `register_id` varchar(32) DEFAULT NULL,
  `register_name` varchar(32) DEFAULT NULL,
  `relation_id` text COMMENT '关联管家工作站服务记录ids',
  `monitor_type` varchar(32) NOT NULL DEFAULT '' COMMENT '血糖监测类型（1：空腹；2：早餐后；3：午餐前；4：午餐后；5：晚餐前；6：晚餐后；7：睡前；8：凌晨；9：随机）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='护士APP上报指标记录(体温\\血糖\\呼吸)';

-- ----------------------------
-- Table structure for lb_nurse_recode
-- ----------------------------
DROP TABLE IF EXISTS `lb_nurse_recode`;
CREATE TABLE `lb_nurse_recode` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `staff_id` varchar(32) DEFAULT '' COMMENT '责任护士id',
  `temperature` varchar(32) DEFAULT '' COMMENT '体温(health_record_id)',
  `heartRate` varchar(32) DEFAULT '' COMMENT '心率(health_record_id)',
  `breatheRate` varchar(32) DEFAULT '' COMMENT '呼吸(health_record_id)',
  `bloodOxygen` varchar(32) DEFAULT '' COMMENT '血氧饱和度(health_record_id)',
  `bloodPressure` varchar(32) DEFAULT '' COMMENT '血压(收缩压)(health_record_id)',
  `lowPressure` varchar(32) DEFAULT '' COMMENT '血压(舒张压)(health_record_id)',
  `pupil_left` varchar(16) DEFAULT '' COMMENT '瞳孔大小(值 左)',
  `pupil_right` varchar(16) DEFAULT '' COMMENT '瞳孔大小(值 右)',
  `insulin` varchar(16) DEFAULT '' COMMENT '胰岛素(值)',
  `blood_sugar` varchar(16) NOT NULL DEFAULT '' COMMENT '血糖',
  `monitor_type` varchar(16) NOT NULL DEFAULT '' COMMENT '血糖监测类型',
  `pupil_reflex_left` varchar(16) DEFAULT '' COMMENT '瞳孔对光反射(值  左 )',
  `pupil_reflex_right` varchar(16) DEFAULT '' COMMENT '瞳孔对光反射(值  右 )',
  `pulse` varchar(32) NOT NULL DEFAULT '' COMMENT '脉搏',
  `desc` text COMMENT '观察与描述',
  `bowel_move_number_shape` text NOT NULL COMMENT '二便次数及形状',
  `record_time` bigint(20) DEFAULT '0' COMMENT '观察记录时间',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `frequency_of_urination` varchar(32) NOT NULL DEFAULT '' COMMENT '小便次数',
  `frequency_of_stool_movements` varchar(32) NOT NULL DEFAULT '' COMMENT '大便次数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_id_index` (`care_object_id`),
  KEY `org_id_index` (`org_id`),
  KEY `record_time_index` (`record_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_nursing_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_nursing_care_object`;
CREATE TABLE `lb_nursing_care_object` (
  `nursing_care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `nursing_name` varchar(32) DEFAULT NULL COMMENT '护士姓名',
  `nursing_worker_id` varchar(32) DEFAULT '' COMMENT 'nursing_worker_id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT 'care_object_id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `nursing_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '护理人员类型；0-护士、1护理员',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`nursing_care_object_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `nursing_worker_id` (`nursing_worker_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_nursing_worker
-- ----------------------------
DROP TABLE IF EXISTS `lb_nursing_worker`;
CREATE TABLE `lb_nursing_worker` (
  `nursing_worker_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构',
  `name` varchar(32) DEFAULT '' COMMENT '名字',
  `description` varchar(32) DEFAULT '' COMMENT '描述',
  `gender` varchar(32) DEFAULT '' COMMENT '性别',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `photo` varchar(128) DEFAULT '' COMMENT '照片',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `entry_time` bigint(20) DEFAULT '0' COMMENT '入职时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '状态',
  `phone_num` varchar(11) DEFAULT '' COMMENT '电话号码',
  `dimission_time` bigint(20) DEFAULT '0' COMMENT '离职时间',
  `code` varchar(32) DEFAULT '' COMMENT '护工编号',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`nursing_worker_id`),
  KEY `lb_nursing_worker_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='护工';

-- ----------------------------
-- Table structure for lb_onenet_physical_model_mapping
-- ----------------------------
DROP TABLE IF EXISTS `lb_onenet_physical_model_mapping`;
CREATE TABLE `lb_onenet_physical_model_mapping` (
  `id` varchar(16) NOT NULL DEFAULT '',
  `pre_id` varchar(16) NOT NULL DEFAULT '' COMMENT '上一级id',
  `protocol_type` varchar(4) NOT NULL DEFAULT '' COMMENT '协议类型(64,66,...)',
  `layer` tinyint(4) NOT NULL DEFAULT '0' COMMENT '层级',
  `report_device_type` tinyint(4) NOT NULL DEFAULT '-1',
  `param` varchar(32) NOT NULL DEFAULT '' COMMENT '物模型标识符',
  `param_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '物模型标识符数据类型(0:int, 1:string, 2:object, 3:boolean, 4:array)',
  `param_order` tinyint(4) NOT NULL DEFAULT '0' COMMENT '参数顺序',
  `is_head` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否是协议头(0:否  1:是)',
  `is_open` tinyint(4) NOT NULL DEFAULT '1' COMMENT '是否开放(0:关闭 1:开放)',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='oneNET物模型映射';

-- ----------------------------
-- Table structure for lb_operation_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_operation_log`;
CREATE TABLE `lb_operation_log` (
  `id` varchar(64) NOT NULL DEFAULT '' COMMENT '操作日志主键',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户主键',
  `account_type` tinyint(1) DEFAULT '0' COMMENT '用户类型',
  `org_id` varchar(64) DEFAULT '' COMMENT '账号所属机构',
  `operation` varchar(64) NOT NULL DEFAULT '' COMMENT '操作内容',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `login_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登录时间',
  `username` varchar(128) DEFAULT NULL COMMENT '用户名',
  `display_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `module` varchar(128) NOT NULL DEFAULT '' COMMENT '操作模块',
  `operate_type` tinyint(1) DEFAULT NULL COMMENT '操作类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='操作日志';

-- ----------------------------
-- Table structure for lb_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_order`;
CREATE TABLE `lb_order` (
  `order_id` varchar(32) NOT NULL COMMENT '主键',
  `username` varchar(32) DEFAULT '' COMMENT '用户',
  `pay_account_id` varchar(64) DEFAULT '' COMMENT '支付用户id',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `description` varchar(32) DEFAULT '' COMMENT '叙述',
  `amount` double DEFAULT '0' COMMENT '金额',
  `pay_way` tinyint(1) DEFAULT '2' COMMENT '1:支付宝 2:微信 3:增加时间 4:初始赠送 5:ios',
  `pay_time` bigint(20) DEFAULT '0' COMMENT '付款时间',
  `order_status` tinyint(1) DEFAULT '1' COMMENT '1:待支付 2:已支付',
  `detail_id` varchar(32) DEFAULT '' COMMENT 'detail_id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `expire_time` bigint(20) DEFAULT '0' COMMENT '到期时间',
  `order_type` tinyint(1) DEFAULT '1' COMMENT '1:缴费1个月 3:缴费3个月 6:缴费6个月 12:缴费12个月',
  `family_id` varchar(64) DEFAULT '' COMMENT '家庭主键',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构主键',
  `pay_username` varchar(32) DEFAULT '' COMMENT '付款人',
  `user_type` char(1) DEFAULT '' COMMENT '1.app 2.终端',
  `sandbox` char(1) DEFAULT '0' COMMENT '0:正式环境 1:沙箱环境',
  `pay_jpush_record_id` varchar(64) DEFAULT '' COMMENT '支付通知记录id',
  `receipt_data` text COMMENT '凭证',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_id`),
  KEY `account_id` (`account_id`),
  KEY `detail_id` (`detail_id`),
  KEY `pay_account_id` (`pay_account_id`),
  KEY `lb_order_create_time_IDX` (`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_order_care_object
-- ----------------------------
DROP TABLE IF EXISTS `lb_order_care_object`;
CREATE TABLE `lb_order_care_object` (
  `order_care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `pay_account_id` varchar(64) DEFAULT '' COMMENT '支付用户id',
  `care_object_id` varchar(64) DEFAULT '' COMMENT '长者id',
  `description` varchar(32) DEFAULT '' COMMENT '叙述',
  `amount` double DEFAULT '0' COMMENT '金额',
  `pay_way` tinyint(1) DEFAULT '2' COMMENT '1:支付宝 2:微信 3:增加时间 4:初始赠送 5:ios 7:公众号支付',
  `pay_time` bigint(20) DEFAULT '0' COMMENT '付款时间',
  `order_status` tinyint(1) DEFAULT '1' COMMENT '1:待支付 2:已支付',
  `detail_id` varchar(32) DEFAULT '' COMMENT 'detail_id',
  `order_type` tinyint(1) DEFAULT '1' COMMENT '1:缴费1个月 3:缴费3个月 6:缴费6个月 12:缴费12个月',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构主键',
  `user_type` char(1) DEFAULT '' COMMENT '1.app ',
  `sandbox` char(1) DEFAULT '0' COMMENT '0:正式环境 1:沙箱环境',
  `pay_jpush_record_id` varchar(64) DEFAULT '' COMMENT '支付通知记录id',
  `receipt_data` text COMMENT '凭证',
  `identity` varchar(32) DEFAULT '' COMMENT '注释身份证',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `expire_time` bigint(20) DEFAULT '0' COMMENT '到期时间',
  `device_type` tinyint(3) DEFAULT '0' COMMENT '设备类型:0手表 1求救定位器',
  `imei` varchar(32) DEFAULT '0' COMMENT '设备类型imei号',
  `pay_version` varchar(32) DEFAULT NULL COMMENT '支付版本',
  `day` int(10) DEFAULT '0' COMMENT '充值天数(order_type=0,必填)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_care_object_id`),
  KEY `detail_id` (`detail_id`) USING BTREE,
  KEY `pay_account_id` (`pay_account_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `idx_imei` (`imei`) USING BTREE,
  KEY `lb_order_care_object_identity_IDX` (`identity`,`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者订单表';

-- ----------------------------
-- Table structure for lb_order_cart
-- ----------------------------
DROP TABLE IF EXISTS `lb_order_cart`;
CREATE TABLE `lb_order_cart` (
  `order_cart_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '用户',
  `goods_id` varchar(32) NOT NULL COMMENT '商品',
  `goods_attribute_id` varchar(32) NOT NULL COMMENT '商品属性',
  `number` int(11) NOT NULL DEFAULT '1' COMMENT '商品数量',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_cart_id`),
  KEY `account_id` (`account_id`) USING BTREE,
  KEY `goods_attribute_id` (`goods_attribute_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='购物车表';

-- ----------------------------
-- Table structure for lb_order_details
-- ----------------------------
DROP TABLE IF EXISTS `lb_order_details`;
CREATE TABLE `lb_order_details` (
  `order_details_id` varchar(32) NOT NULL COMMENT '主键',
  `goods_order_id` varchar(32) NOT NULL COMMENT '订单',
  `order_num` tinyint(4) DEFAULT '0' COMMENT '订单内显示顺序',
  `specification` tinyint(1) NOT NULL COMMENT '商品规格(0:套,1:只,2:个,3:台)',
  `versions` varchar(10) NOT NULL COMMENT '商品型号',
  `color` varchar(20) NOT NULL COMMENT '商品颜色',
  `goods_id` varchar(32) NOT NULL COMMENT '商品',
  `goods_name` varchar(32) NOT NULL COMMENT '商品名称',
  `buy_num` int(11) NOT NULL DEFAULT '1' COMMENT '购买数量',
  `buy_price` float(8,2) NOT NULL COMMENT '购买单价',
  `photo` varchar(60) NOT NULL DEFAULT '' COMMENT '商品图片',
  `is_suit` tinyint(1) NOT NULL DEFAULT '0' COMMENT '商品类型（详见字典表 goods_type）',
  `goods_detail` text NOT NULL COMMENT '卖点描述',
  `additional_desc` text COMMENT '附加描述信息',
  `share_detail` text NOT NULL COMMENT '分享描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_details_id`),
  KEY `goods_order_id` (`goods_order_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单详情表';

-- ----------------------------
-- Table structure for lb_order_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_order_device`;
CREATE TABLE `lb_order_device` (
  `order_device_id` varchar(64) NOT NULL COMMENT '主键',
  `order_id` varchar(32) DEFAULT NULL COMMENT '订单主键',
  `device_id` varchar(32) DEFAULT NULL COMMENT '设备主键',
  `device_type` tinyint(1) DEFAULT NULL COMMENT '设备类型',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`order_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_order_org
-- ----------------------------
DROP TABLE IF EXISTS `lb_order_org`;
CREATE TABLE `lb_order_org` (
  `lb_order_org_id` varchar(64) NOT NULL COMMENT '主键',
  `order_id` varchar(64) DEFAULT NULL COMMENT '订单主键',
  `org_id` varchar(64) DEFAULT NULL COMMENT '机构主键',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`lb_order_org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_org_account_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_account_relation`;
CREATE TABLE `lb_org_account_relation` (
  `account_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '平台id',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `relation_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联的平台id',
  `relation_account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '关联的用户id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除(0未删除,1删除)',
  PRIMARY KEY (`account_relation_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='不同平台用户关联信息表';

-- ----------------------------
-- Table structure for lb_org_alarm_delay_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_alarm_delay_config`;
CREATE TABLE `lb_org_alarm_delay_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `first_time` varchar(32) NOT NULL COMMENT '报警第一次推送时间',
  `second_time` varchar(32) NOT NULL COMMENT '报警第二次推送时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='延后处警配置';

-- ----------------------------
-- Table structure for lb_org_alarm_push_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_alarm_push_config`;
CREATE TABLE `lb_org_alarm_push_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代号',
  `device_type_desc` varchar(64) NOT NULL DEFAULT '' COMMENT '设备描述',
  `device_model` varchar(64) NOT NULL DEFAULT '' COMMENT '设备型号',
  `config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0基于平台',
  `push_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '基于平台中部分推送下1子女app2来邦守护中心3第三方',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目报警推送设备表';

-- ----------------------------
-- Table structure for lb_org_app_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_app_config`;
CREATE TABLE `lb_org_app_config` (
  `org_app_id` varchar(32) NOT NULL DEFAULT '',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `platform_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '平台类型(1:微信、2:苹果)',
  `platform_app_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '平台应用类型(1:小程序、2:客户端、3:公众号)',
  `app_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '应用类型(详见枚举文档)',
  `app_id` varchar(32) NOT NULL DEFAULT '' COMMENT '应用账号',
  `app_secret` varchar(32) NOT NULL DEFAULT '' COMMENT '应用密码',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_app_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='项目-应用配置表';

-- ----------------------------
-- Table structure for lb_org_approval_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_approval_record`;
CREATE TABLE `lb_org_approval_record` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `approve_id` varchar(64) DEFAULT '' COMMENT '审批人账号id',
  `apply_id` varchar(64) DEFAULT '' COMMENT '申请人账号id',
  `apply_name` varchar(32) DEFAULT NULL COMMENT '申请人姓名',
  `type` tinyint(4) DEFAULT '0' COMMENT '审批类型 0 默认 1 守护时间审批',
  `result` tinyint(1) DEFAULT '0' COMMENT '0 审批中、1通过、2驳回',
  `nb_host_sum` int(11) DEFAULT NULL COMMENT '项目支持的手持主机总数 字段当前值',
  `nb_host_sum_change` int(11) DEFAULT NULL COMMENT '项目支持的手持主机总数 字段变更值',
  `is_push_alarm` tinyint(1) DEFAULT NULL COMMENT '报警是否推送到子女APP 字段当前值，1推送，0不推送，默认不推送（仅对机构项目生效）',
  `is_push_alarm_change` tinyint(1) DEFAULT NULL COMMENT '报警是否推送到子女APP 字段变更值，1推送，0不推送，默认不推送（仅对机构项目生效）',
  `expire_time` bigint(20) DEFAULT NULL COMMENT '项目有效期时间 字段当前值',
  `expire_time_change` bigint(20) DEFAULT NULL COMMENT '项目有效期时间 字段变更值',
  `create_time` bigint(20) DEFAULT '0' COMMENT '申请时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '审批时间',
  `server_order_bonus` int(3) DEFAULT '0' COMMENT '服务订单分成百分比',
  `care_server_bonus` varchar(32) DEFAULT NULL COMMENT '守护服务分成比例，来邦:机构',
  `is_free` tinyint(4) DEFAULT '1' COMMENT '守护处警时间是否免费 0 否 1 是',
  `dispose_time_daily` varchar(64) DEFAULT NULL COMMENT '来邦24小时守护处警时间段 字段当前值',
  `dispose_time_daily_change` varchar(64) DEFAULT NULL COMMENT '来邦24小时守护处警时间段 字段变更值',
  `dispose_time_holiday` varchar(64) DEFAULT NULL COMMENT '节假日处警时间段',
  `org_operate_time` bigint(20) DEFAULT NULL COMMENT '项目运维时间 字段当前值',
  `org_operate_time_change` bigint(20) DEFAULT NULL COMMENT '项目运维时间 变更值',
  `org_operate_fee_ratio` decimal(5,2) DEFAULT NULL COMMENT '运维费用比例',
  `org_operate_fee_ratio_change` decimal(5,2) DEFAULT NULL COMMENT '运维费用比例 变更值',
  `remark` text COMMENT '备注',
  `sale_picture` varchar(510) DEFAULT '' COMMENT '销售单图片',
  `org_operate_fee` int(11) DEFAULT NULL COMMENT '运维金额',
  `org_operate_fee_change` int(11) DEFAULT NULL COMMENT '改变的的运维金额',
  `subordinate_platform_num` int(11) DEFAULT NULL COMMENT '子平台数据',
  `subordinate_platform_num_change` int(11) DEFAULT NULL COMMENT '改变子平台数据',
  `nb_user_sum` int(11) DEFAULT NULL COMMENT '平台用户数量',
  `nb_user_sum_change` int(11) DEFAULT NULL COMMENT '改变的平台用户数量',
  `care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼叫中心守护服务是否开启0否1是',
  `care_server_enable_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼叫中心守护服务改变',
  `vip_care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip守护服务是否开启0否1是',
  `vip_care_server_enable_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip服务是否开启改变',
  `care_server_cost` int(11) NOT NULL DEFAULT '0' COMMENT '守护费用',
  `care_server_cost_change` int(11) NOT NULL DEFAULT '0' COMMENT '守护费用改变',
  `care_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '分成比例',
  `care_share_ratio_change` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '分成比例改变',
  `withdraw_limit_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）',
  `withdraw_limit_type_change` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）改变',
  `withdraw_limit_day` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数',
  `withdraw_limit_day_change` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数改变',
  `share_model` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成',
  `share_model_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成改变',
  `renew_share_cycle` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期',
  `renew_share_cycle_change` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期改变',
  `renew_share_cycle_unit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日',
  `renew_share_cycle_unit_change` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日改变',
  `renew_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例',
  `renew_share_ratio_change` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例改变',
  `is_participate_alarm` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否参与项目报警0否1是',
  `is_participate_alarm_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否参与项目报警0否1是改变',
  `vip_dispose_time_daily` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段',
  `vip_dispose_time_daily_change` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段改变',
  `vip_basic_care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip守护服务是否开启0否1是（基础版）',
  `vip_basic_care_server_enable_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip服务是否开启改变（基础版）',
  `vip_basic_dispose_time_daily` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段（基础版）',
  `vip_basic_dispose_time_daily_change` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段改变（基础版）',
  `basic_care_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '首单分成比例（基础版）',
  `basic_care_share_ratio_change` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '首单分成比例改变（基础版）',
  `basic_withdraw_limit_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）（基础版）',
  `basic_withdraw_limit_type_change` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）改变（基础版）',
  `basic_withdraw_limit_day` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数（基础版）',
  `basic_withdraw_limit_day_change` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数改变（基础版）',
  `basic_share_model` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成（基础版）',
  `basic_share_model_change` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成改变（基础版）',
  `basic_renew_share_cycle` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期（基础版）',
  `basic_renew_share_cycle_change` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期改变（基础版）',
  `basic_renew_share_cycle_unit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日（基础版）',
  `basic_renew_share_cycle_unit_change` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日改变（基础版）',
  `basic_renew_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例（基础版）',
  `basic_renew_share_ratio_change` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例改变（基础版）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='审批记录表';

-- ----------------------------
-- Table structure for lb_org_authorize_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_authorize_relation`;
CREATE TABLE `lb_org_authorize_relation` (
  `relation_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(100) NOT NULL DEFAULT '' COMMENT '机构id',
  `authorize_id` varchar(32) NOT NULL DEFAULT '' COMMENT '授权方id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 未删除 1 已删除',
  `is_push` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审批是否推送',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relation_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `authorize_id_IDX` (`authorize_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='机构与授权方关联关系表';

-- ----------------------------
-- Table structure for lb_org_button_show
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_button_show`;
CREATE TABLE `lb_org_button_show` (
  `org_button_show_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_show` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示 1 显示 0 不显示',
  `button_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '按钮类型 1 用户下载手册',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `create_by` varchar(32) NOT NULL DEFAULT '' COMMENT '创建人',
  `update_by` varchar(32) NOT NULL DEFAULT '' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_button_show_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='平台按钮显示设置';

-- ----------------------------
-- Table structure for lb_org_care_attention
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_care_attention`;
CREATE TABLE `lb_org_care_attention` (
  `care_attention_id` varchar(64) NOT NULL COMMENT '注意事项唯一标识',
  `attention_type` tinyint(1) DEFAULT '1' COMMENT '1注意事项一、2 注意事项二、3 注意事项三、4 注意事项四、5饮食类型、6医保类型、7危重类型、8长者类别',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构id',
  `code` varchar(32) DEFAULT '' COMMENT 'code',
  `name` varchar(32) DEFAULT '' COMMENT 'name',
  `order_num` tinyint(1) DEFAULT '0' COMMENT '显示顺序',
  `background_color` varchar(32) DEFAULT 'Green' COMMENT '背景颜色',
  `font_color` varchar(32) DEFAULT 'BrightWhite' COMMENT '字体颜色',
  `content` varchar(150) DEFAULT '' COMMENT '护理标识二级菜单内容',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '1 有效 0 无效',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_attention_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_org_care_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_care_config`;
CREATE TABLE `lb_org_care_config` (
  `org_care_config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构主键',
  `care_config_type` tinyint(1) NOT NULL COMMENT '监护配置类型',
  `is_care` tinyint(1) DEFAULT NULL COMMENT '1  开启  2  关闭',
  `delay` double(11,1) DEFAULT NULL,
  `care_time` mediumtext COMMENT '看护时间',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `danger_level` tinyint(1) DEFAULT NULL COMMENT '危险等级',
  `work_pattern` tinyint(1) DEFAULT NULL COMMENT '工作模式',
  `care_setting` tinyint(1) DEFAULT NULL COMMENT '看护设置',
  `factory_pattern` char(1) DEFAULT NULL COMMENT '工厂模式',
  `band_delay` double(11,1) DEFAULT NULL COMMENT '手表报警阈值',
  `start_time` varchar(64) DEFAULT NULL COMMENT '手表上报时间/每日统计上报时间',
  `lowest_heart_rate` int(11) DEFAULT NULL COMMENT '心率最低阈值',
  `highest_heart_rate` int(11) DEFAULT NULL COMMENT '心率最高阈值',
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'NB上报时设备类型（0 手环，1 按钮）',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '开放配置标识（0 未开放，1 开放）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_care_config_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_org_care_level
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_care_level`;
CREATE TABLE `lb_org_care_level` (
  `care_level_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `code` varchar(32) DEFAULT '' COMMENT 'code',
  `name` varchar(32) DEFAULT '' COMMENT 'name',
  `order_num` int(11) DEFAULT NULL COMMENT '显示顺序',
  `background_color` varchar(32) DEFAULT 'Green' COMMENT '背景颜色',
  `font_color` varchar(32) DEFAULT 'BrightWhite' COMMENT '字体颜色',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '1 有效 0 无效',
  `content` varchar(150) DEFAULT '' COMMENT '护理标识二级菜单内容',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `level_desc` text COMMENT '级别说明',
  `care_type` int(11) DEFAULT NULL COMMENT '护理类型',
  `care_expense` decimal(10,2) DEFAULT NULL COMMENT '护理费用',
  `try_care_expense` decimal(10,2) DEFAULT NULL COMMENT '试住护理费用',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '１－护理　２－风险',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`care_level_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_org_contacts
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_contacts`;
CREATE TABLE `lb_org_contacts` (
  `org_contacts_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `name` varchar(128) DEFAULT '' COMMENT '姓名',
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `serial_num` int(11) DEFAULT '0' COMMENT ' 序号',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系',
  `contacts_type` tinyint(3) NOT NULL DEFAULT '1' COMMENT '联系人类型：1 项目联系人、2 亲属、3 保安、4 物业',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_contacts_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_org_csr_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_csr_config`;
CREATE TABLE `lb_org_csr_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `config_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '呼叫配置类型 1 北恩电话机 2电信云呼 3 阿里云呼 ',
  `phone` varchar(32) NOT NULL DEFAULT '0' COMMENT '呼叫号码',
  `company_id` varchar(32) NOT NULL DEFAULT '' COMMENT '公司id(电信配置必填)',
  `app_secret` varchar(64) NOT NULL DEFAULT '' COMMENT '应用密钥(电信配置必填)',
  `instance_id` varchar(255) NOT NULL DEFAULT '' COMMENT '实例id(阿里配置必填)',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `ip_address` varchar(64) NOT NULL DEFAULT '' COMMENT '服务器ip地址',
  `call_mode` tinyint(1) NOT NULL DEFAULT '0' COMMENT '通话模式： 0可呼入呼出（默认） 1仅呼入 2仅呼出',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='项目呼叫配置';

-- ----------------------------
-- Table structure for lb_org_customer_phone
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_customer_phone`;
CREATE TABLE `lb_org_customer_phone` (
  `customer_phone_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `customer_phone` varchar(32) NOT NULL DEFAULT '' COMMENT '客服电话',
  `caller_display_name` varchar(32) NOT NULL DEFAULT '' COMMENT '来电显示名称',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`customer_phone_id`),
  UNIQUE KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目客服电话';

-- ----------------------------
-- Table structure for lb_org_device_contact
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_device_contact`;
CREATE TABLE `lb_org_device_contact` (
  `record_id` varchar(32) NOT NULL COMMENT '记录',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac地址',
  `device_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构id',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目设备关联表';

-- ----------------------------
-- Table structure for lb_org_device_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_device_relation`;
CREATE TABLE `lb_org_device_relation` (
  `id` varchar(32) NOT NULL,
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `device_type` smallint(6) NOT NULL DEFAULT '0',
  `device_iteration_number` smallint(3) NOT NULL DEFAULT '0',
  `alarm_type` tinyint(1) DEFAULT NULL,
  `is_join` tinyint(1) DEFAULT NULL COMMENT '是否需要拼接描述  1需要',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='机构绑定过的设备记录';

-- ----------------------------
-- Table structure for lb_org_device_sign_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_device_sign_config`;
CREATE TABLE `lb_org_device_sign_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `config_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '配置类型1:深业项目',
  `config_name` varchar(32) NOT NULL DEFAULT '' COMMENT '配置名称',
  `org_use_unmarked_device` tinyint(1) NOT NULL DEFAULT '0' COMMENT '标记项目使用未标记设备0不可1可以',
  `org_use_marked_device` tinyint(1) NOT NULL DEFAULT '1' COMMENT '未标记项目使用标记设备0不可1可以',
  `child_app_use_marked_device` tinyint(1) NOT NULL DEFAULT '1' COMMENT '子女app使用标记设备0不可1可以',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目设备标识配置表';

-- ----------------------------
-- Table structure for lb_org_hierarchical
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_hierarchical`;
CREATE TABLE `lb_org_hierarchical` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `org_hierarchy` varchar(255) NOT NULL DEFAULT '' COMMENT '项目层级信息',
  `parent_id` int(11) DEFAULT '0' COMMENT '父级项目自增主键',
  `level` tinyint(3) NOT NULL DEFAULT '0' COMMENT '级别',
  `platform_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '平台类型 ',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_org_id` (`org_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3662 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='项目层级信息表';

-- ----------------------------
-- Table structure for lb_org_micro_station
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_micro_station`;
CREATE TABLE `lb_org_micro_station` (
  `micro_station_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `banner_url` text COMMENT 'banner图片地址',
  `micro_station_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '机构微站类型（0:未知 1:养老机构、2:社区服务中心、3:助餐点）',
  `micro_station_name` varchar(128) NOT NULL DEFAULT '' COMMENT '机构微站名称',
  `tags` varchar(128) NOT NULL DEFAULT '' COMMENT '标签',
  `contact_name` varchar(128) NOT NULL DEFAULT '' COMMENT '联系人姓名',
  `contact_phone` varchar(128) NOT NULL DEFAULT '' COMMENT '联系人手机号码',
  `region_id` varchar(128) NOT NULL DEFAULT '' COMMENT '行政区域regionId 信息',
  `region_desc` varchar(128) NOT NULL DEFAULT '' COMMENT '行政区域region 名称',
  `address` varchar(64) NOT NULL DEFAULT '' COMMENT '地址信息',
  `advertise_offer` text COMMENT '宣传报价',
  `micro_station_introduce` text COMMENT '机构介绍',
  `qr_code` varchar(128) NOT NULL DEFAULT '' COMMENT '公众号二维码',
  `wechat_qr_code` varchar(128) NOT NULL DEFAULT '' COMMENT '微信客服二维码',
  `tel` varchar(64) NOT NULL DEFAULT '' COMMENT '固定电话',
  `service_hotline` varchar(64) NOT NULL DEFAULT '' COMMENT '24小时客服热线',
  `service_team` varchar(128) NOT NULL DEFAULT '' COMMENT '服务团队',
  `service_time` varchar(128) NOT NULL DEFAULT '' COMMENT '服务时间',
  `service_range` varchar(128) NOT NULL DEFAULT '' COMMENT '服务范围',
  `service_explain` varchar(128) NOT NULL DEFAULT '' COMMENT '服务说明',
  `bed_info` text COMMENT '床位信息',
  `charge_standard` text COMMENT '收费标准',
  `service_photo_url` text COMMENT '服务照片',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_name` varchar(128) NOT NULL DEFAULT '' COMMENT '登记人',
  `register_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '登记时间',
  `register_phone` varchar(64) NOT NULL DEFAULT '' COMMENT '登记电话',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开放 0；不公开 1:公开',
  `coordsys` tinyint(1) NOT NULL DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `lat` varchar(128) NOT NULL DEFAULT '' COMMENT '纬度',
  `lng` varchar(128) NOT NULL DEFAULT '' COMMENT '经度',
  `display_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:示例 1:预览',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除0否1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`micro_station_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目微站详情表';

-- ----------------------------
-- Table structure for lb_org_module_process_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_module_process_config`;
CREATE TABLE `lb_org_module_process_config` (
  `config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `config_type` tinyint(3) NOT NULL DEFAULT '1' COMMENT '配置类型:1:长者登记设置',
  `config_item` tinyint(3) NOT NULL DEFAULT '1' COMMENT '设置项:1:简单入住登记设置，2简单退住登记',
  `config_item_name` varchar(32) NOT NULL DEFAULT '1' COMMENT '设置项名称:1、2:简易入住/退住登记',
  `config_item_value` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设置项值，0:正常模式 1:简易模式',
  `config_item_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT '设置项是否生效，0失效，1生效',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目模块流程配置';

-- ----------------------------
-- Table structure for lb_org_payment_account_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_payment_account_config`;
CREATE TABLE `lb_org_payment_account_config` (
  `account_config_id` varchar(32) NOT NULL COMMENT '收款账户配置id主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `pay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '支付方式（0银联，1支付宝，2微信）',
  `merchant_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '商户类型(0餐饮)',
  `account_config` varchar(255) NOT NULL DEFAULT '' COMMENT '账户配置详情',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`account_config_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目商户支付配置表';

-- ----------------------------
-- Table structure for lb_org_position_rule
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_position_rule`;
CREATE TABLE `lb_org_position_rule` (
  `rule_id` varchar(32) NOT NULL COMMENT '主键',
  `value` varchar(32) NOT NULL DEFAULT '' COMMENT '位置拼接内容',
  `level` tinyint(3) NOT NULL DEFAULT '0' COMMENT '位置等级',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`rule_id`),
  KEY `lb_org_position_rule_org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目地址拼接规则设置表';

-- ----------------------------
-- Table structure for lb_org_record_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_record_config`;
CREATE TABLE `lb_org_record_config` (
  `record_config_id` varchar(32) NOT NULL COMMENT '主键',
  `config_type` tinyint(1) DEFAULT NULL COMMENT '配置类型',
  `record_type` tinyint(1) DEFAULT NULL COMMENT '记录类型',
  `is_show` tinyint(1) DEFAULT '0' COMMENT '是否显示 0:不显示1:显示',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_config_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='数据显示设置表';

-- ----------------------------
-- Table structure for lb_org_regular_reminder_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_regular_reminder_setting`;
CREATE TABLE `lb_org_regular_reminder_setting` (
  `reminder_setting_id` varchar(64) NOT NULL COMMENT '主键',
  `reminder_type_id` varchar(64) NOT NULL COMMENT '定期提醒类型id',
  `setting_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设置类型(详见枚举)',
  `param` varchar(128) NOT NULL DEFAULT '' COMMENT '提醒参数',
  `department_id` text NOT NULL COMMENT '部门id，多个以都好分割，为空则为全部部门',
  `is_open` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否开启提醒 0:关闭 1:开启',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认设置 0:不是 1:是',
  `registrant` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `registrant_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目id(值为systemType为模版)',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`reminder_setting_id`),
  KEY `idx_org_id` (`org_id`),
  KEY `idx_reminder_type_id` (`reminder_type_id`),
  KEY `idx_reminder_type_id_setting_type` (`reminder_type_id`,`setting_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目定期提醒设置表';

-- ----------------------------
-- Table structure for lb_org_regular_reminder_type
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_regular_reminder_type`;
CREATE TABLE `lb_org_regular_reminder_type` (
  `reminder_type_id` varchar(64) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目id(值为systemType为模版)',
  `reminder_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '提醒类型(1:定期评估提醒 2:外出未归提醒 3:欠费提醒 4:余额不足提醒 5:长者入住提醒)',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`reminder_type_id`),
  KEY `idx_org_id` (`org_id`),
  KEY `idx_reminder_type` (`reminder_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目定期提醒类型表';

-- ----------------------------
-- Table structure for lb_org_renewal_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_renewal_record`;
CREATE TABLE `lb_org_renewal_record` (
  `renewal_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '缴费金额（运维费用+守护费用）',
  `renewal_time` int(10) DEFAULT NULL COMMENT '缴费时长 （单位 年）',
  `org_operate_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '项目运维时间',
  `org_operate_time_change` bigint(20) NOT NULL DEFAULT '0' COMMENT '项目运维时间 变更后',
  `operate_name` varchar(16) NOT NULL COMMENT '收费人',
  `note` varchar(255) DEFAULT NULL COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `create_by` varchar(32) NOT NULL DEFAULT '' COMMENT '创建人',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `update_by` varchar(32) NOT NULL DEFAULT '' COMMENT '更新人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`renewal_record_id`) USING BTREE,
  KEY `index_org` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='项目缴费记录表';

-- ----------------------------
-- Table structure for lb_org_sign
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_sign`;
CREATE TABLE `lb_org_sign` (
  `sign_id` varchar(32) NOT NULL COMMENT '主键',
  `sign_name` varchar(64) NOT NULL DEFAULT '' COMMENT '标记名称',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_sign_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可使用未标记设备 0 不可以  1 可以',
  `is_other_sign_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '非标记项目是否可使用标记设备 0 不可以  1 可以',
  `is_home_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '居家项目是否可使用标记设备 0 不可以  1 可以',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sign_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='项目标识表';

-- ----------------------------
-- Table structure for lb_org_sign_contact
-- ----------------------------
DROP TABLE IF EXISTS `lb_org_sign_contact`;
CREATE TABLE `lb_org_sign_contact` (
  `contact_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目主键',
  `sign_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目标记主键',
  `is_sign_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否可使用未标记设备 0 不可以  1 可以',
  `is_other_sign_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '非标记项目是否可使用标记设备 0 不可以  1 可以',
  `is_home_check` tinyint(1) NOT NULL DEFAULT '0' COMMENT '居家项目是否可使用标记设备 0 不可以  1 可以',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contact_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='项目标识关联表';

-- ----------------------------
-- Table structure for lb_organization
-- ----------------------------
DROP TABLE IF EXISTS `lb_organization`;
CREATE TABLE `lb_organization` (
  `org_id` varchar(64) NOT NULL COMMENT '主键',
  `org_name` varchar(128) DEFAULT '' COMMENT '名称',
  `org_type` tinyint(4) DEFAULT '2' COMMENT '类型 字典表organization_type',
  `org_desc` varchar(500) DEFAULT '' COMMENT '描述',
  `org_address` varchar(500) DEFAULT '' COMMENT '位置',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `contacts_name` varchar(32) DEFAULT '' COMMENT '联系人',
  `region_id` varchar(32) DEFAULT '' COMMENT '区域',
  `region_desc` varchar(500) DEFAULT '' COMMENT '详细地址',
  `system_type` tinyint(4) DEFAULT '1' COMMENT '系统类型',
  `status` tinyint(1) DEFAULT '1' COMMENT '管理服务器状态：',
  `last_remind_time` bigint(20) DEFAULT '0' COMMENT '上次短信提醒时间',
  `account_id` varchar(64) DEFAULT '' COMMENT '用户id',
  `is_expire_login` tinyint(1) DEFAULT '0' COMMENT '机构过期后 是否可以登录 0 否 1 是',
  `is_expire_alarm` tinyint(1) DEFAULT '1' COMMENT '守护服务到期后能否处警：1 处理 2 不处理',
  `is_push_alarm` tinyint(1) DEFAULT '0' COMMENT '报警是否推送到子女APP，1推送，0不推送，默认不推送（仅对机构项目生效）',
  `nb_host_sum` int(11) unsigned DEFAULT '0' COMMENT '项目支持的手持主机总数',
  `org_operate_time` bigint(20) DEFAULT '0' COMMENT '项目运维时间',
  `expire_time` bigint(20) DEFAULT '4102413839' COMMENT '机构项目有效期,-1默认永久',
  `app_id` varchar(32) DEFAULT '' COMMENT '项目对接标识',
  `app_secret` varchar(32) DEFAULT '' COMMENT '项目对接密钥',
  `is_approved` tinyint(1) DEFAULT '1' COMMENT '是否审批 0 待审批 1已审批',
  `org_title` varchar(255) DEFAULT '' COMMENT '机构网页软件标题',
  `community_order_rate` decimal(5,2) DEFAULT '0.00' COMMENT '社区订单抽成比例',
  `server_order_bonus` int(3) DEFAULT '0' COMMENT '服务订单分成百分比',
  `franchise_fee` int(11) DEFAULT '0' COMMENT '平台金额',
  `care_server_bonus` varchar(32) DEFAULT NULL COMMENT '守护服务分成比例，来邦:机构',
  `dispose_time_daily` varchar(64) DEFAULT NULL COMMENT '来邦呼叫中心处警时间段（居家场景）',
  `dispose_time_holiday` varchar(64) DEFAULT NULL COMMENT '节假日处警时间段',
  `group_id` varchar(32) DEFAULT NULL COMMENT '所属集团id',
  `is_data_communication` tinyint(1) DEFAULT '1' COMMENT '是否数据互通 1 是 0 否',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '是否启用，1启用，0不启用',
  `back_color` tinyint(1) DEFAULT '1' COMMENT '背景颜色:0白色，1蓝色',
  `manager_type` tinyint(1) DEFAULT '0' COMMENT '监管区域，0无，1养老院',
  `last_pay_time` bigint(20) DEFAULT '0' COMMENT '社区项目最近一次交加盟费时间',
  `is_expire_lb_alarm` tinyint(1) DEFAULT '1' COMMENT '守护服务到期后来邦是否参与处警：1 参与，2 不参与',
  `care_expire_time` bigint(20) DEFAULT '0' COMMENT '守护服务到期时间',
  `password_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '密码校验模式（0 弱密码，1 强密码）',
  `org_logo_url` varchar(255) DEFAULT '' COMMENT '标题图片地址',
  `org_operate_fee_ratio` decimal(5,2) DEFAULT '0.10' COMMENT '运维费用比例',
  `is_master_control_box` tinyint(1) DEFAULT '1' COMMENT '医院项目:是否使用主控盒 0否1是',
  `jurisdiction_longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `jurisdiction_latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `jurisdiction_address` varchar(255) DEFAULT NULL COMMENT '管辖区域地址',
  `adcode` varchar(128) DEFAULT '' COMMENT 'gps对应高德adcode',
  `customer_telephone` varchar(32) DEFAULT '' COMMENT '客服电话',
  `org_alarm_push_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '机构场景报警推送类型（1-平台客服&居家客服&监护主机，2-平台客服&居家客服，3-平台客服&监护主机，4-居家客服&监护主机，5-平台客服，6-居家客服，7-监护主机）',
  `lb_alarm_push_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '居家场景报警推送类型（1-平台客服&居家客服&监护主机，2-平台客服&居家客服，3-平台客服&监护主机，4-居家客服&监护主机，5-平台客服，6-居家客服，7-监护主机）',
  `is_private` tinyint(1) DEFAULT '0' COMMENT '是否私有化,0否,1是',
  `private_url` varchar(128) DEFAULT '' COMMENT '私有化地址',
  `private_status` tinyint(1) DEFAULT '0' COMMENT '私有化状态,0关闭,1正常,2异常',
  `private_error_times` tinyint(1) DEFAULT '0' COMMENT '私有化推送失败次数',
  `change_password_cycle` int(11) NOT NULL DEFAULT '0' COMMENT '修改密码周期(单位：天)（0：无需修改）',
  `login_fail_num` tinyint(1) NOT NULL DEFAULT '5' COMMENT '登录失败次数',
  `login_limit_time` int(11) NOT NULL DEFAULT '300' COMMENT '登录限制时间(单位：秒)',
  `is_white_center_customer_open` tinyint(1) NOT NULL DEFAULT '1' COMMENT '白名单是否开启来邦呼叫中心 0 不开启, 1 开启',
  `subordinate_platform_num` int(11) DEFAULT '0' COMMENT '子平台数据',
  `org_operate_fee` int(11) DEFAULT '0' COMMENT '平台金额',
  `indoor_map_update_frequency` int(11) DEFAULT '0' COMMENT '室内地图更新频率',
  `contain_system_type` varchar(16) DEFAULT '' COMMENT '包含平台:6机构养老2社区养老0居家养老3民政监管',
  `call_center_name` varchar(128) DEFAULT '' COMMENT '呼叫中心名称',
  `jurisdiction_coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `is_shelter` tinyint(1) DEFAULT '0' COMMENT '是否为方舱，1是，0否',
  `power_handle` tinyint(1) DEFAULT '0' COMMENT '低电量显示是否需要处理，1是0否',
  `third_party_platform_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '三方对接平台类型:-1不对接 0:数联天下',
  `energy_monitor_end_time` bigint(20) DEFAULT '0' COMMENT '电量监控结束时间',
  `platform_name` varchar(28) DEFAULT NULL COMMENT '登录页平台名称',
  `platform_logo_url` varchar(128) DEFAULT NULL COMMENT '登录页图片',
  `login_position` tinyint(1) DEFAULT '2' COMMENT '1居左 2居中 3居右 ，默认2',
  `dispose_time_daily_org` varchar(64) DEFAULT NULL COMMENT '来邦呼叫中心处警时间段（机构场景）',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '停用时间',
  `customer_project_type` tinyint(1) DEFAULT '-1' COMMENT '客户项目类型:1客户试用项目2客户签单项目3客户私有化项目4客户对接项目9其他项目',
  `is_abutment` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启监护设备对接功能0关闭1开启',
  `app_customized` tinyint(1) DEFAULT '0' COMMENT 'APP是否定制，1是;0否',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0否 1是',
  `nb_user_sum` int(11) NOT NULL DEFAULT '100' COMMENT '平台账户数量',
  `creator` varchar(128) NOT NULL DEFAULT '' COMMENT '创建人',
  `care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '呼叫中心守护服务是否开启0否1是',
  `care_server_cost` int(11) NOT NULL DEFAULT '0' COMMENT '守护费用',
  `vip_care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip守护服务是否开启0否1是',
  `care_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '首单分成比例',
  `withdraw_limit_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）',
  `withdraw_limit_day` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数',
  `vip_basic_care_server_enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'vip守护服务是否开启0否1是',
  `is_participate_alarm` tinyint(1) DEFAULT '0' COMMENT '是否参与项目报警0否1是',
  `share_model` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成',
  `renew_share_cycle` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期',
  `renew_share_cycle_unit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日',
  `renew_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例',
  `vip_dispose_time_daily` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段',
  `vip_basic_dispose_time_daily` varchar(64) NOT NULL DEFAULT '' COMMENT 'VIP服务呼叫中心处警时间段（基础版）',
  `basic_share_model` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分成模式0首单分成1首单分成+周期内分成（基础版）',
  `basic_care_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '首单分成比例（基础版）',
  `basic_renew_share_cycle` int(11) NOT NULL DEFAULT '0' COMMENT '续费分成周期（基础版）',
  `basic_renew_share_cycle_unit` tinyint(1) NOT NULL DEFAULT '1' COMMENT '续费分成周期单位1年2月3日（基础版）',
  `basic_renew_share_ratio` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '续费分成比例（基础版）',
  `basic_withdraw_limit_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '提现限制1不限制2服务器到期才可以提现3自定义时间（天）(基础版)',
  `basic_withdraw_limit_day` int(11) NOT NULL DEFAULT '0' COMMENT '提现限制天数（基础班）',
  `nursing_push_config` tinyint(1) NOT NULL DEFAULT '0' COMMENT '机构护理服务推送设置 0-不推送 1-次日推送昨日护理服务',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`org_id`),
  UNIQUE KEY `org_id` (`org_id`) USING BTREE,
  KEY `group_id` (`group_id`) USING BTREE,
  KEY `system_type` (`system_type`) USING BTREE,
  KEY `org_type` (`org_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='机构/项目';

-- ----------------------------
-- Table structure for lb_organization_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_organization_config`;
CREATE TABLE `lb_organization_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `indoor_map_update_frequency` tinyint(1) NOT NULL DEFAULT '0' COMMENT '室内地图更新频率',
  `is_abutment` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启监护设备对接功能0关闭1开启',
  `is_upload_device` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备上传开关0关闭1开启',
  `remark` text NOT NULL COMMENT '备注',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除0否1是',
  `is_allow_delete_role` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否允许删除角色',
  `is_repeat_push_alarm` tinyint(1) NOT NULL DEFAULT '1' COMMENT '未处理报警是重复否推送',
  `public_device_version` smallint(6) NOT NULL DEFAULT '1' COMMENT '公区设备版本号',
  `read_card_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '平台助餐机类型1恒星智助餐机2卡联助餐机',
  `abutment_username` varchar(64) NOT NULL DEFAULT '' COMMENT '对接账号',
  `abutment_password` varchar(64) NOT NULL DEFAULT '' COMMENT '对接密码',
  `abutment_tenant_id` varchar(64) NOT NULL DEFAULT '' COMMENT '租户id',
  `is_wechat_push` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否开启微信推送',
  `abutment_url` varchar(64) NOT NULL DEFAULT '' COMMENT '对接url',
  `push_children_app` tinyint(1) NOT NULL DEFAULT '0' COMMENT '推送子女app0全部推送1部分推送2全部不推送',
  `push_guard_center` tinyint(1) NOT NULL DEFAULT '0' COMMENT '推送来邦守护中心0全部推送1部分推送2全部不推送',
  `push_third_platform` tinyint(1) NOT NULL DEFAULT '0' COMMENT '推送三方平台0全部推送1部分推送2全部不推送',
  `food_shop_payment_account_config` tinyint(1) NOT NULL DEFAULT '0' COMMENT '收款账号设置配置信息-餐饮店铺0不支持设置1支持设置',
  `is_show_digital_human` tinyint(1) NOT NULL DEFAULT '0' COMMENT '可视化大屏是否显示数字人0不显示1显示',
  `is_qr_enrolled` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否允许通过二维码登记入住 0:不允许 1:允许',
  `qr_enrolled_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '二维码登记规则类型 默认1:需要审核 0:不需要审核 ',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_utility_meter_reading` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否支持水电费抄表功能:0不支持1支持',
  `care_object_name_length` int(3) NOT NULL DEFAULT '4' COMMENT '长者名称字数，4或100',
  `is_upload_evaluate_data` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否长传评估数据：0否、1是',
  `evaluate_system_identification` varchar(64) NOT NULL DEFAULT '' COMMENT '评估系统标识',
  `evaluate_system_public_key` text COMMENT '评估系统公钥',
  `evaluate_system_private_key` text COMMENT '评估系统私钥',
  PRIMARY KEY (`config_id`),
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='项目高级配置信息表';

-- ----------------------------
-- Table structure for lb_organization_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_organization_relation`;
CREATE TABLE `lb_organization_relation` (
  `org_relation_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '平台id',
  `system_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '系统类型',
  `relation_org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联平台id',
  `relation_system_type` tinyint(4) NOT NULL DEFAULT '1' COMMENT '关联平台的系统类型',
  `enable` tinyint(1) NOT NULL DEFAULT '0' COMMENT '关联关系是否有启用0否1是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间（时间戳）',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间（时间戳）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0:否，1:是）',
  PRIMARY KEY (`org_relation_id`),
  KEY `lb_organization_relation_org_id_IDX` (`org_id`) USING BTREE,
  KEY `lb_organization_relation_relation_org_id_IDX` (`relation_org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='平台关联关系表';

-- ----------------------------
-- Table structure for lb_ota_file_bag
-- ----------------------------
DROP TABLE IF EXISTS `lb_ota_file_bag`;
CREATE TABLE `lb_ota_file_bag` (
  `file_bag_id` varchar(32) NOT NULL DEFAULT '',
  `version_id` varchar(32) NOT NULL DEFAULT '' COMMENT '版本号id',
  `content` text NOT NULL COMMENT '分包内容',
  `num` int(11) NOT NULL DEFAULT '0' COMMENT '分包序号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`file_bag_id`),
  KEY `idx_version` (`version_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='软件升级包分片数据';

-- ----------------------------
-- Table structure for lb_ota_remote_upgrade_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_ota_remote_upgrade_task`;
CREATE TABLE `lb_ota_remote_upgrade_task` (
  `task_id` varchar(64) NOT NULL DEFAULT '' COMMENT '任务id',
  `org_type` tinyint(4) DEFAULT '2' COMMENT '项目类型 1居家项目 2机构项目',
  `org_id` varchar(64) DEFAULT '' COMMENT '项目id',
  `device_type` tinyint(3) DEFAULT '0' COMMENT '设备类型  ',
  `upgrade_way` tinyint(1) DEFAULT '0' COMMENT '设备升级方式 0统一升级  1分批升级',
  `upgrade_status` tinyint(1) DEFAULT '0' COMMENT '任务升级状态 0待升级 1升级中 2已完成 3已取消',
  `nb_version_new` varchar(32) DEFAULT '' COMMENT '固件升级版本号',
  `software_version_new` varchar(32) DEFAULT '' COMMENT '软件升级版本号',
  `upgrade_number` int(10) DEFAULT NULL COMMENT '升级设备数量',
  `nb_upgrade_time_start` bigint(20) DEFAULT '0' COMMENT '固件升级时间段(开始)',
  `nb_upgrade_time_end` bigint(20) DEFAULT '0' COMMENT '固件升级时间段(结束)',
  `software_upgrade_time_start` bigint(20) DEFAULT '0' COMMENT '软件升级时间段(开始)',
  `software_upgrade_time_end` bigint(20) DEFAULT '0' COMMENT '软件升级时间段(结束)',
  `registrant_id` varchar(64) DEFAULT '' COMMENT '登记人id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0否 1是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备远程升级任务';

-- ----------------------------
-- Table structure for lb_ota_remote_upgrade_task_detail
-- ----------------------------
DROP TABLE IF EXISTS `lb_ota_remote_upgrade_task_detail`;
CREATE TABLE `lb_ota_remote_upgrade_task_detail` (
  `id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `task_id` varchar(64) NOT NULL DEFAULT '' COMMENT '任务id',
  `device_id` varchar(64) DEFAULT '' COMMENT '设备id',
  `device_type` tinyint(3) DEFAULT '0' COMMENT '设备类型',
  `care_object_name` varchar(128) DEFAULT '' COMMENT '长者姓名',
  `upgrade_status` tinyint(1) DEFAULT '0' COMMENT '设备升级状态 0待升级 1升级中 2已完成',
  `nb_version` varchar(32) DEFAULT '' COMMENT '设备当前固件版本',
  `nb_version_new` varchar(32) DEFAULT '' COMMENT '设备升级固件版本id',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备当前软件版本',
  `soft_version_new` varchar(32) DEFAULT '' COMMENT '设备升级软件版本id',
  `upgrade_time_start` bigint(20) DEFAULT '0' COMMENT '升级开始时间',
  `upgrade_time_end` bigint(20) DEFAULT '0' COMMENT '升级结束时间',
  `nb_upgrade_result` tinyint(1) DEFAULT '0' COMMENT '固件升级结果  0未升级 1成功 2失败 3无需升级 4取消 5超时 ',
  `nb_upgrade_result_desc` int(11) DEFAULT '0' COMMENT '固件升级结果描述（设备上报，参照枚举）',
  `software_upgrade_result` tinyint(1) DEFAULT '0' COMMENT '软件升级结果  0未升级 1成功 2失败 3无需升级 4取消 5超时 ',
  `software_upgrade_result_desc` int(11) DEFAULT '0' COMMENT '软件升级结果描述（设备上报，参照枚举）',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0否 1是',
  `secret_key` varchar(16) DEFAULT '' COMMENT '升级秘钥',
  `device_iteration_number` int(3) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='设备远程升级详细';

-- ----------------------------
-- Table structure for lb_ota_version
-- ----------------------------
DROP TABLE IF EXISTS `lb_ota_version`;
CREATE TABLE `lb_ota_version` (
  `version_id` varchar(32) NOT NULL,
  `version_code` varchar(64) NOT NULL DEFAULT '' COMMENT '版本号',
  `device_type` tinyint(3) DEFAULT '0' COMMENT '设备类型',
  `device_iteration_number` tinyint(3) DEFAULT '0' COMMENT '设备迭代号',
  `upgrade_type` tinyint(3) DEFAULT '1' COMMENT '升级类型，1固件,2软件',
  `file_url` varchar(128) DEFAULT '' COMMENT '升级文件地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  `validate` tinyint(1) DEFAULT '0' COMMENT '是否为当前升级版本，1是,0否',
  `version_code_last` varchar(64) NOT NULL DEFAULT '' COMMENT '历史版本-版本号',
  `crc` varchar(16) DEFAULT '' COMMENT '软件升级时的文件crc校验码',
  `dat_file` text,
  `file_size` varchar(8) DEFAULT NULL COMMENT 'bin文件大小',
  `signature` varchar(128) DEFAULT '' COMMENT '汇顶bin镜像信息',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_ota_version_mapping
-- ----------------------------
DROP TABLE IF EXISTS `lb_ota_version_mapping`;
CREATE TABLE `lb_ota_version_mapping` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `file_name` varchar(64) NOT NULL DEFAULT '' COMMENT '文件名(version_code)',
  `file_mapping` varchar(64) NOT NULL DEFAULT '' COMMENT '文件映射(fastDFS路径)',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `file_name` (`file_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='固件版本文件映射表';

-- ----------------------------
-- Table structure for lb_out_home_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_out_home_report`;
CREATE TABLE `lb_out_home_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '离家次数',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '离家总时长',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='离家报表';

-- ----------------------------
-- Table structure for lb_outdoor_map
-- ----------------------------
DROP TABLE IF EXISTS `lb_outdoor_map`;
CREATE TABLE `lb_outdoor_map` (
  `map_id` varchar(32) NOT NULL COMMENT '主键',
  `map_name` varchar(32) DEFAULT '' COMMENT '地图名称',
  `map_content` text COMMENT '楼层地图附加信息',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `map_desc` varchar(125) DEFAULT '' COMMENT '区域地图',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`map_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='室外地图';

-- ----------------------------
-- Table structure for lb_outdoor_map_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_outdoor_map_area`;
CREATE TABLE `lb_outdoor_map_area` (
  `relatin_id` varchar(32) NOT NULL COMMENT '主键',
  `map_id` varchar(32) DEFAULT '' COMMENT '地图id',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`relatin_id`) USING BTREE,
  KEY `map_id` (`org_id`,`map_id`) USING BTREE,
  KEY `area_id` (`area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='室外地图房间关系';

-- ----------------------------
-- Table structure for lb_pay_jpush_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_pay_jpush_record`;
CREATE TABLE `lb_pay_jpush_record` (
  `pay_jpush_record_id` varchar(64) NOT NULL DEFAULT '' COMMENT '唯一标识',
  `record_type` tinyint(3) NOT NULL DEFAULT '0' COMMENT '46:请求他人支付通知,47:他人支付成功通知,48他人拒绝通知,49:设备升级通知,50:全体系统通知',
  `content` text NOT NULL COMMENT '内容',
  `title` varchar(120) NOT NULL DEFAULT '' COMMENT '标题',
  `order_type` tinyint(3) DEFAULT '0' COMMENT '订单类型',
  `username` varchar(12) NOT NULL DEFAULT '' COMMENT '接收方',
  `account_id` varchar(64) DEFAULT '' COMMENT '发送方',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`pay_jpush_record_id`),
  KEY `record_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='支付通知推送记录表';

-- ----------------------------
-- Table structure for lb_payment_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_payment_log`;
CREATE TABLE `lb_payment_log` (
  `log_id` varchar(32) NOT NULL COMMENT '日志ID',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目唯一标识',
  `pay_way` tinyint(1) NOT NULL DEFAULT '0' COMMENT '支付类型（0银联，1支付宝，2微信）',
  `merchant_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联商品订单ID/支付订单ID',
  `request` text COMMENT '请求内容',
  `response` text COMMENT '响应内容',
  `remark` varchar(32) NOT NULL DEFAULT '' COMMENT '备注',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`log_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='支付日志表';

-- ----------------------------
-- Table structure for lb_physiological_param_register_template
-- ----------------------------
DROP TABLE IF EXISTS `lb_physiological_param_register_template`;
CREATE TABLE `lb_physiological_param_register_template` (
  `template_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '账号id',
  `choose_physiological_params` varchar(255) NOT NULL DEFAULT '' COMMENT '已选择的生理参数信息（详情见生理体征枚举）',
  `non_choose_physiological_params` varchar(255) NOT NULL DEFAULT '' COMMENT '未选择的生理参数信息（详情见生理体征枚举）',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0-否 1-是',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`template_id`) USING BTREE,
  KEY `account_id_index` (`account_id`) USING BTREE COMMENT '账号id索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='健康管理生理参数登记模板表';

-- ----------------------------
-- Table structure for lb_pillbox
-- ----------------------------
DROP TABLE IF EXISTS `lb_pillbox`;
CREATE TABLE `lb_pillbox` (
  `pillbox_id` varchar(32) NOT NULL COMMENT '主键',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间id',
  `bed_id` varchar(32) DEFAULT NULL COMMENT '床位id',
  `device_type` tinyint(3) DEFAULT NULL COMMENT '设备类型（4g:107,wifi:108）',
  `device_number` varchar(32) DEFAULT NULL COMMENT '设备编号（设备唯一标识）',
  `mac` varchar(32) DEFAULT NULL COMMENT 'mac地址（预留）',
  `device_name` varchar(32) DEFAULT NULL COMMENT '设备名称',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量（默认是0）',
  `power_status` tinyint(1) DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量) 默认是0',
  `hardware_version` varchar(32) DEFAULT NULL COMMENT '硬件版本号',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '设备绑定的长者',
  `bing_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '绑定状态（0：正常 1：未绑定或解绑）',
  `date_standard` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备日期格式 0:年/月/日（默认） 1：日/月/年 2：月/日/年',
  `time_standard` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备时间格式 0:24小时（默认）   1: 12小时',
  `voice_standard` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备音量调节格式 0：大（默认）  1：中 2：低  3：静音  ',
  `language_standard` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备系统语言 0：中文 （默认） 1：英文',
  `time_zone` varchar(32) DEFAULT NULL COMMENT '设备时区',
  `is_manual` tinyint(1) NOT NULL DEFAULT '2' COMMENT '设备手动校准 1：是  2：否（默认）  ',
  `is_auto` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备自动时间校准 1：使能  0：禁用 （默认）',
  `is_disturb` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备是否免打扰 1：是 (默认)0：否',
  `disturb_stime` varchar(128) DEFAULT NULL COMMENT '设备免打扰开始时间 ',
  `disturb_etime` varchar(128) DEFAULT NULL COMMENT '设备免打扰结束时间',
  `time_out` bigint(20) DEFAULT NULL COMMENT '设备超时提醒时间（默认30分钟）',
  `time_miss` bigint(20) DEFAULT NULL COMMENT '设备漏用提醒时间（默认2小时）',
  `rest_pill_number` tinyint(1) DEFAULT NULL COMMENT '剩余服药次数',
  `next_pill_time` bigint(20) DEFAULT NULL COMMENT '下次服药时间',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0：未删除 1：已删除',
  `is_resetLocation` tinyint(1) DEFAULT NULL COMMENT '药盘是否复位 1：已复位 0：未知',
  `current_pill_number` tinyint(1) DEFAULT NULL COMMENT '当前药序格号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`pillbox_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能药盒信息表';

-- ----------------------------
-- Table structure for lb_positioner
-- ----------------------------
DROP TABLE IF EXISTS `lb_positioner`;
CREATE TABLE `lb_positioner` (
  `positioner_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置描述',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id（电信云平台注册返回）',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` tinyint(1) DEFAULT '0' COMMENT '是否加密',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_is_safe` tinyint(1) DEFAULT '0' COMMENT '是否为安全设备',
  `is_activated` tinyint(1) DEFAULT '0' COMMENT '是否激活',
  `version` smallint(1) DEFAULT '1' COMMENT '下发信息版本号',
  `serial_num` int(11) NOT NULL DEFAULT '0' COMMENT '序号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量,2充电中)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `nb_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `device_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '设备类型',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `real_time_track_status` tinyint(1) DEFAULT '0' COMMENT '实时轨迹功能状态，0关闭，1开启中',
  `real_time_track_last_time` bigint(20) DEFAULT '0' COMMENT '上一次开启实时轨迹的开始时间',
  `heart_time` int(3) DEFAULT '0' COMMENT '定位器每小时上报心跳的时间分钟数（秒）',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备软件版本号',
  `electricity_mode` tinyint(1) DEFAULT '1' COMMENT '应用的电量模式,0:eDRX,1:DRX,2:PSM',
  `electricity_mode_code` varchar(32) DEFAULT '' COMMENT '定位器电量模式信息',
  `is_restore` tinyint(1) DEFAULT '0' COMMENT '是否需要恢复出厂设置',
  `is_mode_change` tinyint(1) DEFAULT '1' COMMENT '设备模式是否切换完成 0 切换中 1切换完成',
  `last_change_time` bigint(20) DEFAULT '0' COMMENT '设备上次切换时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `heart_period` int(3) DEFAULT '7200' COMMENT '心跳周期',
  `power_consumption_mode` tinyint(1) DEFAULT '1' COMMENT '功耗模式 0 超低功耗 1 正常功耗',
  `rand_num` int(11) DEFAULT '0' COMMENT '心跳随机数',
  `fault` varchar(16) DEFAULT NULL COMMENT '故障信息（1 心率故障，2 六轴故障，3 WIFI芯片故障，4 生命探头故障）',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `send_num` tinyint(3) DEFAULT '1' COMMENT '更新次数',
  `config_send_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_product_test` tinyint(1) DEFAULT '0' COMMENT '是否为生产测试设备:0否 1是',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `platform_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '平台类型',
  `device_category` smallint(6) DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的上报时间',
  `receive_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最新消息的接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `is_bind` tinyint(1) NOT NULL DEFAULT '0' COMMENT '绑定标识（0：未绑定，1：已绑定）',
  `command_version_info` varchar(128) NOT NULL DEFAULT '' COMMENT '各协议命令版本号信息',
  PRIMARY KEY (`positioner_id`),
  KEY `mac` (`mac`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `idx_orgid` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='定位器设备';

-- ----------------------------
-- Table structure for lb_pressure_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_pressure_record_statistics`;
CREATE TABLE `lb_pressure_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录结束时间',
  `content` text COMMENT '压力数据',
  `record_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '记录类型（1 日常，2 轨迹，3 压力设备测量, 4 实时守护, 5 报警测量, 6 主动测量）',
  `record_time_date` datetime NOT NULL,
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `lb_pressure_record_statistics_update_time_IDX` (`update_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='压力记录统计表';

-- ----------------------------
-- Table structure for lb_pressure_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_pressure_report`;
CREATE TABLE `lb_pressure_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `max_pressure` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内的最高压力',
  `max_pressure_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最高压力上报时间',
  `min_pressure` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内的最低压力',
  `min_pressure_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最低压力上报时间',
  `total_pressure` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内压力数值汇总（用于计算平均压力）',
  `report_count` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内压力上报次数统计（用于计算平均压力）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='压力报表';

-- ----------------------------
-- Table structure for lb_probably_location_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_probably_location_record`;
CREATE TABLE `lb_probably_location_record` (
  `record_id` varchar(64) NOT NULL COMMENT '主键',
  `data` text COMMENT '接口返回内容',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `http_time` int(3) DEFAULT '0' COMMENT 'http请求时长（秒）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='粗定位记录';

-- ----------------------------
-- Table structure for lb_purchase_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_purchase_device`;
CREATE TABLE `lb_purchase_device` (
  `purchase_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `device_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备类型 1 燃气探测器 2烟雾探测器 3 监护手表 4 求救定位器 5 血压计',
  `device_name` varchar(64) NOT NULL DEFAULT '' COMMENT '设备名称',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT 'mac地址',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `activated` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否激活,0:未激活,1:激活',
  `content` varchar(255) NOT NULL DEFAULT '' COMMENT '备注（预留字段）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `device_iteration_number` int(3) DEFAULT '-1' COMMENT '设备迭代版本号',
  `guardianship_center_fee` varchar(128) NOT NULL DEFAULT '' COMMENT '守护中心服务费用',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`purchase_device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='入网设备表';

-- ----------------------------
-- Table structure for lb_quick_phrase
-- ----------------------------
DROP TABLE IF EXISTS `lb_quick_phrase`;
CREATE TABLE `lb_quick_phrase` (
  `quick_phrase_id` varchar(32) NOT NULL COMMENT '主键',
  `quick_code` varchar(32) DEFAULT '' COMMENT '快捷编码',
  `group` varchar(32) DEFAULT '' COMMENT '所属分组（详见字典表 phrase_group类型）',
  `type` tinyint(1) NOT NULL COMMENT '短语类型（0 个人，1 团队）',
  `content` mediumtext NOT NULL COMMENT '短语内容',
  `account_id` varchar(64) DEFAULT NULL COMMENT '个人Id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`quick_phrase_id`),
  KEY `group` (`group`) USING BTREE,
  KEY `type` (`type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='快捷短语表';

-- ----------------------------
-- Table structure for lb_real_name_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_real_name_device`;
CREATE TABLE `lb_real_name_device` (
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT 'id',
  `company_name` varchar(32) NOT NULL DEFAULT '' COMMENT '厂商名称',
  `device_model` varchar(32) NOT NULL DEFAULT '' COMMENT '设备型号',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei',
  `operator_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `acc_num` varchar(64) NOT NULL DEFAULT '' COMMENT '设备号码',
  `import_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '录入时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除 1:删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`),
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='实名设备表';

-- ----------------------------
-- Table structure for lb_receive_alarm_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_receive_alarm_device`;
CREATE TABLE `lb_receive_alarm_device` (
  `device_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `iot_device_id` varchar(64) DEFAULT NULL COMMENT '设备id（电信云平台注册返回）',
  `version` tinyint(1) unsigned DEFAULT '1' COMMENT '下发信息版本号',
  `serial_num` tinyint(1) DEFAULT '0' COMMENT '序号',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量,2充电中)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '电信平台所属应用id',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `nb_version` varchar(32) DEFAULT '' COMMENT '版本号',
  `device_type` tinyint(1) NOT NULL DEFAULT '15' COMMENT '设备类型',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `heart_time` int(3) DEFAULT '0' COMMENT '定位器每小时上报心跳的时间分钟数（秒）',
  `software_version` varchar(32) DEFAULT '' COMMENT '设备软件版本号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `heart_period` int(3) DEFAULT '7200' COMMENT '心跳周期',
  `real_time_track_status` tinyint(1) DEFAULT '0' COMMENT '实时轨迹功能状态，0关闭，1开启中',
  `real_time_track_last_time` bigint(20) DEFAULT '0' COMMENT '上一次开启实时轨迹的开始时间',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`) USING BTREE,
  KEY `mac` (`mac`) USING BTREE,
  KEY `iot_device_id` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='接警器设备';

-- ----------------------------
-- Table structure for lb_receive_alarm_participant
-- ----------------------------
DROP TABLE IF EXISTS `lb_receive_alarm_participant`;
CREATE TABLE `lb_receive_alarm_participant` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `participant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '参与人主键',
  `relation_type` tinyint(4) NOT NULL COMMENT '关系类型（1-紧急联系人，2-亲属）',
  `participation_status` tinyint(1) DEFAULT '1' COMMENT '参与状态（0-不参与，1-参与）',
  `start_time` varchar(8) NOT NULL DEFAULT '00:00' COMMENT '开始时间',
  `end_time` varchar(8) NOT NULL DEFAULT '00:00' COMMENT '结束时间',
  `registrant_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人主键',
  `registrant_name` varchar(128) DEFAULT NULL COMMENT '姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `relation_way` int(11) NOT NULL DEFAULT '-1' COMMENT '与长者关系',
  `is_global` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否全局设置 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `participant_id` (`org_id`,`care_object_id`,`participant_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='接警参与人设置表';

-- ----------------------------
-- Table structure for lb_receive_alarm_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_receive_alarm_record`;
CREATE TABLE `lb_receive_alarm_record` (
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '接警对象标识',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警标识',
  `alarm_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '报警时间',
  `device_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '报警设备MAC（仅用于护工手表接处警场景）',
  `manage_area_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '管理区域类型（员工设备接警）',
  `receive_alarm_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '接警状态（1-待接警, 2-已取消，3-已接警，4-已处警）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `receive_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接收状态（0-未接收，1-接收中，2-已接收）',
  `alarm_send_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '报警下发时间',
  `dispose_send_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '处警下发时间',
  `receive_alarm_record_id` varchar(128) NOT NULL DEFAULT '' COMMENT '主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`receive_alarm_record_id`),
  KEY `device_mac` (`device_mac`,`alarm_time`) USING BTREE,
  KEY `object_id` (`object_id`,`receive_alarm_status`) USING BTREE,
  KEY `alarm_id` (`alarm_id`,`receive_alarm_status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='接警记录表';

-- ----------------------------
-- Table structure for lb_receive_alarm_set
-- ----------------------------
DROP TABLE IF EXISTS `lb_receive_alarm_set`;
CREATE TABLE `lb_receive_alarm_set` (
  `receive_alarm_set_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者Id',
  `receive_alarm_type` tinyint(1) DEFAULT '0' COMMENT '接警类型（0 手动报警，1 其他自动报警，2 无生命活动报警）',
  `receive_alarm_time` bigint(20) DEFAULT '0' COMMENT '接警时间',
  `set_name` varchar(128) DEFAULT '' COMMENT '设置人姓名（处警设置人类型为客服时，为要求人姓名）',
  `set_type` tinyint(1) NOT NULL DEFAULT '2' COMMENT '设置人类型（ 1 子女app用户，2 系统， 3 客服,4 长者，5 紧急联系人，6 守护人）',
  `relation_desc` varchar(32) DEFAULT '' COMMENT '关系描述',
  `csr_id` varchar(64) DEFAULT '' COMMENT '客服Id（设置人类型为客服时存在）',
  `is_valid` tinyint(1) DEFAULT '0' COMMENT '是否有效  0 有效，1 失效',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_type` tinyint(1) DEFAULT NULL COMMENT 'NB上报时设备类型',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `start_time` varchar(8) NOT NULL DEFAULT '' COMMENT '开始时间',
  `end_time` varchar(8) NOT NULL DEFAULT '' COMMENT '结束时间',
  `device_iteration_number` tinyint(1) DEFAULT NULL COMMENT '设备迭代版本号',
  `set_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设置人标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`receive_alarm_set_id`),
  KEY `care_object_id` (`care_object_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='接警设置表';

-- ----------------------------
-- Table structure for lb_receive_level_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_receive_level_config`;
CREATE TABLE `lb_receive_level_config` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置对象标识',
  `receive_level` tinyint(1) NOT NULL COMMENT '接警级别',
  `terminal_type` tinyint(1) NOT NULL COMMENT '终端类型',
  `terminal_type_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '终端类型描述',
  `delay_time` smallint(6) NOT NULL DEFAULT '0' COMMENT '延时时间（秒级）',
  `is_open` tinyint(1) NOT NULL DEFAULT '0' COMMENT '开放标识（0-关闭，1-开放）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `object_id` (`object_id`,`is_open`) USING BTREE,
  KEY `terminal_type` (`object_id`,`terminal_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='接警级别配置表';

-- ----------------------------
-- Table structure for lb_receiver_address
-- ----------------------------
DROP TABLE IF EXISTS `lb_receiver_address`;
CREATE TABLE `lb_receiver_address` (
  `receiver_address_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '用户',
  `name` varchar(32) NOT NULL COMMENT '收货人姓名',
  `phone_num` varchar(11) NOT NULL COMMENT '联系电话',
  `province` int(9) NOT NULL DEFAULT '0' COMMENT '省份',
  `city` int(9) DEFAULT '0' COMMENT '城市',
  `prefecture` int(9) DEFAULT '0' COMMENT '区、县',
  `town` int(9) DEFAULT '0' COMMENT '城镇',
  `address` varchar(100) NOT NULL COMMENT '详细地址',
  `address_label` varchar(32) DEFAULT '' COMMENT '地址标签',
  `default_address` tinyint(1) NOT NULL DEFAULT '0' COMMENT '默认地址(0:否,1:是)',
  `region_desc` varchar(100) NOT NULL COMMENT '地区描述',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`receiver_address_id`),
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='收货地址表';

-- ----------------------------
-- Table structure for lb_region
-- ----------------------------
DROP TABLE IF EXISTS `lb_region`;
CREATE TABLE `lb_region` (
  `region_id` int(11) NOT NULL COMMENT '主键',
  `region_name` varchar(32) DEFAULT '' COMMENT '区域名称',
  `parent_path` varchar(255) DEFAULT NULL COMMENT '区域路径',
  `parent_id` int(11) DEFAULT '0' COMMENT '父级区域',
  `has_child` tinyint(1) DEFAULT '2' COMMENT '是否有子节点 1 是 2 否',
  `adcode` int(11) DEFAULT '0' COMMENT '城市编码',
  `center` varchar(32) DEFAULT '' COMMENT '区域中心点',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `level` tinyint(3) DEFAULT '0' COMMENT '级别',
  `chinese_initials` varchar(32) DEFAULT '' COMMENT '简拼',
  `status` tinyint(1) DEFAULT '0' COMMENT '更新状态（0 历史，1 新增，2 更新， 3 删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`region_id`),
  KEY `parent_id` (`parent_id`) USING BTREE,
  KEY `adcode` (`adcode`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='行政区域';

-- ----------------------------
-- Table structure for lb_region_boundary
-- ----------------------------
DROP TABLE IF EXISTS `lb_region_boundary`;
CREATE TABLE `lb_region_boundary` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `adcode` varchar(128) NOT NULL COMMENT '行政区划编码',
  `name` varchar(128) DEFAULT NULL COMMENT '行政区划名称',
  `center` varchar(128) DEFAULT NULL,
  `properties` varchar(128) DEFAULT NULL,
  `level` varchar(128) DEFAULT NULL,
  `boundaries` text COMMENT '边界点',
  `source` tinyint(1) DEFAULT '0' COMMENT '来源(默认其他)',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `create_time` bigint(20) DEFAULT NULL,
  `update_time` bigint(20) DEFAULT NULL,
  `region_id` int(11) DEFAULT NULL COMMENT '行政区域信息主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=393279896803280393 DEFAULT CHARSET=utf8mb4 COMMENT='行政区划边界信息表';

-- ----------------------------
-- Table structure for lb_region_combination
-- ----------------------------
DROP TABLE IF EXISTS `lb_region_combination`;
CREATE TABLE `lb_region_combination` (
  `id` int(11) NOT NULL COMMENT 'organization_type',
  `combination_id` varchar(255) DEFAULT '' COMMENT '组合地址ID集合',
  `combination_address` varchar(255) DEFAULT '' COMMENT '组合地址的描述信息',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_region_new
-- ----------------------------
DROP TABLE IF EXISTS `lb_region_new`;
CREATE TABLE `lb_region_new` (
  `region_id` int(11) NOT NULL COMMENT '主键',
  `region_name` varchar(32) DEFAULT '' COMMENT '区域名称',
  `parent_path` varchar(255) DEFAULT NULL COMMENT '区域路径',
  `parent_id` int(11) DEFAULT '0' COMMENT '父级区域',
  `has_child` tinyint(1) DEFAULT '2' COMMENT '是否有子节点 1 是 2 否',
  `adcode` int(11) DEFAULT '0' COMMENT '城市编码',
  `center` varchar(32) DEFAULT '' COMMENT '区域中心点',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `level` tinyint(3) DEFAULT '0' COMMENT '级别',
  `chinese_initials` varchar(32) DEFAULT '' COMMENT '简拼',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`region_id`),
  KEY `parent_id` (`parent_id`) USING BTREE,
  KEY `adcode` (`adcode`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='行政区域(实时)';

-- ----------------------------
-- Table structure for lb_region_transit
-- ----------------------------
DROP TABLE IF EXISTS `lb_region_transit`;
CREATE TABLE `lb_region_transit` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `region_id` int(11) DEFAULT NULL COMMENT 'region_id',
  `region_name` varchar(32) DEFAULT '' COMMENT '区域名称',
  `parent_id` int(11) DEFAULT '0' COMMENT '父级区域',
  `adcode` int(11) DEFAULT '0' COMMENT '城市编码',
  `center` varchar(32) DEFAULT '' COMMENT '区域中心点',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `level` tinyint(3) DEFAULT '0' COMMENT '级别',
  `chinese_initials` varchar(32) DEFAULT '' COMMENT '简拼',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `region_id` (`region_id`) USING BTREE,
  KEY `parent_id` (`parent_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=46162 DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='行政区域(天气)';

-- ----------------------------
-- Table structure for lb_remind_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_remind_task`;
CREATE TABLE `lb_remind_task` (
  `task_id` varchar(32) NOT NULL COMMENT '主键',
  `task_content` varchar(64) DEFAULT '' COMMENT '任务内容',
  `task_hour` varchar(32) DEFAULT '' COMMENT '任务设定小时',
  `task_minute` varchar(32) DEFAULT '' COMMENT '任务设定分钟',
  `is_set` tinyint(1) DEFAULT '0' COMMENT '设备是否设置完成 0未完成，1完成',
  `serial_number` tinyint(1) DEFAULT '1' COMMENT '序号',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构唯一标识',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者id ',
  `task_date` varchar(32) NOT NULL DEFAULT '1,2,3,4,5,6,7' COMMENT '任务执行周期',
  `task_type` int(11) NOT NULL DEFAULT '1' COMMENT '任务类型：1、吃药提醒任务 2、自定义任务',
  `is_open` tinyint(1) DEFAULT '1' COMMENT '任务开关  0 关 1 开',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `remind_repeat_number` tinyint(1) NOT NULL DEFAULT '1' COMMENT '提醒播报重复次数',
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设置设备id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='提醒任务表';

-- ----------------------------
-- Table structure for lb_report_show_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_report_show_config`;
CREATE TABLE `lb_report_show_config` (
  `report_type` tinyint(1) NOT NULL COMMENT '报告类型（流水类型）',
  `report_device_type` tinyint(1) NOT NULL COMMENT '上报设备类型',
  `device_iteration_number` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `show_item` varchar(64) NOT NULL DEFAULT '' COMMENT '显示项',
  `is_show` tinyint(1) NOT NULL COMMENT '显示标识（0-不显示，1-显示）',
  `show_item_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '显示项描述',
  `show_item_icon` varchar(64) NOT NULL DEFAULT '' COMMENT '显示项图标',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `show_item_key` varchar(64) NOT NULL DEFAULT '' COMMENT '显示项键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`report_type`,`report_device_type`,`device_iteration_number`,`show_item`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='统计报告显示配置表';

-- ----------------------------
-- Table structure for lb_role
-- ----------------------------
DROP TABLE IF EXISTS `lb_role`;
CREATE TABLE `lb_role` (
  `role_id` varchar(64) NOT NULL COMMENT '主键',
  `role_name` varchar(32) DEFAULT '' COMMENT '名称',
  `org_id` varchar(64) DEFAULT '' COMMENT '描述',
  `role_desc` varchar(32) DEFAULT '' COMMENT '角色叙述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_super` tinyint(1) DEFAULT '0' COMMENT '0非超级管理员  1超级管理员',
  `role_type` int(2) NOT NULL DEFAULT '3' COMMENT '角色类型 1项目管理员 10养老入网工具App 9输液工具App 8养老安装工具App 7养老巡检工具App 6HIS同步数据 3默认角色',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`role_id`),
  KEY `idx_org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='角色表';

-- ----------------------------
-- Table structure for lb_role_function
-- ----------------------------
DROP TABLE IF EXISTS `lb_role_function`;
CREATE TABLE `lb_role_function` (
  `rf_id` varchar(64) NOT NULL COMMENT '角色权限唯一id',
  `role_id` varchar(64) DEFAULT '' COMMENT '角色id',
  `func_op_id` varchar(64) DEFAULT '' COMMENT '功能模块id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `role_authority` varchar(32) NOT NULL DEFAULT '1' COMMENT '角色菜单权限 1浏览 2 编辑 3 增加 4 删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`rf_id`),
  KEY `idx_func_op_id` (`func_op_id`) USING BTREE,
  KEY `idx_role_id` (`role_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_role_function67
-- ----------------------------
DROP TABLE IF EXISTS `lb_role_function67`;
CREATE TABLE `lb_role_function67` (
  `rf_id` varchar(64) NOT NULL COMMENT '角色权限唯一id',
  `role_id` varchar(64) DEFAULT '' COMMENT '角色id',
  `func_op_id` varchar(64) DEFAULT '' COMMENT '功能模块id',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`rf_id`),
  KEY `idx_func_op_id` (`func_op_id`) USING BTREE,
  KEY `idx_role_id` (`role_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_role_route
-- ----------------------------
DROP TABLE IF EXISTS `lb_role_route`;
CREATE TABLE `lb_role_route` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `org_id` varchar(64) NOT NULL,
  `role_id` varchar(64) NOT NULL,
  `route` varchar(255) NOT NULL,
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=35092 DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_schedule_task_cluster
-- ----------------------------
DROP TABLE IF EXISTS `lb_schedule_task_cluster`;
CREATE TABLE `lb_schedule_task_cluster` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `task_name` varchar(64) DEFAULT NULL COMMENT '任务名称',
  `execute_status` tinyint(1) DEFAULT '0' COMMENT '执行状态:0未执行,1在执行',
  `execute_ip` varchar(32) DEFAULT NULL COMMENT '执行机器ip',
  `execute_time` bigint(20) DEFAULT '0' COMMENT '最后一次执行时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `lb_schedule_task_cluster_task_name_IDX` (`task_name`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='定时任务执行状态记录表';

-- ----------------------------
-- Table structure for lb_scheduled_task_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_scheduled_task_config`;
CREATE TABLE `lb_scheduled_task_config` (
  `task_id` varchar(32) NOT NULL COMMENT '任务id',
  `task_cron` varchar(32) NOT NULL COMMENT '任务设置时间',
  `org_id` varchar(32) DEFAULT NULL COMMENT '机构',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除 0:未删除 1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='系统计划任务设置表';

-- ----------------------------
-- Table structure for lb_server_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_server_config`;
CREATE TABLE `lb_server_config` (
  `server_config_id` varchar(32) NOT NULL COMMENT 'organization_type',
  `manufacturer` varchar(32) NOT NULL DEFAULT '' COMMENT '枚举字段 所属厂商',
  `ip` varchar(32) NOT NULL DEFAULT '' COMMENT 'IP',
  `port` int(11) NOT NULL DEFAULT '0' COMMENT 'port',
  `config_type` char(2) NOT NULL DEFAULT '' COMMENT '1 接口服务地址 2 资源服务地址  3 公钥  4 证书',
  `url` varchar(255) NOT NULL DEFAULT '' COMMENT '路径',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `version_code` varchar(255) DEFAULT NULL COMMENT '版本',
  `md_key` varchar(64) DEFAULT NULL COMMENT 'md5加密key',
  `version_name` varchar(64) NOT NULL DEFAULT '' COMMENT '版本名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`server_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_server_version
-- ----------------------------
DROP TABLE IF EXISTS `lb_server_version`;
CREATE TABLE `lb_server_version` (
  `version_code` varchar(255) DEFAULT NULL COMMENT '主键',
  `version_name` varchar(255) DEFAULT '' COMMENT '版本名称',
  `version_validate` tinyint(1) DEFAULT '0' COMMENT '是否为最新版本，1是，0否',
  `version_update` mediumtext COMMENT '版本更新内容',
  `qr_code_url` varchar(64) DEFAULT '' COMMENT '下载二维码（仅限app）',
  `software_name` varchar(64) DEFAULT '' COMMENT '软件名称',
  `software_model` varchar(64) DEFAULT '' COMMENT '型号',
  `type` varchar(10) DEFAULT '' COMMENT '1,安卓app，2,iosapp,3LB版平台服务器，4机构版平台服务器,5居家终端，6机构终端，11入网工具app',
  `download_url` mediumtext COMMENT '升级文件的相对地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `is_urgency` tinyint(4) DEFAULT '0' COMMENT '是否为紧急版本，1是，0否',
  `md_key` varchar(64) DEFAULT '' COMMENT 'md5加密key',
  `version_id` varchar(64) NOT NULL DEFAULT '' COMMENT 'version_id',
  `is_prompt` tinyint(1) DEFAULT '0' COMMENT '是否提示 0:不提示　１：提示',
  `org_id` varchar(32) DEFAULT 'lonbon' COMMENT '所属项目id，lonbon为通用版本',
  `app_name` varchar(20) DEFAULT '' COMMENT 'app名称(定制)',
  `app_download_url` text COMMENT 'app图片地址(定制)',
  `digit_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '子女app(type=1)下生效，位数 0:32+64 ,1:32 ,2:64',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`version_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_server_version_redemption
-- ----------------------------
DROP TABLE IF EXISTS `lb_server_version_redemption`;
CREATE TABLE `lb_server_version_redemption` (
  `id` varchar(32) NOT NULL DEFAULT '',
  `code` varchar(16) NOT NULL DEFAULT '' COMMENT '代码',
  `code_link` varchar(64) NOT NULL DEFAULT '' COMMENT '链接',
  `is_use` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否使用 0未使用  1使用',
  `type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '软件类型(同server_version)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='软件包兑换码';

-- ----------------------------
-- Table structure for lb_service_benefits
-- ----------------------------
DROP TABLE IF EXISTS `lb_service_benefits`;
CREATE TABLE `lb_service_benefits` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '服务对象标识',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '开始时间',
  `expire_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '到期时间',
  `user_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '用户类型（1-体验用户，2-付费用户）',
  `is_give` tinyint(1) NOT NULL DEFAULT '0' COMMENT '赠送标识（0-未赠送，1-已赠送）',
  `device_imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `object_id` (`object_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='服务权益表';

-- ----------------------------
-- Table structure for lb_service_payment_price
-- ----------------------------
DROP TABLE IF EXISTS `lb_service_payment_price`;
CREATE TABLE `lb_service_payment_price` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `payment_duration` tinyint(1) NOT NULL COMMENT '缴费时长（时长单位见描述）',
  `duration_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '时长描述',
  `discount` double NOT NULL DEFAULT '0' COMMENT '折扣',
  `price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '价格',
  `payment_channel` tinyint(1) NOT NULL DEFAULT '1' COMMENT '缴费渠道（1-帮守护小程序）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='服务缴费价目表';

-- ----------------------------
-- Table structure for lb_service_payment_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_service_payment_record`;
CREATE TABLE `lb_service_payment_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '服务对象标识',
  `family_address` text NOT NULL COMMENT '家庭住址',
  `expire_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '到期时间',
  `payer_id` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费人标识',
  `payer_name` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费人姓名',
  `payment_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '缴费类型（1-支付，2-初始赠送，3-平台赠送，4-设备赠送）',
  `payment_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '缴费时间',
  `payment_duration` varchar(32) NOT NULL DEFAULT '' COMMENT '缴费时长',
  `payment_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '缴费金额',
  `payment_detail` text COMMENT '缴费详情',
  `trade_order_id` varchar(32) NOT NULL DEFAULT '' COMMENT '交易订单标识（支付缴费有效）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `object_id` (`object_id`) USING BTREE,
  KEY `trade_order_id` (`trade_order_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='服务缴费记录表';

-- ----------------------------
-- Table structure for lb_share_group
-- ----------------------------
DROP TABLE IF EXISTS `lb_share_group`;
CREATE TABLE `lb_share_group` (
  `group_id` varchar(32) NOT NULL COMMENT '主键',
  `group_name` varchar(255) NOT NULL DEFAULT '' COMMENT '分组名字',
  `file_url` varchar(255) DEFAULT '' COMMENT '文件路径',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `duration` varchar(11) DEFAULT NULL COMMENT '语音时长',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`group_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_share_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_share_info`;
CREATE TABLE `lb_share_info` (
  `share_id` varchar(32) NOT NULL COMMENT '主键',
  `relative_phone` varchar(11) DEFAULT '' COMMENT '亲属电话',
  `identity` varchar(32) DEFAULT '' COMMENT '身份证',
  `info_desc` varchar(128) DEFAULT '' COMMENT '信息',
  `status` tinyint(1) DEFAULT '0' COMMENT '0未接收，1已接收，2已撤回',
  `is_text` tinyint(1) DEFAULT '0' COMMENT '1 文本 0 非文本',
  `file_type` tinyint(1) DEFAULT '2' COMMENT '1 图片 2 文字',
  `group_name` varchar(255) DEFAULT '' COMMENT '分组名称',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `send_time` bigint(20) DEFAULT '0' COMMENT '发送时间',
  `receive_time` bigint(20) DEFAULT '0' COMMENT '接收时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`share_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_shopper
-- ----------------------------
DROP TABLE IF EXISTS `lb_shopper`;
CREATE TABLE `lb_shopper` (
  `shopper_id` varchar(64) NOT NULL DEFAULT '' COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '用户ID',
  `username` varchar(32) DEFAULT '' COMMENT '登录用户名',
  `password` varchar(32) DEFAULT '' COMMENT '密码',
  `display_name` varchar(64) DEFAULT '' COMMENT '昵称',
  `phone_num` varchar(32) DEFAULT '' COMMENT '手机号',
  `gender` tinyint(1) DEFAULT NULL COMMENT '性别（１男,２女）',
  `birthday` bigint(20) DEFAULT NULL COMMENT '生日',
  `account_type` tinyint(1) DEFAULT '0' COMMENT '用户类型（1:子女APP用户,10:微信用户）',
  `head_image` text COMMENT '头像地址',
  `region_combination` varchar(255) DEFAULT NULL COMMENT '行政区域表主键组合',
  `region_desc` varchar(100) DEFAULT NULL COMMENT '地区描述',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`shopper_id`),
  KEY `username` (`username`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商城用户信息表';

-- ----------------------------
-- Table structure for lb_sim
-- ----------------------------
DROP TABLE IF EXISTS `lb_sim`;
CREATE TABLE `lb_sim` (
  `acc_num` varchar(64) NOT NULL COMMENT 'nb卡接入号',
  `iccid` varchar(64) DEFAULT '' COMMENT 'nb卡号',
  `isp_type` char(1) DEFAULT '' COMMENT 'sim卡运营商类型：1 电信 2 移动',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `operation_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '操作时间',
  `agent_type` int(3) DEFAULT '1' COMMENT '代理商类型: 1 南陵电信 2 移远',
  `is_white_manage` tinyint(1) NOT NULL DEFAULT '0' COMMENT '白名单是否支持管理 0 不支持 1 支持',
  `is_answer` tinyint(1) NOT NULL DEFAULT '0' COMMENT '语音接听是否支持 0 不支持 1 支持',
  `is_call` tinyint(1) NOT NULL DEFAULT '0' COMMENT '语音呼出是否支持 0 不支持 1 支持',
  `import_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '导入时间',
  `operator` varchar(128) NOT NULL DEFAULT '' COMMENT '操作人姓名',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`acc_num`),
  KEY `iccid` (`iccid`),
  KEY `lb_sim_isp_type_IDX` (`isp_type`) USING BTREE,
  KEY `lb_sim_operation_time_IDX` (`operation_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_sip_account
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_account`;
CREATE TABLE `lb_sip_account` (
  `sip_account_id` varchar(64) NOT NULL COMMENT 'sip_account_id',
  `sip_account` varchar(32) DEFAULT '' COMMENT 'sip_account',
  `sip_password` varchar(32) DEFAULT '' COMMENT 'sip_password',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `sip_ip` varchar(32) DEFAULT '' COMMENT 'sip_ip',
  `sip_port` smallint(5) unsigned DEFAULT '0' COMMENT 'sip_port',
  `sip_account_type` tinyint(1) DEFAULT '0' COMMENT 'sip账号类型，0一对一，1一对多',
  `is_available` tinyint(1) DEFAULT '0' COMMENT '0 空闲  1 通话中',
  `is_online` tinyint(1) DEFAULT '0' COMMENT '0 离线 1 在线',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  `monthly_call_duration` int(3) NOT NULL DEFAULT '0' COMMENT '每月通话时长，秒，默认0无限制',
  `current_month_call_duration` int(3) NOT NULL DEFAULT '0' COMMENT '当前月通话时长，秒',
  `last_call_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最后一次通话时间',
  `total_call_duration` int(11) NOT NULL DEFAULT '0' COMMENT '累计通话时长，秒',
  PRIMARY KEY (`sip_account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='SIP账号信息表;';

-- ----------------------------
-- Table structure for lb_sip_call_history
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_call_history`;
CREATE TABLE `lb_sip_call_history` (
  `call_history_id` varchar(32) NOT NULL COMMENT '主键',
  `sip_num` varchar(32) DEFAULT '' COMMENT 'sip账号',
  `call_time` bigint(20) DEFAULT '0' COMMENT '呼叫时间',
  `answer_start_time` bigint(20) DEFAULT '0' COMMENT '开始接听时间',
  `answer_end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `status` tinyint(4) DEFAULT '1' COMMENT '记录状态：1等待接听，2已接听，3未接听',
  `answer_account_id` varchar(32) DEFAULT '' COMMENT '接听人主键',
  `answer_account_name` varchar(32) DEFAULT '' COMMENT '接听人姓名',
  `care_object_name` varchar(32) DEFAULT '' COMMENT '看护对象名字',
  `call_type` tinyint(1) DEFAULT '1' COMMENT '通话类型 1视频通话 0语音通话',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `answer_sip_account` varchar(32) NOT NULL DEFAULT '' COMMENT '接听人sip账号',
  `voice_file` varchar(64) NOT NULL DEFAULT '' COMMENT '语音文件地址',
  `caller_video_file` varchar(64) NOT NULL DEFAULT '' COMMENT '呼叫人音频地址',
  `answer_video_file` varchar(64) NOT NULL DEFAULT '' COMMENT '接听人音频地址',
  `hangup_cause` varchar(32) NOT NULL DEFAULT '' COMMENT '通话挂断原因',
  `call_uuid` varchar(64) NOT NULL DEFAULT '' COMMENT 'sip通话uuid',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `recall_status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '回拨状态：1不可回拨 2可回拨 3 已回拨',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '通话持续时长',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`call_history_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_sip_proxy
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_proxy`;
CREATE TABLE `lb_sip_proxy` (
  `proxy_id` int(11) NOT NULL AUTO_INCREMENT COMMENT '代理唯一标识',
  `ice_enable` tinyint(1) DEFAULT NULL COMMENT 'ice开启 0 不开启/1开启',
  `proxy_enable` tinyint(1) DEFAULT NULL COMMENT '代理开启 0 不开启/1开启',
  `proxy_realm` varchar(32) DEFAULT NULL COMMENT '代理协议类型 all',
  `proxy_server_ip` varchar(32) DEFAULT NULL COMMENT '代理ip',
  `proxy_server_port` smallint(6) unsigned DEFAULT NULL COMMENT '代理端口',
  `proxy_username` varchar(255) DEFAULT NULL COMMENT '代理账号',
  `proxy_password` varchar(255) DEFAULT NULL COMMENT '代理密码',
  `proxy_data_type` tinyint(1) DEFAULT NULL COMMENT '密码验证类型 0',
  `transport_type` tinyint(1) DEFAULT NULL COMMENT '1 tcp 0 udp',
  `stun_enable` tinyint(1) DEFAULT '0' COMMENT 'stun代理开启 0 不开启/1开启',
  `stun_server_ip` varchar(32) DEFAULT '' COMMENT 'stun代理ip',
  `stun_server_port` smallint(6) unsigned DEFAULT '0' COMMENT 'stun代理端口',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`proxy_id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_sip_relation
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_relation`;
CREATE TABLE `lb_sip_relation` (
  `sip_relation_id` varchar(64) NOT NULL COMMENT 'sip_relation_id',
  `sip_account_id` varchar(64) DEFAULT '' COMMENT 'sip主键',
  `user_key` varchar(64) DEFAULT '' COMMENT '终端sn/子女id',
  `user_type` tinyint(4) DEFAULT '0' COMMENT '用户类型、终端 0 /子女 1/ 坐席 2',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '项目id',
  PRIMARY KEY (`sip_relation_id`),
  KEY `sip_account_id` (`sip_account_id`) USING BTREE,
  KEY `user_key` (`user_key`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='SIP账号绑定关系表;';

-- ----------------------------
-- Table structure for lb_sip_server
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_server`;
CREATE TABLE `lb_sip_server` (
  `sip_server_id` int(11) NOT NULL COMMENT '主键',
  `server_ip` varchar(32) DEFAULT NULL COMMENT 'sip服务器ip',
  `server_port` smallint(6) unsigned DEFAULT NULL COMMENT 'sip服务器端口',
  `sip_account_sum` int(11) DEFAULT NULL COMMENT '已注册账号总数',
  `cpu_used` tinyint(4) DEFAULT NULL COMMENT '当前cpu使用率',
  `memory_used` tinyint(4) DEFAULT NULL COMMENT '当前内存使用率',
  `net_used` tinyint(4) DEFAULT NULL COMMENT '当前网络使用率',
  `io_used` tinyint(4) DEFAULT NULL COMMENT '当前io使用率',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sip_server_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_sip_server_monitor_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_sip_server_monitor_config`;
CREATE TABLE `lb_sip_server_monitor_config` (
  `sip_server_monitor_id` int(11) NOT NULL COMMENT '主键',
  `server_ip` varchar(32) DEFAULT NULL COMMENT '服务器ip',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sip_server_monitor_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_slave_building
-- ----------------------------
DROP TABLE IF EXISTS `lb_slave_building`;
CREATE TABLE `lb_slave_building` (
  `slave_building_id` varchar(32) NOT NULL COMMENT '主键id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `master_num` varchar(32) NOT NULL DEFAULT '' COMMENT '主机编号',
  `slave_num` varchar(32) NOT NULL DEFAULT '' COMMENT '分机编号',
  `slave_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '分机类型 0分机 1洗手间',
  `description` varchar(32) NOT NULL DEFAULT '' COMMENT '描述信息',
  `community_name` varchar(32) NOT NULL DEFAULT '' COMMENT '小区',
  `building_num` varchar(32) NOT NULL DEFAULT '' COMMENT '楼栋号',
  `unit_num` varchar(32) NOT NULL DEFAULT '' COMMENT '单元',
  `floor_num` varchar(32) NOT NULL DEFAULT '' COMMENT '楼层号',
  `room_num` varchar(32) NOT NULL DEFAULT '' COMMENT '房号',
  `bed_num` varchar(32) NOT NULL DEFAULT '' COMMENT '床号',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`slave_building_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='分机和楼栋信息的关系表';

-- ----------------------------
-- Table structure for lb_sleep_monitor_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_sleep_monitor_device`;
CREATE TABLE `lb_sleep_monitor_device` (
  `device_id` varchar(32) NOT NULL DEFAULT '',
  `area_id` varchar(32) NOT NULL DEFAULT '',
  `bed_id` varchar(32) NOT NULL DEFAULT '',
  `device_name` varchar(16) NOT NULL DEFAULT '' COMMENT '设备名称',
  `device_category` int(11) NOT NULL DEFAULT '0',
  `position_type` int(11) NOT NULL DEFAULT '0',
  `position_desc` varchar(16) NOT NULL DEFAULT '' COMMENT '安装位置',
  `device_type` int(11) NOT NULL DEFAULT '0',
  `device_iteration_number` int(11) NOT NULL DEFAULT '0' COMMENT '设备迭代号',
  `wifi_name` varchar(32) NOT NULL DEFAULT '' COMMENT 'wifi名称',
  `wifi_password` varchar(32) NOT NULL DEFAULT '' COMMENT 'wifi密码',
  `connect_server` varchar(64) NOT NULL DEFAULT '' COMMENT '设备连接服务器地址',
  `status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '在线状态(0:离线 1:在线)',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是'
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

-- ----------------------------
-- Table structure for lb_sleep_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_sleep_record`;
CREATE TABLE `lb_sleep_record` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '日期',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台设备Id',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `sleep_type` tinyint(1) NOT NULL DEFAULT '3' COMMENT '睡眠类型（3-深度睡眠，4-浅度睡眠，-5-清醒睡眠）',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '睡眠开始时间',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '睡眠结束时间',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠持续时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`) USING BTREE,
  KEY `lb_sleep_record_update_time_IDX` (`update_time`) USING BTREE,
  KEY `idx_iot_device_id_sleep_type_start_time` (`iot_device_id`,`sleep_type`,`start_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='睡眠记录表';

-- ----------------------------
-- Table structure for lb_sleep_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_sleep_record_statistics`;
CREATE TABLE `lb_sleep_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录结束时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `content` text NOT NULL COMMENT '睡眠数据',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1 智能床睡眠周期）',
  `record_time_date` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='睡眠周期记录统计表';

-- ----------------------------
-- Table structure for lb_sleep_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_sleep_report`;
CREATE TABLE `lb_sleep_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '睡眠开始时间',
  `deep_sleep` int(11) NOT NULL DEFAULT '0' COMMENT '深度睡眠时长',
  `shallow_sleep` int(11) NOT NULL DEFAULT '0' COMMENT '浅度睡眠时长',
  `sober_sleep` int(11) NOT NULL DEFAULT '0' COMMENT '清醒睡眠时长',
  `quality` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠质量',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `eye_move_duration` int(11) NOT NULL DEFAULT '0' COMMENT '快速眼动时长，单位秒',
  `eye_move_proportion` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '快速眼动占比=（快速眼动时长/有效睡眠时长）',
  `shallow_sleep_proportion` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '浅睡占比=（浅睡时长/有效睡眠时长）',
  `deep_sleep_proportion` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '深睡占比=（深睡时长/有效睡眠时长）',
  `sporadic_naps_duration` int(11) NOT NULL DEFAULT '0' COMMENT '零星小睡时长，单位秒',
  `effective_sleep_duration` int(11) NOT NULL DEFAULT '0' COMMENT '有效睡眠时长，单位秒 有效睡眠时长=快速眼动时长+浅睡时长+深睡时长',
  `sleep_efficiency` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '睡眠效率',
  `latent_duration` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠潜伏期时长，单位秒',
  `weak_sum` int(11) NOT NULL DEFAULT '0' COMMENT '清醒次数',
  `respiratory_exception_sum` int(11) NOT NULL DEFAULT '0' COMMENT '生命体征异常次数',
  `turn_sum` int(11) NOT NULL DEFAULT '0' COMMENT '翻身次数',
  `breath_quality_score` int(11) NOT NULL DEFAULT '0' COMMENT '呼吸质量得分，数值范围：1-100',
  `sleep_fornt` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠前期解读',
  `sleep_middle` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠中期解读',
  `sleep_last` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠后夜解读',
  `sleep_weak` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠醒来解读',
  `total_sleep_duration` bigint(20) NOT NULL DEFAULT '0' COMMENT '睡眠总时长',
  `end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '睡眠结束时间（睡醒时间）',
  `original_sleep_content` text NOT NULL COMMENT '厂家报告内容',
  `report_template_type` int(11) NOT NULL DEFAULT '1' COMMENT '厂家报告模板类型,见睡眠报告模板枚举',
  `in_sleep` int(11) NOT NULL DEFAULT '0' COMMENT '中睡睡眠时长',
  `in_sleep_proportion` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '中睡占比=（中睡时长/有效睡眠时长）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='睡眠报表';

-- ----------------------------
-- Table structure for lb_smart_bed
-- ----------------------------
DROP TABLE IF EXISTS `lb_smart_bed`;
CREATE TABLE `lb_smart_bed` (
  `smart_bed_id` varchar(32) NOT NULL COMMENT '主键',
  `device_number` varchar(32) NOT NULL DEFAULT '' COMMENT '设备号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `device_type` tinyint(1) NOT NULL DEFAULT '119' COMMENT '设备类型',
  `position_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '安装位置',
  `device_iteration_number` varchar(32) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `online_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否在线 1 在线 0 不在线',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '位置id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`smart_bed_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能床';

-- ----------------------------
-- Table structure for lb_smart_bed_heath_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_smart_bed_heath_info`;
CREATE TABLE `lb_smart_bed_heath_info` (
  `heath_info_id` varchar(32) NOT NULL COMMENT '主键',
  `sleep_info_id` varchar(32) NOT NULL DEFAULT '' COMMENT '睡眠id',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `fatigue_degree` tinyint(1) NOT NULL DEFAULT '0' COMMENT '疲劳指数',
  `recover_degree` tinyint(1) NOT NULL DEFAULT '0' COMMENT '恢复指数',
  `heart_biggest_limit` float NOT NULL DEFAULT '0' COMMENT '心率上限',
  `heart_smallest_limit` float NOT NULL DEFAULT '0' COMMENT '心率下限',
  `breath_biggest_limit` float NOT NULL DEFAULT '0' COMMENT '呼吸率上限',
  `breath_smallest_limit` float NOT NULL DEFAULT '0' COMMENT '呼吸率下限',
  `sdnn_biggest_limit` float NOT NULL DEFAULT '0' COMMENT 'SDNN上限',
  `sdnn_smallest_limit` float NOT NULL DEFAULT '0' COMMENT 'SDNN下限',
  `rmssd_biggest_limit` float NOT NULL DEFAULT '0' COMMENT 'RMSSD上限',
  `rmssd_smallest_limit` float NOT NULL DEFAULT '0' COMMENT 'RMSSD下限',
  `pnn_biggest_limit` float NOT NULL DEFAULT '0' COMMENT 'pNN50上限',
  `pnn_smallest_limit` float NOT NULL DEFAULT '0' COMMENT 'pNN50下限',
  `lfhf_biggest_limit` float NOT NULL DEFAULT '0' COMMENT 'LF/HF 上限',
  `lfhf_smallest_limit` float NOT NULL DEFAULT '0' COMMENT 'LF/HF 下限',
  `stress_resistance` varchar(32) NOT NULL DEFAULT '' COMMENT '抗压能力',
  `stress_index` varchar(32) NOT NULL DEFAULT '' COMMENT '压力指数',
  `fatigue_index` varchar(32) NOT NULL DEFAULT '' COMMENT '压力疲劳状态',
  `ans_activity` varchar(32) NOT NULL DEFAULT '' COMMENT '自助神经活性',
  `twitch_times` int(11) NOT NULL DEFAULT '0' COMMENT '体动次数',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`heath_info_id`),
  KEY `sleep_info_id_IDX` (`sleep_info_id`) USING BTREE,
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能床长者健康数据';

-- ----------------------------
-- Table structure for lb_smart_bed_sleep_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_smart_bed_sleep_info`;
CREATE TABLE `lb_smart_bed_sleep_info` (
  `sleep_info_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者id',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `sleep_date` varchar(32) NOT NULL DEFAULT '' COMMENT '报告日期',
  `sleep_grade` tinyint(1) NOT NULL DEFAULT '0' COMMENT '睡眠得分',
  `sleep_duration` int(11) NOT NULL DEFAULT '0' COMMENT '睡眠时长',
  `last_go_bed_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上床时间',
  `sleep_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '入睡时间',
  `get_up_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '起床时间',
  `sleep_efficiency` float NOT NULL DEFAULT '0' COMMENT '睡眠效率',
  `deep_sleep_duration` int(11) NOT NULL DEFAULT '0' COMMENT '深睡时长',
  `shallow_sleep_duration` int(11) NOT NULL DEFAULT '0' COMMENT '浅睡时长',
  `clear_duration` int(11) NOT NULL DEFAULT '0' COMMENT '清醒时长',
  `avg_heart_rate` int(11) NOT NULL DEFAULT '0' COMMENT '平均心率',
  `long_interval_counts` tinyint(1) NOT NULL DEFAULT '0' COMMENT '心率失常指数',
  `avg_breath_rate` tinyint(1) NOT NULL DEFAULT '0' COMMENT '平均呼吸率',
  `snore_times` int(11) NOT NULL DEFAULT '0' COMMENT '打鼾次数',
  `anti_snore_times` tinyint(1) NOT NULL DEFAULT '0' COMMENT '干预次数',
  `anti_snore_stage` text NOT NULL COMMENT '干预周期',
  `hrv_synthesize_status` varchar(32) NOT NULL DEFAULT '' COMMENT 'hrv综合指标',
  `hrv_sdnn` float NOT NULL DEFAULT '0' COMMENT 'SDNN',
  `hrv_rmssd` float NOT NULL DEFAULT '0' COMMENT 'RMSSD',
  `hrv_pnn` float NOT NULL DEFAULT '0' COMMENT 'pNN50',
  `hrv_lf_hf` float NOT NULL DEFAULT '0' COMMENT 'LF/HF',
  `stress_synthesize_state` varchar(32) DEFAULT NULL COMMENT '压力综合指标',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sleep_info_id`),
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能床长者睡眠信息';

-- ----------------------------
-- Table structure for lb_smart_device_csr
-- ----------------------------
DROP TABLE IF EXISTS `lb_smart_device_csr`;
CREATE TABLE `lb_smart_device_csr` (
  `smart_device_csr_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '客服id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `uid` varchar(100) NOT NULL,
  `rtc_token` varchar(100) NOT NULL,
  `expire_time` bigint(20) NOT NULL COMMENT 'rtc_token过期时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `config_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '呼叫中心配置 1 小度',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`smart_device_csr_id`),
  KEY `account_id_IDX` (`account_id`) USING BTREE,
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='小度坐席表';

-- ----------------------------
-- Table structure for lb_smart_device_csr_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_smart_device_csr_config`;
CREATE TABLE `lb_smart_device_csr_config` (
  `config_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `config_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '配置类型 1 小度',
  `phone` varchar(100) NOT NULL COMMENT '呼叫中心号码',
  `shop_id` varchar(32) NOT NULL COMMENT '小度项目id',
  `rtc_appid` varchar(100) NOT NULL,
  `rtc_appsecret` varchar(100) DEFAULT NULL,
  `uids` text NOT NULL COMMENT '坐席范围 (默认1-100)',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL COMMENT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='智能设备通话配置';

-- ----------------------------
-- Table structure for lb_smog_detector
-- ----------------------------
DROP TABLE IF EXISTS `lb_smog_detector`;
CREATE TABLE `lb_smog_detector` (
  `smog_detector_id` varchar(64) NOT NULL DEFAULT '' COMMENT 'id',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `imei` varchar(32) DEFAULT '' COMMENT 'imei',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '电信平台id',
  `iot_app_id` varchar(64) DEFAULT '' COMMENT '应用id',
  `dump_energy` tinyint(3) DEFAULT '100' COMMENT 'NB电量',
  `alarm_type` tinyint(3) DEFAULT '0' COMMENT '报警类型',
  `smog_sensing_value` varchar(10) DEFAULT '' COMMENT '烟雾值',
  `temperature` varchar(10) DEFAULT '' COMMENT '温度',
  `humidity` varchar(10) DEFAULT '' COMMENT '湿度',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `position_desc` varchar(64) DEFAULT '' COMMENT '安装位置',
  `area_id` varchar(64) DEFAULT '' COMMENT '房间id',
  `labyrinth_pollution_degree` varchar(32) DEFAULT '' COMMENT '迷宫污染度',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `iot_device_name` varchar(32) DEFAULT '' COMMENT '设备名称（注册时使用）',
  `iot_is_encode` varchar(32) DEFAULT '' COMMENT '是否加密',
  `iot_chip_model` varchar(32) DEFAULT '' COMMENT '芯片型号',
  `activated` varchar(32) DEFAULT '' COMMENT '是否激活',
  `iot_is_safe` varchar(32) DEFAULT '' COMMENT '是否为安全设备',
  `iot_psk` varchar(32) DEFAULT '' COMMENT '加密的PSK',
  `iot_product_id` varchar(32) DEFAULT '' COMMENT '自定义产品',
  `org_id` varchar(64) DEFAULT '' COMMENT '机构组织id',
  `family_id` varchar(64) DEFAULT '' COMMENT '家庭组',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检查时间',
  `smog_dump_energy` tinyint(3) DEFAULT '0' COMMENT '烟感电量',
  `smog_energy_check_time` bigint(20) DEFAULT '0' COMMENT '烟感电量检查时间',
  `online_status` tinyint(1) DEFAULT '0' COMMENT '在线状态（0:离线，1:在线）',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '1' COMMENT '修改时间',
  `shield_time` bigint(20) DEFAULT '0' COMMENT '离线不提醒时间',
  `power_shield_time` bigint(20) DEFAULT '0' COMMENT '低电量不提醒时间',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`smog_detector_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `imei` (`imei`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='烟雾探测器表';

-- ----------------------------
-- Table structure for lb_sms_template_v2
-- ----------------------------
DROP TABLE IF EXISTS `lb_sms_template_v2`;
CREATE TABLE `lb_sms_template_v2` (
  `id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '',
  `code_num` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '模板代号(ali_template)',
  `sign_code` varchar(16) COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT '签名code (ali_sign)',
  `receive` tinyint(1) NOT NULL DEFAULT '0' COMMENT '接收人 0本人/1亲属/2紧急联系人',
  `reminder` tinyint(1) NOT NULL DEFAULT '0' COMMENT '提醒时间 -1:不提醒(手动)/0实时/1两小时后/2六小时后',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态 0待审批/1启用/2停用/3不通过',
  `org_id` varchar(32) COLLATE utf8_bin NOT NULL DEFAULT '',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_bin COMMENT='短信模块信息';

-- ----------------------------
-- Table structure for lb_snore_record_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_snore_record_statistics`;
CREATE TABLE `lb_snore_record_statistics` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者主键',
  `record_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录开始时间',
  `record_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录结束时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `content` text NOT NULL COMMENT '打鼾数据',
  `record_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '记录类型（1 智能床打鼾周期）',
  `record_time_date` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='打鼾周期记录统计表';

-- ----------------------------
-- Table structure for lb_speech_recognition_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_speech_recognition_record`;
CREATE TABLE `lb_speech_recognition_record` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '注册平台设备标识',
  `report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '上报时间',
  `call_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '喊话类型（1-首次识别，2-二次确认）',
  `call_id` varchar(32) NOT NULL DEFAULT '' COMMENT '语义标识',
  `confidence_level` smallint(6) NOT NULL DEFAULT '0' COMMENT '置信度',
  `first_id` varchar(32) NOT NULL DEFAULT '' COMMENT '首次识别记录标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `iot_device_id` (`iot_device_id`,`call_type`,`report_time`) USING BTREE,
  KEY `first_id` (`first_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='语音识别记录表';

-- ----------------------------
-- Table structure for lb_sphygmomanometer
-- ----------------------------
DROP TABLE IF EXISTS `lb_sphygmomanometer`;
CREATE TABLE `lb_sphygmomanometer` (
  `sphygmomanometer_id` varchar(32) NOT NULL COMMENT '主键',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_type` tinyint(1) NOT NULL DEFAULT '14' COMMENT '设备类型',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT 'imei号',
  `sn` varchar(32) NOT NULL DEFAULT '' COMMENT '设备序列号',
  `iccid` varchar(64) NOT NULL DEFAULT '' COMMENT '卡号',
  `unit` int(11) NOT NULL DEFAULT '-1' COMMENT '单位',
  `voice_switch` tinyint(3) NOT NULL DEFAULT '-1' COMMENT '语音开关 0关1开 ',
  `power` int(11) NOT NULL DEFAULT '-1' COMMENT '设备电量',
  `signal_strength` int(11) NOT NULL DEFAULT '-1' COMMENT '信号强度',
  `protocol_ver` varchar(32) NOT NULL DEFAULT '1.0.0' COMMENT '版本号',
  `online_status` int(3) NOT NULL DEFAULT '0' COMMENT '1:在线 0:离线',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构标识',
  `online_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '在线时间',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `energy_check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '电量检查时间',
  `assist_device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '协助设备种类(0:监护手表 4:求救定位器 5:定位手环)',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`sphygmomanometer_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='血压计表';

-- ----------------------------
-- Table structure for lb_staff_device_manage
-- ----------------------------
DROP TABLE IF EXISTS `lb_staff_device_manage`;
CREATE TABLE `lb_staff_device_manage` (
  `id` varchar(32) NOT NULL,
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '管理实体id',
  `object_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '管理实体类型(1:房间 , )',
  `org_id` varchar(32) NOT NULL DEFAULT '',
  `create_time` bigint(20) NOT NULL DEFAULT '0',
  `update_time` bigint(20) NOT NULL DEFAULT '0',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_area_id` (`object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='员工设备关联管理实体';

-- ----------------------------
-- Table structure for lb_static_resources
-- ----------------------------
DROP TABLE IF EXISTS `lb_static_resources`;
CREATE TABLE `lb_static_resources` (
  `resources_id` varchar(32) NOT NULL COMMENT '主键',
  `resources_name` varchar(32) NOT NULL DEFAULT '' COMMENT '资源名称',
  `resources_address` varchar(255) NOT NULL DEFAULT '' COMMENT '资源路径',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`resources_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='静态资源表';

-- ----------------------------
-- Table structure for lb_statistics
-- ----------------------------
DROP TABLE IF EXISTS `lb_statistics`;
CREATE TABLE `lb_statistics` (
  `statistics_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `device_id` varchar(64) NOT NULL COMMENT '设备Id',
  `device_type` tinyint(4) DEFAULT NULL COMMENT '设备类型（0手环）',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '长者Id',
  `care_object_name` varchar(32) DEFAULT '' COMMENT '长者姓名',
  `gender` tinyint(1) DEFAULT NULL COMMENT '性别（１男,２女）',
  `birthday` bigint(20) DEFAULT '0' COMMENT '生日',
  `statistic_type` tinyint(2) DEFAULT NULL COMMENT '统计类型',
  `immobility_time` mediumint(6) DEFAULT '0' COMMENT '不动时长',
  `in_hand_times` mediumint(6) DEFAULT '0' COMMENT '在手次数',
  `un_hand_times` mediumint(6) DEFAULT '0' COMMENT '离手次数',
  `raw_data_max` mediumint(6) DEFAULT '0' COMMENT '原始数据最大值',
  `raw_data_min` mediumint(6) DEFAULT '0' COMMENT '原始数据最小值',
  `start_time` bigint(20) DEFAULT '0' COMMENT '开始时间',
  `end_time` bigint(20) DEFAULT '0' COMMENT '结束时间',
  `report_time` bigint(20) DEFAULT '0' COMMENT '上报时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `pix_in_hand_count` mediumint(6) DEFAULT '0' COMMENT '绿光在手次数',
  `pix_un_hand_count` mediumint(6) DEFAULT '0' COMMENT '绿光离手次数',
  `fluctuation_max` mediumint(6) DEFAULT '0' COMMENT '绿光波动最大值',
  `fluctuation_min` mediumint(6) DEFAULT '0' COMMENT '绿光波动最小值',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`statistics_id`),
  KEY `care_object_name` (`care_object_name`) USING BTREE,
  KEY `start_time` (`start_time`) USING BTREE,
  KEY `device_id` (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='统计信息表';

-- ----------------------------
-- Table structure for lb_step_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_step_report`;
CREATE TABLE `lb_step_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `step` int(11) NOT NULL DEFAULT '0' COMMENT '总步数',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='计步报表';

-- ----------------------------
-- Table structure for lb_steps_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_steps_record`;
CREATE TABLE `lb_steps_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) DEFAULT '' COMMENT 'care_object_id',
  `care_object_name` varchar(128) DEFAULT '' COMMENT '老人姓名',
  `steps_number` int(11) DEFAULT '0' COMMENT '步数',
  `add_steps_number` int(11) DEFAULT '0' COMMENT '新增步数',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT ' 修改时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT '电信平台设备Id',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`),
  KEY `org_id` (`org_id`,`iot_device_id`) USING BTREE,
  KEY `lb_steps_record_create_time_IDX` (`create_time`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_storage_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_storage_record`;
CREATE TABLE `lb_storage_record` (
  `storage_id` int(32) unsigned NOT NULL AUTO_INCREMENT COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者ID',
  `report_id` varchar(64) DEFAULT NULL COMMENT '报告ID',
  `file_name` varchar(64) DEFAULT NULL COMMENT '文件名称',
  `file_url` varchar(64) DEFAULT NULL COMMENT 'FastDFS路径',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`storage_id`)
) ENGINE=InnoDB AUTO_INCREMENT=646 DEFAULT CHARSET=utf8mb4 COMMENT='一体机上传报告表';

-- ----------------------------
-- Table structure for lb_subsidy_type_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_subsidy_type_setting`;
CREATE TABLE `lb_subsidy_type_setting` (
  `setting_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `subsidy_name` varchar(32) NOT NULL DEFAULT '' COMMENT '补贴名称',
  `start_age` varchar(32) NOT NULL DEFAULT '' COMMENT '年龄段（始）',
  `is_contain_start_age` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否包含开始年龄',
  `end_age` varchar(32) NOT NULL DEFAULT '' COMMENT '年龄段（末）',
  `is_contain_end_age` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否包含结束年龄',
  `subsidy_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '补贴方式 1 折扣补贴 2 减免补贴',
  `subsidy_rate_amount` decimal(8,1) NOT NULL DEFAULT '0.0' COMMENT '折扣率或补贴金额',
  `is_open` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否开启 0 关闭 1 开启',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `audit_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '审核类型 1 人工审核，不自动通过 2 年龄符合条件，自动审核通过 3 申请自动审核通过',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`setting_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='助餐补贴类型设置';

-- ----------------------------
-- Table structure for lb_subsidy_way_setting
-- ----------------------------
DROP TABLE IF EXISTS `lb_subsidy_way_setting`;
CREATE TABLE `lb_subsidy_way_setting` (
  `way_setting_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `subsidy_way` tinyint(1) NOT NULL DEFAULT '1' COMMENT '补贴方式 1 每天一次 2 每餐一次',
  `business_hours_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '补贴餐 0 所有餐都补贴',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`way_setting_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='补贴方式设置';

-- ----------------------------
-- Table structure for lb_suit_aged_manage
-- ----------------------------
DROP TABLE IF EXISTS `lb_suit_aged_manage`;
CREATE TABLE `lb_suit_aged_manage` (
  `suit_aged_manage_id` varchar(32) NOT NULL COMMENT '主键',
  `suit_aged_name` varchar(64) NOT NULL COMMENT '适老改造项目名称',
  `project_administrators` varchar(32) NOT NULL COMMENT '项目管理员',
  `phone_num` varchar(16) NOT NULL COMMENT '手机号码',
  `level` tinyint(1) NOT NULL COMMENT '项目等级',
  `parent_id` varchar(32) NOT NULL DEFAULT '' COMMENT '父类id',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `level_relation` varchar(255) NOT NULL DEFAULT '' COMMENT '层级关系',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `project_module` varchar(64) NOT NULL COMMENT '项目（包）流程模块',
  `parent_model` varchar(64) NOT NULL DEFAULT '' COMMENT '父级项目（包）流程模块',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`suit_aged_manage_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造项目（包）表';

-- ----------------------------
-- Table structure for lb_suit_aged_process_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_suit_aged_process_record`;
CREATE TABLE `lb_suit_aged_process_record` (
  `process_record_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `care_object_id` varchar(32) NOT NULL COMMENT '长者id',
  `project_id` varchar(32) NOT NULL COMMENT '适老项目id',
  `suit_aged_manage_id` varchar(32) NOT NULL COMMENT '适老包id',
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '流程记录id',
  `record_type` tinyint(1) NOT NULL COMMENT '流程类型',
  `record_status` tinyint(1) NOT NULL COMMENT '操作流程状态',
  `create_by` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人',
  `display_name` varchar(32) NOT NULL DEFAULT '' COMMENT '操作人姓名',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '操作时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `approve_content` varchar(255) NOT NULL DEFAULT '' COMMENT '审批备注',
  `estimate_account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '流程人员id',
  `next_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '审核通过下一级的流程记录id',
  `is_read` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否已读',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 0 否 1 是',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`process_record_id`),
  KEY `org_id_IDX` (`org_id`) USING BTREE,
  KEY `care_object_id_IDX` (`care_object_id`) USING BTREE,
  KEY `suit_aged_manage_id_IDX` (`suit_aged_manage_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='适老改造流程记录表';

-- ----------------------------
-- Table structure for lb_syn_del_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_syn_del_log`;
CREATE TABLE `lb_syn_del_log` (
  `syn_del_log_id` varchar(32) NOT NULL COMMENT '自增主键',
  `org_id` varchar(50) DEFAULT NULL COMMENT '机构ID',
  `table_name` varchar(50) DEFAULT NULL COMMENT '同步表名',
  `content` json NOT NULL COMMENT '主键对内容',
  `update_time` timestamp(3) NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '创建时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`syn_del_log_id`) USING BTREE,
  KEY `id_n_u_index` (`org_id`,`table_name`,`update_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='同步增量删除内容';

-- ----------------------------
-- Table structure for lb_synch_msg_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_synch_msg_record`;
CREATE TABLE `lb_synch_msg_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者标识',
  `msg_category` tinyint(1) NOT NULL DEFAULT '1' COMMENT '消息类别，参见消息类别枚举',
  `msg_type` int(11) NOT NULL DEFAULT '0' COMMENT '消息类型，参见消息类型枚举',
  `msg_content` text NOT NULL COMMENT '消息内容',
  `record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '记录时间',
  `read_account` text NOT NULL COMMENT '已读用户',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `source_id` varchar(32) NOT NULL DEFAULT '' COMMENT '消息来源标识',
  `receive_account` varchar(32) NOT NULL DEFAULT '' COMMENT '接收用户',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`),
  KEY `care_object_id` (`care_object_id`,`msg_category`,`msg_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='馨刻消息记录表';

-- ----------------------------
-- Table structure for lb_table_view_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_table_view_config`;
CREATE TABLE `lb_table_view_config` (
  `id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `tab_type` varchar(128) NOT NULL DEFAULT '' COMMENT '表格类型',
  `account_id` varchar(32) NOT NULL DEFAULT '' COMMENT '账号id',
  `hidden_columns` text NOT NULL COMMENT '隐藏列信息',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除 0：未删除 1:删除 默认 0',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `account_id_index` (`account_id`) USING BTREE COMMENT '账户id索引'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='社区列表数据列显示配置表';

-- ----------------------------
-- Table structure for lb_tc_fallalarm_map
-- ----------------------------
DROP TABLE IF EXISTS `lb_tc_fallalarm_map`;
CREATE TABLE `lb_tc_fallalarm_map` (
  `map_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `content` text COMMENT '地图信息',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT 'TC电信平台id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_send` tinyint(2) NOT NULL DEFAULT '0' COMMENT '是否已发送，1是0否',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`map_id`),
  KEY `iot_device_id` (`iot_device_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='TC跌倒报警地图信息';

-- ----------------------------
-- Table structure for lb_tc_fallalarm_position
-- ----------------------------
DROP TABLE IF EXISTS `lb_tc_fallalarm_position`;
CREATE TABLE `lb_tc_fallalarm_position` (
  `position_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `loc_x` varchar(16) NOT NULL DEFAULT '' COMMENT '跌倒位置x坐标',
  `loc_y` varchar(16) NOT NULL DEFAULT '' COMMENT '跌倒位置y坐标',
  `loc_z` varchar(16) NOT NULL DEFAULT '' COMMENT '跌倒位置z坐标',
  `tar_reason` tinyint(2) NOT NULL DEFAULT '0' COMMENT '跌倒原因',
  `tar_height` smallint(6) NOT NULL DEFAULT '0' COMMENT '跌倒高度',
  `loc_num` tinyint(2) NOT NULL DEFAULT '0' COMMENT '跌倒数据编号',
  `event_id` varchar(64) NOT NULL DEFAULT '' COMMENT '跌倒报警事件id',
  `iot_device_id` varchar(64) NOT NULL DEFAULT '' COMMENT 'TC电信平台id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_wrong` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否误报，1是0否',
  `map_id` varchar(32) DEFAULT '' COMMENT '关联的地图id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`position_id`),
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `event_id` (`event_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='TC跌倒报警坐标信息';

-- ----------------------------
-- Table structure for lb_temperature_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_temperature_report`;
CREATE TABLE `lb_temperature_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `max_temperature` decimal(4,1) NOT NULL DEFAULT '0.0' COMMENT '最高体温',
  `max_temperature_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最高体温上报时间',
  `min_temperature` decimal(4,1) NOT NULL DEFAULT '0.0' COMMENT '最低体温',
  `min_temperature_report_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最低体温上报时间',
  `total_temperature` decimal(10,1) NOT NULL DEFAULT '0.0' COMMENT '该时间段内体温数值汇总（用于计算平均体温）',
  `report_count` int(11) NOT NULL DEFAULT '0' COMMENT '该时间段内体温上报次数统计（用于计算平均体温）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='体温报表';

-- ----------------------------
-- Table structure for lb_temperature_sensor
-- ----------------------------
DROP TABLE IF EXISTS `lb_temperature_sensor`;
CREATE TABLE `lb_temperature_sensor` (
  `temperature_sensor_id` varchar(32) NOT NULL COMMENT '主键',
  `serial_num` int(11) DEFAULT '0' COMMENT '序号',
  `area_id` varchar(32) DEFAULT '' COMMENT '房间',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `position_desc` varchar(32) DEFAULT '' COMMENT '位置描述',
  `online_time` bigint(20) DEFAULT '0' COMMENT '在线时间',
  `status` tinyint(1) DEFAULT '0' COMMENT '1:在线 0:离线',
  `dump_energy` tinyint(3) DEFAULT '0' COMMENT '电量',
  `power_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '电量状态(0:正常，1:低电量)',
  `energy_check_time` bigint(20) DEFAULT '0' COMMENT '电量检测时间',
  `hardware_version` varchar(10) DEFAULT '' COMMENT '硬件版本号',
  `device_type` tinyint(1) NOT NULL DEFAULT '68' COMMENT '设备类型',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '设备迭代版本号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '安装位置类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`temperature_sensor_id`),
  KEY `areaId` (`area_id`) USING BTREE,
  KEY `mac` (`mac`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='温湿度传感器';

-- ----------------------------
-- Table structure for lb_terminal
-- ----------------------------
DROP TABLE IF EXISTS `lb_terminal`;
CREATE TABLE `lb_terminal` (
  `terminal_id` varchar(32) NOT NULL COMMENT '主键',
  `terminal_sn` varchar(32) DEFAULT '' COMMENT '序列号',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '0 居家交互终端 1 机构交互终端',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '用户id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`terminal_id`),
  KEY `terminal_sn` (`terminal_sn`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='终端信息表;';

-- ----------------------------
-- Table structure for lb_terminal_csr_msg
-- ----------------------------
DROP TABLE IF EXISTS `lb_terminal_csr_msg`;
CREATE TABLE `lb_terminal_csr_msg` (
  `msg_id` varchar(64) NOT NULL COMMENT '主键',
  `sender_account_id` varchar(64) DEFAULT '' COMMENT 'sender_account_id',
  `sender_account_type` tinyint(4) DEFAULT '0' COMMENT '发送方的账号类型 3',
  `msg_type` tinyint(4) DEFAULT '0' COMMENT '消息类型',
  `msg_content` varchar(128) DEFAULT '' COMMENT '内容',
  `send_time` bigint(20) DEFAULT '0' COMMENT '发送时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `care_object_id` varchar(64) DEFAULT '' COMMENT 'care_object_id',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`msg_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_third_party_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_third_party_area`;
CREATE TABLE `lb_third_party_area` (
  `id` varchar(32) NOT NULL,
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '区划id',
  `area_name` varchar(255) NOT NULL DEFAULT '' COMMENT '名称',
  `parent_id` varchar(32) NOT NULL DEFAULT '0' COMMENT '父级ID',
  `area_full_name` varchar(255) NOT NULL DEFAULT '' COMMENT '区划全称',
  `service_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:含业务1:剥离业务2:爱易云3:http回调 4:深圳实业 6:福建榕基 7:永年',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_area_id` (`area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='三方对接区划表';

-- ----------------------------
-- Table structure for lb_third_party_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_third_party_device`;
CREATE TABLE `lb_third_party_device` (
  `third_party_device_id` varchar(32) NOT NULL COMMENT '主键',
  `imei` varchar(32) DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `dump_energy` int(11) DEFAULT '0' COMMENT '电量',
  `iot_card_num` varchar(32) DEFAULT '' COMMENT '卡号',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型',
  `psk` varchar(32) DEFAULT '' COMMENT '加密密钥',
  `hardware_version` varchar(32) DEFAULT '' COMMENT '硬件版本号',
  `position_desc` varchar(64) DEFAULT '' COMMENT '位置描述',
  `device_iteration_number` varchar(32) DEFAULT '-1' COMMENT '设备迭代版本号',
  `is_use` tinyint(1) DEFAULT '1' COMMENT '设备注册信息是否有效，1有效，0已失效',
  `iot_app_id` varchar(32) DEFAULT '' COMMENT '设备注册的应用id',
  `org_id` varchar(32) NOT NULL COMMENT '机构唯一标识',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `iot_device_id` varchar(64) DEFAULT '' COMMENT '电信平台唯一标识',
  `gas_sensing_value` varchar(10) DEFAULT '' COMMENT '气感值',
  `alarm_type` tinyint(3) DEFAULT NULL COMMENT '前次报警类型',
  `status` tinyint(3) DEFAULT '1' COMMENT '设备状态',
  `smog_sensing_value` varchar(10) DEFAULT '' COMMENT '烟雾值',
  `temperature` varchar(10) DEFAULT '' COMMENT '温度',
  `humidity` varchar(10) DEFAULT '' COMMENT '湿度',
  `labyrinth_pollution_degree` varchar(32) DEFAULT '' COMMENT '迷宫污染度',
  `smog_dump_energy` tinyint(3) DEFAULT NULL COMMENT '烟感电量',
  `longitude` varchar(32) DEFAULT '' COMMENT '经度',
  `latitude` varchar(32) DEFAULT '' COMMENT '纬度',
  `bind_id` varchar(64) DEFAULT '' COMMENT '绑定id',
  `version` smallint(1) DEFAULT '1',
  `energy_check_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '电量检查时间',
  `online_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '在线时间',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`third_party_device_id`) USING BTREE,
  KEY `idx_iot_device_id` (`iot_device_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='第三方应用设备';

-- ----------------------------
-- Table structure for lb_third_party_device_collect
-- ----------------------------
DROP TABLE IF EXISTS `lb_third_party_device_collect`;
CREATE TABLE `lb_third_party_device_collect` (
  `id` varchar(32) NOT NULL,
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `device_imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备imei',
  `device_mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac',
  `device_type` int(3) NOT NULL DEFAULT '1000' COMMENT '设备类型',
  `device_name` varchar(32) NOT NULL DEFAULT '' COMMENT '设备名称',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '设备状态 0离线1在线',
  `producer` varchar(32) NOT NULL DEFAULT '' COMMENT '厂商',
  `bind_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '绑定类型 0-长者',
  `bind_id` varchar(32) NOT NULL DEFAULT '' COMMENT '绑定id',
  `service_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:含业务1:剥离业务2:爱易云3:http回调 4:深圳实业 6:福建榕基 7:永年',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='来邦第三方设备对接表';

-- ----------------------------
-- Table structure for lb_third_party_device_event
-- ----------------------------
DROP TABLE IF EXISTS `lb_third_party_device_event`;
CREATE TABLE `lb_third_party_device_event` (
  `id` varchar(32) NOT NULL,
  `device_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备id',
  `device_type` int(3) NOT NULL DEFAULT '1000' COMMENT '设备类型',
  `event_code` varchar(255) NOT NULL DEFAULT '' COMMENT '设备上报事件code',
  `event_name` varchar(255) NOT NULL DEFAULT '' COMMENT '设备上报事件名称',
  `event_data` varchar(255) NOT NULL DEFAULT '' COMMENT '设备上报事件数据',
  `event_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '设备上报事件时间',
  `service_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:含业务1:剥离业务2:爱易云3:http回调 4:深圳实业 6:福建榕基 7:永年',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_org_id` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='第三方设备上报事件表';

-- ----------------------------
-- Table structure for lb_third_party_relation_id
-- ----------------------------
DROP TABLE IF EXISTS `lb_third_party_relation_id`;
CREATE TABLE `lb_third_party_relation_id` (
  `id` varchar(32) NOT NULL,
  `relation_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '关联类型 1-人员id ',
  `service_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0:含业务1:剥离业务2:爱易云3:http回调 4:深圳实业 6:福建榕基 7:永年',
  `lb_id` varchar(32) NOT NULL DEFAULT '' COMMENT '来邦主键',
  `third_id` varchar(255) NOT NULL DEFAULT '' COMMENT '三方主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  KEY `idx_lb_id` (`lb_id`,`relation_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='来邦-三方关联id表';

-- ----------------------------
-- Table structure for lb_timed_task
-- ----------------------------
DROP TABLE IF EXISTS `lb_timed_task`;
CREATE TABLE `lb_timed_task` (
  `task_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `account_id` varchar(64) NOT NULL DEFAULT '' COMMENT '设置人主键',
  `account_name` varchar(64) DEFAULT '' COMMENT '设置人姓名',
  `task_name` varchar(32) NOT NULL DEFAULT '' COMMENT '任务名称',
  `task_type` tinyint(2) NOT NULL COMMENT '任务类型',
  `title` varchar(32) DEFAULT '' COMMENT '通知标题',
  `content` text COMMENT '通知内容',
  `cron` varchar(64) NOT NULL COMMENT 'cron表达式',
  `is_publish` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否发布（0 未发布，1 已发布）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `run_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '执行时间',
  `next_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '下一次执行时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`task_id`) USING BTREE,
  KEY `org_id` (`org_id`) USING BTREE,
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='定时任务表';

-- ----------------------------
-- Table structure for lb_toilet_config_contact
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_config_contact`;
CREATE TABLE `lb_toilet_config_contact` (
  `contact_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '配置id',
  `object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '对象id',
  `object_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '对象类型 1、设备 2、区域',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `area_id` varchar(64) NOT NULL DEFAULT '' COMMENT '区域主键',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`contact_id`),
  KEY `lb_toilet_config_contact_config_id_index` (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='安装配置关联记录表';

-- ----------------------------
-- Table structure for lb_toilet_probe_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_probe_area`;
CREATE TABLE `lb_toilet_probe_area` (
  `toilet_id` varchar(32) NOT NULL COMMENT '区域主键',
  `length` int(3) DEFAULT '40' COMMENT '区域长度',
  `width` int(3) DEFAULT '40' COMMENT '区域宽度',
  `toilet_map_content` text COMMENT '探测区域信息',
  `device_wall_type` tinyint(1) DEFAULT '1' COMMENT '设备安装墙面类型 1.长  2宽',
  `device_id` varchar(32) DEFAULT '' COMMENT '绑定设备id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL COMMENT '机构主键',
  `area_id` varchar(32) DEFAULT NULL COMMENT '房间主键',
  `serial_num` int(3) DEFAULT '1' COMMENT '序号',
  `device_wall_distance` int(3) DEFAULT '20' COMMENT '离所在墙壁左端距离',
  `hight` int(3) DEFAULT '10' COMMENT '安装高度',
  `device_vertical_distance` int(3) DEFAULT '20' COMMENT '指针平行面距离',
  `install_type` tinyint(1) DEFAULT '1' COMMENT '安装方式 1嵌入 2 吸顶',
  `device_type` int(3) DEFAULT '5' COMMENT '配置对应设备类型',
  `device_iteration_number` int(3) DEFAULT '0' COMMENT '安装设备迭代版本号',
  `toilet_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '洗手间类型: 1.房间内洗手间 2 其他位置洗手间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`toilet_id`),
  KEY `lb_toilet_probe_area_device_id_index` (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='洗手间探测区域';

-- ----------------------------
-- Table structure for lb_toilet_probe_area_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_probe_area_config`;
CREATE TABLE `lb_toilet_probe_area_config` (
  `config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '配置主键',
  `config_name` varchar(32) NOT NULL COMMENT '配置名称',
  `position_desc` varchar(32) NOT NULL COMMENT '安装位置',
  `install_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '设备安装方式 1壁挂安装 2 吸顶安装',
  `device_type` int(3) NOT NULL DEFAULT '5' COMMENT '配置对应设备类型',
  `device_iteration_number` int(3) NOT NULL DEFAULT '0' COMMENT '安装设备迭代版本号',
  `position_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '位置类型: 1.房间内洗手间 2 其他位置',
  `hight` int(3) NOT NULL DEFAULT '10' COMMENT '安装高度',
  `front_length` int(3) NOT NULL DEFAULT '40' COMMENT '前边界长度',
  `back_length` int(3) NOT NULL DEFAULT '25' COMMENT '后边界长度',
  `left_length` int(3) NOT NULL DEFAULT '25' COMMENT '左边界长度',
  `right_length` int(3) NOT NULL DEFAULT '25' COMMENT '右边界长度',
  `delay_alarm_time` int(3) NOT NULL DEFAULT '120' COMMENT '延迟报警时长',
  `toilet_delay_alarm_time` int(3) NOT NULL DEFAULT '40' COMMENT '洗手间滞留报警时长',
  `no_toilet_alarm_time` int(3) NOT NULL DEFAULT '12' COMMENT '未入厕提醒时长',
  `no_life_alarm_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '无生命活动报警开关',
  `no_life_alarm_time` int(3) NOT NULL DEFAULT '6' COMMENT '无生命活动监测时长',
  `off_bed_alarm_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT '长时间离床报警开关',
  `off_bed_alarm_time` int(3) NOT NULL DEFAULT '10' COMMENT '长时间离床报警时长',
  `off_bed_time_quantum` text COMMENT '离床监测时间段',
  `toilet_map_content` text COMMENT '探测区域信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL COMMENT '机构主键',
  `photo` text COMMENT '现场图片',
  `template_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属模板id',
  `fall_alarm_report_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '跌倒报警事件上报开关',
  `fall_alarm_voice_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '跌倒报警语音提醒开关',
  `delay_alarm_report_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '滞留报警事件上报开关',
  `delay_alarm_voice_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '滞留报警语音提醒开关',
  `suspicious_interval_time` int(11) NOT NULL DEFAULT '50' COMMENT '疑似间隔时长设置',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `device_position_type` tinyint(4) NOT NULL DEFAULT '-1' COMMENT '设备安装位置类型(position_type)',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`config_id`),
  KEY `idx_device_iteration_number` (`device_iteration_number`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='洗手间探测区域配置表';

-- ----------------------------
-- Table structure for lb_toilet_report
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_report`;
CREATE TABLE `lb_toilet_report` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `care_object_id` varchar(64) NOT NULL DEFAULT '' COMMENT '看护对象',
  `report_date` varchar(16) NOT NULL DEFAULT '' COMMENT '报表日期',
  `device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备种类',
  `times` int(11) NOT NULL DEFAULT '0' COMMENT '入厕次数',
  `duration` int(11) NOT NULL DEFAULT '0' COMMENT '入厕时长',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '0' COMMENT '设备迭代版本号',
  `health_device_category` smallint(6) NOT NULL DEFAULT '0' COMMENT '健康设备种类',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`),
  UNIQUE KEY `care_object_report_date_device_category_health_category` (`care_object_id`,`report_date`,`device_category`,`device_iteration_number`,`health_device_category`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='入厕报表';

-- ----------------------------
-- Table structure for lb_toilet_shield_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_shield_area`;
CREATE TABLE `lb_toilet_shield_area` (
  `area_id` varchar(32) NOT NULL COMMENT '屏蔽区域主键',
  `toilet_id` varchar(32) NOT NULL COMMENT '所属区域主键',
  `x_start` int(3) DEFAULT '20' COMMENT '屏蔽区域x轴起点',
  `x_stop` int(3) DEFAULT '20' COMMENT '屏蔽区域x轴终点',
  `y_start` int(3) DEFAULT '20' COMMENT '屏蔽区域y轴起点',
  `y_stop` int(3) DEFAULT '20' COMMENT '屏蔽区域y轴终点',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='洗手间探测区域屏蔽区域';

-- ----------------------------
-- Table structure for lb_toilet_shield_area_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_toilet_shield_area_config`;
CREATE TABLE `lb_toilet_shield_area_config` (
  `area_config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '屏蔽区域配置主键',
  `config_id` varchar(32) NOT NULL DEFAULT '' COMMENT '所属配置主键',
  `position_desc` varchar(32) NOT NULL DEFAULT '' COMMENT '区域名称',
  `serial_num` int(3) NOT NULL DEFAULT '1' COMMENT '序号',
  `length` int(3) NOT NULL DEFAULT '40' COMMENT '区域长度',
  `width` int(3) NOT NULL DEFAULT '40' COMMENT '区域宽度',
  `x_start` int(3) NOT NULL DEFAULT '20' COMMENT '屏蔽区域x轴起点',
  `x_stop` int(3) NOT NULL DEFAULT '20' COMMENT '屏蔽区域x轴终点',
  `y_start` int(3) NOT NULL DEFAULT '20' COMMENT '屏蔽区域y轴起点',
  `y_stop` int(3) NOT NULL DEFAULT '20' COMMENT '屏蔽区域y轴终点',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '机构主键',
  `event_type` varchar(32) NOT NULL DEFAULT '' COMMENT '屏蔽事件类型:1、跌倒 2、滞留',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_config_id`),
  KEY `config_id` (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='洗手间探测区域屏蔽区域模板表';

-- ----------------------------
-- Table structure for lb_token
-- ----------------------------
DROP TABLE IF EXISTS `lb_token`;
CREATE TABLE `lb_token` (
  `token_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(128) DEFAULT '' COMMENT 'account_id',
  `token` text COMMENT 'token详情',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `live_time` int(11) DEFAULT '0' COMMENT '有效期',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目标识',
  `username` varchar(128) NOT NULL DEFAULT '' COMMENT '对接账号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`token_id`),
  UNIQUE KEY `account_id` (`account_id`) USING BTREE,
  KEY `username` (`username`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT;

-- ----------------------------
-- Table structure for lb_track_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_track_record`;
CREATE TABLE `lb_track_record` (
  `track_id` varchar(64) NOT NULL COMMENT '主键',
  `lat` varchar(32) DEFAULT '' COMMENT '纬度',
  `lng` varchar(32) DEFAULT '' COMMENT '经度',
  `device_id` varchar(64) DEFAULT '' COMMENT '设备id',
  `device_type` tinyint(1) DEFAULT '0' COMMENT '设备类型',
  `care_object_id` varchar(32) DEFAULT '' COMMENT '老人id',
  `gps_is_detail` tinyint(1) DEFAULT '0' COMMENT 'gps是否为精确gps,0粗定位,1GPS定位,2不显示定位类型,3获取粗定位失败,4定位到其他家庭设备',
  `record_time` bigint(20) DEFAULT '0' COMMENT '记录时间',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `coordsys` tinyint(1) DEFAULT '1' COMMENT '坐标系类型，0：WGS-84，1：百度，2：高德',
  `position_desc` varchar(255) DEFAULT '' COMMENT '位置叙述',
  `power` int(11) DEFAULT '-1' COMMENT '设备电量',
  `device_category` smallint(6) DEFAULT '260' COMMENT '设备种类',
  `device_iteration_number` int(3) DEFAULT '1' COMMENT '设备迭代版本号',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`track_id`),
  KEY `care_object_id` (`care_object_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_trade_order
-- ----------------------------
DROP TABLE IF EXISTS `lb_trade_order`;
CREATE TABLE `lb_trade_order` (
  `trade_order_id` varchar(32) NOT NULL COMMENT '主键',
  `prepay_id` varchar(64) DEFAULT '' COMMENT '预支付交易会话标识',
  `trade_no` varchar(64) NOT NULL DEFAULT '' COMMENT '交易订单号',
  `trade_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '交易时间',
  `trade_amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '交易金额',
  `platform_type` tinyint(1) NOT NULL COMMENT '平台类型（1-支付宝，2-微信）',
  `order_type` tinyint(1) NOT NULL COMMENT '订单类型（1-支付，2-退款）',
  `order_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '订单状态',
  `pay_trade_no` varchar(64) DEFAULT '' COMMENT '支付交易订单号（退款订单有效）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除标识（0-未删除，1-已删除）',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`trade_order_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='交易订单表';

-- ----------------------------
-- Table structure for lb_tutelage_call_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_tutelage_call_record`;
CREATE TABLE `lb_tutelage_call_record` (
  `tutelage_call_record_id` bigint(20) NOT NULL,
  `phone` varchar(32) NOT NULL DEFAULT '' COMMENT '手机号',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '通话状态',
  `answer_account_name` varchar(128) NOT NULL DEFAULT '' COMMENT '接听人账号',
  `file_url` varchar(255) NOT NULL DEFAULT '' COMMENT '录音文件地址',
  `call_start_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '接听时间',
  `call_end_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '结束时间',
  `talk_duration` bigint(20) NOT NULL DEFAULT '0' COMMENT '通话时长',
  `label_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '标签类型',
  `alarm_id` varchar(32) NOT NULL DEFAULT '' COMMENT '报警记录唯一标识',
  `call_device_type` smallint(6) NOT NULL DEFAULT '1' COMMENT '呼叫设备类型',
  `master_num` varchar(32) NOT NULL DEFAULT '' COMMENT '主机号',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构唯一标识',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `call_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '呼叫时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`tutelage_call_record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='融合主机通话记录';

-- ----------------------------
-- Table structure for lb_update_error_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_update_error_record`;
CREATE TABLE `lb_update_error_record` (
  `record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '主键',
  `account_name` varchar(64) DEFAULT '' COMMENT '用户名',
  `phone_num` varchar(32) DEFAULT '' COMMENT '登录手机号',
  `app_version_code` varchar(64) DEFAULT NULL COMMENT 'app版本',
  `phone_type` varchar(32) DEFAULT '' COMMENT '手机类型(android、IOS)',
  `phone_system_type` varchar(32) DEFAULT '' COMMENT '手机系统版本',
  `phone_system_num` varchar(32) DEFAULT '' COMMENT '手机系统型号',
  `error_message` text COMMENT '失败日志',
  `create_time` bigint(20) DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '更新时间',
  `file_path` varchar(128) DEFAULT NULL COMMENT '日志地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='设备升级失败记录';

-- ----------------------------
-- Table structure for lb_upgrade_defeated_log
-- ----------------------------
DROP TABLE IF EXISTS `lb_upgrade_defeated_log`;
CREATE TABLE `lb_upgrade_defeated_log` (
  `upgrade_defeated_log_id` varchar(32) NOT NULL COMMENT '主键',
  `account_id` varchar(32) NOT NULL COMMENT '用户id',
  `device_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '设备类型',
  `imei` varchar(32) NOT NULL DEFAULT '' COMMENT '设备编号',
  `mac` varchar(32) NOT NULL DEFAULT '' COMMENT '设备mac地址',
  `current_version` varchar(32) NOT NULL DEFAULT '' COMMENT '设备当前版本号',
  `upgrade_version` varchar(32) DEFAULT '' COMMENT '设备升级版本号',
  `photo_describe` varchar(32) DEFAULT '' COMMENT '失败图片描述',
  `abnormal_log` text COMMENT '异常日志信息',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间 ',
  `log_type` tinyint(1) DEFAULT '1' COMMENT '1升级异常，2排障分析',
  `log_url` varchar(128) DEFAULT '' COMMENT '日志文件路径',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`upgrade_defeated_log_id`),
  KEY `account_id` (`account_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='设备升级失败日志表';

-- ----------------------------
-- Table structure for lb_upload_data_result
-- ----------------------------
DROP TABLE IF EXISTS `lb_upload_data_result`;
CREATE TABLE `lb_upload_data_result` (
  `id` varchar(32) NOT NULL COMMENT '主键ID',
  `platform_code` tinyint(4) NOT NULL DEFAULT '0' COMMENT '平台类型枚举 1 金民工程',
  `local_id` varchar(32) NOT NULL DEFAULT '' COMMENT '本地对象主键',
  `external_id` varchar(128) NOT NULL DEFAULT '' COMMENT '外部平台返回的对象主键',
  `object_type` tinyint(4) NOT NULL DEFAULT '0' COMMENT '对象类型 1 长者能力评估信息',
  `sync_status` tinyint(4) NOT NULL DEFAULT '0' COMMENT '同步状态：0-待同步 1-同步中 2-同步成功 3-同步失败',
  `sync_result_code` varchar(32) NOT NULL DEFAULT '' COMMENT '同步结果代码',
  `sync_result_msg` varchar(255) NOT NULL DEFAULT '' COMMENT '同步结果消息',
  `task_id` varchar(32) NOT NULL DEFAULT '' COMMENT '同步任务id',
  `last_sync_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '最近一次同步时间戳（秒）',
  `sync_count` int(11) NOT NULL DEFAULT '0' COMMENT '同步次数',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间戳（秒）',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间戳（秒）',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除：0-正常 1-已删除',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_platform_local_object` (`platform_code`,`local_id`,`object_type`),
  KEY `idx_external_id` (`external_id`),
  KEY `idx_sync_status` (`sync_status`),
  KEY `idx_platform_status` (`platform_code`,`sync_status`),
  KEY `idx_last_sync_time` (`last_sync_time`),
  KEY `idx_create_time` (`create_time`),
  KEY `lb_local_id` (`local_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=COMPACT COMMENT='数据上传结果表';

-- ----------------------------
-- Table structure for lb_upload_file_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_upload_file_record`;
CREATE TABLE `lb_upload_file_record` (
  `id` varchar(32) NOT NULL,
  `file_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '文件类型 1-图片 2-音频 3-视频 4-文档',
  `file_name` varchar(255) NOT NULL DEFAULT '' COMMENT '文件名',
  `file_ext` varchar(255) NOT NULL COMMENT '文件后缀',
  `file_size` bigint(20) NOT NULL DEFAULT '0' COMMENT '文件大小',
  `file_url` varchar(255) NOT NULL DEFAULT '' COMMENT '文件url',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除 1是0否',
  `create_by` varchar(255) NOT NULL DEFAULT '' COMMENT '创建人账号id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='fastdfs上传文件记录';

-- ----------------------------
-- Table structure for lb_utility_data_care_object_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_utility_data_care_object_record`;
CREATE TABLE `lb_utility_data_care_object_record` (
  `utility_data_care_object_id` varchar(32) NOT NULL COMMENT '主键',
  `utility_data_id` varchar(32) NOT NULL DEFAULT '' COMMENT '关联抄表记录表主键',
  `care_object_id` varchar(32) NOT NULL DEFAULT '' COMMENT '长者Id',
  `proportional_allocation` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '均摊比例百分比',
  `amount` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '本次计费金额',
  `bill_record_id` varchar(32) NOT NULL DEFAULT '' COMMENT '账单记录主键',
  `record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '费用登记时间',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`utility_data_care_object_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='长者水电费分摊记录表';

-- ----------------------------
-- Table structure for lb_utility_data_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_utility_data_record`;
CREATE TABLE `lb_utility_data_record` (
  `utility_data_id` varchar(32) NOT NULL COMMENT '主键',
  `utility_data_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '抄表数据类型  1:水费 2:电费',
  `last_utility_data` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '上次抄表度数',
  `utility_data` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '本次抄表度数',
  `remark` varchar(512) NOT NULL DEFAULT '' COMMENT '备注',
  `unit_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '单价',
  `total_price` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '合计费用',
  `record_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '抄表时间',
  `area_id` varchar(32) NOT NULL DEFAULT '' COMMENT '房间id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除0:未删除1:删除',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `register_id` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人id',
  `register_name` varchar(32) NOT NULL DEFAULT '' COMMENT '登记人姓名',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`utility_data_id`),
  KEY `org_id_index` (`org_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='水电费抄表记录表';

-- ----------------------------
-- Table structure for lb_vending_machine_device_ext_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_vending_machine_device_ext_info`;
CREATE TABLE `lb_vending_machine_device_ext_info` (
  `device_id` varchar(64) NOT NULL COMMENT '设备主键',
  `open_door_min_amount` double(10,2) NOT NULL DEFAULT '0.00' COMMENT '开门最低金额',
  `goods_shop_id` varchar(64) NOT NULL DEFAULT '' COMMENT '所属购物店铺id',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='自动售卖机设备扩展信息表';

-- ----------------------------
-- Table structure for lb_version_upgrade_record
-- ----------------------------
DROP TABLE IF EXISTS `lb_version_upgrade_record`;
CREATE TABLE `lb_version_upgrade_record` (
  `record_id` varchar(32) NOT NULL COMMENT '主键',
  `device_id` varchar(32) DEFAULT NULL COMMENT '设备标识，设备mac，子女app帐号',
  `device_type` int(3) DEFAULT NULL COMMENT '设备类型，0子女app,1信标,2按键,3探头,4门灯,5发射小板,6手表,7输液报警器，8输液信标 9温湿度传感器 10：求救定位器　54:床头分机　15:接警器',
  `version_code` varchar(32) DEFAULT NULL COMMENT '升级后的版本号',
  `upgrade_time` bigint(20) DEFAULT '0' COMMENT '升级时间',
  `is_delete` tinyint(1) DEFAULT '0' COMMENT '是否删除，0否，１是',
  `org_id` varchar(32) DEFAULT '' COMMENT '机构id',
  `create_time` bigint(20) DEFAULT NULL COMMENT '创建时间',
  `update_time` bigint(20) DEFAULT NULL COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`record_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC;

-- ----------------------------
-- Table structure for lb_video_area
-- ----------------------------
DROP TABLE IF EXISTS `lb_video_area`;
CREATE TABLE `lb_video_area` (
  `area_id` varchar(32) NOT NULL COMMENT '主键',
  `area_name` varchar(100) NOT NULL COMMENT '区域名称',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`area_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管区域';

-- ----------------------------
-- Table structure for lb_video_config
-- ----------------------------
DROP TABLE IF EXISTS `lb_video_config`;
CREATE TABLE `lb_video_config` (
  `video_config_id` varchar(32) NOT NULL COMMENT '主键',
  `title` varchar(100) NOT NULL COMMENT '标题设置',
  `screen_display` int(11) NOT NULL COMMENT '画面显示',
  `polling_interval` int(11) NOT NULL COMMENT '轮询间隔',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '修改时间',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `create_by` varchar(32) NOT NULL COMMENT '创建人',
  `update_by` varchar(32) NOT NULL COMMENT '修改人',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`video_config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监控配置';

-- ----------------------------
-- Table structure for lb_video_device
-- ----------------------------
DROP TABLE IF EXISTS `lb_video_device`;
CREATE TABLE `lb_video_device` (
  `video_device_id` varchar(32) NOT NULL COMMENT '主键',
  `device_id` varchar(32) NOT NULL COMMENT '设备序列号，主键',
  `device_name` varchar(32) NOT NULL COMMENT '设备名称',
  `device_model` varchar(100) NOT NULL COMMENT '设备型号',
  `device_status` varchar(32) NOT NULL COMMENT '设备状态',
  `source` varchar(32) DEFAULT NULL COMMENT '权限类型',
  `channel_num` int(11) DEFAULT NULL COMMENT '设备最大支持接入的通道数',
  `org_id` varchar(32) NOT NULL COMMENT '机构id',
  `docking_platform_id` varchar(32) NOT NULL COMMENT '所属厂商',
  `area_id` varchar(32) DEFAULT 'unallocated' COMMENT '所属区域id',
  `is_show_device_name` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否显示摄像机名称 0 不显示 1 显示',
  `upgradeInfo` text COMMENT '属性',
  `accessType` varchar(32) DEFAULT NULL COMMENT '设备接入类型，PaaS-表示Paas程序接入、Lechange-表示乐橙非PaaS设备、Easy4IP表示Easy4IP程序设备、P2P表示P2P程序设备',
  `deviceVersion` varchar(255) DEFAULT NULL COMMENT '设备版本号',
  `playToken` text COMMENT '设备播放码，opensdk使用',
  `brand` varchar(32) DEFAULT NULL COMMENT '设备品牌信息：lechange-乐橙设备，general-通用设备',
  `encryptMode` varchar(32) DEFAULT NULL COMMENT '设备加密模式：0-设备默认加密 1-用户自定义加密',
  `lastOffLineTime` varchar(100) DEFAULT NULL COMMENT '设备最后离线时间',
  `catalog` varchar(32) DEFAULT NULL COMMENT '设备大类【NVR/DVR/HCVR/IPC/SD/IHG/ARC】',
  `deviceAbility` text COMMENT '设备能力集，逗号隔开',
  `channels` text COMMENT '通道信息',
  `deviceInfo` text COMMENT '设备信息',
  `is_monitor` bigint(1) NOT NULL DEFAULT '0' COMMENT '是否监控 0 否 1 是',
  `care_object_id` varchar(32) DEFAULT NULL COMMENT '绑定的长者id',
  `bind_time` bigint(20) DEFAULT '0' COMMENT '长者绑定时间',
  `channel_type` tinyint(1) DEFAULT NULL COMMENT '流类型(1:rtsp, 2:hls, ...)',
  `is_allow` tinyint(1) NOT NULL DEFAULT '0' COMMENT '子女通过App查看(0:不允许  1:允许)',
  `last_dock_time` bigint(20) DEFAULT '0' COMMENT '上一次同步时间',
  `is_delete` tinyint(4) NOT NULL DEFAULT '0' COMMENT '是否删除默认是0',
  `position_desc` varchar(64) NOT NULL DEFAULT '' COMMENT '安装位置',
  `device_type` int(11) NOT NULL DEFAULT '-1' COMMENT '设备类型',
  `device_unique_id` varchar(32) NOT NULL DEFAULT '' COMMENT '设备唯一标识',
  `device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备种类',
  `position_type` tinyint(1) NOT NULL DEFAULT '-1' COMMENT '安装位置类型',
  `device_iteration_number` smallint(6) NOT NULL DEFAULT '-1' COMMENT '设备迭代版本号',
  `mac` varchar(32) DEFAULT '' COMMENT 'mac地址',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`video_device_id`),
  KEY `idx_device_id` (`device_id`),
  KEY `idx_area_id` (`area_id`),
  KEY `idx_org_id` (`org_id`),
  KEY `idx_dock_id` (`docking_platform_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='视频监管设备';

-- ----------------------------
-- Table structure for lb_video_resource
-- ----------------------------
DROP TABLE IF EXISTS `lb_video_resource`;
CREATE TABLE `lb_video_resource` (
  `video_resource_id` varchar(32) NOT NULL COMMENT '主键',
  `org_id` varchar(32) NOT NULL DEFAULT '' COMMENT '机构主键',
  `resource_name` varchar(125) NOT NULL DEFAULT '' COMMENT '资源名称',
  `resource_logo_url` varchar(125) NOT NULL COMMENT 'log地址',
  `resource_qr_code_url` varchar(128) NOT NULL DEFAULT '' COMMENT '二维码地址',
  `is_delete` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否删除（0 未删除，1 已删除）',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `file_name` varchar(128) NOT NULL DEFAULT '' COMMENT '文件名称',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`video_resource_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 ROW_FORMAT=DYNAMIC COMMENT='视频资源表';

-- ----------------------------
-- Table structure for lb_vip_price
-- ----------------------------
DROP TABLE IF EXISTS `lb_vip_price`;
CREATE TABLE `lb_vip_price` (
  `vip_price_id` varchar(64) NOT NULL COMMENT '主键',
  `type` int(2) DEFAULT '1' COMMENT '1:缴费1个月 3:缴费3个月 6:缴费6个月 12:缴费12个月',
  `description` varchar(64) DEFAULT '' COMMENT '叙述',
  `discount` double DEFAULT '0' COMMENT '折扣',
  `price` double DEFAULT '0' COMMENT '价格',
  `product_id` varchar(64) DEFAULT '' COMMENT 'productID',
  `for_other_product_id` varchar(64) DEFAULT '' COMMENT '代付产品id',
  `user_type` char(1) DEFAULT '1' COMMENT '1.V1.0app，2:交互终端，3:公众号，4:V2.0app',
  `create_time` bigint(20) DEFAULT '0' COMMENT '生成时间',
  `update_time` bigint(20) DEFAULT '0' COMMENT '修改时间',
  `original_price` double NOT NULL DEFAULT '0' COMMENT '原价',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`vip_price_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

-- ----------------------------
-- Table structure for lb_vital_sign_device_ext_info
-- ----------------------------
DROP TABLE IF EXISTS `lb_vital_sign_device_ext_info`;
CREATE TABLE `lb_vital_sign_device_ext_info` (
  `device_id` varchar(64) NOT NULL COMMENT '设备主键',
  `assist_device_category` smallint(6) NOT NULL DEFAULT '-1' COMMENT '协助设备种类(协助者)',
  `org_id` varchar(64) NOT NULL DEFAULT '' COMMENT '项目主键',
  `create_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '创建时间',
  `update_time` bigint(20) NOT NULL DEFAULT '0' COMMENT '更新时间',
  `is_default` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否默认：0-否 1-是',
  `is_init` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否初始：0-否 1-是',
  PRIMARY KEY (`device_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='生命体征设备扩展信息表';

-- ----------------------------
-- Table structure for lb_voice_gateway
-- ----------------------------
DROP TABLE IF EXISTS `lb_voice_gateway`;
CREATE TABLE `lb_voice_gateway` (
  `gateway_id` varchar(32) NOT NULL COMMENT '网关id',
  `ip` varchar(32) NOT NULL DEFAULT '' COMMENT 'ip地址',
  `port` varchar(16) NOT NULL DEFAULT '0' COMMENT '端口',
  `phone` varchar(32) NOT NULL DEFAULT '0' COMMENT '电话号码',
  `phone_type` int(3) DEFAULT '1' COMMENT '电话类型 1 主机号码, 2 客服号码',
  `gateway_type` int(3) DEFAULT '1' COMMENT '网关类型 1 公共网关, 2 私有网关',
  `sn` varchar(128) DEFAULT NULL COMMENT '主机序列号',
  `org_id` varchar(64) DEFAULT NULL COMMENT '机构主键',
